INSERT INTO schema_migrations VALUES(3,1782478515);
INSERT INTO books VALUES('934343','看画识童心：儿童绘画心理解析','徐静茹','https://cdn.weread.qq.com/weread/cover/28/YueWen_934343/t9_YueWen_934343.jpg','本书是一本绘画解析的工具书，把孩子的心理呼唤以及天赋密码翻译给成人。同时，书中记录了大量通过绘画建立起自信、修复心灵创伤的儿童的成功疗愈案例，并配有300余副儿童绘画作品，具有很强的实践性和可操作性，很多案例跟踪长达十年之久。书中还介绍了孩子各生理和心理期、各种感官优势在绘画上的表现特征，帮助学画、艺考家长更好地识别孩子的天赋，开发优势智能，让他们成为最好的自己。','心理-发展心理学','2018-01-01 00:00:00',13,260,0,273,100,4,1,1629191542,1629191542,845.0,514,NULL,'社会科学文献出版社','9787520113960',NULL,1782398781);
INSERT INTO books VALUES('38260364','给教师的建议','B.A.苏霍姆林斯基','https://cdn.weread.qq.com/weread/cover/82/YueWen_38260364/t9_YueWen_38260364.jpg','《给教师的建议》是教育大师苏霍姆林斯基终其一生的心血之作，是公认洞悉教育本源和教师自我完善的教育必读经典。全书100条教育箴言，饱含对教育、教学的深度洞察，为教师理解学生、大众理解教育传承了一个共同的思想基点，勾勒了教师在教育旅途中获得长久幸福的路线图。全书将理论熔铸于生动感人的教育故事中，助力一线教师和教育专业学生理解教育，让复杂的教育问题变得简单。','教育学习-教育','2021-03-01 00:00:00',17,251,1,269,100,4,1,1628078808,1628078808,897.0,1475,NULL,'湖南人民出版社','9787556126064',NULL,1782398782);
INSERT INTO books VALUES('3300025230','长得好看能当饭吃吗：提升认知的33个经济学常识','谢宗博','https://cdn.weread.qq.com/weread/cover/63/cpPlatform_xqUDh8Yhgiz5xypk5RBAph/t9_cpPlatform_xqUDh8Yhgiz5xypk5RBAph.jpg',unistr('水是必需品都这么便宜，钻石没什么用为啥那么贵？\u000d\u000a为什么男朋友会在虚拟游戏中花费巨资买道具？\u000d\u000a我这么优秀，为什么还是剩下了？\u000d\u000a餐厅为什么会有“饮料无限续杯”的服务，不怕被喝破产吗？\u000d\u000a我年轻力壮还需要买保险吗？\u000d\u000a……\u000d\u000a在生活中，我们常常会面临一些疑问和困惑。其实，生活中的一切问题都可以在经济学中找到答案。本书提出了生活中经常遇到的33个问题，通过讲故事的手法，结合现实生活中的实例，从经济学角度进行分析，你会发现，所有的问题都能用经济学进行解答。掌握经济学思维，能帮你更通透的认清人生中各种事件背后的逻辑，从而更好地做好人生抉择。'),'经济理财-理财','2022-04-01 00:00:00',18,249,0,267,100,4,1,1754471521,1754471521,848.0,2000,NULL,'新世界出版社','9787510474750',NULL,1782398781);
INSERT INTO books VALUES('3300101680','笑得出来的养育','李一诺','https://cdn.weread.qq.com/weread/cover/26/cpplatform_bzjeybtf7hkwcznlxthtk2/t9_cpplatform_bzjeybtf7hkwcznlxthtk21717061079.jpg',unistr('我们上一次和孩子大笑，是什么时候？\u000a我要如何培养自己的孩子？\u000a什么才是好的教育？\u000a我们如何在每一次的养育崩溃中峰回路转？\u000a每一个家庭的背景，父母、孩子特点都不一样。所谓的“成功”，背后也有无数看不见、复制不了的机\u000a缘与特色。所以好的养育，不来自于任何专家、道理、方法，而是来自于作为父母的我们，根据自己\u000a的状态，孩子的特点，关系的此时此刻，以及所处的环境与条件，来做的每个当下的“刚刚好，也是\u000a更好”的选择。\u000a如何做出这个合适的选择？来自于我们的内心丰盈自然的状态，对内心障碍、过往伤痛的疗愈，与原\u000a生家庭的链接与和解，对真实自我的接纳与释放。只有当我们能开始看见自己，才能开始懂得孩子。\u000a只有我们能够开始爱自己，才能给孩子真实自然的爱。\u000a所以这不是一本教你如何养孩子的书，而是一趟邀请父母们与我共渡的自我关爱、觉察、疗愈之旅。\u000a在这里，你能看到我的父母养育、觉察反观、自我成长的经历，既有正向的激励和传承，也有卡点的\u000a反思与突破。以及我后来做高管、做教育、做妈妈过程中，看到的父母辈的成长经历，以及同龄朋友、\u000a年轻人群，父母孩子、教育体系背后等等养育方式的不同，带来的人生变化与影响，再回过头来思考：\u000a到底什么才是好的养育？我要如何培养自己的孩子？希望给当下的父母们什么样的分享与启发？\u000a以上汇成了本书，从自我觉察出发的，启迪父母觉醒之书。'),'教育学习-教育','2024-06-01 00:00:00',11,246,0,257,99,4,1,1743220535,1743220535,913.0,2080,NULL,'浙江教育出版社','9787572279010',NULL,1782398781);
INSERT INTO books VALUES('3300053854','为什么学生不喜欢上学？：认知心理学家解开大脑学习的运作结构，如何更有效地学习与思考','丹尼尔·T.威林厄姆','https://cdn.weread.qq.com/weread/cover/67/cpplatform_41udcg8b6xhgmji7sr8rjg/t9_cpplatform_41udcg8b6xhgmji7sr8rjg1679975058.jpg',unistr('本书以“人类是如何思考和学习的”为线索，按章节依次阐述了大脑关于学习的10项基本运作原理，回答了诸如为何我们无须费力就能记住热播剧剧情却记不住知识等普遍学习困惑，揭示了故事、情感、记忆、背景知识、练习在构建知识和创造持久学习经验中的重要性，据此给出教育工作者提高学生的学习能力及精进教学技艺的方法建议。 \u000a作者的多个观点会颠覆你的固有认知，你将会重新认识并思考以下主题：“事实性知识优先于技能知识”“反复练习是精通任何脑力工作的开始”“因材施教是否有科学性证据支持”“智能可通过持续努力而改变掌握10大认知原则，就能掌握有效学习的诀窍，不是你不喜欢学习，原来是大脑喜欢这样学！'),'教育学习-教育','2023-01-01 00:00:00',16,221,0,237,99,4,1,1691046242,1691046242,824.0,611,NULL,'中国青年出版社','9787515367088',NULL,1782398781);
INSERT INTO books VALUES('3300008362','意象的帝国：诗的写作课','黄梵','https://cdn.weread.qq.com/weread/cover/62/3300008362/t9_3300008362.jpg','《意象的帝国：诗的写作课》是作家、诗人黄梵在其系列写作课讲课录音的基础上重新修订、增补而成。全书分为“受用一生的写作观念”“一堂课学会写出好诗句”“新诗写作的核心”“写出整首诗的若干方法”等四堂写作课，针对诗歌创意写作的思路和具体方法路径展开讲解、阐释，是一本具有整体性、实操性的新诗写作指南。','文学-文学鉴赏','2021-08-01 00:00:00',28,212,0,240,99,4,1,1692152671,1692152671,845.0,447,NULL,'广西师范大学出版社','9787559838575',NULL,1782398781);
INSERT INTO books VALUES('26454163','这里是中国','星球研究所 中国青藏高原研究会','https://cdn.weread.qq.com/weread/cover/95/YueWen_26454163/t9_YueWen_26454163.jpg','这本书集结星球研究所近3年来中国主题文章的精华，按照中国地势三级阶梯顺序，呈现出荒原到人间的变化，全书收录300余张精致摄影作品，涵盖诗词、动植物、人文等丰富内容，以广阔的地理视角和宏大的时间尺度，重新解读中国故事。以18个关于中国的独特话题，365张具有地域代表性的高清摄影作品，串联起中国的地理科普和人文故事。了解中国在时间长河中的起源和变迁、生命和文明的孕育及成长。','社会文化-文化','2019-09-01 00:00:00',1,191,0,192,100,4,1,1588763320,1588763320,863.0,19100,NULL,'中信出版集团','9787521701579',NULL,1782398782);
INSERT INTO books VALUES('3300026077','月光落在左手上','余秀华','https://cdn.weread.qq.com/weread/cover/31/cpPlatform_fuLnt2noEFmgyyRQvN8d3a/t9_cpPlatform_fuLnt2noEFmgyyRQvN8d3a.jpg',unistr('本书是余秀华的代表作《月光落在左手上》的全新精装版。《月光落在左手上》2015年出版后获得了众多读者的青睐，这种现象级热销，在诗歌领域引发了一次小浪潮。本次精装版中收录了诗人的140余首作品，包括十余首新作，另收入了记录诗人生活和创作环境的全彩图片。\u000d\u000a本书呈现了诗人对爱情、亲情、日复一日的生活的感悟，带有村庄、土地的朴实气息，混合了女性丰富、敏锐的情感神经。如果你是带着好奇去读余秀华的诗，继而便会被她诗中展现出来的奔放、丰盈、纯净的内心世界席卷，无从抗拒。在现实中，她被贴上“农妇”“诗人”“脑瘫患者”的重重标签，但在诗歌中，她可以抛开这些，尽情倾吐对自由的向往，对于爱情的渴望。就如她所说，“诗歌是什么呢，我不知道，也说不出来，不过是情绪在跳跃，或沉潜。不过是当心灵发出呼唤的时候，它以赤子的姿势到来，不过是一个人摇摇晃晃地在摇摇晃晃的人间走动的时候，它充当了一根拐杖。”'),'文学-现代诗歌','2020-09-01 00:00:00',16,168,0,184,95,4,1,1723525772,1723525772,889.0,3658,NULL,'北京出版集团北京十月文艺出版社','9787530220702',NULL,1782398781);
INSERT INTO books VALUES('27329013','语文课超有趣：部编本语文教材同步学（四年级下册）','李夏','https://wfqqreader-1252317822.image.myqcloud.com/cover/13/27329013/t9_27329013.jpg',unistr('    “语文课超有趣”系列由部编本语文教材总主编温儒敏教授担任顾问，由北京大学语文教育研究所组织学者团队，按照“新课标”要求，以温儒敏高效语文学习理念为核心编写。本系列围绕新版教材的课文篇目，同步进行相关知识的汇总、梳理、延伸、启发，帮助学生全面了解课文周边的历史、人文、社会、自然科学知识，具有很强的配套性、知识性、趣味性和启发性，是语文教育研究领域多位名师、专家共同推荐的语文课内同步拓展阅读教辅书。配套性：与新版语文教材同步推出，根据课文篇目进行针对性编写。知识性：精选课文周边知识，帮助学生了解每一课背后的知识体系。趣味性：打破刷题、死记硬背模式，符合不同年级学生的阅读趣味。启发性：提供跨学科知识转化的钥匙，引导学生自发拓展认知领域。\u000d\u000a'),'教育学习-教材','2019-12-01 00:00:00',3,148,0,151,100,4,1,1593088040,1593088040,763.0,135,NULL,'河南大学出版社','9787564939700',NULL,1782398782);
INSERT INTO books VALUES('820703','一头想要被吃掉的猪','朱利安·巴吉尼','https://wfqqreader-1252317822.image.myqcloud.com/cover/703/820703/t9_820703.jpg','·如果研究红颜色的专家是红绿色盲，还算不算专家？ ·如果实现了长生不死，那么每一天的意义是什么？ ·如果救生艇上的物资只够维持12个人的生命，那么第13个人还要不要救？ ·如果一幅被埋葬的作品公之于众之际就会被损毁，该不该公开？ ·“忒修斯”号船在修补过程中材料被全部替换，用替换下的旧材料又建造了一艘船，那么哪一艘才是原来的“忒修斯”号呢？ …… 100个思想实验，挖掘我们的真实想法和思想漏洞。','哲学宗教-哲学读物','2016-03-18 00:00:00',58,121,0,179,100,4,1,1581146455,1581146455,700.0,406,NULL,'中信出版集团','9787508657233',NULL,1782398782);
INSERT INTO books VALUES('33915626','爱的八次约会','约翰·戈特曼 朱莉·施瓦茨·戈特曼 瑞秋·卡尔顿·艾布拉姆斯 道格·艾布拉姆斯','https://cdn.weread.qq.com/weread/cover/61/YueWen_33915626/t9_YueWen_33915626.jpg','我们常听到“相爱容易，相处难”，这话可能道尽不少伴侣的心声，因为，就算两人承诺“我愿意”或者同床共枕，并不代表你真的了解另一半。那么，爱情真的是一场掷硬币的冒险吗？美国婚姻权威约翰·戈特曼博士从多年的临床研究观察到，很少有夫妻或情侣得到指引，学习营造出幸福的生活，这些伴侣们在热恋期后，常常不知道如何对谈、沟通、发问，遇到磨合跟冲突时常常只是越演越烈，最后不得不寻求婚姻治疗师协助。因此，戈特曼博士透过多年的研究，首先找出伴侣生活中最常发生困难和冲突的8个领域：信任、冲突、性爱、金钱、家庭、玩乐与冒险、心灵成长、梦想。接着，戈特曼博士以八个主题，设计八场亲密的约会，每一场约会代表了一种对话的邀请。在特别安排的约会气氛，两人能够建立亲密的交谈，让伴侣与你分享他内心真正的想法。这样的对话让你明白他的信念、行为、想法背后的原因。为何不能好好谈话，还要约会？一场不被小孩、责任、家务打扰的约会才能让谈话深入，需要被了解。每一场约会章节的最后都有约会安排，具体提出这一个主题约会的细节营造，让你们的重要谈话不无聊，不再是争吵、而是一场关系变得更紧密的约会。我们希望八场约会中，你能学到:→99种说出欣赏对方的方式→认识彼此差异的25种问题→了解对方的金钱观→原生家庭如何影响对方金钱观→亲密对话的4种技巧→容易瓦解信任感的4件事→如何一起追求人生乐趣→如何能在安全的状态下说出彼此的性爱观→如何一起在心灵上成长→如何在争吵之后修补关系→梦想对彼此的重要性→关于冲突、性爱、玩乐、金钱观的迷思。','生活百科-情感','2020-09-14 00:00:00',1,119,3,123,99,4,1,1738247092,1738247092,837.0,1810,NULL,'北京日报出版社','9787547737071',NULL,1782398781);
INSERT INTO books VALUES('216219','诗里特别有禅','骆玉明','https://cdn.weread.qq.com/weread/cover/47/yuewen_216219/t9_yuewen_2162191709022000.jpg',unistr('焦虑时读读这些古诗，用禅意让焦虑消失！\u000a禅是一种富于智慧的人生态度，能让人以恬静而欢喜的心情看待世间的一切。在本书中，我们将在复旦大学著名教授骆玉明的带领下解读和欣赏一系列体现禅理与禅趣的诗篇，通过阅读本书消除紧张和焦虑，便能以朴素自然的心情、随缘自适的态度，求得本应属于你的完美的生命。'),'文学-古代诗词','2024-03-01 00:00:00',5,113,0,118,99,4,1,1726400899,1726400899,879.0,2215,NULL,'河南文艺出版社','9787555916321',NULL,1782398781);
INSERT INTO books VALUES('3300074997','斯宾塞的快乐教育','赫伯特·斯宾塞','https://cdn.weread.qq.com/weread/cover/37/cpplatform_kcws6qjf715h8btytfenpp/t9_cpplatform_kcws6qjf715h8btytfenpp1697682213.jpg','这本书是斯宾塞的代表作，在一定程度上影响了全球的孩子和他们的教育。在斯宾塞看来，教育的目的就是有一天能够不教，在教育中应该尽量鼓励自我发展的过程，应该引导孩子自己去探讨，自己去推论。只有这样，他们才能在这其中发现学习中的奥秘，才能感受到思维的乐趣和学习的乐趣，这才是“快乐教育”的本质。','教育学习-育儿','2021-06-01 00:00:00',3,108,0,111,47,2,1,1701097750,1701097750,NULL,16,NULL,'长江文艺出版社','9787570210121',NULL,1782398781);
INSERT INTO books VALUES('855833','娱乐至死','尼尔·波兹曼','https://wfqqreader-1252317822.image.myqcloud.com/cover/833/855833/t9_855833.jpg',unistr('    《娱乐至死》初版于1985年，是尼尔·波兹曼的代表作之一。《娱乐至死》想告诉大家可能成为现实的，是赫胥黎的预言，不是奥威尔的预言；毁掉我们的，不是我们憎恨的东西，恰恰是我们热爱的东西！电视时代蒸蒸日上，电视改变了公众话语的内容和意义，政治、宗教、教育、体育、商业和任何其他公共领域的内容，都日渐以娱乐的方式出现，并成为一种文化精神，而人类无声无息地成为娱乐的附庸，毫无怨言，甚至心甘情愿，其结果是我们成了一个娱乐至死的物种。\u000a'),'社会文化-社科','2015-05-01 00:00:00',12,91,1,104,100,4,1,1583481417,1583481417,767.0,23159,NULL,'中信出版集团','9787508648286',NULL,1782398782);
INSERT INTO books VALUES('27480233','有趣得让人睡不着的植物','稻垣荣洋','https://wfqqreader-1252317822.image.myqcloud.com/cover/233/27480233/t9_27480233.jpg','“天空不能没有星星，大地不能没有花朵，人间不能没有爱。”这是18世纪德国诗人歌德的诗句。植物的花朵为什么都那么漂亮呢？还有，为什么蒲公英的花朵是黄色的，而紫罗兰的花朵却是紫色的呢？这样认真一想的话，植物的世界里还真是充满了问号啊。植物都是有生命的。每个植物都充满着各种谜团，远比我们想象的要不可思议得多。而植物的生活方式，也是生动活泼，颇具戏剧性。就让我们打开植物学的大门，一起来看看不可思议的植物世界吧。','科学技术-科学科普','2019-06-01 00:00:00',8,90,0,98,99,4,1,1643167243,1643167243,784.0,1285,NULL,'北京时代华文书局','9787569929881',NULL,1782398781);
INSERT INTO books VALUES('920085','烟火人间','老舍著 老树画画绘','https://cdn.weread.qq.com/weread/cover/86/YueWen_920085/t9_YueWen_920085.jpg','这本书选取了老舍先生的一些经典短篇小说和散杂文作品。这些作品多取材于市民生活，通过日常平凡的场景反映普遍的社会冲突，挖掘对人们生存、命运的思考。这些文章或描写城市平民的生活轨迹，或书写知识分子的生活趣事，或描摹生活见闻，作品充满生活情趣，文笔细致入微，更贯穿着老舍先生一贯的幽默风格，让人从轻快诙谐之中体味人生哲思。老舍的创作受益于民间文艺的影响，他的作品从形式到内容都雅俗共赏，突破了知识分子的狭小圈子，这使他的作品具有大众化、通俗性等特点，为广大民众所喜爱。','文学-经典作品','2017-11-01 00:00:00',9,88,2,99,100,4,1,1595014306,1595014306,829.0,530,NULL,'长江文艺出版社','9787535499745',NULL,1782398782);
INSERT INTO books VALUES('30914610','读懂孩子的小情绪','杨俐容','https://cdn.weread.qq.com/weread/cover/18/YueWen_30914610/t9_YueWen_30914610.jpg','　　应对孩子情绪问题的答案之书，读完就有用！易分心/太好动/闹别扭/身心症/不耐挫/爱生气/违抗/攻击/爱哭/焦虑/忧郁……针对从1岁到15岁最常见的情绪问题，台湾大学杨俐容教授运用心理学知识，让家长快速了解孩子的情绪行为，并掌握这些行为背后的可能原因与症结，根据每一种情绪行为提供3种具体可行的教养秘方，以及3种父母常犯却需要避免的教养行为，帮助父母对症下药，陪伴孩子勇敢面对成长困境。期望家长们运用这些方法，轻松化解情绪教养难题，培养高情商的孩子，成就完美亲子关系。这是每一位年轻爸妈的枕边必备书，读完就有用！','教育学习-育儿','2020-01-01 00:00:00',0,86,0,86,84,3,1,1620565578,1620565578,726.0,70,NULL,'天地出版社','9787545552812',NULL,1782398782);
INSERT INTO books VALUES('3300044239','偷诗歌的人','曹韵','https://cdn.weread.qq.com/weread/cover/32/cpPlatform_m2mgzCFKP3FysMaNudJJWk/t9_cpPlatform_m2mgzCFKP3FysMaNudJJWk.jpg','《偷诗歌的人》是一本以短诗为主的原创诗歌作品集。收藏人间的喜怒哀乐与美好情惑。如江风上的明月，如深夜里的烟火，有爱情里的玫瑰，也有爱不能得的沉郁。诗人的创作灵感来源于日常生活与普世情感，充满烟火气。内容分为六个部分，第一、二部分关于珍贵温暖的记忆，以“从岁月中盗得几首往事”和“从蹉跎里折光一枝”为主题；第三、四部分关于情诗，以浪漫的书写表达“从诗里藏你的名字”和“从你的眉眼里偷一首情诗”;第五部分关于和解，以“从遗憾处取一份释怀”呈现另一番世间情；第六部分则关于想象，乌托邦的怀想抒发“从日子里窃一物幻想”的主题，让诗歌的语言更有张力。 就像诗人所说:“只诚恳地记录日子”，希望这本偷来的诗歌，是你如春的温暖。','文学-现代诗歌','2022-05-01 00:00:00',2,84,0,86,99,4,1,1721470733,1721470733,713.0,855,NULL,'南京出版社','9787553335254',NULL,1782398781);
INSERT INTO books VALUES('26174310','送行','袁哲生','https://cdn.weread.qq.com/weread/cover/40/YueWen_26174310/t9_YueWen_26174310.jpg','1995年，袁哲生出版首部作品《静止在树上的羊》，隐约展现日后的小说风格，本书“辑一”即来自于此作。在“辑二”文学评论里，我们则见证小说家与其他创作者的隐秘关联。到了“辑三”“辑四”，袁哲生书写出《温泉浴池》《偏远的哭声》等成熟之作。从最初到最终，从袁哲生的小说到他的私人手札，我们得以见证一个经典作者的诞生。','文学-经典作品','2019-07-20 00:00:00',23,80,0,103,100,4,1,1585988462,1585988462,765.0,526,NULL,'四川人民出版社','9787220113871',NULL,1782398782);
INSERT INTO books VALUES('22391310','新世纪诗典（第六季）','伊沙','https://cdn.weread.qq.com/weread/cover/83/YueWen_22391310/t9_YueWen_22391310.jpg','“新世纪诗典”是诗人伊沙自2011年起，开设的微博（微信）诗歌荐评栏目，每日推荐并点评一首优秀原创当代诗歌，在此基础上每年结集成一本《新世纪诗典》正式出版，此为第六本。不以姿态、立场、资历、辈分取舍作品，只以作品质量为的评价标准。《新世纪诗典》是新世纪以来中国诗歌的集体呈现，它记录时代的声音，展示国人的生存，传递诗人的情感。伊沙的编选不带门户之见，具有一种包容一切的大气。他对每首诗所作的精彩点评加在一起也可看做是对中国当下诗坛所做的一次整体性观察和评价。','文学-现代诗歌','2018-06-01 00:00:00',0,79,1,80,100,4,1,1590885846,1590885846,466.0,26,NULL,'浙江人民出版社','9787213087530',NULL,1782398782);
INSERT INTO books VALUES('26607363','开放的人生','王鼎钧','https://wfqqreader-1252317822.image.myqcloud.com/cover/363/26607363/t9_26607363.jpg',unistr('    本书把青少年成长期间需要的认识，由家庭学校到社会，由少年到成年，由个人到团体，由现实到理想，一步一步一层一层说出来，揭开人生的许多疑惑。行文生动委婉，令人如沐春风。\u000d\u000a'),'个人成长-人生哲学','2014-09-19 00:00:00',6,70,3,79,100,4,1,1584751802,1584751802,693.0,84,NULL,'生活·读书·新知三联书店','9787108050076',NULL,1782398782);
INSERT INTO books VALUES('3300056625','我笨拙地爱着这个世界（“外卖诗人”王计兵自选集）','王计兵','https://cdn.weread.qq.com/weread/cover/28/cpplatform_3gvqc8yprlbx2wyvepzdwj/t9_cpplatform_3gvqc8yprlbx2wyvepzdwj1682074936.jpg','《我笨拙地爱着这个世界》收录了王计兵亲选的130首诗作。他写生活的困顿、对父母的追忆、对故乡的怀念。质朴平实的文字迸发出惊人的力量。每个身处困境的人，都应该读一读王计兵。','文学-现代诗歌','2023-04-01 00:00:00',12,66,0,78,99,4,1,1719134682,1719134682,876.0,964,NULL,'江苏凤凰文艺出版社','9787559476326',NULL,1782398781);
INSERT INTO books VALUES('846663','新世纪诗典（第五季）','伊沙','https://wfqqreader-1252317822.image.myqcloud.com/cover/663/846663/t9_846663.jpg',unistr('    “新世纪诗典”是诗人伊沙开设的微博（微信）诗歌荐评，每日推荐一首优秀原创诗歌，也因此每年集成一本《新世纪诗典》，此为第五本。不以姿态、立场、资历、辈分取舍作品，只以作品质量为唯一评价标准，《新世纪诗典》是新世纪以来中国诗歌的集体呈现，它记录时代的声音，展示国人的生存，传递诗人的情感。伊沙的编选不含门户之见，具有一种无所不包的大气象，他对每首诗所作的精彩点评加在一起也可看做是对中国当下诗坛所做的一次整体性观察和评价。\u000a'),'文学-现代诗歌','2016-11-01 00:00:00',0,63,0,63,100,4,1,1589097086,1589097086,649.0,32,NULL,'浙江人民出版社','9787213076428',NULL,1782398782);
INSERT INTO books VALUES('25506340','一个人生活','[日]谷川俊太郎','https://cdn.weread.qq.com/weread/cover/99/yuewen_25506340/t9_yuewen_255063401733796645.jpg',unistr('日本“宇宙诗人”谷川俊太郎人生轻哲学，全新修订版。\u000a活着，是敢哭是敢笑是敢怒是自由。而一个人生活，是一种生活态度。\u000a一个人生活并非完全的独处，而是更加自由地与自己、朋友、世界交谈。\u000a《一个人生活》是日本灵魂诗人谷川俊太郎年近古稀时的作品，在这期间他经历了父亲去世，孙子出生，好友离别，也开始了一个人的生活。\u000a透过谷川俊太郎，看见一个人生活的理想：热情、孤独、优雅和自在。\u000a他为一个人生活辩护，用细腻而充满禅意的笔触，记录下那些容易被日常琐事所湮没、难以捕捉的心情波动，从细碎平凡的衣食住行等日常小事入手，写信、吃饭、听音乐会、诗歌创作，描写对亲情、友情、爱情的体悟，睿智大方地畅谈生死与美学。\u000a人生一言难尽，作者却什么都坦诚相告，成就了这本充满人生轻哲学的散文集。 \u000a每个人都需要有一个自己的空间，那里住着一个自由的灵魂。'),'文学-散文杂著','2024-05-01 00:00:00',7,62,0,69,100,4,1,1585996380,1585996380,570.0,2700,NULL,'湖南文艺出版社','9787572616693',NULL,1782398782);
INSERT INTO books VALUES('44346269','世界上最聪明的孩子们','阿曼达·里普利','https://cdn.weread.qq.com/weread/cover/20/YueWen_44346269/t9_YueWen_44346269.jpg','世界各地的学习有怎样的不同？出现这些差异的原因是什么？美国孩子为什么会在学生评估能力测试（PISA）中成绩落后？那些培养出成绩优异孩子的国家，老师是怎么教的？学生是怎么学的？为了探究这些疑问，《时代》周刊记者里普利跟随三个美国交换生，前往韩国、波兰、芬兰进行为期一年的寻访之旅。学习到深夜的韩国孩子是被动去学，还是自发努力呢？没有竞争的芬兰教育，是怎样培养出不求量、不求优、不求赢却屡屡成绩夺冠的孩子呢？波兰实行延迟分流的政策，处于“下游”的孩子是否能够抓住机会，改变命运呢？里普利还发现，家庭在孩子的教育中参与度越高，孩子便越可能有更高的排名、更可喜的考试成绩、更得体的行为举止以及更好的考勤记录。学校和家长有多种途径来激发学生的内驱力，比如通过更明智、更有意义、更能对学生的学习产生真正效果的考试，通过慷慨给予学生自主安排学习的权利，通过由接受过好教育的老师完成更高质量、更具挑战性的教学工作等。但是，所有这些策略与学生秉承的刻苦努力的信念密不可分。','历史-历史典籍','2015-02-01 00:00:00',9,62,1,72,100,4,1,1673441229,1673441229,777.0,29,NULL,'中信出版集团','9787508641164',NULL,1782398781);
INSERT INTO books VALUES('3300106072','日子很好，我很我','焦野绿','https://cdn.weread.qq.com/weread/cover/50/cpplatform_me8tykx8j1v267wkzvufye/t9_cpplatform_me8tykx8j1v267wkzvufye1721012077.jpg',unistr('入戏\u000a就让他们\u000a道听途说\u000a而你走在\u000a故事里'),'文学-现代诗歌','2024-07-04 00:00:00',1,61,7,69,99,4,1,1738127645,1738127645,851.0,677,NULL,'江苏凤凰文艺出版公司','9787559486769',NULL,1782398781);
INSERT INTO books VALUES('36985428','写诗真好玩：树才老师给孩子的诗歌课','树才','https://wfqqreader-1252317822.image.myqcloud.com/cover/428/36985428/t9_36985428.jpg','童年是诗歌的黄金时代。这时孩子心里感受到什么，就能随口说出什么，他们对世界异常敏感，也对语言异常敏感。诗人、儿童诗歌教育倡导者树才认为：孩子比大人离诗更近。学习诗歌，是孩子学习使用汉字、开启内心想象力的最佳方式，也是对一颗童心的最好庇护。自2014年起，树才给孩子们讲诗、教孩子们写诗，足迹遍布全国，无数孩子在他的启发下写了人生的第一首诗。在30多年诗歌写作经验和与孩子们实地互动的基础上，他摸索出一套独特的教孩子写诗的方法。在本书中，他精选约40首中外经典现代诗，采用一诗一讲的方式，引导孩子打开感受与想象，体味语言的无穷创造性。从诗歌阅读到赏析再到写出自己的诗句，让每个孩子都能走进诗歌的美妙国度。','童书-儿童文学','2021-01-01 00:00:00',3,59,0,62,99,4,1,1673783918,1673783918,790.0,143,NULL,'上海社会科学院出版社','9787552032994',NULL,1782398781);
INSERT INTO books VALUES('25314646','万物静默如谜（精装纪念版）','维斯拉瓦·辛波斯卡','https://cdn.weread.qq.com/weread/cover/81/YueWen_25314646/t9_YueWen_25314646.jpg','我偏爱写诗的荒谬，胜于不写诗的荒谬。——辛波斯卡。1996年诺贝尔文学奖得主辛波斯卡，是当代最为迷人的诗人之一，享有“诗界莫扎特”的美誉。她的诗别具一格，常从日常生活汲取喜悦，以简单的语言传递深刻的思想，以小隐喻开启广大想象空间，寓严肃于幽默、机智。她是举重若轻的语言大师，在全世界各地都有着广大的粉丝。2012年平装本出版，《万物静默如谜》成了该年度国内读者的至爱，相继入选了“新浪中国”“深圳读书月”等年度十大好书，畅销一时。它的出版间接推动了国内诗集出版的热潮。此次《万物静默如谜》精装版，译者不仅对内文做了全新修订，还新增了《纪念》《火车站》等五首译作。内文全彩印刷，并收录了10幅精美插画。','文学-现代诗歌','2016-08-01 00:00:00',5,57,6,68,100,4,1,1593340531,1593340531,787.0,2459,NULL,'湖南文艺出版社','9787540471811',NULL,1782398782);
INSERT INTO books VALUES('912824','爱你就像爱生命','王小波','https://cdn.weread.qq.com/weread/cover/84/yuewen_912824/t9_yuewen_9128241776069077.jpg','李银河独家授权，并亲自校订全稿。独家首次曝光王小波写在五线谱上的情书，本版独有王小波写给许倬云的信。至今为止难以超越的情书经典。《爱你就像爱生命》是王小波留给世人最全面的书信作品。相比小说和随笔的字斟酌句，这些不加掩饰、发于肺腑的信让我们读到了更为真实的王小波。写给爱人李银河的信看到了他的热烈纯真，写给朋友的信了解到了他对世事的感悟……文字集有趣、深情、思考于一身，让人动容。《爱你就像爱生命》真实展现了王小波丰富的内心世界，是一部超越情书之上的爱情经典。','文学-经典作品','2021-08-01 00:00:00',13,56,0,69,100,4,1,1555546939,1555546939,767.0,16607,NULL,'北京出版集团北京十月文艺出版社','9787530220252',NULL,1782398782);
INSERT INTO books VALUES('23863149','新世纪诗典·第七季','伊沙编选','https://wfqqreader-1252317822.image.myqcloud.com/cover/149/23863149/t9_23863149.jpg','“新世纪诗典”是诗人伊沙自2011年起，开设的微博（微信）诗歌荐评栏目，每日推荐并点评一首优秀原创当代诗歌，在此基础上每年结集成一本《新世纪诗典》正式出版，此为第六本。不以姿态、立场、资历、辈分取舍作品，只以作品质量为仅有的评价标准。《新世纪诗典》是新世纪以来中国诗歌的集体呈现，它记录时代的声音，展示国人的生存，传递诗人的情感。伊沙的编选不带门户之见，具有一种包容一切的大气。他对每首诗所作的精彩点评加在一起也可看做是对中国当下诗坛所做的一次整体性观察和评价。','文学-文学鉴赏','2018-12-01 00:00:00',0,55,1,56,88,4,1,1597565658,1597565658,696.0,23,NULL,'中国青年出版社','9787515353999',NULL,1782398782);
INSERT INTO books VALUES('3300020004','时间的果','黎戈','https://cdn.weread.qq.com/weread/cover/4/3300020004/t9_3300020004.jpg',unistr('《时间的果》是作家黎戈的读书与生活随笔，分为“叶舟”和“根岸”两个部分：“叶舟”收录了黎戈的文艺评论：从法国新浪潮的暧昧美学到《细雪》中东方含蓄的人情之美，从慢走慢爱的永井荷风到飘零无寄的奈保尔，从“鹧鸪悲意，采菊心情”的顾景舟到古典文心的叶嘉莹……从文字的气息到城市的脉搏，从书籍的体温到蔬食的滋味，在无数灵性觉醒的瞬间中，倾听内心深处的回响。\u000d\u000a到了“根岸”，黎戈将笔头瞄准日常生活：一副眼镜、一支铅笔、云的名字、一口锅……在她笔下，平淡的日常也充满别样的玲珑趣意。人与书成为互文、彼此依傍，黎戈将她的阅读、审美经验凝结成册，与自身的成长轨迹交相辉映，在庸常的日子中打捞诗意。'),'文学-散文杂著','2022-06-01 00:00:00',5,52,0,57,99,4,1,1673619729,1673619729,888.0,145,NULL,'北京时代华文书局','9787569945355',NULL,1782398781);
INSERT INTO books VALUES('917268','我不','大冰','https://cdn.weread.qq.com/weread/cover/1/yuewen_917268/t9_yuewen_9172681741836303.jpg',unistr('善意能消戾，善意能得缘，善意能带业往生，善意能回头是岸。\u000a善意能够帮人捕捉并建立起独特的幸福感。\u000a“我不”是一种善意坦然，也是一种善意的随缘，更是一句善意的自省。\u000a书中的每一个故事都可以叫《我不》：\u000a十年如一日坚守藏地、为藏民基础教育尽一己之力的书店老板；亦正亦邪浪荡洒脱，散尽家财救助灾区、带重病母亲游历世界的东北浪子；木讷寡言对绝症女友不离不弃的流浪歌手；心系31年前阵亡战友、不愿偷生于世、为古城安危置生死于度外的不死老兵……书中的每一个有情众生，都在对命运说：我不！\u000a玩命拼命不认命，我命由我不由天。\u000a不服，不要，不怕，不羁、不二、不懈，不屈不挠，不破不立，不卑不亢……\u000a他们因不，而不同。\u000a乃至不凡。\u000a《我不》中的他们，真实存在于这个世界上，他们的故事也是他们的真实生活。他们在无常里学会坦然，坦然中历劫着不幸，于是故事变得动人——凡人解封了神性。但，所有当下动人的故事，全都不是首次发生。大冰笔下的故事，也许正是你心中的往事，故事中的他们，也许就是你。\u000a所以，也许这本书于你而言是一次寻找自我的孤独旅程，亦是一场发现同类的奇妙过程：\u000a愿你我永远善意地面对这个世界，乃至善意地直面自己。\u000a愿你知行合一，愿你能心安。\u000a愿这一声“我不”，能助你涉川。'),'文学-散文杂著','2025-03-01 00:00:00',9,50,2,61,100,4,1,1589826254,1589826254,877.0,35119,NULL,NULL,NULL,NULL,1782398782);
INSERT INTO books VALUES('29165585','十万个为什么（伊林经典科普小丛书）','伊林','https://cdn.weread.qq.com/weread/cover/17/YueWen_29165585/t9_YueWen_29165585.jpg','《十万个为什么》是“伊林经典科普小丛书”（共四册）之一种，讲述了关于日用品的科学知识。图书采用屋内旅行的方式组织内容，形式新颖独特，结构清晰完整。作品共设有水龙头、炉子、餐桌和炉灶、厨房锅架、碗柜、衣柜六个章节，作者围绕每个“旅行站点”，针对该站点中常见的普通事物提出了许多意想不到又饶有兴味的问题，比如，为什么用水来洗涤？为什么火柴会着火？为什么陈面包会发硬？为什么衣服能使人暖和？……作者运用散文的笔调、简练质朴的文字、一问一答的形式，生动有趣、深入浅出地讲解和传授了生活常识，并引导读者观察和思考日常生活中的事物和现象。','科学技术-科学科普','2019-03-01 00:00:00',1,49,1,51,100,4,1,1595246473,1595246473,817.0,1284,NULL,'浙江文艺出版社','9787533955113',NULL,1782398782);
INSERT INTO books VALUES('839748','纸上还乡','郭金牛','https://wfqqreader-1252317822.image.myqcloud.com/cover/748/839748/t9_839748.jpg','《纸上还乡》是作者背井离乡近二十年辗转广东各地写成的诗集，主要记录了一个农民从事建筑工、搬运工、工厂普工、摆地摊的内心生涯。在坎坷、复杂、悲凉的底层经验的打磨熬炼下，逐渐形成了一种十分特别的灵动尖锐、一咏三叹的语言风格，作者用这种时而破碎突兀时而哀婉悠长的语言为广大的命运同路人立言，也展示了席卷全球的工业化历程下人的现代性境遇。','文学-现代诗歌','2014-08-01 00:00:00',5,47,0,52,99,4,1,1691377562,1691377562,694.0,258,NULL,'华东师范大学出版社','9787567519206',NULL,1782398781);
INSERT INTO books VALUES('22297595','陪孩子读诗','北岛','https://wfqqreader-1252317822.image.myqcloud.com/cover/595/22297595/t9_22297595.jpg','在阅读的初始，童诗和歌谣中的纯真和童趣，会成为孩子生命原初的底色。本书由诗人、诺贝尔奖提名获得者北岛先生担任名誉主编，精选艾青、何其芳、金波、柯岩、任溶溶等国内诗人的诗歌和狄金森、谷川俊太郎等外国诗人的诗歌，配以吴冠中先生优美插图，给孩子音韵和美的启蒙。书中的选诗每首孩子都能读懂，既能让孩子自己阅读，也方便家长与孩子进行亲子阅读。','教育学习-育儿','2018-04-01 00:00:00',1,44,2,47,100,4,1,1597675682,1597675682,749.0,400,NULL,'中信出版社','9787508683010',NULL,1782398782);
INSERT INTO books VALUES('23199283','故事的开始','幾米','https://wfqqreader-1252317822.image.myqcloud.com/cover/283/23199283/t9_23199283.jpg','从1998年出版《森林里的秘密》和《微笑的鱼》开始到这本书的诞生，幾米耕耘了十年。十年间，他以惊人的创作能量，推出各种不同面貌的作品，红遍海内外。但他鲜少谈论自己的创作过程。在幾米的脑袋和作品之间那个神秘的世界，始终是读者难以企及的好奇。“我还不够分量谈这些。”他总是腼腆地说。在这本书中，幾米首次完整地详述每个创作背后的故事，从一个画面的完成，到角色、主题的灵感诞生，“创作”背后神秘的帘幕随着幾米的回溯一一揭开。书中并收录王文华、陈绮贞、黎焕雄、陆蓉之、柯倩华等人对幾米作品的看法。“幾米为什么是幾米？”这本书提供了直接的答案。','人物传记-艺术家','2018-10-01 00:00:00',4,44,2,50,100,4,1,1581408105,1581408105,769.0,2690,NULL,'九州出版社','9787510873409',NULL,1782398782);
INSERT INTO books VALUES('34336245','极简穿搭：日常服装穿出别样风采','山本昭子','https://cdn.weread.qq.com/weread/cover/26/YueWen_34336245/t9_YueWen_34336245.jpg','你的衣橱里有多少件“普通”的衣服？想让自己的穿着更时尚、更有品位，关键在于“每个人都有的衣服”。以基本款为主进行搭配，才会让人赞叹：“这么平凡的衣服，竟然可以穿得如此时尚、有品位！”基本款虽然重要，但搭配更加关键。超难预约的知名造型师多年经验大公开，教你运用简单的搭配法则，以基本款穿出好品味！无论是现代、知性、干练、女人味，或是模特的假日休闲风，统统难不倒你！','生活百科-时尚','2018-03-01 00:00:00',0,44,3,47,99,4,1,1643529285,1643529285,386.0,971,NULL,'江西人民出版社','9787210099550',NULL,1782398781);
INSERT INTO books VALUES('839188','二十亿光年的孤独','谷川俊太郎','https://cdn.weread.qq.com/weread/cover/3/YueWen_839188/t9_YueWen_839188.jpg',unistr('    《二十亿光年的孤独》该书分为世界的约定、春的临终、小鸟在天空消失的日子、语言的胎盘、悲伤的天使、如果语言六个部分。由谷川先生与他的知音译者田原先生从其创作的诗歌中，共同遴选出120首（其中17首为新作首次发布）艺术成就比较高、流传最广的篇目编选而成。作者用他蕴含着精湛技艺和惊人想象的诗篇，向这个世界吟唱出悠远而纯粹的恋歌。\u000a'),'文学-现代诗歌','2016-08-01 00:00:00',4,44,0,48,100,4,1,1582963707,1582963707,582.0,1876,NULL,'人民文学出版社','9787020118472',NULL,1782398782);
INSERT INTO books VALUES('3300054377','星期六晚我们去散步吧','隔花人 ','https://cdn.weread.qq.com/weread/cover/35/cpplatform_4iyfjltdnwvh9d7t7vzycf/t9_cpplatform_4iyfjltdnwvh9d7t7vzycf1680504635.jpg',unistr('世间万物都有它自己的生命和生存的意义，花有花的语言，风有风的方向，种子有种子的选择，每个与你相遇的人都有他出现的理由。作者以童真的视角，将大多数人忽略的美好一一落笔成诗。\u000d\u000a·这本诗集很轻，三言两语自成宇宙，\u000d\u000a这本诗集很重，千山万水装满心事。\u000d\u000a每个人都是诗人，每个诗人都是孩子。\u000d\u000a·全书共收录作者136首诗集，作者以童真的视角，直接、清晰、简单、灵动的写下当下年轻人的内心问题、人生困惑以及生活中那些被大多数人忽略的美好。配以简单、黑白且有寓意的漫画，引起当下年轻人的喜欢和思考。'),'文学-现代诗歌','2023-03-01 00:00:00',9,43,1,53,98,4,1,1684765223,1684765223,819.0,12962,NULL,'贵州人民出版社','9787221176165',NULL,1782398781);
INSERT INTO books VALUES('43318719','一天一朵云','加文·普雷特-平尼','https://wfqqreader-1252317822.image.myqcloud.com/cover/719/43318719/t9_43318719.jpg','没有哪朵云是不美的。云是我们每天一抬头就能收到的礼物。本书收录几百张云彩高清相片，带来一场绚丽的云朵奇观盛典。(摄于全球各地，如：冰岛|丹麦|美|英|法|比利时|德|西班牙|瑞士|澳大利亚|爱尔兰|南非……，更有从国际空间站和美国国家航空航天局（NASA）的多个探测器、卫星、火星车拍摄到的金/木/火星的云和有关气象照片。)此外还收录了各时代几十位艺术家笔下的云主题艺术作品（米友仁|葛饰北斋|凡·高|爱德华·霍珀……）。为读者图文对照着科普36种云的类型和21种相关光学效应等云彩及相关气象知识和云主题艺术作品，收录多段文学作品中对云、天空与自然的生动描绘。（莎士比亚《暴风雨》、卡尔·桑德堡《雾》、雪莱《麦布女王》、爱伦·坡《埃莱奥诺拉》……）','艺术-摄影','2022-01-01 00:00:00',0,42,0,42,79,2,1,1737883240,1737883240,851.0,1149,NULL,'北京时代华文书局','9787569942484',NULL,1782398781);
INSERT INTO books VALUES('22486199','云彩收集者手册','加文·普雷特-平尼','https://cdn.weread.qq.com/weread/cover/87/YueWen_22486199/t9_YueWen_22486199.jpg','《云彩收集者手册》介绍了46种云彩和大气光学现象，并且收录了全世界云彩爱好者拍摄的百余幅精彩摄影作品。从太空边缘的神秘夜光云，到我们周围的重重雾霭，都在这本手册之中。即使没有任何自然观察经验，读者也可以了解云彩的名称、特征、形成原因，鉴别云的种类，并利用书中的趣味记分系统与亲朋好友展开观云竞赛。','科学技术-科学科普','2018-03-01 00:00:00',3,41,6,50,64,4,1,1689834908,1689834908,761.0,5000,NULL,'译林出版社','9787544771344',NULL,1782398781);
INSERT INTO books VALUES('40509853','风在悬崖落了空','黄锐','https://cdn.weread.qq.com/weread/cover/8/YueWen_40509853/t9_YueWen_40509853.jpg',unistr('诗人的心，有宇宙那么大，但却只装了风。\u000a风在悬崖落了空，她怕惊扰了在读书的你。\u000a读黄锐，读懂诗的克制和精致。\u000a《风在悬崖落了空》是青年诗人黄锐的第二部诗集，是一场诗人与不可控的时间及可控的生活的对谈。友情、爱情、亲情以及最终的别离，认同与撕裂两种生命态度，都在诗人深远、凝练、克制的笔触下得以表达。诗歌排序没有遵循固定的章法，像极了生活的无常与诗人气质的多变，呈现对生活的不同解读。\u000a全书收录百余篇诗作，读哪首，看天气，爱哪首，看心情，诗歌从来都不能只读一遍，愿你爱它。'),'文学-现代诗歌','2021-07-01 00:00:00',1,41,0,42,99,4,1,1691133705,1691133705,698.0,674,NULL,'新星出版社','9787513345552',NULL,1782398781);
INSERT INTO books VALUES('25298416','从前的我也很可爱啊','石川啄木','https://wfqqreader-1252317822.image.myqcloud.com/cover/416/25298416/t9_25298416.jpg','寂寞的时候，只能念一首石川啄木。石川啄木是天才诗人，其诗歌有清澈的忧伤，又有明快的可爱。读一首石川啄木，能读出轻轻的寂寞，也能感受淡淡的可爱。《从前的我也很可爱啊》收录了石川啄木的三部小集子包括《一握砂》《可悲的玩具》《叫子和口哨》，以及一篇谈论自己诗歌创作之路的文章《可以吃的诗》。石川啄木说：“总之歌这东西不会灭亡的。我们因了这个，也就能够使那爱惜刹那的生命之心得到满足了。”石川啄木的短歌写的都是日常之情，切身之体会，所以最能让人感同身受。“使爱惜刹那的生命之心得满足”，这是石川啄木对诗歌的感受，也是我们对石川啄木的诗歌的感受。','文学-经典作品','2019-03-01 00:00:00',2,40,2,44,100,4,1,1589451839,1589451839,652.0,1633,NULL,'北京时代华文书局有限公司','9787569922981',NULL,1782398782);
INSERT INTO books VALUES('3300080713','爱的五种语言','[美]盖瑞·查普曼','https://cdn.weread.qq.com/weread/cover/84/cpplatform_cs1rjysvneq3fi2r5q9oue/t9_cpplatform_cs1rjysvneq3fi2r5q9oue1701933444.jpg','2023年10月全新翻译修订版','个人成长-沟通表达','2023-10-01 00:00:00',1,37,0,38,96,4,1,1763174271,1763174271,899.0,4364,NULL,'中国社会出版社','9787508768816',NULL,1782398781);
INSERT INTO books VALUES('834467','在细雨中呼喊','余华','https://cdn.weread.qq.com/weread/cover/4/yuewen_834467/t9_yuewen_8344671758542700.jpg',unistr('小说以一个孩子的视角讲述了一个家庭的欢乐和苦痛，细腻地刻画了柔弱的母亲如何完成了自己忍受的一生，她唯一爆发出来的愤怒是在弥留之际；名叫孙广财的父亲又是如何骄傲地将自己培养成一名彻头彻尾的无赖，他对待自己的父亲和对待自己的儿子，就像对待自己的绊脚石；家中三兄弟的道路只是短暂地有过重叠，随即就又叉向了各自的方向。无赖的父亲、沉默的母亲、平庸的哥哥、对往事沾沾自喜的祖父……每个不起眼的小人物，都卖力于自己的人生表演。而“我”则在这一出出家庭闹剧中孤独地成长，像小动物一样观察世界，试探同类，艰难地理解家庭、爱和生命的含义。\u000d\u000a叙述者在过去、现在和将来这三个时间维度里自由穿行，将忆记的碎片穿插、结集、拼嵌完整，精妙无比，文学的光芒闪耀四射。这是一部少年心灵成长史，也是一代人的集体记忆。'),'精品小说-社会小说','2023-07-01 00:00:00',11,37,0,48,99,4,1,1700666699,1700666699,861.0,42189,NULL,'北京出版集团北京十月文艺出版社','9787530222454',NULL,1782398781);
INSERT INTO books VALUES('25314648','我曾这样寂寞生活（精装版）','维斯拉瓦·辛波斯卡','https://cdn.weread.qq.com/weread/cover/83/YueWen_25314648/t9_YueWen_25314648.jpg','《我曾这样寂寞生活》是诺贝尔文学奖获奖诗人辛波斯卡继《万物静默如谜》之后又一经典诗集。在这本诗集中，诗人用机智、迷人的声音与语调，诉说了对家人的怀念与赞美、对世间种种生活的爱、对消逝的时间与国度的迷恋、对日常和万物的诗意描摹，隐隐折射出诗人内心的丰富世界和她的寂寞生活。书中收录《告别风景》《事件的版本》《从无馈赠》《我致力于创造一个世界》《在赫拉克利特的河中》《时代之子》等80多首诗作，同时重译了《万物静默如谜》中广为流传的《一见钟情》《种种可能》《在一颗小星星下》等10余首作品，可以在不同的译文中窥见经典的韵味。','文学-现代诗歌','2018-03-01 00:00:00',5,35,0,40,69,2,1,1592562627,1592562627,721.0,751,NULL,'湖南文艺出版社','9787540484347',NULL,1782398782);
INSERT INTO books VALUES('857883','在江湖','老树绘著','https://cdn.weread.qq.com/weread/cover/37/YueWen_857883/t9_YueWen_857883.jpg','“画这画的人，心在天上游荡呢！”一份“老树画画”对这个世界的内心告白，一本极具标志性的老树式长衫人物绘画集。好玩，通透，真率；乱世绘本，绝妙好词！这是红遍微博的“老树画画”的一份回忆录，一份对画画、对审美、对这个世界的内心告白；也是一本极具标志性的老树式长衫人物画集。一图，一文，即可窥见老树完整的画中世界和画外行藏。画分七组，“日常”、“闲情”、“花犯”、“心事”、“时节”、“江湖”、“桃源”，最具标志性的老树式民国长衫人物画，加上最有味道的老树式“歪诗”，连接起来就是这个独特的长衫人物的世界，就是老树自身的世界。文有七题，以“答客问”的形式，讲述老树从画的经历、师承，谈自己的画，说自己的“诗”，字字都是“自家的思，自家的爱，自家的园子，自家的菜”。','文学-散文杂著','2015-07-01 00:00:00',3,34,20,57,100,4,1,1588872461,1588872461,746.0,923,NULL,'广西师范大学出版社','9787549567294',NULL,1782398782);
INSERT INTO books VALUES('27001575','风很幸福','王宜振','https://wfqqreader-1252317822.image.myqcloud.com/cover/575/27001575/t9_27001575.jpg',unistr('    本书是作家王宜振的诗歌集，其中包括《春天很大又很小》、《红草莓的夏天》、《一朵甜美的笑》、《高原上的向日葵》、《忧思是什么颜色》、《岁月磨小的母亲》、《空气、火焰和颜色》、《春天和我们躲猫猫》以及《云彩还没有把雨点养大》等作品。\u000d\u000a'),'童书-儿童文学','2019-08-19 00:00:00',2,32,0,34,100,4,1,1601727898,1601727898,NULL,10,NULL,'北京少年儿童出版社','9787530157503',NULL,1782398782);
INSERT INTO books VALUES('38084989','数星星的夜：尹东柱的诗','尹东柱','https://cdn.weread.qq.com/weread/cover/47/YueWen_38084989/t9_YueWen_38084989.jpg','他生于中国，死于日本。他远离故土，失了姓氏，却以笔为戈，在28年的短暂生命中，用自己民族的语言写作，以最单纯的文字，为最残酷的时代证言。本书收录了朝鲜族诗人尹东柱的91首诗歌和4篇散文，道出了在日治的黑暗年代，他对故土、人民的热爱，对独立、自由的向往，以及对生活细致入微的观察。','文学-现代诗歌','2021-05-01 00:00:00',2,32,0,34,99,4,1,1738826020,1738826020,815.0,605,NULL,'江苏凤凰文艺出版社','9787559455390',NULL,1782398781);
INSERT INTO books VALUES('25631683','麦子的盖头','胡学文','https://cdn.weread.qq.com/weread/cover/32/YueWen_25631683/t9_YueWen_25631683.jpg','麦子的丈夫马豆根在煤矿事故中受了伤，完全瘫痪不能治愈，由此引发出麦子跟马豆根和老于之间充满悬疑色彩的一场人性较量，麦子用她的坚贞和执着发现了美丽谎言背后的真相，她对未来的生活究竟会做出怎样的选择。','文学-经典作品','2019-04-01 00:00:00',6,31,0,37,100,4,1,1658908244,1658908244,735.0,49,NULL,'现代出版社','9787514376616',NULL,1782398781);
INSERT INTO books VALUES('3300020364','鲸鱼安慰了大海','燕七','https://cdn.weread.qq.com/weread/cover/83/cpplatform_qs2qlzdq7jkcd8edeywxuj/t9_cpplatform_qs2qlzdq7jkcd8edeywxuj1693963603.jpg','《鲸鱼安慰了大海》是一部诗集，收录燕七诗歌138首。燕七的诗，写尘世的悲与喜、欢聚与离别、自然与文明、苍老与天真，无不天真如初、纯净明朗。极简的语言，极朴素的情感，却有直击人心的力量。2022年，此书在小红书爆火，百万人追读、推荐，并被演员李现推荐。','文学-现代诗歌','2025-12-30 00:00:00',2,29,9,40,99,4,1,1664618413,1664618413,733.0,2243,NULL,NULL,NULL,NULL,1782398781);
INSERT INTO books VALUES('23485007','那些回不去的年少时光（套装全2册）','桐华','https://cdn.weread.qq.com/weread/cover/15/yuewen_23485007/t9_yuewen_234850071695728864.jpg','桐华经典青春怀旧小说、全文修正；全二册完美收藏。总有些时光，要在过去后，才发现它已深深刻在记忆中。20世纪的最后十年，一代人最独一无二的成长记忆，小虎队、上海滩、四大天王，每当提到这些我们都无限感慨，还有那些尘封在日记里的面孔与心事……正因为短暂，青春的散场才会显得如此弥足珍贵，重要的是，我们曾经拥有那疼痛而又快乐的青春。拿起这本书，那些属于年少的记忆瞬间扑面而来，彼时的少年已经长大，属于青春的飞扬和放肆也逐渐离我们而去，胸腔里是一颗已经斑驳的心。心中，却流淌着跨越了时光的温暖，永不消逝。','女生小说-青春言情','2013-02-01 00:00:00',1,28,0,29,100,4,1,1659420706,1659420706,901.0,14059,NULL,NULL,'9787540458966',NULL,1782398781);
INSERT INTO books VALUES('3300027195','一生只看风景：卞之琳诗集','卞之琳','https://cdn.weread.qq.com/weread/cover/5/cpPlatform_pySVX2Ze4tBexFrohQ6pdP/t9_cpPlatform_pySVX2Ze4tBexFrohQ6pdP.jpg',unistr('有华人处，就有四句《断章》！\u000d\u000a而作为新月派代表诗人，卞之琳杰作远不止《断章》。从《鱼目集》《十年诗草》《雕虫纪历》三部代表诗集，选取格式严、哲思深、词藻美的诗作69首，配插画家anusman王烁诗境插画41幅，另附诗人、评论家废名长文导读。'),'文学-现代诗歌','2022-03-01 00:00:00',4,28,0,32,99,4,1,1692174393,1692174393,805.0,218,NULL,'万卷出版有限责任公司','9787547059432',NULL,1782398781);
INSERT INTO books VALUES('3300058588','赶时间的人','王计兵','https://cdn.weread.qq.com/weread/cover/52/cpplatform_pc1qu7jf2d36xxkhy6dx1f/t9_cpplatform_pc1qu7jf2d36xxkhy6dx1f1683797322.jpg',unistr('本书作者王计兵是一个外卖员，奔跑的行程累计15万公里，相当于沿着万里长城跑15个来回。在城市穿梭的日子里，他看到更多跟他一样为生存奔波的人，外卖员、农民工、保洁员、保姆。他们匆匆忙忙，慌慌张张地奔波，却跑丢了自己的身份：既不能在城市中找到一个落脚之地，故乡和父母又在不断远去。\u000a如同一个来自底层中国的行吟诗人，王计兵记录下自己和他们的狼狈，以及作为劳动者的自尊。他写道：我也有自己独立的国度，我沸腾的血，就是我奔流不息的江河，我嶙峋的瘦骨，就是我耸立的山川。\u000a这些在赶时间的间隙，写在烟盒上、废报纸上的诗句，是来自劳动现场的民歌，生机勃勃，粗粝尖锐。有些被偶然传到网上，引发了意想不到的共鸣，单首诗歌阅读多达2000万人次。本书就是他诗歌的首次集结出版。'),'文学-现代诗歌','2023-02-10 00:00:00',3,28,1,32,99,4,1,1690769664,1690769664,877.0,5251,NULL,'台海出版社','9787516834114',NULL,1782398781);
INSERT INTO books VALUES('35172617','聪明却混乱的孩子：利用“执行技能训练”提升孩子学习力和专注力','佩格·道森 理查德·奎尔','https://cdn.weread.qq.com/weread/cover/38/yuewen_35172617/t9_yuewen_351726171695026100.jpg','本书从强化执行力、管理情绪等多个方面为父母养育聪明却混乱的孩子提供详细的育儿指导，让父母能够更好地陪伴聪明却混乱的孩子成长。儿童发展领域的研究展示，许多孩子的脑力和心力都足够完善，但在关键的执行技能方面有所缺失——这是一种思维的基本习惯，要求有组织性，保持专注，控制冲动和情绪。本书提供大量易操作、易形成习惯的方法，帮助父母分辨孩子的优势和不足，依据经科学研究证实的规律，帮助父母在教育聪明却混乱的孩子方面游刃有余，让孩子形成特定的执行技能，养成自我管理的好习惯。','教育学习-育儿','2020-09-01 00:00:00',1,28,1,30,14,2,1,1659747557,1659747557,785.0,431,NULL,'机械工业出版社','9787111663393',NULL,1782398781);
INSERT INTO books VALUES('3300025707','快乐就是哈哈哈哈哈','梁实秋','https://cdn.weread.qq.com/weread/cover/83/cpPlatform_qwnRomc1tNR5nwjojvgZUY/t9_cpPlatform_qwnRomc1tNR5nwjojvgZUY.jpg',unistr('如何在这人间，觅得快乐？\u000d\u000a智者乐水，仁者乐山。雨有雨的趣，晴有晴的妙。小鸟跳跃啄食，猫狗饱食酣睡，哪一样不令人看了觉得快乐？正如梁实秋所言：“良辰美景，赏心乐事，随处皆是。”\u000d\u000a我们寻求的快乐，不是简单的快乐，而是发自内心由衷的欢喜。\u000d\u000a精选38篇梁实秋的生活智慧散文，收录《闲暇》《旅行》《骂人的艺术》《生命与吃药》等名篇，以及《蚊子与苍蝇》《老憨看跳舞》《是热了》《父母的爱》等珍贵文章，详尽展现了一代生活家梁实秋的精神世界与生活志趣：\u000d\u000a知冷暖：一个生动的人，他有喜悦和哀愁。\u000d\u000a得自在：生活，就是要活得热热闹闹。\u000d\u000a爱世间：人生毕竟是非常可爱的啊。\u000d\u000a有态度：我对生活有诸多意见。\u000d\u000a快乐是在心里，不在别处，它是一种积极乐观的生活态度。从快乐出发，通过调动积极的情绪，用更乐观的方式去面对生活，于是快乐和满足也就产生啦！'),'文学-散文杂著','2022-08-01 00:00:00',11,27,0,38,99,4,1,1723776725,1723776725,761.0,3564,NULL,'中国友谊出版公司','9787505754942',NULL,1782398781);
INSERT INTO books VALUES('858485','外婆的道歉信','弗雷德里克·巴克曼','https://cdn.weread.qq.com/weread/cover/86/YueWen_858485/t9_YueWen_858485.jpg','七岁的爱莎有个古怪又疯狂的外婆，会埋伏在雪堆里吓唬邻居，把重要的事情记在墙上因为墙不会丢，半夜从医院溜出来带着爱莎翻进动物园，基本上想干什么就干什么。这个四处惹麻烦的外婆却是爱莎最好的朋友，也是她心中的超级英雄。但就算是超级英雄，也有失去超能力的一天。外婆不幸得了癌症去世，留给爱莎一项艰巨的任务——将外婆的道歉信送给她得罪过的九个邻居。这一趟送信之旅让爱莎渐渐发现：外婆和邻居们的故事，比她听过的所有童话都更加精彩。巴克曼让我们爱上这个活泼过头的外婆，也重新爱上生活。随书附赠一封神秘道歉信，读完故事之前绝不要打开。这是一个关于爱、原谅和守护的故事，在合上书之后很久都难以忘记。','精品小说-治愈小说','2017-05-01 00:00:00',10,27,0,37,100,4,1,1652365548,1652365548,856.0,25691,NULL,'天津人民出版社','9787201116693',NULL,1782398781);
INSERT INTO books VALUES('22305960','哼哈二将','周锐','https://wfqqreader-1252317822.image.myqcloud.com/cover/960/22305960/t9_22305960.jpg','本书包含《哼哈二将》《特别通行证》《九重天》《森林手记》《明星和他的四个替身》《东西木兰村》《无姓家族》《扣子老三》等20余篇中短篇幽默童话，奇幻的想象、幽默的语言、跌宕起伏的情节，让小读者们在阅读的过程中既能收获快乐，又能体悟其中蕴含的哲理。','童书-儿童文学','2018-04-01 00:00:00',1,26,0,27,100,4,1,1559961891,1559961891,NULL,3,NULL,'山东友谊出版社','9787551615402',NULL,1782398782);
INSERT INTO books VALUES('23606759','我愿意舍弃一切，以想念你终此一生：朱生豪情书精选','朱生豪','https://wfqqreader-1252317822.image.myqcloud.com/cover/759/23606759/t9_23606759.jpg','1932年秋，朱生豪在之江大学与宋清如因“诗”相识，随后因志趣相投，便相知相许。1933年，朱生豪毕业后到上海工作，两人便两地分隔，开始近十年的苦恋之旅，以书信交流情感，倾诉相思。在信中，朱生豪无话不谈，畅聊人生、倾诉思念之情、切磋诗词、交流喜怒哀乐、相互鼓励、翻译莎剧……贯穿始终的主线是对宋清如无限的思念和爱慕。朱生豪的书信，绝对适合在阴冷的冬日夜晚，暖心暖肺而又更坚定心之所向，是情人更是益友，被感动到触及灵魂，有一种说不出的好。本书精选了朱先生的188封情书，这些情书无不展示了他当时写作的手迹和心迹，更让我们重新认识了一个立体的栩栩如生的朱生豪，这或许是他的同学、友人都不曾认识到的，因他在旁人面前不爱开口，所有的幽默、聪敏与遐思，只对他亲爱的“好友”宋清如讲。','文学-散文杂著','2015-01-01 00:00:00',6,26,0,32,28,3,1,1588843446,1588843446,760.0,249,NULL,'中国文史出版社','9787503454158',NULL,1782398782);
INSERT INTO books VALUES('25856501','且听风吟','[日]村上春树','https://wfqqreader-1252317822.image.myqcloud.com/cover/501/25856501/t9_25856501.jpg','“不存在十全十美的文章，如同不存在彻头彻尾的绝望。”《且听风吟》是村上春树的成名处女作，是“我与鼠”的“青春三部曲”系列开端之作。本书讲述了回到故乡海边度假的少年“我”与愤世嫉俗的青年“鼠”厮混了一整个夏天的故事。在此期间，“我”捡到了一个醉酒女孩。俩人因奇妙的缘分而互相吸引，并产生了一些朦胧的情感。但“我”寒假归来之后，却发现女孩早已不知去向，短暂的恋情莫名结束，徒留“我”一人面对人生前路的迷惘，怅愁无限。','文学-外国文学','2018-06-01 00:00:00',8,25,0,33,100,4,1,1580950764,1580950764,648.0,7387,NULL,'上海译文出版社','9787532777631',NULL,1782398782);
INSERT INTO books VALUES('27350612','上一堂朴素的语文课','韩素静','https://cdn.weread.qq.com/weread/cover/30/YueWen_27350612/t9_YueWen_27350612.jpg','《上一堂朴素的语文课》是“河南省最具影响力教师”韩素静在长期亲身教学和大量听评课基础上用心写就的总结和反思。书中有对源自教学一线的大量课例的翔实记录和精心剖析，涉及新授课、讲评课、听读课等多种课型和多个教学环节，通过从不同角度对不同走向的课例进行解读，挖掘其精妙与遗憾之处背后的原因，并对如何实现高效语文课堂提出了具体而有效的策略，对广大一线教师具有指导和借鉴作用。','教育学习-教育','2015-09-01 00:00:00',0,25,0,25,29,2,1,1674378264,1674378264,877.0,588,NULL,'华东师范大学出版社','9787567540057',NULL,1782398781);
INSERT INTO books VALUES('3300049180','小巷人家（同名影视原著）','大米','https://cdn.weread.qq.com/weread/cover/32/cpplatform_wxxo2bpco5xlabw5b7y38v/t9_cpplatform_wxxo2bpco5xlabw5b7y38v1705993399.jpg',unistr('20世纪70年代末，苏州棉纺厂家属区一条小巷里住着庄家、林家、吴家三个家庭，恢复高考、知青返城和改革开放等时代变迁让三家家长和孩子们的命运都发生了翻天覆地的变化。\u000a长辈们先后随时代变迁，或调动或留职停薪，各寻出路。\u000a晚辈们随时代变迁而拼搏。\u000a庄家长子庄图南考入同济建筑系，但国家统包统分，他无法决定自己的毕业去向，同时，他的暗恋对象李佳为了留沪，放弃了两人间的感情萌芽。数年后，两人在浦东新区的工地上重逢......\u000a次女庄筱婷考入上海交通大学，毕业后和男友林栋哲两地分居，两人瞒着家人偷偷领了结婚证......\u000a外甥儿向鹏飞是知青子女，他孤身一人回苏州上学，但高考落榜......\u000a社会青年李一鸣和宋向阳在两次落榜后，分别成为了个体工商户和乡镇企业技术员......\u000a邻居吴家的长女吴姗姗受家庭环境拖累，变得争强好胜......\u000a吴家继女张敏就读纺织职高，毕业时恰逢棉纺厂人员精简，不再招收职高或技校文凭的职工子弟......\u000a一方小院，袅袅炊烟，\u000a几家人、两代人的故事。'),'精品小说-年代小说','2023-02-01 00:00:00',10,25,0,35,100,4,1,1723299014,1723299014,914.0,47199,NULL,NULL,NULL,NULL,1782398781);
INSERT INTO books VALUES('23562424','为何家会伤人（百万畅销纪念版）','武志红','https://cdn.weread.qq.com/weread/cover/66/YueWen_23562424/t9_YueWen_23562424.jpg','本书为心理学经典畅销书《为何家会伤人》百万畅销纪念版。该书出版十余年来，在读者中引起持久震荡，深深触动和改变了千万人，堪称中国家庭问题第1书。本书中，作者细致入微地揭示出中国家庭的运行机理，解读你我的情感模式，用最温暖有力的文字贴着当下读者的心，凭借25年行业经验，带领为家庭关系所困的万千读者一起踏上自我治愈与寻求幸福和自由的旅程。','心理-心理学应用','2018-11-01 00:00:00',1,24,0,25,17,2,1,1660785273,1660785273,744.0,6095,NULL,'北京联合出版公司','9787559613196',NULL,1782398781);
INSERT INTO books VALUES('26639909','绿色的书简（百所名校校长推荐版）','张晓风','https://wfqqreader-1252317822.image.myqcloud.com/cover/909/26639909/t9_26639909.jpg',unistr('    收录著名作家张晓风经典散文作品，包括《只因为年轻啊》《我交给你们一个孩子》《晴日手记》《近水》《一半儿春愁，一半儿水》等文学价值极高的文章。张晓风的作品往往洋溢着一种空灵而温暖人心的情感，主题内容包括自然的美丽和对万物的敬仰，家的温馨和对亲人的牵挂，生活的美好和对生命的珍惜，有温暖，有感恩，有领悟，有释然。余光中称其为“华语世界一支亦秀亦豪的健笔”，蒋勋更盛赞她的文字像沸水中复活的春茶。\u000d\u000a'),'文学-经典作品','2019-10-01 00:00:00',0,24,0,24,99,4,1,1689385545,1689385545,838.0,225,NULL,'北京联合出版公司','9787559636300',NULL,1782398781);
INSERT INTO books VALUES('926287','给孩子的截句','蒋一谈','https://wfqqreader-1252317822.image.myqcloud.com/cover/287/926287/t9_926287.jpg','截句是一种源自古典，具有现代诗歌精神的诗歌文体，融合了截拳道大师李小龙“简洁、直接、非传统性”的美学理念，强调诗意的瞬间生发，没有诗歌题目，且诗句在四行之内完成。《给孩子的截句》是“文坛鬼才”蒋一谈献给孩子们的一份礼物。书中精选了82首截句，题材包含自然万物、日常生活、内心情感等，诗中充满无处不在的幽默灵动，以及细致入微的观察和表达。每首截句配有唯美、趣味的彩绘插图，以图文并茂的形式营造了一个诗意空间，贴近孩子的心灵，给孩子艺术的熏陶和美的享受。','童书-儿童文学','2017-07-01 00:00:00',1,24,0,25,100,4,1,1588791752,1588791752,700.0,909,NULL,'中国画报出版社','9787514615319',NULL,1782398782);
INSERT INTO books VALUES('929782','半小时漫画世界史','陈磊','https://wfqqreader-1252317822.image.myqcloud.com/cover/782/929782/t9_929782.jpg','《半小时漫画世界史》是300万粉丝大号“混子曰”创始人陈磊（笔名：二混子）推出的全新作品！《半小时漫画世界史》，比《半小时漫画中国史》更有趣、更爆笑、更丰富、更好看！《半小时漫画世界史》，其实是一本严谨的极简世界史！作者曾获前央视主持人张泉灵鼎力推荐！《半小时漫画世界史》内容摘选自公众号旗下的Stone历史剧栏目，该栏目累计阅读量高达3亿，平均阅读量为60万每一页都有历史段子，每三秒让你笑翻一次，而你在笑出腹肌的同时，不知不觉已经通晓历史。仅仅通过手绘和段子，二混子就捋出清晰的历史大脉络：简到崩溃的极简欧洲史、美国往事三部曲、一口气就能读完的日本史、肌肉猛男斯巴达300勇士…','历史-世界史','2018-04-01 00:00:00',2,24,1,27,100,4,1,1563024710,1563024710,807.0,31266,NULL,'江苏凤凰文艺出版社','9787559418111',NULL,1782398782);
INSERT INTO books VALUES('23562223','不装','王小柔','https://wfqqreader-1252317822.image.myqcloud.com/cover/223/23562223/t9_23562223.jpg',unistr('    王小柔最新段子《不装》延续以往“把日子过成段子”叙事风格，全书文字与日常息息相关的话题直抵人心，涉及话题从都市白领的职场生活到从侧面观察教育及亲子关系，从互联网包裹的游戏人生到闺密的相处。每一个话题由头都是从大众关注点出发，不失热度，把最真实的百姓日子用风趣幽默的态度呈现出来。\u000d\u000a'),'文学-散文杂著','2018-08-15 00:00:00',2,23,0,25,50,3,1,1598539486,1598539486,726.0,135,NULL,'人民文学出版社','9787020138968',NULL,1782398782);
INSERT INTO books VALUES('3300135523','愿你可以自在张扬（罕见病患者的生命赞歌）','刘开心','https://cdn.weread.qq.com/weread/cover/53/cpplatform_cvrw6wvyrp5zmpkbprxgea/t9_cpplatform_cvrw6wvyrp5zmpkbprxgea1740729379.jpg','无关苦难，她用文字和画笔讲述爱与生命讲给你听。我是一个''潜伏’在健康人群体之中的罕见病人--你可以这样定义我。又或者，你可以慢慢认识我，从这本书开始。','文学-散文杂著','2025-02-05 00:00:00',2,23,1,26,38,4,1,1766205965,1766205965,901.0,4147,NULL,'北京联合出版有限责任公司','9787559681683',NULL,1782398781);
INSERT INTO books VALUES('816114','到你心里躲一躲','汤汤','https://wfqqreader-1252317822.image.myqcloud.com/cover/114/816114/t9_816114.jpg','《到你心里躲一躲》是汤汤的童话合集。作者用灵动清澈、简洁干净、略带幽默的语言将执着的等待、对誓言的坚守、坚韧无私的友谊等等对儿童来说抽象又空洞的主题，在温暖轻松的叙述中予以准确的表达。作品纯真而宽容，饱含爱意与怜悯，带有奇异的光芒、暖暖的感动和清甜的味道。汤汤的童话是当下儿童不可多得的阅读良品，它能够传达给儿童一种向善的正能量，同时娟秀的文字风格对培养儿童的文学修养也有一定帮助。','童书-儿童文学','2015-09-01 00:00:00',0,22,0,22,100,4,1,1592656001,1592656001,809.0,136,NULL,'春风文艺出版社','9787531348658',NULL,1782398782);
INSERT INTO books VALUES('23199285','故事团团转','幾米','https://wfqqreader-1252317822.image.myqcloud.com/cover/285/23199285/t9_23199285.jpg','这本书的制作过程、辛苦程度完全不下于幾米的绘本，三年前开始谈好要做这本书，研究了架构，两年多前开始与幾米透过问答访谈方式记录下他的创作思考。每隔两周我们就在咖啡厅里面讨论、记录，幾米常常笑说：“怎么办？我都忘了。”两年多断断续续整理，结果整理出来的内容语气太像访谈，于是幾米又全盘重新写来。认识幾米的朋友应该知道，他宁愿画一百张图换取要他写一百个字的任务，就知道这是什么样等级的辛苦。当编辑的一边要鼓励，一边要协助整理，比编绘本辛苦太多太多，喔不，编绘本是另一种等级的可怕。但就像幾米说的，创作者总是自找麻烦一样，希望这本我们彼此摧残找自己麻烦的小书，能让大家更了解、更喜欢绘本，那一切就值得了。','人物传记-艺术家','2018-10-01 00:00:00',1,21,7,29,100,4,1,1590397106,1590397106,760.0,574,NULL,'九州出版社','9787510873416',NULL,1782398782);
INSERT INTO books VALUES('25170964','瞧！这样的语文有意思','蒋军晶','https://wfqqreader-1252317822.image.myqcloud.com/cover/964/25170964/t9_25170964.jpg','本书是一名小学语文特级教师十余年教学经验的感悟结晶。与一般教师单单是教学经验的总结不同，蒋军晶的语文阅历以及他的思考使他关照的是整个语文生态的生活问题。如何让语文变得有意思，让生活在语文生态中的师生们变得快乐，是他思考的核心。本书致力于建立一种这样的情景模式：语文不再是一种枯燥的学科，而成为师生们乐于沉浸其中的有意思的生活方式。','教育学习-教育','2017-04-01 00:00:00',1,21,0,22,13,2,1,1674620703,1674620703,914.0,722,NULL,'浙江大学出版社','9787308165778',NULL,1782398781);
INSERT INTO books VALUES('26001263','人鼠之间（读客三个圈经典文库）','约翰·斯坦贝克','https://cdn.weread.qq.com/weread/cover/78/YueWen_26001263/t9_YueWen_26001263.jpg','当你成为大人的一瞬间，也就读懂了人鼠之间。诺贝尔文学奖获奖作品，真正的美国国民小说！美国高中生十大阅读经典之首。欧美国家高中必修课书目。《卫报》100部人生经典。“一百部最好看的小说”（全美图书馆馆员票选）“二十一世纪最具挑战性之书”（全美图书馆联合会）“英国人最喜爱的100部小说”（英国BBC）托福考试推荐阅读书目。在人类文学史上，《人鼠之间》借一个短小精悍的寓言故事，写透人存在于世的美好与残酷，是二十世纪西方文学史上里程碑式的经典之作！共发行有两百多种语言版本，引发过美国出版史上激烈的版权争夺战。一段金子般的友谊，一个海市蜃楼般的梦想。流浪工人乔治和伦尼是一起长大的好朋友。心智像小孩的伦尼不断惹祸，乔治只好带着他不断逃亡。两人一直梦想拥有自己的一块地，在那里种苜蓿、养伦尼心爱的兔子，不用再被驱逐。可当他们终于停止流浪，梦想也到了尽头……','文学-外国文学','2019-05-01 00:00:00',8,21,0,29,100,4,1,1587725482,1587725482,796.0,4265,NULL,'江苏凤凰文艺出版社','9787559437396',NULL,1782398782);
INSERT INTO books VALUES('28416170','傻子的一生','[日]芥川龙之介','https://wfqqreader-1252317822.image.myqcloud.com/cover/170/28416170/t9_28416170.jpg','灵魂的扭曲，精神的悽惨，串连起生活的起伏、失败与自嘲的回忆……本书集中收录了《侏儒的话》、《傻子的一生》、《西方人》、《续西方人》等十八篇芥川龙之介晚期的作品及遗稿。形式风格丰富多彩，内容大异其趣，展现了作者灵动多变的创作才华。《傻子的一生》是芥川龙之介的短篇小说遗稿，芥川自杀后，由友人久米正雄整理后发表。这篇小说实际上影射了芥川的一生，其间包含了他对自身的回顾、对家人的思考、对当时社会发展的不安。《侏儒的话》是芥川的随笔与评论，堪称其格言代表作，以智慧诉说心情，阐述了他对艺术和人生的看法，是有关人生领悟和社会议论之作，形式虽是随笔，但又以侏儒代言，似带上几分小说的风格。《西方人》与《续西方人》是芥川在自杀前留下的最后的遗著，探讨了芥川心目中的基督的形象，揭示了基督教在芥川短暂一生中对他本人和创作方面的影响。','文学-经典作品','2019-09-01 00:00:00',4,21,0,25,100,4,1,1585384129,1585384129,750.0,100,NULL,'百花文艺出版社','9787530675656',NULL,1782398782);
INSERT INTO books VALUES('3300119345','我应该，我要，我愿意（女性主义诗人焦野绿 全新女性力量诗集）','焦野绿','https://cdn.weread.qq.com/weread/cover/67/cpplatform_scnnhjahwbmpevtkpgcaae/t9_cpplatform_scnnhjahwbmpevtkpgcaae1730774980.jpg',unistr('本书是专治焦虑的95后女性主义诗人、小红书头部青年诗人焦野绿的全新女性力量诗集《我应该，我要，我愿意》，全书收录212首最新原创诗歌。\u000a这部作品中，焦野绿透过女性诗人细腻的视角，立足日常，为普通人发声。\u000a全书共五个章节，从开始面对心中的呐喊走向成长与勇气，从学会拥抱世界到接受爱和自己，每一首诗都是她人生中往前行走的足迹。\u000a涂鸦是焦野绿创作的独特方式，作为95后，她脱离传统诗歌的写作框架，用年轻的语言，前卫的方法，把诗歌带到大街小巷，让诗意和真实生活碰撞。在这本书里，读者与作者同频，在诗句之间感受被理解、被看到、被表达的喜悦；他们关心世界，更关心自己。\u000a“这天地广阔，有一半是我的”\u000a“我会踩着时间的骨头，成为勇者”\u000a“暂时只爱自己，停止招待过客”\u000a“我应该，我要，我愿意”\u000a……\u000a焦野绿把年轻人那些迷茫、焦虑以及如鲠在喉的痛苦都写下来，在新颖、轻盈的表达中给人治愈的力量：我要用尽全力，不让自己成为别人。'),'文学-现代诗歌','2024-05-01 00:00:00',0,21,0,21,85,2,1,1778918826,1778918826,787.0,358,NULL,'湖南文艺出版社','9787572616457',NULL,1782398781);
INSERT INTO books VALUES('857264','大萝卜和难挑的鳄梨','[日]村上春树','https://cdn.weread.qq.com/weread/cover/10/YueWen_857264/t9_YueWen_857264.jpg',unistr('《大萝卜和难挑的鳄梨》收录村上春树的52篇风趣随笔，配以画家大桥步的52幅美丽插画，村上以幽默的语言写下蔬菜的心情、关于大萝卜的怪谈、挑选好吃鳄梨的超能力、和海豹接吻的感觉……囊括了形形色色的有趣话题，被誉为“日本好喝的乌龙茶”。\u000a《大萝卜和难挑的鳄梨》中有有趣、真实的村上春树，平淡得恰到好处的笔触，描绘出耐人寻味的生命细节，让人发现在日常生活中忽视的有趣的东西，找回遗忘许久的自己。'),'文学-散文杂著','2014-10-01 00:00:00',12,20,1,33,100,4,1,1583053557,1583053557,741.0,4250,NULL,'南海出版公司','9787544274050',NULL,1782398782);
INSERT INTO books VALUES('918330','找个人，一起去破坏这无聊的世界','梅晨斐','https://cdn.weread.qq.com/weread/cover/16/YueWen_918330/t9_YueWen_918330.jpg','作为一个地地道道的理科生，梅晨斐最爱的却是写字。他是《如何定义孵化器》的作者，也是一年读49本书、看124部电影、书写354篇文章的“文艺青年”。《找个人，一起去破坏这无聊的世界》写得正是梅晨斐的“小心思”，在不经意间，总有一些文字涌上心头，它们或许不成段落、不成文章，但是这一个个跳跃的字符，却组成了一篇篇让人心动的俳句。这本书，藏着可以打动你的小秘密。','文学-散文杂著','2017-09-01 00:00:00',0,20,5,25,100,4,1,1585356802,1585356802,553.0,2183,NULL,'杭州蓝狮子文化创意股份有限公司',NULL,NULL,1782398782);
INSERT INTO books VALUES('25028541','但愿呼我的名为旅人：松尾芭蕉俳句300','松尾芭蕉','https://wfqqreader-1252317822.image.myqcloud.com/cover/541/25028541/t9_25028541.jpg','俳句是一种极具日本特色、极为重要的文学类型，而松尾芭蕉则被誉为“俳圣”。他是古典俳句的第一位大师，也是将俳句艺术推至最高峰的俳人。芭蕉之于俳句，正如杜甫之于唐诗。芭蕉的俳句，既承袭了汉诗、日本和歌的古典传统，又毫不避讳掺杂日常俗语，深得滑稽精髓，极富自由创作的精神。芭蕉擅长捕捉日常中的绝对孤独、寂静时刻中的声香之色，如晨昏树叶被照得灼热时的香气，又如蛙跃进古池时的幽冷水声。诗人借此展示在永恒流动的时间中对自然的热烈一瞥。后世日式文学的物哀精神，对自然万物的灵敏感性，多受其影响。在其笔下，俳句的雅与俗的调和达到了前所未有的高度。本书从芭蕉一生创作的俳句中遴选三百余句，按年代先后编排并附上原文、读音及简注，以助鉴赏。','文学-现代诗歌','2019-02-01 00:00:00',0,19,0,19,100,4,1,1592648429,1592648429,463.0,1044,NULL,'北京联合出版公司','9787559628534',NULL,1782398782);
INSERT INTO books VALUES('42766056','力量从哪里来：面对每一个不敢','李一诺','https://wfqqreader-1252317822.image.myqcloud.com/cover/56/42766056/t9_42766056.jpg','我是李一诺。我经常被问到的问题是：“你怎么可以做成那么多事？”人们只看到光鲜亮丽的标签，其实真实生活都是一地鸡毛。我的起点，和大家一样，是从一个个“不敢”、一个个“不会”开始的：初入职场，不敢开口，不敢成功，不会当领导。职场小成，不敢要孩子，不会教育孩子，生活与工作无法平衡。人到中年，不敢转场，不敢做梦，不敢想“大问题”。生活里琐碎的烦，不会面对；生活的挑战，不敢“臣服”。最终，知道内心的障碍，但不敢面对真实的自我。所以每一件看上去“做成”的事，背后是十件、百件“没做成”的事。面对未知，我会恐惧；面对竞争，我会犹豫；面对孩子，我会焦虑。要想走出来，别无他路，只有从不敢到面对。一旦面对，你就会知道，等待皇冠，并不能等来事业成功；放低自己，并不能启发他人；使自己渺小，并不能改变世界；不敢发光，就没有真正活过。回看我的轨迹，是一次次不得不“面对”每一个“不敢”后，得到力量的旅程。这本书虽然讲的是我的故事，但对你肯定不陌生。希望你也能在这里找到自己的内心金矿、光和力量。','个人成长-人生哲学','2021-12-01 00:00:00',0,19,0,19,15,2,1,1751466583,1751466583,894.0,5942,NULL,'中信出版集团','9787521736533',NULL,1782398781);
INSERT INTO books VALUES('449751','只有医生知道！1','张羽','https://cdn.weread.qq.com/weread/cover/94/YueWen_449751/t9_YueWen_449751.jpg','这是一本有关女性的百科全书。抱着“大医治未病”的愿景，作者通过一个个生动的故事，在幽默而不乏温情的叙述中，力图帮助女性真正了解自己的身体，懂得爱护并且知道如何爱护自己，让女性真正掌控自己的身体、命运和生活的方向，不再受到无谓的伤害。','医学健康-两性','2013-01-01 00:00:00',5,19,0,24,50,2,1,1613289121,1613289121,826.0,7938,NULL,'江苏人民出版社','9787214090065',NULL,1782398782);
INSERT INTO books VALUES('519185','长相思（赵丽颖、杨洋主演）','桐华','http://wfqqreader-1252317822.image.myqcloud.com/cover/185/519185/t9_519185.jpg','同名电视剧由赵丽颖、杨洋主演，2018年即将开拍。桐华继《大漠谣》《云中歌》《曾许诺》后历经三年创作，再现上古时代瑰丽多姿的爱情神话。写不尽的儿女情长，说不完的地老天荒，最恢宏的画卷，最动人的故事，最浩大的恩怨，最纠结的爱恨，尽在桐华《长相思》。','精品小说-情感小说','2013-03-01 00:00:00.0',1,19,0,20,100,4,1,1532877499,1532877499,925.0,2065,NULL,'湖南文艺出版社','9787540460075',NULL,1782398782);
INSERT INTO books VALUES('22305962','小猪照镜子','周锐','https://wfqqreader-1252317822.image.myqcloud.com/cover/962/22305962/t9_22305962.jpg','本书包含《口袋里的爸爸妈妈》《一百颗树》《不一样的眼泪》《小猪照镜子》《老亮着的黄灯》《红脸和白脸》等50余篇幽默的短篇童话，分为成长篇、奇幻篇、友谊篇、社会篇、智慧篇五部分，奇幻的想象、幽默的语言、跌宕起伏的情节，故事虽短，但每一篇都很精彩，读过之后小读者们肯定会有不小的收获呢！','童书-儿童文学','2018-04-01 00:00:00',1,18,0,19,100,4,1,1559443975,1559443975,NULL,4,NULL,'山东友谊出版社','9787551615433',NULL,1782398782);
INSERT INTO books VALUES('230107','白夜行','东野圭吾','https://cdn.weread.qq.com/weread/cover/1/yuewen_230107/t9_yuewen_2301071682244014.jpg','1999年，东野圭吾41岁正值盛年，写作出道已14年，在笔力、技巧、体力和雄心上都炉火纯青，于是洋洋洒洒写出了这部鸿篇巨制《白夜行》。这种规模宏大的长篇作品在职业作家一生的创作中极为罕见，完成后基本都被视为生涯代表作。《白夜行》一经推出即成为东野圭吾的长篇小说代表作，被万千书迷视为东野圭吾作品中的无冕之·王，畅销至今。《白夜行》中文版发行量超600万册，和《嫌疑人X的献身》《恶意》《解忧杂货店》并称为东野圭吾四大杰作。','精品小说-悬疑推理','2017-07-21 00:00:00',8,18,1,27,100,4,1,1576378133,1576378133,897.0,177993,NULL,'南海出版公司','9787544291163',NULL,1782398782);
INSERT INTO books VALUES('3300030955','命运','蔡崇达','https://cdn.weread.qq.com/weread/cover/46/cpPlatform_tEnsXcTvcuE69ZuvviMknD/t9_cpPlatform_tEnsXcTvcuE69ZuvviMknD.jpg',unistr('《命运》是蔡崇达继《皮囊》之后，时隔八年潜心创作的长篇小说。\u000d\u000a《皮囊》里的那句“皮囊是拿来用的，不是拿来伺候的。”正是出自《命运》的主人公，阿太之口。《命运》以九十九岁的她一生的故事为主线，串联起福建闽南沿海小镇几代人的人生故事、命运选择与时代浮沉。\u000d\u000a全书以阿太的五段回忆，切入时间长河中人们不得不直面的一个个本质命题：\u000d\u000a层层浪：你们就此没有过去，只有将来——\u000d\u000a当原本稳固的活法被打碎，给人庇护的传统秩序被割裂，陷入巨大无常中的一个个单薄的人，要如何活下去？内心的安宁要放置在何处？\u000d\u000a海上土：灵感是浮游在海上的土——\u000d\u000a羁绊和意义是人心灵的压舱石，当生活的浪头打过来时不至于被掀翻。阿太生命中那些失去了压舱石的人，被命运一个个顺水推舟地带走了。而此时的她，尚只有十六岁。\u000d\u000a田里花：想结果的花，都早早低头——\u000d\u000a背负着“无子无孙无儿送终”的命运预言，她成了亲，有了婆家与丈夫，抱养了孩子。但见过命运的人会明白，命运的激流从未停止，人在其中并不知晓，哪一次告别，就是诀别。\u000d\u000a厕中佛：腐烂之地，神明之所——\u000d\u000a时代的巨浪之下，如何守住内心的清明与信仰？这世上容易的活法，就是为别人而活。而如果那人恰好也是为你而活，那么日子再苦，也过得像地瓜一样甜了。\u000d\u000a天顶孔：要么入土为安，要么向天开枪——\u000d\u000a阿太的故事走到了落幕时分，死亡成了她亲密的旧友。她终是生下了自己的命运，成为自己命运的母亲。这人间她来过，她永不再回。'),'精品小说-治愈小说','2022-09-01 00:00:00',1,18,0,19,26,2,1,1751255807,1751255807,932.0,42319,NULL,'浙江文艺出版社/广州出版社','9787533969608',NULL,1782398781);
INSERT INTO books VALUES('826214','悲哀也该成人了','严力','https://wfqqreader-1252317822.image.myqcloud.com/cover/214/826214/t9_826214.jpg','《悲哀也该成人了》收录了严力从1970年代到2015年的诗歌70首。每一首都是严力各个时期的代表作。','文学-现代诗歌','2016-05-01 00:00:00',2,18,0,20,100,4,1,1586226633,1586226633,532.0,190,NULL,'浙江文艺出版社','9787533944704',NULL,1782398782);
INSERT INTO books VALUES('40740496','素食者【2024诺贝尔文学奖得主】','[韩]韩江','https://cdn.weread.qq.com/weread/cover/54/yuewen_40740496/t9_yuewen_407404961722245314.jpg','为了逃避来自丈夫、家庭、社会和人群的暴力，她决定变成一棵树。在英惠的丈夫郑先生的眼中，“病”前的英惠，是个再普通不过的女子：不高不矮的个头、不长不短的头发，相貌平平，着装一般，温顺、平淡、文静。正如他所希望的那样，英惠完美地扮演了平凡妻子的角色——料理家务，伺候丈夫，就像千千万万的传统妇女一样。','精品小说-社会小说','2021-09-01 00:00:00',10,17,0,27,99,4,1,1755052245,1755052245,798.0,71848,NULL,'四川文艺出版社','9787541160868',NULL,1782398781);
INSERT INTO books VALUES('43229346','抱着你和人间','苍白','https://cdn.weread.qq.com/weread/cover/71/YueWen_43229346/t9_YueWen_43229346.jpg','《抱着你和人间》此书是一本诗文集，包括90首现代诗，3篇短篇故事。诗歌内容主题广泛，情感，成长，生活，哲理等方面均有涉及。所选诗歌作品均在网络上获得读者认可。短篇故事分别以亲情，友情，爱情为主题，表达伤痛或诱惑下的人们对真情的留恋与向往，悲中有喜，结局完满，一定程度上具有抚慰人心的作用。诗文主要表达了作者对各种人物心灵的理解与同情，用充满个性色彩的语言，富有故事性的情节，生动展示出一个又一个人物鲜活而不为人知的内心与情感。感染力极强，同时也能给青年人思考和启迪。','文学-现代诗歌','2020-12-01 00:00:00',1,17,1,19,99,4,1,1690206242,1690206242,811.0,639,NULL,'中国友谊出版公司','9787505750425',NULL,1782398781);
INSERT INTO books VALUES('3300070952','看见孩子','贝姬·肯尼迪','https://cdn.weread.qq.com/weread/cover/51/cpplatform_59zd8bsvew2haapnupon1r/t9_cpplatform_59zd8bsvew2haapnupon1r1694596495.jpg','这是一本可以奠定美好亲子关系基础、改变家庭运作方式的全新教养力作。无论你是想让蹒跚学步的孩子平静下来，还是让十几岁的孩子敞开心扉，孩子各个年龄段让你头疼的养育问题书里都有答案。推荐给新手妈妈、二胎妈妈，还有每一位间歇性育儿崩溃的家长。又是被孩子搞砸的一天，如果你正在经受育儿焦虑，在育儿的重压下挣扎，如果你曾经无数次想要停止向孩子发火，重拾养育的信心，成为更有力量的父母，那么你都应该看看这本书。本书的核心理念是看见孩子的内在美好，看见我们自己的好，只要理解了孩子的内心需求，改善的就不仅仅是孩子的行为，还有整个家庭的运转和彼此的感情。书中不仅分享了贝姬博士的10个育儿准则，还通过40多个案例，教会家长应对一系列的教养难题，包括：孩子乱发脾气、二胎矛盾、撒谎、缺乏自信、畏难、害羞等等。','教育学习-育儿','2023-06-01 00:00:00',0,16,0,16,17,2,1,1747443420,1747443420,930.0,4632,NULL,'中信出版集团','9787521755459',NULL,1782398781);
INSERT INTO books VALUES('36829046','诗经绘','胡永凯绘 易中天译','https://cdn.weread.qq.com/weread/cover/18/YueWen_36829046/t9_YueWen_36829046.jpg','《诗经》，中国诗歌的源头。2500年来，它在诉说些什么？“摽有梅，其实七兮！求我庶士，迨其吉兮”是女孩盼望情郎尽快迎娶之歌：熟了的梅子往下掉，枝头只剩六七成。熟了的梅子往下掉，枝头只剩二三成。熟了的梅子往下掉，枝头一个都不剩。你要求婚就快点来，磨磨蹭蹭急死个人……（易中天译）孔子说，诗经就是“思无邪”。诗经是民歌，是我们普通人的歌，是2500年前，我们心底曾经回荡的声音。《诗经绘》由画家胡永凯作画，易中天译诗。这一次，加起来150岁的两个老小孩，要用光影和文字，为我们重现2500年前中国人的无邪记忆。','文学-古代诗词','2021-03-01 00:00:00',3,16,0,19,98,4,1,1723947181,1723947181,732.0,217,NULL,'上海文艺出版社','9787532178322',NULL,1782398781);
INSERT INTO books VALUES('920149','神的家里全是人','张执浩','https://cdn.weread.qq.com/weread/cover/27/YueWen_920149/t9_YueWen_920149.jpg',unistr('作者旨在通过本书的书写和40位诗人的介绍，传达诗歌之于当下的两层含义：一方面诗歌依然是我们这个愈来愈世俗化的国度里惟一具有神性的艺术载体，具有拯救世事人心的奇妙力量；另一方面，从事现代汉诗写作这项工作的人已经不再具有神秘性，诗歌的世俗化倾向既拓展了诗歌的内部空间，又让这个空间显得过于杂芜和凌乱，亟需反复梳理，才能保持它应有的格局和活力。本书即是一种梳理，遴选出的40位诗人，极具创作力和可读性。\u000a'),'文学-散文杂著','2017-05-01 00:00:00',0,16,0,16,100,3,1,1613440390,1613440390,669.0,97,NULL,'江苏凤凰文艺出版社','9787559401786',NULL,1782398782);
INSERT INTO books VALUES('925764','午夜蝴蝶：胡学文中短篇小说选','胡学文','https://wfqqreader-1252317822.image.myqcloud.com/cover/764/925764/t9_925764.jpg',unistr('    《午夜蝴蝶：胡学文中短篇小说选》收录了胡学文近年中短篇小说十部，其中，中篇四部，短篇六部。在这十部小说中，既有对乡村人物命运的追寻，又有对城市边缘群体的书写，既是此时的，也是彼时的，既是敞开的，又是隐秘的。《午夜蝴蝶》写一个人午夜的遭遇，《牙齿》写一对男女另类的婚姻，《同谋》写潜伏在生活角落中无处不在的阴谋，《我的婚姻生涯》则是写在混乱与秩序中的生存。所有的指向均不相同，但都关乎人生的困境。\u000a'),'文学-经典作品','2016-01-01 00:00:00',0,16,0,16,46,2,1,1587565437,1587565437,869.0,24,NULL,'中国言实出版社','9787517117018',NULL,1782398782);
INSERT INTO books VALUES('23863103','猴子·罗汉池（袁哲生中篇小说合辑）','袁哲生','https://cdn.weread.qq.com/weread/cover/72/YueWen_23863103/t9_YueWen_23863103.jpg','雨水不断降下，被隔绝在朦胧雨景中的爱情，让安静的眷村少年无数次来到心仪女孩梁羽玲的家门前。月亮重复升起，被笼罩在残存黄昏里的爱情，令雕刻匠建兴仔一直无法成功打造出庄严的佛像。他刻出的雕像轮廓始终近似倾心的对象小月娘，过于艳丽。他们都是深情的人，但一往而深之后的爱情，究竟能多美好？若注定无法寻得，又能如何靠近？','文学-经典作品','2018-11-01 00:00:00',2,15,0,17,100,4,1,1587194510,1587194510,803.0,1151,NULL,'四川人民出版社','9787220109478',NULL,1782398782);
INSERT INTO books VALUES('3300120093','带着诗歌上街去','隔花人','https://cdn.weread.qq.com/weread/cover/41/cpplatform_n289r1czdqxebnagk9x4mz/t9_cpplatform_n289r1czdqxebnagk9x4mz1731053202.jpg','全书共4个章节，收录171首诗+171张生活载体照片。从自然到街道，从自由到自我，用即兴创作，记录生活中的永恒瞬间。 人类出现之前，自然没有高楼。高楼与高楼之间，就是街道。街道划分左右，森林没有性别。 慢是时间的表述吗？还是一个好天气 ，把街道的角落晾晒一遍，显现诗。 隔花人用她独有的视角与语言，讲述生活中的诗意。','文学-现代诗歌','2024-10-16 00:00:00',2,15,40,57,99,4,1,1737689895,1737689895,790.0,315,NULL,'浙江人民出版社有限公司','9787213116209',NULL,1782398781);
INSERT INTO books VALUES('27328997','语文课超有趣：部编本语文教材同步学（三年级上册）','王云超','https://cdn.weread.qq.com/weread/cover/31/YueWen_27328997/t9_YueWen_27328997.jpg','高效语文学习课系列是由部编本语文教材总主编温儒敏教授担任顾问并作序推荐，围绕新版教材的课文篇目，同步进行相关知识的汇总、梳理、延伸、启发，帮助学生和教育工作者全面了解课文周边的国学、人文、社会、历史、科学、自然知识，不仅帮助学生加深对课文内容的理解，更让语文教材成为引导学生进入更广阔知识海洋的钥匙。本系列具有突出的知识性、启发性、可读性和趣味性，目标是帮助学生进行主动性、探究性学习，并成为学生和教育工作者常备的语文课程辅助读物。','教育学习-教材','2019-07-01 00:00:00',0,13,0,13,9,3,1,1598269543,1598269543,697.0,69,NULL,'浙江人民出版社','9787213092992',NULL,1782398782);
INSERT INTO books VALUES('3300016824','陈年喜的诗','陈年喜','https://cdn.weread.qq.com/weread/cover/24/3300016824/t9_3300016824.jpg',unistr('因为一句“再低微的骨头里也有江河”，许多人记住了“矿工诗人”陈年喜。他生活的A面，是地下5000米令人窒息的爆破工作；B面却是将一切执笔成诗的才华与执着。《陈年喜的诗》收录了陈年喜近年来的171首新作，共分四辑：第一辑（峡河边上），关于童年与回忆；第二辑（内心的更易何其缓慢），写朋友的聚散、爱情的缝补、亲情的牵挂；第三辑 离开与抵达，北至新疆，南到贵州，为自己漂泊的每个地方写一首诗；第四辑（奔跑的孩子），在现代工业文明与柔软的人性之间，填充以诗意。\u000a陈年喜的诗歌，既有粗粝的浪漫，也有质朴的豪情；有时炸裂如铁，有时温柔如灯火；既有古典气质，也有现代表达。甚至可以说，陈年喜的骨骼中都是浩浩荡荡的诗篇。\u000a他写生活：“生活有时候会无比沸腾，连死亡也无力打扰”。\u000a他写爱情：“我们对于爱情的理解，总是过于繁复，除了锦开花簇，还有细细地缝补。”\u000a他写记忆：“记忆像一册旧书本，重要章节都已消损。”\u000a他写美好：“世界有许多美好，有的像梦一样繁复，有的像花一样简单。”\u000a读诗是奢侈的，读诗又是值得的。从陈年喜的诗中，读者可以一次次汲取到更丰富的生命体验，以诗为盾，抵挡时间的速朽和轻薄。'),'文学-现代诗歌','2022-02-01 00:00:00',1,13,0,14,99,4,1,1690351266,1690351266,773.0,432,NULL,'江苏凤凰文艺出版社','9787559449474',NULL,1782398781);
INSERT INTO books VALUES('39336353','小学语文开学第一课','王振刚','https://cdn.weread.qq.com/weread/cover/57/YueWen_39336353/t9_YueWen_39336353.jpg','《小学语文开学第一课》的语言多变，每节课均贴近学生不同阶段的特点，可读性强，引人入胜，是教师上好开学第一课不可多得的参考用书。','教育学习-教育','2019-08-01 00:00:00',0,13,0,13,9,2,1,1629373350,1629373350,NULL,19,NULL,'华东师范大学出版社有限公司','9787567592209',NULL,1782398781);
INSERT INTO books VALUES('40315793','一日三秋','刘震云','https://cdn.weread.qq.com/weread/cover/54/YueWen_40315793/t9_YueWen_40315793.jpg','小说《一日三秋》引用民间“花二娘”的传说，以想象的故事描述“我”记忆中的六叔生前所画的画作，探讨延津人幽默的本质。从两米见方的剧团人物群像素描中挑出陈长杰、李延生、樱桃，围绕几位主人公身边出现的人物，有开车的、扫大街的、开饭馆的，串联起几个家庭的人生经历和故事，把世人被忘却的情感和心事复刻出来。后引出寻常父子二人遍尝生活辛酸后对人生至理的了悟，在不同时间和地点悟出：一个重要的瞬间，在人生中犹如一日三秋，但这瞬间永不再来。小说充满了黑色幽默，世俗生活所包含的哲理，及打破日常生活壁垒的想象力。刘震云写出现实与想象中的人性、土地、命运。既是幽默，也是讽刺；既是魔幻，也是现实。','精品小说-社会小说','2021-07-01 00:00:00',6,13,0,19,99,4,1,1669521390,1669521390,897.0,12655,NULL,'花城出版社','9787536094420',NULL,1782398781);
INSERT INTO books VALUES('749907','牧羊少年奇幻之旅','保罗•柯艾略','https://cdn.weread.qq.com/weread/cover/64/yuewen_749907/t9_yuewen_7499071696843421.jpg',unistr('一部能改变一个人一生的书，当你想要某种东西时，整个宇宙会合力助你实现愿望。\u000a这是一部少年追求梦想的寓言故事，更是百年一遇的能改变一个人一生的书，每个人都能在其中找到自己追寻梦想的方式。\u000a西班牙牧羊少年圣.地亚哥接连做了同一个梦，梦见埃及金字塔附近藏有一批宝藏。少年卖掉羊群，历尽千辛万苦一路向南，跨海来到非洲，穿越撒哈拉大沙漠，其间奇遇不断。\u000a在一位炼金术士的指引下，他终于到达金字塔前，却刚刚悟出宝藏的真正所在……'),'精品小说-治愈小说','2017-11-01 00:00:00',0,13,0,13,100,4,1,1555557950,1555557950,816.0,37984,NULL,'北京十月文艺出版社','9787530217054',NULL,1782398782);
INSERT INTO books VALUES('25028543','这世界如露水般短暂：小林一茶俳句300','[日]小林一茶','https://cdn.weread.qq.com/weread/cover/41/YueWen_25028543/t9_YueWen_25028543.jpg','小林一茶是江户时代最后一位俳句大家，与松尾芭蕉、与谢芜村并称日本古典俳句三大俳人。一茶早年离乡赴江户谋生，流浪半生后返乡成家。然而儿女均先于他离世，一茶的晚年寂寥又困窘，唯自然万物和俳句可寄情。一茶的俳风独树一帜，效仿前人的同时又发展出独特的变奏，继承闲寂、幽玄美学的同时，又带上了诙谐的个人标记。他厌恶世俗，反抗强者，而此类激进的情感均在落笔时全然稀释，只剩下安贫乐道、甘于品尝生之苦涩的豁达，对弱小生命的无尽悲悯，以及对世事无常的喟叹。一茶一生创作了两万多句俳句。本书从中遴选三百余句，按年代先后编排并附上原文、读音及简注，以助鉴赏。','文学-现代诗歌','2019-02-01 00:00:00',1,12,0,13,100,4,1,1587723132,1587723132,671.0,2868,NULL,'北京联合出版公司','9787559627490',NULL,1782398782);
INSERT INTO books VALUES('31839232','涂乐','姜末','https://wfqqreader-1252317822.image.myqcloud.com/cover/232/31839232/t9_31839232.jpg','《涂乐》是知名漫画家姜末创作的漫画作品集。 姜末具有深厚的绘画功底，其画风鲜明，具有强烈的传统绘画风格。书中有200多个图文并茂、幽默风趣的小故事，每页皆由一幅妙趣横生的漫画配以简短的文字，通过作者本人的视角展现了当下中国老百姓的幸福生活，并从细微之处帮助每一位读者发现生活的乐趣与美好。','漫画-经典改编','2020-07-01 00:00:00',1,12,3,16,100,4,1,1690880418,1690880418,791.0,628,NULL,'中信出版集团','9787521713541',NULL,1782398781);
INSERT INTO books VALUES('917541','冯唐诗百首（2017）','冯唐','https://wfqqreader-1252317822.image.myqcloud.com/cover/541/917541/t9_917541.jpg','百炼成诗，诗是较好的汉语。诗，一个字就要有纵横捭阖的气象，就要有“缘情而绮靡”的婉转，没什么过人的才情，不敢自称诗人。而冯唐敢，敢写，还敢自称写诗第一，小说和杂文都要往后排。他的诗句如人，读一句就知是他，只有他。那份痞、坏和眼睛里的真情、脑子里的思考、每一寸皮肉里隐藏的那点儿荷尔蒙因子一道搅和在一起，凝聚成这本似与唐诗一争高下的诗集。这本《冯唐诗百首》收录冯唐创作至今的116首诗歌，内含24张鎏银黑卡，新增14幅亲题书法，精致、完整、匠心独蕴。','文学-现代诗歌','2017-08-01 00:00:00',0,12,1,13,100,4,1,1594149490,1594149490,446.0,3362,NULL,'天津人民出版社','9787201118581',NULL,1782398782);
INSERT INTO highlights VALUES('934343_66_996-1100','934343',66,'后记','弗洛伊德的精神分析和解梦、荣格的曼陀罗绘画治疗、温尼科特的涂鸦游戏、末永苍生的色彩疗愈、申荷永老师的沙盘技术、李中莹老师的简快疗法、朱建军老师的意象对话、刘峰老师的心理画像等很多心理学的技术都融入了实践当中，','996-1100',NULL,1629191398,1782398652);
INSERT INTO highlights VALUES('934343_65_633-713','934343',65,'发现关系','对于一个孩子来说，自我价值感可以决定他的未来发展。在做人生重大抉择的时候，都要依据自我的价值判断决定进退取舍，过低的自我评价会让孩子自动放弃很多可以争取的机会。','633-713',NULL,1629190899,1782398652);
INSERT INTO highlights VALUES('934343_64_4430-4567','934343',64,'疗愈故事','如果到了12岁，孩子还丝毫没有个人理想和责任意识，每天只惦记吃和玩两件事，那就需要家长反省一下自己，是不是给了孩子太多生活上的照顾和物质上的满足。通常在过度保护和过度满足的状况下，孩子的思想会发育迟缓。要让他们承接一些责任、面对一些挑战，才会激活那些担当、理想、努力的程序。','4430-4567',NULL,1629190710,1782398652);
INSERT INTO highlights VALUES('934343_64_3664-3745','934343',64,'疗愈故事','台湾认知科学专家洪兰老师曾经专门告诫过家长，保护孩子的自尊是很重要的，千万不能对孩子有侮辱性的言辞和行为，那会导致脑神经萎缩，会极大伤害孩子的智力发育和人格发育。','3664-3745',NULL,1629190647,1782398652);
INSERT INTO highlights VALUES('934343_64_1893-1967','934343',64,'疗愈故事','我们都觉得教育是很难的事，但是有的时候又会发现，只要真心对一个孩子，教育又变得很简单。当一个孩子的心感受到被爱、被尊重，他的成长也许就能在瞬间发生。','1893-1967',NULL,1629190184,1782398652);
INSERT INTO highlights VALUES('934343_63_5043-5158','934343',63,'发现创伤','孩子4岁之前是建立安全感和自信最重要的时期，在这个时期给孩子陪伴，会让他对这个世界建立起安全的印象，否则他可能一生都缺少安全感。大部分心理学的资料讲的都是3岁之前，但是在我亲身经历的实践中，很多孩子到了4岁仍无法应对抚养人的更换。','5043-5158',NULL,1629189605,1782398652);
INSERT INTO highlights VALUES('934343_63_3993-4084','934343',63,'发现创伤','如果孩子在4岁前被不断地更换抚养人，那么孩子对这个世界的第一印象就是不可靠的，这个印象在他的心里会形成一种不安全的背景色，一生都难以消除，他所表现出的人格形态总会带有一种担忧的阴影。','3993-4084',NULL,1629189526,1782398652);
INSERT INTO highlights VALUES('934343_62_1990-2023','934343',62,'发现攻击性','我更欣赏那些用刀的人，因为他们是在用技艺和品格征服别人，不是用蛮力','1990-2023',NULL,1629189208,1782398652);
INSERT INTO highlights VALUES('934343_62_980-1060','934343',62,'发现攻击性','我的猜测是，他长期在比自己年长的人群中，受了委屈又不敢表达，身边的人不接纳他，他也不知道怎样和比自己大的孩子交往，时间长了，他就对同学普遍产生了不信任感和敌意。','980-1060',NULL,1629189107,1782398652);
INSERT INTO highlights VALUES('934343_62_1150-1288','934343',62,'发现攻击性','孩子的大部分攻击行为都是在探底线，他丢橡皮的目的应该是看看老师和同学是不是会包容他，是不是愿意接纳他。如果大家包容他，说明他是安全的，即使老师和同学生气了，橡皮打不疼人，也不会惹太大麻烦。但是我知道，如果大家只是包容他的发泄行为，却不能接纳他做朋友，攻击的行为恐怕还是会持续。','1150-1288',NULL,1629189082,1782398652);
INSERT INTO highlights VALUES('934343_61_641-681','934343',61,'发现安全感','安全感对一个孩子来说，实在是太重要了，这决定着孩子是否能够构建自信和健康的人格。','641-681',NULL,1629188624,1782398652);
INSERT INTO highlights VALUES('934343_60_9178-9209','934343',60,'发现情绪','孩子不同不可怕，试图去改变他，让他和别人一样，这才是最可怕的。','9178-9209',NULL,1629188360,1782398652);
INSERT INTO highlights VALUES('934343_60_7570-7627','934343',60,'发现情绪','对于一个家长来说，命令孩子做一件事太简单了，但是了解孩子的心理却太难了，那就需要付出巨大的努力，去学习和改变自己。','7570-7627',NULL,1629188259,1782398652);
INSERT INTO highlights VALUES('934343_60_6916-6982','934343',60,'发现情绪','有一次，我布置了一个创作的题目，让学生们把自己的心声画出来，再把内心的呼唤写出来，写什么都可以。结果我看见了很多孩子内心发出的呼唤。','6916-6982',NULL,1629187971,1782398652);
INSERT INTO highlights VALUES('934343_60_6246-6329','934343',60,'发现情绪','语言是有催眠作用的，它会形成一种巨大的能量，根植在孩子的内心，挥之不去。那种重复的负面语言——指责、谩骂、唠叨，对孩子的大脑是有极大损伤的，可以在很多年里持续造成伤害','6246-6329',NULL,1629187923,1782398652);
INSERT INTO highlights VALUES('934343_60_5808-5846','934343',60,'发现情绪','心理健康需要有两个口保持畅通，一个是爱的能量输入口，一个是垃圾情绪的倾倒口。','5808-5846',NULL,1629187676,1782398652);
INSERT INTO highlights VALUES('934343_60_5318-5352','934343',60,'发现情绪','想做个智慧的家长，就要在孩子说他想拯救世界的时候，积极肯定这个说法。','5318-5352',NULL,1629187215,1782398652);
INSERT INTO highlights VALUES('934343_60_5274-5318','934343',60,'发现情绪','所以，我们看见哪一面都并不重要，只要我们愿意认同这里面积极的价值，它就会不断向正面转化。','5274-5318',NULL,1629187208,1782398652);
INSERT INTO highlights VALUES('934343_60_5174-5202','934343',60,'发现情绪','二者可以相互转化，当正义感不被认同时，就会转化成毁灭欲。','5174-5202',NULL,1629187182,1782398652);
INSERT INTO highlights VALUES('934343_60_5146-5174','934343',60,'发现情绪','男孩子身上有天生的两样东西，一种是毁灭欲，一种是正义感。','5146-5174',NULL,1629187175,1782398652);
INSERT INTO highlights VALUES('934343_60_5000-5028','934343',60,'发现情绪','潜意识无论做什么事，意识都会给这个行为找一个合理的理由。','5000-5028',NULL,1629187070,1782398652);
INSERT INTO highlights VALUES('934343_60_854-883','934343',60,'发现情绪','亚洲男性的潜意识会显得更压抑一些，隐性的愤怒也会更多一些。','854-883',NULL,1629186971,1782398652);
INSERT INTO highlights VALUES('934343_60_3300-3368','934343',60,'发现情绪','我们往往看见一个孩子画面里不阳光的东西，就会猜测，他是不是内心很黑暗。其实，这都不是孩子的问题，孩子呈现的都是社会、家庭、抚养人的问题。','3300-3368',NULL,1629186836,1782398652);
INSERT INTO highlights VALUES('934343_60_2978-2985','934343',60,'发现情绪',' 人生被操控。','2978-2985',NULL,1629186784,1782398652);
INSERT INTO highlights VALUES('934343_60_2722-2751','934343',60,'发现情绪','青春期提前到来，缺少宣泄渠道，这是适龄孩子普遍的压抑成因。','2722-2751',NULL,1629186743,1782398652);
INSERT INTO highlights VALUES('934343_60_2426-2445','934343',60,'发现情绪','无处不在的过度保护也是孩子压抑的成因。','2426-2445',NULL,1629186708,1782398652);
INSERT INTO highlights VALUES('934343_60_2319-2395','934343',60,'发现情绪','所以，不管是面临着生存压力还是家庭矛盾，父母都要学会调整自己的心态，减少焦虑情绪和负面心情，像山一样岿然不动，像海一样包容接纳，这样才会让孩子有安全感。','2319-2395',NULL,1629186699,1782398652);
INSERT INTO highlights VALUES('934343_60_2212-2234','934343',60,'发现情绪','父母的情绪不稳定，是孩子内心最大的压力来源。','2212-2234',NULL,1629186673,1782398652);
INSERT INTO highlights VALUES('934343_60_524-629','934343',60,'发现情绪','家长必须知道一个常识，情绪是流水，必须允许它流动，尤其是负面情绪，一旦被积压，就会成为精神毒素，长期压抑下去，就会造成创伤和心理疾患。那种一看孩子哭就说“我数三个数，给我憋回去”的家长，简直就是在制造问题儿童。','524-629',NULL,1629186434,1782398652);
INSERT INTO highlights VALUES('934343_59_1646-1779','934343',59,'发现爱','孩子的情感能力是被好的抚养人唤醒的，只要早期的抚养人常常关注孩子，积极给予爱的呼应，哪怕是很小的婴儿都可以拥有很高的情感共鸣能力。但是，如果抚养人缺失情感的能力，做不到积极呼应，甚至长期忽视和粗暴阻断孩子情感的渴求，就会制造出情感发育迟缓甚至情感处于关闭状态的孩子。','1646-1779',NULL,1629186257,1782398652);
INSERT INTO highlights VALUES('934343_59_5750-5786','934343',59,'发现爱','在我看来，一套教育体系是否健全完善，要看教育者有没有告诉孩子去善待生命。','5750-5786',NULL,1629185564,1782398652);
INSERT INTO highlights VALUES('934343_59_5675-5721','934343',59,'发现爱','甘地曾经说过这样一句名言：一个民族的文明和道德进步的程度，可以通过观察其如何对待动物来衡量！','5675-5721',NULL,1629185545,1782398652);
INSERT INTO highlights VALUES('934343_59_5456-5513','934343',59,'发现爱','早于同龄人对情爱有觉知且更敏感的那部分孩子，也是对艺术有觉知且更敏感的那部分孩子，我将其视为一种情感和灵性的优势。','5456-5513',NULL,1629185512,1782398652);
INSERT INTO highlights VALUES('934343_58_2853-2893','934343',58,'发现天性','这只熊绝对不仅仅是孩子喜欢的玩具，还是他们情感取暖的陪伴和建立自信、安全感的工具','2853-2893',NULL,1629185319,1782398652);
INSERT INTO highlights VALUES('934343_59_3323-3367','934343',59,'发现爱','很多家庭中备有一些卡片，或者有一块爱的留言板，这都是很好的交流方式，促进爱的表达和流动。','3323-3367',NULL,1629178596,1782398652);
INSERT INTO highlights VALUES('934343_59_585-624','934343',59,'发现爱','有爱的能力的人，才会积极表达。从这一点来说，很多孩子可能比成年人都更有爱的能力','585-624',NULL,1629178307,1782398652);
INSERT INTO highlights VALUES('934343_59_509-556','934343',59,'发现爱','这些表达都不能让孩子感受到爱，最糟糕的是，孩子很可能去沿袭这种扭曲的表达方式，再去教育下一代。','509-556',NULL,1629178297,1782398652);
INSERT INTO highlights VALUES('934343_59_420-445','934343',59,'发现爱','每个人都需要爱，却不是每个人都有能力准确地表达出来','420-445',NULL,1629178275,1782398652);
INSERT INTO highlights VALUES('934343_58_7512-7551','934343',58,'发现天性','女孩子到了青春期，她渴望离开家人独立，独立的标志就是转移注意力去寻找同龄伙伴。','7512-7551',NULL,1629178209,1782398652);
INSERT INTO highlights VALUES('934343_58_7356-7390','934343',58,'发现天性','女孩子似乎比男孩子更需要亲近伙伴，因为女孩子更需要情感和肢体的黏性。','7356-7390',NULL,1629178189,1782398652);
INSERT INTO highlights VALUES('934343_58_5061-5123','934343',58,'发现天性','如果希望他们表达得更得体，需要教会他们一些边界和分寸的概念，对他们做正向的引导，相信他们的表达一定会越来越得体、越来越优雅。','5061-5123',NULL,1629178061,1782398652);
INSERT INTO highlights VALUES('934343_58_4751-4837','934343',58,'发现天性','恶搞是小男孩在潜意识里想取悦异性的一种方式，但是，这个年龄的男孩子还不能够完美地掌握表达技巧和分寸，想去取悦异性时，总是选择挑衅或者恶作剧的方式接近对方，也常常会弄巧成拙。','4751-4837',NULL,1629178028,1782398652);
INSERT INTO highlights VALUES('934343_58_4592-4636','934343',58,'发现天性','他们的表达也会更直接、更大胆，也更真实。而女孩子的面具就更多一些，对本我的压抑也更强烈。','4592-4636',NULL,1629177989,1782398652);
INSERT INTO highlights VALUES('934343_58_3417-3472','934343',58,'发现天性','小熊会形影不离，小熊会乖乖听我讲故事，什么都听我的。于是，这只小熊就成了孩子建立控制感和安全感的一个情感陪伴。','3417-3472',NULL,1629177852,1782398652);
INSERT INTO highlights VALUES('934343_58_2358-2423','934343',58,'发现天性','而我们给孩子准备的涂鸦盛宴，就是在一个幼小生命的初期，给他一个足够开放自由的空间，给他一次充分触摸世界、构建自信、释放天性的机会。','2358-2423',NULL,1629177677,1782398652);
INSERT INTO highlights VALUES('934343_58_2169-2216','934343',58,'发现天性','很多时候，心灵某个地方留下的创伤我们都没有来得及察觉，它就进入了结痂过程，被深深埋在潜意识里，','2169-2216',NULL,1629177629,1782398652);
INSERT INTO highlights VALUES('934343_58_1764-1880','934343',58,'发现天性','在涂鸦的现场，经常能看到那种怯生生的孩子，总不敢下笔。这样的孩子后面通常都有个批评型家长，他们不允许孩子弄脏自己，不允许孩子犯错，不允许孩子淘气，孩子做什么他们都会有对错的评价，孩子总是担心被批评、被惩罚，所以顾虑重重、放不开手脚。','1764-1880',NULL,1629177586,1782398652);
INSERT INTO highlights VALUES('934343_58_1678-1735','934343',58,'发现天性','孩子能够专注做一件事的能力，就是他的探索力和学习力，这个意义才是最重要的，最后那张作品只不过是一个顺带的结果而已。','1678-1735',NULL,1629177554,1782398652);
INSERT INTO highlights VALUES('934343_58_444-459','934343',58,'发现天性','天性的表现，更多是本我的需求。','444-459',NULL,1629177350,1782398652);
INSERT INTO highlights VALUES('934343_56_2913-3049','934343',56,'一些特殊的孩子','这个孩子给了我一个新的视角，发现了一种特殊的成长模式，他的逆序学习、原生思维、灵性预感，甚至他执拗抵抗时的那种力量，都是那么独特。我希望更多家长能够本着开放的心态，对看不太懂或者某些能力发育迟缓的孩子给予更多包容。确实有一些孩子的思维天生和大众不同，更要给予个性化的支持。','2913-3049',NULL,1629171653,1782398652);
INSERT INTO highlights VALUES('934343_56_2770-2884','934343',56,'一些特殊的孩子','据俄罗斯科学家称，靛蓝儿童是拥有某种特殊意志力或超自然能力的儿童，他们的共同特征是智力很高、直觉和预感性强、非常敏感等。科学家用人体能量摄影机拍摄他们的时候，发现他们身上会散发出蓝光，因此他们被称为“靛蓝儿童”或者“深蓝儿童”。','2770-2884',NULL,1629171158,1782398652);
INSERT INTO highlights VALUES('934343_55_5856-5899','934343',55,'顺应天赋的洪流','在长期的教学当中我发现，让孩子在自己擅长的领域学习，就等于把鱼放回大海，把鸟放飞长空。','5856-5899',NULL,1629171132,1782398652);
INSERT INTO highlights VALUES('934343_56_1838-1895','934343',56,'一些特殊的孩子','他是绝对不能按照常规模式学习的孩子，他想学的东西不用教，自己研究研究就会了，他不想学的东西，任凭你怎么灌输都没用。','1838-1895',NULL,1629170994,1782398652);
INSERT INTO highlights VALUES('934343_56_1634-1712','934343',56,'一些特殊的孩子','也许我的儿子是一个天才。爸爸的话成为妈妈信念的支撑，从那时候起，妈妈就开始尝试个性化的教育，不再强迫他识字和算术，而是找很多音乐和音频，在他画画的时候播放。','1634-1712',NULL,1629170956,1782398652);
INSERT INTO highlights VALUES('934343_56_1577-1589','934343',56,'一些特殊的孩子','阿斯伯格综合征和阅读障碍','1577-1589',NULL,1629170939,1782398652);
INSERT INTO highlights VALUES('934343_56_1151-1186','934343',56,'一些特殊的孩子','所谓的原生艺术，就是不通过跟他人学习，使用自己原始的思维去创作的作品。','1151-1186',NULL,1629170695,1782398652);
INSERT INTO highlights VALUES('934343_56_826-859','934343',56,'一些特殊的孩子','否则，即便他是天才，不给予个性发展，也可能连做普通人的能力都没有。','826-859',NULL,1629170665,1782398652);
INSERT INTO highlights VALUES('934343_56_665-740','934343',56,'一些特殊的孩子','大部分孩子的各种天赋均衡分配，任何一项都不会很高，也不会很低，我们的教育体制更适合天赋分配均衡的孩子发展，这类分配不均衡的孩子，会被视为差生、偏科生。','665-740',NULL,1629170643,1782398652);
INSERT INTO highlights VALUES('934343_55_5972-6024','934343',55,'顺应天赋的洪流','对的时间，将对的“物种”放入对的环境，他自己就能够找到所需的养分，这就是对的开发，一定可以收获对的结果。','5972-6024',NULL,1629170602,1782398652);
INSERT INTO highlights VALUES('934343_55_6503-6659','934343',55,'顺应天赋的洪流','孩子自己要求学习的科目，学到一半想放弃，这也是正常的，孩子也需要在不断试错中学会认识自己。而且就算方向对了，每个孩子在不同时期的承压状态也不同，哪怕是他天才的方向，也不能强逼着他在超限承压的状态下去开发。这样的时刻，也需要家长权衡，是强行制造一个心理扭曲的天才，还是先让他成为一个心理健康的人，再去塑造他的才能。','6503-6659',NULL,1629170565,1782398652);
INSERT INTO highlights VALUES('934343_55_6428-6492','934343',55,'顺应天赋的洪流','台湾认知科学家洪兰老师说得很对，哪里跌倒了要换个地方爬起来，孩子往往在不擅长的领域才会跌倒，不要强行要求一只老虎在水域里学习游泳','6428-6492',NULL,1629170330,1782398652);
INSERT INTO highlights VALUES('934343_55_6103-6224','934343',55,'顺应天赋的洪流','我的建议是，孩子10岁以前，在尊重孩子意愿的前提下可以多报一些兴趣班，广泛报班的目的不在学习，而是去找孩子天赋的方向。孩子想要放弃，一定要允许。10岁以后，建议留下一两个喜欢并擅长的科目坚持学习，暂停广泛的开发，给优势天赋更多时间和空间发展。','6103-6224',NULL,1629170289,1782398652);
INSERT INTO highlights VALUES('934343_55_4314-4348','934343',55,'顺应天赋的洪流','大众还有个误区，认为天才全靠培养，而在我看来，顺应天赋的培养才有效。','4314-4348',NULL,1629170109,1782398652);
INSERT INTO highlights VALUES('934343_55_4259-4285','934343',55,'顺应天赋的洪流','其实只要让每个孩子做回他自己的“物种”，就都是天才。','4259-4285',NULL,1629170093,1782398652);
INSERT INTO highlights VALUES('934343_55_3292-3339','934343',55,'顺应天赋的洪流','所以，越是天马行空、倾其性情创作的孩子，越不善于完成命题的任务，这是发散性思维孩子的典型特征。','3292-3339',NULL,1629170026,1782398652);
INSERT INTO highlights VALUES('934343_55_2977-3009','934343',55,'顺应天赋的洪流','所以很多完不成命题的孩子，绝非能力有缺陷，反而可能是能力超长的。','2977-3009',NULL,1629169862,1782398652);
INSERT INTO highlights VALUES('934343_55_2130-2174','934343',55,'顺应天赋的洪流','台湾漫画家蔡志忠曾经说：父母就是弓，孩子是箭，弓要送箭去它想去的地方，帮助箭实现箭的梦想','2130-2174',NULL,1629169715,1782398652);
INSERT INTO highlights VALUES('934343_55_1353-1434','934343',55,'顺应天赋的洪流','我对他说：“恨画画没有关系，但是不能伤害纸张和石膏像，因为它们是无辜的。”我给他讲了石膏像的制作过程，这小子居然能乖乖听我讲半天，最后自己用橡皮擦掉了他画的耳钉。','1353-1434',NULL,1629169641,1782398652);
INSERT INTO highlights VALUES('934343_55_828-904','934343',55,'顺应天赋的洪流','顺应天赋发展也是顺应自己的基因和宇宙的规律，是每个人自我实现的方向，当天赋的洪流被压抑和阻断，就会引发灾难甚至让自我破碎，很多心理疾病患者都是这种病因。','828-904',NULL,1629169574,1782398652);
INSERT INTO highlights VALUES('934343_54_21954-21981','934343',54,'发现天赋','比如七巧板、T字谜、九连环、解环和解扣玩具、孔明锁等。','21954-21981',NULL,1629169481,1782398652);
INSERT INTO highlights VALUES('934343_54_21691-21802','934343',54,'发现天赋','建议家长建立一个零用钱的制度，教孩子理财的常识，教会他们消费时怎样权衡性价比。然后告诉孩子，买玩具是你自己的事情，只要你的零用钱够，想买多少都可以。当孩子学会用有限的钱去购买最想要的东西时，他们既学会了花钱，又守住了梦想。','21691-21802',NULL,1629169453,1782398652);
INSERT INTO highlights VALUES('934343_54_19959-19998','934343',54,'发现天赋','我看孩子，最看重的不仅仅是他对什么感兴趣，更看重的是这个孩子在兴趣里关注什么。','19959-19998',NULL,1629168745,1782398652);
INSERT INTO highlights VALUES('934343_54_16833-16904','934343',54,'发现天赋','不要在孩子4岁之前教他们认识颜色，让他们充分使用原始能力感受和记忆色彩，也要减少他们看手机、电视、电脑的时间，保护好孩子的色彩辨识力和敏感度。','16833-16904',NULL,1629168378,1782398652);
INSERT INTO highlights VALUES('934343_54_15236-15360','934343',54,'发现天赋','这样的行为家长应给予支持，给他们多买一些颜料，选择色彩丰富的绘本给他们欣赏。挑选绘本的时候，不要买电脑上色的图画书，那些过于鲜艳的电脑色，就像放了过量味精的菜，会破坏天然的味觉，建议家长给孩子买画家用颜料画的手绘本作品，尤其是那些世界经典的手绘本。','15236-15360',NULL,1629168247,1782398652);
INSERT INTO highlights VALUES('934343_54_14888-14926','934343',54,'发现天赋','梵高之所以被称为色彩大师，就是因为他使用色彩的时候表现出狂热和反常规的任性。','14888-14926',NULL,1629168198,1782398652);
INSERT INTO highlights VALUES('934343_54_13525-13546','934343',54,'发现天赋','敏锐的观察力、幽默的敏感度、丰富的联想力。','13525-13546',NULL,1629167973,1782398652);
INSERT INTO highlights VALUES('934343_54_12811-12912','934343',54,'发现天赋','真正会玩的人可以玩一辈子，玩出一番大事业。其实这种特别贪玩、特别会玩的孩子，往往是精力和智力过人的，常规和低端的游戏满足不了他们的需求，他们就发动自身的创造力去满足自己，这样的孩子越贪玩，就越有创造力。','12811-12912',NULL,1629167877,1782398652);
INSERT INTO highlights VALUES('934343_54_11507-11573','934343',54,'发现天赋','我常常建议家长允许他们多看电影，因为导演必须懂得怎么讲故事，也要懂表演、摄像、布景、剪辑、特效等技术，而电影就是这样一所立体的学校。','11507-11573',NULL,1629167785,1782398652);
INSERT INTO highlights VALUES('934343_54_11362-11470','934343',54,'发现天赋','喜欢画故事的孩子就像三栖动物，他们的优势是把绘画、文字、故事情节结合起来创作，如果只让他们发展一个优势是很可惜的。他们未来也更适合做“三栖合一”的工作。在广告、影视、文艺创作等领域里，故事型人才一直是顶级的稀缺资源。','11362-11470',NULL,1629167748,1782398652);
INSERT INTO highlights VALUES('934343_54_11268-11328','934343',54,'发现天赋','这种故事型的小孩很有做编剧和导演的潜能，如果这个时期我们给予保护和理解，让他们很好地发挥，他们就会构建起一种多维的能力。','11268-11328',NULL,1629167719,1782398652);
INSERT INTO highlights VALUES('934343_54_9123-9136','934343',54,'发现天赋','故事型的人才是很容易识别的','9123-9136',NULL,1629167628,1782398652);
INSERT INTO highlights VALUES('934343_54_8964-8986','934343',54,'发现天赋','“没有想象力的灵魂，就像没有望远镜的天文台。','8964-8986',NULL,1629165432,1782398652);
INSERT INTO highlights VALUES('934343_54_8780-8833','934343',54,'发现天赋','如果我们在艺术的课堂上，让处于黄金期、钻石期的孩子们学习画很多固定的图案，这不仅不是开发，反而是扼杀行为。','8780-8833',NULL,1629165382,1782398652);
INSERT INTO highlights VALUES('934343_54_8712-8780','934343',54,'发现天赋','孩子的想象力开发是有年龄限制的，错过开发的时间段，就再难开发了。19岁之前都算是开发期，11岁之前是黄金期，6岁以前是最最珍贵的钻石期。','8712-8780',NULL,1629165365,1782398652);
INSERT INTO highlights VALUES('934343_54_7732-7804','934343',54,'发现天赋','有一些孩子能通过看一些图形联想出无穷无尽的图案和故事，他们喜欢做一些跨越常规的设计，打破植物、动物、机器、时间、空间的界限，这是有联想力的表现。','7732-7804',NULL,1629165191,1782398652);
INSERT INTO highlights VALUES('934343_54_5288-5394','934343',54,'发现天赋','每个孩子都是天生的艺术家，他们有很好的感知力、观察力和想象力。这些能力都需要呵护，过早地给孩子头脑中植入一些公式化的概念、固化思维，孩子就不再依靠自己的观察和直觉去画画了，这等同于折断了自主观察、自由发挥的翅膀。','5288-5394',NULL,1629165037,1782398652);
INSERT INTO highlights VALUES('934343_54_4793-4833','934343',54,'发现天赋','日本著名亲子教育家鸟居昭美就非常反对让孩子学习简笔画，她认为这会扼杀孩子的创造力','4793-4833',NULL,1629164986,1782398652);
INSERT INTO highlights VALUES('934343_54_4564-4636','934343',54,'发现天赋','9岁中国孩子的画，画面过于工整，内容重复，构图刻板，是被限制性教育固化了思维的产物，这个孩子的自主创造力遭到严重的破坏，这张画已经算是创伤作品了','4564-4636',NULL,1629164915,1782398652);
INSERT INTO highlights VALUES('934343_54_4488-4561','934343',54,'发现天赋','上图是国外9岁孩子的画，无论是色彩和内容都很自由，天空可以有两个太阳，蝴蝶翅膀也是不对称的，每一片萝卜叶都可以是不同的颜色，这是开放式教育的产物。','4488-4561',NULL,1629164898,1782398652);
INSERT INTO highlights VALUES('934343_54_3330-3421','934343',54,'发现天赋','他们对作品有自己的要求，不会因为任务的时间限制而放弃自己做了一半的工作。他们追求质量，也追求最终的结果，哪怕一件事被迫中途停止，他们也会再想办法继续完成，这都需要耐心和持续力的保障，','3330-3421',NULL,1629164793,1782398652);
INSERT INTO highlights VALUES('934343_54_3296-3318','934343',54,'发现天赋','有一些孩子可以持续地画一张很大或者很复杂的画','3296-3318',NULL,1629164782,1782398652);
INSERT INTO highlights VALUES('934343_54_2476-2570','934343',54,'发现天赋','其实，大部分孩子不是先天就缺失专注力的，都是后天造成的。很多注意力缺失的孩子，是因为小时候专注于探索的时候总是被一次次地打断，长期下来专注力就遭到严重破坏，以后在学习中也就无法集中注意力了','2476-2570',NULL,1629163623,1782398652);
INSERT INTO highlights VALUES('934343_54_2096-2142','934343',54,'发现天赋','他们的行为看上去就是痴迷，但是这是专注力好的表现，这份能力未来就会发展成一种珍贵的专业精神。','2096-2142',NULL,1629163538,1782398652);
INSERT INTO highlights VALUES('934343_54_482-510','934343',54,'发现天赋','情感能力、感性思维能力强的人群，也是艺术天赋高发的人群。','482-510',NULL,1629163428,1782398652);
INSERT INTO highlights VALUES('934343_53_2116-2190','934343',53,'感官优势','感觉优先的孩子说话比较慢，喜欢停顿，他们做事情也会比较缓慢。他们不喜欢画黑白分明和对比强烈的画，喜欢凭直觉画出事物的印象，画色彩柔和、边界模糊的画。','2116-2190',NULL,1629163330,1782398652);
INSERT INTO highlights VALUES('934343_53_1857-1999','934343',53,'感官优势','听觉优先的孩子对声音敏感，特别喜欢听音乐、听故事。因为听觉敏锐，他们说话语调宛转好听，擅长朗诵和模仿各种声音。但他们不太注重穿着，甚至有时穿反衣服和袜子都不自知。他们刻画精准造型较困难，但有丰富的想象力，他们的力量向内走，往创意和变形的方向发展，因此画出来的画创意丰富，或者特别复杂。','1857-1999',NULL,1629162986,1782398652);
INSERT INTO highlights VALUES('934343_53_1616-1761','934343',53,'感官优势','视觉优先的孩子，说话的语速会比较快，因为他们大脑里出现的都是图像，而图像形式的信息承载量最大，使得大脑处理信息速度也快，所以他们的语言和手势往往很快。视觉优先的孩子画画通常不用起稿，就能准确画出造型，他们绘画的线条未经训练就可以很有艺术感，他们喜欢画写实的景物和人物，并不太热衷变形和抽象。','1616-1761',NULL,1629162871,1782398652);
INSERT INTO highlights VALUES('934343_53_513-612','934343',53,'感官优势','只有三个内感官处理系统，那就是内视觉、内听觉和内感觉，意思就是嗅觉、触觉和味觉这三个外感官所接收到的信息，在内部统归为内感觉这部分来处理。所以不同的人会表现出视觉优先、听觉优先、感觉优先的优势特点。','513-612',NULL,1629162706,1782398652);
INSERT INTO highlights VALUES('934343_52_1462-1570','934343',52,'从绘画中发现孩子的天赋','大部分情况是，一个孩子身上有很多不同的智能，孩子的发展方向也就有更多的可能性，这就需要尊重孩子自己的意愿，本着有序开发的原则，适当作一些排序，最终孩子愿意向哪个方向发展，还要让他自己来选择决定，家长不要人为制造遗憾。','1462-1570',NULL,1629162619,1782398652);
INSERT INTO highlights VALUES('934343_52_887-995','934343',52,'从绘画中发现孩子的天赋','发现天赋，就要寻找这头潜在水下的巨兽露出水面的两只犄角，一个是擅长，另一个是兴趣。孩子很小的时候，能够轻松完成其他同龄人做不到的事，这就是擅长。孩子很小的时候，对某件事表现出极大的热情，总是重复性地去探索，这就是兴趣','887-995',NULL,1629162524,1782398652);
INSERT INTO highlights VALUES('934343_51_2081-2220','934343',51,'青春期（10～20岁）','这个时候，父母对孩子的态度需要做很多调整，一个很重要的原则就是不求助不帮助。还有，一定要尊重孩子的隐私和他自己的选择，不要替他包办事情，不要随意进入他的房间，不要偷看他的日记，不要随意动他的东西。做到这些的父母，一定可以在这个俗称叛逆期的时候，最大程度地减少引发孩子的叛逆情绪。','2081-2220',NULL,1629162394,1782398652);
INSERT INTO highlights VALUES('934343_51_1651-1714','934343',51,'青春期（10～20岁）','遮挡面部还是他们开始与家庭、父母划界的一个标志。这个行为的潜台词是：我不想被你们太关注，别窥探我，别逼视我，别老盯着我问这问那','1651-1714',NULL,1629162351,1782398652);
INSERT INTO highlights VALUES('934343_51_386-397','934343',51,'青春期（10～20岁）','青春期（10～20岁）','386-397',NULL,1629162288,1782398652);
INSERT INTO highlights VALUES('934343_50_1033-1101','934343',50,'同龄认同期（9～11岁）','这个行为是孩子在满足自己心理的需求，当需求满足后，他会逐渐找回创造的状态。家长不要阻断孩子这种心理上的需求，应该帮他们顺利度过这个阶段。','1033-1101',NULL,1629162256,1782398652);
INSERT INTO highlights VALUES('934343_50_386-398','934343',50,'同龄认同期（9～11岁）','同龄认同期（9～11岁）','386-398',NULL,1629162188,1782398652);
INSERT INTO highlights VALUES('934343_50_582-630','934343',50,'同龄认同期（9～11岁）','这是一种关系认同的表达，那个看上去喜欢模仿的孩子，他的潜台词是在说：我喜欢你，我要做你的好朋友，','582-630',NULL,1629162183,1782398652);
INSERT INTO highlights VALUES('934343_49_879-945','934343',49,'女孩“公主情结期”（5～12岁）','这个时期，父母要允许孩子扮演小公主，让她获得可以被爱的自信，让女性心理得到发展，这个时期的愿望得到满足，她会顺利进入下一个成长阶段。','879-945',NULL,1629162139,1782398652);
INSERT INTO highlights VALUES('934343_48_430-549','934343',48,'男孩“狗不理期”（7～9岁）','7～9岁的男孩子很调皮好动，精力过于旺盛，民间称他们“狗都嫌”，我称之为男孩“狗不理期”。这个时期他们会特别喜欢搞笑和滑稽的事，喜欢给同伴甚至老师起绰号，热衷恶搞童谣、诗歌，还喜欢画恶搞漫画，也喜欢破坏性的探索，但这些行为的背后都无恶意，','430-549',NULL,1629162011,1782398652);
INSERT INTO highlights VALUES('934343_47_978-1084','934343',47,'太阳笑脸期（6～10岁）','我们发现小孩子总是笑点很低，他们并非很傻很天真，这是一种有引导作用的心理机制。孩子发现，一旦自己傻笑，父母就会笑，他们降低笑点，就是为了引导父母多赐予他们一点微笑，因为父母的笑容是孩子这个时期最为重要的精神营养。','978-1084',NULL,1629161976,1782398652);
INSERT INTO highlights VALUES('934343_46_1058-1122','934343',46,'写实期（6岁以后）','孩子从6岁以后就开始追求写实，这个时候他们开始画出自己观察到的细节，随着年龄越来越大，孩子的画就会追求更多细节的真实性和立体感，','1058-1122',NULL,1629161868,1782398652);
INSERT INTO highlights VALUES('934343_46_498-534','934343',46,'写实期（6岁以后）','6岁的孩子也进入了人生的第一个觉醒期，12岁时他会再觉醒一次，以此类推。','498-534',NULL,1629161831,1782398652);
INSERT INTO highlights VALUES('934343_45_933-984','934343',45,'俄狄浦斯期（5～8岁）','如果孩子希望通过接触父母的身体满足自己爱欲的愿望，父母应该本着没有敌意的坚定和不带诱惑的深情拒绝孩子。','933-984',NULL,1629161789,1782398652);
INSERT INTO highlights VALUES('934343_45_462-529','934343',45,'俄狄浦斯期（5～8岁）','中文语境下有时也说成“恋母情结”和与之类似的“恋父情结”。这个时期大约在5～8岁，儿童会对双亲中异性的一方产生占有欲和类似爱欲的情感。','462-529',NULL,1629161732,1782398652);
INSERT INTO highlights VALUES('934343_44_1043-1134','934343',44,'性蕾期（3岁左右）','成年人把孩子问“我是怎么来的”这件事理解成了问“你们是怎么性交的”这件事了。其实，孩子没有那么复杂，只是在探索生命的起源，成年人这种遮遮掩掩的态度，反而制造了不必要的神秘感和羞耻感。','1043-1134',NULL,1629161694,1782398652);
INSERT INTO highlights VALUES('934343_44_425-514','934343',44,'性蕾期（3岁左右）','3岁左右的孩子处于一个性心理发展的特殊阶段，这个阶段在心理学上称为“性蕾期”。他们会对自己、父母或异性的生殖器特别感兴趣，也会很热衷抚弄自己的生殖器，这些行为都是正常发育的需要，','425-514',NULL,1629161639,1782398652);
INSERT INTO highlights VALUES('934343_43_427-557','934343',43,'印象派时期（2～5岁）','2～5岁的孩子，都是印象派的绘画大师，而且每个孩子都会经历这样一个印象派时期。这个时候孩子绝对不是写实派，他们会把看见的事物转化成一种心理印象画出来。这个时期他们的感觉是很敏锐的，他们能够分辨出同类东西的相似性，可以描绘出一个事物的感觉、状态，我们称为“神似”','427-557',NULL,1629161524,1782398652);
INSERT INTO highlights VALUES('934343_42_1248-1383','934343',42,'涂鸦期（2～4岁）','这个道理就如同生在广阔草原上的孩子，心胸就会开阔；生在狭窄弄堂里的孩子，个性难免斤斤计较。我个人建议，3岁之前，可以给孩子A3大小的纸，如果条件允许，还可以常让孩子在半开的大纸上涂鸦。涂鸦的纸不需要太讲究，更不必使用昂贵的专业绘画纸，使用过一面的办公用纸、喷绘布都可以。','1248-1383',NULL,1629161387,1782398652);
INSERT INTO highlights VALUES('934343_42_1084-1126','934343',42,'涂鸦期（2～4岁）','如果条件允许，请在家中设置一面让孩子随时涂鸦的墙。还有，请尽量给低龄孩子大一点的纸。','1084-1126',NULL,1629161322,1782398652);
INSERT INTO highlights VALUES('934343_41_1991-2019','934343',41,'口唇期和肛欲期','这个过程中，孩子充分释放天性，把压抑的情结转化成了创造力','1991-2019',NULL,1629161187,1782398652);
INSERT INTO highlights VALUES('934343_41_1311-1336','934343',41,'口唇期和肛欲期','既是补偿他们肛欲期的缺失，也是对他们创造力的开发，','1311-1336',NULL,1629161165,1782398652);
INSERT INTO highlights VALUES('934343_40_1613-1680','934343',40,'成长时期在绘画中的表现','6～10岁的孩子很喜欢画太阳和笑脸，我为其命名为“太阳笑脸期”，还有女孩的“公主情结期”、男孩的“狗不理期”等，都有一些规律性的特征。','1613-1680',NULL,1629160982,1782398652);
INSERT INTO highlights VALUES('934343_40_999-1021','934343',40,'成长时期在绘画中的表现','孩子画面中表现出来的问题有滞后和延迟的特点。','999-1021',NULL,1629160825,1782398652);
INSERT INTO highlights VALUES('934343_40_915-970','934343',40,'成长时期在绘画中的表现','儿童成长会经历各种生理和心理期，比如口唇期、肛欲期、性蕾期、青春期等，这些时期的特征会在孩子的绘画上得以表达。','915-970',NULL,1629160820,1782398652);
INSERT INTO highlights VALUES('934343_40_1323-1411','934343',40,'成长时期在绘画中的表现','如果孩子在绘画中常常有重复性的表达，那可能说明，他在某个时期的需求没有获得充分的满足，或者某个时期的成长愿望被压抑了，他正在通过绘画去释放郁结的能量，努力帮助自己度过这个时期。','1323-1411',NULL,1629160808,1782398652);
INSERT INTO highlights VALUES('934343_39_5361-5411','934343',39,'怎么看环境','想要成为一名专业的绘画解读师还需要系统学习房树人测试、风景构成法、主题统觉测试、墨迹测试等专业课程。','5361-5411',NULL,1629160308,1782398652);
INSERT INTO highlights VALUES('934343_39_4381-4457','934343',39,'怎么看环境','也不要对某些细节做评价和夸奖，以免引发暗示，孩子以为家长喜欢，就可能违背心愿向那个方向去画。也绝对不能帮助孩子修改画面，绘画过程中一切都让孩子独立完成。','4381-4457',NULL,1629160173,1782398652);
INSERT INTO highlights VALUES('934343_39_3114-3142','934343',39,'怎么看环境','密密麻麻的树疤有可能代表成长坎坷或有过于追求完美的性格。','3114-3142',NULL,1629160063,1782398652);
INSERT INTO highlights VALUES('934343_39_2691-2762','934343',39,'怎么看环境','树干画得细细长长，表示孩子和顺安静但是不够活泼，承压力需要提高。树枝和树根画得尖利得像鹰爪一样，往往代表有攻击性，青春期的孩子常画出这样的树，','2691-2762',NULL,1629160036,1782398652);
INSERT INTO highlights VALUES('934343_39_2314-2349','934343',39,'怎么看环境','在房子屋顶上画烟囱，表示希望获得关心，向上的直烟、黑烟暗示需要出气筒。','2314-2349',NULL,1629159974,1782398652);
INSERT INTO highlights VALUES('934343_39_1529-1554','934343',39,'怎么看环境','如果房子外观丑陋，孩子可能把家看作束缚自由的牢笼。','1529-1554',NULL,1629159922,1782398652);
INSERT INTO highlights VALUES('934343_39_1474-1500','934343',39,'怎么看环境','房子巨大无比，代表孩子渴望亲情或是有难以抑制的冲动。','1474-1500',NULL,1629159911,1782398652);
INSERT INTO highlights VALUES('934343_39_1296-1326','934343',39,'怎么看环境','把太阳和月亮用力涂黑，则表示孩子对父母和目前的生活强烈不满。','1296-1326',NULL,1629159858,1782398652);
INSERT INTO highlights VALUES('934343_39_686-708','934343',39,'怎么看环境','画被遮挡的太阳，有可能孩子渴望获得更多的父爱','686-708',NULL,1629159788,1782398652);
INSERT INTO highlights VALUES('934343_39_725-747','934343',39,'怎么看环境','画出偏右的太阳，通常代表孩子性格偏内敛一些，','725-747',NULL,1629159781,1782398652);
INSERT INTO highlights VALUES('934343_39_583-625','934343',39,'怎么看环境','大部分孩子喜欢画偏左的太阳，代表渴望在家庭中获得更多的爱，或者代表他的爱主要来自家庭','583-625',NULL,1629159763,1782398652);
INSERT INTO highlights VALUES('934343_38_1696-1740','934343',38,'怎么看关系','一个家族里面，每个人都必须被尊重，哪怕是不会说话的孩子，甚至是逝去的亲人或被堕胎的孩子。','1696-1740',NULL,1629159451,1782398652);
INSERT INTO highlights VALUES('934343_38_1586-1668','934343',38,'怎么看关系','幸福的家庭都很相似，不幸的家庭各有各的不幸，因为幸福是有法则的。爱是幸福家庭的第一保障，相亲相爱的夫妻关系对孩子的影响其实胜于教育。合理的排序是幸福家庭的第二保障，','1586-1668',NULL,1629159439,1782398652);
INSERT INTO highlights VALUES('934343_36_1745-1828','934343',36,'怎么看创伤','这份伤痛，有些是整个社会转型的震荡所造成，也有些是落后和僵化的教育模式造成的。所以很多孩子画出创伤符号并非是他遭遇了具体的创伤事件，他们画出的是整个时代孩子的伤痛感。','1745-1828',NULL,1628940570,1782398652);
INSERT INTO highlights VALUES('934343_36_858-950','934343',36,'怎么看创伤','不同的位置代表着不同类型的伤痛，头部的伤往往代表精神和心理的创伤，身体上的伤往往代表社交的创伤，手和脚上的伤往往代表行动力的创伤。画面中肢体的残损程度越大，往往代表内心的伤痛程度越深，','858-950',NULL,1628940300,1782398652);
INSERT INTO highlights VALUES('934343_35_3766-3874','934343',35,'怎么看攻击性','因为孩子一旦画出来，原来的情绪指数就会大大降低。艺术疗愈就是这样神奇，会将巨大的情绪峰值降下来，一旦情绪指数降低，理性就会逐渐恢复。如果这个孩子很热爱绘画，将那份压抑的情绪转化成创造力，在绘画方面还可以收获到很多好处','3766-3874',NULL,1628939840,1782398652);
INSERT INTO highlights VALUES('934343_35_3623-3661','934343',35,'怎么看攻击性','这样的孩子喜欢正面表达，不藏着掖着，表达后也能够快速放下，是“狮子型”的人。','3623-3661',NULL,1628939812,1782398652);
INSERT INTO highlights VALUES('934343_35_3122-3211','934343',35,'怎么看攻击性','如今孩子压抑的原因，不是看得见的伤害，而是周围总有人讲太多大道理。对于一个有情绪的孩子来说，他们需要的就是物理性的宣泄，如果总是受到太多冠冕堂皇的说教，对于他们来说也是一种伤害。','3122-3211',NULL,1628939760,1782398652);
INSERT INTO highlights VALUES('934343_34_940-968','934343',34,'怎么看安全感','通常女孩对人的安全感低，对环境的安全感高，而男孩正好相反','940-968',NULL,1628939329,1782398652);
INSERT INTO highlights VALUES('934343_33_1331-1409','934343',33,'怎么看情绪','而低温表达者的画面色彩和内容相对比较理性平和，代表画者的性格比较内向，产生情绪后有自我压抑或克制的倾向，也代表这份情绪处理起来比较缓慢。这类孩子更需要被关注','1331-1409',NULL,1628939157,1782398652);
INSERT INTO highlights VALUES('934343_32_3118-3147','934343',32,'怎么看人物','手代表对环境的支配，伸得越开，表示支配力越强，主动性越强，','3118-3147',NULL,1628938604,1782398652);
INSERT INTO highlights VALUES('934343_31_2863-2923','934343',31,'怎么看布局','4岁以上的孩子画贴着底边或者构图偏下的画，代表孩子配合度和执行力很好，但是缺乏安全感，不太敢于打破常规做事，缺乏幻想力，','2863-2923',NULL,1628938027,1782398652);
INSERT INTO highlights VALUES('934343_31_2153-2194','934343',31,'怎么看布局','代表绘画者内心有憧憬未来、渴望向新领域发展的意愿。如果特别偏右也有回避过去的倾向，','2153-2194',NULL,1628937985,1782398652);
INSERT INTO highlights VALUES('934343_31_1460-1509','934343',31,'怎么看布局','构图偏左：代表绘画者对家庭和父母有强烈的依赖感，还处于需要保护和扶助的阶段，也代表对外界有不信任感','1460-1509',NULL,1628909331,1782398652);
INSERT INTO highlights VALUES('934343_31_1061-1139','934343',31,'怎么看布局','而把图画得很小，画在纸张的边缘，或者没有超过整个画面的1/3，都是比较内向、社会适应性比较弱的表现，如果常常喜欢把内容画在角落，可能有心理压抑情绪或自卑感，','1061-1139',NULL,1628909051,1782398652);
INSERT INTO highlights VALUES('934343_31_756-915','934343',31,'怎么看布局','[插图]','756-915',NULL,1628908930,1782398652);
INSERT INTO highlights VALUES('934343_31_497-557','934343',31,'怎么看布局','大自然中的有壳生物的螺纹方向也都是左旋的，比如蜗牛、海螺。左边代表回归、家、安全、传统，绘画主体偏左代表比较传统和保守。','497-557',NULL,1628908868,1782398652);
INSERT INTO highlights VALUES('934343_30_3154-3204','934343',30,'怎么看形状','喜欢画折线：通常代表分析能力比较强，思维敏捷，反应速度快。但容易陷入相对紧张的状态之中，情绪不稳定，','3154-3204',NULL,1628908808,1782398652);
INSERT INTO highlights VALUES('934343_30_2812-2862','934343',30,'怎么看形状','喜欢画波浪形曲线：通常代表个性随和，富于弹性，适应能力强。也代表善于自我安慰，遇事愿意往好的方面想，','2812-2862',NULL,1628908745,1782398652);
INSERT INTO highlights VALUES('934343_30_2420-2499','934343',30,'怎么看形状','喜欢画矩形的孩子容易遵守秩序，有规则感，做事追求准确，人格稳定性强。如果孩子在5岁之前特别喜欢画矩形，就需要关注，他在个性方面有没有固执、缺少思维弹性的特点，','2420-2499',NULL,1628908711,1782398652);
INSERT INTO highlights VALUES('934343_30_1991-2029','934343',30,'怎么看形状','喜欢画格子：通常代表有恒心、有毅力，做什么事情都有一股不达目的誓不罢休的劲头','1991-2029',NULL,1628908666,1782398652);
INSERT INTO highlights VALUES('934343_30_1640-1697','934343',30,'怎么看形状','喜欢画连环图案：通常代表善于沟通，能站在别人的立场上着想，他们对生活充满信心，适应能力很强，各种环境都能很快地融入','1640-1697',NULL,1628908639,1782398652);
INSERT INTO highlights VALUES('934343_30_1188-1266','934343',30,'怎么看形状','喜欢画三角形：通常代表数学和逻辑思维能力比较强，头脑清醒，思路清晰，有很好的判断力和决断力，但人际关系中适应慢，缺乏耐性，容易急躁，有时爱发脾气，有攻击性。','1188-1266',NULL,1628908505,1782398652);
INSERT INTO highlights VALUES('934343_30_1292-1320','934343',30,'怎么看形状','在这类喜欢画三角、刺的孩子中，创意能力强和喜欢数学的较多','1292-1320',NULL,1628908491,1782398652);
INSERT INTO highlights VALUES('934343_30_847-858','934343',30,'怎么看形状','思维进入有序开发的状态','847-858',NULL,1628908449,1782398652);
INSERT INTO highlights VALUES('934343_30_859-887','934343',30,'怎么看形状','这样的孩子对规律性的认知有特别的能力，具有很强的探索愿望','859-887',NULL,1628908443,1782398652);
INSERT INTO highlights VALUES('934343_30_445-515','934343',30,'怎么看形状','过了涂鸦期，在绘画中仍然特别喜欢画圆形的孩子，一般来说有一定的规划和设计能力，善于掌控时间，合理安排，他们多有很强的创造力和很丰富的想象力，','445-515',NULL,1628908411,1782398652);
INSERT INTO highlights VALUES('934343_29_1770-1816','934343',29,'怎么看色彩','5岁前偏好蓝色，代表有分寸，6岁后常常使用，表示适应力好，但过度使用则表示孩子过于自我约束。','1770-1816',NULL,1628866408,1782398652);
INSERT INTO highlights VALUES('934343_29_1713-1769','934343',29,'怎么看色彩','孩子6岁前偏爱用红色画画是正常的，6岁后过度频繁使用红色，就要注意孩子是否有情绪化和暴力倾向，关注他的感情自控力','1713-1769',NULL,1628866400,1782398652);
INSERT INTO highlights VALUES('934343_29_1647-1684','934343',29,'怎么看色彩','偏爱一两种颜色：代表这个阶段比较冷静、谦让，也代表承压能力弱，交往愿望低。','1647-1684',NULL,1628866375,1782398652);
INSERT INTO highlights VALUES('934343_29_1572-1605','934343',29,'怎么看色彩','喜欢偏淡和纯度不高的颜色：代表这个阶段被动和谦让，容易被别人侵犯，','1572-1605',NULL,1628866339,1782398652);
INSERT INTO highlights VALUES('934343_29_1493-1529','934343',29,'怎么看色彩','喜欢对撞的互补色：代表这个阶段有很强的生命能量，也代表有冲突和矛盾的倾向','1493-1529',NULL,1628866328,1782398652);
INSERT INTO highlights VALUES('934343_29_1423-1464','934343',29,'怎么看色彩','喜欢多种明亮的颜色搭配在一起：代表这个阶段个性开朗乐观，有交往愿望，也容易受欢迎。','1423-1464',NULL,1628866313,1782398652);
INSERT INTO highlights VALUES('934343_29_1363-1394','934343',29,'怎么看色彩','喜欢阴郁的颜色：代表这个阶段承压能力弱，被动、含蓄、多愁善感。','1363-1394',NULL,1628866308,1782398652);
INSERT INTO highlights VALUES('934343_29_1276-1334','934343',29,'怎么看色彩','喜欢很强烈的颜色：代表这个阶段做事有激情，有热情，生命力旺盛，但属于易怒型，需要增加持续力的训练，也可能具有侵犯性。','1276-1334',NULL,1628866292,1782398652);
INSERT INTO highlights VALUES('934343_29_1187-1214','934343',29,'怎么看色彩','偏爱冷色：代表这个阶段理智、思考、严谨、悲伤、心情低落','1187-1214',NULL,1628866280,1782398652);
INSERT INTO highlights VALUES('934343_29_1098-1125','934343',29,'怎么看色彩','偏爱暖色：代表这个阶段个性活泼热情，精力充沛，心情愉快','1098-1125',NULL,1628866271,1782398652);
INSERT INTO highlights VALUES('934343_29_471-500','934343',29,'怎么看色彩','红色象征着温暖和保护，红色也是孩子人生最初都爱过的疗愈色，','471-500',NULL,1628866239,1782398652);
INSERT INTO highlights VALUES('934343_28_569-588','934343',28,'怎么看持续力和爆发力','在人际交往中热情高，但也容易引发冲突。','569-588',NULL,1628866173,1782398652);
INSERT INTO highlights VALUES('934343_28_564-568','934343',28,'怎么看持续力和爆发力','短期攻坚','564-568',NULL,1628866164,1782398652);
INSERT INTO highlights VALUES('934343_28_527-556','934343',28,'怎么看持续力和爆发力','细碎的短线条，代表爆发力好，有激情，也代表有“逆”的能量。','527-556',NULL,1628866154,1782398652);
INSERT INTO highlights VALUES('934343_28_427-493','934343',28,'怎么看持续力和爆发力','线条画得长而稳定，代表孩子有很好的持续力，也代表有“顺”的能量。这种状态的优势是可以做一些专注的探索，在人际交往中表现得通融和接纳。','427-493',NULL,1628866127,1782398652);
INSERT INTO highlights VALUES('934343_27_1773-1831','934343',27,'怎么看生命能量','能够熟练使用笔却还会戳破纸张，往往代表孩子心理能量受阻，或有很重的负面情绪，形成了攻击性，也可能有脑部的病理性问题。','1773-1831',NULL,1628866070,1782398652);
INSERT INTO highlights VALUES('934343_27_1725-1752','934343',27,'怎么看生命能量','如果孩子总是画无序的线条，常常把纸戳破，就要引起注意了','1725-1752',NULL,1628866057,1782398652);
INSERT INTO highlights VALUES('934343_27_1599-1683','934343',27,'怎么看生命能量','教育这样的孩子，不要限制他们的探索，应放手让他们体验。他们不怕挫折，产生的负面后果都要让他们自己去承担，当他们在探索和承担中逐渐学会尊重规则，未来就会有大的担当和作为，','1599-1683',NULL,1628865931,1782398652);
INSERT INTO highlights VALUES('934343_27_1507-1549','934343',27,'怎么看生命能量','这样的孩子往往具有很强的好奇心和抗压能力，但是个性中也会有冲撞主流、破坏规矩的一面。','1507-1549',NULL,1628865906,1782398652);
INSERT INTO highlights VALUES('934343_27_1040-1141','934343',27,'怎么看生命能量','画出比较淡和纤细的线条，很在意细节的孩子，往往在这个阶段有“顺”的生命能量，也很容易顺应主流、尊重长辈和规则。教育这样孩子的重点可以主要放在引导和鼓励上，他们更加适应正向引导，管教这样的孩子不要过于严厉','1040-1141',NULL,1628865883,1782398652);
INSERT INTO highlights VALUES('934343_27_919-954','934343',27,'怎么看生命能量','执拗。但是他们也有很大的优势，对一些认准的事情会做持久的坚持，坚韧不拔','919-954',NULL,1628865841,1782398652);
INSERT INTO highlights VALUES('934343_27_845-888','934343',27,'怎么看生命能量','如果孩子喜欢逆时针画圈，可能有“逆”的能量（逆的生命能量是指不顺应社会主流意识的倾向）','845-888',NULL,1628865834,1782398652);
INSERT INTO highlights VALUES('934343_27_477-547','934343',27,'怎么看生命能量','如果顺时针画圈，这个孩子可能适应性较强，有“顺”的能量（顺的生命能量是指顺应社会主流意识的倾向），在人际交往中，适应宽度较大，包容性也较好。','477-547',NULL,1628865828,1782398652);
INSERT INTO highlights VALUES('934343_23_4439-4518','934343',23,'解读须知','有时候只看孩子的画还不够，还需要家长参与动物模拟测试，让家长把家庭成员以动物的形式画出来，通过动物之间的强弱差距和制衡关系，看出孩子在家庭中的地位和承压状态，','4439-4518',NULL,1628857525,1782398652);
INSERT INTO highlights VALUES('934343_23_4363-4425','934343',23,'解读须知','想了解孩子的家庭亲子关系，最常用的方式是命题让孩子画出自己的家人，而且一定要看孩子先画谁、后画谁，在哪位亲人的身上增加了细节','4363-4425',NULL,1628857512,1782398652);
INSERT INTO highlights VALUES('934343_23_4172-4176','934343',23,'解读须知','多维解读','4172-4176',NULL,1628857422,1782398652);
INSERT INTO highlights VALUES('934343_23_3860-3865','934343',23,'解读须知','个性化解读','3860-3865',NULL,1628856955,1782398652);
INSERT INTO highlights VALUES('934343_23_3357-3452','934343',23,'解读须知','一个孩子正面的优势得到肯定，才能使这部分充分放大，最终让负面的部分逐渐减弱、消失。一知半解的初学者解读出来的往往都是负面信息，如果解读出孩子的一大堆缺点，给孩子造成自卑心理，那还不如不解读。','3357-3452',NULL,1628856673,1782398652);
INSERT INTO highlights VALUES('934343_23_2624-2684','934343',23,'解读须知','当我们面对一团潦草的画，很多人只能看到孩子粗心和不耐烦的一面。而疗愈师应该能看到孩子旺盛的生命力、爆发力、不拘小节的胆识','2624-2684',NULL,1628856224,1782398652);
INSERT INTO highlights VALUES('934343_23_2541-2595','934343',23,'解读须知','而是要告诉家长，我看见了孩子的哪些善意动机、哪些优势天赋、哪些内心呼唤，帮助家长学习如何理解孩子和看到需求。','2541-2595',NULL,1628855878,1782398652);
INSERT INTO highlights VALUES('934343_23_2346-2350','934343',23,'解读须知','正面解读','2346-2350',NULL,1628855353,1782398652);
INSERT INTO highlights VALUES('934343_23_1338-1346','934343',23,'解读须知','1．不能粗暴解读','1338-1346',NULL,1628855026,1782398652);
INSERT INTO highlights VALUES('934343_23_1047-1128','934343',23,'解读须知','通常不建议把解读内容直接告诉孩子，疗愈师可以积极表达对孩子画作的哪些部分有兴趣，很欣赏。解读主要是面向家长的，至于解读什么，解读多少，一定要从帮助孩子的角度出发。','1047-1128',NULL,1628854890,1782398652);
INSERT INTO highlights VALUES('934343_23_752-817','934343',23,'解读须知','有经验的疗愈师看出了绘画中的很多问题，却一直保持缄默，就是因为他们深知解读本身并不重要，只有确定可以帮到对方的时候，解读才有意义。','752-817',NULL,1628854798,1782398652);
INSERT INTO highlights VALUES('934343_22_6502-6613','934343',22,'如何接纳','会选择在角落里偷偷干点坏事的孩子，往往是因为他们正面的诉求得不到满足，也没有更好的表达渠道。这需要老师和家长去理解这些行为背后的心理需求，如果想让孩子减少这样的行为，就要帮助孩子打开更多正向表达的渠道，而不是一味批评指责。','6502-6613',NULL,1628854729,1782398652);
INSERT INTO highlights VALUES('934343_22_6440-6447','934343',22,'如何接纳','深层的本能呼唤','6440-6447',NULL,1628854714,1782398652);
INSERT INTO highlights VALUES('934343_22_6382-6404','934343',22,'如何接纳','日本的艺术界把这类随手的涂鸦叫作“编外艺术”','6382-6404',NULL,1628854700,1782398652);
INSERT INTO highlights VALUES('934343_22_5312-5355','934343',22,'如何接纳','孩子画出带有性器官的画，这是他们在表达自己的性意识，这也是孩子在释放需要性教育的信号。','5312-5355',NULL,1628854598,1782398652);
INSERT INTO highlights VALUES('934343_22_4353-4396','934343',22,'如何接纳','当我们看见一张内容黑暗、充满负面信息的画时，应该懂得这是创作者的情绪表达，并非动机表达','4353-4396',NULL,1628849394,1782398652);
INSERT INTO highlights VALUES('934343_22_4294-4302','934343',22,'如何接纳','4．接纳任何内容','4294-4302',NULL,1628849371,1782398652);
INSERT INTO highlights VALUES('934343_22_3446-3489','934343',22,'如何接纳','最常见的一个原因是，孩子把大量的时间和精力花在了某个他感兴趣的部分上了，顾不上涂颜色。','3446-3489',NULL,1628849299,1782398652);
INSERT INTO highlights VALUES('934343_22_3271-3280','934343',22,'如何接纳','3．接纳发展中状态','3271-3280',NULL,1628849209,1782398652);
INSERT INTO highlights VALUES('934343_22_3199-3217','934343',22,'如何接纳','在艺术的世界中，没有第一，只有唯一。','3199-3217',NULL,1628849059,1782398652);
INSERT INTO highlights VALUES('934343_22_3136-3170','934343',22,'如何接纳','艺术作品是不能拿来比较的。艺术的领域里，没有标准答案，只有个性发展。','3136-3170',NULL,1628849052,1782398652);
INSERT INTO highlights VALUES('934343_22_2283-2290','934343',22,'如何接纳','2．接纳差异化','2283-2290',NULL,1628848968,1782398652);
INSERT INTO highlights VALUES('934343_22_2589-2660','934343',22,'如何接纳','有的孩子天生擅长模仿形体，有的孩子对色彩敏感而忽略形体，有的孩子乐于将看见的物体进行再设计，他们的笔下就会出现真实的蜗牛、印象蜗牛和概念蜗牛，','2589-2660',NULL,1628848960,1782398652);
INSERT INTO highlights VALUES('934343_22_1603-1620','934343',22,'如何接纳','涂鸦就是玩和表达结合在一起的行为，','1603-1620',NULL,1628848860,1782398652);
INSERT INTO highlights VALUES('934343_22_1233-1239','934343',22,'如何接纳','1．接纳涂鸦','1233-1239',NULL,1628848852,1782398652);
INSERT INTO highlights VALUES('934343_22_1508-1523','934343',22,'如何接纳','玩和表达是孩子最重要的两种需求','1508-1523',NULL,1628848823,1782398652);
INSERT INTO highlights VALUES('934343_22_1034-1113','934343',22,'如何接纳','自由的氛围才能够保障疗愈，只有允许孩子在这里足够“放”，在生活中他们才能合理地“收”，适当宣泄是理性的保障，大量儿童正是因为在生活中常常被压抑才出现心理问题。','1034-1113',NULL,1628848687,1782398652);
INSERT INTO highlights VALUES('934343_22_920-1026','934343',22,'如何接纳','当孩子在绘画疗愈过程中出现一些探索、宣泄的行为，例如孩子会泼洒、甩、滴、拍打颜料，或者破坏画纸，将画具和环境弄脏，或者有过于兴奋和攻击性的表现时，都需要疗愈师给予接纳和抱持，不可以采取呵斥性、压制性和限制性的处理','920-1026',NULL,1628848674,1782398652);
INSERT INTO highlights VALUES('934343_22_497-527','934343',22,'如何接纳','接纳实际上是对生命差异性的深度理解，每个孩子都有自己的禀赋。','497-527',NULL,1628819804,1782398652);
INSERT INTO highlights VALUES('934343_21_483-558','934343',21,'疗愈师的职业素养','解读必须本着接纳的态度，对儿童的思考方式、感情、情绪不带任何道德的评判，不带任何高低贵贱的身份偏见，接纳孩子任何形式的绘画，做正面积极、建设性的解读。','483-558',NULL,1628819667,1782398652);
INSERT INTO highlights VALUES('934343_19_761-916','934343',19,'孩子是自己最好的疗愈师','成年人的疗愈大多是单功能的，他们大部分的社会能力已经开发完成，疗伤时只需要用这种简单的填图让自己静心和整理碎片。而孩子的疗愈具有更多的深远意义，疗愈的过程也能增进他们的情感表达力，帮助开发想象力，而且，疗愈会启动孩子的最优天赋，这对找不到天赋方向的孩子来说意义就更加重大，这个行为完全可以影响他们未来的人生发展','761-916',NULL,1628819597,1782398652);
INSERT INTO highlights VALUES('934343_19_1008-1157','934343',19,'孩子是自己最好的疗愈师','那些对孩子有强烈帮助冲动的家长，能觉察一下自己是否在心底深处藏着一份对孩子的不信任。每个生命都是一个高智能的灵体，孩子自己有具足的天资，知道什么时候该做什么，怎么做。孩子自发的选择，不是他的菜就是他的药。请相信，孩子才是他自己最好的疗愈师。','1008-1157',NULL,1628819525,1782398652);
INSERT INTO highlights VALUES('934343_17_4870-4906','934343',17,'疗愈的几个阶段','这份疼痛会帮助他们开启深刻的思考。荣格曾说过，精神成长的最高阶段是升华。','4870-4906',NULL,1628779393,1782398652);
INSERT INTO highlights VALUES('934343_17_4755-4802','934343',17,'疗愈的几个阶段','孩子的绘画疗愈，看起来是疗伤的过程，但实质上是孩子通过自己的天赋实现心灵成长、精神升华的过程。','4755-4802',NULL,1628779375,1782398652);
INSERT INTO highlights VALUES('934343_17_5133-5165','934343',17,'疗愈的几个阶段','这份收获也是疗愈的最高境界和终极目的——将痛苦升华为思想和大爱。','5133-5165',NULL,1628779292,1782398652);
INSERT INTO highlights VALUES('934343_17_4037-4046','934343',17,'疗愈的几个阶段','第四个阶段，升华。','4037-4046',NULL,1628779150,1782398652);
INSERT INTO highlights VALUES('934343_17_2736-2764','934343',17,'疗愈的几个阶段','这个时期不能要求他们和正常的孩子一样承担繁重的学业压力。','2736-2764',NULL,1628779043,1782398652);
INSERT INTO highlights VALUES('934343_17_2498-2510','934343',17,'疗愈的几个阶段','第三个阶段，疗愈和修复。','2498-2510',NULL,1628779003,1782398652);
INSERT INTO highlights VALUES('934343_17_1944-1953','934343',17,'疗愈的几个阶段','第二个阶段，诉说。','1944-1953',NULL,1628778938,1782398652);
INSERT INTO highlights VALUES('934343_17_1889-1915','934343',17,'疗愈的几个阶段','一定要接纳孩子任何形式的表达，阻断表达是非常危险的。','1889-1915',NULL,1628778934,1782398652);
INSERT INTO highlights VALUES('934343_17_1638-1717','934343',17,'疗愈的几个阶段','老师，我的孩子为什么总在课本上画一些很暴力的画面呢？”柳贞子老师做了一个呕吐的动作说：“那是孩子在呕吐心里的垃圾，你如果不允许他呕吐，他就会这里疼，那里病。”','1638-1717',NULL,1628778877,1782398652);
INSERT INTO highlights VALUES('934343_17_641-659','934343',17,'疗愈的几个阶段','通常创伤的疗愈需要经历四个主要过程，','641-659',NULL,1628778752,1782398652);
INSERT INTO highlights VALUES('934343_17_708-716','934343',17,'疗愈的几个阶段','第一个阶段，宣泄','708-716',NULL,1628778745,1782398652);
INSERT INTO highlights VALUES('934343_17_424-471','934343',17,'疗愈的几个阶段','弗洛伊德说：未被表达的情绪永远都不会消失。它们只是被活埋了，有朝一日会以更丑恶的方式爆发出来。','424-471',NULL,1628778681,1782398652);
INSERT INTO highlights VALUES('934343_16_1560-1660','934343',16,'何为疗愈？','当孩子开始自由创作时，既调动了眼睛，又调动了手，还调动了情绪、记忆、设计思维、创意思维等资源。假如在绘画的过程中还配有音乐，听觉也就介入了这个过程，这种疗愈激活的大脑神经元就非常多，疗愈的效果也最好。','1560-1660',NULL,1628778644,1782398652);
INSERT INTO highlights VALUES('934343_16_1256-1268','934343',16,'何为疗愈？','宣泄即疗愈，疏导即疗愈。','1256-1268',NULL,1628778517,1782398652);
INSERT INTO highlights VALUES('934343_16_1093-1105','934343',16,'何为疗愈？','满足即疗愈，释怀即疗愈。','1093-1105',NULL,1628778500,1782398652);
INSERT INTO highlights VALUES('934343_16_583-598','934343',16,'何为疗愈？','所以，表达即疗愈，共鸣即疗愈。','583-598',NULL,1628778495,1782398652);
INSERT INTO highlights VALUES('934343_15_1798-1833','934343',15,'开启右脑的钥匙','所以家长们必须知道一个常识，处理孩子情绪的问题一定要多用右脑优势功能。','1798-1833',NULL,1628778411,1782398652);
INSERT INTO highlights VALUES('934343_15_898-1057','934343',15,'开启右脑的钥匙','[插图]','898-1057',NULL,1628778308,1782398652);
INSERT INTO highlights VALUES('934343_15_552-604','934343',15,'开启右脑的钥匙','左脑主要负责语言、逻辑、推理、分析等理性的认知功能，右脑主要负责艺术、创意、感受、直觉等感性的情绪功能。','552-604',NULL,1628778247,1782398652);
INSERT INTO highlights VALUES('934343_14_606-637','934343',14,'绘画为何能疗愈？','大多数的心理问题都来自情绪，能够发现情绪、顺应情绪、疏导情绪，','606-637',NULL,1628778159,1782398652);
INSERT INTO highlights VALUES('934343_13_4885-4950','934343',13,'孩子的画在说什么？','潜意识最常使用的几种编码语言是：集体潜意识投射、注意力投射、成长投射、生理投射、象征投射、共鸣投射、需求投射、好恶投射、位置投射，','4885-4950',NULL,1628778098,1782398652);
INSERT INTO highlights VALUES('934343_13_4376-4380','934343',13,'孩子的画在说什么？','位置投射','4376-4380',NULL,1628778019,1782398652);
INSERT INTO highlights VALUES('934343_13_4247-4286','934343',13,'孩子的画在说什么？','在画人物的时候，潜意识会将绘画者的生命状态不知不觉地投射在画中人的相应的位置上','4247-4286',NULL,1628778016,1782398652);
INSERT INTO highlights VALUES('934343_13_3737-3741','934343',13,'孩子的画在说什么？','好恶投射','3737-3741',NULL,1628777901,1782398652);
INSERT INTO highlights VALUES('934343_13_3136-3140','934343',13,'孩子的画在说什么？','共鸣投射','3136-3140',NULL,1628777887,1782398652);
INSERT INTO highlights VALUES('934343_13_1965-2164','934343',13,'孩子的画在说什么？','情绪激烈的时候，孩子会选用大红色来画画；情绪愉快的时候，孩子会画出五彩缤纷的色彩；情绪消极抑郁的时候，孩子就会选用黑色、灰色来画乌云密布的天空、破败的城市等。如果孩子有快乐的情绪，就会画出多彩的画面，画高举的双手、有笑脸的人。如果孩子有悲伤、失落的情绪，就会画有背影、落叶等元素的画面。如果孩子有激烈的情绪和攻击愿望，就会画出激烈的色彩，画武器、战场等画面，如图2-3-04所示。这是象征投射现象。','1965-2164',NULL,1628777721,1782398652);
INSERT INTO highlights VALUES('934343_13_1222-1248','934343',13,'孩子的画在说什么？','通过绘画可以发现孩子身体的病症，这都是生理投射现象。','1222-1248',NULL,1628777661,1782398652);
INSERT INTO highlights VALUES('934343_12_1645-1717','934343',12,'画中的集体无意识','男孩喜欢画动态画面，主人公以男性为主，喜欢机械、武器、怪物、战场等主题。女孩喜欢画静态画面，主人公以女性为主，喜欢画公主、花卉、宠物、饰物等主题','1645-1717',NULL,1628777406,1782398652);
INSERT INTO highlights VALUES('934343_12_1158-1178','934343',12,'画中的集体无意识','还有一个现象比较普遍，就是画面追求对称。','1158-1178',NULL,1628777337,1782398652);
INSERT INTO highlights VALUES('934343_12_1240-1252','934343',12,'画中的集体无意识','做事情追求平衡，讲究中庸','1240-1252',NULL,1628777327,1782398652);
INSERT INTO highlights VALUES('934343_12_809-819','934343',12,'画中的集体无意识','讲究秩序的集体无意识','809-819',NULL,1628777239,1782398652);
INSERT INTO highlights VALUES('934343_11_1696-1765','934343',11,'解读原理','国内的孩子在学校里画画时，常常会画太阳、笑脸、家庭和谐的场景，他们会不自觉地迎合主旋律和权威者的期待，这样的画就掩盖了很多内在的真实信息，','1696-1765',NULL,1628770375,1782398652);
INSERT INTO highlights VALUES('934343_11_1376-1436','934343',11,'解读原理','心理机制为了保护我们，会在语言表达上设有各种防御，因此通过语言获取心理信息是比较难的。但大部分人都不会在绘画中设置防御，','1376-1436',NULL,1628770314,1782398652);
INSERT INTO highlights VALUES('934343_11_785-875','934343',11,'解读原理','我们若想了解孩子在想什么，只要读懂那些图形、色彩语言背后的潜台词，就知道他们是怎么想的了。而我们想告诉孩子一些事时，与其给孩子讲大道理，不如用绘本、游戏的方式，这更容易让他们接受。','785-875',NULL,1628770197,1782398652);
INSERT INTO highlights VALUES('934343_11_522-568','934343',11,'解读原理','内心世界无时无刻不在外部世界寻找另一个自己，我们也无时无刻不通过一些外部媒介表达内心的自己。','522-568',NULL,1628770143,1782398652);
INSERT INTO highlights VALUES('934343_11_462-466','934343',11,'解读原理','心理投射','462-466',NULL,1628770127,1782398652);
