INSERT INTO highlights VALUES('934343_9_2257-2326','934343',9,'什么是绘画疗愈','越是自由随意的涂鸦，可被解读出来的信息就越多。越小的孩子越适合绘画疗愈，疗愈的效果也越好，绘画疗愈已成为药物治疗和语言治疗的一个重要补充。','2257-2326',NULL,1628770014,1782398652);
INSERT INTO highlights VALUES('934343_9_2129-2158','934343',9,'什么是绘画疗愈','可以通过绘画帮助孩子疗愈非病理性的情绪、情感、表达等问题。','2129-2158',NULL,1628769990,1782398652);
INSERT INTO highlights VALUES('934343_6_1199-1272','934343',6,'序四','静茹老师把孩子的天赋比作沉在水里的一头巨兽，露在外面的是两个犄角，一个是兴趣，另一个是特长，如此通俗易懂，又如此形象贴切地给出了发现天赋的关键点。','1199-1272',NULL,1628644997,1782398652);
INSERT INTO highlights VALUES('934343_4_624-643','934343',4,'序二','慕容引刀（著名绘本画家）','624-643',NULL,1628644109,1782398652);
INSERT INTO highlights VALUES('934343_3_1198-1230','934343',3,'序一','当功利和焦虑笼罩了学校和家庭，孩子们离自由和快乐也就渐行渐远了。','1198-1230',NULL,1628643954,1782398652);
INSERT INTO highlights VALUES('934343_3_981-1036','934343',3,'序一','这个世界会好的，哪怕我们终年营营役役，满脸狼狈，却依然相信这一点并为之努力。因为我们有孩子，他们是全部的希望。','981-1036',NULL,1628643910,1782398652);
