INSERT INTO highlights VALUES('38260364_104_201-253','38260364',106,'第104章 最后一个建议——关于保密','交流，让每一个针对年轻头脑和心灵的词都能唤醒内心的精神力量，引起头脑和心脏工作，进行自我认知和自我完善。','626-678',NULL,1628078738,1782398654);
INSERT INTO highlights VALUES('38260364_104_153-185','38260364',106,'第104章 最后一个建议——关于保密','为什么人不应该知道、感受到自己在被教育？因为真正的教育是自我教育','578-610',NULL,1628078717,1782398654);
