INSERT INTO highlights VALUES('38260364_103_811-866','38260364',105,'第103章 怎样与懒惰作斗争？','预防懒惰的一个有力手段是克制愿望。要让人从童年起就通过自己的经验认识到“不能”“应该”“可能”这些概念的本质。','1333-1388',NULL,1628078482,1782398654);
