INSERT INTO highlights VALUES('38260364_99_2765-2864','38260364',101,'第99章 怎样珍惜儿童的信任？','要知道，一个控制不住的淘气包和“爱闹事的人”在必要时候会表现出自己的善良热心，而意志薄弱、无条件服从的学生，经常会对一切无动于衷，他也不会觉得自己残酷，不会认为自己会直接无视因为个人利益而产生的不幸','3512-3611',NULL,1628066433,1782398654);
INSERT INTO highlights VALUES('38260364_99_2368-2413','38260364',101,'第99章 怎样珍惜儿童的信任？','教师应该特别谨慎运用自己的权力：大人的意志可能很容易就会变成专横，有时候还会变成对人的摧残','3090-3135',NULL,1628066327,1782398654);
