INSERT INTO highlights VALUES('38260364_98_283-336','38260364',100,'第98章 教师的权力是什么？它应该如何体现？','你跨进学校的大门，决定一生致力于创造人的崇高使命，请记住，我的朋友，你可能会陷入反复无常、情绪冲动的危险。','712-765',NULL,1628065904,1782398654);
INSERT INTO highlights VALUES('38260364_97_807-884','38260364',99,'第97章 要善于使美德具有吸引力','每年春天，高年级学生都会给独居老人建造几个花圃，这项劳动笼罩着美德的浪漫光环。在这些日子，学生们体验到一种思想：我们所有人都会变老，年轻一代也会关心我们。','1280-1357',NULL,1628065816,1782398654);
INSERT INTO highlights VALUES('38260364_97_777-807','38260364',99,'第97章 要善于使美德具有吸引力','我们的青年男女学生努力为那些丧失劳动能力、独居的人带去快乐。','1250-1280',NULL,1628065804,1782398654);
INSERT INTO highlights VALUES('38260364_96_1310-1411','38260364',98,'第96章 怎样让时代精神深入青少年的头脑和心灵？','我年轻的朋友们，你们要知道，在我们的社会中，没有什么比人更珍贵的了。但是如果人听从内心的驱使为了什么付出自己的生命，那就意味着有的东西是我们每个人的生命无法与之相提并论的，那高尚神圣的东西，就是祖国。”','1891-1992',NULL,1628065520,1782398654);
INSERT INTO highlights VALUES('38260364_96_569-602','38260364',98,'第96章 怎样让时代精神深入青少年的头脑和心灵？','一周召集一次所有高年级学生，由校长给他们简要讲讲国内外发生的大事。','1050-1083',NULL,1628065387,1782398654);
INSERT INTO highlights VALUES('38260364_95_3185-3247','38260364',97,'第95章 课堂上的思想教育是什么？','思考知识恰好是，也应该是与别人的信念“切磋”。关于自然和社会的知识不应是一套不容反驳的真理，而应该是斗争的结果，是观点的碰撞','4346-4408',NULL,1628065237,1782398654);
INSERT INTO highlights VALUES('38260364_95_240-255','38260364',97,'第95章 课堂上的思想教育是什么？','教育是从知识转变成信念开始的。','664-679',NULL,1628064662,1782398654);
INSERT INTO highlights VALUES('38260364_92_1929-1957','38260364',94,'第92章 在什么条件下，集体能够有效发挥教育个人的功能？','在学校集体里领导别人意味着首先要在劳动中成为大家的榜样。','2614-2642',NULL,1628058197,1782398654);
