INSERT INTO highlights VALUES('38260364_90_124-166','38260364',92,'第90章 怎样在脑力劳动中培养自律？','要让教师的知识储备是他在课堂上讲的知识的一百倍，要让每个学生都有自己钟爱的脑力劳动。','524-566',NULL,1628057033,1782398654);
INSERT INTO highlights VALUES('38260364_90_308-346','38260364',92,'第90章 怎样在脑力劳动中培养自律？','因为你阅读的一切，都是上课教材的无数个知识点。这些点可以称之为“记忆锚点”，','733-771',NULL,1628056997,1782398654);
INSERT INTO highlights VALUES('38260364_88_68-124','38260364',90,'第88章 怎样激励道德方面的自我教育？','我们在物质世界里碰到的每件东西上，都会留下自己的痕迹。但我们留下的最显眼、最不可磨灭的痕迹是在与我们交往的人身上','469-525',NULL,1628055138,1782398654);
INSERT INTO highlights VALUES('38260364_87_2706-2731','38260364',89,'第87章 请掌握与学生单独谈话的艺术','自我教育包括几个方面：道德、劳动、学习、体育运动。','3506-3531',NULL,1628045055,1782398654);
INSERT INTO highlights VALUES('38260364_87_2633-2656','38260364',89,'第87章 请掌握与学生单独谈话的艺术','你的学生尊重自己，珍视你说的关于自己的每一句话','3408-3431',NULL,1628045045,1782398654);
INSERT INTO highlights VALUES('38260364_87_2564-2626','38260364',89,'第87章 请掌握与学生单独谈话的艺术','教师作为教育者最重要的一项任务就是，要爱护年轻人心里愉悦的智力情感的火苗，不要让它熄灭，一旦熄灭，让它重新点燃将会非常困难。','3314-3376',NULL,1628045030,1782398654);
INSERT INTO highlights VALUES('38260364_87_2348-2392','38260364',89,'第87章 请掌握与学生单独谈话的艺术','我想把自我尊重称为“儿童的文化修养”，这是一种增加思想、激励和愿望纯洁性的精神上的花朵。','3098-3142',NULL,1628044993,1782398654);
INSERT INTO highlights VALUES('38260364_87_2020-2081','38260364',89,'第87章 请掌握与学生单独谈话的艺术','明白并体验到，他今天比昨天更好，他的心灵中有人性的美德，而这种美德融入心灵，在很大程度上取决于他自己，取决于他的个人意志。','2745-2806',NULL,1628044945,1782398654);
INSERT INTO highlights VALUES('38260364_87_1004-1039','38260364',89,'第87章 请掌握与学生单独谈话的艺术','对年轻的心伤害最大的惩罚之一就是，在集体面前展示个人隐私、内心的东西。','1554-1589',NULL,1628044822,1782398654);
INSERT INTO highlights VALUES('38260364_87_821-853','38260364',89,'第87章 请掌握与学生单独谈话的艺术','请保守别人告诉你的秘密，这是关乎教育和自我教育的基本教育规则之一','1371-1403',NULL,1628044794,1782398654);
INSERT INTO highlights VALUES('38260364_87_583-598','38260364',89,'第87章 请掌握与学生单独谈话的艺术','善于倾听孩子就是一大教育艺术。','1083-1098',NULL,1628044753,1782398654);
INSERT INTO highlights VALUES('38260364_87_99-139','38260364',89,'第87章 请掌握与学生单独谈话的艺术','只有你从不试图怀着压制、约束孩子的请求或要求和他谈话，他才会坦率地向你敞开心扉。','524-564',NULL,1628044694,1782398654);
INSERT INTO highlights VALUES('38260364_86_1650-1664','38260364',88,'第86章 怎样教学生自己教育自己？','首先就是与孩子进行单独谈话。','2719-2733',NULL,1628044644,1782398654);
INSERT INTO highlights VALUES('38260364_86_1038-1060','38260364',88,'第86章 怎样教学生自己教育自己？','因为惩罚已经把学生从良心的谴责中解放出来了，','2032-2054',NULL,1628044580,1782398654);
INSERT INTO highlights VALUES('38260364_86_1074-1128','38260364',88,'第86章 怎样教学生自己教育自己？','，如果良心沉睡了，那就谈不上自我教育。被惩罚的人会认为：对于自己的行为，我没什么可再想的了，我得到了应得的。','2068-2122',NULL,1628044569,1782398654);
INSERT INTO highlights VALUES('38260364_86_742-773','38260364',88,'第86章 怎样教学生自己教育自己？','在你们的集体中，应该以安静平和为主，而不应该大喊大叫、神经质。','1521-1552',NULL,1628044500,1782398654);
INSERT INTO highlights VALUES('38260364_86_481-526','38260364',88,'第86章 怎样教学生自己教育自己？','自我教育需要一种非常重要、强有力的刺激因素——自尊心、尊重自己、想要今天比昨天更好的愿望。','1235-1280',NULL,1628044463,1782398654);
INSERT INTO highlights VALUES('38260364_86_356-370','38260364',88,'第86章 怎样教学生自己教育自己？','要教人从小认识自己、教育自己','830-844',NULL,1628044438,1782398654);
INSERT INTO highlights VALUES('38260364_85_512-537','38260364',87,'第85章 请让自己的学生远离空话','诚实是对别人诚实的同时也忠于自己，忠于自己的良知。','985-1010',NULL,1628044309,1782398654);
INSERT INTO highlights VALUES('38260364_80_1044-1089','38260364',82,'第80章 怎样教共青团员生活在公共利益的世界里？','少一些学生集体劳动中程式化的书呆子气，这就是我们培养人从小关心公共利益的精神时提出的要求。','1575-1620',NULL,1628040952,1782398654);
INSERT INTO highlights VALUES('38260364_79_1080-1085','38260364',81,'第79章 请珍惜青少年纯洁的精神热情','“热心课”','1605-1610',NULL,1628040760,1782398654);
INSERT INTO highlights VALUES('38260364_75_113-121','38260364',77,'第75章 怎样能让少年对我们的生活和斗争不无动于衷？','培育爱国者和公民','546-554',NULL,1628039945,1782398654);
INSERT INTO highlights VALUES('38260364_74_132-148','38260364',76,'第74章 怎样激励人不断地进行道德发展和完善？','一个人是不可能形成自己的“我”的','537-553',NULL,1628039855,1782398654);
INSERT INTO highlights VALUES('38260364_74_70-111','38260364',76,'第74章 怎样激励人不断地进行道德发展和完善？','要让人追求自己的道德美好和完善，他应该看到自己身边的人——自己同伴的道德美好和完善','475-516',NULL,1628039850,1782398654);
INSERT INTO highlights VALUES('38260364_69_460-491','38260364',71,'第69章 怎样培养服从和领导的能力？怎样培养严格要求的精神？','领导者让集体去做的这件事，本质上应该是为人、为社会服务的事情。','897-928',NULL,1628039083,1782398654);
INSERT INTO highlights VALUES('38260364_67_2115-2150','38260364',69,'第67章 集体是一种教育方法，怎样创建集体？集体的基础是什么？','智力一致是对知识的普遍追求，是尊重科学思想、书籍、聪明有教养的人的精神','2753-2788',NULL,1627977184,1782398654);
INSERT INTO highlights VALUES('38260364_67_719-774','38260364',69,'第67章 集体是一种教育方法，怎样创建集体？集体的基础是什么？','我总是这样开始建立集体，让孩子们对善与恶，换句话说，就是对“什么是好，什么是坏”有共同一致的概念、看法和认知。','1232-1287',NULL,1627976825,1782398654);
INSERT INTO highlights VALUES('38260364_67_454-474','38260364',69,'第67章 集体是一种教育方法，怎样创建集体？集体的基础是什么？','思想一致、智力一致、感情一致、组织一致。','917-937',NULL,1627976788,1782398654);
INSERT INTO highlights VALUES('38260364_66_1730-1761','38260364',68,'第66章 教师作为教育者应该具备什么品质？','你的知识、求知欲、对阅读的热情，都是你本人教育力量的丰富源泉。','2648-2679',NULL,1627976548,1782398654);
INSERT INTO highlights VALUES('38260364_66_197-268','38260364',68,'第66章 教师作为教育者应该具备什么品质？','学生是教育者的一面镜子。教育的艺术和技巧在于，要会从学生身上看到自己，在这个我们从一个小孩子培养起来的会思考、会感知、会体悟的生命身上看到自己','764-835',NULL,1627976401,1782398654);
INSERT INTO highlights VALUES('38260364_66_154-182','38260364',68,'第66章 教师作为教育者应该具备什么品质？','只有个性才能影响个性的发展和定型，只有性格才能养成性格。','557-585',NULL,1627976372,1782398654);
INSERT INTO highlights VALUES('38260364_63_789-850','38260364',65,'第63章 怎样用劳动使心灵高尚、培养人性？','但为了攀上顶峰，必须走过最初的台阶——为家庭的物质财富而工作，创造物质价值，满足人吃好、穿暖、住在设施完善的房子里的需求。','1392-1453',NULL,1627959277,1782398654);
INSERT INTO highlights VALUES('38260364_62_1090-1114','38260364',64,'第62章 怎样与家庭共同指导儿童劳动？','正是因为劳动，人才获得了用心认识周围世界的能力。','1641-1665',NULL,1627958399,1782398654);
INSERT INTO highlights VALUES('38260364_61_1388-1416','38260364',63,'第61章 怎样随着孩子的成长和发展，加强与家长的教育工作？','一个人怎样劳动，做事情的目的是什么，决定着他的思维方式。','2024-2052',NULL,1627958229,1782398654);
INSERT INTO highlights VALUES('38260364_61_1101-1175','38260364',63,'第61章 怎样随着孩子的成长和发展，加强与家长的教育工作？','高年级学生的社会成熟，我们要做到，让每一个男孩、女孩都参与社会生产，真正参加劳动，不是学校安排的以教育为目的的劳动，而是以创造物质财富为目的的劳动。','1637-1711',NULL,1627958201,1782398654);
INSERT INTO highlights VALUES('38260364_61_1016-1044','38260364',63,'第61章 怎样随着孩子的成长和发展，加强与家长的教育工作？','青少年社会成熟的最主要根源在于他们对家庭收入的劳动贡献。','1552-1580',NULL,1627958170,1782398654);
INSERT INTO highlights VALUES('38260364_61_616-647','38260364',63,'第61章 怎样随着孩子的成长和发展，加强与家长的教育工作？','人的道德面貌，在很大程度上取决于他在童年时期体验过的快乐的源泉','1102-1133',NULL,1627958126,1782398654);
INSERT INTO highlights VALUES('38260364_61_108-134','38260364',63,'第61章 怎样随着孩子的成长和发展，加强与家长的教育工作？','图书日的意义在于，让父母为家庭藏书增加一些文学作品。','519-545',NULL,1627958034,1782398654);
INSERT INTO highlights VALUES('38260364_60_1144-1186','38260364',62,'第60章 怎样让孩子愿意好好学习？','在这个缺乏教育常识的奇怪观点里，人不再是各种各样特点、品质、能力、爱好的和谐统一体。','1618-1660',NULL,1627957971,1782398654);
INSERT INTO highlights VALUES('38260364_60_37-81','38260364',62,'第60章 怎样让孩子愿意好好学习？','使他的脑力劳动人格化，使他感到为自己的亲人——母亲、父亲——带来快乐，是一种高尚的愿望。','436-480',NULL,1627957850,1782398654);
INSERT INTO highlights VALUES('38260364_59_1901-1949','38260364',61,'第59章 进行情感教育的训练应该是什么样？','一个孩子体验到做善事的需求，体验到作为一个人的需求——马克思把这种需求称为自由人最高尚的精神财富','2729-2777',NULL,1627957762,1782398654);
INSERT INTO highlights VALUES('38260364_58_194-204','38260364',60,'第58章 怎样才能让作为教育者的父亲和母亲保持一致？','溺爱、专横、包办的爱','602-612',NULL,1627954816,1782398654);
INSERT INTO highlights VALUES('38260364_57_2318-2351','38260364',59,'第57章 怎样才能让学生听进去教育者的话？','要知道在创造人的过程中极其重要的是，两个雕刻师不能站在对立的位置。','2996-3029',NULL,1627906100,1782398654);
INSERT INTO highlights VALUES('38260364_57_2079-2148','38260364',59,'第57章 怎样才能让学生听进去教育者的话？','但事实上，我们对学前儿童教育问题的关心，最终会得到百倍的补偿。正是因为这些关心，我们的工作会更加轻松，我们不会碰到其他学校里出现的许多问题','2757-2826',NULL,1627906072,1782398654);
INSERT INTO highlights VALUES('38260364_57_646-733','38260364',59,'第57章 怎样才能让学生听进去教育者的话？','你未来学生的道德在很大程度上取决于，他是否会把自己的一份真心献给一个人，还是活在自己的封闭世界里，只有一点点自己关心的事情和有限的兴趣。个人主义就是从没有接受情感教育开始的。','1124-1211',NULL,1627905917,1782398654);
INSERT INTO highlights VALUES('38260364_54_949-993','38260364',56,'第54章 关于自己孩子的教育问题','你还要有自己的藏书。你的孩子刚一上学，就带他去书架看书。请教会他热爱读书，尊重文化珍宝。','1547-1591',NULL,1627904751,1782398654);
INSERT INTO highlights VALUES('38260364_54_630-678','38260364',56,'第54章 关于自己孩子的教育问题','请找时间，每天都和自己的孩子聊聊天，和他一起读读书，一起去看看大自然。而这对于父亲来说尤为重要。','1153-1201',NULL,1627904699,1782398654);
INSERT INTO highlights VALUES('38260364_54_368-395','38260364',56,'第54章 关于自己孩子的教育问题','不要在自己孩子在场的时候，毫无顾忌地评价个别学生和教师','841-868',NULL,1627904665,1782398654);
INSERT INTO highlights VALUES('38260364_54_172-204','38260364',56,'第54章 关于自己孩子的教育问题','教育并不是什么专门的、人为组织的“活动”，而首先是一种生活方式。','620-652',NULL,1627904631,1782398654);
INSERT INTO highlights VALUES('38260364_54_119-168','38260364',56,'第54章 关于自己孩子的教育问题','不要把家庭变成一个小学校，尽量把学校的气氛隔离在你家门外，让你和你的孩子只是一个简单、美好的家庭。','542-591',NULL,1627904587,1782398654);
INSERT INTO highlights VALUES('38260364_53_1035-1093','38260364',55,'第53章 关于教师日记的建议','我认为，发现他们的行为、课上课下脑力劳动中的细微特点非常重要。记录这些观察结果，并进行思考，对于教师的工作有很大帮助','1706-1764',NULL,1627872250,1782398654);
INSERT INTO highlights VALUES('38260364_53_1014-1035','38260364',55,'第53章 关于教师日记的建议','日记中占重要地位的是对“困难”学生的记录。','1685-1706',NULL,1627872235,1782398654);
INSERT INTO highlights VALUES('38260364_53_936-988','38260364',55,'第53章 关于教师日记的建议','我会在自己的日记中记录，学生的家里有哪些藏书，其父母的受教育程度如何，母亲和父亲会花多少时间来教育孩子。','1557-1609',NULL,1627872226,1782398654);
INSERT INTO highlights VALUES('38260364_53_1236-1245','38260364',55,'第53章 关于教师日记的建议','日记可以教人思考。','1932-1941',NULL,1627872202,1782398654);
INSERT INTO highlights VALUES('38260364_53_2-17','38260364',55,'第53章 关于教师日记的建议','我建议每一位教师都要写教育日记','398-413',NULL,1627872055,1782398654);
INSERT INTO highlights VALUES('38260364_52_968-1021','38260364',54,'第52章 教师要制订哪些计划？','在写专题计划的本子上，必须要留出些空白地方，如果出现一些与原计划不同的意外情况，则可以在这里做相应的修改。','1765-1818',NULL,1627872030,1782398654);
INSERT INTO highlights VALUES('38260364_52_759-780','38260364',54,'第52章 教师要制订哪些计划？','专题计划中要指明，课上要学些什么，怎么学。','1506-1527',NULL,1627872000,1782398654);
INSERT INTO highlights VALUES('38260364_52_710-719','38260364',54,'第52章 教师要制订哪些计划？','专题计划或课时计划','1457-1466',NULL,1627871986,1782398654);
INSERT INTO highlights VALUES('38260364_52_546-551','38260364',54,'第52章 教师要制订哪些计划？','自然界观察','1243-1248',NULL,1627871956,1782398654);
INSERT INTO highlights VALUES('38260364_52_472-489','38260364',54,'第52章 教师要制订哪些计划？','10.小学阶段要组织的旅游参观地。','1169-1186',NULL,1627871946,1782398654);
INSERT INTO highlights VALUES('38260364_52_448-468','38260364',54,'第52章 教师要制订哪些计划？','9.教师和学生要制作的直观教具大致清单。','1120-1140',NULL,1627871935,1782398654);
INSERT INTO highlights VALUES('38260364_52_429-443','38260364',54,'第52章 教师要制订哪些计划？','学生在小学阶段要写的作文主题','1076-1090',NULL,1627871923,1782398654);
INSERT INTO highlights VALUES('38260364_52_410-423','38260364',54,'第52章 教师要制订哪些计划？','去思想和言语发源地的旅行。','1032-1045',NULL,1627871918,1782398654);
INSERT INTO highlights VALUES('38260364_52_313-338','38260364',54,'第52章 教师要制订哪些计划？','学生在小学阶段应该牢固掌握，并终生记忆的基础词汇。','885-910',NULL,1627871893,1782398654);
INSERT INTO highlights VALUES('38260364_52_347-364','38260364',54,'第52章 教师要制订哪些计划？','拓宽学生眼界的科普读物和手册清单。','944-961',NULL,1627871887,1782398654);
INSERT INTO highlights VALUES('38260364_52_368-396','38260364',54,'第52章 教师要制订哪些计划？','单独列出一些针对思想过程相对迟缓的困难学生的书籍、手册。','965-993',NULL,1627871878,1782398654);
INSERT INTO highlights VALUES('38260364_52_283-300','38260364',54,'第52章 教师要制订哪些计划？','4.要求背诵的课文和文学作品片段。','830-847',NULL,1627871849,1782398654);
INSERT INTO highlights VALUES('38260364_52_262-279','38260364',54,'第52章 教师要制订哪些计划？','3.和学生谈话时会用到的绘画作品。','784-801',NULL,1627871845,1782398654);
INSERT INTO highlights VALUES('38260364_52_227-258','38260364',54,'第52章 教师要制订哪些计划？','2.学生们要在学校里听的音乐作品（学校里最好能有一间音乐室）。','724-755',NULL,1627871840,1782398654);
INSERT INTO highlights VALUES('38260364_52_173-194','38260364',54,'第52章 教师要制订哪些计划？','1.儿童应该在小学阶段读完的文学作品书目。','645-666',NULL,1627871832,1782398654);
INSERT INTO highlights VALUES('38260364_52_117-138','38260364',54,'第52章 教师要制订哪些计划？','对于小学教师，制订几年的远景计划非常重要。','564-585',NULL,1627871821,1782398654);
INSERT INTO highlights VALUES('38260364_50_1398-1496','38260364',52,'第50章 给在大学校里工作的教师的建议','今天在已经耕耘过的肥沃土壤中播下种子，却远不是在明天就会发芽的。在很多情况下，今天所做的工作，只有经过若干年之后才可以进行评价。这是教育工作中一条非常重要的规律，它会始终让你以长远的目光进行思考。','2049-2147',NULL,1627871257,1782398654);
INSERT INTO highlights VALUES('38260364_50_1209-1223','38260364',52,'第50章 给在大学校里工作的教师的建议','要提高教育技巧，首先是要自修','1835-1849',NULL,1627871202,1782398654);
INSERT INTO highlights VALUES('38260364_50_1058-1158','38260364',52,'第50章 给在大学校里工作的教师的建议','在教育工作中，没有一项成果是只取决于某一个因素的，似乎你只要这样做，就一定会得到这样或那样的结果。每种结果都取决于数十个或上百个因素，有时候甚至是与研究、观察和分析的对象相距遥远、没有直接联系的因素。','1634-1734',NULL,1627871117,1782398654);
INSERT INTO highlights VALUES('38260364_50_935-950','38260364',52,'第50章 给在大学校里工作的教师的建议','到底良好的教学效果取决于什么。','1461-1476',NULL,1627871083,1782398654);
INSERT INTO highlights VALUES('38260364_50_434-466','38260364',52,'第50章 给在大学校里工作的教师的建议','作业本是全部教育过程的结果，书写质量取决于学生阅读的数量和质量。','910-942',NULL,1627871028,1782398654);
INSERT INTO highlights VALUES('38260364_50_308-338','38260364',52,'第50章 给在大学校里工作的教师的建议','我想建议你，在一开始，先去看看所有低年级教师各自学生的作业本','784-814',NULL,1627871008,1782398654);
INSERT INTO highlights VALUES('38260364_48_549-630','38260364',50,'第48章 怎么训练孩子流利书写？','应该努力使小孩子的劳动动作成为一种美学创造。让他们在自己制造的产品中，不断地重复运用圆形、椭圆形和波浪线条，让孩子从小就习惯于那些要求高度灵敏的精细、平稳的动作。','1022-1103',NULL,1627870778,1782398654);
INSERT INTO highlights VALUES('38260364_48_428-529','38260364',50,'第48章 怎么训练孩子流利书写？','在孩子们上学前一年，就应该让他们做一些这样的劳动，比如，用小刀（刻刀）和剪子剪纸，做木雕、编织、设计和制作小型木制模型。精细的劳动动作可以培养他们手指动作的协调和节奏，并形成手指的灵敏和对小型图案的感知','876-977',NULL,1627870662,1782398654);
INSERT INTO highlights VALUES('38260364_48_357-399','38260364',50,'第48章 怎么训练孩子流利书写？','学习流利书写，首先要求一定数量的手部肌肉训练。而多年经验表明，这些训练应该早于书写。','780-822',NULL,1627870531,1782398654);
INSERT INTO highlights VALUES('38260364_47_1153-1191','38260364',49,'第47章 请培养孩子对绘画的热爱','在讲解的过程中，在黑板上画些情节画，对帮助学生理解和记忆起到了非常大的作用。','1726-1764',NULL,1627870324,1782398654);
INSERT INTO highlights VALUES('38260364_47_586-618','38260364',49,'第47章 请培养孩子对绘画的热爱','孩子们在绘画中讲故事、编童话，绘画则成为创造性想象力活动的起源。','1059-1091',NULL,1627870165,1782398654);
INSERT INTO highlights VALUES('38260364_46_704-734','38260364',48,'第46章 请爱惜和发展青少年的记忆力','随意的记忆，这在本质上是区别于对教材知识的刻意背诵和记忆的。','1204-1234',NULL,1627870000,1782398654);
INSERT INTO highlights VALUES('38260364_45_427-440','38260364',47,'第45章 怎样培养记忆力？','在直接观察的过程中去掌握。','897-910',NULL,1627869873,1782398654);
INSERT INTO highlights VALUES('38260364_45_357-382','38260364',47,'第45章 怎样培养记忆力？','学龄前和小学阶段是奠定其记忆力牢固基础的最佳时期。','827-852',NULL,1627869859,1782398654);
INSERT INTO highlights VALUES('38260364_44_205-264','38260364',46,'第44章 怎样发展孩子的思维和智力？','思维课是对周围世界的形象、图画、现象和物体的生动、直接感知，同时也是逻辑分析、知识获取、思维练习，寻找因果关系的学习。','630-689',NULL,1627869782,1782398654);
INSERT INTO highlights VALUES('38260364_44_149-164','38260364',46,'第44章 怎样发展孩子的思维和智力？','专门的“思维课”是很有必要的。','574-589',NULL,1627869758,1782398654);
INSERT INTO highlights VALUES('38260364_43_1887-1986','38260364',45,'第43章 怎样在学龄前阶段研究孩子的思维？','一年级的教师：在一年时间内组织20～30次去思想的发源地——自然界旅行。带孩子们去的环境中，既要有鲜明的形象，又要有现象之间的因果联系，让孩子们去欣赏美，对美的事物感到惊奇，同时也能进行思考和分析。','2680-2779',NULL,1627869592,1782398654);
INSERT INTO highlights VALUES('38260364_43_2-40','38260364',45,'第43章 怎样在学龄前阶段研究孩子的思维？','人的思维有两种基本类型——逻辑分析思维（或数学思维）和艺术思维（或形象思维）','405-443',NULL,1627869436,1782398654);
INSERT INTO highlights VALUES('38260364_42_905-944','38260364',44,'第42章 给准备教一年级的教师的建议','你们孩子的智慧取决于你们的智力兴趣，也取决于书在家庭的精神生活中占什么地位。”','1455-1494',NULL,1627869114,1782398654);
INSERT INTO highlights VALUES('38260364_42_536-559','38260364',44,'第42章 给准备教一年级的教师的建议','孩子神经系统和心脏的健康状况，尤其受家庭的影响','1036-1059',NULL,1627869068,1782398654);
INSERT INTO highlights VALUES('38260364_42_160-172','38260364',44,'第42章 给准备教一年级的教师的建议','首先是要了解他的健康状况','610-622',NULL,1627869010,1782398654);
INSERT INTO highlights VALUES('38260364_41_2673-2712','38260364',43,'第41章 给刚参加教学工作的教师的建议','教师应该大量储备针对全班学生的习题和例题，同时，还要有针对个别学生的个性化题目','3424-3463',NULL,1627868929,1782398654);
INSERT INTO highlights VALUES('38260364_41_2511-2555','38260364',43,'第41章 给刚参加教学工作的教师的建议','同样，教师也需要对美的敏锐感知。你应该爱美、创造美，维护自然界中的美和你的学生心灵的美。','3237-3281',NULL,1627868904,1782398654);
INSERT INTO highlights VALUES('38260364_41_2131-2135','38260364',43,'第41章 给刚参加教学工作的教师的建议','文学作品','2807-2811',NULL,1627868688,1782398654);
INSERT INTO highlights VALUES('38260364_41_2050-2061','38260364',43,'第41章 给刚参加教学工作的教师的建议','音乐会拉近心与心的距离','2726-2737',NULL,1627868685,1782398654);
INSERT INTO highlights VALUES('38260364_41_2030-2034','38260364',43,'第41章 给刚参加教学工作的教师的建议','音乐天赋','2706-2710',NULL,1627868676,1782398654);
INSERT INTO highlights VALUES('38260364_41_1663-1694','38260364',43,'第41章 给刚参加教学工作的教师的建议','请记住，你不只是一名教师，更是学生生活的教育者和道德的指路人。','2264-2295',NULL,1627868617,1782398654);
INSERT INTO highlights VALUES('38260364_41_1270-1367','38260364',43,'第41章 给刚参加教学工作的教师的建议','每个月买三本书：（1）关于你所教科目相关科学的书；（2）介绍可以作为青年人启蒙者和榜样的人的生活和奋斗的书；（3）关于人的心灵的书，尤其是与儿童、少年和青年的心灵相关的书籍（与心理学相关书籍）。','1821-1918',NULL,1627868553,1782398654);
INSERT INTO highlights VALUES('38260364_41_284-308','38260364',43,'第41章 给刚参加教学工作的教师的建议','首先，应该一点一点积累教师的智力财富和教育智慧。','735-759',NULL,1627868408,1782398654);
INSERT INTO highlights VALUES('38260364_40_2299-2306','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','形象思维”训练','3215-3222',NULL,1627803439,1782398654);
INSERT INTO highlights VALUES('38260364_40_1974-1992','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','请逐渐从绘画直观性转向词汇形象直观性','2865-2883',NULL,1627803394,1782398654);
INSERT INTO highlights VALUES('38260364_40_1471-1485','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','都用到了黑板和各种彩色粉笔。','2262-2276',NULL,1627803319,1782398654);
INSERT INTO highlights VALUES('38260364_40_902-952','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','应该从实物的直观手段逐渐过渡到绘画的直观手段，之后再过渡到那种用象征性图画来表示物体和现象的直观手段','1618-1668',NULL,1627803246,1782398654);
INSERT INTO highlights VALUES('38260364_40_690-715','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','请到思维的源头，在自然界和劳动中教孩子们进行思考。','1356-1381',NULL,1627803198,1782398654);
INSERT INTO highlights VALUES('38260364_40_441-458','38260364',42,'第40章 直观性是认知的道路，也是照亮这条道路的光','直观性是小学生脑力劳动的一般原则。','898-915',NULL,1627803138,1782398654);
INSERT INTO highlights VALUES('38260364_39_1156-1175','38260364',41,'第39章 怎样才能让学生专注？','无意的注意力应该与刻意的注意力相结合。','1703-1722',NULL,1627802848,1782398654);
INSERT INTO highlights VALUES('38260364_39_454-483','38260364',41,'第39章 怎样才能让学生专注？','要管理注意力，必须非常了解孩子的心理，了解他们的年龄特点。','901-930',NULL,1627802687,1782398654);
INSERT INTO highlights VALUES('38260364_38_2147-2163','38260364',40,'第38章 请用劳动爱好来教育学生','灵活的农业劳动则能教会他们思考。','2820-2836',NULL,1627797558,1782398654);
INSERT INTO highlights VALUES('38260364_38_1904-1937','38260364',40,'第38章 请用劳动爱好来教育学生','为生命过程（植物和动物）的正常发展创造必要的环境，并对其进行管理。','2577-2610',NULL,1627797552,1782398654);
INSERT INTO highlights VALUES('38260364_38_687-708','38260364',40,'第38章 请用劳动爱好来教育学生','设计和安装各种实用的设施、设备和机械模型。','1235-1256',NULL,1627797076,1782398654);
INSERT INTO highlights VALUES('38260364_38_32-48','38260364',40,'第38章 请用劳动爱好来教育学生','孩子的智慧就体现在他的手指尖上。','430-446',NULL,1627797005,1782398654);
INSERT INTO highlights VALUES('38260364_37_1155-1170','38260364',39,'第37章 请让每个学生都有自己的爱好','请让自己的学生培养合理的爱好。','1755-1770',NULL,1627796941,1782398654);
INSERT INTO highlights VALUES('38260364_36_1096-1147','38260364',38,'第36章 请教会学生利用空闲时间','教孩子利用空闲时间，可以不用口头讲解（小孩子还不懂这些讲解），而是通过组织活动、示范和集体劳动来教育。','1619-1670',NULL,1627796656,1782398654);
INSERT INTO highlights VALUES('38260364_36_1043-1092','38260364',38,'第36章 请教会学生利用空闲时间','给孩子们提供空闲时间，并不意味着让他想干什么就干什么，因为放任自流可能会养成无所事事和懈怠的习气。','1541-1590',NULL,1627796643,1782398654);
INSERT INTO highlights VALUES('38260364_36_632-647','38260364',38,'第36章 请教会学生利用空闲时间','和他待几天，并用他的眼光看世界','1055-1070',NULL,1627796591,1782398654);
INSERT INTO highlights VALUES('38260364_36_686-725','38260364',38,'第36章 请教会学生利用空闲时间','教师不理解，学生在做什么，他为什么会这么做，而学生也不理解，教师想要他怎么做。','1109-1148',NULL,1627796582,1782398654);
INSERT INTO highlights VALUES('38260364_35_1144-1204','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','低年级学生晚上9点睡觉，早上6点起床（9个小时睡眠），中、高年级学生晚上10点睡觉，早上5:30起床（7个半小时睡眠）。','1725-1785',NULL,1627791416,1782398654);
INSERT INTO highlights VALUES('38260364_35_890-920','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','阅读，是出于兴趣和求知欲的阅读，而不是出于背诵和记忆的要求。','1421-1451',NULL,1627791380,1782398654);
INSERT INTO highlights VALUES('38260364_35_767-789','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','在下午应该进行一些知识扩展和转化的脑力活动。','1298-1320',NULL,1627791360,1782398654);
INSERT INTO highlights VALUES('38260364_35_676-758','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','让学生自由支配下午的时间，不用坐着看书、写作业。下午应该是学生的空闲时间。在这个时间，学生可以阅读、参加科学课程小组的活动、去大自然劳动、观察自然现象和人们的劳作。','1182-1264',NULL,1627791351,1782398654);
INSERT INTO highlights VALUES('38260364_35_460-491','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','绝对不允许，让学生刚上完课，就连续好几个小时坐着看书、写作业。','941-972',NULL,1627791319,1782398654);
INSERT INTO highlights VALUES('38260364_35_14-48','38260364',37,'第35章 要克服负担过重的现象，就必须有空闲时间','只有学生不将所有时间都花在学习上，还留下很多的空闲时间，他才能学习好','420-454',NULL,1627791263,1782398654);
INSERT INTO highlights VALUES('38260364_34_784-834','38260364',36,'第34章 关于学生的智力生活','个人的智力生活不能局限在一个封闭、狭小的圈子里。人在丰富集体智力生活的同时，也在利用集体的精神财富。','1330-1380',NULL,1627791147,1782398654);
INSERT INTO highlights VALUES('38260364_34_259-301','38260364',36,'第34章 关于学生的智力生活','列一个你的学生应该在中学学习阶段全部读完的书单，并请设法把这些书摆放在班级图书室里。','705-747',NULL,1627791045,1782398654);
INSERT INTO highlights VALUES('38260364_33_1541-1571','38260364',35,'第33章 怎样按季节安排学生的劳动？','不要让学习变成对遗漏知识无止境的补习，也不要无休止地“拖尾”','2116-2146',NULL,1627790965,1782398654);
INSERT INTO highlights VALUES('38260364_33_1370-1382','38260364',35,'第33章 怎样按季节安排学生的劳动？','不要让能力和知识比例失调','1945-1957',NULL,1627790922,1782398654);
INSERT INTO highlights VALUES('38260364_33_1355-1366','38260364',35,'第33章 怎样按季节安排学生的劳动？','不断提高父母的教育素养','1930-1941',NULL,1627790864,1782398654);
INSERT INTO highlights VALUES('38260364_33_1300-1332','38260364',35,'第33章 怎样按季节安排学生的劳动？','第一，从孩子3、4、5岁的时候，就要关心他的智力背景是否足够丰富','1875-1907',NULL,1627790850,1782398654);
INSERT INTO highlights VALUES('38260364_33_842-871','38260364',35,'第33章 怎样按季节安排学生的劳动？','在夏天给学生布置这样的任务：阅读下一学年将要学习的文学作品','1317-1346',NULL,1627790768,1782398654);
INSERT INTO highlights VALUES('38260364_33_665-681','38260364',35,'第33章 怎样按季节安排学生的劳动？','春天应该让学生采取新的学习方法。','1115-1131',NULL,1627790735,1782398654);
INSERT INTO highlights VALUES('38260364_33_374-405','38260364',35,'第33章 怎样按季节安排学生的劳动？','应该在春天，为下一学年前两个学季要学习的理论概括知识积累事例。','799-830',NULL,1627790686,1782398654);
INSERT INTO highlights VALUES('38260364_33_356-373','38260364',35,'第33章 怎样按季节安排学生的劳动？','春天似乎应该专门用于最高强度的观察','781-798',NULL,1627790676,1782398654);
INSERT INTO highlights VALUES('38260364_32_533-601','38260364',34,'第32章 分享知识和参加社会生活','在向别人传授知识的过程中，学生们自己也弄明白了很多事情，也会产生许多疑问，并努力解释清楚一些细微的思想弯曲和转变，弄明白隐蔽的因果联系。','981-1049',NULL,1627790557,1782398654);
INSERT INTO highlights VALUES('38260364_31_781-794','38260364',33,'第31章 怎样把思想和自尊心相融合？','树立了高年级学生的自尊心。','1281-1294',NULL,1627790258,1782398654);
INSERT INTO highlights VALUES('38260364_31_600-669','38260364',33,'第31章 怎样把思想和自尊心相融合？','到了三、四年级，开始举办“读书晚会”：孩子们讲述自己读过的书的内容，大声地朗读书籍，朗诵诗歌和散文片段。而这是一种特殊的理智和技巧的竞赛。','1075-1144',NULL,1627790228,1782398654);
INSERT INTO highlights VALUES('38260364_31_476-513','38260364',33,'第31章 怎样把思想和自尊心相融合？','每个人都会讲点什么，或是他生活中经历的事，或是他的梦想，或是他虚构的故事。','926-963',NULL,1627790213,1782398654);
INSERT INTO highlights VALUES('38260364_31_548-566','38260364',33,'第31章 怎样把思想和自尊心相融合？','思考和讲述的能力都像是一种道德尊严。','998-1016',NULL,1627790202,1782398654);
INSERT INTO highlights VALUES('38260364_31_454-475','38260364',33,'第31章 怎样把思想和自尊心相融合？','到了二年级，我们会在冬天的傍晚讲故事和童话','904-925',NULL,1627790187,1782398654);
INSERT INTO highlights VALUES('38260364_31_245-272','38260364',33,'第31章 怎样把思想和自尊心相融合？','从一年级开始，就做一个集体创作的画册，取名为“朝霞”。','670-697',NULL,1627790154,1782398654);
INSERT INTO highlights VALUES('38260364_31_344-391','38260364',33,'第31章 怎样把思想和自尊心相融合？','把你喜欢的自然界的事物画下来，并写下一句话，几个词也行，但要让这些词就像一首美妙的歌曲一样。”','794-841',NULL,1627790147,1782398654);
INSERT INTO highlights VALUES('38260364_30_2876-2911','38260364',32,'第30章 请努力争取学生的思想和心灵','我想要使学生在小组里获得知识，改善在集体中的人际关系，树立个人的自尊。','3576-3611',NULL,1627789946,1782398654);
INSERT INTO highlights VALUES('38260364_30_2704-2756','38260364',32,'第30章 请努力争取学生的思想和心灵','，唤醒冷漠，挽救头脑懒惰，就要让学生在某个方面体现出他自己的知识，在智力活动中表达自己和体现自己的个性。','3354-3406',NULL,1627789925,1782398654);
INSERT INTO highlights VALUES('38260364_30_2319-2356','38260364',32,'第30章 请努力争取学生的思想和心灵','学生在某一门课上的落后、成绩不好，这都不可怕，最可怕的就是麻木冷淡的态度。','2944-2981',NULL,1627789844,1782398654);
INSERT INTO highlights VALUES('38260364_29_1473-1516','38260364',31,'第29章 兴趣的奥秘何在？','他们体验到了一种无与伦比的人类的自豪感：我们控制着事物的发展，知识在我们手中变成力量。','2018-2061',NULL,1627789540,1782398654);
INSERT INTO highlights VALUES('38260364_29_114-122','38260364',31,'第29章 兴趣的奥秘何在？','体验到创造的欢乐','534-542',NULL,1627789287,1782398654);
INSERT INTO highlights VALUES('38260364_29_79-95','38260364',31,'第29章 兴趣的奥秘何在？','对面前展示的真理感到惊奇甚至震惊','499-515',NULL,1627789279,1782398654);
INSERT INTO highlights VALUES('38260364_28_2166-2224','38260364',30,'第28章 不要让能力与知识的比例失调','请思考一下，上课时要选择哪些事例，要让学生自己搜集和分析哪些事例。请你制订搜集事例过程的教学指示，教会学生思考事例。','2816-2874',NULL,1627789249,1782398654);
INSERT INTO highlights VALUES('38260364_27_338-357','38260364',29,'第27章 阅读是“学困生”智力培养的重要手段','他创造性劳动的一大特点就是合理组织阅读','767-786',NULL,1627788856,1782398654);
INSERT INTO highlights VALUES('38260364_27_225-274','38260364',29,'第27章 阅读是“学困生”智力培养的重要手段','在学习困难学生的脑力劳动中起决定性作用的是阅读、阅读、再阅读，而并非补课，也不是无止境的“督促”。','629-678',NULL,1627788837,1782398654);
INSERT INTO highlights VALUES('38260364_26_538-573','38260364',28,'第26章 如何用阅读扩充知识？','会在学习这些章节之前、学习的过程中或者之后，就让学生阅读一些科普文献。','1035-1070',NULL,1627788796,1782398654);
INSERT INTO highlights VALUES('38260364_26_664-702','38260364',28,'第26章 如何用阅读扩充知识？','在课堂上学习新知识点之前就已经开始积累问题，这倒是一个非常有趣的教学法问题。','1161-1199',NULL,1627788762,1782398654);
INSERT INTO highlights VALUES('38260364_26_376-407','38260364',28,'第26章 如何用阅读扩充知识？','教师应该在学校图书馆或个人藏书里有一些根据大纲教材扩充知识的书','848-879',NULL,1627788721,1782398654);
INSERT INTO highlights VALUES('38260364_25_824-844','38260364',27,'第25章 教会学生观察和发现','学龄初期的观察是智力发展必不可少的条件。','1370-1390',NULL,1627788544,1782398654);
INSERT INTO highlights VALUES('38260364_25_743-764','38260364',27,'第25章 教会学生观察和发现','请你教会学生观察和发现周围世界的各种现象。','1264-1285',NULL,1627788535,1782398654);
INSERT INTO highlights VALUES('38260364_25_144-170','38260364',27,'第25章 教会学生观察和发现','如果说复习是学习之母，那么观察就是理解和记忆知识之母','565-591',NULL,1627788432,1782398654);
INSERT INTO highlights VALUES('38260364_22_1124-1158','38260364',24,'第22章 学习之母不应该是继母','在每一科的作业本上专门留出一块地方，用红笔记下那些需要永远记住的内容','1696-1730',NULL,1627783112,1782398654);
INSERT INTO highlights VALUES('38260364_22_915-942','38260364',24,'第22章 学习之母不应该是继母','应该教会学生离教材远一些，抓住主要内容，不要注重细节。','1437-1464',NULL,1627783064,1782398654);
INSERT INTO highlights VALUES('38260364_21_778-817','38260364',23,'第21章 评分应该有分量','永远不要急于打出不及格分数。请记住，成功的喜悦是促使孩子变得更好的强大情感力量','1247-1286',NULL,1627782898,1782398654);
INSERT INTO highlights VALUES('38260364_19_151-192','38260364',21,'第19章 思考新知识点是上课的一个阶段','“理解”还不能表示“已知”，理解还不是掌握知识。要获得牢固的知识，就必须“思考”。','577-618',NULL,1627782238,1782398654);
INSERT INTO highlights VALUES('38260364_18_1064-1088','38260364',20,'第18章 第一次学习新知识点','而教师的错误在于，他没有给学生提出不犯错的目标。','1585-1609',NULL,1627782141,1782398654);
INSERT INTO highlights VALUES('38260364_18_838-910','38260364',20,'第18章 第一次学习新知识点','不要让他只是听其他同学的正确答案或抄板书，一定要强迫他在每堂课上独立思考，耐心、委婉地引导他，让他在每堂课上都能取得哪怕是一点点的脑力劳动成果。','1334-1406',NULL,1627782113,1782398654);
INSERT INTO highlights VALUES('38260364_18_2-35','38260364',20,'第18章 第一次学习新知识点','学生落后、成绩不好的一个原因是，第一次学习新知识点的时候没有学好。','398-431',NULL,1627781943,1782398654);
INSERT INTO highlights VALUES('38260364_16_724-767','38260364',18,'第16章 知识的发掘','这就必须知道：哪些应该讲，哪些则不用全部讲完。没有讲完的那部分就像是学生思维的“引线”','1316-1359',NULL,1627780938,1782398654);
INSERT INTO highlights VALUES('38260364_16_374-383','38260364',18,'第16章 知识的发掘','疑问能激发求知欲。','866-875',NULL,1627780883,1782398654);
INSERT INTO highlights VALUES('38260364_16_117-159','38260364',18,'第16章 知识的发掘','教学中要让新的知识通过已经获得的知识被“发掘”出来，我认为，高超的教学技巧就在于此。','534-576',NULL,1627780808,1782398654);
INSERT INTO highlights VALUES('38260364_16_85-99','38260364',18,'第16章 知识的发掘','教师应该追求学生思维的积极性','477-491',NULL,1627780705,1782398654);
INSERT INTO highlights VALUES('38260364_15_1460-1464','38260364',17,'第15章 知识既是目的，也是手段','创造手段','2108-2112',NULL,1627733962,1782398654);
INSERT INTO highlights VALUES('38260364_15_1472-1520','38260364',17,'第15章 知识既是目的，也是手段','如果他只是背诵别人的思想，而不创造自己的思想，也不用话语表达出来，那他就会对语言冷淡、漠不关心、','2120-2168',NULL,1627733951,1782398654);
INSERT INTO highlights VALUES('38260364_15_1386-1426','38260364',17,'第15章 知识既是目的，也是手段','对语言的冷淡和不解，是学习的一大灾难；如果这个灾难深深扎根，那么人就会疏远学习。','1984-2024',NULL,1627733915,1782398654);
INSERT INTO highlights VALUES('38260364_15_131-220','38260364',17,'第15章 知识既是目的，也是手段','片面的评价：能把知识储存在记忆里，并根据教师的要求立刻把它“拿出来”，这样的学生就有能力并掌握了知识。但这在实践中会造成什么后果？会导致知识脱离学生的精神生活，脱离他的个人兴趣。','529-618',NULL,1627733817,1782398654);
INSERT INTO highlights VALUES('38260364_15_805-820','38260364',17,'第15章 知识既是目的，也是手段','把词汇作为一个重要的创造工具。','1328-1343',NULL,1627733743,1782398654);
INSERT INTO highlights VALUES('38260364_15_289-338','38260364',17,'第15章 知识既是目的，也是手段','“知道”意味着会运用知识。只有当它成为精神生活的一部分，占据人的思想，激发兴趣，才可以称之为知识。','712-761',NULL,1627733691,1782398654);
INSERT INTO highlights VALUES('38260364_14_1926-1977','38260364',16,'第14章 与“学困生”打交道','学生思考得越多，他在周围世界中看到的不懂的东西就越多，对知识就越敏感，而你，作为教师的工作也就更轻松。','2547-2598',NULL,1627733198,1782398654);
INSERT INTO highlights VALUES('38260364_14_1870-1887','38260364',16,'第14章 与“学困生”打交道','阅读教会他思考，而思考则会激发智力','2491-2508',NULL,1627733188,1782398654);
INSERT INTO highlights VALUES('38260364_14_532-563','38260364',16,'第14章 与“学困生”打交道','大脑皮层神经细胞的萎缩、惰性和衰弱，都可以用惊奇和赞叹来医治，','978-1009',NULL,1627732850,1782398654);
INSERT INTO highlights VALUES('38260364_14_258-272','38260364',16,'第14章 与“学困生”打交道','最有效的方法是扩大其阅读面。','679-693',NULL,1627732839,1782398654);
INSERT INTO highlights VALUES('38260364_13_1313-1355','38260364',15,'第13章 “双教学大纲”和学生的思维发展','请思考一下，怎么把现在正在学习的或即将学习的东西变成学生乐于思考、分析和观察的对象。','1840-1882',NULL,1627732587,1782398654);
INSERT INTO highlights VALUES('38260364_13_529-571','38260364',15,'第13章 “双教学大纲”和学生的思维发展','坚持“双教学大纲”：第一个是必须要熟记的材料，第二个是课外阅读，以及其他的信息来源。','981-1023',NULL,1627732526,1782398654);
INSERT INTO highlights VALUES('38260364_12_699-806','38260364',14,'第12章 基础知识在学生记忆中的储存','“记忆管理技术”可以这样进行：工作日刚开始（第一节课前），我会在黑板上写下今天要学的三个单词，比如“草原”“温暖”“沙沙响”。孩子们走进教室后，迅速把这几个单词写到他们的重要词汇本中，这个词汇本会陪伴他们整整三年。','1174-1281',NULL,1627732315,1782398654);
INSERT INTO highlights VALUES('38260364_11_1212-1234','38260364',13,'第11章 教师的时间和教学各阶段的相互依存','阅读的同时，书写也是孩子掌握知识的另一项工具','1790-1812',NULL,1627732115,1782398654);
INSERT INTO highlights VALUES('38260364_11_594-629','38260364',13,'第11章 教师的时间和教学各阶段的相互依存','请在小学阶段就教会所有学生这样阅读：在阅读的同时思考，在思考的同时阅读','1097-1132',NULL,1627731991,1782398654);
INSERT INTO highlights VALUES('38260364_11_375-394','38260364',13,'第11章 教师的时间和教学各阶段的相互依存','小学许多任务中的重中之重是教会学生学习','853-872',NULL,1627731957,1782398654);
INSERT INTO highlights VALUES('38260364_10_875-905','38260364',12,'第10章 时间从哪里来？一昼夜只有24小时','这个准备是什么？就是阅读，每天不间断地阅读，一生都与书为伴。','1478-1508',NULL,1627731746,1782398654);
INSERT INTO highlights VALUES('38260364_9_2262-2317','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','如果教师能给这些淘气的孩子一些力所能及，并让他们感到成功喜悦的脑力劳动，他们就会非常勤奋、能集中注意力去解题！','2989-3044',NULL,1627696541,1782398654);
INSERT INTO highlights VALUES('38260364_9_983-1024','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','学习带给他精神上的满足和发现的乐趣。此时教师与学生相互的善意与相互信任结合在一起。','1485-1526',NULL,1627696310,1782398654);
INSERT INTO highlights VALUES('38260364_9_778-821','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','无论是从脑力劳动的内容（作业题的性质），还是从时间上，在学习过程中，都要实现其个性化。','1255-1298',NULL,1627696279,1782398654);
INSERT INTO highlights VALUES('38260364_9_445-493','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','正确认识到每个学生在某个阶段适合什么，如何进一步发展他的智力，是教育智慧特别重要的组成部分之一。','872-920',NULL,1627695889,1782398654);
INSERT INTO highlights VALUES('38260364_9_358-393','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','没有一个完全一致的前提条件能适用于所有学生，使他们都获得好的学习成绩。','785-820',NULL,1627695702,1782398654);
INSERT INTO highlights VALUES('38260364_9_252-337','38260364',11,'第9章 请记住，没有也不可能有抽象的学生','而另一个孩子的脑力劳动则是完全不一样的：接受知识很慢，记忆的时间短，也不牢固。但也可能正是这个孩子，未来在学习和智力发展上，会比那些在一开始学习更好的学生取得更大的成就。','679-764',NULL,1627695682,1782398654);
INSERT INTO highlights VALUES('38260364_8_2515-2594','38260364',10,'第8章 请保持善意！','学生的成绩反映在他的精神状态上；而精神状态则反映在教师精神生活的充实和身体健康状况上。如果学生想要变得更好，想要牢固地掌握知识，这就已经是你工作快乐的一半了。','3182-3261',NULL,1627695610,1782398654);
INSERT INTO highlights VALUES('38260364_8_2300-2344','38260364',10,'第8章 请保持善意！','而这种对真心的罔顾源自于情感上没有教养，原因在于在孩子幼年时并没有人教会他用心去认识人。','2942-2986',NULL,1627695309,1782398654);
INSERT INTO highlights VALUES('38260364_8_541-645','38260364',10,'第8章 请保持善意！','我一直都认为，教育工作最重要的任务之一，就是教会孩子用心去认识世界，用心去感受人的状态，不仅仅是亲人、朋友，更是他在成长道路上碰到的每一个人。教会小孩感受他所遇到的人的心理压力和痛苦，也是一种最细致的教育能力','958-1062',NULL,1627694517,1782398654);
INSERT INTO highlights VALUES('38260364_7_2653-2676','38260364',9,'第7章 如何预防日常工作中的神经衰弱？','这就是情感教育最重要的一个方面——善意的本质。','3279-3302',NULL,1627694303,1782398654);
INSERT INTO highlights VALUES('38260364_7_176-192','38260364',9,'第7章 如何预防日常工作中的神经衰弱？','童年首先是对周围世界的情感认知。','602-618',NULL,1627693861,1782398654);
INSERT INTO highlights VALUES('38260364_6_2722-2764','38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','良好的自制力和保持镇静能让他们与自然长时间交流，从而使得身体的紧张和观察、思考相结合','3377-3419',NULL,1627641627,1782398654);
INSERT INTO highlights VALUES('38260364_6_2617-2627','38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','合理地利用休息时间。','3272-3282',NULL,1627641595,1782398654);
INSERT INTO highlights VALUES('38260364_6_2324-2382','38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','温和善意地看待一切负面的东西，以玩笑的方式去支持鼓励正面的东西，这种能力是一个好教师、一个优秀的学生集体的重要特征。','2929-2987',NULL,1627641553,1782398654);
INSERT INTO highlights VALUES('38260364_6_2091-2181','38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','与其强迫自己压制激动的心情，不如去找一个以另外一种完全不同的方式引发兴奋或生气的活动，从而帮你把“弹簧”压下去。以一种玩笑的方式来面对不快的事情，你就会成为所有思想和感觉的主宰者。','2671-2761',NULL,1627641509,1782398654);
INSERT INTO highlights VALUES('38260364_6_905-948','38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','很难想象，对于教师而言，还有比感觉自己充满智慧、思想，可是身体却无能为力更悲惨的事情。','1360-1403',NULL,1627641349,1782398654);
INSERT INTO highlights VALUES('38260364_5_2966-2987','38260364',7,'第5章 什么是教师的才能？它是如何形成的？','有时候需要暂缓采取行动，让感情“稳定下来”','4060-4081',NULL,1627641218,1782398654);
INSERT INTO highlights VALUES('38260364_5_2509-2530','38260364',7,'第5章 什么是教师的才能？它是如何形成的？','理解、感受到，孩子是一个永远在变化的生命。','3503-3524',NULL,1627638434,1782398654);
INSERT INTO highlights VALUES('38260364_5_1750-1778','38260364',7,'第5章 什么是教师的才能？它是如何形成的？','因为教育人首先就要认识他的内心，发现并感知他的个人世界。','2543-2571',NULL,1627638316,1782398654);
INSERT INTO highlights VALUES('38260364_5_1087-1172','38260364',7,'第5章 什么是教师的才能？它是如何形成的？','教师职业是一项研究人的科学，要不断地深入人的复杂的精神世界。其显著特点是，不断地发掘人身上新的东西，对新的东西感到惊奇，并能看到人的成长过程，这就是滋养教育工作才能的根源','1830-1915',NULL,1627638226,1782398654);
INSERT INTO highlights VALUES('38260364_4_440-512','38260364',6,'第4章 代序','关于如何在教育年轻一代这项高尚的事业中展示自己的才能，如何在这个被认为是最有意义、最复杂、最富人文气息的职业中实现自我，这是一个值得深思的问题。','878-950',NULL,1626855153,1782398654);
INSERT INTO highlights VALUES('3300025230_43_1523-1571','3300025230',43,'后记 生活没有白走的路，每走一步都作数','所有命运馈赠的礼物，早已在暗中标好了价格。我更想说的是：你付出的所有努力，命运也都暗中馈赠了你。','1523-1571',1,1754471000,1782398540);
INSERT INTO highlights VALUES('3300025230_42_10894-10907','3300025230',42,'33 博傻理论 一株郁金香能换一栋楼你敢信吗？','寨有盍饕之心，而欲不可足。','10894-10907',1,1754470831,1782398540);
INSERT INTO highlights VALUES('3300025230_41_8394-8404','3300025230',41,'32 保险 我年轻力壮还需要买保险吗？','三是先大险，后小险。','8394-8404',1,1754469627,1782398540);
INSERT INTO highlights VALUES('3300025230_41_8062-8075','3300025230',41,'32 保险 我年轻力壮还需要买保险吗？','二是先保主心骨，再保其他人','8062-8075',1,1754469592,1782398540);
INSERT INTO highlights VALUES('3300025230_41_7911-7921','3300025230',41,'32 保险 我年轻力壮还需要买保险吗？','一是先人身，后分红。','7911-7921',1,1754469577,1782398540);
INSERT INTO highlights VALUES('3300025230_41_4800-4825','3300025230',41,'32 保险 我年轻力壮还需要买保险吗？','大数定律的结论就是：无数的偶然，最终导致某种必然。','4800-4825',1,1754469253,1782398540);
INSERT INTO highlights VALUES('3300025230_40_16867-16926','3300025230',40,'31 基金 投资小白应该如何入局？','如果多选几只基金，分散投资，一是可以防止自己判断失误；二是可以在不同状况下，避免单一基金收益的大幅波动，平抑一下风险。','16867-16926',1,1754463518,1782398540);
