INSERT INTO highlights VALUES('3300025230_38_8990-9106','3300025230',38,'29 股票之涨跌 为什么我买的股票明明业绩非常好，却突然跌了10%呢？','那就取决于我们在这个机器上期望的必要报酬率是多少。如果我期望实现10%的必要报酬率，那么我愿意投入的金额就是100/110%=90.9元。因为我今天投入90.9元，一年后收到100元，收益是9.1元，刚好超过我期望的10%的收益率。','8990-9106',1,1754448109,1782398540);
