INSERT INTO highlights VALUES('3300025230_36_11740-11828','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','随着我们的阅历、能力的提升和成熟，新知识的学习需要打破的成见、积累越来越重，当学习变成对自己几十年来好不容易成型的三观进行颠覆重组时，学习已经不是一个增长知识那么简单的问题了。','11740-11828',1,1754390678,1782398540);
INSERT INTO highlights VALUES('3300025230_36_10147-10200','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','如果世界一直在变，而且变化的速度越来越快，那么我们所要做的，就是绝对不能停滞不前，而应该随着世界同频变化。','10147-10200',1,1754390494,1782398540);
