INSERT INTO highlights VALUES('3300025230_36_8195-8240','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','第三，如果不能跟上大趋势，那么，就在自己现有的行业里做积极的储备，等待随时会到来的小趋势。','8195-8240',1,1754389921,1782398540);
INSERT INTO highlights VALUES('3300025230_36_7981-8043','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','如果你还是自认格局不够，无法准确看清未来的商业趋势，那么不妨看看同行业的大企业家是怎么做的，他们的选择本身就代表着一种趋势。','7981-8043',1,1754389914,1782398540);
INSERT INTO highlights VALUES('3300025230_36_7620-7683','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','你不需要去关注世界整体的经济大趋势，只要在自己的行业内，看到稍远一点的消费需求，看到可以帮助到这种需求的工具，就能够看到趋势。','7620-7683',1,1754389754,1782398540);
