INSERT INTO highlights VALUES('3300025230_36_4567-4624','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','这个时候，你会发现不是苏宁不努力，不牛，而是再牛也没用。你是很好很好的人，只是我不需要了，这是个挺悲伤的爱情故事。','4567-4624',1,1754387239,1782398540);
INSERT INTO highlights VALUES('3300025230_36_3810-3870','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','总体来说，爱折腾的人胜算更大，未来的创业很大程度上会是比拼试错的次数和成本的综合，尤其是趋势留的时间窗口越来越小的时候。','3810-3870',1,1754387107,1782398540);
INSERT INTO highlights VALUES('3300025230_36_3545-3590','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','当真理都被大家接受的时候，真理就会沦落为常识，你已经没有任何机会和优势来成为一个布道者了。','3545-3590',1,1754387054,1782398540);
INSERT INTO highlights VALUES('3300025230_36_2422-2471','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','如果你能尽量去做一些趋势性机会的事情，抓住市场整体向上的机会，只要做得稍微好点儿，总还是有机会的。','2422-2471',1,1754386782,1782398540);
INSERT INTO highlights VALUES('3300025230_36_2066-2118','3300025230',36,'27 风口 埋头走路与抬头看天，哪个更重要？','为什么很多发达国家技术工人收入就比较高呢？这正是说明了，只有发展趋于稳定的时期，个人能力才比机遇更重要。','2066-2118',1,1754386728,1782398540);
