INSERT INTO highlights VALUES('3300025230_33_2694-2727','3300025230',33,'25 商业与慈善 赚了我的钱，你还说是在做慈善？','市场核心的一点是它把每个人出于个人目的做的事情，变成对别人有用的。','2694-2727',1,1754312105,1782398540);
INSERT INTO highlights VALUES('3300025230_33_1630-1704','3300025230',33,'25 商业与慈善 赚了我的钱，你还说是在做慈善？','夏代的商国人就开始了经商行为，商国第七任君主王亥为中国商业始祖。王亥不仅帮助父亲冥在治水中立了大功，而且还在商国（今河南省商丘市）服牛驯马发展生产。','1630-1704',1,1754310088,1782398540);
INSERT INTO highlights VALUES('3300025230_32_8022-8052','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','自由、平等、自我实现、充满创意的工作环境会对他们更具吸引力。','8022-8052',1,1754309698,1782398540);
INSERT INTO highlights VALUES('3300025230_32_7811-7859','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','使命感驱动型公司才是“有灵魂的组织”，最具创新性和凝聚力的组织，才有更高的机会穿越周期走得更远。','7811-7859',1,1754296881,1782398540);
INSERT INTO highlights VALUES('3300025230_32_7769-7811','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','除了给丰厚的报酬之外，提供给他们有挑战性的工作、有充分自由的创新氛围也是非常重要的。','7769-7811',1,1754296788,1782398540);
INSERT INTO highlights VALUES('3300025230_32_7185-7278','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','虽然也都享受着巨大的物质奖励，但他们也深深被内在成就感所激励，为自己所独立创造的贡献所自豪。硅谷人注重智力激励，勇于接受挑战，用创意去解决困难，这就足以解释为什么存在这些相互矛盾的方面。','7185-7278',1,1754296424,1782398540);
INSERT INTO highlights VALUES('3300025230_32_7038-7094','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','那些新招募的人才是否会有合适的发展和晋升空间？他们是否还有机会独立完成一些成就，还是只能被之前的骨干成员所管辖？','7038-7094',1,1754296119,1782398540);
INSERT INTO highlights VALUES('3300025230_32_6794-6828','3300025230',32,'24 激励机制 为什么说金钱不是万能的？','生理（食物和衣服）、安全（工作保障）、社交（友谊）、尊重和自我实现。','6794-6828',1,1754295658,1782398540);
