INSERT INTO highlights VALUES('3300025230_31_9856-9940','3300025230',31,'23 信任成本 做生意，最贵的成本是什么？','人和人的相处本就充满了诸多的不确定性，当我们跟他人相处时带着自己的信任，同样也会收获到别人予以回报的信任。如果世界处处充满了信任，那么人和人之间的关系也会变得坚不可摧。','9856-9940',1,1754290211,1782398540);
