INSERT INTO highlights VALUES('3300025230_30_11712-11767','3300025230',30,'22 边际效用 餐厅为什么会有“饮料无限续杯”的服务，不怕被喝破产吗？','这类产品应该具备三个特点：一是成本较低，二是能够带来关注度，三是能够转移其他成本。只要是符合这类特点的都可以。','11712-11767',1,1754217130,1782398540);
