INSERT INTO highlights VALUES('3300025230_29_3604-3619','3300025230',29,'21 价格歧视 商家为什么要麻烦顾客领优惠券，直接降价不是更能吸引顾客吗？','一级价格歧视，又称完全价格歧视','3604-3619',1,1754205480,1782398540);
INSERT INTO highlights VALUES('3300025230_29_3170-3254','3300025230',29,'21 价格歧视 商家为什么要麻烦顾客领优惠券，直接降价不是更能吸引顾客吗？','按照经济学的定义，价格歧视实质上是一种价格差异，通常指商品或服务的提供者在向不同的接受者提供相同等级、相同质量的商品或服务时，在接受者之间实行不同的销售价格或收费标准。','3170-3254',1,1754192507,1782398540);
INSERT INTO highlights VALUES('3300025230_29_2923-2994','3300025230',29,'21 价格歧视 商家为什么要麻烦顾客领优惠券，直接降价不是更能吸引顾客吗？','所以对不同的消费者来说，他的价格需求弹性不同，也就是说他对价格的敏感度不一样。有的人没有优惠券是不会买这些商品的，而有的人则不在乎这点优惠券。','2923-2994',1,1754192440,1782398540);
INSERT INTO highlights VALUES('3300025230_29_467-491','3300025230',29,'21 价格歧视 商家为什么要麻烦顾客领优惠券，直接降价不是更能吸引顾客吗？','产品定价里充满了价格歧视，不过歧视的是“有钱人”','467-491',1,1754192178,1782398540);
