INSERT INTO highlights VALUES('3300025230_27_9473-9545','3300025230',27,'20 叙事经济学 倾家荡产疯狂追星是不是特别无理性？','就像圣埃克苏佩里所说：“如果你想造一艘船，你先要做的不是催促人们去收集木材，也不是忙着分配工作和发布命令，而是激起他们对浩瀚无垠的大海的向往。”','9473-9545',1,1754185460,1782398540);
