INSERT INTO highlights VALUES('3300025230_27_3721-3810','3300025230',27,'20 叙事经济学 倾家荡产疯狂追星是不是特别无理性？','席勒（Robert J. Shiller），开创了叙事经济学（narrative economics），揭示集体情绪、叙事对经济的影响，研究叙述与经济之间的因果关系和数据相关性。','3721-3810',1,1754177945,1782398540);
INSERT INTO highlights VALUES('3300025230_26_7693-7792','3300025230',26,'19 美貌经济学 长得好看能当饭吃吗？','能保颜保值的，只有沉淀于内心的品质。我们可以用意志力、恒心和耐心来管理身体；用能力和金钱投资美丽；用善良、平和的微笑对待别人；用自信、笃定的态度对待事业……没有怨气和愤懑挂在脸上，便有春风沐浴相伴。','7693-7792',1,1754145711,1782398540);
INSERT INTO highlights VALUES('3300025230_26_7853-7868','3300025230',26,'19 美貌经济学 长得好看能当饭吃吗？','始于颜值，陷于才华，终于人品。','7853-7868',1,1754145623,1782398540);
INSERT INTO highlights VALUES('3300025230_26_5299-5393','3300025230',26,'19 美貌经济学 长得好看能当饭吃吗？','这表明颜值较高的人在学生时代有更多的机会参与社会组织活动，在宝贵的社会实践场景中不断加强自身的沟通能力、领导能力、纪律性、团队协调能力等，从而形成了日后被劳动力市场十分看重的人力资本素质。','5299-5393',1,1754139889,1782398540);
INSERT INTO highlights VALUES('3300025230_26_4259-4294','3300025230',26,'19 美貌经济学 长得好看能当饭吃吗？','最最可怕的是，真的会漂亮到没朋友。因为，伴随美丽而来的还有可能是孤独。','4259-4294',1,1754138191,1782398540);
