INSERT INTO highlights VALUES('3300025230_25_3930-4002','3300025230',25,'18 幸福经济学 金钱能买到幸福吗？','结果发现，看过钞票的这组测试者在吃巧克力时感觉到的享受指数更低。这也暗合了我们生活中的经验，那些薪水高的员工，更难从生活的细小事件中感受到快乐。','3930-4002',1,1754120808,1782398540);
INSERT INTO highlights VALUES('3300025230_25_2701-2749','3300025230',25,'18 幸福经济学 金钱能买到幸福吗？','当收入超过了一定水准，物质生活得到充分满足后，在收入和幸福之间就会呈现出明显的“边际效用递减”。','2701-2749',1,1754120377,1782398540);
INSERT INTO highlights VALUES('3300025230_22_10655-10715','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','坦白说，谁也无法确定自己是否能遇到最好的那一个，最终与你走到一起的，往往是在恰当的时间、恰当的地点出现的最恰当的那个人。','10655-10715',1,1754049037,1782398540);
INSERT INTO highlights VALUES('3300025230_22_10091-10142','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','世界上本没有天生的灵魂伴侣。所谓的灵魂伴侣都是彼此在想要了解另一半的同时，长久时间沉淀下来的爱的默契。','10091-10142',1,1754048932,1782398540);
INSERT INTO highlights VALUES('3300025230_22_9150-9182','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','林语堂在《人生不过如此》中也说道：“不完美，才是最完美的人生。”','9150-9182',1,1754048643,1782398540);
INSERT INTO highlights VALUES('3300025230_22_8707-8760','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','人生在世，总会遇到各种各样的事，各种各样的人。其中，真的有意义的事，真正值得交往的人，可能最多只有10%。','8707-8760',1,1754045477,1782398540);
INSERT INTO highlights VALUES('3300025230_22_5921-6014','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','高考就是一种次优选择。高考肯定不是最好的人才选拔制度，它存在着认分不认人、一刀切、太过机械化等诸多缺陷。但就现阶段来看，相比其他评价机制，高考却是“最不坏的制度”，也是相对最公平的制度。','5921-6014',1,1754045000,1782398540);
INSERT INTO highlights VALUES('3300025230_22_5736-5747','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','“最好”是“好”的敌人','5736-5747',1,1754044977,1782398540);
INSERT INTO highlights VALUES('3300025230_22_5252-5319','3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','次优选择的经济意义在于以有限的资源获得次优但是仍然让人满意的结果。对应的极端情况是不计成本耗用资源（时间、人力、金钱）以获得最佳结果。','5252-5319',1,1754044859,1782398540);
INSERT INTO highlights VALUES('3300025230_21_3553-3601','3300025230',21,'15 柠檬市场 我这么优秀，为什么还是剩下了？','逆向选择（adverse selection），指的是信息不对称所造成的市场资源配置扭曲的现象，','3553-3601',1,1754035204,1782398540);
INSERT INTO highlights VALUES('3300025230_21_906-925','3300025230',21,'15 柠檬市场 我这么优秀，为什么还是剩下了？','最优质的资源往往不能得到最大化的配置。','906-925',1,1754034446,1782398540);
INSERT INTO highlights VALUES('3300025230_20_4401-4444','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','普通人（非经济学家）常常不计算机会成本，而经济学家则往往忽略沉没成本——这是一种睿智。','4401-4444',1,1754032890,1782398540);
INSERT INTO highlights VALUES('3300025230_20_4281-4349','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','从决策的角度看，以往发生的费用只是造成当前状态的某个因素，当前决策所要考虑的是未来可能发生的费用及所带来的收益，而不考虑以往发生的费用。','4281-4349',1,1754032825,1782398540);
INSERT INTO highlights VALUES('3300025230_20_4083-4135','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','沉没成本（sunk cost）是经济学中的一个概念，是指那些已经付出，不可收回，且与当前决策无关的成本。','4083-4135',1,1754032765,1782398540);
INSERT INTO highlights VALUES('3300025230_20_3375-3429','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','其实你应该庆幸，你已经算是很早就做出了果断而理智选择的人，让自己剩下的时间、精力和金钱及时转移到别的地方去。','3375-3429',1,1754032678,1782398540);
INSERT INTO highlights VALUES('3300025230_20_2638-2650','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','损失厌恶会让损失越来越大','2638-2650',1,1754032589,1782398540);
INSERT INTO highlights VALUES('3300025230_20_1662-1708','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','人们在内心感受上，对损失和获得的敏感程度是不同的，损失带来的痛苦要大于等量获得所带来的快乐。','1662-1708',1,1754032459,1782398540);
INSERT INTO highlights VALUES('3300025230_20_398-424','3300025230',20,'14 损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','损失厌恶 有了美满的婚姻，却一直放不下前任，怎么办？','398-424',1,1754031914,1782398540);
INSERT INTO highlights VALUES('3300025230_19_7412-7471','3300025230',19,'13 锚定效应 为什么总是找不到比初恋更好的男朋友呢？','测验一个人的智力是否属于上乘，只要看他脑子里能否同时容纳两种相反的思想，而无碍于其处世行事。即“思可相反，得须相成”。','7412-7471',1,1754031777,1782398540);
INSERT INTO highlights VALUES('3300025230_19_7100-7151','3300025230',19,'13 锚定效应 为什么总是找不到比初恋更好的男朋友呢？','皮格马利翁效应”。一定程度上，人的预期就相当于锚沉没的深度，预期越高，锚沉得越深，锚定效应也会越明显。','7100-7151',1,1754031654,1782398540);
INSERT INTO highlights VALUES('3300025230_19_6192-6216','3300025230',19,'13 锚定效应 为什么总是找不到比初恋更好的男朋友呢？','对于只有锤子的人而言，每个问题都像是一个钉子。”','6192-6216',1,1754031480,1782398540);
INSERT INTO highlights VALUES('3300025230_19_1883-1962','3300025230',19,'13 锚定效应 为什么总是找不到比初恋更好的男朋友呢？','锚定效应，是指当人们需要对某个事件做定量估测时，会将某些特定数值作为起始值，起始值像锚一样制约着估测值。在做决策的时候，会不自觉地给予最初获得的信息过多的重视','1883-1962',1,1754030398,1782398540);
INSERT INTO highlights VALUES('3300025230_17_9790-9825','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','请相信，人生会偏爱那些努力的孩子，但是所有的偏爱，都来源于自己的努力。','9790-9825',1,1754018517,1782398540);
INSERT INTO highlights VALUES('3300025230_17_9630-9684','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','知识的积累未必能立即得到应用，但是知识会给你应对一切变化的底气，你不会再怕被淘汰，因为你有让自己变强的能力；','9630-9684',1,1754018470,1782398540);
INSERT INTO highlights VALUES('3300025230_17_9462-9482','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','要知道，只有你长久地积累，才能走得长久。','9462-9482',1,1754018429,1782398540);
INSERT INTO highlights VALUES('3300025230_17_8862-8899','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','捷径只是求之不得的人对别人暗自努力的误解，以及为自己的不努力画的一个大饼。','8862-8899',1,1754018263,1782398540);
INSERT INTO highlights VALUES('3300025230_17_7366-7405','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','以跟随策略搭便车，还需要注意形成与强者的差异化，一旦完全一致，就变成了硬碰硬。','7366-7405',1,1754017832,1782398540);
INSERT INTO highlights VALUES('3300025230_17_6825-6869','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','负外部性是某个经济行为个体的活动使他人或社会受损，而造成负外部性的人却没有为此承担成本。','6825-6869',1,1754017728,1782398540);
INSERT INTO highlights VALUES('3300025230_17_6655-6689','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','正外部性是某个个体的经济行为使他人或社会受益，而受益者无须花费代价，','6655-6689',1,1754017710,1782398540);
INSERT INTO highlights VALUES('3300025230_17_6489-6514','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','所谓搭便车现象，基本含义是不付成本而坐享他人之利。','6489-6514',1,1754016933,1782398540);
INSERT INTO highlights VALUES('3300025230_17_5223-5252','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','比如这个例子，把自己置身事外，也是一种比较智慧的博弈手段。','5223-5252',1,1754016774,1782398540);
INSERT INTO highlights VALUES('3300025230_17_1012-1045','3300025230',17,'12 博弈论 作为一个“弱鸡”，我如何在这个弱肉强食的世界活下去？','世界上并没有那么多强者，所有的芸芸众生都是跟我们一样，在努力活着。','1012-1045',1,1754015934,1782398540);
INSERT INTO highlights VALUES('3300025230_16_13436-13528','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','不管是工作还是生活，正确看待概率，努力去争取美好事情发生的机会，精心化解不美好的可能性；看淡短期内概率波动这个被叫作“运气”的东西，坚持积极而长期的决策思维，时间最终会送上鲜花和掌声。','13436-13528',1,1753958099,1782398540);
INSERT INTO highlights VALUES('3300025230_16_8836-8869','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','从选择的倾向来看，选择红按钮的人都在打工，选择绿按钮的人都在创业。','8836-8869',1,1753955937,1782398540);
INSERT INTO highlights VALUES('3300025230_16_8008-8116','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','人生没有绝对的对与错，概率的价值就在这里。所有的事情，都有无数种结果，每种结果都隐藏在不同的概率之中，没有任何一种结果是绝对的好或绝对的坏，你只能在尽可能搜索信息的同时，找出各种选择，从中选出相对更符合你心意的方案。','8008-8116',1,1753955778,1782398540);
INSERT INTO highlights VALUES('3300025230_16_7776-7802','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','本质上都是有信息支持的，都是由信息驱动的无意识决定。','7776-7802',1,1753953383,1782398540);
INSERT INTO highlights VALUES('3300025230_16_7599-7637','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','你对信息掌握得不够全面。在信息不全面的时候，你只能依赖于自己的直觉做出判断。','7599-7637',1,1753953336,1782398540);
INSERT INTO highlights VALUES('3300025230_16_6579-6625','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','事实上，搞清楚每项选择的机会成本与价值并不容易。因为，我们大多数的决策，都是不完全信息决策。','6579-6625',1,1753953234,1782398540);
INSERT INTO highlights VALUES('3300025230_16_6352-6411','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','这种现象称之为“选择的假象”。你看起来拥有无数的机会和选择权，实际上，你并不了解每个机会的可能性，以及这些机会的价值。','6352-6411',1,1753953200,1782398540);
INSERT INTO highlights VALUES('3300025230_16_6083-6127','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','你这些选择有多大概率是更好的选择，新的选择经过一系列的随机事件，最终的结果又会走向何方？','6083-6127',1,1753953165,1782398540);
INSERT INTO highlights VALUES('3300025230_16_5727-5755','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','你现在公司提供的发展机会，行业内还有多少家能够提供给你？','5727-5755',1,1753953039,1782398540);
INSERT INTO highlights VALUES('3300025230_16_5360-5427','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','如果你想让成功稍微偏向你一些，你不能依靠对结果的完美预测，你必须去努力改变链条上每个事件发生的概率，使最终的结果一步步向你的预想靠近。','5360-5427',1,1753952778,1782398540);
INSERT INTO highlights VALUES('3300025230_16_4755-4980','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','事情的发展过程是一个个事件组成的链条，每一个事件的发生都是随机的，都有着各自不同的发生概率，单看每一个事件都是独立的，但是组成的链条却又错综复杂互相关联。只有随着事件发展过程中一些真实情况的发生，未来的可能性才会逐渐向一些事件链条归拢，你需要不断关注还剩下哪些事件链条，发生的概率又产生了什么变化。最终，所有的可能性会聚集到一个事件链条上，那就是这件事情真正产生结果的时刻。只有到这个时候，才最终会看到：所有的可能性都消失了，一个不可逆的结果产生了。','4755-4980',1,1753952597,1782398540);
INSERT INTO highlights VALUES('3300025230_16_4267-4360','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','选择性偏差”。我们会记着那些印象深刻的事而不是平淡无奇的事，所以天气预报准的那些日子都淡淡而过，一旦预报不准我们就暗暗“记恨于心”，长此以往我们就留下了天气预报就是“天气乱报”的印象了。','4267-4360',1,1753952353,1782398540);
INSERT INTO highlights VALUES('3300025230_16_3752-3813','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','为了让这个结论更能说服自己和他人，还会将更多其实完全无关的独立事件全部归拢在一起，以此来说明自己所遇到的只是“运气”问题。','3752-3813',1,1753952306,1782398540);
INSERT INTO highlights VALUES('3300025230_16_3692-3752','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','事实上，人们在遇到挫折时，往往既难以接受自身的错误，也难以接受只是概率使然，为了让自己释怀而给出一个“运气不佳”的结论。','3692-3752',1,1753952289,1782398540);
INSERT INTO highlights VALUES('3300025230_16_2930-2951','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','大数定律，意思是大样本均值向总体均值趋近。','2930-2951',1,1753952133,1782398540);
INSERT INTO highlights VALUES('3300025230_16_1609-1695','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','是的，命运确实不公平。历史的曲折不会均匀地分布在每一个参与者的身上，在跌宕起伏的过程中，很多人的人生都被随机裹挟着前行。对个人而言，时代的一粒尘埃，砸在自己身上都是一座山。','1609-1695',1,1753951915,1782398540);
INSERT INTO highlights VALUES('3300025230_16_457-467','3300025230',16,'11 概率与风险 为什么别人的人生开了挂，我却处处碰壁？','人生赢家都是概率赢家','457-467',1,1753951781,1782398540);
INSERT INTO highlights VALUES('3300025230_15_11705-11734','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','最美的爱情就是你很好，我也不差，两个人势均力敌，相扶相依。','11705-11734',1,1753950603,1782398540);
INSERT INTO highlights VALUES('3300025230_15_11286-11371','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','但是随着生活的推进，恋爱关系的客观效用开始边际递减，洗衣、做饭等世俗需求开始磨灭双方对美好生活的向往。主观稀缺性上呢？明显游戏已经开始入侵男生的生活，他的眼里不再只有你。','11286-11371',1,1753950257,1782398540);
INSERT INTO highlights VALUES('3300025230_15_10435-10463','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','实际上，男女感情问题，本质上也是一个主观价值的判断问题。','10435-10463',1,1753950135,1782398540);
INSERT INTO highlights VALUES('3300025230_15_10492-10552','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','大家都知道爱情的本质是吸引，但吸引的本质是什么呢？其实是价值。','10492-10552',1,1753950122,1782398540);
INSERT INTO highlights VALUES('3300025230_15_11599-11656','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','爱的双方都应该致力于提高自身的客观效用——如自我素质、爱的能力，同时努力在彼此心目中让主观稀缺性为正值并不断增加。','11599-11656',1,1753949925,1782398540);
INSERT INTO highlights VALUES('3300025230_15_9581-9623','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','我们在销售的时候，必须以消费者的个人价值判断为基准，才能打动消费者，实现销售最大化。','9581-9623',1,1753949681,1782398540);
INSERT INTO highlights VALUES('3300025230_15_8782-8826','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','首先，我们在投资时，必须以大众的价值判断为基准，避免因为个人的价值判断影响了投资的回报。','8782-8826',1,1753949590,1782398540);
INSERT INTO highlights VALUES('3300025230_15_6986-6999','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','价值=客观效用×主观稀缺性','6986-6999',1,1753949361,1782398540);
INSERT INTO highlights VALUES('3300025230_15_6138-6147','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','价值=效用×稀缺性','6138-6147',1,1753949259,1782398540);
INSERT INTO highlights VALUES('3300025230_15_4667-4721','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','也就是说，如果没有人，世上所有的财富就不成为财富，没有丝毫价值。价值都是人赋予的，比如本就是一块石头的钻石。','4667-4721',1,1753949109,1782398540);
INSERT INTO highlights VALUES('3300025230_15_2894-2922','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','每一方都是用对自己价值低的东西换取了对自己价值高的东西。','2894-2922',1,1753948931,1782398540);
INSERT INTO highlights VALUES('3300025230_15_2183-2233','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','人们以什么样的价格接受一件物品，并不是基于这个物品的客观价值，而是基于自己对这个物品的主观价值判断。','2183-2233',1,1753948779,1782398540);
INSERT INTO highlights VALUES('3300025230_15_1773-1785','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','不同的人有不同的价值判断','1773-1785',1,1753948502,1782398540);
INSERT INTO highlights VALUES('3300025230_15_1151-1158','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','价值是主观的。','1151-1158',1,1753948446,1782398540);
INSERT INTO highlights VALUES('3300025230_15_1058-1072','3300025230',15,'10 价值判断 为什么男朋友会在虚拟游戏中花费巨资买道具？','“汝之蜜糖，我之砒霜”的问题','1058-1072',1,1753948442,1782398540);
INSERT INTO highlights VALUES('3300025230_14_9843-9877','3300025230',14,'09 幸存者偏差 为什么别人家的孩子都那么优秀？','爱笑的女孩，运气都不会太差——没错，因为运气差的女孩，根本笑不出来。','9843-9877',1,1753941547,1782398540);
INSERT INTO highlights VALUES('3300025230_14_5045-5073','3300025230',14,'09 幸存者偏差 为什么别人家的孩子都那么优秀？','所以说，成功不可借鉴，因为所有的成功经验都不具有普遍性。','5045-5073',1,1753941012,1782398540);
INSERT INTO highlights VALUES('3300025230_14_3221-3293','3300025230',14,'09 幸存者偏差 为什么别人家的孩子都那么优秀？','即分析问题时所依赖的信息全部或者大部分来自显著信息，较少利用不显著的信息或者彻底忽略“沉默的信息”，因此得出的结论与事实情况就可能存在巨大偏差。','3221-3293',1,1753940847,1782398540);
INSERT INTO highlights VALUES('3300025230_14_2014-2132','3300025230',14,'09 幸存者偏差 为什么别人家的孩子都那么优秀？','幸存者偏差（survivorship bias），又称为生存者偏差或存活者偏差，意思是只能看到经过某种筛选而产生的结果，而没有意识到筛选的过程，因此忽略了被筛选掉的关键信息。这个概念的别名还有很多，比如“沉默的数据”“死人不会说话”等。','2014-2132',1,1753940675,1782398540);
INSERT INTO highlights VALUES('3300025230_13_7749-7756','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','《解忧杂货店》','7749-7756',1,1753940223,1782398540);
INSERT INTO highlights VALUES('3300025230_13_7762-7821','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','“其实所有纠结做选择的人，心里早就有了答案，咨询只是想得到内心所倾向的选择。最终的所谓命运，还是自己一步步走出来的。”','7762-7821',1,1753940218,1782398540);
INSERT INTO highlights VALUES('3300025230_13_5860-5885','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','“那时我只会想自己想要什么，从不想自己拥有什么。”','5860-5885',1,1753931061,1782398540);
INSERT INTO highlights VALUES('3300025230_13_5709-5778','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','选择的意义不仅仅在于你选择的东西，更在于你放弃的东西。你放弃的每一个机会都没有真正地放弃，而是变成了机会成本，作为日后衡量利益得失的基石。','5709-5778',1,1753931032,1782398540);
INSERT INTO highlights VALUES('3300025230_13_4865-4886','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','一个好的选择就是要让它的机会成本尽可能低。','4865-4886',1,1753930837,1782398540);
INSERT INTO highlights VALUES('3300025230_13_4337-4358','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','机会成本不是你选择的东西，而是你放弃的东西','4337-4358',1,1753930774,1782398540);
INSERT INTO highlights VALUES('3300025230_13_3077-3129','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','机会成本本质上是对不能利用的机会所付出的成本，因为一般选择了这种用途，就必然丧失其他用途所能带来的收益。','3077-3129',1,1753930611,1782398540);
INSERT INTO highlights VALUES('3300025230_13_2882-2922','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','当吃鱼给你带来的愉悦超过熊掌给你带来的愉悦时，那你的选择就应该是吃鱼，反之亦然。','2882-2922',1,1753930588,1782398540);
INSERT INTO highlights VALUES('3300025230_13_2688-2720','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','其依据是实际收益必须大于机会成本，从而使有限的资源得到最佳配置。','2688-2720',1,1753930541,1782398540);
INSERT INTO highlights VALUES('3300025230_13_2512-2584','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','机会成本（opportunity cost），是指为从事某项经营活动而放弃另一项经营活动的机会，或利用一定资源获得某种收入时所放弃的另一种收入。','2512-2584',1,1753930266,1782398540);
INSERT INTO highlights VALUES('3300025230_13_1657-1665','3300025230',13,'08 机会成本 是在小城市岁月静好，还是到大城市策马奔腾？','人生没有两全其美','1657-1665',1,1753930242,1782398540);
INSERT INTO highlights VALUES('3300025230_11_8625-8635','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','敬畏未知，才会努力。','8625-8635',1,1753866997,1782398540);
INSERT INTO highlights VALUES('3300025230_11_8011-8049','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','不是你和这个人同频，也不是你表达能力强，而是这个人的认知和思维能力在你之上。','8011-8049',1,1753866820,1782398540);
INSERT INTO highlights VALUES('3300025230_11_7750-7855','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','向下兼容”。也就是说，一个认知和思维水平比你高的人，在发现你们并不在同一高度时，也会主动向下兼容你，你和这样的人相处会非常愉快，你抛出的梗对方都能接，交流没有任何不适，你会感觉到他是和你在同一个高度和频率的人。','7750-7855',1,1753866794,1782398540);
INSERT INTO highlights VALUES('3300025230_11_7451-7531','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','你手上也许掌握了许多人不了解的信息，但是为什么你没有成功？除了信息质量外，问题的关键是解决认知差。也就是说，你对这个世界的理解力，最终决定了你能跑多远、飞多高。','7451-7531',1,1753866604,1782398540);
INSERT INTO highlights VALUES('3300025230_11_7003-7138','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','最基础的代价，就是时间。想要获取知识，就需要时间去找书、看书、上网搜寻、找人问、自己实践……付出很多很多的时间成本。最普遍的代价，就是金钱。所谓知识付费，即出钱买高密度的信息。想要节省时间，最直接的就是付出金钱。','7003-7138',1,1753866548,1782398540);
INSERT INTO highlights VALUES('3300025230_11_6493-6522','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','二是依靠截断信息获利——设置门槛，截断消息，永远不给你真相','6493-6522',1,1753866472,1782398540);
INSERT INTO highlights VALUES('3300025230_11_6371-6397','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','一是依靠传递信息获利——在弥合信息鸿沟的过程中获利。','6371-6397',1,1753866452,1782398540);
INSERT INTO highlights VALUES('3300025230_11_5491-5535','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','有关社交媒体的研究表明，在用户优先连接到与他们共享观点的其他用户时，会发生意见和情绪传染','5491-5535',1,1753866195,1782398540);
INSERT INTO highlights VALUES('3300025230_11_5143-5208','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','所谓回声室效应，是指在一个网络空间里，如果你听到的都是和你意见相似的回响，你会认为自己的看法代表主流，从而扭曲你对一般共识的认识。','5143-5208',1,1753864850,1782398540);
INSERT INTO highlights VALUES('3300025230_11_4991-5114','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','久而久之，一直深处于自己乐意看到的内容池当中，所见所闻被APP所控制，信息接受维度变窄，知识获取单一，对其他领域越来越陌生，便会很难接受不同的观点，行为习惯被自己的兴趣引导，在单调的信息中形成了特定思维习惯。这种特定的思维，被叫作“回声室效应”。','4991-5114',1,1753864764,1782398540);
INSERT INTO highlights VALUES('3300025230_11_4956-4991','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','实现“看我想看，听我想听”，如同吸食精神鸦片后所获得的心理上的舒适感。','4956-4991',1,1753864731,1782398540);
INSERT INTO highlights VALUES('3300025230_11_4533-4612','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','当个人长期禁锢在自己所建构的个人日报中，久而久之，个人生活呈现出一种定式化、程序化，失去了解不同事物的能力和接触机会，不知不觉间为自己制造了一个“信息茧房”。','4533-4612',1,1753864569,1782398540);
INSERT INTO highlights VALUES('3300025230_11_4306-4356','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','公众的信息需求并非全方位的，公众只注意使自己愉悦的领域，久而久之，会将自身桎梏于像蚕茧一般的茧房中。','4306-4356',1,1753864461,1782398540);
INSERT INTO highlights VALUES('3300025230_11_4208-4225','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','“信息茧房”的概念出现于2006年','4208-4225',1,1753864436,1782398540);
INSERT INTO highlights VALUES('3300025230_11_2095-2175','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','信息不对称理论是指在市场经济活动中，各类人员对有关信息的了解是有差异的。掌握信息比较充分的人员，往往处于比较有利的地位；而信息贫乏的人员，则处于比较不利的地位。','2095-2175',1,1753864209,1782398540);
INSERT INTO highlights VALUES('3300025230_11_1059-1069','3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','中间商是信息的搬运工','1059-1069',1,1753863975,1782398540);
INSERT INTO highlights VALUES('3300025230_10_10563-10645','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','有认知偏差并不可怕。最可怕的是偏差盲点（bias blind spot），即看不到自己的认知偏差存在。正如俗语所说，“你不知道并不可怕，可怕的是你不知道你不知道”。','10563-10645',1,1753863443,1782398540);
INSERT INTO highlights VALUES('3300025230_10_10430-10455','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','或者说人只能拥有有限理性，认知的误差无法被完全消除','10430-10455',1,1753863429,1782398540);
INSERT INTO highlights VALUES('3300025230_10_9303-9339','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','证实性偏差导致个体过分相信自己判断的准确性，评价一旦形成便不会轻易改变。','9303-9339',1,1753845333,1782398540);
INSERT INTO highlights VALUES('3300025230_10_9149-9206','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','证实性偏差是指当人确立了某一个信念或观念时，在收集信息和分析信息的过程中，会产生一种寻找支持这个信念的证据的倾向。','9149-9206',1,1753845254,1782398540);
INSERT INTO highlights VALUES('3300025230_10_8826-8884','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','一开始只是一种感觉，模模糊糊没有那么多的证据。但是当你注意起这件事，证据就一一浮出水面，一件一桩都在证实着你的判断：','8826-8884',1,1753845225,1782398540);
INSERT INTO highlights VALUES('3300025230_10_9095-9100','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','证实性偏差','9095-9100',1,1753845116,1782398540);
INSERT INTO highlights VALUES('3300025230_10_8471-8530','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','认知偏差出现的原因，在于人脑的本质功能是处理人与人之间的关系，而不是进行统计计算，大脑处理视觉形象远胜于处理数字逻辑。','8471-8530',1,1753845024,1782398540);
INSERT INTO highlights VALUES('3300025230_10_8157-8180','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','在投资时，选择性偏差往往来源于人们的认知局限性','8157-8180',1,1753844936,1782398540);
INSERT INTO highlights VALUES('3300025230_10_7703-7753','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','为什么演讲比赛的时候，讲生动鲜活的故事会更加感动观众？为什么会讲故事的创业者更容易得到投资人的青睐？','7703-7753',1,1753844889,1782398540);
INSERT INTO highlights VALUES('3300025230_10_6908-7005','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','人会根据信息容易想起来的程度来评估其发生的可能性。所以那些很生动、特别容易回忆起来的事情，会被人认为比那些没有什么印象或不太容易回忆起来的事发生的频率更高——这种心理上的认知偏差被称为可得性偏差','6908-7005',1,1753844654,1782398540);
INSERT INTO highlights VALUES('3300025230_10_6724-6878','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','因为媒体追求的是新闻的爆点，如果是经常发生的事也就没必要报道了。空难发生少，反而每次发生空难，媒体都会铺天盖地地大肆报道，搭配大量触目惊心的照片，媒体报道的照片、视频、声音、个人见证等具备生动和鲜活性，对每个人的右脑产生冲击，导致在观众心中留下不可磨灭的印象，进而影响人们的情绪反应，使大家高估空难发生的概率','6724-6878',1,1753844587,1782398540);
INSERT INTO highlights VALUES('3300025230_10_5178-5243','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','恋爱失败者处于情感的低落期，需要进行心理和情感上的调整。将错误归因于对方，可以帮助自己从低谷中走出来。二是为了维护自尊心和良好形象','5178-5243',1,1753844372,1782398540);
INSERT INTO highlights VALUES('3300025230_10_4911-5001','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','假设恋爱本人在恋爱中的行为表现和生活中的表现一致，一旦出现问题，就归因于恋爱本人的个人因素，比如本身的性格、能力、处世态度，如性格太倔强、有大男子主义、容易发脾气、经常无理取闹等。','4911-5001',1,1753844113,1782398540);
INSERT INTO highlights VALUES('3300025230_10_4661-4729','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','一段恋情结束后，人们在事后描述时总会找出这样那样的原因。但是，很多时候，人们在进行归因时，却并不总是合乎逻辑的，这是因为出现了归因偏差。','4661-4729',1,1753843906,1782398540);
INSERT INTO highlights VALUES('3300025230_10_4060-4121','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','由于人们在归因的时候，往往站在自己的角度，或者说对自己有利的角度去认知，所以经济学家也提出了一个概念，叫利己主义归因偏差。','4060-4121',1,1753843545,1782398540);
INSERT INTO highlights VALUES('3300025230_10_3534-3601','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','研究表明，实施行为的人往往强调情境的作用，对自己的行为多强调外部原因，作外归因；而旁观者常常强调并高估实施行为的人自身的、内在的因素。','3534-3601',1,1753843238,1782398540);
INSERT INTO highlights VALUES('3300025230_10_2939-2978','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','归因偏差是指对人的行为进行归因时，高估内在倾向作用而忽视情境因素作用的一般倾向','2939-2978',1,1753786023,1782398540);
INSERT INTO highlights VALUES('3300025230_10_3162-3262','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','一种解释认为，人们之所以会强调行为的个人因素而忽视情境因素，是因为个人的内在因素比情境因素更突出，更显眼，更易引起人们的注意。将活动结果归因于活动者个人的特质反映了人们的一种自然的、习惯性的认识倾向。','3162-3262',1,1753786016,1782398540);
INSERT INTO highlights VALUES('3300025230_10_3394-3444','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','正是这种强调个人权利和义务，鼓励个人奋斗的社会标准或规范，使得人们倾向于做出个人归因而不是环境归因。','3394-3444',1,1753786001,1782398540);
INSERT INTO highlights VALUES('3300025230_10_2029-2121','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','我们或许无法也不应该把自己训练成一个冷酷的“绝对理性的人”，但是知道“非理性”行为对决策造成的偏差，却可以帮助自己更清晰地认知这个世界，从而让将来的决策比自己、比别人更精准那么一丢丢。','2029-2121',1,1753785714,1782398540);
INSERT INTO highlights VALUES('3300025230_10_1571-1642','3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','相比绝对理性的“经济人”来说，我们更符合心理学上“行为人”的定义。我们的行为不仅是理性的，更受到外界环境、经历、个性、情感等非理性因素的影响。','1571-1642',1,1753785521,1782398540);
INSERT INTO highlights VALUES('3300025230_9_10663-10690','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','“iPhone和喜诗糖果类似，都能给人带来美好的感觉。','10663-10690',1,1753783054,1782398540);
INSERT INTO highlights VALUES('3300025230_9_10960-11101','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','你之所以会冲动消费，并非自己还没有修炼到理性人的高度，而是因为你就是人，活生生有感情的人。对于人来说，完美的理性不存在，绝对的正确也不是我们能控制的。我们所能做的，就是擦亮眼睛，对自己的认知更清晰一点，对世界的看法更准确一点','10960-11101',1,1753783044,1782398540);
INSERT INTO highlights VALUES('3300025230_9_9722-9821','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','对于每一个人，生活必要的开支账户、家庭建设和个人发展的开支账户、情感维系的账户、享乐休闲吃喝玩乐的账户等虽然都是你的账户，但每一个子账户都是独立存在的。对于每个账户的余额，每个人都有自己不同的判断。','9722-9821',1,1753782732,1782398540);
INSERT INTO highlights VALUES('3300025230_9_8574-8628','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','实际上，禀赋效应反映的正是由于人们在决策过程中对利害的权衡不均衡，对“避害”的考虑远远大于对“趋利”的考虑。','8574-8628',1,1753782345,1782398540);
INSERT INTO highlights VALUES('3300025230_9_8281-8357','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','一些商品可以提供一段时间的免费试用，客户通过免费试用的方式使用一段时间后，在顾客心理上因为禀赋效应放大了商品的价值，所以舍不得送回去，就会产生购买行为。','8281-8357',1,1753782175,1782398540);
INSERT INTO highlights VALUES('3300025230_9_7959-8045','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','禀赋效应（endowment effect），是指我们一旦拥有某件物品，那么自然而然就会对该物品价值的评价比没有拥有之前大大增加，这实际上可以理解为我们常说的“敝帚自珍”。','7959-8045',1,1753782077,1782398540);
INSERT INTO highlights VALUES('3300025230_9_4602-4694','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','投资时，多数人的表现是“赔则拖，赢必走”。在股市中，普遍有一种“卖出效应”，也就是投资者卖出获利股票的意向，要远远大于卖出亏损股票的意向。这与“对则持，错即改”的投资核心理念背道而驰。','4602-4694',1,1753781693,1782398540);
INSERT INTO highlights VALUES('3300025230_9_3855-3928','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','简言之，人在面临获利时不愿冒风险；而在面临损失时，人人都成了冒险家。而损失和获利是相对于参照点而言的，改变评价事物的参照点，就会改变对风险的态度。','3855-3928',1,1753781555,1782398540);
INSERT INTO highlights VALUES('3300025230_9_3102-3156','3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','大多数人对损失和获得的敏感程度不对称，面对损失的痛苦感要大大超过面对获得的快乐感，导致我们更倾向于损失规避。','3102-3156',1,1753781457,1782398540);
INSERT INTO highlights VALUES('3300025230_8_9691-9730','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','世界上没有免费的午餐。正如那句名言所说：所有命运的馈赠，早已在暗中标好了价格。','9691-9730',1,1753773694,1782398540);
INSERT INTO highlights VALUES('3300025230_8_8491-8573','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','所以说，我们花了一笔钱，如果不去，我们会觉得亏，因为那个是惩罚机制，但惩罚机制其实并没有帮助我们更多地去健身房；反而是奖励机制，可以让我们更好地培养去健身房的习惯。','8491-8573',1,1753773513,1782398540);
INSERT INTO highlights VALUES('3300025230_8_8000-8033','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','决策疲乏，在决策疲乏时，人们往往放弃最佳决定，而是做最简单的决定。','8000-8033',1,1753773418,1782398540);
INSERT INTO highlights VALUES('3300025230_8_7870-7923','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','人们往往比较专注于现在的快乐，而对于未来可能的好处，却打上了夸张的折扣。在生活中，我们经常被这种心理控制。','7870-7923',1,1753773402,1782398540);
INSERT INTO highlights VALUES('3300025230_8_5057-5125','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','商家将“诱饵”放入选择当中，就可以构建出简单的、直观的对比关系，既可以促使消费者尽快做出决定，更可以把消费者的决定导向事先设定好的方案。','5057-5125',1,1753772803,1782398540);
INSERT INTO highlights VALUES('3300025230_8_4938-4972','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','被“诱饵”帮助的选项通常称为“目标”，而另一选项则被称为“竞争者”。','4938-4972',1,1753772697,1782398540);
INSERT INTO highlights VALUES('3300025230_8_4868-4938','3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','诱饵效应（decoy effect），是指人们对两个不相上下的选项进行选择时，因为第三个新选项（诱饵）的加入，会使某个旧选项显得更有吸引力。','4868-4938',1,1753772686,1782398540);
INSERT INTO highlights VALUES('3300025230_6_8704-8745','3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','着眼长远，把当前的事情做好，聚焦于能够增加价值的事情，就是在为自己拓展人生的边际。','8704-8745',1,1753758062,1782398540);
INSERT INTO highlights VALUES('3300025230_6_8444-8510','3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','换句话说，如果你能把投入一份时间精力的产品卖出更多份，那就是做着边际成本递减的事。规模越大，你需要多投入的精力越少，而你的收入越高。','8444-8510',1,1753757944,1782398540);
INSERT INTO highlights VALUES('3300025230_6_7522-7605','3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','但是，最有价值的事情不是一成不变的，是会随着情境的不同而动态转移的。一件事情一旦完成，重要性就不复存在。最重要的永远是当下要完成的工作，我们可以把它叫作“边际工作”。','7522-7605',1,1753757809,1782398540);
INSERT INTO highlights VALUES('3300025230_6_1522-1558','3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','边际主义指出：在价值决策中最重要的是边际，即最后一单位的消费品或是产品。','1522-1558',1,1753707289,1782398540);
INSERT INTO highlights VALUES('3300025230_6_472-483','3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','理性的决策看的是边际量','472-483',1,1753706422,1782398540);
INSERT INTO highlights VALUES('3300025230_5_8874-8965','3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','财富分化带给我们的直观感受，并不是收入更高了就变富了，而是在财富中的位置靠前了，才是变富了。放大来看，如果在整个社会中，财富的排位一直能够维持不变，甚至有所进步，才是所谓的“富”了。','8874-8965',1,1753694811,1782398540);
INSERT INTO highlights VALUES('3300025230_5_5285-5340','3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','财富和收入之间的离散度在加大，劳动产生的收入增长远远赶不上资产创造的财富增长，“人挣钱”远远赶不上“钱生钱”。','5285-5340',1,1753693725,1782398540);
INSERT INTO highlights VALUES('3300025230_5_5378-5382','3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','马太效应','5378-5382',1,1753693714,1782398540);
INSERT INTO highlights VALUES('3300025230_5_4839-4901','3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','与大家关系密切的就是工资增长远远没有赶上社会财富的增长，这就导致依靠工资收入来累积财富的人，在社会财富中的地位必然逐步下降。','4839-4901',1,1753693632,1782398540);
INSERT INTO highlights VALUES('3300025230_5_2452-2486','3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','其实，钱并不等于购买力。甚至社会上的钱越多，我们手里的钱越“不值钱”','2452-2486',1,1753693376,1782398540);
INSERT INTO highlights VALUES('3300025230_3_2005-2027','3300025230',3,'序 经济学有什么用？','经济学家认为，所有的人类行为都是选择的结果。','2005-2027',1,1753692937,1782398540);
INSERT INTO highlights VALUES('3300025230_3_1513-1556','3300025230',3,'序 经济学有什么用？','就会发现经济学存在的意义并不是告诉你一个直接的结论，而是带你掌握认知世界的方法和逻辑。','1513-1556',1,1753692841,1782398540);
INSERT INTO highlights VALUES('3300101680_23_361-372','3300101680',23,'附录 给宝贝的一首小诗','附录　给宝贝的一首小诗','361-372',1,1743219330,1782398548);
INSERT INTO highlights VALUES('3300101680_23_1326-1417','3300101680',23,'附录 给宝贝的一首小诗','生命本轻盈，当我们有机会瞥见真相，就知道：我们随时可以选择不一样。','1326-1417',1,1743219300,1782398548);
INSERT INTO highlights VALUES('3300101680_22_1304-1409','3300101680',22,'写在最后 了不起的努力','而每一个真心的笑，都像投入湖心的小石子，会泛起涟漪。你不知道，谁会被这涟漪触动，也漾出了笑容。','1304-1409',1,1743219225,1782398548);
INSERT INTO highlights VALUES('3300101680_22_938-1156','3300101680',22,'写在最后 了不起的努力','所以我们要养成的一个习惯，就是给自己加油，给同行的人加油。从自己开始，从现在开始，从一件小事开始，从一句话开始，从对孩子的一个笑容、一个拥抱开始，','938-1156',1,1743219213,1782398548);
INSERT INTO highlights VALUES('3300101680_21_9755-10176','3300101680',21,'第12章 专治笑不出来','我只是碰巧成了你的父亲，你只是碰巧成了我的孩子，我并不是你的前传，你也不是我的续篇。你是独立的个体，是与我不同的灵魂；你并不因我而来，你是因对生命的渴望而来。你是自由的，我是爱你的，但我绝不会“以爱之名”，去掌控你的人生。','9755-10176',1,1743218530,1782398548);
INSERT INTO highlights VALUES('3300101680_21_9332-9351','3300101680',21,'第12章 专治笑不出来','每一天都是新的，每一刻都可以重新开始。','9332-9351',1,1743217818,1782398548);
INSERT INTO highlights VALUES('3300101680_21_7727-7764','3300101680',21,'第12章 专治笑不出来','“如果把全世界3岁的小男孩排成一排，让我选一个，我依然会毫不犹豫地选你！”','7727-7764',1,1743217648,1782398548);
INSERT INTO highlights VALUES('3300101680_21_7409-7481','3300101680',21,'第12章 专治笑不出来','你可以在生气的前一刻给我们一个预警。”我暗笑，好贴心啊。我又问：“咱们的预警要用个什么暗号呢？”他们说：“你就说‘我快变红了，火山要爆发了’！”','7409-7481',1,1743217589,1782398548);
INSERT INTO highlights VALUES('3300101680_21_7282-7301','3300101680',21,'第12章 专治笑不出来','定期问反馈：你觉得妈妈哪里做得不够好？','7282-7301',1,1743217558,1782398548);
INSERT INTO highlights VALUES('3300101680_21_6936-6980','3300101680',21,'第12章 专治笑不出来','我最大的收获就是，常提醒自己，从孩子的视角看世界。','6936-6980',1,1743217497,1782398548);
INSERT INTO highlights VALUES('3300101680_21_5980-6021','3300101680',21,'第12章 专治笑不出来','“在你还是天上的一颗星星的时候，怎么就选中了我做你的妈妈呢？你怎么就来我家了呢？”','5980-6021',1,1743217425,1782398548);
INSERT INTO highlights VALUES('3300101680_21_4375-4451','3300101680',21,'第12章 专治笑不出来','“一会儿你去了你的幼儿园，我也要去我工作的幼儿园了，如果我想你怎么办呢？我不想去我的幼儿园，我可以在你的幼儿园里上班吗？”她觉得好可笑，推着我赶紧离开。','4375-4451',1,1743217307,1782398548);
INSERT INTO highlights VALUES('3300101680_21_3581-3616','3300101680',21,'第12章 专治笑不出来','让孩子能够应对“不友好”的，恰恰是他们接收到的无条件的爱和他们的自信。','3581-3616',1,1743217194,1782398548);
INSERT INTO highlights VALUES('3300101680_21_2640-2743','3300101680',21,'第12章 专治笑不出来','但也不是一味地“顺应”，是有技巧的。“但是，妈妈稍微有点累，你说抱几下呢？”孩子一般情况下都会很快地说个数字。他说“20下”，你就说：“1000下吧！我想多抱会儿宝贝呢！”这样一来，孩子反而会想要早点下来。','2640-2743',1,1743217015,1782398548);
INSERT INTO highlights VALUES('3300101680_21_2126-2195','3300101680',21,'第12章 专治笑不出来','这个宇宙飞船小游戏，看上去似乎很耗时，但其实只需5分钟，而且省去了大人反复催促的时间，灭掉了孩子的起床气。大人和孩子会变得更亲密、更开心。','2126-2195',1,1743216931,1782398548);
INSERT INTO highlights VALUES('3300101680_21_1245-1394','3300101680',21,'第12章 专治笑不出来','对7岁以下的孩子，你不妨这样试试：在孩子床边，亲一下宝贝，说，哎哟，宇宙飞船休息了一晚上，要准备起飞啦！现在开始热身怎么样？','1245-1394',1,1743216785,1782398548);
INSERT INTO highlights VALUES('3300101680_20_17453-17540','3300101680',20,'第11章 轮回里看到自己','或许，那些看到可爱的小物件眼里就会放光的妈妈们，她们的灵魂距离外部世界更近。社会赋予我们的所谓经验，往往让很多人的外壳变得过于厚重。能够直接展现其灵魂之美的人，真是无价之宝。','17453-17540',1,1743216511,1782398548);
INSERT INTO highlights VALUES('3300101680_20_16897-16930','3300101680',20,'第11章 轮回里看到自己','一是给孩子提供一个自由成长的环境，二是用激情和热情过好自己的生活。','16897-16930',1,1743216448,1782398548);
INSERT INTO highlights VALUES('3300101680_20_15304-15327','3300101680',20,'第11章 轮回里看到自己','“哎，去它的吧，走，咱俩出去玩玩，放松放松”。','15304-15327',1,1743216239,1782398548);
