INSERT INTO highlights VALUES('3300101680_20_14367-14408','3300101680',20,'第11章 轮回里看到自己','“不改变”。这不是消极的不改变，而是意识到人能改变的只有自己，不要试图去改变他人。','14367-14408',1,1743215853,1782398548);
INSERT INTO highlights VALUES('3300101680_20_14346-14354','3300101680',20,'第11章 轮回里看到自己','“如何改变他人”','14346-14354',1,1743215846,1782398548);
INSERT INTO highlights VALUES('3300101680_20_13907-13921','3300101680',20,'第11章 轮回里看到自己','“要允许别人作不同的选择。”','13907-13921',1,1743215680,1782398548);
INSERT INTO highlights VALUES('3300101680_20_13715-13797','3300101680',20,'第11章 轮回里看到自己','你要是不做事，那就只有一个错，就是没做。你只要做事情，就有多于一个错。挑毛病谁都会，有啥了不起，真有本事就去做事情。问问自己，你会因为别人这样议论你，就不做了吗？”','13715-13797',1,1743215665,1782398548);
INSERT INTO highlights VALUES('3300101680_20_11898-11909','3300101680',20,'第11章 轮回里看到自己','第三板斧：爱要表达出来','11898-11909',1,1743214845,1782398548);
INSERT INTO highlights VALUES('3300101680_20_11785-11850','3300101680',20,'第11章 轮回里看到自己','富足的心灵，在任何困难和低谷面前都相信“我可以”的信念和行动力。父母无须说教，自己选择过怎样的人生，就是给孩子最大、最真实的力量。','11785-11850',1,1743214778,1782398548);
INSERT INTO highlights VALUES('3300101680_20_11372-11410','3300101680',20,'第11章 轮回里看到自己','一个女人遵循内心的选择，并付出努力过好自己的生活，可能是对子女最正面的影响。','11372-11410',1,1743214717,1782398548);
INSERT INTO highlights VALUES('3300101680_20_9093-9110','3300101680',20,'第11章 轮回里看到自己','第二板斧：遇事不怕，总可以重新开始','9093-9110',1,1743214430,1782398548);
INSERT INTO highlights VALUES('3300101680_20_8582-8592','3300101680',20,'第11章 轮回里看到自己','平等交流，共同成长。','8582-8592',1,1743214398,1782398548);
INSERT INTO highlights VALUES('3300101680_20_8131-8149','3300101680',20,'第11章 轮回里看到自己','第一板斧：抓大放小，让孩子自己做决定','8131-8149',1,1743214347,1782398548);
INSERT INTO highlights VALUES('3300101680_20_7965-8017','3300101680',20,'第11章 轮回里看到自己','每个普通人，一旦意识到、觉知到，就可以做出改变。这种改变，哪怕需要很长的时间跨度，也终会带来正面的影响。','7965-8017',1,1743214217,1782398548);
INSERT INTO highlights VALUES('3300101680_20_4775-4805','3300101680',20,'第11章 轮回里看到自己','很多学习跟早晚其实没有太大关系，孩子自主发展的空间反而更重要','4775-4805',1,1743172726,1782398548);
INSERT INTO highlights VALUES('3300101680_20_4348-4357','3300101680',20,'第11章 轮回里看到自己','习惯性地忽视情绪，','4348-4357',1,1743172660,1782398548);
INSERT INTO highlights VALUES('3300101680_20_4165-4319','3300101680',20,'第11章 轮回里看到自己','这种“压抑”和“懂事”，成了我后来“成就”的基础，但这些“懂事”，也是有代价的：习惯性地忽视自己，习惯性地取悦权威，习惯性的实用主义，','4165-4319',1,1743172655,1782398548);
INSERT INTO highlights VALUES('3300101680_20_3688-3720','3300101680',20,'第11章 轮回里看到自己','如果无法选择，就不要纠结，尽量把经历转化成财富。”','3688-3720',1,1743172563,1782398548);
INSERT INTO highlights VALUES('3300101680_20_1492-1544','3300101680',20,'第11章 轮回里看到自己','做父母难，不仅因为眼前的灵性个体，也因为我们所处的一个具有偶然性的、复杂的、多维的、无法选择的历史场景。','1492-1544',1,1743172370,1782398548);
INSERT INTO highlights VALUES('3300101680_20_1357-1426','3300101680',20,'第11章 轮回里看到自己','每个时代的父母，都处在一个复杂、多维、既相连又相异的世界中。他们在一个无法选择的历史场景里，用个体的生命体验，不断地探索和应对未知的挑战。','1357-1426',1,1743172326,1782398548);
INSERT INTO highlights VALUES('3300101680_20_1185-1242','3300101680',20,'第11章 轮回里看到自己','1776年的《独立宣言》，也是乾隆年间发布的。这一历史时间线上的交错，让我们对文明的不同步发展产生了强烈的错位感。','1185-1242',1,1743172267,1782398548);
INSERT INTO highlights VALUES('3300101680_19_12251-12272','3300101680',19,'第10章 怎么就丧失了笑的能力','最核心层，是关于获得内在的生命力和智慧的。','12251-12272',1,1743171566,1782398548);
INSERT INTO highlights VALUES('3300101680_19_12087-12108','3300101680',19,'第10章 怎么就丧失了笑的能力','中间层，是关于获得面对“不确定”的能力的。','12087-12108',1,1743171561,1782398548);
INSERT INTO highlights VALUES('3300101680_19_11945-11958','3300101680',19,'第10章 怎么就丧失了笑的能力','最外层，是关于技能获得的。','11945-11958',1,1743171557,1782398548);
INSERT INTO highlights VALUES('3300101680_19_11443-11491','3300101680',19,'第10章 怎么就丧失了笑的能力','其实完全是一种自我平复。只有这个时候，你会感觉既没有忽略孩子，又在自我成长，还暂时地撇开了现实。','11443-11491',1,1743171433,1782398548);
INSERT INTO highlights VALUES('3300101680_19_11258-11304','3300101680',19,'第10章 怎么就丧失了笑的能力','孩子是母体自我分裂出来的一个“非我”，他既是母亲不可抗拒的一部分，又是与母亲完全不同的个体。','11258-11304',1,1743171363,1782398548);
INSERT INTO highlights VALUES('3300101680_19_9814-9862','3300101680',19,'第10章 怎么就丧失了笑的能力','所以我们对孩子的教育，大部分也不是通过说教来完成的，而是通过我们自身的状态向外构建出的家庭场域。','9814-9862',1,1743171184,1782398548);
INSERT INTO highlights VALUES('3300101680_19_9963-9982','3300101680',19,'第10章 怎么就丧失了笑的能力','我们的内在障碍越少，这个场域就越松弛。','9963-9982',1,1743171175,1782398548);
INSERT INTO highlights VALUES('3300101680_19_8942-8987','3300101680',19,'第10章 怎么就丧失了笑的能力','我们内心追求的、渴望的和我们在外在世界里所做的事情、所呈现的状态是一致的，这就是一种幸福。','8942-8987',1,1743171107,1782398548);
INSERT INTO highlights VALUES('3300101680_19_8857-8906','3300101680',19,'第10章 怎么就丧失了笑的能力','他的幸福感从何而来？和成年人一样，源于由内而外的自洽与一致。','8857-8906',1,1743171041,1782398548);
INSERT INTO highlights VALUES('3300101680_19_8044-8158','3300101680',19,'第10章 怎么就丧失了笑的能力','成功被分成两类：一类看得见、摸得着，如学历、工资和职位。很多“人生指南”都在讲如何追求这些看得见的东西。还有更重要的一类，是看不见、摸不着的，如完善的人格、健康的身心，以及与周围人建立深度友好关系的能力，或者说，笑得出来的能力。','8044-8158',1,1743170930,1782398548);
INSERT INTO highlights VALUES('3300101680_19_7028-7068','3300101680',19,'第10章 怎么就丧失了笑的能力','最好的准备就是在每一个当下能够抽离、觉察、看到事情本身的样子，并做出相应的反应。','7028-7068',1,1743088625,1782398548);
INSERT INTO highlights VALUES('3300101680_19_6688-6783','3300101680',19,'第10章 怎么就丧失了笑的能力','每一个起点，都是终点，而每一个终点，又都是新的起点。这就是所谓的“当下”。','6688-6783',1,1743088580,1782398548);
INSERT INTO highlights VALUES('3300101680_19_5670-5707','3300101680',19,'第10章 怎么就丧失了笑的能力','作为父母，我们的成长和精进正是通过意识到并改变我们内心曾经的信念而实现的。','5670-5707',1,1743000689,1782398548);
INSERT INTO highlights VALUES('3300101680_19_4978-5020','3300101680',19,'第10章 怎么就丧失了笑的能力','因为孩子所表达的，正是一种难得的“抽离感”，一种对自我和他人都有“退后一步”的观察。','4978-5020',1,1743000550,1782398548);
INSERT INTO highlights VALUES('3300101680_19_3290-3479','3300101680',19,'第10章 怎么就丧失了笑的能力','我发现“对话”和“自由发挥”是需要前提的，而这个前提现在几乎不存在。女工既不是白纸，也很难用简单的“缺乏经验”或“受教育程度不高”来概括。从我的角度看，她们是被高度“污染”和“规训”的。这些“污染”包括：中学时代被灌输的“中心思想+三段式写作法”；对抒情和口号的推崇；对一些所谓“经典文学”权威的崇拜，对所谓“美文”和“成功学”的迷信；对遣词造句、修辞手法、衔接过渡之类的追随；','3290-3479',1,1742995031,1782398548);
INSERT INTO highlights VALUES('3300101680_19_2909-2968','3300101680',19,'第10章 怎么就丧失了笑的能力','而我们的情绪底色对孩子的影响远超我们自以为拥有的教育理念和教养知识，这底色也是我们构建自己教育理念中最强大的影响因素。','2909-2968',1,1742994763,1782398548);
INSERT INTO highlights VALUES('3300101680_19_2728-2754','3300101680',19,'第10章 怎么就丧失了笑的能力','成年人自己的内心状态对孩子的影响”中的“内心状态”。','2728-2754',1,1742994726,1782398548);
INSERT INTO highlights VALUES('3300101680_19_1596-1676','3300101680',19,'第10章 怎么就丧失了笑的能力','孩子的降临带给我们的种种困难和挑战，都是难得的锻炼机会。因为它们能够让我们看到那些自身深藏的、未曾觉察的关于“我”的内在模式，那些平日里不为人知的“隐形图案”。','1596-1676',1,1742994594,1782398548);
INSERT INTO highlights VALUES('3300101680_19_1434-1479','3300101680',19,'第10章 怎么就丧失了笑的能力','并非清水使你变成了某种模样，而是你本就有这些印记，只是有清水之后，这些图案才得以显现而已。','1434-1479',1,1742994491,1782398548);
INSERT INTO highlights VALUES('3300101680_19_869-908','3300101680',19,'第10章 怎么就丧失了笑的能力','显然不是，只是这些生活的际遇，刚好让我们本就有的“自我”有机会凸显和浮现罢了。','869-908',1,1742993973,1782398548);
INSERT INTO highlights VALUES('3300101680_17_12542-12580','3300101680',17,'第9章 那些棘手的问题（儿童版）','不限制孩子的观看时间：“你每天只能看10分钟。”因为限制时间会让他们更想玩。','12542-12580',1,1742993503,1782398548);
INSERT INTO highlights VALUES('3300101680_17_7997-8018','3300101680',17,'第9章 那些棘手的问题（儿童版）','让每个孩子都感觉自己是特殊的、独一无二的。','7997-8018',1,1742992952,1782398548);
INSERT INTO highlights VALUES('3300101680_17_7004-7063','3300101680',17,'第9章 那些棘手的问题（儿童版）','第三，也是最重要的，就是不要上纲上线， 用成人的道德标准要求孩子。','7004-7063',1,1742992873,1782398548);
INSERT INTO highlights VALUES('3300101680_17_6155-6181','3300101680',17,'第9章 那些棘手的问题（儿童版）','第二，随着孩子能力的提升，尽量支持孩子自己解决问题。','6155-6181',1,1742992868,1782398548);
INSERT INTO highlights VALUES('3300101680_17_5899-6008','3300101680',17,'第9章 那些棘手的问题（儿童版）','3.最重要的是，哪怕最后的结果并不完全符合我们推演的样子，也能使孩子原本不敢面对的情景被“扒开”，清晰地展现在他们眼前，不再是模糊不清的一团恐惧。这样的体验对于支持孩子在面对困境时获得勇气并找寻解决方法是非常有帮助的。','5899-6008',1,1742914630,1782398548);
INSERT INTO highlights VALUES('3300101680_17_4645-4670','3300101680',17,'第9章 那些棘手的问题（儿童版）','第一，不要马上进入“当裁判”模式，先让孩子充分表达','4645-4670',1,1742914496,1782398548);
INSERT INTO highlights VALUES('3300101680_17_3140-3181','3300101680',17,'第9章 那些棘手的问题（儿童版）','最重要的是，区分哪些因素是我们无法控制的，哪些是需要我们自己负责并可以做出调整的。','3140-3181',1,1742914307,1782398548);
INSERT INTO highlights VALUES('3300101680_17_3118-3140','3300101680',17,'第9章 那些棘手的问题（儿童版）','第三步，和孩子一起探索产生“坏情绪”的根源。','3118-3140',1,1742914296,1782398548);
INSERT INTO highlights VALUES('3300101680_17_3019-3046','3300101680',17,'第9章 那些棘手的问题（儿童版）','第二步，引导孩子描述和表达自己在其中体验到的感受和情绪','3019-3046',1,1742914277,1782398548);
INSERT INTO highlights VALUES('3300101680_17_2938-2957','3300101680',17,'第9章 那些棘手的问题（儿童版）','第一步，尽可能客观地描述所发生的事情。','2938-2957',1,1742914267,1782398548);
INSERT INTO highlights VALUES('3300101680_17_1109-1123','3300101680',17,'第9章 那些棘手的问题（儿童版）','关系决定状态，状态决定效能，','1109-1123',1,1742914148,1782398548);
INSERT INTO highlights VALUES('3300101680_17_868-902','3300101680',17,'第9章 那些棘手的问题（儿童版）','真正的高质量陪伴，意味着孩子在和你互动的过程中，处于一种愉悦的状态。','868-902',1,1742914116,1782398548);
INSERT INTO highlights VALUES('3300101680_16_16168-16252','3300101680',16,'第8章 那些棘手的问题（成年人版）','年轻时要改变世界的梦想，虽然从未放弃，但总在夜深人静的时候，觉得自己是拿着长枪刺向风车的堂吉诃德，可笑而无望。','16168-16252',1,1742826966,1782398548);
INSERT INTO highlights VALUES('3300101680_16_13179-13215','3300101680',16,'第8章 那些棘手的问题（成年人版）','别把重心放在成年人之间的争论上，试着用和孩子的互动模式来“教育”成年人。','13179-13215',1,1742826762,1782398548);
INSERT INTO highlights VALUES('3300101680_16_12693-12760','3300101680',16,'第8章 那些棘手的问题（成年人版）','如果对方和我们的意见不一致怎么办？用我们与孩子的沟通方式来处理：从接纳开始。','12693-12760',1,1742826687,1782398548);
INSERT INTO highlights VALUES('3300101680_16_12789-12909','3300101680',16,'第8章 那些棘手的问题（成年人版）','接纳，不是说我一定认为你是对的，而是我接纳这是你现在的状态。希望被接纳是每一个人的本能。一旦被接纳了，反而可能比较容易改变。','12789-12909',1,1742826679,1782398548);
INSERT INTO highlights VALUES('3300101680_16_9781-9807','3300101680',16,'第8章 那些棘手的问题（成年人版）','自我修复意味着将你的身份、你的行为、你所做的事情分开','9781-9807',1,1742826460,1782398548);
INSERT INTO highlights VALUES('3300101680_16_9995-10096','3300101680',16,'第8章 那些棘手的问题（成年人版）','宝贝，我一直在想那天晚上我对你发火的事情。对不起，我大吼大叫了，我相信你当时肯定很害怕。这不是你的错。下一次妈妈会学着更好地处理自己的情绪。','9995-10096',1,1742826413,1782398548);
INSERT INTO highlights VALUES('3300101680_16_9044-9069','3300101680',16,'第8章 那些棘手的问题（成年人版）','这其实是“关闭沟通”，而好的修复是打开和重构沟通。','9044-9069',1,1742826070,1782398548);
INSERT INTO highlights VALUES('3300101680_16_7612-7695','3300101680',16,'第8章 那些棘手的问题（成年人版）','人改变不了别人，能改变的只有自己。深呼吸，拥抱一下自己，','7612-7695',1,1742825934,1782398548);
INSERT INTO highlights VALUES('3300101680_16_7021-7109','3300101680',16,'第8章 那些棘手的问题（成年人版）','孩子是听得懂的。还有一点很重要，告诉孩子，“这和你没关系”。','7021-7109',1,1742825861,1782398548);
INSERT INTO highlights VALUES('3300101680_16_6956-6992','3300101680',16,'第8章 那些棘手的问题（成年人版）','尝试和孩子建立一种互动：状态不好的时候，告诉孩子，“妈妈现在心情不好”。','6956-6992',1,1742825856,1782398548);
INSERT INTO highlights VALUES('3300101680_16_6853-6869','3300101680',16,'第8章 那些棘手的问题（成年人版）','第一步，意识到自己现在状态不好。','6853-6869',1,1742825849,1782398548);
INSERT INTO highlights VALUES('3300101680_16_6601-6615','3300101680',16,'第8章 那些棘手的问题（成年人版）','心里有能量，我们才可能笑啊！','6601-6615',1,1742825845,1782398548);
INSERT INTO highlights VALUES('3300101680_16_5016-5061','3300101680',16,'第8章 那些棘手的问题（成年人版）','那些每天不得不做的事情，只要你改变一下心态，和孩子一块做，就可以变成高质量的亲子互动时间。','5016-5061',1,1742825617,1782398548);
INSERT INTO highlights VALUES('3300101680_16_4844-4862','3300101680',16,'第8章 那些棘手的问题（成年人版）','从小的空间里，为自己寻找喘息的窗口。','4844-4862',1,1742825599,1782398548);
INSERT INTO highlights VALUES('3300101680_16_4680-4702','3300101680',16,'第8章 那些棘手的问题（成年人版）','时常给自己定一个小目标：保持3分钟的好心情。','4680-4702',1,1742825594,1782398548);
INSERT INTO highlights VALUES('3300101680_16_2885-2928','3300101680',16,'第8章 那些棘手的问题（成年人版）','真实的生活里，不存在完美的伴侣、完美的婚姻、完美的孩子。生活有的就是，不断出现的问题。','2885-2928',1,1742815295,1782398548);
INSERT INTO highlights VALUES('3300101680_16_2835-2849','3300101680',16,'第8章 那些棘手的问题（成年人版）','生活并没有什么“终极”出路。','2835-2849',1,1742777783,1782398548);
INSERT INTO highlights VALUES('3300101680_16_1840-1861','3300101680',16,'第8章 那些棘手的问题（成年人版）','第二，不要用宏观叙事去描述自己的生活状态。','1840-1861',1,1742777728,1782398548);
INSERT INTO highlights VALUES('3300101680_16_2037-2063','3300101680',16,'第8章 那些棘手的问题（成年人版）','每个结论都有两个共同点：一是令人沮丧，二是难以改变。','2037-2063',1,1742777722,1782398548);
INSERT INTO highlights VALUES('3300101680_16_1737-1792','3300101680',16,'第8章 那些棘手的问题（成年人版）','要多和孩子“无意义地待在一起”，讲的就是这种“无为之为”。','1737-1792',1,1742777691,1782398548);
INSERT INTO highlights VALUES('3300101680_16_1484-1545','3300101680',16,'第8章 那些棘手的问题（成年人版）','不要觉得养育孩子，一定要不断地去“做”，事实上很多时候是“不做”。要意识到，“不做”，有时候也是一种“做”。','1484-1545',1,1742777663,1782398548);
INSERT INTO highlights VALUES('3300101680_15_13564-13682','3300101680',15,'第7章 生气，不是你的错','所以看上去的困难，何尝不是生活的馈赠，从新冠疫情到妈妈受伤，这样的“困境”都促使我们去重新思考和组织自己的生活。你不可能什么都有，什么都要，这些“挑战”让我们退一步，看见到底什么对我们是真正重要的。','13564-13682',1,1742714334,1782398548);
INSERT INTO highlights VALUES('3300101680_15_13180-13238','3300101680',15,'第7章 生气，不是你的错','没有什么是偶然的(There are no accidents)”。生活中的所有，都不是偶然。一切的发生，都有缘由。','13180-13238',1,1742714247,1782398548);
INSERT INTO highlights VALUES('3300101680_15_12101-12177','3300101680',15,'第7章 生气，不是你的错','为了让孩子健康，我们每天都会精心给孩子做营养早餐。同样地，孩子的心灵也需要“营养早餐”，那就是充足的爱、接纳和认可。精神层面的早餐滋养，是灵性养育的关键','12101-12177',1,1742714102,1782398548);
INSERT INTO highlights VALUES('3300101680_15_11931-12027','3300101680',15,'第7章 生气，不是你的错','学习，最底层的能力是专注。专注力来自哪里？如何能拥有长久的专注？需要先有平和。如何才能变得平和？平和的根本是知道自己可以被无条件接纳。无条件接纳来自无条件的爱，就是前面的第二条。','11931-12027',1,1742714086,1782398548);
INSERT INTO highlights VALUES('3300101680_15_11590-11628','3300101680',15,'第7章 生气，不是你的错','养育这个“平行宇宙”看似纷繁复杂，一旦有了觉知，你就会明白，其核心只有两条：','11590-11628',1,1742713971,1782398548);
INSERT INTO highlights VALUES('3300101680_15_11657-11710','3300101680',15,'第7章 生气，不是你的错','1.健康的身体。2.家庭成员之间亲密幸福的关系。','11657-11710',1,1742713964,1782398548);
INSERT INTO highlights VALUES('3300101680_15_10695-10721','3300101680',15,'第7章 生气，不是你的错','我经常和孩子们说，妈妈永远是爱你们的，生气的时候也是','10695-10721',1,1742713838,1782398548);
INSERT INTO highlights VALUES('3300101680_15_10329-10388','3300101680',15,'第7章 生气，不是你的错','其实，我们对外在世界的假设都是自己内心的投射，所以要实现这种转变，核心是接纳自己','10329-10388',1,1742713792,1782398548);
INSERT INTO highlights VALUES('3300101680_15_10195-10300','3300101680',15,'第7章 生气，不是你的错','我们的底层信念只需要做一个转变：这个世界不是只有淘汰，还可以是成全。世界是多样的，每一个孩子，每一个人，都会因为他是他，而在这个世界拥有独一无二的价值。这时，你对未来的假设，就会从冰冷的残酷竞争变成温暖的花园。','10195-10300',1,1742713741,1782398548);
INSERT INTO highlights VALUES('3300101680_15_9465-9554','3300101680',15,'第7章 生气，不是你的错','我们生气，其实从来都和孩子无关，是我们自己内心的怪兽在作怪罢了。孩子正常的作为，莫名激起了我们内心的某个怪兽，于是我们做起了编剧，剧情尤其复杂，孩子莫名其妙变成了我们情绪的垃圾桶','9465-9554',1,1742713634,1782398548);
INSERT INTO highlights VALUES('3300101680_15_8274-8279','3300101680',15,'第7章 生气，不是你的错','知道真相，','8274-8279',1,1742713457,1782398548);
INSERT INTO highlights VALUES('3300101680_15_8298-8325','3300101680',15,'第7章 生气，不是你的错','自救的办法，我称它为“反向脑补”，补回真实完整的样子。','8298-8325',1,1742713452,1782398548);
INSERT INTO highlights VALUES('3300101680_14_536-775','3300101680',14,'第三部分 那些让我们笑不出来的难题','孩子是独立的灵性个体，没有义务为我们的恐惧和焦虑负责；“我”要为自己的恐惧和焦虑负责。如何负责？不是靠超出常人的勇气，而是看到，那些让我们恐惧和焦虑的东西，是经由我们的仰望才被赋予了力量。','536-775',1,1742710797,1782398548);
INSERT INTO highlights VALUES('3300101680_13_27907-27940','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','《AI时代的教育：当教育不再以就业为导向，孩子们未来应该学什么？》','27907-27940',1,1742700174,1782398548);
INSERT INTO highlights VALUES('3300101680_13_26432-26513','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','重新学习一项技能，需要有一定的积蓄，更需要时间。所以对有一定经济基础并对自己的时间有控制权的人来说更容易；当然，在这之外，还需要有学习的意愿，这也不是人人都有的。','26432-26513',1,1742699791,1782398548);
INSERT INTO highlights VALUES('3300101680_13_25762-25803','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','晨会的时候让孩子们自己定目标，并把目标可视化','25762-25803',1,1742699661,1782398548);
INSERT INTO highlights VALUES('3300101680_13_25177-25203','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','儿童教育体系中的问题，其实反映的都是成年人社会的问题','25177-25203',1,1742699597,1782398548);
INSERT INTO highlights VALUES('3300101680_13_23696-23748','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','核心技能”只有3个：共情能力、持续学习的能力和创造力','23696-23748',1,1742699435,1782398548);
INSERT INTO highlights VALUES('3300101680_13_23336-23354','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','观点2 什么是未来需要的“核心技能”','23336-23354',1,1742699393,1782398548);
INSERT INTO highlights VALUES('3300101680_13_21791-21808','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','观点1 是不是学得越多，赚钱就越多','21791-21808',1,1742699344,1782398548);
INSERT INTO highlights VALUES('3300101680_13_21109-21129','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','想当老大？做到先人后己，才有可能当老大。','21109-21129',1,1742696854,1782398548);
INSERT INTO highlights VALUES('3300101680_13_21047-21078','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','什么是自己的？自己学会了的东西、理解了的东西，才真正是自己的。','21047-21078',1,1742696837,1782398548);
INSERT INTO highlights VALUES('3300101680_13_20978-21016','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','在公共场所，或者在别人家做客，你去的时候是什么样，走的时候就要恢复成什么样。','20978-21016',1,1742696819,1782398548);
INSERT INTO highlights VALUES('3300101680_13_20921-20947','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','2.如果你不希望别人这样对待你，就不要这样对待别人。','20921-20947',1,1742696810,1782398548);
INSERT INTO highlights VALUES('3300101680_13_20836-20854','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','什么是长大了？能照顾自己就是长大了。','20836-20854',1,1742696771,1782398548);
INSERT INTO highlights VALUES('3300101680_13_19766-19801','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','面对自我的能力来自认知、自我接纳以及在这个基础上发展而来的自信与自尊。','19766-19801',1,1742696723,1782398548);
INSERT INTO highlights VALUES('3300101680_13_19465-19488','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','让孩子树立这种价值观、培养这种心态是很重要的。','19465-19488',1,1742696624,1782398548);
INSERT INTO highlights VALUES('3300101680_13_19517-19571','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','一方面，个体要独立；另一方面，家庭成员要互相支持。','19517-19571',1,1742696619,1782398548);
INSERT INTO highlights VALUES('3300101680_13_19269-19287','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第三，提早说清楚，我的钱与你没关系。','19269-19287',1,1742696578,1782398548);
INSERT INTO highlights VALUES('3300101680_13_18426-18512','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','安迪10岁左右的时候，我给了他一个月的时间，让他收集和整理我们家的所有开销，方法就是，我把所有开销的账单收据都给他留着，然后他用了一张大纸，把收据按类别分好，然后加总计算。','18426-18512',1,1742696564,1782398548);
INSERT INTO highlights VALUES('3300101680_13_18110-18158','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我和孩子讲，金钱是一种流动的东西，可以来也可以走。我们要知道它是怎么来的，也要知道它是怎么走的。','18110-18158',1,1742696475,1782398548);
INSERT INTO highlights VALUES('3300101680_13_18092-18102','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第二，教孩子理解金钱','18092-18102',1,1742696457,1782398548);
INSERT INTO highlights VALUES('3300101680_13_17731-17793','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','可以从小处去感受生活的美好的。而这种美好的体验在孩子心中种下的种子，是他以后面对自己的人生和未来可能遇到的困境时无尽的动力。','17731-17793',1,1742696391,1782398548);
INSERT INTO highlights VALUES('3300101680_13_16979-17034','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','因为“穷”对孩子而言，并不是一个金融概念，而是一种不配得到感，就是“我不能用好的东西，我不配”。','16979-17034',1,1742696308,1782398548);
INSERT INTO highlights VALUES('3300101680_13_9649-9721','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我们可以借助工具。比如用颜色来表达：高兴可以是绿色的，生气可以是红色的；处于绿色情绪时可以全力以赴去做一件事，处于红色情绪时可以安静地休息片刻；','9649-9721',1,1742694303,1782398548);
INSERT INTO highlights VALUES('3300101680_13_16736-16743','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第一，不哭穷。','16736-16743',1,1742694083,1782398548);
INSERT INTO highlights VALUES('3300101680_13_16415-16511','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','原则1：经常给孩子机会跟你谈判，你扮演一个相对难缠的角色。原则2：合理刁难之后让他赢。让他有赢的体验，有足够好的角度去重新看这个问题。','16415-16511',1,1742694059,1782398548);
INSERT INTO highlights VALUES('3300101680_13_15824-15909','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','但有一个很重要的原则：“为难”之后，尽量让孩子有一个“赢”的体验，不是孩子说什么都可以，而是在谈判中，如果他提出了有意思的观点或者他思考的角度很有意思，你要看到并鼓励他。','15824-15909',1,1742693969,1782398548);
INSERT INTO highlights VALUES('3300101680_13_15008-15094','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','谈判是人和人之间交互的一个很重要的方式，我们都是通过这个过程，去意识到新的可能性在哪里。所以，提升谈判能力不仅是表层的“术”的练习，而且是一个非常重要的深层的“道”的锻炼。','15008-15094',1,1742693913,1782398548);
INSERT INTO highlights VALUES('3300101680_13_14877-14896','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','正是这些真实的体验和经历，让孩子成长。','14877-14896',1,1742693813,1782398548);
INSERT INTO highlights VALUES('3300101680_13_13762-13763','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','作','13762-13763',1,1742693607,1782398548);
INSERT INTO highlights VALUES('3300101680_13_13763-13838','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','为一个给我做咨询的人，需要跟我说清楚，让我知道哪些东西是必须去做一些妥协的。这在谈判里是非常重要的，也就是谁的问题谁负责。你觉得我应该在哪些方面妥协？','13763-13838',1,1742693601,1782398548);
INSERT INTO highlights VALUES('3300101680_13_13649-13688','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','这个谈判的重要转变，就是安迪可以把我扔给他的问题的一部分，抛回来让我自己负责。','13649-13688',1,1742693572,1782398548);
INSERT INTO highlights VALUES('3300101680_13_12478-12488','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','谈判三，客户要妥协。','12478-12488',1,1742693413,1782398548);
INSERT INTO highlights VALUES('3300101680_13_12327-12351','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我觉得特别逗，成年人在小孩子眼里原来果真是蠢笨的','12327-12351',1,1742693363,1782398548);
INSERT INTO highlights VALUES('3300101680_13_11607-11615','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','谈判二，谁打电话','11607-11615',1,1742693266,1782398548);
INSERT INTO highlights VALUES('3300101680_13_11360-11367','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','谈判一，收费。','11360-11367',1,1742693261,1782398548);
INSERT INTO highlights VALUES('3300101680_13_11176-11258','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我没空研究，就委托他做调查，看看什么样的电动汽车我们可以买，他很乐意。这个项目很快就启动了，从2022年7月到11月，直到我生日那天买了车，整个过程历时4个月之久。','11176-11258',1,1742693249,1782398548);
INSERT INTO highlights VALUES('3300101680_13_11039-11118','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','其实，孩子给出的具体的原因和理由并没有那么重要，重要的是通过这个过程让孩子学会从对方的视角看待和思考问题，这是非常重要的底层能力！学校里，社会上，处处都需要。','11039-11118',1,1742693127,1782398548);
INSERT INTO highlights VALUES('3300101680_13_10757-10803','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','孩子想要什么，不要马上说可以或者不可以，而是要把这作为一次机会，来让孩子锻炼说服他人的能力。','10757-10803',1,1742693092,1782398548);
INSERT INTO highlights VALUES('3300101680_13_10832-10915','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','如果孩子想要一个玩具，你就说：“那你来说服一下妈妈吧，说说为什么要给你买。”他们一开始会说“因为我想玩”。你可以说：“你想玩跟我有什么关系，这对我来说就是要多花钱。”','10832-10915',1,1742693084,1782398548);
INSERT INTO highlights VALUES('3300101680_13_10289-10295','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','角色扮演练习','10289-10295',1,1742693047,1782398548);
INSERT INTO highlights VALUES('3300101680_13_10188-10216','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第四，提出建议：我们真实的感受和需求是什么，可以怎么做。','10188-10216',1,1742693014,1782398548);
INSERT INTO highlights VALUES('3300101680_13_10028-10068','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第三，表达自己的感受和需求时，使用“我”开头的语句，而不是使用“你”开头的语句。','10028-10068',1,1742693002,1782398548);
INSERT INTO highlights VALUES('3300101680_13_9838-9876','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第二，倾听他人的能力，学会倾听他人的感受和需求，尊重他们的观点和底层的情感。','9838-9876',1,1742692984,1782398548);
INSERT INTO highlights VALUES('3300101680_13_9544-9579','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第一，非暴力沟通的起点，其实是自我意识，即从了解自己的情感和需求开始。','9544-9579',1,1742692960,1782398548);
INSERT INTO highlights VALUES('3300101680_13_9122-9128','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','深度学习能力','9122-9128',1,1742692627,1782398548);
INSERT INTO highlights VALUES('3300101680_13_8695-8714','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','学东西分三步：看一遍、做一遍、教一遍。','8695-8714',1,1742692487,1782398548);
INSERT INTO highlights VALUES('3300101680_13_8279-8315','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我每周至少有一天，每天至少有一小时是不做任何“安排”的。孩子可以自己玩。','8279-8315',1,1742692443,1782398548);
INSERT INTO highlights VALUES('3300101680_13_6637-6659','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第三，寻求帮助的能力，这也是我们容易忽视的。','6637-6659',1,1742692196,1782398548);
INSERT INTO highlights VALUES('3300101680_13_6373-6389','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第二，整理、安排自己生活的能力。','6373-6389',1,1742692051,1782398548);
INSERT INTO highlights VALUES('3300101680_13_6132-6156','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','我和孩子们总结了快速适应未知环境的三个核心能力。','6132-6156',1,1742692007,1782398548);
INSERT INTO highlights VALUES('3300101680_13_6204-6213','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第一，做饭的能力。','6204-6213',1,1742692002,1782398548);
INSERT INTO highlights VALUES('3300101680_13_5231-5238','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第三，管理时间','5231-5238',1,1742691950,1782398548);
INSERT INTO highlights VALUES('3300101680_13_5054-5061','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第二，记录时间','5054-5061',1,1742691945,1782398548);
INSERT INTO highlights VALUES('3300101680_13_4713-4721','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第一，感知时间。','4713-4721',1,1742691940,1782398548);
INSERT INTO highlights VALUES('3300101680_13_4867-4958','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','可以从6岁左右开始，让孩子有意识地猜测时间。比如告诉孩子一部电影是一个半小时，一集动画片是20分钟，刚才做手工差不多用了一个小时，等等，通过把时间说出来，让孩子开始有意识地感知时间。','4867-4958',1,1742691662,1782398548);
INSERT INTO highlights VALUES('3300101680_13_4455-4465','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','“可视化”的教育过程','4455-4465',1,1742691625,1782398548);
INSERT INTO highlights VALUES('3300101680_13_4244-4258','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','2.有机会讨论什么是“公平”','4244-4258',1,1742691619,1782398548);
INSERT INTO highlights VALUES('3300101680_13_3765-3782','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','让所有看不见的家务活都“看得见”。','3765-3782',1,1742691612,1782398548);
INSERT INTO highlights VALUES('3300101680_13_3339-3374','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','做家务排班表，把所有需要做的事情都列出来，大家一起参与讨论，然后排班。','3339-3374',1,1742691496,1782398548);
INSERT INTO highlights VALUES('3300101680_13_3087-3121','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','做家务这个事情，你做了一天啥也看不出来，但是你一天不做就看出来了。”','3087-3121',1,1742691477,1782398548);
INSERT INTO highlights VALUES('3300101680_13_1295-1518','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','整理生活的能力面对未知的能力深度学习的能力非暴力沟通能力说服别人的能力认知金钱的能力面对自我的能力','1295-1518',1,1742691353,1782398548);
INSERT INTO highlights VALUES('3300101680_13_945-950','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','什么是成功','945-950',1,1742691293,1782398548);
INSERT INTO highlights VALUES('3300101680_13_991-1114','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','第一是Smarts，就是学习能力；第二是Purpose，就是人生方向和使命感；第三是Agency，就是对自己人生的掌控感和自主性。','991-1114',1,1742691284,1782398548);
INSERT INTO highlights VALUES('3300101680_13_753-766','3300101680',13,'第6章 养好孩子，给他7个“充分”能力','《高成就孩子的养育法则》(','753-766',1,1742691088,1782398548);
INSERT INTO highlights VALUES('3300101680_12_20033-20085','3300101680',12,'第5章 破除“扫兴父母”的魔咒','成长是长期且反复的过程，必须明白且接受这一点，这样面对孩子们的“退步”，我们才不那么容易沮丧，继而放弃。','20033-20085',1,1742655313,1782398548);
INSERT INTO highlights VALUES('3300101680_12_18433-18486','3300101680',12,'第5章 破除“扫兴父母”的魔咒','我们的角色是支持孩子们去做他们觉得有趣的事，而不是让他们跟着我们的价值判断，做我们眼中“性价比最优”的事。','18433-18486',1,1742655117,1782398548);
INSERT INTO highlights VALUES('3300101680_12_18184-18214','3300101680',12,'第5章 破除“扫兴父母”的魔咒','在情绪还没被疏导的情况下，孩子是不可能调动理性去解决问题的。','18184-18214',1,1742655071,1782398548);
INSERT INTO highlights VALUES('3300101680_12_13619-13691','3300101680',12,'第5章 破除“扫兴父母”的魔咒','而要跟孩子们玩、进入孩子们的世界，就要以他们的方式玩耍。他们喜欢趴在地上玩，若我们非要他们端端正正地都坐在桌椅前来玩，那大半玩兴早就被扫掉了吧。','13619-13691',1,1742650899,1782398548);
INSERT INTO highlights VALUES('3300101680_12_9473-9533','3300101680',12,'第5章 破除“扫兴父母”的魔咒','当你和孩子的关系受到了伤害，沟通的空间变得狭小的时候，任何看上去正确的教育方法都失去了在孩子身上由内而外起作用的可能性。','9473-9533',1,1742650313,1782398548);
INSERT INTO highlights VALUES('3300101680_12_9102-9132','3300101680',12,'第5章 破除“扫兴父母”的魔咒','做到以上4点——不提要求、不讲道理、站在同一边、巧用游戏力，','9102-9132',1,1742650281,1782398548);
INSERT INTO highlights VALUES('3300101680_12_6836-6853','3300101680',12,'第5章 破除“扫兴父母”的魔咒','边界感是通过触碰边界才建立起来的。','6836-6853',1,1742650009,1782398548);
INSERT INTO highlights VALUES('3300101680_12_6611-6710','3300101680',12,'第5章 破除“扫兴父母”的魔咒','但真正理解和遵守规则，是从允许孩子打破规则开始的。','6611-6710',1,1742649991,1782398548);
INSERT INTO highlights VALUES('3300101680_12_5908-5974','3300101680',12,'第5章 破除“扫兴父母”的魔咒','比如想让孩子好好吃蔬菜，与其给孩子做一个营养讲座，不如让毛绒玩具扮演不爱吃蔬菜的小朋友，你和孩子一起给它讲讲，为什么吃蔬菜对身体好。','5908-5974',1,1742649950,1782398548);
INSERT INTO highlights VALUES('3300101680_12_5619-5634','3300101680',12,'第5章 破除“扫兴父母”的魔咒','他们会因为不知道怎么回应而沉默','5619-5634',1,1742649908,1782398548);
INSERT INTO highlights VALUES('3300101680_12_4721-4742','3300101680',12,'第5章 破除“扫兴父母”的魔咒','孩子不是问题，孩子需要你的帮助去解决问题。','4721-4742',1,1742649826,1782398548);
INSERT INTO highlights VALUES('3300101680_12_4468-4510','3300101680',12,'第5章 破除“扫兴父母”的魔咒','一土学校给出的反馈原则是：具体、友好、有帮助。','4468-4510',1,1742649770,1782398548);
INSERT INTO highlights VALUES('3300101680_12_4179-4194','3300101680',12,'第5章 破除“扫兴父母”的魔咒','不管说什么，先入耳，才能入心。','4179-4194',1,1742649734,1782398548);
INSERT INTO highlights VALUES('3300101680_12_4110-4142','3300101680',12,'第5章 破除“扫兴父母”的魔咒','如果是让孩子改变行为，那么一个必需的前提就是，孩子愿意听你说话。','4110-4142',1,1742649727,1782398548);
INSERT INTO highlights VALUES('3300101680_12_2601-2666','3300101680',12,'第5章 破除“扫兴父母”的魔咒','就是自己要成为有力量的人，而不是依靠孩子的“成就”“出息”来给自己力量。','2601-2666',1,1742649648,1782398548);
INSERT INTO highlights VALUES('3300101680_12_2269-2321','3300101680',12,'第5章 破除“扫兴父母”的魔咒','从而获得对自己的信心，和克服困难的勇气与力量。','2269-2321',1,1742649568,1782398548);
INSERT INTO highlights VALUES('3300101680_12_2223-2240','3300101680',12,'第5章 破除“扫兴父母”的魔咒','感到温暖，感到被支持，感到被接纳，','2223-2240',1,1742649560,1782398548);
INSERT INTO highlights VALUES('3300101680_12_2105-2194','3300101680',12,'第5章 破除“扫兴父母”的魔咒','父母对孩子最大的意义是：当孩子想起父母的时候，内心会充满力量，','2105-2194',1,1742649546,1782398548);
INSERT INTO highlights VALUES('3300101680_12_1289-1631','3300101680',12,'第5章 破除“扫兴父母”的魔咒','这里先给父母几个日常提醒：1.你的首要任务是为孩子创造愉悦的环境；2.好的家庭，每天都应该有笑容和笑声；3.你现在做的一切，都会成为孩子长大以后记忆的一部分；4.在成长经历中，你最喜欢的成年人是什么样子的？有没有一个人，总是对你“无条件接纳”？如果有，向他（她）学习；如果没有，就自己学会；5.每次在和孩子说话或者做决定之前，先问问自己：我这样说或这样做，孩子会有什么样的感受？然后再开始行动。','1289-1631',1,1742649522,1782398548);
INSERT INTO highlights VALUES('3300101680_12_966-1114','3300101680',12,'第5章 破除“扫兴父母”的魔咒','心底的爱到外化的行为的过程，中间要经过一个“大染缸”，其中盛满了对生活的担忧：害怕不够好，害怕不够强，害怕生活得不如意……','966-1114',1,1742649378,1782398548);
INSERT INTO highlights VALUES('3300101680_11_23409-23441','3300101680',11,'第4章 改下脑回路','没有哪一个人是静态的。每时每刻，我们都可以反思和自省，继而进步。','23409-23441',1,1742649286,1782398548);
INSERT INTO highlights VALUES('3300101680_11_20925-21008','3300101680',11,'第4章 改下脑回路','人生到最后，追求的是什么呢？最高的“成就”不是钱和物本身，而是幸福生活的能力，是吧？幸福的最高境界是什么？无非是开悟，是吧？开悟，就是时时刻刻活在当下，拥有无尽欢喜。','20925-21008',1,1742648958,1782398548);
INSERT INTO highlights VALUES('3300101680_11_20088-20120','3300101680',11,'第4章 改下脑回路','做父母的，能给孩子的最好的礼物之一，就是支持和扩大这个想象的世界','20088-20120',1,1742648863,1782398548);
INSERT INTO highlights VALUES('3300101680_11_18105-18119','3300101680',11,'第4章 改下脑回路','可以“发号施令”的“特权卡”','18105-18119',1,1742648600,1782398548);
INSERT INTO highlights VALUES('3300101680_11_12995-13017','3300101680',11,'第4章 改下脑回路','最后一点，也是很重要的一点：做不到也没关系。','12995-13017',1,1742648164,1782398548);
INSERT INTO highlights VALUES('3300101680_11_12671-12790','3300101680',11,'第4章 改下脑回路','第一点，察觉孩子有情绪的时候，允许自己做一个呼吸，提醒自己，先不着急逃跑。第二点，给自己一个短暂的停顿，做一个呼吸，几秒钟就够。','12671-12790',1,1742648160,1782398548);
INSERT INTO highlights VALUES('3300101680_11_11722-11752','3300101680',11,'第4章 改下脑回路','ZZ最重要的作用，就是给孩子的负面情绪一个夸张又合理的出口。','11722-11752',1,1742648038,1782398548);
INSERT INTO highlights VALUES('3300101680_11_9244-9336','3300101680',11,'第4章 改下脑回路','真相是，越想更快地解决和逃离，越逃不了，而且这种状态会持续地产生新的问题。','9244-9336',1,1742647811,1782398548);
INSERT INTO highlights VALUES('3300101680_11_8056-8241','3300101680',11,'第4章 改下脑回路','但每一个生命，都有3件宝贝：觉察觉知，爱与慈悲，智慧。','8056-8241',1,1742647305,1782398548);
INSERT INTO highlights VALUES('3300101680_11_7387-7437','3300101680',11,'第4章 改下脑回路','而“正路”是：有觉察，到当下，让我们看到生活中的馈赠和充盈感。','7387-7437',1,1742647193,1782398548);
INSERT INTO highlights VALUES('3300101680_11_6927-7077','3300101680',11,'第4章 改下脑回路','用自己制造出来的“权威”来“管理”自己，用自己想象出来的“未来”来“吓唬”自己。我们容易陷入这样的困境，是因为匮乏感。','6927-7077',1,1742647142,1782398548);
INSERT INTO highlights VALUES('3300101680_11_5159-5236','3300101680',11,'第4章 改下脑回路','而“抗挫”其实是与生俱来的能力。当我们尊重孩子的内心状态，那么他的这种能力就会很自然地展现出来。','5159-5236',1,1742646742,1782398548);
INSERT INTO highlights VALUES('3300101680_11_4930-5063','3300101680',11,'第4章 改下脑回路','尽量支持和延长孩子沉浸的状态，可以聊刚才玩的，继续沉浸在想象世界的游戏中，即回到第3章提到的“矛盾一”，和孩子一起在想象的世界里继续玩沙子、编故事。玩沙子、编故事是行为，其内核是我们尊重了孩子当下的内心状态。','4930-5063',1,1742646477,1782398548);
INSERT INTO highlights VALUES('3300101680_11_3852-3892','3300101680',11,'第4章 改下脑回路','时间有限且珍贵，有好的东西游走在孩子的生命里、生活里，有愉悦感、成就感、价值感，','3852-3892',1,1742646398,1782398548);
INSERT INTO highlights VALUES('3300101680_11_3499-3539','3300101680',11,'第4章 改下脑回路','允许发生；支持和鼓励。','3499-3539',1,1742646370,1782398548);
INSERT INTO highlights VALUES('3300101680_11_3452-3470','3300101680',11,'第4章 改下脑回路','允许孩子有大块的而不是碎片化的时间；','3452-3470',1,1742646366,1782398548);
INSERT INTO highlights VALUES('3300101680_11_2967-2988','3300101680',11,'第4章 改下脑回路','在时间安排上，一周至少有半天不要安排计划。','2967-2988',1,1742646330,1782398548);
INSERT INTO highlights VALUES('3300101680_11_2810-2845','3300101680',11,'第4章 改下脑回路','就是看到孩子沉浸于某件事中的时候，提醒自己，先不打扰，让他做，让他想。','2810-2845',1,1742646319,1782398548);
INSERT INTO highlights VALUES('3300101680_11_848-899','3300101680',11,'第4章 改下脑回路','因此，首先要对自己降低期待：都改好，不可能！','848-899',1,1742646298,1782398548);
INSERT INTO highlights VALUES('3300101680_11_635-776','3300101680',11,'第4章 改下脑回路','三个最重要，也是最难改的回路一是从“别处”到“当下”；二是从“匮乏”到“充盈”；三是从“逃离”到“入局”。','635-776',1,1742646285,1782398548);
INSERT INTO highlights VALUES('3300101680_11_1064-1076','3300101680',11,'第4章 改下脑回路','偶尔能想起，就很了不起！','1064-1076',1,1742646163,1782398548);
INSERT INTO highlights VALUES('3300101680_10_402-413','3300101680',10,'第二部分 专治笑不出来','笑的起点，是理解儿童。','402-413',1,1742646119,1782398548);
INSERT INTO highlights VALUES('3300101680_10_593-660','3300101680',10,'第二部分 专治笑不出来','当他们令人“生厌”的时候，并不是因为他们是“问题”，而是他们遇到了“问题”。','593-660',1,1742646110,1782398548);
INSERT INTO highlights VALUES('3300101680_9_16793-16927','3300101680',9,'第3章 理解儿童','教育充满了焦虑，其实并非偶然。当很多人内心的恐惧没有被面对和与之和解的时候，必然会有很多“产品”，利用这个焦虑，给你提供“解决问题”的方案。似乎只要买一个什么，孩子就可以“胜出”。其实当你学会了听焦虑和恐惧的语言，就能够一眼看出这些产品是在利用我们的“动物性”的真相。','16793-16927',1,1742044657,1782398548);
INSERT INTO highlights VALUES('3300101680_9_16720-16764','3300101680',9,'第3章 理解儿童','我喜欢的这些人，不管在什么领域，都是闪耀着人性之光的人，都是坚持诚信、敢于直面恐惧的人。','16720-16764',1,1742044582,1782398548);
INSERT INTO highlights VALUES('3300101680_9_16528-16612','3300101680',9,'第3章 理解儿童','他小时候，家里很穷，父亲问他：“给你两分钱，买什么可以把这个房间装满？”他挠头想不出答案。这时候父亲拿出一根火柴，一划，房间就亮了，虽然是微弱的光，但照亮了整个房间……','16528-16612',1,1742044472,1782398548);
INSERT INTO highlights VALUES('3300101680_9_14969-15054','3300101680',9,'第3章 理解儿童','当我们这样做后，就会看到我们对孩子的那些怒火，其实都是因为在那一刻我们被恐惧挟持而产生的机械一般的反应；就会知道，其实我们看上去很繁忙、很努力的时候，也无非是在“梦游”。','14969-15054',1,1742044303,1782398548);
INSERT INTO highlights VALUES('3300101680_9_14672-14699','3300101680',9,'第3章 理解儿童','动物性要索取和占有；人性则有无限的能力给予且不计回报。','14672-14699',1,1742044184,1782398548);
INSERT INTO highlights VALUES('3300101680_9_13956-13999','3300101680',9,'第3章 理解儿童','真正意义上的养育，需要我们面对人生最深的恐惧——对未来，对前途，对不确定，对求而不得。','13956-13999',1,1742044054,1782398548);
INSERT INTO highlights VALUES('3300101680_9_13558-13641','3300101680',9,'第3章 理解儿童','真正的6000天，往往是在“对孩子不满——语言暴力——后悔和自责——与孩子短暂亲密——对孩子不满”的循环中度过的。','13558-13641',1,1742044012,1782398548);
INSERT INTO highlights VALUES('3300101680_9_12337-12378','3300101680',9,'第3章 理解儿童','别人看不见，肉麻无底线！','12337-12378',1,1742043852,1782398548);
INSERT INTO highlights VALUES('3300101680_9_11925-11958','3300101680',9,'第3章 理解儿童','因为孩子都有“皮肤饥渴症”（其实成年人也是），所以有机会就抱抱吧！','11925-11958',1,1742043683,1782398548);
INSERT INTO highlights VALUES('3300101680_9_11826-11831','3300101680',9,'第3章 理解儿童','16个抱抱','11826-11831',1,1742043599,1782398548);
INSERT INTO highlights VALUES('3300101680_9_10895-10899','3300101680',9,'第3章 理解儿童','亲亲炮弹','10895-10899',1,1742043511,1782398548);
INSERT INTO highlights VALUES('3300101680_9_10644-10653','3300101680',9,'第3章 理解儿童','攻占堡垒+袜子大战','10644-10653',1,1742043478,1782398548);
INSERT INTO highlights VALUES('3300101680_9_9974-9979','3300101680',9,'第3章 理解儿童','“扔”出去','9974-9979',1,1742043454,1782398548);
INSERT INTO highlights VALUES('3300101680_9_8996-9001','3300101680',9,'第3章 理解儿童','数数脚趾头','8996-9001',1,1742043447,1782398548);
INSERT INTO highlights VALUES('3300101680_9_8703-8708','3300101680',9,'第3章 理解儿童','超大脚趾头','8703-8708',1,1742043443,1782398548);
INSERT INTO highlights VALUES('3300101680_9_8396-8401','3300101680',9,'第3章 理解儿童','闻“臭脚”','8396-8401',1,1742043440,1782398548);
INSERT INTO highlights VALUES('3300101680_9_8028-8032','3300101680',9,'第3章 理解儿童','刷卡游戏','8028-8032',1,1742043434,1782398548);
INSERT INTO highlights VALUES('3300101680_9_7503-7508','3300101680',9,'第3章 理解儿童','人体摇摇车','7503-7508',1,1742043429,1782398548);
INSERT INTO highlights VALUES('3300101680_9_6777-6893','3300101680',9,'第3章 理解儿童','生活在现代都市，被冰冷、坚硬的平面所包围，我们不用时刻关照自己的身体，也能生存下来。渐渐地，我们已经忘记了身体的存在。本来，在自然森林中，平坦的地面并不存在。这套装置的目的就是提醒我们记起已经遗忘了的身体，让我们对身体有更多的感知。','6777-6893',1,1742043045,1782398548);
INSERT INTO highlights VALUES('3300101680_9_6338-6364','3300101680',9,'第3章 理解儿童','只是因为他们还不具备通过视觉去理解和欣赏艺术的能力。','6338-6364',1,1742042958,1782398548);
INSERT INTO highlights VALUES('3300101680_9_2920-2942','3300101680',9,'第3章 理解儿童','第二点来了，玩可以培养孩子的幽默感和自信心！','2920-2942',1,1742042548,1782398548);
INSERT INTO highlights VALUES('3300101680_9_2360-2388','3300101680',9,'第3章 理解儿童','第一点，孩子们在想象的世界里玩耍，是一个高效学习的过程。','2360-2388',1,1742042472,1782398548);
INSERT INTO highlights VALUES('3300101680_9_1355-1455','3300101680',9,'第3章 理解儿童','孩子是生活在想象世界里的，但这不是矛盾产生的原因。矛盾的产生，是因为我们成年人很难“回到”想象的世界里。','1355-1455',1,1742042427,1782398548);
INSERT INTO highlights VALUES('3300101680_8_8584-8606','3300101680',8,'第2章 为什么笑不出来','所以第一条，就是不要用“佛”的标准要求自己！','8584-8606',1,1742042163,1782398548);
INSERT INTO highlights VALUES('3300101680_8_8784-8867','3300101680',8,'第2章 为什么笑不出来','起点是给自己种下一颗觉知的种子，并开始有意识地观察自己。','8784-8867',1,1742042159,1782398548);
INSERT INTO highlights VALUES('3300101680_8_3799-3876','3300101680',8,'第2章 为什么笑不出来','家庭教育也不是“行业”，而是每一天都无法预知的发生和体验，是我们真切、密实又常常不堪重负的生活。','3799-3876',1,1742041776,1782398548);
INSERT INTO highlights VALUES('3300101680_8_3671-3763','3300101680',8,'第2章 为什么笑不出来','人不是“问题”，不是“产品”，而是具有神秘性、复杂性、不可知性的灵性个体。','3671-3763',1,1742041766,1782398548);
INSERT INTO highlights VALUES('3300101680_7_3746-3948','3300101680',7,'第1章 会笑，是高阶能力','孩子就是这样的，你交给他们的事，只要带着尊重和信任，他们便会全身心地投入去做，毫无保留。','3746-3948',1,1741705976,1782398548);
INSERT INTO highlights VALUES('3300101680_7_3232-3292','3300101680',7,'第1章 会笑，是高阶能力','“现在我们是一列小火车。你是司机，你往前推，阿姨就往前走；你往后拉，我就停下来。你要拐弯，就把树枝向左或向右转，好吗？”','3232-3292',1,1741705922,1782398548);
INSERT INTO highlights VALUES('3300101680_7_1437-1441','3300101680',7,'第1章 会笑，是高阶能力','烤肉游戏','1437-1441',1,1741705729,1782398548);
INSERT INTO highlights VALUES('3300101680_7_1226-1284','3300101680',7,'第1章 会笑，是高阶能力','孩子喜欢愿意陪他们玩的成年人。就是这么简单。','1226-1284',1,1741705627,1782398548);
INSERT INTO highlights VALUES('3300101680_5_7145-7172','3300101680',5,'前言 笑出来，不容易','本书写的，不是对教育高线的探索，而是对教育底线的维护。','7145-7172',1,1741687611,1782398548);
INSERT INTO highlights VALUES('3300101680_5_6900-7023','3300101680',5,'前言 笑出来，不容易','如果你的周围有一个甚至几个不同年龄的孩子，一定别浪费，可以借他们的眼睛和笑声帮你“穿透性识人”。他们喜欢的人，是相对清澈、清爽的，','6900-7023',1,1741687586,1782398548);
INSERT INTO highlights VALUES('3300101680_5_5982-5990','3300101680',5,'前言 笑出来，不容易','嗯，说废话，乐。','5982-5990',1,1741687347,1782398548);
INSERT INTO highlights VALUES('3300101680_4_754-850','3300101680',4,'文前','做错了，没关系。我们没有经验嘛！所以不需要自责，只需要允许自己随时重新开始。','754-850',1,1741484543,1782398548);
INSERT INTO highlights VALUES('3300053854_20_5286-5344','3300053854',20,'术语表','多任务处理通常被认为是“同时做两件事”，但当我们觉得自己在同时做两项任务时，实际上是注意力在不同任务之间的快速切换。','5286-5344',1,1691046141,1782398611);
INSERT INTO highlights VALUES('3300053854_19_4288-4316','3300053854',19,'结语','教育铸就更好的大脑，而关于头脑的知识可以成就更好的教育。','4288-4316',1,1691046078,1782398611);
INSERT INTO highlights VALUES('3300053854_19_4166-4228','3300053854',19,'结语','教育是将世代积累的智慧传递给孩子，我们强烈地相信它的重要性，因为我们知道，它为每个孩子以及其他所有人都带来了更好生活的希望。','4166-4228',1,1691046059,1782398611);
INSERT INTO highlights VALUES('3300053854_19_4114-4136','3300053854',19,'结语','如果你遵循这些原则，你就能使学生的成长最大化','4114-4136',1,1691046037,1782398611);
INSERT INTO highlights VALUES('3300053854_19_3995-4013','3300053854',19,'结语','其次，认知科学的原则可以约束教学实践','3995-4013',1,1691046029,1782398611);
INSERT INTO highlights VALUES('3300053854_19_3881-3962','3300053854',19,'结语','课堂毕竟不只是认知的地方，它还存在着情感、社交、激励等。这些不同的因素促使教师关注不同的问题，它们有时会发生冲突。也就是说，认知上最佳的练习可能是缺少动机的实践。','3881-3962',1,1691045985,1782398611);
INSERT INTO highlights VALUES('3300053854_19_3836-3881','3300053854',19,'结语','我认为认知科学在两个方面对教师有用。首先，认知科学可以帮助教师在相互冲突的顾虑中找到平衡。','3836-3881',1,1691045956,1782398611);
INSERT INTO highlights VALUES('3300053854_19_2742-2743','3300053854',19,'结语','[插图]','2742-2743',1,1691045608,1782398611);
INSERT INTO highlights VALUES('3300053854_19_2224-2273','3300053854',19,'结语','为了预测读者的反应，你必须了解他的个性、品味、偏好和背景知识。我们都听说过“了解你的受众”这个建议','2224-2273',1,1691045350,1782398611);
INSERT INTO highlights VALUES('3300053854_19_2093-2109','3300053854',19,'结语','“大部分的写作是预测读者的反应。','2093-2109',1,1691045130,1782398611);
INSERT INTO highlights VALUES('3300053854_19_1177-1201','3300053854',19,'结语','需要读者付出努力的比例越高，能继续阅读的人就越少','1177-1201',1,1691044976,1782398611);
INSERT INTO highlights VALUES('3300053854_19_975-1069','3300053854',19,'结语','阅读是一种精神行为，它实际上改变了读者的思考过程。因此，每一篇散文或诗歌都是一种提案：“跟着我，相信我，让我带你踏上一段心灵之旅。虽然这条路时而坎坷陡峭，但参与这场冒险肯定对你大有益处。”','975-1069',1,1691044942,1782398611);
INSERT INTO highlights VALUES('3300053854_19_883-919','3300053854',19,'结语','他只是在明确一个相当浅显的原则：如果你的作品无趣，为什么要要求别人去读？','883-919',1,1691044910,1782398611);
INSERT INTO highlights VALUES('3300053854_18_14967-15017','3300053854',18,'第10章 教师的大脑又是如何运作的？','新手教师觉得在教师教育项目中没有学到足够多的课堂管理知识。可以说，这项技能应该排在第一位，你怎么看？','14967-15017',1,1691044670,1782398611);
INSERT INTO highlights VALUES('3300053854_18_13686-13711','3300053854',18,'第10章 教师的大脑又是如何运作的？','刻意练习常常包括一些对目标技能没有直接帮助的活动，','13686-13711',1,1691044569,1782398611);
INSERT INTO highlights VALUES('3300053854_18_13642-13651','3300053854',18,'第10章 教师的大脑又是如何运作的？','查漏补缺，慢慢进步','13642-13651',1,1691044429,1782398611);
INSERT INTO highlights VALUES('3300053854_18_13543-13607','3300053854',18,'第10章 教师的大脑又是如何运作的？','你会注意到更多关于社交互动的微妙线索、个性的诸多方面，以及学生是如何思考的。给自己留有观察的时间和空间，你会看到非比寻常的东西。','13543-13607',1,1691044394,1782398611);
INSERT INTO highlights VALUES('3300053854_18_12976-12987','3300053854',18,'第10章 教师的大脑又是如何运作的？','观察学生不为人知的一面','12976-12987',1,1691044304,1782398611);
INSERT INTO highlights VALUES('3300053854_18_11228-11270','3300053854',18,'第10章 教师的大脑又是如何运作的？','首先，试着找到一天中你可以写作的时间，尽量确保这个时间段是你能够轻易坚持下来的时间。','11228-11270',1,1691044070,1782398611);
INSERT INTO highlights VALUES('3300053854_18_11010-11015','3300053854',18,'第10章 教师的大脑又是如何运作的？','写教学日记','11010-11015',1,1691044028,1782398611);
INSERT INTO highlights VALUES('3300053854_18_10400-10459','3300053854',18,'第10章 教师的大脑又是如何运作的？','。因为你不能一次性解决所有问题，你必须确定优先次序，决定最重要的事情，并专注于具体的、可管理的步骤，使你朝着目标前进。','10400-10459',1,1691043956,1782398611);
INSERT INTO highlights VALUES('3300053854_18_10150-10164','3300053854',18,'第10章 教师的大脑又是如何运作的？','其次，你要在教学上花更多时间','10150-10164',1,1691043904,1782398611);
INSERT INTO highlights VALUES('3300053854_18_9992-10062','3300053854',18,'第10章 教师的大脑又是如何运作的？','可以预期的是，一旦你有足够的经验，至少有些时候你会不动脑筋地授课。这没什么错，但不断改进教学的工作意味着你将更少地使用这种自动化的上课模式。','9992-10062',1,1691043898,1782398611);
INSERT INTO highlights VALUES('3300053854_18_9908-9921','3300053854',18,'第10章 教师的大脑又是如何运作的？','首先，要为额外工作做计划。','9908-9921',1,1691043877,1782398611);
INSERT INTO highlights VALUES('3300053854_18_9685-9698','3300053854',18,'第10章 教师的大脑又是如何运作的？','有意识地尝试改进：自我管理','9685-9698',1,1691043807,1782398611);
INSERT INTO highlights VALUES('3300053854_18_9003-9054','3300053854',18,'第10章 教师的大脑又是如何运作的？','你可以就某一节课上关注的问题制订计划，即便你能想到三件你想要做的事情，但一次只解决一件，让它保持简单。','9003-9054',1,1691043707,1782398611);
INSERT INTO highlights VALUES('3300053854_18_8875-8894','3300053854',18,'第10章 教师的大脑又是如何运作的？','第5步：将反馈运用于课堂，进行跟踪记录','8875-8894',1,1691043671,1782398611);
INSERT INTO highlights VALUES('3300053854_18_8728-8840','3300053854',18,'第10章 教师的大脑又是如何运作的？','如果你的搭档想知道你对如何解决某个问题的看法，她会询问你，在这种情况下，你当然应该竭尽所能提供你的任何想法。但是，在被问到这个问题之前，你要保持谨慎的、支持的观察态度，不要自动代入专家的角色，不管你对自己的解决方案有多自信。','8728-8840',1,1691043664,1782398611);
INSERT INTO highlights VALUES('3300053854_18_8186-8196','3300053854',18,'第10章 教师的大脑又是如何运作的？','支持、具体、关注行为','8186-8196',1,1691043568,1782398611);
INSERT INTO highlights VALUES('3300053854_18_8003-8024','3300053854',18,'第10章 教师的大脑又是如何运作的？','第4步：与你的搭档观看并点评彼此的教学录像','8003-8024',1,1691043541,1782398611);
INSERT INTO highlights VALUES('3300053854_18_7845-7877','3300053854',18,'第10章 教师的大脑又是如何运作的？','.评价应该是具体的，是基于你观察到的行为，而不是你推断出的品质。','7845-7877',1,1691043512,1782398611);
INSERT INTO highlights VALUES('3300053854_18_7595-7625','3300053854',18,'第10章 教师的大脑又是如何运作的？','.评价应该是支持性的。支持别人并不意味着你只会说一些积极的话','7595-7625',1,1691043478,1782398611);
INSERT INTO highlights VALUES('3300053854_18_7674-7686','3300053854',18,'第10章 教师的大脑又是如何运作的？','正面评论应该多于负面评论','7674-7686',1,1691043468,1782398611);
INSERT INTO highlights VALUES('3300053854_18_7410-7440','3300053854',18,'第10章 教师的大脑又是如何运作的？','你应该有一个具体的目标，比如观察课堂管理或观察课堂的情感氛围','7410-7440',1,1691043426,1782398611);
INSERT INTO highlights VALUES('3300053854_18_7131-7149','3300053854',18,'第10章 教师的大脑又是如何运作的？','第3步：与搭档一起观看其他教师的视频','7131-7149',1,1691043391,1782398611);
INSERT INTO highlights VALUES('3300053854_18_6859-6948','3300053854',18,'第10章 教师的大脑又是如何运作的？','不要从一开始就对你的表现评头论足。首先，你要考虑一下班上有什么让你感到惊讶的地方。你注意到哪些学生的细节是你之前忽视的？你注意到了自己的哪些方面？花点时间观察。不要一上来就评价。','6859-6948',1,1691043346,1782398611);
INSERT INTO highlights VALUES('3300053854_18_6031-6051','3300053854',18,'第10章 教师的大脑又是如何运作的？','第2步：用视频记录课堂教学，独自复盘观看','6031-6051',1,1691043236,1782398611);
INSERT INTO highlights VALUES('3300053854_18_5883-5900','3300053854',18,'第10章 教师的大脑又是如何运作的？','第1步：确定一两位你愿意共事的教师','5883-5900',1,1691043223,1782398611);
INSERT INTO highlights VALUES('3300053854_18_5632-5649','3300053854',18,'第10章 教师的大脑又是如何运作的？','首先，你需要至少和一个人一起工作。','5632-5649',1,1691043177,1782398611);
INSERT INTO highlights VALUES('3300053854_18_4800-4852','3300053854',18,'第10章 教师的大脑又是如何运作的？','而另一些人（实际上是我们大多数人）则以对自己有利的方式解释他们的世界。社会心理学家将此称为“自利性偏差”','4800-4852',1,1691043028,1782398611);
INSERT INTO highlights VALUES('3300053854_18_3898-4066','3300053854',18,'第10章 教师的大脑又是如何运作的？','刻意练习有以下特点：(1)挑选一个你自己不满意的技能的一个小特点，并试图改善它，设定一个具体的目标，而不是像“变得更好”这样一个模糊的愿望。(2)当你练习时，至少从和你一样了解该技能的人那里得到反馈。(3)把自己推到舒适区之外，尝试新的东西。(4)你会发现刻意练习在心智上要求很高，坦白来讲，它枯燥无趣。(5)你参与间接促进技能的活动。','3898-4066',1,1691042838,1782398611);
INSERT INTO highlights VALUES('3300053854_18_3490-3536','3300053854',18,'第10章 教师的大脑又是如何运作的？','事实上，大量的数据显示，教师的授课水平会在头5年有显著的进步，但在那之后，情况就不太明朗了。','3490-3536',1,1691042726,1782398611);
INSERT INTO highlights VALUES('3300053854_18_2681-2721','3300053854',18,'第10章 教师的大脑又是如何运作的？','如果没有长期的练习，你几乎不可能精通任何脑力工作。改进教学的最好办法是实践教学。','2681-2721',1,1691042656,1782398611);
INSERT INTO highlights VALUES('3300053854_18_2226-2312','3300053854',18,'第10章 教师的大脑又是如何运作的？','这些数据表明学科教学法知识(pedagogical content knowledge)也很重要。也就是说，对于教师来说，仅仅学好代数是不够的。你需要掌握教代数的专门知识。','2226-2312',1,1691042597,1782398611);
INSERT INTO highlights VALUES('3300053854_18_1148-1163','3300053854',18,'第10章 教师的大脑又是如何运作的？','思考是将信息以新的方式组合起来','1148-1163',1,1691042407,1782398611);
INSERT INTO highlights VALUES('3300053854_18_692-693','3300053854',18,'第10章 教师的大脑又是如何运作的？','[插图]','692-693',1,1691042306,1782398611);
INSERT INTO highlights VALUES('3300053854_17_26073-26121','3300053854',17,'第9章 新技术能否改善学生的学习？','我在前文说过，尽管你几乎可以在互联网上学习或体验任何东西，但学生只是在非常有限的活动范围内探索。','26073-26121',1,1691029975,1782398611);
INSERT INTO highlights VALUES('3300053854_17_24146-24191','3300053854',17,'第9章 新技术能否改善学生的学习？','人们认为智能手机和平板电脑为孩子提供了即时满足。对父母来说，这其实是立竿见影的即时满足感。','24146-24191',1,1691029753,1782398611);
INSERT INTO highlights VALUES('3300053854_17_23857-23883','3300053854',17,'第9章 新技术能否改善学生的学习？','那么21世纪最需要的技能可能是运用耐心、警惕的能力。','23857-23883',1,1691029692,1782398611);
INSERT INTO highlights VALUES('3300053854_17_23044-23066','3300053854',17,'第9章 新技术能否改善学生的学习？','注意力不仅是一个能力问题，也是一个愿望问题。','23044-23066',1,1691029584,1782398611);
INSERT INTO highlights VALUES('3300053854_17_22729-22788','3300053854',17,'第9章 新技术能否改善学生的学习？','政策和程序不一样。这项政策可能是好的，但如果这些程序把教师变成了时刻保持警惕的“警察”，那么这个程序就应该被重新审视。','22729-22788',1,1691029553,1782398611);
INSERT INTO highlights VALUES('3300053854_17_21289-21365','3300053854',17,'第9章 新技术能否改善学生的学习？','(1)我们希望能改变什么？(2)我们如何知道它是否已经改变？(3)到什么时候应该改变？(4)如果它改变了，我们要做什么，如果它没有改变，我们又要做什么？','21289-21365',1,1691029403,1782398611);
INSERT INTO highlights VALUES('3300053854_17_21225-21240','3300053854',17,'第9章 新技术能否改善学生的学习？','我常常对目标的模糊性感到惊讶。','21225-21240',1,1691029311,1782398611);
INSERT INTO highlights VALUES('3300053854_17_21054-21129','3300053854',17,'第9章 新技术能否改善学生的学习？','黑板有一个容易被忽视的特点：教师可以从左向右地依次书写内容，因此随着课程的进展，教师很容易回溯到课程的早期部分。即使教师不这样做，学生也可以自行回顾。','21054-21129',1,1691029227,1782398611);
INSERT INTO highlights VALUES('3300053854_17_19982-20073','3300053854',17,'第9章 新技术能否改善学生的学习？','雇用缺乏技术专长的员工或者其技术专长已经过时的员工是雇主的常规做法，且他们常常怀有这样的想法：员工可以参加一个课程来加强技能。但是，雇用缺乏阅读、写作或数学技能的员工却不是常规做法。','19982-20073',1,1691029104,1782398611);
INSERT INTO highlights VALUES('3300053854_17_18763-18800','3300053854',17,'第9章 新技术能否改善学生的学习？','最显著的变化似乎是当今的青少年（以及许多成年人）的确对他们的手机爱不释手。','18763-18800',1,1691028939,1782398611);
INSERT INTO highlights VALUES('3300053854_17_18525-18717','3300053854',17,'第9章 新技术能否改善学生的学习？','第一，你的大脑是可塑的，会随着经验而改变，但思维的基本结构可能不会改变，所以技术并没有改变当今孩子们的思维方式，无论好坏。第二，技术并没有像一些人预测的那样完全取代教育。第三，技术变化对认知的细微改变是很难预测的。那些看起来应该对认知影响不大的变化（例如，用屏幕代替纸质阅读），有时会对学生的学习和情感产生影响。第四，沉浸在技术中会对学生的生活产生显著影响的更普遍的想法似乎没有成真，','18525-18717',1,1691028931,1782398611);
INSERT INTO highlights VALUES('3300053854_17_18311-18416','3300053854',17,'第9章 新技术能否改善学生的学习？','(1)信息往往是有社交属性的，而青少年对社交信息特别感兴趣；(2)延迟奖励对任何人来说都是困难的，但对青少年来说比成年人更难；(3)社会资讯往往是易逝的，这进一步加剧了现在查看手机和以后查看手机之间的价值差异。','18311-18416',1,1691028824,1782398611);
INSERT INTO highlights VALUES('3300053854_17_17849-17960','3300053854',17,'第9章 新技术能否改善学生的学习？','当我们对青少年沉迷于手机感到沮丧时，我们经常建议他们把手机收起来，每两个小时左右查看一次。但现在，你就能够明白为什么这种策略对他们毫无作用了吧。这就像给他们看一碗冰激凌，然后建议他们把它放在一边几个小时，而不是现在就开吃。','17849-17960',1,1691028728,1782398611);
INSERT INTO highlights VALUES('3300053854_17_17311-17334','3300053854',17,'第9章 新技术能否改善学生的学习？','随着回报的预期在未来越来越久，它就会失去价值。','17311-17334',1,1691028665,1782398611);
INSERT INTO highlights VALUES('3300053854_17_16643-16760','3300053854',17,'第9章 新技术能否改善学生的学习？','虽然成年人通常认为青少年过度关心同龄人的看法，但心理学家认为这种现象是一个特点，而不是一个错误。13—19岁的青少年痴迷于研究他们的同龄人，因为他们正临近要和父母分开生活的年纪，对同龄人的密切研究是他们学习驾驭家庭之外世界的一种方式。','16643-16760',1,1691028562,1782398611);
INSERT INTO highlights VALUES('3300053854_17_16531-16566','3300053854',17,'第9章 新技术能否改善学生的学习？','即使我们知道信息通知通常预示着一些微不足道的东西，我们仍然想一探究竟。','16531-16566',1,1691028508,1782398611);
INSERT INTO highlights VALUES('3300053854_17_16368-16448','3300053854',17,'第9章 新技术能否改善学生的学习？','首先，人类是信息的探索者。如第1章所述，当判断出环境中有需要学习的东西时，我们的好奇心就会被激发出来，而手机通知就是一个极其明确的信号，提醒我们有东西需要学习。','16368-16448',1,1691028501,1782398611);
INSERT INTO highlights VALUES('3300053854_17_11596-11623','3300053854',17,'第9章 新技术能否改善学生的学习？','其二，心理学家会告诉你，抵制诱惑的聪明方法是改变环境。','11596-11623',1,1691024332,1782398611);
INSERT INTO highlights VALUES('3300053854_17_11265-11342','3300053854',17,'第9章 新技术能否改善学生的学习？','其一，它希望达到的这个免受分心干扰的标准是极具困难的。青少年在控制冲动方面不如成年人，而且青少年热衷于过度社交，甚至是亢奋社交(hyper-social)','11265-11342',1,1691024322,1782398611);
INSERT INTO highlights VALUES('3300053854_17_11184-11236','3300053854',17,'第9章 新技术能否改善学生的学习？','“好吧，这确实让人分心，但这就是我们生活的世界。他们需要学习如何避免分心。”这种说法存在两个方面的错误。','11184-11236',1,1691024309,1782398611);
INSERT INTO highlights VALUES('3300053854_17_5981-6015','3300053854',17,'第9章 新技术能否改善学生的学习？','这一切都取决于音乐所带来的激励效应和分散注意力的代价两者之间的抗衡。','5981-6015',1,1691023562,1782398611);
INSERT INTO highlights VALUES('3300053854_17_4419-4449','3300053854',17,'第9章 新技术能否改善学生的学习？','而我们不擅长一心多用的原因是我们不是在一心多用的环境中长大的','4419-4449',1,1691023332,1782398611);
INSERT INTO highlights VALUES('3300053854_17_3302-3345','3300053854',17,'第9章 新技术能否改善学生的学习？','根据该观点我们可以得知，这种快速的注意力转移成为一种习惯，使学生无法长时间集中注意力。','3302-3345',1,1691023142,1782398611);
INSERT INTO highlights VALUES('3300053854_17_2465-2526','3300053854',17,'第9章 新技术能否改善学生的学习？','现在很清楚的是，由于这种无处不在的环境以及他们与环境的大量互动，今天的学生在思考和处理信息方面与他们的前辈有着根本的不同。','2465-2526',1,1691023091,1782398611);
INSERT INTO highlights VALUES('3300053854_17_2941-2965','3300053854',17,'第9章 新技术能否改善学生的学习？','对科技的适应来自你所处的环境，而不是你们这一代人','2941-2965',1,1691023051,1782398611);
INSERT INTO highlights VALUES('3300053854_17_988-989','3300053854',17,'第9章 新技术能否改善学生的学习？','[插图]','988-989',1,1691022689,1782398611);
INSERT INTO highlights VALUES('3300053854_16_19583-19611','3300053854',16,'第8章 如何帮助“慢热型”学生？','。这让我怀疑我的态度也在影响着我在课堂上与学生的互动方式','19583-19611',1,1691021978,1782398611);
INSERT INTO highlights VALUES('3300053854_16_19552-19583','3300053854',16,'第8章 如何帮助“慢热型”学生？','这不禁让我意识到我个人对学生的了解可能影响了我对他们作品的评分','19552-19583',1,1691021952,1782398611);
INSERT INTO highlights VALUES('3300053854_16_19434-19457','3300053854',16,'第8章 如何帮助“慢热型”学生？','.相信一个人的智能肯定会影响我们对其成就的看法','19434-19457',1,1691021894,1782398611);
INSERT INTO highlights VALUES('3300053854_16_19369-19404','3300053854',16,'第8章 如何帮助“慢热型”学生？','越来越多的数字工具会不会把我们从认知工作中解放出来，从而使我们变笨呢？','19369-19404',1,1691021720,1782398611);
INSERT INTO highlights VALUES('3300053854_16_18012-18050','3300053854',16,'第8章 如何帮助“慢热型”学生？','在考虑帮助“慢热型”学生迎头赶上时，制订可实现的、具体的阶段性目标是明智的。','18012-18050',1,1691021483,1782398611);
INSERT INTO highlights VALUES('3300053854_16_17225-17246','3300053854',16,'第8章 如何帮助“慢热型”学生？','需要学生拥有自律、时间管理和善于思考的技能','17225-17246',1,1691021392,1782398611);
INSERT INTO highlights VALUES('3300053854_16_16650-16702','3300053854',16,'第8章 如何帮助“慢热型”学生？','最重要的是，你要为你的学生示范这种态度。当你失败时——谁又不会失败呢——让他们看到你采取的积极学习态度。','16650-16702',1,1691021259,1782398611);
INSERT INTO highlights VALUES('3300053854_16_16392-16436','3300053854',16,'第8章 如何帮助“慢热型”学生？','尽量创造一种课堂氛围，在这种氛围中，虽然失败不可取，但它既不带来难堪，也不完全是负面的。','16392-16436',1,1691021195,1782398611);
INSERT INTO highlights VALUES('3300053854_16_16180-16205','3300053854',16,'第8章 如何帮助“慢热型”学生？','“孩子，唯一不犯错的人是那些从未做过任何事的人。”','16180-16205',1,1691021053,1782398611);
INSERT INTO highlights VALUES('3300053854_16_15770-15860','3300053854',16,'第8章 如何帮助“慢热型”学生？','那些在学校表现良好的学生并不是因为他们是聪明而不需要学习的人，相反，他们是能够在努力学习中获得满足感的那种人，他们可能是通过克服最初的那种“糟糕，我想放弃”的想法而获得这种满足的。','15770-15860',1,1691021017,1782398611);
INSERT INTO highlights VALUES('3300053854_16_15501-15561','3300053854',16,'第8章 如何帮助“慢热型”学生？','学习也是一样。大多数人都必须非常努力才能学好。有少数人不用努力就能学得不错，但这种人少之又少，而且没有人喜欢或尊重他们。','15501-15561',1,1691020940,1782398611);
INSERT INTO highlights VALUES('3300053854_16_14255-14286','3300053854',16,'第8章 如何帮助“慢热型”学生？','你可以变得更聪明，但你必须努力学习，寻求反馈，并尝试新事物”。','14255-14286',1,1691020813,1782398611);
INSERT INTO highlights VALUES('3300053854_16_13558-13599','3300053854',16,'第8章 如何帮助“慢热型”学生？','第三，学生必须养成在出错或行不通的时候寻找新策略的习惯，并在寻求新策略时要足智多谋','13558-13599',1,1691020483,1782398611);
INSERT INTO highlights VALUES('3300053854_16_13406-13417','3300053854',16,'第8章 如何帮助“慢热型”学生？','第二，鼓励学生寻求反馈','13406-13417',1,1691020453,1782398611);
INSERT INTO highlights VALUES('3300053854_16_13234-13249','3300053854',16,'第8章 如何帮助“慢热型”学生？','第一，你赞扬的应是过程而非能力','13234-13249',1,1691020436,1782398611);
INSERT INTO highlights VALUES('3300053854_16_12887-12942','3300053854',16,'第8章 如何帮助“慢热型”学生？','为了帮助学习迟缓者提高学习成绩，首先我们必须让他们相信自己可以做到，然后我们必须说服他们，这是值得付出努力的。','12887-12942',1,1691020338,1782398611);
INSERT INTO highlights VALUES('3300053854_16_12760-12824','3300053854',16,'第8章 如何帮助“慢热型”学生？','成绩较差的学生可能和聪明的学生有类似的潜力，但他们可能在知识、动机、逆商（面对学业挫折的坚持）和作为学生的自我映象等方面有所不同','12760-12824',1,1691020299,1782398611);
INSERT INTO highlights VALUES('3300053854_16_11051-11130','3300053854',16,'第8章 如何帮助“慢热型”学生？','(1)努力尝试或寻求帮助并不意味着你很笨。(2)失败并不是因为能力低下，而是因为缺乏经验。(3)没有必要担心因为失败和暴露你不知道的东西而使你“看起来很笨”。','11051-11130',1,1691019408,1782398611);
INSERT INTO highlights VALUES('3300053854_16_9858-9894','3300053854',16,'第8章 如何帮助“慢热型”学生？','认为智能是可塑的，这种可以通过努力工作来提高的核心信念被称为“成长型思维','9858-9894',1,1690988823,1782398611);
INSERT INTO highlights VALUES('3300053854_16_8783-8797','3300053854',16,'第8章 如何帮助“慢热型”学生？','智能是可塑的，它可以被提高。','8783-8797',1,1690988435,1782398611);
INSERT INTO highlights VALUES('3300053854_16_8735-8760','3300053854',16,'第8章 如何帮助“慢热型”学生？','我们会努力让学生在他们所拥有的智能条件下做到最好。','8735-8760',1,1690988426,1782398611);
INSERT INTO highlights VALUES('3300053854_16_7115-7162','3300053854',16,'第8章 如何帮助“慢热型”学生？','是练习—环境因素让他们打球出色，而这并不取决于他们的基因。基因因素会让你寻找或选择不同的环境。','7115-7162',1,1690988214,1782398611);
INSERT INTO highlights VALUES('3300053854_16_6670-6698','3300053854',16,'第8章 如何帮助“慢热型”学生？','因组成也可能有间接影响，因为它使人们有可能寻求特定的环境','6670-6698',1,1690988138,1782398611);
INSERT INTO highlights VALUES('3300053854_16_6621-6640','3300053854',16,'第8章 如何帮助“慢热型”学生？','他们的基因组成将影响着他们如何抚养你。','6621-6640',1,1690988121,1782398611);
INSERT INTO highlights VALUES('3300053854_16_4558-4618','3300053854',16,'第8章 如何帮助“慢热型”学生？','研究人员的观点发生了重大转变：从认为答案是“两者皆有，但可能更多是遗传因素”转变成“两者皆有，但可能更多的是环境因素”。','4558-4618',1,1690987478,1782398611);
INSERT INTO highlights VALUES('3300053854_16_4003-4028','3300053854',16,'第8章 如何帮助“慢热型”学生？','我强调了练习和努力学习对熟练掌握认知任务的重要性。','4003-4028',1,1690987461,1782398611);
INSERT INTO highlights VALUES('3300053854_16_1129-1130','3300053854',16,'第8章 如何帮助“慢热型”学生？','[插图]','1129-1130',1,1690987064,1782398611);
INSERT INTO highlights VALUES('3300053854_16_852-901','3300053854',16,'第8章 如何帮助“慢热型”学生？','如果你没有通过考试或不理解一个概念，你不会把这作为你笨的证据——你只是觉得自己还没有掌握这个内容。','852-901',1,1690987027,1782398611);
INSERT INTO highlights VALUES('3300053854_15_16390-16417','3300053854',15,'第7章 如何因材施教？','承认每个孩子的价值，即使他或她在某些方面没那么“聪明”','16390-16417',1,1690855049,1782398611);
INSERT INTO highlights VALUES('3300053854_15_16289-16355','3300053854',15,'第7章 如何因材施教？','不要对每个学生的思考过程进行针对性的个性化训练，而是让所有学生都练习所有过程，并将这些转变视为每个学生重新开始、再次集中精力的机会。','16289-16355',1,1690855038,1782398611);
INSERT INTO highlights VALUES('3300053854_15_16041-16057','3300053854',15,'第7章 如何因材施教？','擅用变化，让学生的注意力重新集中','16041-16057',1,1690854974,1782398611);
INSERT INTO highlights VALUES('3300053854_15_15591-15601','3300053854',15,'第7章 如何因材施教？','思考内容而非思考学生','15591-15601',1,1690854966,1782398611);
INSERT INTO highlights VALUES('3300053854_15_15899-15965','3300053854',15,'第7章 如何因材施教？','你是希望学生在上课时进行演绎思考，还是让他们自由地进行创造性联想？他们应该关注所学概念之间的相似性，还是应该关注区分这些概念的细节？','15899-15965',1,1690854959,1782398611);
INSERT INTO highlights VALUES('3300053854_15_15122-15249','3300053854',15,'第7章 如何因材施教？','如果我认为自己擅长，那么就会认为这意味着我能轻而易举地将它实现，我不需要努力就可以做到。相比之下，如果我明白自己天生不擅长，那么我就可能会认为这意味着一开始尝试就没有多大意义。或者，我可能会用我在这一领域所谓的缺乏才智作为在经历任何挫折后放弃尝试的理由。','15122-15249',1,1690854875,1782398611);
INSERT INTO highlights VALUES('3300053854_15_8285-8382','3300053854',15,'第7章 如何因材施教？','首先，它早已成为普世智慧。这是一个每个人都认为是正确的事实，因为每个人都相信它，这种现象被称为“社会认同”(social proof)。尽管这听起来似乎很傻，但我们都会因为社会认同而相信很多事情','8285-8382',1,1690854055,1782398611);
INSERT INTO highlights VALUES('3300053854_15_3630-3665','3300053854',15,'第7章 如何因材施教？','风格只代表了我们在思考上的个人偏好，而不应该是衡量我们思考能力的标准。','3630-3665',1,1690853553,1782398611);
INSERT INTO highlights VALUES('3300053854_15_2447-2509','3300053854',15,'第7章 如何因材施教？','认知风格是一种偏好或倾向，即以一种特定的方式思考，例如，线性思考（一次一件事）或整体思考（同时思考事情的所有方面、全局性）。','2447-2509',1,1690853294,1782398611);
INSERT INTO highlights VALUES('3300053854_15_2370-2401','3300053854',15,'第7章 如何因材施教？','认知能力的定义很简单：它意味着在某种类型的思维中取得成功的能力','2370-2401',1,1690853272,1782398611);
INSERT INTO highlights VALUES('3300053854_15_2035-2127','3300053854',15,'第7章 如何因材施教？','发挥学生的优势（如凯西的情况）或改变你展示材料的方式（如李的情况）意味着你要在教学方法上做出改变，并竭尽所能为班上的每个学生做一些不同的事情。这听起来要做很多额外的工作。这样做值得吗？','2035-2127',1,1690852679,1782398611);
INSERT INTO highlights VALUES('3300053854_15_925-926','3300053854',15,'第7章 如何因材施教？','[插图]','925-926',1,1690852524,1782398611);
INSERT INTO highlights VALUES('3300053854_15_722-733','3300053854',15,'第7章 如何因材施教？','“彼之珍宝，吾之芥草”','722-733',1,1690852500,1782398611);
INSERT INTO highlights VALUES('3300053854_14_14893-14910','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','每个艺术家首先都是从学徒做起的。”','14893-14910',1,1690852220,1782398611);
INSERT INTO highlights VALUES('3300053854_14_13736-13785','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','不要过于关注雄心勃勃的目标本身，而要关注中途站，即成功的中间阶段。把“熟能生巧”换成“熟能进步”。','13736-13785',1,1690852141,1782398611);
INSERT INTO highlights VALUES('3300053854_14_13708-13736','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','学习者可以看到进步的迹象，我认为这是长期保持动力的关键。','13708-13736',1,1690852128,1782398611);
INSERT INTO highlights VALUES('3300053854_14_12595-12611','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','需要创造力的作业也可能有激励作用','12595-12611',1,1690852014,1782398611);
INSERT INTO highlights VALUES('3300053854_14_11764-11855','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','对学生来说，一个更为谦虚和现实的目标是理解知识。学生可能不能发展自己的科学理论，但他们可以发展对现有理论的深刻理解。一个学生可能不会依据史实给出全新的见解，但是她可以理解别人的诠释。','11764-11855',1,1690851945,1782398611);
INSERT INTO highlights VALUES('3300053854_14_10006-10024','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','坚毅的一半是激情，是学生热爱的东西。','10006-10024',1,1690851765,1782398611);
INSERT INTO highlights VALUES('3300053854_14_9838-9876','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','达克沃思指出了两种基本的性格成分，即坚持和对长期目标的热情，并将其称为坚毅。','9838-9876',1,1690851740,1782398611);
INSERT INTO highlights VALUES('3300053854_14_9545-9572','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','伟大的科学家有着惊人的毅力，他们的精神疲惫阈值非常高。','9545-9572',1,1690851682,1782398611);
INSERT INTO highlights VALUES('3300053854_14_9464-9478','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','伟大的科学家几乎都是工作狂。','9464-9478',1,1690851666,1782398611);
INSERT INTO highlights VALUES('3300053854_14_4893-4929','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','我发现了两种克服工作记忆局限性的方法：背景知识（第2章）和练习（第5章）','4893-4929',1,1690851246,1782398611);
INSERT INTO highlights VALUES('3300053854_14_7093-7130','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','第二种克服工作记忆有限问题的方法是反复练习操作程序，使其成为一种自动化过程','7093-7130',1,1690851218,1782398611);
INSERT INTO highlights VALUES('3300053854_14_934-935','3300053854',14,'第6章 让学生像真正的科学家、数学家和历史学家一样思考的秘诀是什么？','[插图]','934-935',1,1690850415,1782398611);
INSERT INTO highlights VALUES('3300053854_13_11529-11535','3300053854',13,'第5章 反复练习值得吗？','间隔效应(s','11529-11535',1,1690795896,1782398611);
INSERT INTO highlights VALUES('3300053854_13_14953-14980','3300053854',13,'第5章 反复练习值得吗？','有两个显而易见的理由说明我们需要练习：获得最基础的能力','14953-14980',1,1690795895,1782398611);
INSERT INTO highlights VALUES('3300053854_13_15074-15137','3300053854',13,'第5章 反复练习值得吗？','(1)它可以帮助心理过程变得自动化，从而使进一步的学习成为可能。(2)它使记忆持久。(3)它增加了学习迁移到新环境中的可能性。','15074-15137',1,1690795894,1782398611);
INSERT INTO highlights VALUES('3300053854_13_15003-15010','3300053854',13,'第5章 反复练习值得吗？','和获得熟练程度','15003-15010',1,1690795894,1782398611);
INSERT INTO highlights VALUES('3300053854_13_4589-4625','3300053854',13,'第5章 反复练习值得吗？','思考过程也可以自动化。这种不假思索的自动处理很少甚至不需要工作记忆空间。','4589-4625',1,1690795893,1782398611);
INSERT INTO highlights VALUES('3300053854_13_9160-9205','3300053854',13,'第5章 反复练习值得吗？','努力学习并不能防止遗忘。如果我们假设一个学生学习很努力，我们就必须承认他们和其他人一样健忘','9160-9205',1,1690795892,1782398611);
INSERT INTO highlights VALUES('3300053854_13_8577-8602','3300053854',13,'第5章 反复练习值得吗？','我们很快就忘记了我们所学的很多（但不是全部）东西。','8577-8602',1,1690795891,1782398611);
INSERT INTO highlights VALUES('3300053854_13_8193-8231','3300053854',13,'第5章 反复练习值得吗？','文明的进步是通过扩大重要练习的数量来实现的，这些练习我们无须思考就能完成。”','8193-8231',1,1690795891,1782398611);
INSERT INTO highlights VALUES('3300053854_13_988-989','3300053854',13,'第5章 反复练习值得吗？','[插图]','988-989',2,1690795890,1782398611);
INSERT INTO highlights VALUES('3300053854_13_8270-8279','3300053854',13,'第5章 反复练习值得吗？','练习促使记忆更持久','8270-8279',1,1690795889,1782398611);
INSERT INTO highlights VALUES('3300053854_13_15333-15352','3300053854',13,'第5章 反复练习值得吗？','练习高频次出现的事情和领域内的关键技能','15333-15352',1,1690795888,1782398611);
INSERT INTO highlights VALUES('3300053854_13_5193-5203','3300053854',13,'第5章 反复练习值得吗？','冲突减缓了你的反应。','5193-5203',1,1690795888,1782398611);
INSERT INTO highlights VALUES('3300053854_13_7433-7561','3300053854',13,'第5章 反复练习值得吗？','虽然我们不能使工作记忆的空间变大，但我们可以通过两种方式使工作记忆的内容变小：(1)通过分块使知识占据更少的空间，这需要长期记忆中的知识，如第2章所述。(2)通过使我们用来将信息带入工作记忆的过程更加有效率，或者通过创建一个记忆表征来消除对这些过程的需求。','7433-7561',1,1690795887,1782398611);
INSERT INTO highlights VALUES('3300053854_13_12658-12724','3300053854',13,'第5章 反复练习值得吗？','练习是良好知识迁移的另一个重要因素。处理大量特定类型的问题会使你更有可能认识到问题的深层结构，即使你以前没有见过该问题的这个特定版本','12658-12724',1,1690795886,1782398611);
INSERT INTO highlights VALUES('3300053854_13_16179-16191','3300053854',13,'第5章 反复练习值得吗？','把练习融入更高级的技能中','16179-16191',1,1690795885,1782398611);
INSERT INTO highlights VALUES('3300053854_13_15784-15790','3300053854',13,'第5章 反复练习值得吗？','进行分散练习','15784-15790',1,1690795885,1782398611);
INSERT INTO highlights VALUES('3300053854_13_1824-1867','3300053854',13,'第5章 反复练习值得吗？','练习可以带来三个重要的好处：强化学习更高阶技能所需的基本技能；防止遗忘；改善知识迁移。','1824-1867',1,1690795884,1782398611);
INSERT INTO highlights VALUES('3300053854_13_11377-11500','3300053854',13,'第5章 反复练习值得吗？','如果你在短时间内学习很多东西，你足以应付眼前的考试，但你很快就会忘记。如果你换一个方式，分几个阶段学习，中间有一段时间的延迟，你可能不能在眼下的考试中做得理想，但与考试前强化训练式的临时抱佛脚不同的是，你会在考试后更长的时间内记住你学习过的材料。','11377-11500',1,1690795883,1782398611);
INSERT INTO highlights VALUES('3300053854_13_16589-16611','3300053854',13,'第5章 反复练习值得吗？','，练习表层结构的各种形式有助于理解深层结构。','16589-16611',1,1690795882,1782398611);
INSERT INTO highlights VALUES('3300053854_13_3979-4044','3300053854',13,'第5章 反复练习值得吗？','摆脱工作记忆有限性的第一种方法是借助事实性知识，这使得分块记忆成为可能。第二种方法是你可以让处理工作记忆中信息的过程变得更有效率。','3979-4044',1,1690795882,1782398611);
INSERT INTO highlights VALUES('3300053854_13_1446-1467','3300053854',13,'第5章 反复练习值得吗？','为什么要练习？一个原因是能获得最基本的能力','1446-1467',1,1690795881,1782398611);
INSERT INTO highlights VALUES('3300053854_13_11584-11610','3300053854',13,'第5章 反复练习值得吗？','相比之下，分散学习更有利于记忆的说法自然更有说服力。','11584-11610',1,1690795880,1782398611);
INSERT INTO highlights VALUES('3300053854_13_16845-16904','3300053854',13,'第5章 反复练习值得吗？','：学生不仅需要在特定的深层结构问题上进行练习，以识别不同形式的深层结构。他们首先更需要的是用不同的形式来练习这个问题。','16845-16904',1,1690795878,1782398611);
INSERT INTO highlights VALUES('3300053854_12_15668-15700','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','知识再浅也比没有知识要好得多，而浅表知识是通往深层知识的必经之路','15668-15700',2,1690690599,1782398611);
INSERT INTO highlights VALUES('3300053854_12_15620-15639','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','渊博的知识来之不易，是大量实践的产物。','15620-15639',2,1690690583,1782398611);
INSERT INTO highlights VALUES('3300053854_12_15420-15457','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','如果你的学生到了能够参加小测试和测验的年龄，那么一定要测试他们的知识深度。','15420-15457',2,1690690412,1782398611);
INSERT INTO highlights VALUES('3300053854_12_15457-15500','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','学生会从测试内容中得到一个强烈的隐含信息：因为它出现在测试中，所以它是很重要的知识点。','15457-15500',2,1690690402,1782398611);
INSERT INTO highlights VALUES('3300053854_12_14184-14219','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','不要徒劳地认为教授一种不同的技能，就可以指望它能打磨出孩子的其他技能。','14184-14219',2,1690690101,1782398611);
INSERT INTO highlights VALUES('3300053854_12_12466-12519','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','当一个问题在其解决过程中含有许多组成部分和步骤时，往往会因为难以将已解决的问题映射到新问题中而阻碍知识迁移','12466-12519',2,1690689919,1782398611);
INSERT INTO highlights VALUES('3300053854_12_4371-4394','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','给出的例子重要的不是要足够具体，而是要足够常见','4371-4394',2,1690688890,1782398611);
INSERT INTO highlights VALUES('3300053854_12_1541-1575','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','他们通过将新观点（未知之事）与旧观点（已知之事）联系起来以理解新观点','1541-1575',2,1690688715,1782398611);
INSERT INTO highlights VALUES('3300053854_12_913-914','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','[插图]','913-914',1,1690688560,1782398611);
INSERT INTO highlights VALUES('3300053854_12_767-779','3300053854',12,'第4章 为什么学生很难理解抽象的概念？','大脑似乎更喜欢具体的东西','767-779',1,1690688547,1782398611);
INSERT INTO highlights VALUES('3300053854_11_19581-19592','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','学生能记住他们所想的。','19581-19592',1,1690688454,1782398611);
INSERT INTO highlights VALUES('3300053854_11_25885-25924','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','一个可能的解决办法是看看学生是否能自己想出更好的记忆法，并把最好的分享给大家。','25885-25924',1,1690683012,1782398611);
INSERT INTO highlights VALUES('3300053854_11_22967-22980','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','通过作业设计让学生思考意义','22967-22980',1,1690682719,1782398611);
INSERT INTO highlights VALUES('3300053854_11_22112-22154','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','在解释了基本原理并促使学生预测可能发生的情况后，“金属物沸腾”的演示效果可能会更好。','22112-22154',1,1690682553,1782398611);
INSERT INTO highlights VALUES('3300053854_11_21942-22020','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','通常是在课程进行到一半的时候，需要一点戏剧性的表演来吸引学生，把他们的注意力拉回来。但是不管何时使用它，仔细想想你将如何在吸引注意力及其设计意图之间建立联系','21942-22020',1,1690682420,1782398611);
INSERT INTO highlights VALUES('3300053854_11_20731-20739','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','吸引注意力要慎重','20731-20739',1,1690682266,1782398611);
INSERT INTO highlights VALUES('3300053854_11_19899-19921','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','根据学生可能想到的内容来重新审视你的课程计划','19899-19921',1,1690682259,1782398611);
INSERT INTO highlights VALUES('3300053854_11_18142-18143','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','[插图]','18142-18143',1,1690682024,1782398611);
INSERT INTO highlights VALUES('3300053854_11_16500-16586','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','在一部100分钟的好莱坞标准影片中，其冲突通常在20分钟左右时发生。编剧用这20分钟让你熟悉人物角色及其处境，这样当主要冲突出现时，你已经置身其中了，你关心角色会发生什么。','16500-16586',1,1690681723,1782398611);
INSERT INTO highlights VALUES('3300053854_11_12787-12808','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','4C原则”——因果关系、冲突、复杂性和角色','12787-12808',1,1690681238,1782398611);
INSERT INTO highlights VALUES('3300053854_11_11248-11273','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','第四个也是最后一个原则是角色(character)','11248-11273',1,1690642194,1782398611);
INSERT INTO highlights VALUES('3300053854_11_11077-11100','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','第三个原则是复杂性(complication)','11077-11100',1,1690642160,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10907-10924','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','第二个原则是冲突(conflict','10907-10924',1,1690642135,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10789-10818','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','“4C原则”。第一个原则是因果关系(causality)，','10789-10818',1,1690642121,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10497-10504','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','重视故事的力量','10497-10504',1,1690642102,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10309-10399','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','笑话、故事和热情的态度都产生了善意，调动了学生的注意力。但我们如何确保他们思考意义呢？这就是成为一名好教师的第二个特点，即以连贯的方式组织教学计划中的思想，以便学生能够理解和记住。','10309-10399',1,1690642036,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10188-10211','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','要知道教师既要有良好的组织能力，又要平易近人。','10188-10211',1,1690622649,1782398611);
INSERT INTO highlights VALUES('3300053854_11_10049-10096','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','优秀教师具备这两种品质：他们能够与学生建立个人联系，并以一种有趣且易于理解的方式组织课堂材料。','10049-10096',1,1690622633,1782398611);
INSERT INTO highlights VALUES('3300053854_11_8401-8433','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','我不推荐的关于让学生思考意义的技巧：努力使主题与学生的兴趣相关。','8401-8433',1,1690622375,1782398611);
INSERT INTO highlights VALUES('3300053854_11_8106-8193','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','几年前，我女儿完成了一项类似的作业，但她的教师要求学生使用单词或短语，而不是图案。我认为这项作业更有效地实现了教师的预期目标，因为我女儿更多地思考了书中的观点是如何相互关联的','8106-8193',1,1690622323,1782398611);
INSERT INTO highlights VALUES('3300053854_11_7763-7849','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','对于要学习的内容（即最终进入长期记忆），它必须在工作记忆中停留一段时间，也就是说，学生必须注意它。此外，学生对学习经历的思考方式将彻底决定了最终会进入长期记忆的内容是什么。','7763-7849',1,1690622263,1782398611);
INSERT INTO highlights VALUES('3300053854_11_7224-7281','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','学生在学校学到的95%的事物关注的是意义，而不是它看起来或听起来像什么。因此，教师的目标应该始终是让学生思考意义。','7224-7281',1,1690622002,1782398611);
INSERT INTO highlights VALUES('3300053854_11_6351-6362','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','思考意义对记忆有好处。','6351-6362',1,1690621758,1782398611);
INSERT INTO highlights VALUES('3300053854_11_6183-6217','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','因为判断是否有愉悦感会让你思考这个词的意义以及与这个意义相关的其他词','6183-6217',1,1690621721,1782398611);
INSERT INTO highlights VALUES('3300053854_11_4898-4932','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','“能引起情绪反应的东西会更容易被记住”，但情绪并不是学习的必要条件。','4898-4932',1,1690621591,1782398611);
INSERT INTO highlights VALUES('3300053854_11_2002-2018','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','如果你不注意某件事，你就学不到它','2002-2018',1,1690620088,1782398611);
INSERT INTO highlights VALUES('3300053854_11_1296-1353','3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','要想教得好，你应该认真考虑布置的每一项作业会让学生实际思考什么（而不是你希望他们思考的），因为那才是他们会记住的。','1296-1353',1,1690619568,1782398611);
INSERT INTO highlights VALUES('3300053854_10_24222-24276','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','上一章提到的一种解决方法是将复杂的材料分解成更小的部分。本章提到的另一个解决方案是获取足够的知识来实现分块。','24222-24276',1,1690619357,1782398611);
INSERT INTO highlights VALUES('3300053854_10_22332-22428','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','学生不能从阅读低于自己阅读水平的书中获得太多，而且每种阅读水平都存在有趣而迷人的书，所以为什么不把她推向适合她的书呢？另外，读一本太难的书不是一个好主意。学生不会理解它，阅读它只会以沮丧告终。','22332-22428',1,1690617120,1782398611);
INSERT INTO highlights VALUES('3300053854_10_20014-20030','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','先构造知识体系，后掌握批判性思维','20014-20030',1,1690616869,1782398611);
INSERT INTO highlights VALUES('3300053854_10_17571-17647','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','想象力比知识更重要。但愿你现在已经同意爱因斯坦的这句话是错的。知识更重要，因为它是想象力的先决条件，或者至少是导致问题解决、决策和创新想象力的先决条件。','17571-17647',1,1690616433,1782398611);
INSERT INTO highlights VALUES('3300053854_10_17264-17320','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','因为长期记忆能力强的人更容易学习，这种差距只会越来越大。我能赶上你的唯一办法就是确保我比你了解更多的事实性知识。','17264-17320',1,1690616373,1782398611);
INSERT INTO highlights VALUES('3300053854_10_16647-16721','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','背景知识的最后一个作用，即长期记忆中的事实性知识使人们更容易获得更多的事实性知识，这是值得深思的。这意味着你持有的信息量取决于你已经拥有的信息量。所','16647-16721',2,1690613592,1782398611);
INSERT INTO highlights VALUES('3300053854_10_14745-14782','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','“最好的地质学家是见过最多岩石的人”。历史、语言艺术、音乐等领域也是如此。','14745-14782',2,1690613378,1782398611);
INSERT INTO highlights VALUES('3300053854_10_10416-10513','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','背景知识对于阅读理解起重要作用的四种方式：(1)它提供词汇；(2)它允许你弥合作者留下的逻辑鸿沟；(3)它允许分块，这增加了工作记忆的空间，从而更容易将想法联系在一起；(4)它指导歧义句的解释。','10416-10513',2,1690536437,1782398611);
INSERT INTO highlights VALUES('3300053854_10_10139-10179','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','我们不是在真空中吸收新信息的。我们解读和读到的新东西是根据我们已掌握的其他信息。','10139-10179',2,1690536337,1782398611);
INSERT INTO highlights VALUES('3300053854_10_9655-9697','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','背景知识允许分块，这在工作记忆中有更大的空间，更容易将想法联系起来，从而更容易理解。','9655-9697',2,1690536258,1782398611);
INSERT INTO highlights VALUES('3300053854_10_8260-8299','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','将环境中独立的信息片段在心理上联系在一起的现象叫作分块记忆(chunking)','8260-8299',2,1690535892,1782398611);
INSERT INTO highlights VALUES('3300053854_10_8117-8152','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','因为工作记忆中的空间量并不取决于字母的数量；它取决于有意义对象的数量。','8117-8152',2,1690535825,1782398611);
INSERT INTO highlights VALUES('3300053854_10_4011-4038','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','我们必须确保学生在学习批判性思考技能的同时获得背景知识','4011-4038',2,1690535128,1782398611);
INSERT INTO highlights VALUES('3300053854_10_3527-3540','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','：良好的思考需要知道事实，','3527-3540',2,1690535105,1782398611);
INSERT INTO highlights VALUES('3300053854_10_3290-3479','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','在当今社会，为什么要背东西呢？你可以在几秒钟内通过互联网找到任何你需要的事实性信息，包括yegg的定义。还有，世间万物的变化如此之快，以至于你记忆中的一半信息在5年左右的时间里就会过时。与其学习事实，不如练习批判性思维，让学生努力评估互联网上的所有信息，而不是试图记住其中的一小部分。在本章中，我将证明上述论点是错误的。','3290-3479',2,1690534865,1782398611);
INSERT INTO highlights VALUES('3300053854_10_1271-1350','3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','当今的教育工作存在着一个极大的危险，那就是唯恐科学教学退化为相互脱节的事实和无法解释的公式的累积，这些事实和公式在没有养成理解力的情况下加重了学生记忆的负担。','1271-1350',2,1690534578,1782398611);
INSERT INTO highlights VALUES('3300053854_9_15966-16003','3300053854',9,'第1章 为什么学生不喜欢上学？','所以，计划好变化，监控全班的注意力，看看你是否需要更加频繁地增减课堂变化。','15966-16003',2,1690532164,1782398611);
INSERT INTO highlights VALUES('3300053854_9_15311-15328','3300053854',9,'第1章 为什么学生不喜欢上学？','在学生准备过程中接受差异并采取行动','15311-15328',2,1690532126,1782398611);
INSERT INTO highlights VALUES('3300053854_9_15659-15714','3300053854',9,'第1章 为什么学生不喜欢上学？','但事实是，鉴于他们落后于其他人，给他们超出其能力范围的作业不太可能帮助他们迎头赶上，反而可能使他们落后得更远。','15659-15714',2,1690532116,1782398611);
INSERT INTO highlights VALUES('3300053854_9_14664-14695','3300053854',9,'第1章 为什么学生不喜欢上学？','当你计划一节课的时候，你要从希望学生在课程结束前知道的信息开始','14664-14695',2,1690531964,1782398611);
INSERT INTO highlights VALUES('3300053854_9_14126-14162','3300053854',9,'第1章 为什么学生不喜欢上学？','怎样才能使问题变得有趣呢？一个常见的策略是尽量使教学材料与学生“相关”。','14126-14162',2,1690531903,1782398611);
INSERT INTO highlights VALUES('3300053854_9_13999-14054','3300053854',9,'第1章 为什么学生不喜欢上学？','解决工作记忆过载的方法很简单：放慢速度，使用记忆辅助工具，如在白板上书写，以避免学生在工作记忆中保留太多信息。','13999-14054',2,1690531832,1782398611);
INSERT INTO highlights VALUES('3300053854_9_13796-13839','3300053854',9,'第1章 为什么学生不喜欢上学？','如果学生缺乏解决问题的背景知识，那就把这个问题留到下次他们有相关背景知识的时候再说吧。','13796-13839',2,1690531711,1782398611);
INSERT INTO highlights VALUES('3300053854_9_13724-13733','3300053854',9,'第1章 为什么学生不喜欢上学？','尊重学生的认知局限','13724-13733',2,1690531695,1782398611);
INSERT INTO highlights VALUES('3300053854_9_13179-13222','3300053854',9,'第1章 为什么学生不喜欢上学？','从认知的角度来看，一个重要的因素是学生是否能持续地体验到学习新东西、解决问题的愉悦感。','13179-13222',2,1690531399,1782398611);
INSERT INTO highlights VALUES('3300053854_9_12584-12687','3300053854',9,'第1章 为什么学生不喜欢上学？','亚里士多德说：“从思考和学习中获得的乐趣将使我们思考和学习得更多。”你已经看到这种观点过于乐观。成功的学习是令人愉快的，它会促使学生们继续学习。我们已经看到，成功学习的因素之一是在长期记忆中拥有合适的信息。','12584-12687',2,1690531316,1782398611);
INSERT INTO highlights VALUES('3300053854_9_8264-8312','3300053854',9,'第1章 为什么学生不喜欢上学？','我们会快速评估解决问题或理解内容需要多少脑力劳动。如果工作太多或太少，我们会尽可能停止思考问题。','8264-8312',2,1690530607,1782398611);
INSERT INTO highlights VALUES('3300053854_9_7392-7476','3300053854',9,'第1章 为什么学生不喜欢上学？','所以，如果内容不足以吸引你的注意力，那么好奇心何时还会有持久力呢？答案似乎取决于我们对可能学到多少东西的判断。当我们认为自己能学到很多东西时，我们就会保持住这份好奇心。','7392-7476',2,1690530460,1782398611);
INSERT INTO highlights VALUES('3300053854_9_6212-6251','3300053854',9,'第1章 为什么学生不喜欢上学？','脑力劳动之所以吸引我们，是因为当它成功时，它为我们提供了一个获得愉悦感的机会。','6212-6251',2,1690530105,1782398611);
INSERT INTO highlights VALUES('3300053854_9_5742-5759','3300053854',9,'第1章 为什么学生不喜欢上学？','在成功的思考中有一种满足感和成就感','5742-5759',2,1690529845,1782398611);
INSERT INTO highlights VALUES('3300053854_9_5480-5495','3300053854',9,'第1章 为什么学生不喜欢上学？','人们天生好奇，但好奇心是脆弱的','5480-5495',2,1690507529,1782398611);
INSERT INTO highlights VALUES('3300053854_9_4823-4849','3300053854',9,'第1章 为什么学生不喜欢上学？','另一种是，你倾向于用记忆来指导你的行动，而不是思考。','4823-4849',2,1690507477,1782398611);
INSERT INTO highlights VALUES('3300053854_9_4739-4823','3300053854',9,'第1章 为什么学生不喜欢上学？','到目前为止，我已经描述了两种让你的大脑免于思考的方式。一种是，一些最重要的功能（例如视觉和运动）：你不需要对你看到的东西进行推理，而是马上就能知道外面的世界发生了什么。','4739-4823',2,1690507469,1782398611);
INSERT INTO highlights VALUES('3300053854_9_5180-5218','3300053854',9,'第1章 为什么学生不喜欢上学？','因此，一项最初需要大量思考的任务，随着实践练习，变成了一项不需要思考的任务。','5180-5218',2,1690507429,1782398611);
INSERT INTO highlights VALUES('3300053854_9_3485-3523','3300053854',9,'第1章 为什么学生不喜欢上学？','我们面临的大多数问题都是我们以前解决过的，所以我们只是在做我们过去做过的事情','3485-3523',2,1690507236,1782398611);
INSERT INTO highlights VALUES('3300053854_3_1301-1349','3300053854',3,'推荐序','。其中关键的是学会自我反思，即“有意识地尝试改进：自我管理”，记录教学日记是自我反思中有效的方法','1301-1349',2,1690447755,1782398611);
INSERT INTO highlights VALUES('3300008362_8_3392-3415','3300008362',8,'新诗50条','写诗的不一定与诗有关，不写诗的不一定与诗无关。','3392-3415',1,1692152253,1782398608);
INSERT INTO highlights VALUES('3300008362_8_3156-3186','3300008362',8,'新诗50条','唤起读者共鸣，不该令诗人感到羞愧，要感谢读者重新陈述了诗歌。','3156-3186',1,1692152221,1782398608);
INSERT INTO highlights VALUES('3300008362_8_2347-2364','3300008362',8,'新诗50条','诗意不来自世界，而来自诗人的注视。','2347-2364',1,1692152112,1782398608);
INSERT INTO highlights VALUES('3300008362_7_42445-42491','3300008362',7,'第四堂课 写出整首诗的若干方法','写诗永远是工作之余的爱好，全世界的诗人都知道，找一份有业余时间的工作，是诗人唯一的生存之道。','42445-42491',1,1692151905,1782398608);
INSERT INTO highlights VALUES('3300008362_7_41798-41845','3300008362',7,'第四堂课 写出整首诗的若干方法','懒惰是人的天性，但写作正是克服这种天性的古老技艺之一。与写作实践并行推进的，还应该有大量阅读。','41798-41845',1,1692151768,1782398608);
INSERT INTO highlights VALUES('3300008362_7_41527-41653','3300008362',7,'第四堂课 写出整首诗的若干方法','不少诗人写完，会搁置一段时间再修改，一般搁置多久比较合适呢？我的经验是，搁置到你拿出来阅读时，感觉是别人的作品，作品一旦在你眼里“陌生”起来，你的判断力就不再夹杂个人情感，会趋向客观，修改时就下得了狠手。陌生化不只是写诗的靠山，也是让你判断力苏醒的利器','41527-41653',1,1692151734,1782398608);
INSERT INTO highlights VALUES('3300008362_7_38225-38527','3300008362',7,'第四堂课 写出整首诗的若干方法','起风了我爱你芦苇野茫茫的一片顺着风在这遥远的地方不需要思想只需要芦苇顺着风野茫茫的一片像我们的爱，没有内容[插图]','38225-38526',1,1692149818,1782398608);
INSERT INTO highlights VALUES('3300008362_7_36684-36825','3300008362',7,'第四堂课 写出整首诗的若干方法','三段式的结构，它易掌握又严谨，用记号来表示是：ABA′。整首诗分为A、B、A′三部分，第三部分A′与第一部分A相似，复现A的部分主题，通过添加内容或部分改变A，使A′不只是对A的简单复现，而是对A的提升。B要么是与A的对比，要么是深化或拓展A中的要素或部分主题，把A与A′连成整体。','36684-36825',1,1692149258,1782398608);
INSERT INTO highlights VALUES('3300008362_7_35767-35840','3300008362',7,'第四堂课 写出整首诗的若干方法','母亲，如果你低头看我的眼睛，你会看见更多的星栖息于我的视网膜——它们是一些有痛感的树','35767-35840',1,1692148991,1782398608);
INSERT INTO highlights VALUES('3300008362_7_35357-35451','3300008362',7,'第四堂课 写出整首诗的若干方法','明迪的诗《海叶集》：从水的方向看，海是一棵树鱼，是海里的风吹动叶','35357-35451',1,1692148954,1782398608);
INSERT INTO highlights VALUES('3300008362_7_32542-32662','3300008362',7,'第四堂课 写出整首诗的若干方法','我要每天清晨遛狗让狗带着我把路熟透熟得像西瓜那样开裂[插图]','32542-32662',1,1692148170,1782398608);
INSERT INTO highlights VALUES('3300008362_7_32003-32027','3300008362',7,'第四堂课 写出整首诗的若干方法','郑愁予写“月遗落遍地的影子，／云以纤手拾了去”，','32003-32027',1,1692148034,1782398608);
INSERT INTO highlights VALUES('3300008362_7_31795-31807','3300008362',7,'第四堂课 写出整首诗的若干方法','鸽子品尝着／光的香甜。”','31795-31807',1,1692147956,1782398608);
INSERT INTO highlights VALUES('3300008362_7_29198-29221','3300008362',7,'第四堂课 写出整首诗的若干方法','通感手法：以一种感官感觉，描绘另一种感官感觉。','29198-29221',1,1692103509,1782398608);
INSERT INTO highlights VALUES('3300008362_7_26188-26407','3300008362',7,'第四堂课 写出整首诗的若干方法','放过我。你属于去年的暴雨。而你却穿破层层脑墙履声哒哒踏着梦归来。[插图]','26188-26407',1,1692091816,1782398608);
INSERT INTO highlights VALUES('3300008362_7_25609-25644','3300008362',7,'第四堂课 写出整首诗的若干方法','3．通篇描绘B并提及A，或通篇描绘A并提及B，或通篇既描绘A也描绘B。','25609-25644',1,1692091697,1782398608);
INSERT INTO highlights VALUES('3300008362_7_24327-24828','3300008362',7,'第四堂课 写出整首诗的若干方法','台湾诗人夏宇也用隐喻，写过一首爱情诗《爱情》：为蛀牙写的一首诗，很短念给你听：“拔掉了还疼一种空洞的疼。”就是只是这样，很短仿佛爱情[插图]','24327-24828',1,1692091685,1782398608);
INSERT INTO highlights VALUES('3300008362_7_25462-25580','3300008362',7,'第四堂课 写出整首诗的若干方法','1．先列出你想表达的事物A，比如爱情、孤独、痛苦等等；2．寻找A的对应物B，所谓对应物B，就是你希望通过描绘B，能让读者更好地领悟A，比如北岛为“卑鄙”找到的对应物是“通行证”；','25462-25580',1,1692091655,1782398608);
INSERT INTO highlights VALUES('3300008362_7_23113-23143','3300008362',7,'第四堂课 写出整首诗的若干方法','多恩在《别离辞：节哀》中，就用隐喻来表达他和妻子的伉俪之爱。','23113-23143',1,1692091527,1782398608);
INSERT INTO highlights VALUES('3300008362_7_23194-23678','3300008362',7,'第四堂课 写出整首诗的若干方法','就还算两个吧，两个却这样和一副两脚圆规情况相同；你的灵魂是定脚，并不想移动另一脚一移，它也动。虽然它一直是坐在中心，可是另一个去天涯海角，它就侧了身，倾听八垠；那一个一回家，它马上挺腰。你对我就会这样子，我一生像另外那一脚，得侧身打转；你坚定，我的圆圈才会准，我才会终结在开始的地点。[插图]','23194-23678',1,1692091475,1782398608);
INSERT INTO highlights VALUES('3300008362_7_22061-22063','3300008362',7,'第四堂课 写出整首诗的若干方法','庞德','22061-22063',1,1692091346,1782398608);
INSERT INTO highlights VALUES('3300008362_7_22154-22186','3300008362',7,'第四堂课 写出整首诗的若干方法','，创立了西方意象派。他的代表作《地铁车站》就是典型的意象派诗歌：','22154-22186',1,1692091342,1782398608);
INSERT INTO highlights VALUES('3300008362_7_22217-22275','3300008362',7,'第四堂课 写出整首诗的若干方法','出现在人群里这一张张面孔；湿的黑树枝上的一片片花瓣。[插图]','22217-22275',1,1692091330,1782398608);
INSERT INTO highlights VALUES('3300008362_7_21797-21825','3300008362',7,'第四堂课 写出整首诗的若干方法','主观意象完全可以看作是局部的隐喻，或说用单句完成的隐喻。','21797-21825',1,1692091189,1782398608);
INSERT INTO highlights VALUES('3300008362_7_21562-21584','3300008362',7,'第四堂课 写出整首诗的若干方法','隐喻：通过两个事物的对比来表达情感或思想等。','21562-21584',1,1692091149,1782398608);
INSERT INTO highlights VALUES('3300008362_7_18944-18955','3300008362',7,'第四堂课 写出整首诗的若干方法','2．通篇只描绘对应物。','18944-18955',1,1692090805,1782398608);
INSERT INTO highlights VALUES('3300008362_7_18890-18915','3300008362',7,'第四堂课 写出整首诗的若干方法','1．找到想表达的观念事物（情感或思想等）的对应物；','18890-18915',1,1692090797,1782398608);
INSERT INTO highlights VALUES('3300008362_7_16452-16481','3300008362',7,'第四堂课 写出整首诗的若干方法','象征是指通过一个具体事物，表达一个抽象事物（情感、观念等）','16452-16481',1,1692090340,1782398608);
INSERT INTO highlights VALUES('3300008362_7_12361-12879','3300008362',7,'第四堂课 写出整首诗的若干方法','我以为我已把你藏好了藏在那样深那样冷的昔日的心底我以为只要绝口不提只要让日子继续地过去你就终于终于会变成一个古老的秘密可是不眠的夜仍然太长而早生的白发又泄露了我的悲伤[插图]','12361-12878',1,1692089625,1782398608);
INSERT INTO highlights VALUES('3300008362_7_7864-7939','3300008362',7,'第四堂课 写出整首诗的若干方法','先随便写两行客观意象，作为第一节，然后把第一行重复一遍，再改写第二行，作为第二节。以此类推，看四分钟之内能写几节。完成后，大声朗读全诗，听一听音乐效果','7864-7939',1,1692084354,1782398608);
INSERT INTO highlights VALUES('3300008362_7_7456-7478','3300008362',7,'第四堂课 写出整首诗的若干方法','写一段有叠句或叠字的句子，形成一定的音乐性。','7456-7478',1,1692084345,1782398608);
INSERT INTO highlights VALUES('3300008362_7_5803-5833','3300008362',7,'第四堂课 写出整首诗的若干方法','当代中国诗人已把叠句视为，既产生整体结构又产生音效的神奇手段','5803-5833',1,1692083899,1782398608);
INSERT INTO highlights VALUES('3300008362_7_2020-2064','3300008362',7,'第四堂课 写出整首诗的若干方法','通过不时使用叠句，不只可以产生回音似的音效，还提供了支撑整首诗的结构，即一种楼层似的结构','2020-2064',1,1692083459,1782398608);
INSERT INTO highlights VALUES('3300008362_7_1921-1968','3300008362',7,'第四堂课 写出整首诗的若干方法','你看，押韵就相当追忆，只不过叠句的“押韵”更老实，更笨拙，不是追求相似音，是追求完全相同的音。','1921-1968',1,1692083434,1782398608);
INSERT INTO highlights VALUES('3300008362_7_1514-1529','3300008362',7,'第四堂课 写出整首诗的若干方法','这种部分重复的句子，叫重词叠句','1514-1529',1,1692083143,1782398608);
INSERT INTO highlights VALUES('3300008362_7_1436-1451','3300008362',7,'第四堂课 写出整首诗的若干方法','这种完全重复的句子，叫重章叠句','1436-1451',1,1692083096,1782398608);
INSERT INTO highlights VALUES('3300008362_7_1096-1120','3300008362',7,'第四堂课 写出整首诗的若干方法','《诗经》解决音乐性的方法极简单，就是大量使用叠句','1096-1120',1,1692083020,1782398608);
INSERT INTO highlights VALUES('3300008362_6_47439-47534','3300008362',6,'第三堂课 新诗写作的核心','课后习题：每天写一个不超过四行的诗节，至少包含一个主观意象。用一周写一首不超过八行的小诗，每四行至少包含一个主观意象。','47439-47534',1,1691937053,1782398608);
INSERT INTO highlights VALUES('3300008362_6_46956-47108','3300008362',6,'第三堂课 新诗写作的核心','春天把雪线卷得很高而绝白仍隐在雪线之上只有春风偷吻得到[插图]','46956-47107',1,1691937003,1782398608);
INSERT INTO highlights VALUES('3300008362_6_45416-45636','3300008362',6,'第三堂课 新诗写作的核心','人生短——而山里的黑夜长没有流尽的月光——多神秘一个人的感慨——多陈旧就算愤怒——也像土里那踢也踢不动的树根是——隆重的埋葬！ [插图]','45416-45636',1,1691936854,1782398608);
INSERT INTO highlights VALUES('3300008362_6_40535-40576','3300008362',6,'第三堂课 新诗写作的核心','用你的火点燃我的蜡烛','40535-40576',1,1691936410,1782398608);
INSERT INTO highlights VALUES('3300008362_6_40607-40687','3300008362',6,'第三堂课 新诗写作的核心','蜡烛，搂着夜喂奶夜胖了而蜡烛在瘦下去','40607-40687',1,1691936394,1782398608);
INSERT INTO highlights VALUES('3300008362_6_38136-38171','3300008362',6,'第三堂课 新诗写作的核心','所以，阅读对写作的帮助，还可以理解为，是为了知道或排除尽可能多的常识。','38136-38171',1,1691935539,1782398608);
INSERT INTO highlights VALUES('3300008362_6_37880-37961','3300008362',6,'第三堂课 新诗写作的核心','就是让你的心里，始终绷着一根弦：规避常识。我把它称为“泛陌生化”的意识。既然你一时难以直接构造陌生的意象，那你索性采取排除法，写作时，排除一切你熟悉或知道的说法。','37880-37961',1,1691935496,1782398608);
INSERT INTO highlights VALUES('3300008362_6_35024-35053','3300008362',6,'第三堂课 新诗写作的核心','陌生化的本质，是增加人感受事物的难度，延长感受事物的时间。','35024-35053',1,1691935191,1782398608);
INSERT INTO highlights VALUES('3300008362_6_34709-34771','3300008362',6,'第三堂课 新诗写作的核心','写作一定要避开套词套语，原因就是“自动化现象”，只要人们经常看到或用到的东西，他们就会视而不见，这些东西对他们也就不起作用。','34709-34771',1,1691934863,1782398608);
INSERT INTO highlights VALUES('3300008362_6_34334-34351','3300008362',6,'第三堂课 新诗写作的核心','陌生化”是俄国人什克洛夫斯基提出的','34334-34351',1,1691934806,1782398608);
INSERT INTO highlights VALUES('3300008362_6_33977-34053','3300008362',6,'第三堂课 新诗写作的核心','人对熟悉的耐受力是有限度的，一旦超过限度，人就渴望陌生，这是摆脱不掉的人性法则。不管是文学，文化，还是人的日常生活，都能透过表象，找到背后的这条人性法则','33977-34053',1,1691934760,1782398608);
INSERT INTO highlights VALUES('3300008362_6_31790-31892','3300008362',6,'第三堂课 新诗写作的核心','熟悉为人提供安全保障的同时，也摆脱不掉另一个弊端，即人待在熟悉的环境过久，就把日子过成了“太阳底下无新事”，眼前的所有事物，因不会超出预料，就不会令他感到新鲜、刺激或激动，甚至会成为他眼里早已僵死的事物。','31790-31892',1,1691934434,1782398608);
INSERT INTO highlights VALUES('3300008362_6_31277-31304','3300008362',6,'第三堂课 新诗写作的核心','我把诗歌形式背后的人性需要，总结为一句话：熟悉中的陌生','31277-31304',1,1691934362,1782398608);
INSERT INTO highlights VALUES('3300008362_6_29437-29506','3300008362',6,'第三堂课 新诗写作的核心','习题：写一节不超过四行的诗，至少含一个主观意象，要求诗意相对完整。','29437-29506',1,1691934144,1782398608);
INSERT INTO highlights VALUES('3300008362_6_27463-27508','3300008362',6,'第三堂课 新诗写作的核心','独立于淡淡的斜阳里风撩起黑发','27463-27508',1,1691933989,1782398608);
INSERT INTO highlights VALUES('3300008362_6_28065-28104','3300008362',6,'第三堂课 新诗写作的核心','四行是我心目中的一个界限，即写出完整诗意的效率界限，一旦超出四行，效率就偏低。','28065-28104',1,1691933937,1782398608);
INSERT INTO highlights VALUES('3300008362_6_26983-27081','3300008362',6,'第三堂课 新诗写作的核心','一旦日子成了飞驰的卡车生日就是一条救命的斑马线能让卡车带着羞愧，慢下来[插图]','26983-27081',1,1691933835,1782398608);
INSERT INTO highlights VALUES('3300008362_6_26401-26418','3300008362',6,'第三堂课 新诗写作的核心','生活，有多少次我被驱赶进一个句号！','26401-26418',1,1691933817,1782398608);
INSERT INTO highlights VALUES('3300008362_6_26003-26035','3300008362',6,'第三堂课 新诗写作的核心','所谓的最小诗意单元，大约指的是，包含一个完整诗意时最小的诗歌单元','26003-26035',1,1691933679,1782398608);
INSERT INTO highlights VALUES('3300008362_6_20431-20478','3300008362',6,'第三堂课 新诗写作的核心','它在夜风中等你。静静唱着灿烂的歌','20431-20478',1,1691850352,1782398608);
INSERT INTO highlights VALUES('3300008362_6_19455-19497','3300008362',6,'第三堂课 新诗写作的核心','让主观意象准确到位，或让多义的主观意象具有说服力，是主观意象留给诗人的两个可为之处。','19455-19497',1,1691849994,1782398608);
INSERT INTO highlights VALUES('3300008362_6_16678-16857','3300008362',6,'第三堂课 新诗写作的核心','我坐在摇椅上赞美酒精它们深埋于空中的某处我就像空瓶呼吸着我所知道的地下水，我希望时光迅速矿化，重现往日的葡萄[插图]','16678-16857',1,1691849426,1782398608);
INSERT INTO highlights VALUES('3300008362_6_15295-15306','3300008362',6,'第三堂课 新诗写作的核心','那些忧伤比泥土还要密集','15295-15306',1,1691849244,1782398608);
INSERT INTO highlights VALUES('3300008362_6_14859-14906','3300008362',6,'第三堂课 新诗写作的核心','树枝从云层中长出飞鸟向往我的眼睛','14859-14906',1,1691754563,1782398608);
INSERT INTO highlights VALUES('3300008362_6_13985-14126','3300008362',6,'第三堂课 新诗写作的核心','多义的主观意象，迄今已进化出两种，第一种，哪怕意象对应的体悟十分私密，诗人也不在乎读者能否领会；第二种，诗人通过说明或给意象提供特定的语境，提高意象的说服力，令读者可以接近私密体悟。第一种由于不受体悟之累，诗人一般把重点放在语言的美感、意象的神奇上，竭力发挥想象力，创造语言的可能。','13985-14126',1,1691754442,1782398608);
INSERT INTO highlights VALUES('3300008362_6_13221-13250','3300008362',6,'第三堂课 新诗写作的核心','追求多义的主观意象，可以造成意象的神奇，需要诗人脑洞大开。','13221-13250',1,1691753735,1782398608);
INSERT INTO highlights VALUES('3300008362_6_12010-12128','3300008362',6,'第三堂课 新诗写作的核心','起身的时候可以清楚听见那些光线在我体内折断的声音[插图]','12010-12128',1,1691753547,1782398608);
INSERT INTO highlights VALUES('3300008362_6_11836-11902','3300008362',6,'第三堂课 新诗写作的核心','意味你的意象含有的体悟，可以被他人的类似体悟验证，无数个他人就成了你意象的裁判，有能力判定意象含有的体悟是否真实，是否与生活经验一致','11836-11902',1,1691753399,1782398608);
INSERT INTO highlights VALUES('3300008362_6_7047-7065','3300008362',6,'第三堂课 新诗写作的核心','青春是被仇恨啃过的，布满牙印的骨头”','7047-7065',1,1691746871,1782398608);
INSERT INTO highlights VALUES('3300008362_6_4661-4747','3300008362',6,'第三堂课 新诗写作的核心','“夕阳是遗忘在西边的一把椅子，苦苦等着人们坐上去。”由于“夕阳”与“椅子”处于同一情景，关联就在情景之内产生。读者一旦进入这一特定情景，就不再觉得“夕阳”与“椅子”无甚关联','4661-4747',1,1691746117,1782398608);
INSERT INTO highlights VALUES('3300008362_6_3769-3800','3300008362',6,'第三堂课 新诗写作的核心','第二种：设法创造一个情景或情景说明，使事物A与事物B产生关联。','3769-3800',1,1691745974,1782398608);
INSERT INTO highlights VALUES('3300008362_6_3590-3620','3300008362',6,'第三堂课 新诗写作的核心','先大胆设想出B，如果发现实在没有关联，就通过创造情景产生关联','3590-3620',1,1691745938,1782398608);
INSERT INTO highlights VALUES('3300008362_6_2500-2549','3300008362',6,'第三堂课 新诗写作的核心','第一种：单凭事物A与事物B彼此的特征或状态，就能一目了然，或往深处多想一步，就能意识到彼此的关联。','2500-2549',1,1691745800,1782398608);
INSERT INTO highlights VALUES('3300008362_6_1996-2011','3300008362',6,'第三堂课 新诗写作的核心','平底锅下的火环，被他拧为日落”','1996-2011',1,1691745688,1782398608);
INSERT INTO highlights VALUES('3300008362_6_1059-1081','3300008362',6,'第三堂课 新诗写作的核心','我们既迷恋对立中的差异，又迷恋差异中的统一，','1059-1081',1,1691745526,1782398608);
INSERT INTO highlights VALUES('3300008362_6_927-967','3300008362',6,'第三堂课 新诗写作的核心','但从现在起，我们强调A与B不搭界的同时，再增加一个要求，即还要找到两者的一点关联','927-967',1,1691745513,1782398608);
INSERT INTO highlights VALUES('3300008362_5_56505-56775','3300008362',5,'第二堂课 一堂课学会写出好诗句','乌云——黄昏的假睫毛桥梁伸懒腰时眼泪开始跳河一对恋人在我们种下的路灯旁接吻我们的爱情是被汽车撞烂了的水果摊','56505-56775',1,1691723774,1782398608);
INSERT INTO highlights VALUES('3300008362_5_57289-57420','3300008362',5,'第二堂课 一堂课学会写出好诗句','模式①某场景中用错搭模式替换某物模式② A是B模式③用B解释A模式④让A去做A做不到的事','57289-57420',1,1691723748,1782398608);
INSERT INTO highlights VALUES('3300008362_5_57083-57140','3300008362',5,'第二堂课 一堂课学会写出好诗句','维柯在《新科学》中已提示：“最初的诗人们给事物命名，就必须用最具体的感性意象，这种感性意象就是替换和转喻的来源。”','57083-57140',1,1691723704,1782398608);
INSERT INTO highlights VALUES('3300008362_5_55045-55062','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗意不来自世界，而来自诗人的注视。','55045-55062',1,1691723293,1782398608);
INSERT INTO highlights VALUES('3300008362_5_54249-54264','3300008362',5,'第二堂课 一堂课学会写出好诗句','中国诗人洛夫写的《子夜读信》。','54249-54264',1,1691723155,1782398608);
INSERT INTO highlights VALUES('3300008362_5_53196-53231','3300008362',5,'第二堂课 一堂课学会写出好诗句','北岛《回答》里的诗句，“卑鄙是卑鄙者的通行证／高尚是高尚者的墓志铭”，','53196-53231',1,1691723040,1782398608);
INSERT INTO highlights VALUES('3300008362_5_50650-50659','3300008362',5,'第二堂课 一堂课学会写出好诗句','能采取悖论式的表述','50650-50659',1,1691722678,1782398608);
INSERT INTO highlights VALUES('3300008362_5_50700-50862','3300008362',5,'第二堂课 一堂课学会写出好诗句','“我总在接近欢乐，也接近友好的痛苦。”[插图]直述表达为了解决含义单一的问题，只能引入悖论，引起理解上的歧义。','50700-50862',1,1691722659,1782398608);
INSERT INTO highlights VALUES('3300008362_5_50345-50358','3300008362',5,'第二堂课 一堂课学会写出好诗句','你自由了，却不如一颗豌豆。','50345-50358',1,1691722601,1782398608);
INSERT INTO highlights VALUES('3300008362_5_49959-49985','3300008362',5,'第二堂课 一堂课学会写出好诗句','当八月中旬我初次站在热气腾腾的街道，像个快熟的肉包子','49959-49985',1,1691722595,1782398608);
INSERT INTO highlights VALUES('3300008362_5_50537-50574','3300008362',5,'第二堂课 一堂课学会写出好诗句','意象可以表达很多你无法表达的东西，甚至潜意识里的东西，真正做到言尽意无穷。','50537-50574',1,1691722588,1782398608);
INSERT INTO highlights VALUES('3300008362_5_47486-47508','3300008362',5,'第二堂课 一堂课学会写出好诗句','雪莱说过的一句话：“诗人是世界未公认的立法者','47486-47508',1,1691721913,1782398608);
INSERT INTO highlights VALUES('3300008362_5_45988-46073','3300008362',5,'第二堂课 一堂课学会写出好诗句','1．写下事物A；2．列出A做不到的事；3．硬让A去做。','45988-46073',1,1691721745,1782398608);
INSERT INTO highlights VALUES('3300008362_5_45907-45923','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗句模式④：让A做A做不到的事。','45907-45923',1,1691721737,1782398608);
INSERT INTO highlights VALUES('3300008362_5_45488-45517','3300008362',5,'第二堂课 一堂课学会写出好诗句','让一个人或某个事物，去做他（它）做不到的事，诗意就会诞生。','45488-45517',1,1691721698,1782398608);
INSERT INTO highlights VALUES('3300008362_5_45006-45084','3300008362',5,'第二堂课 一堂课学会写出好诗句','很多文学“发现”，就是需要挣脱生活的束缚，你越是能没心没肺地胡想、错搭，就越是能打开一个诗意的世界。写诗也可以理解为纠错：把一扇扇被生活锈死的门，重新打开。','45006-45084',1,1691721657,1782398608);
INSERT INTO highlights VALUES('3300008362_5_44483-44512','3300008362',5,'第二堂课 一堂课学会写出好诗句','汤勺是盲诗人的空眼窝，“它宁愿空着眼窝，也不要汤水给它眼睛','44483-44512',1,1691721569,1782398608);
INSERT INTO highlights VALUES('3300008362_5_41117-41134','3300008362',5,'第二堂课 一堂课学会写出好诗句','这就是拉康在《宗教的凯旋》中说的，','41117-41134',1,1691720836,1782398608);
INSERT INTO highlights VALUES('3300008362_5_41135-41178','3300008362',5,'第二堂课 一堂课学会写出好诗句','所有新的意义只能从一个能指对另一个能指的替换中产生，这是隐喻的维度，由此现实承载诗歌。','41135-41178',1,1691720820,1782398608);
INSERT INTO highlights VALUES('3300008362_5_40951-40986','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗句模式③（或叫B解释A）：用事物B重新解释事物A（A与B不太搭界）。','40951-40986',1,1691720706,1782398608);
INSERT INTO highlights VALUES('3300008362_5_40281-40290','3300008362',5,'第二堂课 一堂课学会写出好诗句','彼之蜜糖，吾之砒霜','40281-40290',1,1691720398,1782398608);
INSERT INTO highlights VALUES('3300008362_5_39497-39510','3300008362',5,'第二堂课 一堂课学会写出好诗句','蝴蝶是秋天不肯落地的落叶”','39497-39510',1,1691720313,1782398608);
INSERT INTO highlights VALUES('3300008362_5_39302-39311','3300008362',5,'第二堂课 一堂课学会写出好诗句','夜晚是烧尽的烟头”','39302-39311',1,1691720213,1782398608);
INSERT INTO highlights VALUES('3300008362_5_38230-38274','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗句模式②：A是B（A与B不太搭界。“是”还可以替换成“像”“如”“似”“属于”等等）。','38230-38274',1,1691718064,1782398608);
INSERT INTO highlights VALUES('3300008362_5_37825-37858','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗句模式①（或叫A的B）：将某现实场景中的某物，用错搭模式替换掉。','37825-37858',1,1691718021,1782398608);
INSERT INTO highlights VALUES('3300008362_5_37132-37312','3300008362',5,'第二堂课 一堂课学会写出好诗句','1．先用一句话，写出某个现实场景（或现实中可能存在的场景）；2．选择该场景中的某个事物A，找出不太搭界的事物B与之错搭，形成错搭模式“A的B”；3．把错搭模式“A的B”，放回原来的句子，替换掉事物A，即用“A的B”替换掉“A”，诗句就大功告成。','37132-37312',1,1691717957,1782398608);
INSERT INTO highlights VALUES('3300008362_5_35396-35402','3300008362',5,'第二堂课 一堂课学会写出好诗句','巨石的温柔。','35396-35402',1,1691717820,1782398608);
INSERT INTO highlights VALUES('3300008362_5_32432-32608','3300008362',5,'第二堂课 一堂课学会写出好诗句','我认为，它就来自人性自身的悖论。人天然追求安全，同时也追求冒险。人性悖论会要求诗歌并置事物时，寻找两个不太搭界的事物，以便用两个旧事物，能轻易并置出新事物。错搭中使用的旧事物，因为人们常见、熟悉，体现了人对安全的追求，错搭出的新事物，则迎合了人冒险的诉求，因为它新鲜、陌生。用旧事物组合出新事物，是人人可以参与的事，不必再依赖天才或“天眼”的神秘之法。','32432-32608',1,1691715812,1782398608);
INSERT INTO highlights VALUES('3300008362_5_32027-32054','3300008362',5,'第二堂课 一堂课学会写出好诗句','要像脑子进水一样，疯疯癫癫，把不相干的东西搭配在一起。','32027-32054',1,1691715692,1782398608);
INSERT INTO highlights VALUES('3300008362_5_31895-31986','3300008362',5,'第二堂课 一堂课学会写出好诗句','我把这种模式叫“错搭模式”，我为错搭模式总结出了一个公式：A的B。这里的A和B，分别是两个不太搭界的事物。正因为不太搭界，普通人没事不会把两者搭配在一起，所以，我才称这种搭配叫错搭。','31895-31986',1,1691715674,1782398608);
INSERT INTO highlights VALUES('3300008362_5_30653-30668','3300008362',5,'第二堂课 一堂课学会写出好诗句','“月亮的龙骨／冲破紫色的云雾”','30653-30668',1,1691715552,1782398608);
INSERT INTO highlights VALUES('3300008362_5_30348-30360','3300008362',5,'第二堂课 一堂课学会写出好诗句','一只夜的手臂／伸进我的窗','30348-30360',1,1691715434,1782398608);
INSERT INTO highlights VALUES('3300008362_5_29782-29804','3300008362',5,'第二堂课 一堂课学会写出好诗句','绿色的火焰在草上摇曳／它渴求着拥抱你花朵”。','29782-29804',1,1691715404,1782398608);
INSERT INTO highlights VALUES('3300008362_5_30067-30105','3300008362',5,'第二堂课 一堂课学会写出好诗句','洛尔卡的诗句，他在《凝滞，最后的歌》中写道：“月光的光芒／敲打着黄昏的铁砧。','30067-30105',1,1691715387,1782398608);
INSERT INTO highlights VALUES('3300008362_5_27105-27151','3300008362',5,'第二堂课 一堂课学会写出好诗句','据说普希金写诗的方法，就类似习题三。他先用散文把想写的内容，完整地写出来，再将散文改写成诗歌','27105-27151',1,1691714655,1782398608);
INSERT INTO highlights VALUES('3300008362_5_26494-26498','3300008362',5,'第二堂课 一堂课学会写出好诗句','习题三：','26494-26498',1,1691714633,1782398608);
INSERT INTO highlights VALUES('3300008362_5_26252-26256','3300008362',5,'第二堂课 一堂课学会写出好诗句','习题二：','26252-26256',1,1691714619,1782398608);
INSERT INTO highlights VALUES('3300008362_5_25518-25568','3300008362',5,'第二堂课 一堂课学会写出好诗句','人一旦遭遇不完整的描述，作品又有一定的形式暗示，人就会本能地调动想象，自行在脑中“造出”缺失的事物。','25518-25568',1,1691679199,1782398608);
INSERT INTO highlights VALUES('3300008362_5_25112-25186','3300008362',5,'第二堂课 一堂课学会写出好诗句','用客观意象写诗时，难度更大的是“逻辑跳跃”或叫“蒙太奇手法”。它的实质是让原本完整的描述和逻辑，通过故意缺失或省略某些部分，造成仿佛处于未完成状态。','25112-25186',1,1691679142,1782398608);
INSERT INTO highlights VALUES('3300008362_5_24381-24413','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗人叶辉有一首六行诗《礼物》，可以说兼顾了穿插和诗尾的染色之道。','24381-24413',1,1691679106,1782398608);
INSERT INTO highlights VALUES('3300008362_5_20845-20873','3300008362',5,'第二堂课 一堂课学会写出好诗句','归纳起来就是从客观意象的某处，插入诗人的主观感慨等说明。','20845-20873',1,1691678478,1782398608);
INSERT INTO highlights VALUES('3300008362_5_20785-20845','3300008362',5,'第二堂课 一堂课学会写出好诗句','刻意把说明插在客观意象的中间，且说明部分主要是诗人的内心独白等感慨，这种属于染色特例的方法，被一些学者称为“穿插技巧”。','20785-20845',1,1691678468,1782398608);
INSERT INTO highlights VALUES('3300008362_5_17406-17442','3300008362',5,'第二堂课 一堂课学会写出好诗句','描述完客观意象，再用说明、对比、拟人等方式，写出有情感或立场色彩的句子。','17406-17442',1,1691668723,1782398608);
INSERT INTO highlights VALUES('3300008362_5_17113-17139','3300008362',5,'第二堂课 一堂课学会写出好诗句','难免会落得作品优美、迷人，却内涵单薄、视野局限的声名','17113-17139',1,1691668622,1782398608);
INSERT INTO highlights VALUES('3300008362_5_16559-16569','3300008362',5,'第二堂课 一堂课学会写出好诗句','像迎接你到来时一样”','16559-16569',1,1691668455,1782398608);
INSERT INTO highlights VALUES('3300008362_5_16440-16468','3300008362',5,'第二堂课 一堂课学会写出好诗句','我修剪你种下的树／我照看你撇下的花房／我让窗子四季敞开”','16440-16468',1,1691668446,1782398608);
INSERT INTO highlights VALUES('3300008362_5_16046-16062','3300008362',5,'第二堂课 一堂课学会写出好诗句','洛尔卡是20世纪西班牙的伟大诗人','16046-16062',1,1691668341,1782398608);
INSERT INTO highlights VALUES('3300008362_5_15768-15838','3300008362',5,'第二堂课 一堂课学会写出好诗句','古人写诗时，一旦使用了大量客观意象，等描述完客观意象，他一定会添上有情感或立场色彩的诗句，来给前面写的客观意象“染色”，染上情感或立场之色。','15768-15838',1,1691668258,1782398608);
INSERT INTO highlights VALUES('3300008362_5_15303-15338','3300008362',5,'第二堂课 一堂课学会写出好诗句','《诗经》中的诗句，带来的身临其境之感，恰恰得益于客观意象的描绘和营造。','15303-15338',1,1691668181,1782398608);
INSERT INTO highlights VALUES('3300008362_5_13380-13431','3300008362',5,'第二堂课 一堂课学会写出好诗句','好的主观意象甚至可以彻底摆脱对外部形式的依赖，就算把它置于诗以外的体裁中，它的诗意仍有抗环境的耐受力。','13380-13431',1,1691660161,1782398608);
INSERT INTO highlights VALUES('3300008362_5_12881-13058','3300008362',5,'第二堂课 一堂课学会写出好诗句','夏宇的《甜蜜的仇恨》为例：把你的影子加点盐腌起来风干老的时候下酒','12881-13058',1,1691660105,1782398608);
INSERT INTO highlights VALUES('3300008362_5_12848-12875','3300008362',5,'第二堂课 一堂课学会写出好诗句','一句话，为了确保新诗有足够的诗意，更多要仰赖主观意象。','12848-12875',1,1691660057,1782398608);
INSERT INTO highlights VALUES('3300008362_5_10007-10039','3300008362',5,'第二堂课 一堂课学会写出好诗句','这种试图把抽象概念形象化的做法，十分重要，是诗歌表达的重要理念。','10007-10039',1,1691659226,1782398608);
INSERT INTO highlights VALUES('3300008362_5_8323-8362','3300008362',5,'第二堂课 一堂课学会写出好诗句','这说明什么？说明通过阅读语言，浮现在脑海中的画面，比实景图片呈现的画面要丰富。','8323-8362',1,1691659004,1782398608);
INSERT INTO highlights VALUES('3300008362_5_7707-7791','3300008362',5,'第二堂课 一堂课学会写出好诗句','一旦在诗中启用这些非意象事物，为了使之不徒然无效，你时常得用意象来救场：通过将观念与意象搭配，让观念产生可以触摸的感觉，即让空洞的观念落到有形象的事物上，产生及物之感。','7707-7791',1,1691658947,1782398608);
INSERT INTO highlights VALUES('3300008362_5_7576-7601','3300008362',5,'第二堂课 一堂课学会写出好诗句','意象的对立面，是抽象事物或观念事物，或叫非意象事物','7576-7601',1,1691658917,1782398608);
INSERT INTO highlights VALUES('3300008362_5_6342-6396','3300008362',5,'第二堂课 一堂课学会写出好诗句','意象有两种：一种指物体或物象，我把它称作“客观意象”；还有一种指想象的、内心的图景，我把它称作“主观意象”。','6342-6396',1,1691658630,1782398608);
INSERT INTO highlights VALUES('3300008362_5_5649-5675','3300008362',5,'第二堂课 一堂课学会写出好诗句','诗歌除了有容易记忆的功能，还有抓住各种瞬间感觉的能力','5649-5675',1,1691658491,1782398608);
INSERT INTO highlights VALUES('3300008362_5_5094-5191','3300008362',5,'第二堂课 一堂课学会写出好诗句','通过写诗训练，你可以释放出语言潜能，培育出敏锐的语感，重新认识词与词的微妙搭配，摆脱日常语言对你的束缚，极大解放你的想象力。你的笔需要长出更多、更纤敏的语言触须，来供小说、散文、应用文写作之用。','5094-5191',1,1691658400,1782398608);
INSERT INTO highlights VALUES('3300008362_5_3452-3508','3300008362',5,'第二堂课 一堂课学会写出好诗句','当风的彩旗，像一片被缚住的波浪。（汪曾祺《彩旗》）','3452-3508',1,1691658142,1782398608);
INSERT INTO highlights VALUES('3300008362_5_3041-3062','3300008362',5,'第二堂课 一堂课学会写出好诗句','追求诗意，是让语言脱离庸常、俗气的唯一途径','3041-3062',1,1691657984,1782398608);
INSERT INTO highlights VALUES('3300008362_5_1038-1087','3300008362',5,'第二堂课 一堂课学会写出好诗句','你接触诗人会发现，一旦涉及写作，他们考虑的问题都很小，入口小，擅长见微知著，以小搏大，四两拨千斤。','1038-1087',1,1691657685,1782398608);
INSERT INTO highlights VALUES('3300008362_5_613-634','3300008362',5,'第二堂课 一堂课学会写出好诗句','新诗受局部诗意的支配较多，局部难，整体易。','613-634',1,1691657584,1782398608);
INSERT INTO highlights VALUES('3300008362_5_663-687','3300008362',5,'第二堂课 一堂课学会写出好诗句','我后面要讲的小说正好相反，小说是整体难，局部易。','663-687',1,1691657572,1782398608);
INSERT INTO highlights VALUES('3300008362_4_42584-42837','3300008362',4,'第一堂课 受用一生的写作观念','新诗阅读捷径：（国内）何其芳→穆旦→顾城→多多→新诗年选（国外）狄金森→弗罗斯特→策兰→辛波丝卡→阿多尼斯小说阅读捷径：（国内）施蛰存→白先勇→韩少功→马原→小说年选（国外）契诃夫→海明威→卡夫卡→博尔赫斯→麦克尤恩','42584-42837',1,1691568910,1782398608);
INSERT INTO highlights VALUES('3300008362_4_43018-43139','3300008362',4,'第一堂课 受用一生的写作观念','每天定时定点，用半小时做如下练习。选择任意主题，比如父亲、冬天、踏青、失败、羞耻、孤独等，限时十分钟写满二百字，反复朗读，通过听音来修订。再选一主题，重复上述练习。此练习要点有二，一是不管文字好坏，快写初稿；二是通过朗读的听觉效果来修改文字。','43018-43139',1,1691568857,1782398608);
INSERT INTO highlights VALUES('3300008362_4_42438-42529','3300008362',4,'第一堂课 受用一生的写作观念','敢于书写主人翁内心的幽暗，敢于让读者误解作者是个“肮脏的人”。初写者要想写好，真正踏上探索写作艺术的旅途，就要主动承受被误解的风险，不突破这道心理关，你的写作就会充满伪善，虚假，说教','42438-42529',1,1691568782,1782398608);
INSERT INTO highlights VALUES('3300008362_4_41476-41596','3300008362',4,'第一堂课 受用一生的写作观念','一旦作品人物，与作者生活中的原型扯上关系，护短心理就令作者如临大敌，不敢放手塑造作品人物。作者担心要是把作品人物写得比较败坏、阴暗，甚至邪恶，家人、朋友或读者就会以为，作品人物正是作者本人，或作者的家人或朋友，写作就成为他人眼中的“毁容”。','41476-41596',1,1691568540,1782398608);
INSERT INTO highlights VALUES('3300008362_4_40986-41028','3300008362',4,'第一堂课 受用一生的写作观念','语言脱敏”指的是，写作者每天写到一定时间或字数，就失去对语言的敏感，丧失审美判断力。','40986-41028',1,1691568202,1782398608);
INSERT INTO highlights VALUES('3300008362_4_40860-40964','3300008362',4,'第一堂课 受用一生的写作观念','我已如此行事20年，每天写的字数不超过1000字，4小时一到，哪怕字数没到1000字，也马上停笔；或4小时还没到，字数已够1000字，也马上停笔。这样可以避免写作时间过长，或写作字数过多，令我难以判断语言好坏','40860-40964',1,1691568184,1782398608);
INSERT INTO highlights VALUES('3300008362_4_40622-40638','3300008362',4,'第一堂课 受用一生的写作观念','他们的限产中含着语言的洁癖，自律','40622-40638',1,1691568116,1782398608);
INSERT INTO highlights VALUES('3300008362_4_40380-40396','3300008362',4,'第一堂课 受用一生的写作观念','海明威4小时一般写不到800字，','40380-40396',1,1691568078,1782398608);
INSERT INTO highlights VALUES('3300008362_4_40024-40081','3300008362',4,'第一堂课 受用一生的写作观念','重要的是让某些东西或环境与你的写作，结成彼此熟悉的对子，仿佛它们是你写作的开关按钮，你一触碰按钮，写作就会找到感觉','40024-40081',1,1691568034,1782398608);
INSERT INTO highlights VALUES('3300008362_4_38935-38972','3300008362',4,'第一堂课 受用一生的写作观念','他们让灵感集中出现的秘诀，就是初写者认为微不足道的写作纪律：定时定点写作。','38935-38972',1,1691567861,1782398608);
INSERT INTO highlights VALUES('3300008362_4_38360-38367','3300008362',4,'第一堂课 受用一生的写作观念','定时定点写作。','38360-38367',1,1691567772,1782398608);
INSERT INTO highlights VALUES('3300008362_4_37766-37851','3300008362',4,'第一堂课 受用一生的写作观念','比如，为何很多人会天天写网文，甚至有人天天写诗，但他们不认为自己想当作家。道理再简单不过，他们有把内心的情感、感觉等，审美化的内在需要，写作不过是迎合内心的审美需要而已，','37766-37851',1,1691567696,1782398608);
INSERT INTO highlights VALUES('3300008362_4_37637-37674','3300008362',4,'第一堂课 受用一生的写作观念','审美要求从高往低（由塔尖往下）依次是：诗歌、小说、散文、信（便条）、诉说。','37637-37674',1,1691567627,1782398608);
INSERT INTO highlights VALUES('3300008362_4_37398-37418','3300008362',4,'第一堂课 受用一生的写作观念','。这些不满足诉说的人，就会用写来代替说。','37398-37418',1,1691567572,1782398608);
INSERT INTO highlights VALUES('3300008362_4_36853-37136','3300008362',4,'第一堂课 受用一生的写作观念','黄氏理论认为，高兴、悲伤、忧郁、孤独、痛苦、爱、恨、虚无等情感、情绪、感觉，如果只是堆积在心里，它们是无序的、混沌的、无形的、模糊的，如百爪挠心，难以触摸，人对这样的内心状况不会满意，会本能地想改变它。普通人能找到的改变方式，就是诉说。诉说时，人需要用语言把内心堆积的东西，一句一句说出来。这样原本无序的感觉等，就有了语言秩序；原本混沌的感觉等，就有了时间、逻辑的顺序；原本无形的、模糊的感觉等，因为语言有明确含义，就会得到明确描述，变得有形可感。你会发现，诉说本身就是一个审美化的过程。与人把身外之物审美化一样，人人也有把身内之物的情感、情绪、感觉等，审美化的需要','36853-37136',1,1691567476,1782398608);
INSERT INTO highlights VALUES('3300008362_4_36432-36463','3300008362',4,'第一堂课 受用一生的写作观念','人有把身边的一切用品、环境等，全部审美化的需要。人是审美动物，','36432-36463',1,1691567361,1782398608);
INSERT INTO highlights VALUES('3300008362_4_35996-36104','3300008362',4,'第一堂课 受用一生的写作观念','一句话，写作可教说的是，我不知你是否有天赋，但可以先把你训练成职业作家（如同机械专业可以把普通人训练成机械工程师，绘画专业可以把普通人训练成职业画家），天赋之事就交给你自己日后去慢慢发现，那将决定你能否成为一流人物。','35996-36104',1,1691567273,1782398608);
INSERT INTO highlights VALUES('3300008362_4_35733-35819','3300008362',4,'第一堂课 受用一生的写作观念','要成为任何领域的一流人物，除了勤奋，还必须要有天赋，没有普通人会把自己轻易列入人数稀少的天才行列；但千千万万的普通人经过专业训练，都能成为各行各业的职业专家（包括职业作家）','35733-35819',1,1691567213,1782398608);
INSERT INTO highlights VALUES('3300008362_4_33463-33521','3300008362',4,'第一堂课 受用一生的写作观念','主题的实质就是，人把作品看成一个有何种意义的整体。过去的语文老师都错误地认为，此整体是唯一的，且完全取决于作品本身。','33463-33521',1,1691566748,1782398608);
INSERT INTO highlights VALUES('3300008362_4_32145-32207','3300008362',4,'第一堂课 受用一生的写作观念','人天生有完形的需要和能力，倾向按一定形式把经验材料看成整体。第二，人会把经验材料看成什么样的整体，是主观之事，与经验材料无关','32145-32207',1,1691566565,1782398608);
INSERT INTO highlights VALUES('3300008362_4_31985-32105','3300008362',4,'第一堂课 受用一生的写作观念','格式塔心理学认为，完形是人先天就有的（先验的），与人的经验材料无关。人会倾向把一堆事物看作整体，但他从中能看出什么样的整体，则依照“完形组织法则”。完形组织法则说的是，人在感知事物时，会按照一定的形式，把眼前的经验材料，组织成有意义的整体。','31985-32105',1,1691566483,1782398608);
INSERT INTO highlights VALUES('3300008362_4_31468-31527','3300008362',4,'第一堂课 受用一生的写作观念','格式塔心理学也叫完形心理学，我觉得“完形”一词，点出了它的要点。所谓完形，指的是心理上的整体观，即人会整体地看待事物。','31468-31527',1,1691566389,1782398608);
INSERT INTO highlights VALUES('3300008362_4_31392-31439','3300008362',4,'第一堂课 受用一生的写作观念','你可能接着会问，为什么只用一个标题，就能创造出整体感？要想明白这一点，就需要提及格式塔心理学。','31392-31439',1,1691566370,1782398608);
INSERT INTO highlights VALUES('3300008362_4_30389-30439','3300008362',4,'第一堂课 受用一生的写作观念','这是人们为了避免陷入一堆事实的迷宫，为了让自己安心，用因果律进行的主观关联，实质是虚构、反常、夸张。','30389-30439',1,1691566054,1782398608);
INSERT INTO highlights VALUES('3300008362_4_28973-29005','3300008362',4,'第一堂课 受用一生的写作观念','还有一种逻辑关联，若赋予生活也会显得夸张，就是大家熟悉的因果律。','28973-29005',1,1691565640,1782398608);
INSERT INTO highlights VALUES('3300008362_4_27103-27164','3300008362',4,'第一堂课 受用一生的写作观念','所有动物都有性喜夸大（夸张）的本能，但选择夸大（夸张）什么，取决于生存需要。什么东西对生存重要，它们就选择夸大（夸张）什么','27103-27164',1,1691565029,1782398608);
INSERT INTO highlights VALUES('3300008362_4_26661-26678','3300008362',4,'第一堂课 受用一生的写作观念','怎么写的问题，牵连到文学表达的实质','26661-26678',1,1691564758,1782398608);
INSERT INTO highlights VALUES('3300008362_4_26200-26248','3300008362',4,'第一堂课 受用一生的写作观念','只是他们并不知道，不是写作之初的设想，把人物带到了这个结局，是写作过程改变了小说进展和人物结局。','26200-26248',1,1691564473,1782398608);
INSERT INTO highlights VALUES('3300008362_4_25123-25219','3300008362',4,'第一堂课 受用一生的写作观念','你领到这个主题，真就可以代替你读《白鲸》吗？厚厚一本书的世界，真可以用一句话穷尽吗？其实作品的每种真实，都可以找到一个主题与之对应，读者能从作品中看出什么主题，看出多少主题，是因人因时而异的。','25123-25219',1,1691564229,1782398608);
INSERT INTO highlights VALUES('3300008362_4_24975-25001','3300008362',4,'第一堂课 受用一生的写作观念','中心思想或单一主题，怎么能代替丰富立体的阅读感受呢？','24975-25001',1,1691564173,1782398608);
INSERT INTO highlights VALUES('3300008362_4_24646-24716','3300008362',4,'第一堂课 受用一生的写作观念','作者心中当然不会有唯一的“中心思想”，他写作品时，触及的真实是多重的、立体的、复杂的，他并不知道语文老师，会把哪种真实规定为作品的唯一真实。','24646-24716',1,1691564124,1782398608);
INSERT INTO highlights VALUES('3300008362_4_24228-24307','3300008362',4,'第一堂课 受用一生的写作观念','文学真实是多义的，就能想通，为何每一代学者都会重新诠释经典，每一次的诠释，都赋予作品新的真实，所有这些不同的真实，令经典变得立体、丰富，成为永远谈不完的话题。','24228-24307',1,1691564077,1782398608);
INSERT INTO highlights VALUES('3300008362_4_24033-24095','3300008362',4,'第一堂课 受用一生的写作观念','了“人在共同体中的孤独感”。家庭是一个小共同体，社会是一个大共同体。人置身共同体中，渐渐会产生孤独感，这是现代人的普遍境遇。','24033-24095',1,1691563766,1782398608);
INSERT INTO highlights VALUES('3300008362_4_23685-23722','3300008362',4,'第一堂课 受用一生的写作观念','文学真实的价值恰恰就在，关闭了通向唯一解释的通道，打开了多义、朦胧的大门。','23685-23722',1,1691563606,1782398608);
INSERT INTO highlights VALUES('3300008362_4_23246-23313','3300008362',4,'第一堂课 受用一生的写作观念','作家遭遇“生活事实”时，为了文学需要，如何把生活事实变成“事象”（虚构的事实），再用文学手段，让事象负载一些意义，来达成“文学真实”。','23246-23313',1,1691563524,1782398608);
INSERT INTO highlights VALUES('3300008362_4_22037-22103','3300008362',4,'第一堂课 受用一生的写作观念','“人变成甲虫”这一类虚构的事实，统统称作事象。你大概已看出，事象与事实一样，也是没有倾向的，不自带意义的，等着人来赋予它倾向或意义。','22037-22103',1,1691563305,1782398608);
INSERT INTO highlights VALUES('3300008362_4_21914-21956','3300008362',4,'第一堂课 受用一生的写作观念','文学中还有一类“事实”，你不靠想象虚构它，它就不存在，我把这类虚构的事实，叫“事象”','21914-21956',1,1691563289,1782398608);
INSERT INTO highlights VALUES('3300008362_4_21687-21764','3300008362',4,'第一堂课 受用一生的写作观念','因为生活事实本身不具有推断的逻辑和能力，本身产生不了倾向或意义，除非由人来赋予。苏格拉底之所以会说，不经过思考的人生，是不值得过的，大约也是出于类似的理由','21687-21764',1,1691563106,1782398608);
INSERT INTO highlights VALUES('3300008362_4_21298-21318','3300008362',4,'第一堂课 受用一生的写作观念','所谓的真实是指赋予事实合理的倾向或意义。','21298-21318',1,1691562944,1782398608);
INSERT INTO highlights VALUES('3300008362_4_20954-20985','3300008362',4,'第一堂课 受用一生的写作观念','日常生活里其实只有事实。所谓的事实，就是客观存在且无倾向的事物','20954-20985',1,1691562636,1782398608);
INSERT INTO highlights VALUES('3300008362_4_20425-20539','3300008362',4,'第一堂课 受用一生的写作观念','按照老掉牙的传统说法，如果你前面提到墙上挂着一把枪，后面就要设法让这把枪开火，目的是把已写的普通场景，变成看起来十分巧妙的伏笔。用这个思路来写开头，就是我说的方法，怎么开头也就不重要，关键是如何通过后续的写作，让开头变得不可或缺','20425-20539',1,1691562453,1782398608);
INSERT INTO highlights VALUES('3300008362_4_20045-20099','3300008362',4,'第一堂课 受用一生的写作观念','我们都知道，必须做的事与意外天成的事，永远有一定的比例，大师也无法把每篇开头，都写成令其他开头都逊色的珠峰。','20045-20099',1,1691562331,1782398608);
INSERT INTO highlights VALUES('3300008362_4_18530-18555','3300008362',4,'第一堂课 受用一生的写作观念','两百年前就有人发明了结尾写作法，发明者是爱伦·坡。','18530-18555',1,1691562090,1782398608);
INSERT INTO highlights VALUES('3300008362_4_18400-18490','3300008362',4,'第一堂课 受用一生的写作观念','结尾写作法，一来迫使你的写作面对未知，能极大激发想象力，松开捆绑你的理性锁链，二来已有的结尾，提供了故事或情节发展的方向和目的地，避免即兴发挥的自由，陷入漫无目的、混乱、结构失调。','18400-18490',1,1691562023,1782398608);
INSERT INTO highlights VALUES('3300008362_4_17627-17697','3300008362',4,'第一堂课 受用一生的写作观念','我喜欢把目光投向生活或新闻，从中汲取的精华不是什么故事，真正让我激动的，是形形色色事件的结尾。这些由现实逻辑演绎的结尾，含着人们正承受的重负','17627-17697',1,1691561265,1782398608);
INSERT INTO highlights VALUES('3300008362_4_16323-16390','3300008362',4,'第一堂课 受用一生的写作观念','日常生活中，有一种不被人看重的写作，能带给你作家一样的写作体验，能让你留意到自动写作强调的即兴发挥，会如何参与写作，这种写作就是写信。','16323-16390',1,1691462120,1782398608);
INSERT INTO highlights VALUES('3300008362_4_16608-16706','3300008362',4,'第一堂课 受用一生的写作观念','真正的写作，是让你把写作交给内心的两个自我管辖，让理性的自我预先画出“鱼”的样子，又让即兴探索的自我推动着“鱼”一步一步向前演变，进化成“智人”。学会同时发掘两个自我的潜力，正是写作课欲达成的目标','16608-16706',1,1691462104,1782398608);
INSERT INTO highlights VALUES('3300008362_4_15898-15940','3300008362',4,'第一堂课 受用一生的写作观念','我的朋友王珂教授，近年用诗歌来治疗抑郁症患者，用文学来释放不良的潜意识，据说疗效不错','15898-15940',1,1691461965,1782398608);
INSERT INTO highlights VALUES('3300008362_4_15221-15437','3300008362',4,'第一堂课 受用一生的写作观念','海明威说：“有时候你写起来才让故事浮现，又不知道它是从哪里冒出来的。运转起来就什么都变了。运转起来就造成故事……”[插图]海明威说的“运转”，就是不知道会遇到什么的试探性写作，离开了已知想法，作家就要靠面对未知的即兴发挥','15221-15437',1,1691461865,1782398608);
INSERT INTO highlights VALUES('3300008362_4_13517-13556','3300008362',4,'第一堂课 受用一生的写作观念','海明威有一句话，颇能帮我们消除这一认识魔障，他说，“任何文章的初稿都是狗屎”。','13517-13556',1,1691461570,1782398608);
INSERT INTO highlights VALUES('3300008362_4_12900-12966','3300008362',4,'第一堂课 受用一生的写作观念','创作要像苍蝇试错那样，及时捕捉即兴涌现的种种灵感，不断修正先前的想法。凡认为写作可以完全靠理性设计的人，就不幸落入了蜜蜂的教条境地。','12900-12966',1,1691461224,1782398608);
INSERT INTO highlights VALUES('3300008362_4_12783-12817','3300008362',4,'第一堂课 受用一生的写作观念','你看，智商高的蜜蜂错在方法不当，错在把过去的经验当成不可更改的教条。','12783-12817',1,1691461192,1782398608);
INSERT INTO highlights VALUES('3300008362_4_12510-12533','3300008362',4,'第一堂课 受用一生的写作观念','试错会牵连到即兴发挥，潜意识就会暗中发挥作用。','12510-12533',1,1691461089,1782398608);
INSERT INTO highlights VALUES('3300008362_4_12306-12327','3300008362',4,'第一堂课 受用一生的写作观念','他把自己的才智，直接投入试错的创作摸索中。','12306-12327',1,1691461065,1782398608);
INSERT INTO highlights VALUES('3300008362_4_12247-12264','3300008362',4,'第一堂课 受用一生的写作观念','通过不断地否定，就能摸索到最佳姿态','12247-12264',1,1691461052,1782398608);
INSERT INTO highlights VALUES('3300008362_4_11976-11983','3300008362',4,'第一堂课 受用一生的写作观念','“妙手偶得之”','11976-11983',1,1691460948,1782398608);
INSERT INTO highlights VALUES('3300008362_4_11142-11224','3300008362',4,'第一堂课 受用一生的写作观念','在腹中苦思冥想的那个“想”，与落笔纸上既成事实的那个“写”，其实是有天壤之别的。逆向工程的思维，会令你把写作中的自由，压缩到几乎没有，会排除潜意识对写作的有利功用。','11142-11224',1,1691460714,1782398608);
INSERT INTO highlights VALUES('3300008362_4_10096-10142','3300008362',4,'第一堂课 受用一生的写作观念','分析课不经意就把你的写作与作家们的写作彻底拉开了距离，他们的“盖世武功”，必然令你自惭形秽。','10096-10142',1,1691460564,1782398608);
INSERT INTO highlights VALUES('3300008362_4_9635-9693','3300008362',4,'第一堂课 受用一生的写作观念','课上对经典文章做出的大量分析，大大加强了文章像精密机器的观念，令学生们赞叹每个词、句子、段落，多么准确无误，无懈可击','9635-9693',1,1691460400,1782398608);
INSERT INTO highlights VALUES('3300008362_4_9159-9186','3300008362',4,'第一堂课 受用一生的写作观念','意识到人无法被理性完全把握，会令你对写作的认识起变化，','9159-9186',1,1691460204,1782398608);
INSERT INTO highlights VALUES('3300008362_4_8079-8117','3300008362',4,'第一堂课 受用一生的写作观念','，显意识和潜意识之间，有一个所谓的前意识区，负责审查想成为显意识的那些潜意识','8079-8117',1,1691460092,1782398608);
INSERT INTO highlights VALUES('3300008362_4_8556-8579','3300008362',4,'第一堂课 受用一生的写作观念','中国古代的泼墨写意画，就完全不同，即兴色彩很浓','8556-8579',1,1691460066,1782398608);
INSERT INTO highlights VALUES('3300008362_4_8497-8527','3300008362',4,'第一堂课 受用一生的写作观念','这样的画也意味着是可以复制的，因为作画时，主要调动的是理性。','8497-8527',1,1691460052,1782398608);
INSERT INTO highlights VALUES('3300008362_4_7761-7776','3300008362',4,'第一堂课 受用一生的写作观念','过失会不经意泄露它背后的潜意识','7761-7776',1,1691459928,1782398608);
INSERT INTO highlights VALUES('3300008362_4_7500-7520','3300008362',4,'第一堂课 受用一生的写作观念','人不经意犯错时，背后的指使者就是潜意识。','7500-7520',1,1691459898,1782398608);
INSERT INTO highlights VALUES('3300008362_4_7107-7132','3300008362',4,'第一堂课 受用一生的写作观念','梦既是潜意识的杰作，也是我们窥探潜意识的一个窗口。','7107-7132',1,1691459843,1782398608);
INSERT INTO highlights VALUES('3300008362_4_5532-5569','3300008362',4,'第一堂课 受用一生的写作观念','弗洛伊德认为，人除了有理性照拂的意识，还有理性照拂不到的意识，即人的潜意识','5532-5569',1,1691459634,1782398608);
INSERT INTO highlights VALUES('3300008362_4_5377-5495','3300008362',4,'第一堂课 受用一生的写作观念','说明安娜体内有两个自我，一个受理性控制，毫不犹豫要安娜自杀，另一个不受理性控制，它抗拒安娜想自杀的理性决定，要安娜重新站起来，躲开火车。你能感受到，安娜同时受到两个自我的拉扯。托尔斯泰真的了不起，他已意识到，人的理性不可能完全把握自我。','5377-5495',1,1691459615,1782398608);
INSERT INTO highlights VALUES('3300008362_4_4859-4892','3300008362',4,'第一堂课 受用一生的写作观念','精神分裂不是指安娜得了精神病，是指她的理性，并不能完全把握她的自我','4859-4892',1,1691459508,1782398608);
INSERT INTO highlights VALUES('3300008362_4_4078-4103','3300008362',4,'第一堂课 受用一生的写作观念','人的一生就是靠着理性的打量，不断把陌生人转变成熟人','4078-4103',1,1691458415,1782398608);
INSERT INTO highlights VALUES('3300008362_4_3190-3200','3300008362',4,'第一堂课 受用一生的写作观念','人完全了解自己吗？”','3190-3200',1,1691458082,1782398608);
INSERT INTO highlights VALUES('3300008362_4_1940-2026','3300008362',4,'第一堂课 受用一生的写作观念','人有了观念，等于有了比基因突变还强大的工具，人就不会把自己的行为，完全交给基因调遣，他可以通过发掘出各种观念，大肆改变行为，甚至可以随时随地迅速改变，这是其他物种望尘莫及的','1940-2026',1,1691456655,1782398608);
INSERT INTO highlights VALUES('3300008362_4_1523-1663','3300008362',4,'第一堂课 受用一生的写作观念','“寓言故事必然就是各种诗性语言的词源”[插图]，同时“诗性语言的产生完全由于语言的贫乏和表达的需要”。','1523-1663',1,1691456525,1782398608);
INSERT INTO highlights VALUES('3300008362_4_1434-1474','3300008362',4,'第一堂课 受用一生的写作观念','《人类简史》的作者赫拉利认为，人类近五千年之所以发展迅猛，“故事”立下了汗马功劳','1434-1474',1,1691456377,1782398608);
INSERT INTO highlights VALUES('3300008362_3_1610-1697','3300008362',3,'自序：一个人的写作启蒙','普通人容易理解的人性，才是支撑那些眼花缭乱诗句的基础。确切地说，构成诗意的内部机制，与构成自我的内部机制，不过是人性的一体两面。诗、文明的悖论、野心等，都来自悖论人性的挑动。','1610-1697',1,1691400347,1782398608);
INSERT INTO highlights VALUES('26454163_28_13677-13684','26454163',108,'什么是中国','胶州湾跨海大桥','13573-13580',NULL,1587805840,1782398683);
INSERT INTO highlights VALUES('26454163_28_10286-10302','26454163',108,'什么是中国','一跃成为世界上著名的藏传佛学院。','10266-10282',NULL,1587805639,1782398683);
INSERT INTO highlights VALUES('26454163_28_9614-9653','26454163',108,'什么是中国','江西婺源篁岭、汉中盆地、云南罗平平原、青海门源等地都成为油菜花观赏的热门地点。','9536-9575',NULL,1587805591,1782398683);
