INSERT INTO highlights VALUES('26454163_12_5634-5785','26454163',92,'横断山：中国极致风光最密集的山脉','在碳酸盐岩众多的山地，流水将岩石中的钙质溶解，不断在沿途沉积，形成钙华，钙华层层堆叠犹如梯田。于是，云南香格里拉的白水台诞生了。更为出众的则是黄龙、九寨沟，其钙华景观遍布数条沟谷，声名远播。根据生长在表面的微生物群落的不同，钙华会呈现出不同的颜色，配上周围植物的缤纷色彩，可以幻化出一个极为绚烂的世界。','5885-6041',NULL,1586503851,1782398683);
