INSERT INTO highlights VALUES('26454163_12_1499-1578','26454163',92,'横断山：中国极致风光最密集的山脉','三条纵穿其中的公路——318国道、317国道、214国道也因此一跃成为中国最知名的景观大道。它们在横断山的任意一处途经点，都有可能让东部一个5A景区自愧不如。','1825-1904',NULL,1586503442,1782398683);
