INSERT INTO highlights VALUES('3300026077_275_1020-1115','3300026077',275,'今夜，我特别想你','只是一想到你，世界在明亮的光晕里倒退一些我们以为永恒的，包括时间都不堪一击','1020-1115',1,1723514250,1782398562);
INSERT INTO highlights VALUES('3300026077_275_608-828','3300026077',275,'今夜，我特别想你','即便病入膏肓，我依然高挂明月它让我白，让我有理由空荡让我在这个地图上找不到的村庄里奢侈地悲伤只是一想到你，我就小了，轻了如一棵狗尾草怀抱永恒的陌生摇晃','608-828',1,1723514194,1782398562);
