INSERT INTO highlights VALUES('3300026077_265_373-564','3300026077',265,'初冬的傍晚','阳光退出院子，退得那么慢其间还有多次停顿，如同一种哽咽北风很小，翻不起落在院子里的杨树叶儿炉子上的一罐药沉闷地咕噜，药味儿冲了出来击打着一具陈旧的病体','373-564',1,1723512576,1782398562);
