INSERT INTO highlights VALUES('3300026077_263_338-765','3300026077',263,'感谢','感谢阳光照着屋檐，照着白杨树和白杨树的第二个枝丫上的灰喜鹊照着它腹部炫目的白我坐在一个门墩上猫坐在另一个门墩，打瞌睡它的头一会儿歪向这边一会儿歪向那边阳光从我们中间踏进堂屋摆钟似乎停顿了一下继续以微不足道的声音摆动','338-765',1,1723512222,1782398562);
INSERT INTO highlights VALUES('3300026077_261_371-477','3300026077',261,'阔叶林','我喜欢这已不着一叶的林子，喜欢林子里稀薄的秋甚至，我也喜欢这里密集的哀愁酝酿到此，恰到好处的哀愁','371-477',1,1723512085,1782398562);
