INSERT INTO highlights VALUES('3300026077_242_665-718','3300026077',242,'在湖边散步的女人','走着走着，就走进一棵树里，被树梢挂起来而人群摇晃','665-718',1,1723454306,1782398562);
INSERT INTO highlights VALUES('3300026077_242_376-515','3300026077',242,'在湖边散步的女人','云落在湖水里，她落在云上，树影落在她背上这棕红的时辰，这泥质的时辰这薄而脆的，一捅就破的时辰在她前面摇晃','376-515',1,1723454234,1782398562);
INSERT INTO highlights VALUES('3300026077_242_747-832','3300026077',242,'在湖边散步的女人','没有人留意一个空酒瓶一样的女人也不知道一瓶酒洒在了哪里','747-832',1,1723454155,1782398562);
INSERT INTO highlights VALUES('3300026077_241_820-922','3300026077',241,'你没有看见我被遮蔽的部分','那些假象你还是不知道的好啊需要多少人间灰尘才能掩盖住一个女子血肉模糊却依然发出光芒的情意','820-922',1,1723454041,1782398562);
INSERT INTO highlights VALUES('3300026077_241_380-454','3300026077',241,'你没有看见我被遮蔽的部分','春天的时候，我举出花朵，火焰，悬崖上的树冠但是雨里依然有寂寞的呼声，钝器般捶打在向晚的云朵','380-454',1,1723453973,1782398562);
INSERT INTO highlights VALUES('3300026077_240_377-582','3300026077',240,'一只水蜘蛛游过池塘','我停下来，镰刀握在手里，草静止在黄昏——我是说一只水蜘蛛刚刚下水的时候我就看见了它向对岸游动，迅速，没有一点迟疑水面没有一丝波纹，它如同趴在一块玻璃上嵌进了天空，云朵，树影的玻璃','377-582',1,1723453854,1782398562);
INSERT INTO highlights VALUES('3300026077_239_859-949','3300026077',239,'我知道结果是这样的','如果我在一条河里去向不明我希望你保持沉默，在预定的时间里掏出黎明','859-949',1,1723453785,1782398562);
INSERT INTO highlights VALUES('3300026077_235_754-886','3300026077',235,'岔路镇','我们走了多少岔路于这晚秋的凄清里，才巧遇我已准备好了炭火，酒，简单的日子和你想要的一儿半女','754-886',1,1723453043,1782398562);
INSERT INTO highlights VALUES('3300026077_234_642-778','3300026077',234,'在村子的马路上散步','我从来不改变走路的速度有时候急雨等在一场情绪的路口一棵孤独的稗子给予我的相依为命让我颤抖又深深哀伤','642-778',1,1723452931,1782398562);
