INSERT INTO highlights VALUES('3300026077_185_374-892','3300026077',185,'横店村的下午','恰巧阳光正好，照到坡上的屋脊，照到一排白杨照到一方方小水塘，照到水塘边的水草照到匍匐的蕨类植物。照到油菜，小麦光阴不够平整，被那么多的植物分取被一头牛分取，被水中央的鸭子分取被一个个手势分取同时，也被我分取我用分取的光阴凑足了半辈子母亲用这些零碎凑足了一头白发只有万物欢腾——它们又凑足了一个春天我们在这样的春天里不过是把横店村重新捂热一遍','374-892',1,1720233520,1782398562);
