INSERT INTO highlights VALUES('3300026077_169_690-1065','3300026077',169,'我身体里也有一列火车','茅草屋很低，炊烟摇摇晃晃的那个小男孩低头，逆光而坐，泪水未干手里的一朵花瞪大眼睛看着他我身体里的火车，油漆已经斑驳它不慌不忙，允许醉鬼，乞丐，卖艺的，或什么领袖上上下下我身体里的火车从来不会错轨所以允许大雪，风暴，泥石流，和荒谬','690-1065',1,1720226958,1782398562);
