INSERT INTO highlights VALUES('27329013_25_3016-3090','27329013',25,'古人的浪漫——《文言文二则》','雄萤腹部有两节发光，雌性只有一节。亮灯是耗能活动，不会整晚发亮，一般只维持2至3个小时。成虫寿命一般只有5天至2星期，这段时间主要为交尾繁殖下一代。','3016-3090',NULL,1591350051,1782398672);
