INSERT INTO highlights VALUES('27329013_17_495-593','27329013',17,'伟大的母爱——《母鸡》','文章以作者的情感变化为线索，前后形成了鲜明的对比。前半部分写了母鸡的无病呻吟、欺软怕硬和拼命炫耀，再现其浅薄、媚俗；后半部分则描写了母鸡的负责、慈爱、勇敢和辛苦，塑造了一位“伟大的鸡母亲”的形象。','495-593',NULL,1590288316,1782398672);
