INSERT INTO highlights VALUES('27329013_16_3981-4095','27329013',16,'第四单元','下雨前空气潮湿，蜜蜂翅膀容易沾上细细的水珠，体重增加，飞行困难，所以只好待在蜂巢里不出来。蚂蚁也有这样的功能，下雨前空气湿度大，如果蚁窝太湿，蚂蚁就无法再在里面待下去，只好搬去高处干燥的地方，因此就会出现蚂蚁在下雨前搬家的情形。','3981-4095',NULL,1590288022,1782398672);
