INSERT INTO highlights VALUES('27329013_15_3954-4074','27329013',15,'今天，你的心情放晴了吗？——《在天晴了的时候》','戴望舒很少表达乐观的追求和向往，更多的是书写因为理想无法实现而产生的悲观感受。戴望舒是一个“寻梦者”。所谓“梦”，就是理想的一种情绪体验，它是美好的，充满诱惑的，但又是飘忽不定的、难以捉摸的，而且易于破碎的。因此，戴望舒的诗歌极具悲剧气息。','3954-4074',NULL,1588321409,1782398672);
