INSERT INTO highlights VALUES('820703_75_1419-1488','820703',75,'72. 拯救鹦鹉佩西','我们拥有人的属性，而非拥有人类的属性。因此，我们的认同并非由我们的身体外形决定，而是由身为个人必须拥有的自我特征决定——思想、情感与知觉。','1419-1488',NULL,1581122870,1782398707);
