INSERT INTO highlights VALUES('820703_72_1461-1521','820703',72,'69. 恐惧','尼采的回归形式是指，人类无法察觉自己在一遍又一遍地做同样的事，因此也没有机会改变；他们过的是完全一样的人生，不断地重复。','1461-1521',NULL,1581122265,1782398707);
