INSERT INTO highlights VALUES('820703_66_1473-1495','820703',66,'63. 不明不觉','最后，你的真实想法必须能以某种方式自圆其说。','1473-1495',NULL,1581071534,1782398707);
INSERT INTO highlights VALUES('820703_66_1433-1446','820703',66,'63. 不明不觉','其次，你所相信的必须是真的','1433-1446',NULL,1581071514,1782398707);
INSERT INTO highlights VALUES('820703_66_1369-1402','820703',66,'63. 不明不觉','许多哲学家认为，知识有三个条件。首先，要知道某事，必须相信它是真的','1369-1402',NULL,1581071487,1782398707);
INSERT INTO highlights VALUES('820703_65_1576-1677','820703',65,'62. 我思，故我在哪儿？','我们思考或许显示我们存在，但并未说明我们是什么，也没有说明我们在时间的流逝中是否还是原来的自己。我们从“我思，故我在”中得到确定性，但付出了不小的代价：一旦走出思考发生的瞬间，面对的就是完全的不确定性。','1576-1677',NULL,1581071057,1782398707);
INSERT INTO highlights VALUES('820703_64_1262-1344','820703',64,'61. 马苏里拉芝士做的月亮','第二种限制听起来相当不得了，叫作“有证据的理论弱决定论”。用直白的话来说，就是事实无法提供足够的证据，决定性地证明某一个理论为真，总是存在漏洞，其他理论也有可能为真','1262-1344',NULL,1581062702,1782398707);
INSERT INTO highlights VALUES('820703_64_1101-1164','820703',64,'61. 马苏里拉芝士做的月亮','阴谋论之所以可能出现，是因为知识的形成有两种限制。第一种被称为“理解的整体性”：我们相信的任何单一的事物都与其他观念成网状相连','1101-1164',NULL,1581062675,1782398707);
INSERT INTO highlights VALUES('820703_61_1659-1698','820703',61,'58. 信仰，还是疯狂？','信仰不是等到上帝要求你行动时才产生，信仰是即便缺乏上帝存在的证据，你依然要信。','1659-1698',NULL,1580098078,1782398707);
INSERT INTO highlights VALUES('820703_59_1392-1479','820703',59,'56. 全视角旋涡','但不表示用来衡量事物的意义或价值的真正标准是唯一的，而是要根据事物对整个宇宙造成的影响来判断。用这种方式判断自己的生命，并因此死于旋涡中，等于是用错误的标准衡量了自己的生命。','1392-1479',NULL,1580097371,1782398707);
INSERT INTO highlights VALUES('820703_58_1386-1446','820703',58,'55. 可持续发展','我们是否也会以牺牲经济发展为代价，结果只是推迟了不可避免的气候变化，最后剥夺了下一代用来解决上一代遗留的问题所需的资金？','1386-1446',NULL,1580094440,1782398707);
INSERT INTO highlights VALUES('820703_58_1095-1113','820703',58,'55. 可持续发展','我们如何回应我们目前面对的环境威胁？','1095-1113',NULL,1580094291,1782398707);
INSERT INTO highlights VALUES('820703_57_1676-1742','820703',57,'54. 捉摸不定的我','自我等于所有分享着同一观点且相互关联的经验集合。自我并不是物，当然也就无法被认知。我们无法察觉自己是什么，只能察觉到自己体验了什么。','1676-1742',NULL,1580094201,1782398707);
INSERT INTO highlights VALUES('820703_56_1300-1368','820703',56,'53. 双重效果原则','双重效果原则”认为，为了行善而做某事，即使你已经预见这么做会带来某种恶，但只要意图是善的，而且没有产生恶的结果，那么在道德上就可以接受。','1300-1368',NULL,1580093775,1782398707);
INSERT INTO highlights VALUES('820703_53_1309-1315','820703',53,'50. 善意的贿赂','道德自我沉迷','1309-1315',NULL,1580045274,1782398707);
INSERT INTO highlights VALUES('820703_53_1386-1416','820703',53,'50. 善意的贿赂','首相该受指责的地方在于他对自身清白的兴趣远大于让世界变得更好','1386-1416',NULL,1580045111,1782398707);
INSERT INTO highlights VALUES('820703_53_1201-1270','820703',53,'50. 善意的贿赂','正当程序与法治对于民主开放社会十分重要，但如果稍微扭曲规则能带来极大的好处和只有极小的坏处，僵硬地遵循法律是不是太过愚蠢甚至可以说不道德？','1201-1270',NULL,1580044959,1782398707);
INSERT INTO highlights VALUES('820703_52_1938-1968','820703',52,'49. 这不是牛津大学','范畴错误的概念确实有效防止了将语言特征与世界特征混淆在一起。','1938-1968',NULL,1580040455,1782398707);
INSERT INTO highlights VALUES('820703_51_1480-1497','820703',51,'48. 恶俗与艺术','济慈写道：“美即是真，真即是美。”','1480-1497',NULL,1579966501,1782398707);
INSERT INTO highlights VALUES('820703_51_1093-1152','820703',51,'48. 恶俗与艺术','无所谓道德不道德的书，只有写得好与写得不好的书。”王尔德认为艺术独立于道德之外，因此，将伦理标准套在艺术里就是个错误。','1093-1152',NULL,1579966493,1782398707);
INSERT INTO highlights VALUES('820703_50_2141-2163','820703',50,'47. 兔子！','这是否意味着真理与语言、文化之间存在相对性？','2141-2163',NULL,1579965910,1782398707);
INSERT INTO highlights VALUES('820703_50_1850-1923','820703',50,'47. 兔子！','词语与事物及观念并不是一对一的关系，相反，词语与词语之间以及词语与说话者的应用之间是彼此关联的。意义是整体的，你永远不能孤立地理解一个单独的词语。','1850-1923',NULL,1579965772,1782398707);
INSERT INTO highlights VALUES('820703_49_1653-1738','820703',49,'46. 再生人','问题在于我们提出的身份问题与同一性随着时间的变迁有一种一对一的关系，当问题中的情况出现一对多的关系时，同一性的逻辑在这里就无用武之地了，我们应该讨论的是连续或持续的问题。','1653-1738',NULL,1579965501,1782398707);
INSERT INTO highlights VALUES('820703_49_1908-1953','820703',49,'46. 再生人','人的存活与否最重要的并非身份在时间变迁中被保存下来，而是现在的我与未来的我具有正确的连续性','1908-1953',NULL,1579965467,1782398707);
INSERT INTO highlights VALUES('820703_48_2045-2061','820703',48,'45. 隐形的园丁','如果上帝不仅是一个词或者一个希望','2045-2061',NULL,1579965128,1782398707);
INSERT INTO highlights VALUES('820703_47_1526-1577','820703',47,'44. 不至死亡，永不分离','如果彼此信任，我们的确会自己暴露在被利用的风险中，但如果我们不相信彼此，就将自己与生活中最好的可能隔绝','1526-1577',NULL,1579964252,1782398707);
INSERT INTO highlights VALUES('820703_46_1705-1746','820703',46,'43. 未来冲击','当我们代表未来的自己做出承诺时，在某种程度上，我们是替某个不同于现在的自己做承诺，','1705-1746',NULL,1579958878,1782398707);
INSERT INTO highlights VALUES('820703_46_1661-1666','820703',46,'43. 未来冲击','人是会变的','1661-1666',NULL,1579958835,1782398707);
INSERT INTO highlights VALUES('820703_46_1107-1132','820703',46,'43. 未来冲击','我们有权代表未来的自己做出具有法律拘束力的决定吗？','1107-1132',NULL,1579945858,1782398707);
INSERT INTO highlights VALUES('820703_45_2011-2091','820703',45,'42. 拿了钱就跑','如果可以预测未来，人类的自由意志将无法改变未来，因为不管我们如何选择都会是预测的一部分。我们也许自由，但是我们前面的未来可能只有一个，一个原则上可以预测的未来。','2011-2091',NULL,1579945742,1782398707);
INSERT INTO highlights VALUES('820703_44_1290-1326','820703',44,'41. 就是没有蓝色','所谓的新事物其实来自于已知事物的结合。新事物的产生取决于如何整合旧元素，','1290-1326',NULL,1579936581,1782398707);
INSERT INTO highlights VALUES('820703_44_1038-1062','820703',44,'41. 就是没有蓝色','经验对于学习有多重要？这个问题贯穿了整个观念史。','1038-1062',NULL,1579936557,1782398707);
INSERT INTO highlights VALUES('820703_43_1072-1151','820703',43,'40. 木马赢家','这个人接受卡片上的说法，相信这些城市确实就是各个国家的首都。结果只有罗马是对的。虽然他相信罗马是意大利的首都，而这一点也是对的，但我们能说他的确知道这件事吗？','1072-1151',NULL,1579772625,1782398707);
INSERT INTO highlights VALUES('820703_42_1891-1938','820703',42,'39. 算命摊','像心灵那样运作不足以称为拥有心灵，那要拥有什么才算？我们如何知道其他人或计算机是否拥有心灵呢？','1891-1938',NULL,1579772437,1782398707);
INSERT INTO highlights VALUES('820703_42_1125-1130','820703',42,'39. 算命摊','功能心理学','1125-1130',NULL,1579772292,1782398707);
INSERT INTO highlights VALUES('820703_41_1501-1540','820703',41,'38. 我是大脑','构成个人人格的音符与音调就是思想、记忆与性格特征，这些结合起来决定了我们是谁。','1501-1540',NULL,1579772143,1782398707);
INSERT INTO highlights VALUES('820703_40_1618-1624','820703',40,'37. 自然就是美？','艺术是多面的','1618-1624',NULL,1579771980,1782398707);
INSERT INTO highlights VALUES('820703_40_873-926','820703',40,'37. 自然就是美？','新的正统学说认为艺术作品一旦完成，就拥有了自己的生命，独立于作者之外。艺术家对作品的诠释并没有特殊的权威。','873-926',NULL,1579771857,1782398707);
INSERT INTO highlights VALUES('820703_40_862-866','820703',40,'37. 自然就是美？','意图谬误','862-866',NULL,1579771845,1782398707);
INSERT INTO highlights VALUES('820703_37_987-1026','820703',37,'34. 不是我的错','要承认坏事是因为自己的错很困难，但奇怪的是，一遇上好事，人人都会接受是自己做的','987-1026',NULL,1579770970,1782398707);
INSERT INTO highlights VALUES('820703_36_1376-1408','820703',36,'33. 言论自由亭','我们为自由付出的代价就是有时必须面对因为听人们散播谣言造成的不便','1376-1408',NULL,1579770755,1782398707);
INSERT INTO highlights VALUES('820703_36_1004-1038','820703',36,'33. 言论自由亭','因为言论自由不只是说你所想的自由，还包括你想跟谁说话与何时说话的自由','1004-1038',NULL,1579770702,1782398707);
INSERT INTO highlights VALUES('820703_35_1793-1852','820703',35,'32. 自由的西蒙妮','就像在疯子角色上入戏很深的悲剧演员最后真的发疯一样，完全复制智能功能的机器最后也会变得拥有智能。你做的事决定了你是谁。','1793-1852',NULL,1579770611,1782398707);
INSERT INTO highlights VALUES('820703_33_1867-1912','820703',33,'30. 别人的回忆','我们的记忆衰退或欺骗我们时，又会怎样？随着记忆的可靠性越来越低，自我的边界会不会开始瓦解？','1867-1912',NULL,1579676513,1782398707);
INSERT INTO highlights VALUES('820703_31_1569-1594','820703',31,'28. 噩梦景象','然而，有没有可能我不是在回想过去，而是在创造过去？','1569-1594',NULL,1579674523,1782398707);
INSERT INTO highlights VALUES('820703_30_1760-1776','820703',30,'27. 信守承诺','行动者与行动以及结果之间的联系。','1760-1776',NULL,1579674235,1782398707);
INSERT INTO highlights VALUES('820703_30_1232-1268','820703',30,'27. 信守承诺','争议的焦点在于行动之后若是无法得到期望的结果，能不能说自己已经尽到责任。','1232-1268',NULL,1579674171,1782398707);
INSERT INTO highlights VALUES('820703_29_1682-1719','820703',29,'26. 忘记疼痛','不只是动物是否会感觉到疼痛，还有它们是否拥有痛苦必不可少的疼痛记忆与预期。','1682-1719',NULL,1579673537,1782398707);
INSERT INTO highlights VALUES('820703_29_1037-1060','820703',29,'26. 忘记疼痛','如果动物会感到疼痛，它们就值得在道德上得到关注','1037-1060',NULL,1579673450,1782398707);
INSERT INTO highlights VALUES('820703_28_1420-1433','820703',28,'25. 优柔寡断的布里丹','而是一个理性并未参与的过程','1420-1433',NULL,1579673202,1782398707);
INSERT INTO highlights VALUES('820703_28_1860-1901','820703',28,'25. 优柔寡断的布里丹','采取与理性无关的做法仍然可以符合理性，接受这个想法并不表示开启了通往非理性的大门。','1860-1901',NULL,1579673162,1782398707);
INSERT INTO highlights VALUES('820703_28_907-932','820703',28,'25. 优柔寡断的布里丹','再也没有比自作聪明的悖论更能高效制造出深奥的幻觉。','907-932',NULL,1579672842,1782398707);
INSERT INTO highlights VALUES('820703_27_1552-1595','820703',27,'24. 方形的圆','大多数宗教信徒都乐于接受上帝全能是指他能做所有逻辑上行得通的事，而不是逻辑上行不通的事','1552-1595',NULL,1579672579,1782398707);
INSERT INTO highlights VALUES('820703_26_1007-1059','820703',26,'23. 盒子中的“甲虫”','所有的语言运用都是游戏，靠的是规则与习惯的结合，而这些都无法完全解释清楚，只有参与游戏的人才能真正理解。','1007-1059',NULL,1579671941,1782398707);
INSERT INTO highlights VALUES('820703_24_1263-1290','820703',24,'21. 埃皮菲尼亚人的土地','我们的意识经验是其副产品，由机器引发，而不会影响机器。','1263-1290',NULL,1579670609,1782398707);
INSERT INTO highlights VALUES('820703_24_1203-1239','820703',24,'21. 埃皮菲尼亚人的土地','副现象论认为思想与其他精神事件并未在物质世界引发任何事物，包括我们的行动','1203-1239',NULL,1579670578,1782398707);
INSERT INTO highlights VALUES('820703_24_519-552','820703',24,'21. 埃皮菲尼亚人的土地','思想无法影响行动。思想仅仅是身体行为的效果，而不是反过来控制身体。','519-552',NULL,1579670492,1782398707);
INSERT INTO highlights VALUES('820703_23_1695-1734','820703',23,'20. 赖活不如好死','或许我们不该想“如果我有更多时间”，而是该想“如果我能善加利用所拥有的时间”。','1695-1734',NULL,1579666068,1782398707);
INSERT INTO highlights VALUES('820703_23_1508-1555','820703',23,'20. 赖活不如好死','如果我们拥有无限的时间，“充分利用”的概念将变得毫无意义：既然时间是无限的，就无所谓浪费时间。','1508-1555',NULL,1579665996,1782398707);
INSERT INTO highlights VALUES('820703_23_1346-1369','820703',23,'20. 赖活不如好死','越来越多的人享受着延长的青春期，直到30多岁。','1346-1369',NULL,1579665877,1782398707);
INSERT INTO highlights VALUES('820703_23_967-1003','820703',23,'20. 赖活不如好死','我们需要死亡赋予生命外在形式与意义，没有死亡，我们将会发现人生毫无意义。','967-1003',NULL,1579665598,1782398707);
INSERT INTO highlights VALUES('820703_22_1467-1510','820703',22,'19. 幻想破灭','我们不会真的用墙将自己完全封闭起来，但我们的确用许多更微妙的方式限定了自己的经验范围。','1467-1510',NULL,1579596737,1782398707);
INSERT INTO highlights VALUES('820703_22_1322-1343','820703',22,'19. 幻想破灭','确切的内容到底是什么取决于他们如何被社会化','1322-1343',NULL,1579596640,1782398707);
INSERT INTO highlights VALUES('820703_21_1263-1316','820703',21,'18. 理性的要求','不管怎样，认为理性总是与善同行，这种乐观主义是一种错位。据说精神病患者的问题不在于缺乏理性，而在于缺乏情感','1263-1316',NULL,1579592944,1782398707);
INSERT INTO highlights VALUES('820703_21_973-998','820703',21,'18. 理性的要求','我们从经验中得知，人总是会被理性论证说服做恐怖的事','973-998',NULL,1579592867,1782398707);
INSERT INTO highlights VALUES('820703_20_1424-1485','820703',20,'17. 严刑逼供','但在实际操作中，一旦偶尔允许拷打，将不可避免地延续到原本无须拷打的案子上。有时候，更好的情况是我们在可拷打的情形下不拷打，','1424-1485',NULL,1579592629,1782398707);
INSERT INTO highlights VALUES('820703_20_737-777','820703',20,'17. 严刑逼供','。如果他只是因为个人厌恶拷打和缺乏道德勇气而不下令拷打，是否等于判处了民众死刑？','737-777',NULL,1579592104,1782398707);
INSERT INTO highlights VALUES('820703_19_1738-1749','820703',19,'16. 赛跑的乌龟','真正难的是如何运用逻辑','1738-1749',NULL,1579525023,1782398707);
INSERT INTO highlights VALUES('820703_19_1639-1669','820703',19,'16. 赛跑的乌龟','运用基本逻辑进行的理论空想是认识宇宙基础本质的不可靠的向导。','1639-1669',NULL,1579524842,1782398707);
INSERT INTO highlights VALUES('820703_18_1150-1232','820703',18,'15. 平凡的英雄行为','功利主义认为，凡是道德上正确的行动就是符合多数人利益的行动。如果真是这样，一旦无法让大多数人受益，就表示无法做到在道德上正确的事，即使做这件事在很大程度上要自我牺牲','1150-1232',NULL,1579489819,1782398707);
INSERT INTO highlights VALUES('820703_17_1633-1696','820703',17,'14. 对你有利的银行错误','对自己有利的理由总是比对自己不利的理由更有说服力，我们很难消除这种偏见而从无私的角度思考。毕竟，我们有什么理由不为自己考虑呢？','1633-1696',NULL,1579483440,1782398707);
INSERT INTO highlights VALUES('820703_16_1023-1048','820703',16,'13. 专门研究红色的色盲','但否定错误的世界观并不能保证我们拥有正确的世界观。','1023-1048',NULL,1579482923,1782398707);
INSERT INTO highlights VALUES('820703_15_1693-1722','820703',15,'12. 沙滩上的毕加索','也许就能看清艺术与生命的价值，更重要的是过程，而不是结果。','1693-1722',NULL,1579482394,1782398707);
INSERT INTO highlights VALUES('820703_15_1595-1627','820703',15,'12. 沙滩上的毕加索','实际上艺术的寿命远超人类，因此人类往往试图通过艺术延续自己的生命','1595-1627',NULL,1579482350,1782398707);
INSERT INTO highlights VALUES('820703_15_1573-1595','820703',15,'12. 沙滩上的毕加索','我们渴望长存的天性是拒绝自身灭亡的一种形式。','1573-1595',NULL,1579482287,1782398707);
INSERT INTO highlights VALUES('820703_15_1328-1388','820703',15,'12. 沙滩上的毕加索','一般来说，我们认为应该保存或修复绘画使它们和以前一样，但是或许我们应该将艺术品的逐渐磨损也看作表现形式中的重要组成部分。','1328-1388',NULL,1579481737,1782398707);
INSERT INTO highlights VALUES('820703_15_1010-1042','820703',15,'12. 沙滩上的毕加索','艺术品无法永久留存并不代表这是悲剧，主要还是取决于艺术品的形式。','1010-1042',NULL,1579481461,1782398707);
INSERT INTO highlights VALUES('820703_14_1619-1740','820703',14,'11. “忒修斯”号','人类不也像“忒修斯”号一样吗？随着生命的推移，体内的细胞不断死亡并被新细胞取代。我们的思想在不断变化，20岁时，脑子里10岁时的想法已经所剩无几。随着年龄的增长，思想、记忆、信仰与性情也在不断地更替。现在的我们跟许多年前的我们是不是同一个人？','1619-1740',NULL,1579425813,1782398707);
INSERT INTO highlights VALUES('820703_14_1129-1150','820703',14,'11. “忒修斯”号','哲学总是与事实倶全却仍无法解答的问题有关。','1129-1150',NULL,1579425729,1782398707);
INSERT INTO highlights VALUES('820703_13_1627-1652','820703',13,'10. 蒙蔽公平','罗尔斯的支持者相信无知是最能决定公平社会面貌的工具','1627-1652',NULL,1579425259,1782398707);
INSERT INTO highlights VALUES('820703_12_1881-1916','820703',12,'9. 反应预测','如果这是对的，那我们又何必因为能完全预测一个人的行为就认定人不自由呢？','1881-1916',NULL,1579319534,1782398707);
INSERT INTO highlights VALUES('820703_12_1065-1104','820703',12,'9. 反应预测','因为并非所有的因果过程都完全取决于先前的条件，宇宙远比拉普拉斯想象得更不确定。','1065-1104',NULL,1579319216,1782398707);
INSERT INTO highlights VALUES('820703_11_1200-1222','820703',11,'8. 为善','“是”的功能在于将某些特质归属于某人或某物，','1200-1222',NULL,1579317917,1782398707);
INSERT INTO highlights VALUES('820703_11_801-852','820703',11,'8. 为善','你选择什么是善是因为这些事本身就是善。但这样就表明善并非由你决定，所以我们不需要理解上帝就能理解善。”','801-852',NULL,1579317786,1782398707);
INSERT INTO highlights VALUES('820703_11_491-539','820703',11,'8. 为善','你命令我们行善，但这些行为是因为你命令才变成善，还是说这些行为本身是善，所以你才命令我们去做？”','491-539',NULL,1579317572,1782398707);
INSERT INTO highlights VALUES('820703_9_803-826','820703',9,'6. 幸运轮盘','赌徒很容易在自己想象的场景中迷失，哲学家也是。','803-826',NULL,1579316543,1782398707);
INSERT INTO highlights VALUES('820703_8_1592-1612','820703',8,'5. 一头想要被吃掉的猪','这是人们面对某种不自然的东西时的本能反应','1592-1612',NULL,1579316349,1782398707);
INSERT INTO highlights VALUES('820703_8_1357-1468','820703',8,'5. 一头想要被吃掉的猪','但如果能创造出在生存上没有利益的动物，也就是说，这些动物跟胡萝卜一样没有知觉，那又会怎么样呢？剥夺它们从未意识到或拥有过的存在感有错吗？或者，如果动物实际上渴望被吃掉，就像道格拉斯·亚当斯在《宇宙尽头的餐馆》中设想的那样？','1357-1468',NULL,1579316088,1782398707);
INSERT INTO highlights VALUES('820703_7_1705-1747','820703',7,'4. 虚拟外遇','应该将注意力集中在不贞这一点，即夫妻双方从什么时候开始远离这段最值得珍视的婚姻关系的','1705-1747',NULL,1579310159,1782398707);
INSERT INTO highlights VALUES('820703_6_1532-1655','820703',6,'3. 印度人与冰','然而，问题在于，有时候会出现某样真实存在的事物迫使我们重新思考我们原先的认知。我们不能因为某个观点与我们当时的认知不符就嗤之以鼻。我们需要充分的理由才能予以驳斥，因为言之成理、不可撼动的东西应该要比反对这个观点的某个人或者某一小群人的观点有分量。','1532-1655',NULL,1579309280,1782398707);
INSERT INTO highlights VALUES('820703_5_1876-1920','820703',5,'2. 瞬间移动装置','这种做法对我们过去与未来的存在有何影响，也许这个问题的答案就是要不择手段地保持心理持续性','1876-1920',NULL,1579308346,1782398707);
INSERT INTO highlights VALUES('33915626_13_2848-2860','33915626',13,'附录','我很珍惜你，因为你很……','2848-2860',1,1738247092,1782398552);
INSERT INTO highlights VALUES('33915626_12_1288-1330','33915626',12,'结语','最好的方式就是以你们的关系为重，给它以时间、关注，并对你们将要一起创造的生活保持激情','1288-1330',1,1738246810,1782398552);
INSERT INTO highlights VALUES('33915626_12_1085-1175','33915626',12,'结语','那些婚姻幸福的夫妻，特别之处就在于他们会做出积极的表达。即便是发生了重大的冲突或者很激烈的争吵，他们之间积极表达和消极表达的比例也高达5∶1；在日常相处时，这一比例会高达20∶1。','1085-1175',1,1738246792,1782398552);
INSERT INTO highlights VALUES('33915626_12_855-919','33915626',12,'结语','你们必须勇于袒露自我，不要将自己有所隐藏。真正的爱情是由两人间平凡细微的瞬间和互动组成的，要让这些瞬间变得有意义。','855-919',1,1738246763,1782398552);
INSERT INTO highlights VALUES('33915626_12_587-658','33915626',12,'结语','把你们的关系当作一次伟大的探险，保持好奇心，勇于袒露内心的脆弱，并敢于踏出自己的舒适区。学会倾听，勇于对话，并互相分享你们的希望、恐惧和梦想。','587-658',1,1738246677,1782398552);
INSERT INTO highlights VALUES('33915626_11_14340-14379','33915626',11,'CHAPTER 9 让彼此发光','我承诺，充分探索并理解你的梦想，并在接下来的6个月里用行动支持你实现这个梦想。','14340-14379',1,1738246622,1782398552);
INSERT INTO highlights VALUES('33915626_11_13048-13118','33915626',11,'CHAPTER 9 让彼此发光','在充分理解这个梦想之前，不要直接分析实现梦想的现实层面。这会很快扼杀这一梦想，或者让伴侣缄默不语。即便这个梦想看上去不切实际，也不要说出来。','13048-13118',1,1738246529,1782398552);
INSERT INTO highlights VALUES('33915626_11_8202-8213','33915626',11,'CHAPTER 9 让彼此发光','激发我有创造力的一面。','8202-8213',1,1738246266,1782398552);
INSERT INTO highlights VALUES('33915626_11_6320-6330','33915626',11,'CHAPTER 9 让彼此发光','[插图] 探索“我是谁”。','6322-6330',1,1738246252,1782398552);
INSERT INTO highlights VALUES('33915626_11_5806-5816','33915626',11,'CHAPTER 9 让彼此发光','[插图] 拥有更多的自由。','5808-5816',1,1738246247,1782398552);
INSERT INTO highlights VALUES('33915626_11_4987-5073','33915626',11,'CHAPTER 9 让彼此发光','反之，要和伴侣对话：你为什么会有这个梦想？这个梦想对你意味着什么？当你实现了它，会有什么感受？你和伴侣每个人所拥有的每个梦想背后都有一个故事，你们需要互相仔细倾听这些故事。','4987-5073',1,1738246056,1782398552);
INSERT INTO highlights VALUES('33915626_11_4711-4755','33915626',11,'CHAPTER 9 让彼此发光','当我们隐藏大大小小的梦想时，我们也藏匿了自己最重要的一些方面，这会阻碍亲密感和建立联结。','4711-4755',1,1738246016,1782398552);
INSERT INTO highlights VALUES('33915626_11_3936-3971','33915626',11,'CHAPTER 9 让彼此发光','他们的共识是，只要能守住可以维持生存的底线，他们就可以去追求个人梦想。','3936-3971',1,1738245887,1782398552);
INSERT INTO highlights VALUES('33915626_11_2461-2516','33915626',11,'CHAPTER 9 让彼此发光','每个人都有一个人生梦想或目标，你需要守护好这些梦想，不要让它们淹没在日常的工作、家庭，甚至是你们关系的琐事中。','2461-2516',1,1738245733,1782398552);
INSERT INTO highlights VALUES('33915626_11_1755-1902','33915626',11,'CHAPTER 9 让彼此发光','你觉得未来你的工作会有什么样的变化？现在的生活中，什么会让你激动？你对未来最大的担忧是什么？你觉得我们可以怎样在生活中拥有更多的乐趣？你思念生命中的哪些事物？','1755-1902',1,1738245591,1782398552);
INSERT INTO highlights VALUES('33915626_11_389-451','33915626',11,'CHAPTER 9 让彼此发光','尊重伴侣的梦想是一种向对方传达爱意的有效方式，所以首先要互相分享这些梦想。同时，没有任何一方应该为两人的关系牺牲自己的梦想。','389-451',1,1738245188,1782398552);
INSERT INTO highlights VALUES('33915626_10_11609-11632','33915626',10,'CHAPTER 8 好的爱情是共同成长','9. 在你自我成长的道路上，我可以怎样支持你？','11609-11632',1,1738226074,1782398552);
INSERT INTO highlights VALUES('33915626_10_11546-11580','33915626',10,'CHAPTER 8 好的爱情是共同成长',' 你希望向孩子（如果我们有孩子或者计划要孩子）传递你的哪些精神信仰？','11547-11580',1,1738226063,1782398552);
INSERT INTO highlights VALUES('33915626_10_11271-11289','33915626',10,'CHAPTER 8 好的爱情是共同成长','3. 是什么支撑你度过最艰难的时光？','11271-11289',1,1738225959,1782398552);
INSERT INTO highlights VALUES('33915626_10_8790-8830','33915626',10,'CHAPTER 8 好的爱情是共同成长',' 研究发现，只要有一方把这段关系看作神圣不可侵犯的事物，你们关系的质量就会提高。','8791-8830',1,1738225493,1782398552);
INSERT INTO highlights VALUES('33915626_10_8097-8168','33915626',10,'CHAPTER 8 好的爱情是共同成长','3. 我们常常被紧迫之事占据时间，但是你需要思考什么才是你生命中至关重要的事情。它们是你力量和快乐的源泉，且重要到你需要推迟或是不做其他事项。','8097-8168',1,1738225416,1782398552);
INSERT INTO highlights VALUES('33915626_10_4285-4306','33915626',10,'CHAPTER 8 好的爱情是共同成长','试着营造放松的氛围，让对方分享新鲜的事物。','4285-4306',1,1738225139,1782398552);
INSERT INTO highlights VALUES('33915626_10_4074-4206','33915626',10,'CHAPTER 8 好的爱情是共同成长','分享怎么度过这一天也可以是一种建立联结的仪式，你可以温柔地去探索对方为什么会有压力，为什么会感到疲惫；创造出一个安全的空间，和对方分享自己的内在世界也是建立联结的一种仪式。你们共度的每一刻，甚至分开的每一刻，都可以为两人的关系创造神圣感——不管你们如何定义神圣感。','4074-4206',1,1738225089,1782398552);
INSERT INTO highlights VALUES('33915626_10_3140-3188','33915626',10,'CHAPTER 8 好的爱情是共同成长','3. 波折不可避免，但是当你们共同面对这些波折，共同在逆境中成长时，你就为你们的不同创造了意义。','3140-3188',1,1738224938,1782398552);
INSERT INTO highlights VALUES('33915626_10_3219-3249','33915626',10,'CHAPTER 8 好的爱情是共同成长','4. 如果你们能走出波折，并创造意义，你们就能够永远在一起。','3219-3249',1,1738224931,1782398552);
INSERT INTO highlights VALUES('33915626_10_2867-2913','33915626',10,'CHAPTER 8 好的爱情是共同成长','我们需要坦然迎接冲突，这可以让我们学习如何更好地爱对方，如何去理解伴侣那个不同于我们的头脑。','2867-2913',1,1738224868,1782398552);
INSERT INTO highlights VALUES('33915626_10_952-1011','33915626',10,'CHAPTER 8 好的爱情是共同成长','我们各自都有变化，但不变的是一路支持对方的改变和成长，这是很激动人心的事情。我们都一直持续不断地发现自己，了解对方。”','952-1011',1,1738224493,1782398552);
INSERT INTO highlights VALUES('33915626_10_393-468','33915626',10,'CHAPTER 8 好的爱情是共同成长','亲密关系不是把另外一个人改造成和你一样，而是从对方身上学习，并从你们的差异中受益。通过真正地对伴侣的经历保有好奇心，你们就可以适应关系中的成长和改变。','393-468',1,1738224148,1782398552);
INSERT INTO highlights VALUES('33915626_9_22592-22615','33915626',9,'CHAPTER 7 让爱情充满新鲜感','4. 玩乐与冒险的意义在于大笑和体验新鲜事物。','22592-22615',1,1738220916,1782398552);
INSERT INTO highlights VALUES('33915626_9_19179-19191','33915626',9,'CHAPTER 7 让爱情充满新鲜感','学习夫妻或情侣间的按摩。','19179-19191',1,1738220829,1782398552);
INSERT INTO highlights VALUES('33915626_9_18253-18287','33915626',9,'CHAPTER 7 让爱情充满新鲜感','在某个地方约会，并假装我们互不认识，是第一次见面，调情并互相撩对方。','18253-18287',1,1738220813,1782398552);
INSERT INTO highlights VALUES('33915626_9_10874-10887','33915626',9,'CHAPTER 7 让爱情充满新鲜感','一起远足或走很长的一段路。','10874-10887',1,1738220658,1782398552);
INSERT INTO highlights VALUES('33915626_9_9884-9940','33915626',9,'CHAPTER 7 让爱情充满新鲜感','“游戏的对立面不是工作，而是压抑。”当我们可以“游戏”人生，我们就能从严肃的地方发现可笑之处，从无聊中找到激情。','9884-9940',1,1738219639,1782398552);
INSERT INTO highlights VALUES('33915626_9_9398-9432','33915626',9,'CHAPTER 7 让爱情充满新鲜感','想拥有完美的爱情，想保持亲密关系的乐趣，不一定需要用一样的方式去玩乐','9398-9432',1,1738219577,1782398552);
INSERT INTO highlights VALUES('33915626_9_7634-7692','33915626',9,'CHAPTER 7 让爱情充满新鲜感','你们可以体验过山车、看恐怖片，或者其他任何让你和伴侣感到恐怖的事情，然后看一看在这个体验后，你们的亲密度会不会增加。','7634-7692',1,1738219303,1782398552);
INSERT INTO highlights VALUES('33915626_9_7356-7396','33915626',9,'CHAPTER 7 让爱情充满新鲜感','“共同面对挑战可以让两个人体验同舟共济的感觉，而且让你们更加珍惜对方。”道格说。','7356-7396',1,1738218975,1782398552);
INSERT INTO highlights VALUES('33915626_9_6284-6316','33915626',9,'CHAPTER 7 让爱情充满新鲜感','。那些让你走出自我舒适区的活动都能让你体验到多巴胺带来的刺激感。','6284-6316',1,1738218862,1782398552);
INSERT INTO highlights VALUES('33915626_9_6268-6284','33915626',9,'CHAPTER 7 让爱情充满新鲜感','冒险的实质是追求新鲜的不同的体验','6268-6284',1,1738218853,1782398552);
INSERT INTO highlights VALUES('33915626_9_5463-5515','33915626',9,'CHAPTER 7 让爱情充满新鲜感','对两个人来说，游戏和冒险的意义在于共同学习、共同成长、共同探索，以及满足我们都拥有的、与生俱来的好奇心。','5463-5515',1,1738218748,1782398552);
INSERT INTO highlights VALUES('33915626_9_1626-1687','33915626',9,'CHAPTER 7 让爱情充满新鲜感','不管是一起放风筝，去野营，还是玩棋类游戏，只要你们一起玩乐，你们就创造了共同的意义和乐趣，这也会让你们之间的联系更加紧密。','1626-1687',1,1738218259,1782398552);
INSERT INTO highlights VALUES('33915626_8_9819-9843','33915626',8,'CHAPTER 6 成长的空间','3. 你希望我们的孩子能拥有我的哪些特点或品质？','9819-9843',1,1738217976,1782398552);
INSERT INTO highlights VALUES('33915626_8_9579-9635','33915626',8,'CHAPTER 6 成长的空间','2. 你父母在有孩子之后是怎样维持他们之间的亲密感、爱情、感情浓度的？他们有哪些地方做得好，哪些地方做得不够好？','9579-9635',1,1738217900,1782398552);
INSERT INTO highlights VALUES('33915626_8_6405-6506','33915626',8,'CHAPTER 6 成长的空间','为了维持亲密度，你们需要互相倾诉自己面临的压力，抽出时间来建立联结（约会之夜！），并避免自我防卫、批评指责、蔑视对方、向对方关闭自己的世界，或把自己从你们共同的世界里抽离出来，以致两人心生嫌隙，渐行渐远','6405-6506',1,1738217558,1782398552);
INSERT INTO highlights VALUES('33915626_8_6332-6357','33915626',8,'CHAPTER 6 成长的空间','二是两个人要以亲密关系为重，注重维持亲密感和联结。','6332-6357',1,1738217499,1782398552);
INSERT INTO highlights VALUES('33915626_8_6173-6251','33915626',8,'CHAPTER 6 成长的空间','一是两个人都要在孕期和孩子出生时积极参与，给予新生儿均等的陪伴。研究发现，对夫妻而言，父亲的参与至关重要，而让父亲积极参与照顾孩子的一大驱动力是夫妻关系良好','6173-6251',1,1738217345,1782398552);
INSERT INTO highlights VALUES('33915626_8_5918-5972','33915626',8,'CHAPTER 6 成长的空间','他们能积极参与进来，和妻子腹中的孩子说话，赞美自己的妻子，告诉妻子她很美，很懂得照顾两个人尚在子宫中的孩子。','5918-5972',1,1738217301,1782398552);
INSERT INTO highlights VALUES('33915626_8_2579-2620','33915626',8,'CHAPTER 6 成长的空间','家，其实可以定义为：无论你在哪儿，和谁在一起，你都可以感到被爱，有归属感和安定感。','2579-2620',1,1738216722,1782398552);
INSERT INTO highlights VALUES('33915626_8_389-457','33915626',8,'CHAPTER 6 成长的空间','把我们的关系放在第一位，把孩子放在第二位。因为我们可以为孩子做的最好的事情，就是我们牢固的婚姻关系，使孩子能生活在一个父母恩爱的环境中。','389-457',1,1738216285,1782398552);
INSERT INTO highlights VALUES('33915626_7_21051-21059','33915626',7,'CHAPTER 5 爱情的代价','赞赏伴侣的3个点','21051-21059',1,1738209460,1782398552);
INSERT INTO highlights VALUES('33915626_7_21647-21679','33915626',7,'CHAPTER 5 爱情的代价','我承诺，尊重你的金钱观和工作观，并和你一起为共同的财务目标努力。','21647-21679',1,1738209450,1782398552);
INSERT INTO highlights VALUES('33915626_7_21133-21151','33915626',7,'CHAPTER 5 爱情的代价','3. 讨论你目前对拥有什么充满感激。','21133-21151',1,1738209402,1782398552);
INSERT INTO highlights VALUES('33915626_7_20921-20954','33915626',7,'CHAPTER 5 爱情的代价','对方分享任何梦想时，我们都应该倾听，表示支持，并在不懂的地方发问。','20921-20954',1,1738208929,1782398552);
INSERT INTO highlights VALUES('33915626_7_20693-20730','33915626',7,'CHAPTER 5 爱情的代价','关注你所拥有的，而不是你所没有的，不要关注过去所做的和金钱相关的错误决定。','20693-20730',1,1738208915,1782398552);
INSERT INTO highlights VALUES('33915626_7_18353-18387','33915626',7,'CHAPTER 5 爱情的代价','. 共同分担家务是爱情完美的另外一大要素，仅次于忠诚和满意的性生活。','18353-18387',1,1738208490,1782398552);
INSERT INTO highlights VALUES('33915626_7_17790-17841','33915626',7,'CHAPTER 5 爱情的代价','想要拥有一段持续一生的高质量的亲密关系，就要感激你所拥有的，感激各自的贡献，并感激你们正在建设的一切。','17790-17841',1,1738208418,1782398552);
