INSERT INTO highlights VALUES('33915626_6_10892-10919','33915626',6,'CHAPTER 4 别让爱情死于“无性婚姻”','另外一个保持激情的方式就是用语言表达对对方的爱和赞赏。','10892-10919',1,1738156913,1782398552);
INSERT INTO highlights VALUES('33915626_6_10727-10766','33915626',6,'CHAPTER 4 别让爱情死于“无性婚姻”','没有任何理由地激吻是拥有令人满意的性生活的关键，这是一个放之四海而皆准的规律。','10727-10766',1,1738156889,1782398552);
INSERT INTO highlights VALUES('33915626_6_9784-9847','33915626',6,'CHAPTER 4 别让爱情死于“无性婚姻”','谢谢你告诉我你现在没有这个兴致。现在你想做些什么呢？你想出去遛弯、聊聊天吗？看电视？拥抱？还是只想聊一聊？或是想自己待一会儿？','9784-9847',1,1738155308,1782398552);
INSERT INTO highlights VALUES('33915626_6_8149-8218','33915626',6,'CHAPTER 4 别让爱情死于“无性婚姻”','不过谈论性是完全不同的，因为很多时候暴露身体似乎比暴露情感更加简单。但是话说回来，如果你们想要关系长久，就必须要容忍两者都暴露在伴侣面前。','8149-8218',1,1738155114,1782398552);
INSERT INTO highlights VALUES('33915626_6_7716-7777','33915626',6,'CHAPTER 4 别让爱情死于“无性婚姻”','研究表明男性需要并渴望得到女性的一些引导。男性希望能给伴侣带来愉悦感，他们想要在性上满足伴侣，所以他们希望知道女性的感受。','7716-7777',1,1738155052,1782398552);
