INSERT INTO highlights VALUES('33915626_5_9988-10063','33915626',5,'CHAPTER 3 为什么会吵架','婚姻或恋爱关系里真正幸福的夫妻或情侣会以温和、积极的方式处理冲突和矛盾。他们倾听伴侣的观点，努力理解对方，而且一起努力找到一个双方都能接受的折中方案。','9988-10063',1,1738152240,1782398552);
INSERT INTO highlights VALUES('33915626_5_6142-6201','33915626',5,'CHAPTER 3 为什么会吵架','每个强烈情绪的背后必然会有故事。做好准备和对方讲述相关故事，并寻求对方的理解，这会帮助你们以智慧、平和的方式处理问题。','6142-6201',1,1738151821,1782398552);
INSERT INTO highlights VALUES('33915626_5_4725-4772','33915626',5,'CHAPTER 3 为什么会吵架','反之，要承认它们是永久性问题，因为这些问题最终的导向不是解决方案，而是接受并珍视你们的不同点。','4725-4772',1,1738151619,1782398552);
INSERT INTO highlights VALUES('33915626_5_3917-4003','33915626',5,'CHAPTER 3 为什么会吵架','事实上，一段婚姻的幸福程度取决于两个人是否能学会和永久性问题共存。而这些看似无解的永久性问题里隐藏着促进你们成长和增进两性感情的机会。','3917-4003',1,1738150918,1782398552);
