INSERT INTO highlights VALUES('33915626_3_10290-10380','33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','但是能否柳暗花明完全取决于两人的态度。要看两人是否能积极看待这些负面事件及伴侣的性格，并能够在日常生活中最大化地在意识层面趋利避害（即多想想伴侣的可爱之处和这段关系中光明的一面）。','10290-10380',1,1723543096,1782398552);
