INSERT INTO highlights VALUES('33915626_3_2218-2253','33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','把留出固定的时间专心陪伴爱人当作生命的重中之重，并保持对爱人的好奇心。','2218-2253',1,1723542206,1782398552);
INSERT INTO highlights VALUES('33915626_3_1716-1788','33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','伴侣间的互相了解永远没有期限，你可以一辈子都对伴侣的内心世界保持好奇，一辈子都勇于和他（她）分享自己的内心世界，并且永远不停止对他（她）的探索。','1716-1788',1,1723542156,1782398552);
INSERT INTO highlights VALUES('33915626_3_1607-1653','33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','天长地久的爱情是朝夕相处的产物，成功的亲密关系来源于平凡日子里一句慰勉的话语、一个关怀的动作','1607-1653',1,1723542144,1782398552);
