INSERT INTO highlights VALUES('216219_43_3030-3093','216219',43,'十八 四厢花影怒于潮','少年哀乐过于人，歌泣无端字字真。既壮周旋杂痴黠，童心来复梦中身。','3030-3093',1,1726399815,1782398557);
