INSERT INTO highlights VALUES('216219_42_5559-5675','216219',42,'十七 禅者，活泼泼也','杨万里还有一首《舟过谢潭》，也是很好的例子：碧酒时倾一两杯，船门才闭又还开。好山万皱无人见，都被斜阳拈出来。','5559-5675',1,1726399309,1782398557);
INSERT INTO highlights VALUES('216219_42_6160-6227','216219',42,'十七 禅者，活泼泼也','只有对美敏感的人，心意与造化之流行息息相通的人，才能够在一个恰当的瞬间，因为心与造化的共同作用，看到新异的景色以完美的形态呈现在眼前。','6160-6227',1,1726399127,1782398557);
INSERT INTO highlights VALUES('216219_42_5975-6036','216219',42,'十七 禅者，活泼泼也','同时，仍然是杨万里特有的对美的敏感。钱锺书先生说他的诗如同摄影的快镜头，善于捕捉变幻的影像，加以定格，在这首诗中尤为显著。','5975-6036',1,1726399091,1782398557);
INSERT INTO highlights VALUES('216219_42_5381-5456','216219',42,'十七 禅者，活泼泼也','一颗沙里看出一个世界，一朵野花里看出一座天堂。把无限放在你的手掌上，永恒在一刹那里收藏。','5381-5456',1,1726399027,1782398557);
INSERT INTO highlights VALUES('216219_42_5485-5530','216219',42,'十七 禅者，活泼泼也','诗人能够在极平凡处发现美，是因为“活泼”活泼是生命感受活跃的状态，我们不能说这是不重要的。','5485-5530',1,1726399021,1782398557);
INSERT INTO highlights VALUES('216219_42_5205-5249','216219',42,'十七 禅者，活泼泼也','在这首诗里真正打动读者的东西是诗人的敏感，他从稍纵即逝的景物变化中捕捉到最为动人的瞬间。','5205-5249',1,1726398935,1782398557);
INSERT INTO highlights VALUES('216219_42_4367-4394','216219',42,'十七 禅者，活泼泼也','大自然适时地将美好的事物呈献给人类，生命因此是美好的。','4367-4394',1,1726398824,1782398557);
INSERT INTO highlights VALUES('216219_42_2880-3009','216219',42,'十七 禅者，活泼泼也','什么叫作“活法”呢？关键有两点：一是对外界事物具有高度的敏感，写寻常景象也总有新鲜的趣味；二是语言不落俗套，鲜活生动。而归根结底，它体现了活跃的生命状态。这种诗常常并不包含说理的成分，却让人感到某种“理趣”或“禅味”，因为这里面融入了诗人对自然和人生的感悟。','2880-3009',1,1726398700,1782398557);
INSERT INTO highlights VALUES('216219_42_2169-2333','216219',42,'十七 禅者，活泼泼也','“半亩方塘”是指人的心境。古人常用“方寸之地”来形容人心，言其体量甚小。可是人的精神世界又是多么神奇、多么广大啊，古往今来，天文地理，它真是无所不能容纳。并且，它也并不只是被动地反映美妙的大千世界，它还品味万物，给万物以新的生命和风采。用小小池塘中“天光云影共徘徊”这样美丽的景象来象征人的精神世界，令人感受到一种欣欣然的生气。','2169-2333',1,1726398622,1782398557);
INSERT INTO highlights VALUES('216219_41_5320-5383','216219',41,'十六 春来草自青','偷放风鸢不在家，先生差伴没处拿。有人指点春郊外，雪下红衫便是他。','5320-5383',1,1726398376,1782398557);
INSERT INTO highlights VALUES('216219_40_1690-1786','216219',40,'十五 长啸一声天地秋','云和水本是一物，但云在天是空阔无碍、任意舒卷的景象，水在瓶却是拘局而无法舒展的状态。要说“道”本该是无形之物，一旦固执便成了“瓶”；“瓶”不打碎，何从谈“道”？这么读，就隐含了批评儒道的意思。','1690-1786',1,1726396167,1782398557);
INSERT INTO highlights VALUES('216219_40_1586-1630','216219',40,'十五 长啸一声天地秋','水在瓶则静而定，波澜不起；在天则化为云，自在飘浮，所以顺自然，适物性，应物随缘就是“道”','1586-1630',1,1726396109,1782398557);
INSERT INTO highlights VALUES('216219_40_1517-1525','216219',40,'十五 长啸一声天地秋','云在天，水在瓶。','1517-1525',1,1726396095,1782398557);
INSERT INTO highlights VALUES('216219_40_850-900','216219',40,'十五 长啸一声天地秋','如何是奇特事？”百丈答云：独坐大雄峰。','850-900',1,1726396085,1782398557);
INSERT INTO highlights VALUES('216219_40_1445-1452','216219',40,'十五 长啸一声天地秋','“何谓道耶”，','1445-1452',1,1726396078,1782398557);
INSERT INTO highlights VALUES('216219_39_4465-4510','216219',39,'十四 雁过长空，影沉寒水','世事总是因人成相，而人人各据一端，所见不同。要想见真相，需要脱离自身的处境，从高远处观照。','4465-4510',1,1726395753,1782398557);
INSERT INTO highlights VALUES('216219_39_2218-2227','216219',39,'十四 雁过长空，影沉寒水','应无所住，而生其心','2218-2227',1,1726395560,1782398557);
INSERT INTO highlights VALUES('216219_39_1595-1633','216219',39,'十四 雁过长空，影沉寒水','雁过长空，影沉寒水。雁无遗踪之意，水无留影之心。若能如是，方解向异类中行。”','1595-1633',1,1726394119,1782398557);
INSERT INTO highlights VALUES('216219_39_1004-1064','216219',39,'十四 雁过长空，影沉寒水','人的一生很难说有什么既定目标，因为外在环境与条件的变化不受人的意志控制；人生到处会留下一些痕迹，但那些痕迹很快都会消失。','1004-1064',1,1726386372,1782398557);
INSERT INTO highlights VALUES('216219_39_670-826','216219',39,'十四 雁过长空，影沉寒水','人生到处知何似？应似飞鸿踏雪泥。泥上偶然留指爪，鸿飞那复计东西？老僧已死成新塔，坏壁无由见旧题。往日崎岖还记否？路长人困蹇驴嘶','670-826',1,1726377942,1782398557);
INSERT INTO highlights VALUES('216219_39_429-483','216219',39,'十四 雁过长空，影沉寒水','生命只是一种偶然，万千景象不过都是瞬间的变化。','429-483',1,1726377903,1782398557);
INSERT INTO highlights VALUES('216219_38_2476-2539','216219',38,'十三 见山是山，见水是水','庐山烟雨浙江潮，未到千般恨不消。到得还来别无事，庐山烟雨浙江潮。','2476-2539',1,1726371511,1782398557);
INSERT INTO highlights VALUES('216219_38_2353-2363','216219',38,'十三 见山是山，见水是水','苏轼写的《庐山烟雨》','2353-2363',1,1726371499,1782398557);
INSERT INTO highlights VALUES('216219_38_3317-3359','216219',38,'十三 见山是山，见水是水','《菜根谭》说：“文章做到极处，无有他奇，只是恰好；人品做到极处，无有他异，只是本然。','3317-3359',1,1726371435,1782398557);
INSERT INTO highlights VALUES('216219_38_2257-2314','216219',38,'十三 见山是山，见水是水','人本是人，不必刻意去做人；世本是世，无须精心去处世。便也是真正的做人与处世了。”返归自然朴素，就是人生“休歇处”。','2257-2314',1,1726371321,1782398557);
INSERT INTO highlights VALUES('216219_38_2080-2155','216219',38,'十三 见山是山，见水是水','第三阶段是事物自身显示出不同，并非我们以自己的需要和特定的立场去探究而发现的，我们只是平淡地接受事物的不同。三个阶段大致是“成见—破成见—回到本来”。','2080-2155',1,1726371258,1782398557);
INSERT INTO highlights VALUES('216219_38_1906-1938','216219',38,'十三 见山是山，见水是水','用阿部正雄的话来说：“否定性的观念也必须被否定。空必须空掉自身，','1906-1938',1,1726371219,1782398557);
INSERT INTO highlights VALUES('216219_38_1750-1861','216219',38,'十三 见山是山，见水是水','在这个否定阶段，万物皆空。物、我的对立不存在了，是非也好，善恶也好，其实都是名相。“恶”难道不是“社会认定恶”吗？“好”难道不是“我觉得好”吗？癞蛤蟆哪里会爱上天鹅，它觉得天鹅丑得出奇!这时候，“见山不是山，见水不是水”。','1750-1861',1,1726371195,1782398557);
INSERT INTO highlights VALUES('216219_38_1890-1906','216219',38,'十三 见山是山，见水是水','但一味执着于“空”也是一种偏执。','1890-1906',1,1726371183,1782398557);
INSERT INTO highlights VALUES('216219_38_1453-1478','216219',38,'十三 见山是山，见水是水','但“社会”有它的历史性偏执，“我”有它的个体性偏执','1453-1478',1,1726371142,1782398557);
INSERT INTO highlights VALUES('216219_38_1337-1424','216219',38,'十三 见山是山，见水是水','在接受教育的过程中，我们获得了认识事物的方法和评判事物的标准。构成常识的还有一个要素是自我。人总是自然地倾向于肯定自我，把“我”置于万物的中心地位，用“我”的眼光来看待一切。','1337-1424',1,1726371132,1782398557);
INSERT INTO highlights VALUES('216219_38_429-486','216219',38,'十三 见山是山，见水是水','我们看到的“清清楚楚”的东西，其实并不是事物的真相。','429-486',1,1726370844,1782398557);
INSERT INTO highlights VALUES('216219_37_3854-3928','216219',37,'十二 吃茶去','你老想着晴，偏偏就来风雨，结果“晴”反而成了精神负担。只有随缘，才能自得；只有淡定，才能旷达。随缘和淡定，才是在坎坷的人生道路上自己需要把握的力量。','3854-3928',1,1726370799,1782398557);
INSERT INTO highlights VALUES('216219_37_3438-3543','216219',37,'十二 吃茶去','说到底，人生到处是艰辛，此时有风彼时有雨。想要一路平平安安，什么麻烦都没有，这本身就是不正常的念头。“一蓑烟雨任平生”，蓑衣总还是有的，应对麻烦的办法总还是有的。那么，无论遇到什么，除了坦然面对，还能怎么样呢？','3438-3543',1,1726370734,1782398557);
INSERT INTO highlights VALUES('216219_37_2664-2741','216219',37,'十二 吃茶去','“要知冰雪心肠好，不是膏油首面新。戏作小诗君勿笑，从来佳茗似佳人。”（《次韵曹辅寄壑源试焙新茶》）好茶是朴素的，天然风韵，就像真正的美女，不需要涂脂抹粉。','2664-2741',1,1726370633,1782398557);
INSERT INTO highlights VALUES('216219_37_1504-1511','216219',37,'十二 吃茶去','我们也吃茶吧。','1504-1511',1,1726369721,1782398557);
INSERT INTO highlights VALUES('216219_37_1351-1475','216219',37,'十二 吃茶去','茶和酒不一样，酒让人兴奋，茶让人平静。茶味清香甘甜，略带苦涩，蕴含着大自然的气息。只有在平心静气的情形下，才能充分品尝茶的妙处；也正是在品尝绵长的茶味时，人心渐渐淡定起来。习禅先要“吃茶去”，就是首先要让人生种种繁杂的念头消歇，使内心渐渐清澈澄明。','1351-1475',1,1726369575,1782398557);
INSERT INTO highlights VALUES('216219_37_417-474','216219',37,'十二 吃茶去','世事无常，都在变化之中，该来的总要来，该走的总要走。','417-474',1,1726369391,1782398557);
INSERT INTO highlights VALUES('216219_36_4981-5003','216219',36,'十一 平常心是道','得道的人是平静的，在平静中感受到生命的愉悦。','4981-5003',1,1726368514,1782398557);
INSERT INTO highlights VALUES('216219_36_4687-4730','216219',36,'十一 平常心是道','关键只是在于要明白差别的成因，懂得名相的依据，摆脱偏执的立场。所谓万象各异，真如一体。','4687-4730',1,1726368458,1782398557);
INSERT INTO highlights VALUES('216219_36_4362-4541','216219',36,'十一 平常心是道','地球是个球体，哪有什么固定不变的东南西北!人间的事情也是如此。站在对立的立场上，甲有甲的是非，乙有乙的是非，“彼亦一是非，此亦一是非”（语出《庄子》），等到对立消失，是非亦随着消失。人若过分地执着于自我，永远也不能理解他人的立场，永远只有自己道理十足，不合自己的道理就必然错。这样，也许自己会觉得满足，可是哪里还能看到事物的本相呢？贪、嗔、痴，无非由此而起。','4362-4541',1,1726368396,1782398557);
INSERT INTO highlights VALUES('216219_36_4183-4209','216219',36,'十一 平常心是道','世间万物是有差别的吗？其实种种差别，都是由人而生的。','4183-4209',1,1726368333,1782398557);
INSERT INTO highlights VALUES('216219_36_3477-3517','216219',36,'十一 平常心是道','总之是让人摸不着头脑，但这些奇怪的回答其实都有一个共同的答案那是各人自己的事情！','3477-3517',1,1726368238,1782398557);
INSERT INTO highlights VALUES('216219_36_2381-2438','216219',36,'十一 平常心是道','事之自然”，不能够以淡然的心情去面对一切，欣赏事物的趣味，那真的容易觉得“不好”，看不到处处都在的“人间好时节”。','2381-2438',1,1726367804,1782398557);
INSERT INTO highlights VALUES('216219_36_1660-1779','216219',36,'十一 平常心是道','这样来看“平常心”，说简单其实也很简单，就是远离颠倒梦想，不因世间的荣辱得失而妄生喜忧；就是处变不惊，遇事泰然自若、无所畏惧；就是万事随缘，不勉强不焦躁，平平淡淡；就是宽容大度，不苛刻，不张狂；就是不避艰辛，踏实劳作，一分耕耘一分收获……','1660-1779',1,1726367735,1782398557);
INSERT INTO highlights VALUES('216219_36_421-484','216219',36,'十一 平常心是道','世俗的知识和欲念就像一件湿衣服一样，紧紧裹在我们身上，脱不下来。','421-484',1,1726367559,1782398557);
INSERT INTO highlights VALUES('216219_35_2274-2290','216219',35,'十 禅意的月亮','一月普现一切水，一切水月一月摄。','2274-2290',1,1726367496,1782398557);
INSERT INTO highlights VALUES('216219_35_419-486','216219',35,'十 禅意的月亮','月亮只有一轮，却普遍地在一切水中显现出来，一切水中的月亮乃是一月的显现。','419-486',1,1726367478,1782398557);
INSERT INTO highlights VALUES('216219_35_5558-5605','216219',35,'十 禅意的月亮','欲望永无止境，迷乱也随之增加。甘于平淡，耐得寂寞，才能保持内心的纯明，就像那月下的松林与山泉。','5558-5605',1,1726367248,1782398557);
INSERT INTO highlights VALUES('216219_35_4856-4871','216219',35,'十 禅意的月亮','贾平凹有一篇《明月清泉自在怀》','4856-4871',1,1726367093,1782398557);
INSERT INTO highlights VALUES('216219_35_4908-5057','216219',35,'十 禅意的月亮','苦也罢，乐也罢；得也罢，失也罢要紧的是心间的一泓清泉里不能没有月辉。哲学家培根说过：‘历史使人明智，诗歌使人灵秀。’顶上的松月、足下的流泉，以及座下的磐石，何曾因宠辱得失而抛却自在？又何曾因风霜雨雪而易移萎缩？它们自我踏实，不变心性，才有了千年的阅历、万年的长久，也才有了诗人的神韵和学者的品性。”','4908-5057',1,1726367087,1782398557);
INSERT INTO highlights VALUES('216219_35_3496-3520','216219',35,'十 禅意的月亮','自然的美好，只对那些热爱自然、童心未泯的人存在。','3496-3520',1,1726366626,1782398557);
INSERT INTO highlights VALUES('216219_34_7059-7262','216219',34,'九 夜半钟声到客船','人生总是有很多艰辛，除了对自己，没有人可以说。一千二百多年前的这个夜晚，张继长夜无眠。世界是美好的，江南水乡的秋夜格外清幽，作为诗人，张继能够体会它。但世界也是难以理解的，你无法知道究竟是什么东西催逼着人不由自主地奔走不息，孤独地漂泊。这时候钟声响了，清晰地撞击着人的内心。深夜里，张继听到一种呼唤，他找到近乎完美的语言形式把这个夜晚感受到的一切保存下来。寒山寺的夜钟，从那一刻到永远，被无数人在心中体味。','7059-7262',1,1726310957,1782398557);
INSERT INTO highlights VALUES('216219_34_2922-3063','216219',34,'九 夜半钟声到客船','但是就像水，如果水是污浊而又混乱的，它就不可能反映出外界的本相；人心也是如此，如果心中充满烦恼、欲望，动荡不宁，它也不可能洞见事物的本来面目。同时，“寂照”也就是“照寂”，就是用寂然的心照见万物寂然的本质。世间诸相似为实有而终归虚幻，就像潭水中浮动着的云光山影，那是一种虚幻的美景。','2922-3063',1,1726310077,1782398557);
INSERT INTO highlights VALUES('216219_34_2668-2712','216219',34,'九 夜半钟声到客船','这是一种非常相近的感受：只有热爱自然的人，才能为自然所爱，他们和自然之间有着神秘的语言。','2668-2712',1,1726310017,1782398557);
INSERT INTO highlights VALUES('216219_34_2546-2639','216219',34,'九 夜半钟声到客船','我遇见的第一件好事，在白晃晃的清新小径，一朵花告诉我她的姓名。','2546-2639',1,1726310011,1782398557);
INSERT INTO highlights VALUES('216219_33_1079-1099','216219',33,'八 我今不是渠','无情说法”（无生命之物也能显示佛法之义）','1079-1099',1,1726309226,1782398557);
INSERT INTO highlights VALUES('216219_32_4444-4512','216219',32,'七 只许佳人独自知','缘已尽时还不能洒脱地放下，只会把一切都弄得很糟糕。爱有尽头，恨也有尽头。不能爱时便不爱，事已过去便不恨，不能死在爱与恨里，一切才有生机。','4444-4512',1,1726309104,1782398557);
INSERT INTO highlights VALUES('216219_32_3779-3842','216219',32,'七 只许佳人独自知','你既无心我亦休，此身无喜亦无忧。饥来吃饭困来睡，花落从教逐水流。','3779-3842',1,1726308983,1782398557);
INSERT INTO highlights VALUES('216219_32_3151-3160','216219',32,'七 只许佳人独自知','“你既无心我便休”','3151-3160',1,1726308974,1782398557);
INSERT INTO highlights VALUES('216219_32_5636-5662','216219',32,'七 只许佳人独自知','这是表明法界真如，在世而不为世污，自性开发，不赖外力','5636-5662',1,1726308926,1782398557);
INSERT INTO highlights VALUES('216219_32_5511-5563','216219',32,'七 只许佳人独自知','禅并不意味禁欲，它只是追求对于欲的超脱。说到底就是：人既生活于情欲之中，又需要由情欲走向更高的心灵境界。','5511-5563',1,1726308911,1782398557);
INSERT INTO highlights VALUES('216219_32_5407-5487','216219',32,'七 只许佳人独自知','俺法门像什么？像荷叶上露水珠儿，又要沾着，又要不沾着；又像荷叶下淤泥藕节，又不要龌龊，又要些龌龊。”这是说“法门”的洁净不是与日常生活脱离，它仍然植根在生活之中','5407-5487',1,1726308901,1782398557);
INSERT INTO highlights VALUES('216219_31_423-480','216219',31,'六 春在枝头已十分','那个遍寻不得的意中人，原来就在身边不曾注意到的地方。','423-480',1,1726307520,1782398557);
INSERT INTO highlights VALUES('216219_31_3974-3997','216219',31,'六 春在枝头已十分','最高的完成并不是外在目标的完成，而是自我的完成','3974-3997',1,1726307281,1782398557);
INSERT INTO highlights VALUES('216219_31_3662-3918','216219',31,'六 春在枝头已十分','“衣带渐宽终不悔，为伊消得人憔悴。”这是第二层境界。词句出于柳永的《蝶恋花》，本意是写相思中的人虽历尽艰辛，但依然执着的心情。王国维用来譬喻在追求远大目标的过程中，必然会陷入迷惘，遭遇困顿，而这时需要“九死而无悔”的坚毅，哪怕看不到出路，也绝不回头。“众里寻他千百度，蓦然回首，那人却在灯火阑珊处。”这是第三层境界。词句出于辛弃疾的《青玉案》，本意是说那个遍寻不得的意中人，原来就在身边不曾注意到的地方。王国维用来譬喻在经历各种周折与磨炼之后，豁然开朗。','3662-3918',1,1726307264,1782398557);
INSERT INTO highlights VALUES('216219_31_3405-3633','216219',31,'六 春在枝头已十分','所以王国维在《人间词话》里，借用禅宗的顿悟经验，总结“古今之成大事业、大学问者”，必然要经过的三层境界。“昨夜西风凋碧树。独上高楼，望尽天涯路。”这是第一层境界。这里的词句出自晏殊的《蝶恋花》，原来是写思妇上高楼眺望远方，只见一片萧飒的秋景，不知所想念的人儿到底在何方。王国维用它来譬喻具有崇高理想的人不畏孤独、目光远大、意志坚决，穷尽一切力量寻求和确定人生的目标。这时主人公的注意力完全是向外的。','3405-3633',1,1726307155,1782398557);
INSERT INTO highlights VALUES('216219_31_1219-1282','216219',31,'六 春在枝头已十分','尽日寻春不见春，芒鞋踏遍陇头云。归来笑拈梅花嗅，春在枝头已十分。','1219-1282',1,1726306849,1782398557);
INSERT INTO highlights VALUES('216219_31_1659-1702','216219',31,'六 春在枝头已十分','只是人类的意识已经习惯了用对立的方法来看待万物，物我对立，善恶对立，是非对立，黑白对立','1659-1702',1,1726293602,1782398557);
INSERT INTO highlights VALUES('216219_30_5080-5143','216219',30,'五 坐看云起时','手把青秧插满田，低头便见水中天。六根清净方为道，退步原来是向前。','5080-5143',1,1726181050,1782398557);
INSERT INTO highlights VALUES('216219_30_6945-7087','216219',30,'五 坐看云起时','从禅宗的思想来说，“进”或者“退”其实不过是人根据需要所做的假设，本身就是虚妄的。目标设在东，往西走是“退”。目标反过来呢？那就是“进”了。昨天以为进步了，今天形势一变，居然是倒退!如果不能圆融地看待世俗的价值和行为常规，就会陷入虚妄的意念中，手舞足蹈，念念有词，归根结底，一场虚空。','6945-7087',1,1726181038,1782398557);
INSERT INTO highlights VALUES('216219_30_7179-7213','216219',30,'五 坐看云起时','主张随缘，以一种安静而活泼的心情对待世间的变化，因此获得人生的乐趣。','7179-7213',1,1726180989,1782398557);
INSERT INTO highlights VALUES('216219_30_5385-5438','216219',30,'五 坐看云起时','大肚能容容天下难容之事开口便笑笑世间可笑之人','5385-5438',1,1726180752,1782398557);
INSERT INTO highlights VALUES('216219_30_3737-3742','216219',30,'五 坐看云起时','山中问答》','3737-3742',1,1726180658,1782398557);
INSERT INTO highlights VALUES('216219_30_4732-4824','216219',30,'五 坐看云起时','花谢了，你可以把它看成一个过程的结束，而人们为之伤感，是因为联想到一切美好的事物都不长久。但在大自然的无限生机里，花落只是一个变化；在落花随流水而去的所在，有另一片美好的天地向你展开。','4732-4824',1,1726180510,1782398557);
INSERT INTO highlights VALUES('216219_30_4060-4123','216219',30,'五 坐看云起时','问余何意栖碧山，笑而不答心自闲。桃花流水窅然去，别有天地非人间。','4060-4123',1,1726180411,1782398557);
INSERT INTO highlights VALUES('216219_30_3136-3150','216219',30,'五 坐看云起时','，而诗人的天性在于对美的敏感','3136-3150',1,1726180267,1782398557);
INSERT INTO highlights VALUES('216219_30_2145-2181','216219',30,'五 坐看云起时','走到路的尽头无路可走，并不是挫折也无所谓困顿，而是随遇而安，到处都有佳境','2145-2181',1,1726180122,1782398557);
INSERT INTO highlights VALUES('216219_29_5181-5250','216219',29,'四 满船空载月明归','世间有无穷的是非、无穷的争执，还有无穷的诱惑，人不能不在其中走过，要全然不动心也许很难，但若是处处动心，那恐怕要一生慌张，片刻也不得安宁。','5181-5250',1,1726179899,1782398557);
INSERT INTO highlights VALUES('216219_29_2332-2368','216219',29,'四 满船空载月明归','“满船空载月明归”，你什么也没有得到，空船而去，空船而归，但心是欢喜的。','2332-2368',1,1726179360,1782398557);
INSERT INTO highlights VALUES('216219_29_1666-1674','216219',29,'四 满船空载月明归','满船空载月明归。','1666-1674',1,1726179349,1782398557);
INSERT INTO highlights VALUES('216219_29_4454-4521','216219',29,'四 满船空载月明归','但有时人也可以安静下来，把事件和焦虑放在身心之外。于是，那些在生活的事件中全然无意义的东西，诸如草叶的摇动、小鸟的鸣唱，忽然都别有韵味','4454-4521',1,1726179199,1782398557);
INSERT INTO highlights VALUES('216219_29_4222-4326','216219',29,'四 满船空载月明归','人总是活得很匆忙，无数的生活事件迭为因果、相互拥挤，造成人们心理的紧张和焦虑；在这种紧张与焦虑之中，时间的频率显得格外急促。而假如我们把人生比拟为一场旅行，那么渡口、车站这一类地方就更集中地显示了人生的慌乱。','4222-4326',1,1726179173,1782398557);
INSERT INTO highlights VALUES('216219_29_4561-4619','216219',29,'四 满船空载月明归','当人摆脱了事件之链，这一刻也就从时间之链上解脱出来。它是完全孤立的，它不是某个过程的一部分，而是世界的永恒性的呈现。','4561-4619',1,1726179138,1782398557);
INSERT INTO highlights VALUES('216219_29_935-1030','216219',29,'四 满船空载月明归','当人们判断一个事物“是什么”或“怎么样”的时候，他自身的立场、知识、经验，以及价值尺度是在起作用的，这个时候他往往看不到事物的本质。当一个人内心充满温情时，世界是美好的，春花固佳，秋叶亦美。','935-1030',1,1726178593,1782398557);
INSERT INTO highlights VALUES('216219_29_748-764','216219',29,'四 满船空载月明归','心生则种种法生，心灭则种种法灭。','748-764',1,1726178580,1782398557);
INSERT INTO highlights VALUES('216219_28_7388-7414','216219',28,'三 何处惹尘埃','“心外无佛”。每个人的心性就是佛性，成佛只在自悟本性','7388-7414',1,1726178269,1782398557);
INSERT INTO highlights VALUES('216219_28_5033-5065','216219',28,'三 何处惹尘埃','六祖慧能。有人把他和孔子、老子并列，称为中国儒、道、释的“三圣”','5033-5065',1,1724338700,1782398557);
INSERT INTO highlights VALUES('216219_28_4115-4176','216219',28,'三 何处惹尘埃','我们在世间会遭遇很多变化，也必须应对这些变化，但我们的内心必须保持平静和稳定，能不被外界的变化带着走，这就是“空”的意义。','4115-4176',1,1724338588,1782398557);
INSERT INTO highlights VALUES('216219_28_3878-3950','216219',28,'三 何处惹尘埃','譬如说，你做了官，官位就是你把着的“锄头”。如果不能意识到自己说到底是“空手”，迷失在官腔官威中，只会做官，不会做人，那么你整个就变成“锄头”了','3878-3950',1,1724338546,1782398557);
INSERT INTO highlights VALUES('216219_28_3725-3758','216219',28,'三 何处惹尘埃','无论人处在什么样的境况下，都需要保持心性的空明，而不受外物的牵累。','3725-3758',1,1724338441,1782398557);
INSERT INTO highlights VALUES('216219_28_3221-3276','216219',28,'三 何处惹尘埃','空手把锄头，步行骑水牛。人从桥上过，桥流水不流。','3221-3276',1,1724338407,1782398557);
INSERT INTO highlights VALUES('216219_28_2816-2903','216219',28,'三 何处惹尘埃','佛性是在天地尚未形成之前就已经存在的，它没有具体的外形可以让人们看见与捉摸，却无所不包容；它不生不灭，万古长存，既是永恒的空寂，也是无时无刻不在刹那间生生灭灭的万事万物的本体','2816-2903',1,1724338359,1782398557);
INSERT INTO highlights VALUES('216219_28_2724-2779','216219',28,'三 何处惹尘埃','有物先天地，无形本寂寥。能为万象主，不逐四时凋。','2724-2779',1,1724338340,1782398557);
INSERT INTO highlights VALUES('216219_28_2991-3025','216219',28,'三 何处惹尘埃','有物混成，先天地生。寂兮寥兮，独立而不改，周行而不殆，可以为天地母。','2991-3025',1,1724338334,1782398557);
INSERT INTO highlights VALUES('216219_27_4982-5025','216219',27,'二 拈花微笑','禅悟是一种摆脱语言阐释和逻辑分析，通过个体的体验与实践彻悟真理，使生命趋向完美的过程。','4982-5025',1,1724337916,1782398557);
INSERT INTO highlights VALUES('216219_27_4862-4936','216219',27,'二 拈花微笑','“拈花微笑”的故事被人们喜爱，还有更平凡、更日常性的原因，就是它象征了一种生活态度：以恬静而欢喜的心情看待世间的一切，笑对众生，笑对万事，自然超脱。','4862-4936',1,1724337865,1782398557);
INSERT INTO highlights VALUES('216219_27_4034-4110','216219',27,'二 拈花微笑','并处处告诫人们对语言的不足保持警惕，强调就像使用“筌”的目的是捕鱼，使用语言是为了达意，要懂得“得鱼而忘筌，得意而忘言”，到了最高境界，便是会意的静穆。','4034-4110',1,1724337769,1782398557);
INSERT INTO highlights VALUES('216219_27_3752-3801','216219',27,'二 拈花微笑','宗白华先生说：“禅是中国人接触佛教大乘义后体认到自己心灵的深处而灿烂地发挥到哲学境界与艺术境界。”','3752-3801',1,1724337639,1782398557);
INSERT INTO highlights VALUES('216219_27_2618-2693','216219',27,'二 拈花微笑','这个“最上大法”是真实的，却没有任何迹象，它极其微妙，无法用语言、文字来解说，只能在心心相印中传递。当时只有摩诃迦叶感知到释迦牟尼在无言中宣示的大法，','2618-2693',1,1724337149,1782398557);
INSERT INTO highlights VALUES('216219_27_1341-1405','216219',27,'二 拈花微笑','伟大的思想者都会在某个时刻意识到一个问题：已有的一切学说都无法使他感到满足，他找不到老师了。这使释迦牟尼感到一种近于绝望的痛苦。','1341-1405',1,1724336994,1782398557);
INSERT INTO highlights VALUES('216219_27_417-463','216219',27,'二 拈花微笑','花虽微渺，却显示着人世的美好。','417-463',1,1724336722,1782398557);
INSERT INTO highlights VALUES('216219_26_5331-5343','216219',26,'一 鸟鸣山更幽','曲径通幽处，禅房花木深”','5331-5343',1,1724330784,1782398557);
INSERT INTO highlights VALUES('216219_26_4366-4370','216219',26,'一 鸟鸣山更幽','松尾芭蕉','4366-4370',1,1724330656,1782398557);
INSERT INTO highlights VALUES('216219_26_4018-4051','216219',26,'一 鸟鸣山更幽','诗止于感性，它给出了提示，让人受到感染，然后停留在意味深长的瞬间。','4018-4051',1,1724330624,1782398557);
INSERT INTO highlights VALUES('216219_26_3260-3358','216219',26,'一 鸟鸣山更幽','如果说，世界根本是个“无常”，海也会枯，石也会烂，但那种过程不是某个人在某个当下可以体会到的，它有赖于知识和推理。而声音和光，则无时不在变化之中，无时不在演示无常，只是它太平凡，人们未必能注意到。','3260-3358',1,1724330406,1782398557);
INSERT INTO highlights VALUES('216219_26_1537-1569','216219',26,'一 鸟鸣山更幽','遥望远处的山峰萦绕着淡淡的云霞，近处阳光伴随着水波的流动而闪耀。','1537-1569',1,1724330132,1782398557);
INSERT INTO highlights VALUES('216219_26_1205-1217','216219',26,'一 鸟鸣山更幽','蝉噪林逾静，鸟鸣山更幽。','1205-1217',1,1724330041,1782398557);
INSERT INTO highlights VALUES('216219_26_419-442','216219',26,'一 鸟鸣山更幽','一切都会过去，变化的背后仍然是一片深邃的幽静。','419-442',1,1724329766,1782398557);
INSERT INTO highlights VALUES('216219_25_1004-1041','216219',25,'代序 从诗走进禅，一路好风光','苍山空寂，明月清朗，幽潭澄澈，野花自开自落，浮云时聚时散，这里面都有禅意。','1004-1041',1,1721470908,1782398557);
INSERT INTO highlights VALUES('3300074997_45_355-375','3300074997',45,'尝试让他自拟题目，写作会成为一件快乐的事','尝试让他自拟题目，写作会成为一件快乐的事','355-375',1,1701097750,1782398596);
INSERT INTO highlights VALUES('3300074997_43_1739-1802','3300074997',43,'第九章 教会孩子快乐写作','夏夜，有时天上布满无数星星，我喜欢坐在花园里，静静地看它们，听它们说话的声音。凉风从花园的树叶间吹过，树叶也像在低声细语……”','1739-1802',1,1701097330,1782398596);
INSERT INTO highlights VALUES('3300074997_43_1400-1525','3300074997',43,'第九章 教会孩子快乐写作','来，我们试试快乐的写作方法。现在假设你要写一篇关于花园的文章，你的朋友们看了后，都想来玩，如果这样想的话，写作就会变得简单啦。实际上，你已经很熟悉我们的花园了，用不着像画画一样照着写，你可以想想这里曾经发生过什么事情，写下那些让你难忘的事情就行了。”','1400-1525',1,1701097317,1782398596);
INSERT INTO highlights VALUES('3300074997_43_530-571','3300074997',43,'第九章 教会孩子快乐写作','我认为，世界上比语言更生动的是真实的情感和思想，比言辞更有魅力的是真实的事物本身。','530-571',1,1701097193,1782398596);
INSERT INTO highlights VALUES('3300074997_43_421-431','3300074997',43,'第九章 教会孩子快乐写作','教孩子找到自己的语言','421-431',1,1701097177,1782398596);
INSERT INTO highlights VALUES('3300074997_42_2322-2538','3300074997',42,'每个家庭都应该有藏书，更重要的是培养孩子的阅读兴趣','3～6岁的孩子喜欢配有丰富色彩和图画简短故事、科幻故事以及动物的童话，书中那些短小、生动、易背诵的重叠句对孩子很有帮助。6～8岁的孩子在阅读书籍时，渐渐有了自己的偏好。除了父母认为重要的以外，可让他们自己去选择。至于8岁以上的孩子，他们会喜欢一些幽默的故事、传统的民间故事、古典名著与名著、奇幻故事以及侦探推理小说等','2322-2538',1,1701096613,1782398596);
INSERT INTO highlights VALUES('3300074997_42_1017-1036','3300074997',42,'每个家庭都应该有藏书，更重要的是培养孩子的阅读兴趣','1.培养孩子读书的兴趣，开始得越早越好','1017-1036',1,1701096543,1782398596);
INSERT INTO highlights VALUES('3300074997_42_1377-1427','3300074997',42,'每个家庭都应该有藏书，更重要的是培养孩子的阅读兴趣','具体在每天的什么时间读书并不重要，只要每天坚持在同一个时间读上15分钟书，就一定会有意想不到的效果。','1377-1427',1,1701096534,1782398596);
INSERT INTO highlights VALUES('3300074997_41_4440-4466','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','缺乏生活自理能力的孩子，他的自我教育能力也会比较差。','4440-4466',1,1701096427,1782398596);
INSERT INTO highlights VALUES('3300074997_41_3931-3943','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','4.让孩子自己拟订计划表','3931-3943',1,1701096304,1782398596);
INSERT INTO highlights VALUES('3300074997_41_3747-3787','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','“难过可以一个人承受，但快乐最好能与人分享”这句话放在孩子的自我教育上也非常适合','3747-3787',1,1701096254,1782398596);
INSERT INTO highlights VALUES('3300074997_41_2507-2634','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','(5)向孩子提出一些新的问题，让他依靠自己的力量去寻找答案。(6)对他因兴趣而产生的成果，作出阶段性的评价，让他看到评价的变化。他会高兴也会很重视这种评价，并从变化中思考怎样获得好评价的方法。','2507-2634',1,1701095825,1782398596);
INSERT INTO highlights VALUES('3300074997_41_2389-2428','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','(3)让他的兴趣能对家庭有所贡献，让他体会到他的兴趣会经过他的劳动转换成价值。','2389-2428',1,1701095791,1782398596);
INSERT INTO highlights VALUES('3300074997_41_1892-1929','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','只要你细心地去分析，你会发现每种兴趣如果加以正确的引导都会是“有价值”的。','1892-1929',1,1701095753,1782398596);
INSERT INTO highlights VALUES('3300074997_41_1533-1597','3300074997',41,'自我教育是一次充满乐趣和智慧的漫长跋涉','一般来说，如果一个孩子不太具备某一个方面的潜能，那么他偶尔产生的兴趣很快就会转移，趋利避害是动物也会表现出来的本能，更何况是人。','1533-1597',1,1701095705,1782398596);
INSERT INTO highlights VALUES('3300074997_40_1632-1668','3300074997',40,'第八章 培养孩子自我学习的能力','3.孩子能不能发自内心地感受到快乐，是衡量教育方法和内容是否正确的标准。','1632-1668',1,1701095608,1782398596);
INSERT INTO highlights VALUES('3300074997_39_2446-2583','3300074997',39,'绘画应成为早期教育的一部分','当孩子们慢慢长大，他们还可以把这种才能用在自然笔记上，会兴致勃勃地为自己做插图、装饰。也可以用绘画来表达内心的情感和想法，比如亲手制作送给朋友或父母的生日贺卡，制作卡片慰问病中的亲人。甚至还可以用绘画来讲故事，在家庭通讯上记事。每画一次，孩子就能获得一次美妙的体验和成就感。','2446-2583',1,1700967031,1782398596);
INSERT INTO highlights VALUES('3300074997_39_1688-1752','3300074997',39,'绘画应成为早期教育的一部分','学习绘画的重点，最开始不在于他们是否创作出了一幅画，而在于在这个过程中他们学会了控制手指、眼睛和思维，以及保持了手的控制和平衡。','1688-1752',1,1700966900,1782398596);
INSERT INTO highlights VALUES('3300074997_35_1206-1261','3300074997',35,'一切学习都开始于观察','伟大的哲学家能够看到别人看不到的事物之间的相互联系；而诗人的伟大之处在于，他们能在现实中看到别人看不到的美丽。','1206-1261',1,1700964268,1782398596);
INSERT INTO highlights VALUES('3300074997_34_1041-1081','3300074997',34,'发现知识比灌输知识更重要','如果知识是孩子们通过自己的发现所获得的，那么解决新问题也会同解决老问题一样容易。','1041-1081',1,1700964161,1782398596);
INSERT INTO highlights VALUES('3300074997_34_1202-1263','3300074997',34,'发现知识比灌输知识更重要','而一个通过自己发现探索学到知识的孩子，即使没有现成的规则遵循，也会采取主动养成的正确方法去进行相关的研究，进而获得新知识。','1202-1263',1,1700964139,1782398596);
INSERT INTO highlights VALUES('3300074997_34_901-970','3300074997',34,'发现知识比灌输知识更重要','现在我们明白，如果一样东西永远有用，那么得到东西的过程也必然是费力的。所谓“来得容易去得也容易”，这句话对财富的积累和知识的积累同样适用。','901-970',1,1700964094,1782398596);
INSERT INTO highlights VALUES('3300074997_33_355-368','3300074997',33,'心智发展和身体发展一样重要','心智发展和身体发展一样重要','355-368',1,1700964035,1782398596);
INSERT INTO highlights VALUES('3300074997_32_355-364','3300074997',32,'心智没有一定的模式','心智没有一定的模式','355-364',1,1700963947,1782398596);
INSERT INTO highlights VALUES('3300074997_32_396-457','3300074997',32,'心智没有一定的模式','一个人心智的成长是一个自然而且循序渐进的过程，不合理地去干扰只能给它带来损伤，我们更不能用固定的模式来限制孩子心智的发展。','396-457',1,1700963942,1782398596);
INSERT INTO highlights VALUES('3300074997_29_4389-4426','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','6.在做记录时，开头尽量不要使用“任务”“作业”这类词，要写个有趣的开头。','4389-4426',1,1700963496,1782398596);
INSERT INTO highlights VALUES('3300074997_29_4315-4358','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','5.如果孩子还不具备文字记录能力，父母可以给他准备一个笔记本，把题目写下来，让他口述。','4315-4358',1,1700963490,1782398596);
INSERT INTO highlights VALUES('3300074997_29_4246-4284','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','4.让孩子学会记录，因为它是使知识存留，并训练使用文字、图画、书籍的好办法。','4246-4284',1,1700963470,1782398596);
INSERT INTO highlights VALUES('3300074997_29_4189-4215','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','3.诱导孩子通过自己查阅和请教别人的方式来获得知识。','4189-4215',1,1700963463,1782398596);
INSERT INTO highlights VALUES('3300074997_29_2669-2686','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','而且还总结出了它们的一些“社会特点','2669-2686',1,1700963269,1782398596);
INSERT INTO highlights VALUES('3300074997_29_3017-3027','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','“疑问是智慧的源泉。','3017-3027',1,1700963255,1782398596);
INSERT INTO highlights VALUES('3300074997_29_2277-2318','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','通过这些活动，小斯宾塞学会了系统学习知识的方法，而且他的专注力也得到了一定的锻炼。','2277-2318',1,1700963177,1782398596);
INSERT INTO highlights VALUES('3300074997_29_1654-1708','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','在这种情况下，诱导就显得尤为重要。这种诱导是为了让他们获得相关的知识、得到正确的方法，同时养成一些好的习惯。','1654-1708',1,1700963123,1782398596);
INSERT INTO highlights VALUES('3300074997_29_1065-1159','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','这样一来，很多父母们就会擅自把自己认为“有用”的兴趣保留，而把孩子们真正感兴趣的，在大人看来“没用”的兴趣删除掉。而实际上，在孩子的心智发展时期，很难用“有用”或“没用”去界定他们的兴趣。','1065-1159',1,1700963041,1782398596);
INSERT INTO highlights VALUES('3300074997_29_678-722','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','兴趣是孩子对事物的主动选择，诱导则是促使和加强孩子的这种主动性，使兴趣变得持久、有目的。','678-722',1,1700962377,1782398596);
INSERT INTO highlights VALUES('3300074997_29_617-633','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','“诱导是教育和培养孩子最好的方法','617-633',1,1700962364,1782398596);
INSERT INTO highlights VALUES('3300074997_29_543-553','3300074997',29,'兴趣是最好的老师，让孩子在兴趣的引导下学习','“兴趣是最好的老师。','543-553',1,1700962359,1782398596);
INSERT INTO highlights VALUES('3300074997_28_3614-3665','3300074997',28,'留心观察孩子，了解他的潜能和特长','5.我们应该着重培养对于孩子在语言和逻辑方面的能力，关于孩子做人做事的能力，我们也应该加以开发、培养。','3614-3665',1,1700962212,1782398596);
INSERT INTO highlights VALUES('3300074997_28_3360-3382','3300074997',28,'留心观察孩子，了解他的潜能和特长','1.用心观察自己的孩子，了解他的特点和潜能。','3360-3382',1,1700962188,1782398596);
INSERT INTO highlights VALUES('3300074997_28_3546-3583','3300074997',28,'留心观察孩子，了解他的潜能和特长','4.对他暂时表现出的不是特别擅长的方面，告诉他，这些才能是可以培养出来的。','3546-3583',1,1700962147,1782398596);
INSERT INTO highlights VALUES('3300074997_27_2612-2653','3300074997',27,'第六章 每个孩子只是特点不同','4.即使在教育上遇到了很大的困难也应坚持，许多奇迹的发生就是由于人们的坚持和不懈。','2612-2653',1,1700961901,1782398596);
INSERT INTO highlights VALUES('3300074997_27_2419-2444','3300074997',27,'第六章 每个孩子只是特点不同','1.相信每个孩子只是特点不同，而非有智力差异之分。','2419-2444',1,1700961893,1782398596);
INSERT INTO highlights VALUES('3300074997_27_2263-2341','3300074997',27,'第六章 每个孩子只是特点不同','对孩子有信心也就是对自己的事业有信心。而对孩子的所有的培养和教育，都应该基于让他们的潜能得到充分开发，并让他们成为一个对别人有益而自己也快乐富足的人这点上。','2263-2341',1,1700961646,1782398596);
INSERT INTO highlights VALUES('3300074997_27_2024-2074','3300074997',27,'第六章 每个孩子只是特点不同','对孩子坚信不疑，不但可以改变自己，更能改变孩子。关键是长期地保持这份信心，并把它变成可以实施的计划。','2024-2074',1,1700961495,1782398596);
INSERT INTO highlights VALUES('3300074997_27_1504-1651','3300074997',27,'第六章 每个孩子只是特点不同','我们可以看一看世界上各种各样的树木，有的能结出果实，有的则不能。就是在这些能结出果实的树木中，有的结的是苹果，有的结的是梨。结果子的树可以为人们提供水果，而不结果子的树则很多可以成为栋梁之材，制作各种实用或者供人观赏的东西。关于树木价值的认识，关键点在于我们用什么方法去培育、发展以及认识它们。','1504-1651',1,1700960364,1782398596);
INSERT INTO highlights VALUES('3300074997_27_1451-1475','3300074997',27,'第六章 每个孩子只是特点不同','智商”这个概念就和考试题目一样，多半都是人为的。','1451-1475',1,1700960329,1782398596);
INSERT INTO highlights VALUES('3300074997_27_1069-1099','3300074997',27,'第六章 每个孩子只是特点不同','绝大多数的孩子只存在智力特点的区别，而不存在智力高低的差别。','1069-1099',1,1700960278,1782398596);
INSERT INTO highlights VALUES('3300074997_26_3414-3425','3300074997',26,'良好的家庭氛围能为孩子带来快乐','9.打造亲密的家庭关系','3414-3425',1,1700959931,1782398596);
INSERT INTO highlights VALUES('3300074997_26_3219-3232','3300074997',26,'良好的家庭氛围能为孩子带来快乐','8.给孩子讲讲家庭里的历史','3219-3232',1,1700959888,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2920-2930','3300074997',26,'良好的家庭氛围能为孩子带来快乐','7.和孩子一起做游戏','2920-2930',1,1700959878,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2736-2804','3300074997',26,'良好的家庭氛围能为孩子带来快乐','相对固定的家庭传统和仪式，会让孩子对家庭产生必要的敬畏和归属感，也能培养孩子从小就学会区别哪些是一般的事和哪些是重要的、有特别意义的事。','2736-2804',1,1700959858,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2696-2707','3300074997',26,'良好的家庭氛围能为孩子带来快乐','6.形成稳定的家庭习惯','2696-2707',1,1700959849,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2485-2607','3300074997',26,'良好的家庭氛围能为孩子带来快乐','我经常和他一起合作去做一件事，比如种植植物，比如把许多散乱的照片整理成家庭影集或一起烤出一盘香气扑鼻的面包。我们合作所做的最大的一件事，是制作一张大餐桌。我们一起选木料、设计草图，经过几个星期的努力，当餐桌做成时，我们互相对望，高兴得叫了起来。','2485-2607',1,1700959818,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2342-2357','3300074997',26,'良好的家庭氛围能为孩子带来快乐','5.和孩子一起做一些快乐的事情','2342-2357',1,1700959771,1782398596);
INSERT INTO highlights VALUES('3300074997_26_2060-2070','3300074997',26,'良好的家庭氛围能为孩子带来快乐','4.一家人在一起吃饭','2060-2070',1,1700959762,1782398596);
INSERT INTO highlights VALUES('3300074997_26_1634-1647','3300074997',26,'良好的家庭氛围能为孩子带来快乐','3.给孩子为家庭分忧的机会','1634-1647',1,1700959719,1782398596);
INSERT INTO highlights VALUES('3300074997_26_1202-1213','3300074997',26,'良好的家庭氛围能为孩子带来快乐','2.增加彼此之间的了解','1202-1213',1,1700959680,1782398596);
INSERT INTO highlights VALUES('3300074997_26_1052-1066','3300074997',26,'良好的家庭氛围能为孩子带来快乐','1.多制造一家人在一起的机会','1052-1066',1,1700959674,1782398596);
INSERT INTO highlights VALUES('3300074997_26_771-813','3300074997',26,'良好的家庭氛围能为孩子带来快乐','根据调查发现，家庭是否能够给孩子力量，取决于家庭成员之间的感情和思想联系的密切程度。','771-813',1,1700959573,1782398596);
INSERT INTO highlights VALUES('3300074997_26_402-455','3300074997',26,'良好的家庭氛围能为孩子带来快乐','家庭，永远是孩子的港湾，无论孩子在外面遇到什么难题和困惑，我们都应该是他们的加油站、避风港和最坚强的后盾。','402-455',1,1700959555,1782398596);
INSERT INTO highlights VALUES('3300074997_25_1627-1719','3300074997',25,'像医生发现病因一样，找到孩子不快乐的原因','成人在潜意识里，总会给孩子规定很多条条框框，当孩子没有达到成人规定的要求时，孩子就会被“判刑”，事实上，被“判刑”的孩子并不一定有罪。相反，可能很多真正有错的孩子，却没有受到任何惩罚。','1627-1719',1,1700959376,1782398596);
INSERT INTO highlights VALUES('3300074997_25_637-663','3300074997',25,'像医生发现病因一样，找到孩子不快乐的原因','成功的孩子都是相似的，而失败的孩子却各有各的原因”。','637-663',1,1700959281,1782398596);
INSERT INTO highlights VALUES('3300074997_24_1555-1642','3300074997',24,'带着同情心去感受孩子的不快乐','还要告诉大家的是，研究表明，孩子越小，心理自主调节能力越差：0～3岁的孩子几乎没有心理调节能力，3～7岁的孩子稍微有一点心理调节能力，7～12岁的孩子一般也较少，但明显有了。','1555-1642',1,1700959087,1782398596);
INSERT INTO highlights VALUES('3300074997_23_3794-3889','3300074997',23,'第五章 把不快乐的小虫子找出来','我给劳伦斯谈得最多的是，这种遭遇是一种幸福，很多名人经常遭遇到和他类似的事情，但他们没有向生命屈服。相反，他们有了别人没有的境遇和忍受能力，所以他们才会在以后的学习和工作中，有了惊人的成绩。','3794-3889',1,1700958669,1782398596);
INSERT INTO highlights VALUES('3300074997_23_1249-1293','3300074997',23,'第五章 把不快乐的小虫子找出来','孩子们的控制力都比较弱，受环境的影响很大，而孩子染上一个坏习惯比培养一个好习惯要容易得多','1249-1293',1,1700958341,1782398596);
INSERT INTO highlights VALUES('3300074997_22_1624-1652','3300074997',22,'教的目的是为了有一天能不教','自主教育对于培养一个孩子的独立思考的能力，也是大有好处的','1624-1652',1,1700881910,1782398596);
INSERT INTO highlights VALUES('3300074997_22_1111-1144','3300074997',22,'教的目的是为了有一天能不教','我知道，没有一种快乐能比得上他自己通过努力来证明自己来得更可贵了。','1111-1144',1,1700881859,1782398596);
INSERT INTO highlights VALUES('3300074997_22_880-1032','3300074997',22,'教的目的是为了有一天能不教','在小斯宾塞很小的时候我就开始培养他自主学习的能力。我记得他小时候问我：“为什么燕子春天来，却秋天走？为什么太阳白天升起，黄昏的时候又落下？为什么夏天下雨，但冬天却要下雪？”像这样的问题，还有好多好多。但我从来不会简单地告诉他答案，而是会告诉他，去什么样的地方，或者查找什么样的图书，能找到这些问题的答案。','880-1032',1,1700881838,1782398596);
INSERT INTO highlights VALUES('3300074997_22_754-793','3300074997',22,'教的目的是为了有一天能不教','在孩子的早期教育中，一个重要的任务，我认为是培养他们自我教育和自主学习的能力。','754-793',1,1700881810,1782398596);
INSERT INTO highlights VALUES('3300074997_22_512-544','3300074997',22,'教的目的是为了有一天能不教','“最成功的教育不是教给孩子多少知识，而是教给他们学习知识的能力。','512-544',1,1700881790,1782398596);
INSERT INTO highlights VALUES('3300074997_21_1747-1821','3300074997',21,'看呀，天才的教育家又在训练他的小动物啦！','请父母和老师不要忽视这一点：从胎儿起到青年时代，孩子身体的成长和心智的成长同等重要，而且在婴儿、童年、少年时期，身体的发育和成长反而应该是最重要的。','1747-1821',1,1700881750,1782398596);
INSERT INTO highlights VALUES('3300074997_21_1228-1340','3300074997',21,'看呀，天才的教育家又在训练他的小动物啦！','我之所以要把带小斯宾塞去河边做运动，看作是快乐教育的一部分，是因为心智的成长和身体是密切相关的。去河边运动这项活动看起来和学习相关知识完全没有直接的关系，却可以给孩子带来良好的身体和情绪的反应，这种反应的后续效果却是神奇的。','1228-1340',1,1700881694,1782398596);
INSERT INTO highlights VALUES('3300074997_20_355-455','3300074997',20,'友好和鼓励推着孩子进步','友好和鼓励推着孩子进步如果孩子们是在一种友好、亲切而又充满鼓励的气氛中学习，学习的效果不但会好很多，还可以增加孩子对父母、老师的信任感。','355-455',1,1700881252,1782398596);
INSERT INTO highlights VALUES('3300074997_19_355-365','3300074997',19,'兴趣，让孩子快乐学习','兴趣，让孩子快乐学习','355-365',1,1700881072,1782398596);
INSERT INTO highlights VALUES('3300074997_19_509-558','3300074997',19,'兴趣，让孩子快乐学习','每一个孩子都会有自己的爱好和兴趣，当他们的爱好和兴趣产生的时候，就是我们对他们进行教育的最佳时机。','509-558',1,1700881014,1782398596);
INSERT INTO highlights VALUES('3300074997_18_1684-1755','3300074997',18,'第四章 先让孩子们快乐起来','因此，对于教育者来说，应该先让孩子们快乐起来，然后再给出可行的目标。而绝对不能采用威胁甚至恐吓的手段，那样只会让孩子厌恶学习，获得糟糕的结果。','1684-1755',1,1700880980,1782398596);
INSERT INTO highlights VALUES('3300074997_18_822-842','3300074997',18,'第四章 先让孩子们快乐起来','我认为孩子在快乐的状态下学习是最有效的。','822-842',1,1700880896,1782398596);
INSERT INTO highlights VALUES('3300074997_17_1008-1074','3300074997',17,'用跳格子游戏，教孩子学数字','人的教育，多像鸟儿对小鸟的训练啊。从教育的生物学特征来看，教育就是使一个小生命在身体和心智上不断得到完善，并使它更加适应生活的过程。','1008-1074',1,1700880616,1782398596);
INSERT INTO highlights VALUES('3300074997_17_644-763','3300074997',17,'用跳格子游戏，教孩子学数字','游戏非常简单，先画一个格子，把1～9这几个数字依次写在9宫格里，接下来我们就可以开始玩游戏了。刚开始我们的规则很简单，我说数字，小斯宾塞在这个格子里面找到数字，并跳进去，然后他说数字，我去跳，说哪个数字，就在哪个数字所在的格子里面跳几下。','644-763',1,1700880572,1782398596);
INSERT INTO highlights VALUES('3300074997_16_500-550','3300074997',16,'地图游戏，小图纸玩出大世界','为了训练小斯宾塞的记忆能力、描述能力和抽象与形象思维相结合的能力，我又制作了另一种教学工具——地图纸','500-550',1,1700880253,1782398596);
INSERT INTO highlights VALUES('3300074997_16_400-471','3300074997',16,'地图游戏，小图纸玩出大世界','在人类的知识技能学习中，一种是继承，一种是发现和描述。孩子从小就具备这两种天赋，只要用恰当的方法去激发孩子的潜能，就一定会收到意想不到的效果。','400-471',1,1700880239,1782398596);
INSERT INTO highlights VALUES('3300074997_16_1388-1485','3300074997',16,'地图游戏，小图纸玩出大世界','之后，我每带小斯宾塞去一个地方，都会让他画一个地图，并在地图旁边写上一些说明文字和他遇到的有趣的事情。随着去的地方越来越多，小斯宾塞的地图也画得越来越好，而那些说明文字简直就是一篇篇很好的作文。','1388-1485',1,1700880230,1782398596);
INSERT INTO highlights VALUES('3300074997_15_2492-2509','3300074997',15,'小斯宾塞的农田','农业与园艺还可以培养一个孩子的心性','2492-2509',1,1700880079,1782398596);
INSERT INTO highlights VALUES('3300074997_15_1808-1888','3300074997',15,'小斯宾塞的农田','我们总把教育仅仅看作是在严肃教室中的苦行僧的生活，而忽视了对孩子来说更有意义的自然教育和自助教育。而自然教育和自助教育在孩子身上最直接的反应恰恰就是快乐和趣味。','1808-1888',1,1700880023,1782398596);
INSERT INTO highlights VALUES('3300074997_15_1263-1436','3300074997',15,'小斯宾塞的农田','以后的每一天，小斯宾塞都会到地里去看有没有发生什么变化。但地里好像非常平静，什么事也没有发生。小斯宾塞有些迫不及待了，我告诉他：“这需要时间。你看，座钟时针从早到晚，每小时当当地响一次，这就是时间。从把这些种子种到地里，直到它们有一天从地里冒出头来，这也是时间。亲爱的，有时变化是需要很长时间的，但只要你等待、坚持，它们一定会出现。耐心等待吧。”','1263-1436',1,1700879987,1782398596);
INSERT INTO highlights VALUES('3300074997_15_1126-1172','3300074997',15,'小斯宾塞的农田','种好以后，我又和小斯宾塞在上面盖上了一层薄薄的土，然后在旁边竖了一块牌子——小斯宾塞的农田。','1126-1172',1,1700879942,1782398596);
INSERT INTO highlights VALUES('3300074997_15_972-1021','3300074997',15,'小斯宾塞的农田','“可别小看这些小颗粒啊，只要你好好照顾它们，它们会在你的手中变出惊人的东西来，但需要时间和耐心。”','972-1021',1,1700879907,1782398596);
INSERT INTO highlights VALUES('3300074997_15_394-471','3300074997',15,'小斯宾塞的农田','我觉得让孩子早些接触事物，学习事物，对开启孩子心智有很大的好处。人的心智开启了，他就会留心发现周围的世界，探究其中的道理，学会思考身边一切事物之间的联系。','394-471',1,1700879862,1782398596);
INSERT INTO highlights VALUES('3300074997_15_743-809','3300074997',15,'小斯宾塞的农田','“不，都不对。这样吧，我提醒你一下，这是一种有生命的事物，它在白天和夜里都会发生变化，等时间久了，它就能变出一些很有意思的东西来。”','743-809',1,1700879817,1782398596);
INSERT INTO highlights VALUES('3300074997_15_577-604','3300074997',15,'小斯宾塞的农田','小斯宾塞学习的第一件事物是从“一把植物的种子”开始的。','577-604',1,1700879795,1782398596);
INSERT INTO highlights VALUES('3300074997_14_1555-1644','3300074997',14,'词汇风铃，充满魔力的教育道具','小孩子的兴趣转移得总是很快，这会喜欢这个，马上就可能喜欢那个。有时候他们就像一只蜜蜂一样，一会停在这朵花上，一会又停在另外一朵花上，在空中闲逛的嗡嗡声也吵得人头疼，一刻也不安静。','1555-1644',1,1700879679,1782398596);
INSERT INTO highlights VALUES('3300074997_14_1247-1299','3300074997',14,'词汇风铃，充满魔力的教育道具','他认为学习事物比学习词汇对孩子更有意义，事实上，我从小就是从学习事物开始的，比如植物的种子、动物的标本。','1247-1299',1,1700879514,1782398596);
INSERT INTO highlights VALUES('3300074997_13_3426-3486','3300074997',13,'第三章 快乐的家庭教具','让我惊讶的是，后来许多英国家庭都开始玩这种12张卡片的游戏，有的还在里面加进讲笑话、表演节目等项目，这样当然更有趣一些。','3426-3486',1,1700879416,1782398596);
INSERT INTO highlights VALUES('3300074997_13_3338-3397','3300074997',13,'第三章 快乐的家庭教具','让父母们多试着把自己还原成一个同样会玩耍、会忧伤、会无助的真实的人，会拉近和孩子的距离。作为家长的你们，不妨试一试吧！','3338-3397',1,1700879330,1782398596);
INSERT INTO highlights VALUES('3300074997_13_1419-1518','3300074997',13,'第三章 快乐的家庭教具','6.哪件事，你努力了，但成效不大？7.深呼吸3次。8.拥抱一下你喜欢的人。','1419-1518',1,1700879136,1782398596);
INSERT INTO highlights VALUES('3300074997_13_1141-1388','3300074997',13,'第三章 快乐的家庭教具','这12张卡片上的问题是这样的：1.讲一讲你最不快乐的事情。2.讲一件你觉得自己做得最好的事情。3.对你身边的一个人进行评价。4.今年你最想做的三件事是什么？5.你对自己有什么不满意的？','1141-1388',1,1700879126,1782398596);
INSERT INTO highlights VALUES('3300074997_12_1515-1600','3300074997',12,'一个渐进的家教计划会使自己充分享受教育的快乐','他经常在外面和其他孩子玩耍，每次回到家里，衣服上全是泥土，可是一到家，他就会换衣服，然后主动把脏衣服洗掉。所以我从来没有阻止他出去玩，我只想让他尽情地享受自己的童年时光。','1515-1600',1,1700878983,1782398596);
INSERT INTO highlights VALUES('3300074997_12_1290-1341','3300074997',12,'一个渐进的家教计划会使自己充分享受教育的快乐','为了鼓励他，我又在家里挂了一个小黑板，把我们的名字都写上去，谁做得好，就在谁的名字后面贴上一朵小红花。','1290-1341',1,1700878964,1782398596);
INSERT INTO highlights VALUES('3300074997_12_1156-1227','3300074997',12,'一个渐进的家教计划会使自己充分享受教育的快乐','我是从生活中的小事着手的。首先我让他从整理自己的衣物开始。我们开展了一个家庭衣服自理比赛，看谁能把自己的衣服洗得干净，晒晾得整齐，收拾得有序。','1156-1227',1,1700878939,1782398596);
INSERT INTO highlights VALUES('3300074997_10_3156-3450','3300074997',10,'第二章 教育的快乐','1.不要在自己情绪很糟时教育孩子，因为这时容易把这种情绪发泄到孩子身上。2.不要在孩子情绪低落或刚刚哭闹的时候开始教育和强迫他学什么。这样你常常会根据当时非常差的教育结果，从而误认为孩子天赋太差。3.努力营造快乐、鼓舞的家庭教育气氛，让孩子有获得感和成就感。4.努力做一个乐观、快乐、积极的人。一个快乐积极的人看孩子时，更多会看到他们的优点，而一个忧郁、不开心、负面情绪的人更多看到的则会是孩子的缺点。','3156-3450',1,1700877523,1782398596);
INSERT INTO highlights VALUES('3300074997_10_2232-2410','3300074997',10,'第二章 教育的快乐','当孩子们处于情绪低落、精神紧张的状态下时，他们对事情就容易失去信心，这个时候，即使世界上最伟大的教育家站在他们面前，也可能没有办法让他们爱上学习。而相反，如果他们情绪非常激昂，整个人都处于非常快乐的情绪当中时，学习东西的效率就会非常高，学起东西来也会变得非常容易。因此，要想教育好孩子，唯一的办法是把他们的情绪调节到快乐、自信、专注这一挡，然后再开始学习。','2232-2410',1,1700877432,1782398596);
INSERT INTO highlights VALUES('3300074997_10_1698-1890','3300074997',10,'第二章 教育的快乐','：“亲爱的，我特别喜欢你弹的那首小曲子，它叫什么来着？”小斯宾塞抢着说：“林中仙子。”“没错，好像就是这支曲子，你能弹给我听一下吗？”小斯宾塞为难地摇了摇头。我说：“唉，太遗憾。可惜我不会，要是我自己会弹就好了，哪怕只是一小段呢！我觉得这首曲子太美妙了，真想听听。”小斯宾塞赶紧说，那我就试试吧。于是他坐上去，轻轻地弹了起来。','1698-1890',1,1700877410,1782398596);
INSERT INTO highlights VALUES('3300074997_10_1036-1115','3300074997',10,'第二章 教育的快乐','“亲爱的，快看，这是一架有魔力的风琴，只要你不断用脚踩踏板，同时用手按上面的黑白琴键，它就会唱歌。如果懂得了由七个数字组成的魔法，它就会唱出非常美妙的歌来。”','1036-1115',1,1700877393,1782398596);
INSERT INTO highlights VALUES('3300074997_10_2013-2154','3300074997',10,'第二章 教育的快乐','我认为教育应该是一件充满快乐的事情，当一个孩子不快乐时，他的智力和潜能就会大大降低，而大声地呵斥和愤怒的指责不会带来什么好的结果。在我看来，如果教育的最终目的，是为了让孩子成为一个快乐的人，那么教育的手段和方法也应该是快乐的','2013-2154',1,1700877377,1782398596);
INSERT INTO highlights VALUES('3300074997_8_1834-1885','3300074997',8,'孩子是家庭的一面镜子，能照出你内心的一切','孩子就像家庭的一面镜子，他能照出你内心的一切。你快乐，他也快乐；你烦躁，他也烦躁；你暴戾，他也暴戾……','1834-1885',1,1700876996,1782398596);
INSERT INTO highlights VALUES('3300074997_7_2903-3032','3300074997',7,'父母是孩子在这个世界上最重要的老师','这就好比种子发芽生长一样，孩子的成长，学校好比就是白天，而家庭就像是夜晚。在大家的印象中似乎白天种子在吸收太阳光，但请大家都不要忽视夜晚发生的事情，这些事情往往是看不见的，但是只要细心观察一下就会发现，夜晚才是种子发芽成长最快的时候，而人也是在夜晚长高的啊！','2903-3032',1,1700876794,1782398596);
INSERT INTO highlights VALUES('3300074997_7_2093-2179','3300074997',7,'父母是孩子在这个世界上最重要的老师','“孩子教育的第一步不是学校教育，而是家庭教育。你们没有对孩子进行很好的家庭前期教育，基础没有打好，以后的路怎么能走好？这就像盖房子一样，没有打好地基，将来房子就不会坚固。”','2093-2179',1,1700876162,1782398596);
INSERT INTO highlights VALUES('3300074997_7_1861-1963','3300074997',7,'父母是孩子在这个世界上最重要的老师','“然而接下来的孩子成长过程中，这就像种庄稼一样，你们之中的人，有的悉心去培养，就像照料一粒麦种；有的却渐渐失去了耐心，不再去寻求教育孩子的方法，反而粗暴、简单地对待孩子，以致孩子越来越愚钝，甚至走上歧途。','1861-1963',1,1700876146,1782398596);
INSERT INTO highlights VALUES('855833_16_6303-6346','855833',33,'第11章 赫胥黎的警告','人们感到痛苦的不是他们用笑声代替了思考，而是他们不知道自己为什么笑以及为什么不再思考。','6159-6202',NULL,1583481270,1782398700);
INSERT INTO highlights VALUES('855833_16_5724-5811','855833',33,'第11章 赫胥黎的警告','“媒介意识”。但是，他们的这种意识往往集中在“我们怎样利用电视（或电脑，或文字处理机）来控制教育”这个问题上，而不是“我们怎样利用教育来控制电视（或电脑，或文字处理机）”上。','5643-5730',NULL,1583480921,1782398700);
INSERT INTO highlights VALUES('855833_16_1585-1615','855833',33,'第11章 赫胥黎的警告','对于一个因为大笑过度而体力衰竭的文化，我们能有什么救命良方？','1566-1596',NULL,1583475639,1782398700);
INSERT INTO highlights VALUES('855833_15_9473-9517','855833',32,'第10章 教学是一种娱乐活动','教育部的官员们也应该想到这样的问题：谁应该来教我们的孩子怎样看电视？什么时候不该看电视？','9125-9169',NULL,1583475247,1782398700);
INSERT INTO highlights VALUES('855833_15_5131-5186','855833',32,'第10章 教学是一种娱乐活动','这种重新定位的后果不仅体现在教室的传统功能的日益衰退，而且还体现在教室被改造成一个教和学都以娱乐为目的的地方。','4969-5024',NULL,1583468386,1782398700);
INSERT INTO highlights VALUES('855833_15_4443-4479','855833',32,'第10章 教学是一种娱乐活动','电视通过摒弃教育中的顺序和连贯性而彻底否定了它们和思想之间存在任何关系。','4252-4288',NULL,1583467342,1782398700);
INSERT INTO highlights VALUES('855833_15_3632-3661','855833',32,'第10章 教学是一种娱乐活动','电视对教育哲学的主要贡献是它提出了教学和娱乐不可分的理念。','3426-3455',NULL,1583466683,1782398700);
INSERT INTO highlights VALUES('855833_15_3716-3736','855833',32,'第10章 教学是一种娱乐活动','孩子在学习自己有兴趣的东西时掌握得最好；','3510-3530',NULL,1583466667,1782398700);
INSERT INTO highlights VALUES('855833_15_3516-3539','855833',32,'第10章 教学是一种娱乐活动','我曾写过一本书，书名叫“教学是一种保护活动”。','3310-3333',NULL,1583466636,1782398700);
INSERT INTO highlights VALUES('855833_15_3292-3325','855833',32,'第10章 教学是一种娱乐活动','电视通过控制人们的时间、注意力和认知习惯获得了控制人们教育的权力。','3086-3119',NULL,1583466447,1782398700);
INSERT INTO highlights VALUES('855833_15_2148-2244','855833',32,'第10章 教学是一种娱乐活动','“也许人们对于教育最大的错误认识是，一个人学会的只有他当时正在学习的东西。其实，伴随学习的过程形成持久的态度……也许比拼写课或地理历史课更为重要……因为这些态度才是在未来发挥重要作用的东西。”','2067-2163',NULL,1583466048,1782398700);
INSERT INTO highlights VALUES('855833_14_11983-12025','855833',31,'第9章 伸出你的手投上一票','印刷术的世界里，信息是思想的火药，所以审查者们才需要穿着肃穆的长袍来熄灭点燃的炸药。','11157-11199',NULL,1583461133,1782398700);
INSERT INTO highlights VALUES('855833_14_7880-7912','855833',31,'第9章 伸出你的手投上一票','古希腊哲学家在2500年以前就说过，人常常以自己的形象塑造上帝。','7551-7583',NULL,1583460846,1782398700);
INSERT INTO highlights VALUES('855833_14_9710-9734','855833',31,'第9章 伸出你的手投上一票','零星破碎的信息无法汇集成一个连贯而充满智慧的整体','9257-9281',NULL,1583460845,1782398700);
INSERT INTO highlights VALUES('855833_14_7449-7488','855833',31,'第9章 伸出你的手投上一票','霍恩没有表达他自己的想法，你也没有表达你自己的想法，霍恩表达的是你的想法。”[插图]','7182-7220',NULL,1583460845,1782398700);
INSERT INTO highlights VALUES('855833_14_7915-7947','855833',31,'第9章 伸出你的手投上一票','电视政治又添了新招：那些想当上帝的人把自己塑造成观众期望的形象。','7586-7618',NULL,1583460844,1782398700);
INSERT INTO highlights VALUES('855833_14_2876-3143','855833',31,'第9章 伸出你的手投上一票','电视广告把企业从生产有价值的产品引向了设法使消费者感觉产品有价值，这意味着企业的业务已经成为一种伪疗法，消费者成了信赖心理表演疗法[插图]的病人。','2795-3000',NULL,1583460843,1782398700);
INSERT INTO highlights VALUES('855833_14_1111-1151','855833',31,'第9章 伸出你的手投上一票','如果政治真的像体育比赛，那么它至少有这样几个优点：一目了然、公正诚实、超越平凡。','1030-1070',NULL,1583459236,1782398700);
INSERT INTO highlights VALUES('855833_13_8577-8583','855833',30,'第8章 走向伯利恒','“大众文化”','8061-8067',NULL,1583379268,1782398700);
INSERT INTO highlights VALUES('855833_12_2422-2455','855833',29,'第7章 “好……现在”','电视为真实性提供了一种新的定义：讲述者的可信度决定了事件的真实性。','2341-2374',NULL,1583370207,1782398700);
