INSERT INTO highlights VALUES('855833_8_4571-6618','855833',25,'第4章 印刷机统治下的思想','在林肯和道格拉斯辩论的时候，美国正处于其辉煌的文学创作的中期。1858年，埃德温·马卡姆[插图]6岁，马克·吐温23岁，艾米莉·狄金森[插图]28岁，惠特曼[插图]和詹姆斯·拉塞尔·洛威尔[插图]39岁，梭罗[插图]41岁，梅尔维尔[插图]39岁，惠蒂尔[插图]和朗费罗[插图]51岁，霍桑[插图]和爱默生[插图]分别是54岁和55岁，爱伦·坡[插图]则已经辞世9年了。','4056-5421',NULL,1583204998,1782398700);
