INSERT INTO highlights VALUES('855833_3_412-631','855833',20,'前言','乔治·奥威尔关于1984年[插图]的预言','394-550',NULL,1583059991,1782398700);
INSERT INTO highlights VALUES('27480233_42_1675-1797','27480233',42,'生活中不可或缺的植物纤维','人类吃掉植物纤维的话，会增加以植物纤维为食的乳酸菌、双歧杆菌等肠道有益菌的数量，从而调整肠道状态。此外，植物纤维还可以吸附有害物质，通过增加便量刺激肠道，达到通便、给肠道做大扫除的效果。所以，虽然植物纤维里不包含营养，但依然可以调理我们的身体。','1675-1797',NULL,1643167243,1782398647);
INSERT INTO highlights VALUES('27480233_42_1124-1140','27480233',42,'生活中不可或缺的植物纤维','植物的细胞壁，是由纤维素构成的。','1124-1140',NULL,1643167165,1782398647);
INSERT INTO highlights VALUES('27480233_42_1076-1124','27480233',42,'生活中不可或缺的植物纤维','植物的细胞和动物的细胞，基本构造都是一样的。但是，两者最大的差别，就是植物的细胞有细胞壁这一点。','1076-1124',NULL,1643167154,1782398647);
INSERT INTO highlights VALUES('27480233_42_793-805','27480233',42,'生活中不可或缺的植物纤维','纸张的原料，就是植物纤维','793-805',NULL,1643166128,1782398647);
INSERT INTO highlights VALUES('27480233_41_3854-3924','27480233',41,'法隆寺的柱子还活着？','秋冬季节造就的年轮部分不易透水，所以沿着年轮切出来的曲线纹木材也具有不易透水的特性。这样的木材，非常适合用作木桶、浴桶和船这类物品的原材料。','3854-3924',NULL,1643165976,1782398647);
INSERT INTO highlights VALUES('27480233_41_3427-3464','27480233',41,'法隆寺的柱子还活着？','用作木板，更为高级的材料是直线纹木材。因为直线木纹的纹理更加均衡，不易弯曲','3427-3464',NULL,1643165929,1782398647);
INSERT INTO highlights VALUES('27480233_41_2183-2275','27480233',41,'法隆寺的柱子还活着？','我们仔细观察一下木材的话就会发现，在年轮的正交方向上，有着一种从中心向外侧发散的髓射线。这种髓射线就如同施工时所用的道路那样，把抗菌物质从还活着的外侧部分运送到树木的中心部分，形成心材','2183-2275',NULL,1643165742,1782398647);
INSERT INTO highlights VALUES('27480233_41_2070-2113','27480233',41,'法隆寺的柱子还活着？','树皮内侧的部分被称为嫩皮。嫩皮中富含淀粉和蛋白质。这个嫩皮的部分，就是细胞存活的部分。','2070-2113',NULL,1643165695,1782398647);
INSERT INTO highlights VALUES('27480233_41_1972-2053','27480233',41,'法隆寺的柱子还活着？','树木就是这样，用死掉的细胞来支撑枝干，而活着的细胞则越过这些残骸继续生长。但是，将活着的部分暴露在最外面的话可以说是毫无防备，所以树木会在此之上覆盖一层坚硬的树皮','1972-2053',NULL,1643165675,1782398647);
INSERT INTO highlights VALUES('27480233_41_1588-1615','27480233',41,'法隆寺的柱子还活着？','树木，是靠一种很难被分解的叫作木质素的物质使细胞结合的','1588-1615',NULL,1643165604,1782398647);
INSERT INTO highlights VALUES('27480233_41_1211-1327','27480233',41,'法隆寺的柱子还活着？','为了抵抗这些外敌，树木会在木材的中央储存抗菌物质。而且，这些抗菌物质还能使木材变得更加坚固，可以起到物理上的防御作用。此外，这种抗菌物质的注入，可以堵塞运输水分和营养成分的导管和筛管，具有防止水分渗入内部使木材从内部开始腐朽的效果。','1211-1327',NULL,1643165559,1782398647);
INSERT INTO highlights VALUES('27480233_41_1099-1122','27480233',41,'法隆寺的柱子还活着？','心材非常坚固而且不易腐烂，非常适合用来做柱子。','1099-1122',NULL,1643165520,1782398647);
INSERT INTO highlights VALUES('27480233_41_906-973','27480233',41,'法隆寺的柱子还活着？','之所以说柱子还活着，是因为柱子会变弯曲，会和呼吸一样，从空气中吸收水分或是排出水分。但是，这只不过是死掉的细胞在吸收或是散发水分罢了。','906-973',NULL,1643165451,1782398647);
INSERT INTO highlights VALUES('27480233_40_1812-1889','27480233',40,'雄树和雌树','有的植物还具有这样的结构：即使自身的花粉落到了雌蕊上，雌蕊顶端的物质也会对花粉发起攻击，阻碍花粉发芽，并终止花粉管的伸长。这种特性被称为“自交不亲和性”。','1812-1889',NULL,1643165293,1782398647);
INSERT INTO highlights VALUES('27480233_40_1656-1679','27480233',40,'雄树和雌树','一些植物的花朵中，雄蕊和雌蕊的成熟期也是错开的','1656-1679',NULL,1643165271,1782398647);
INSERT INTO highlights VALUES('27480233_40_1564-1577','27480233',40,'雄树和雌树','雌蕊大多要比雄蕊要高出一些','1564-1577',NULL,1643165259,1782398647);
INSERT INTO highlights VALUES('27480233_40_813-920','27480233',40,'雄树和雌树','在动物中，也是有雌雄同体的现象的。比如说蚯蚓和蜗牛。蚯蚓和蜗牛，都没办法移动到太远的地方去。所以，雄性和雌性能相遇的机会非常少。因此，为了不论遇到雄性还是雌性都可以延续子孙，蚯蚓和蜗牛就逐渐演变成了雌雄同体的状态。','813-920',NULL,1643165156,1782398647);
INSERT INTO highlights VALUES('27480233_39_1473-1516','27480233',39,'小偷包袱皮上的藤蔓花纹','蔓生植物的茎无需发育得很挺拔，而是可以把相应的能量，用到茎的延伸上，使茎向更远处伸展。','1473-1516',NULL,1643164950,1782398647);
INSERT INTO highlights VALUES('27480233_38_3529-3619','27480233',38,'狗尾巴草是一种高性能植物','CAM植物只会在气温相对低的夜间打开气孔，而在气温相对高的白天，则把气孔完全关闭，靠储存的碳元素进行光合作用。如此一来，通过白天和夜间的这两套不同的系统，可以成功地抑制水分的蒸发。','3529-3619',NULL,1643164581,1782398647);
INSERT INTO highlights VALUES('27480233_38_2618-2727','27480233',38,'狗尾巴草是一种高性能植物','C4循环，可以在高温强光的条件下发挥出非常厉害的光合作用能力。但是，在低温弱光的条件下，C4循环不管吸收多少二氧化碳，光合作用的能力都没办法提高。而且，为了运行C4循环，需要更多的能量支持。就效率来看，并不如C3植物。','2618-2727',NULL,1643164428,1782398647);
INSERT INTO highlights VALUES('27480233_38_1915-2006','27480233',38,'狗尾巴草是一种高性能植物','C4植物会将气孔打开后吸收的二氧化碳进一步浓缩，所以可以一次性地吸收大量二氧化碳。如此，就减少了打开气孔的次数。属于C4植物的狗尾巴草即使在炎炎的夏日里也能够茁壮生长，就是这个原因。','1915-2006',NULL,1643164305,1782398647);
INSERT INTO highlights VALUES('27480233_38_661-722','27480233',38,'狗尾巴草是一种高性能植物','狗尾巴草自身有着可以进行特殊光合作用的结构。这种高性能光合作用的系统被称为C4循环。而拥有C4循环的植物则被称为C4植物。','661-722',NULL,1643164046,1782398647);
INSERT INTO highlights VALUES('27480233_38_542-555','27480233',38,'狗尾巴草是一种高性能植物','狗尾巴草的学名叫作阿罗汉草','542-555',NULL,1643164021,1782398647);
INSERT INTO highlights VALUES('27480233_36_2230-2303','27480233',36,'萝卜苗长大了会变成什么呢？','萝卜的根部会偏辣。萝卜的根，是储存地上形成的营养成分的地方。为了防止虫子或是动物吃掉自己好不容易储存下来的营养成分，萝卜会生成辣味成分来守护自己。','2230-2303',NULL,1643163801,1782398647);
INSERT INTO highlights VALUES('27480233_36_2055-2118','27480233',36,'萝卜苗长大了会变成什么呢？','胚轴，起着将根部吸上来的水分运输到地上，将地上形成的糖分等营养物质运输到根部的作用。所以，胚轴的部分有着水分多、甜度高的特点。','2055-2118',NULL,1643163724,1782398647);
INSERT INTO highlights VALUES('27480233_36_1452-1509','27480233',36,'萝卜苗长大了会变成什么呢？','和萝卜的下半部分不同，萝卜的上半部分滑溜溜的，一点根须的痕迹都没有。这上半部分其实不是根，而是生长得很粗壮的胚轴。','1452-1509',NULL,1643163579,1782398647);
INSERT INTO highlights VALUES('27480233_35_3346-3381','27480233',35,'厨房里的植物学','萝卜也具有相反的特点，靠近根部的地方最辣，靠近顶部的地方则没有那么辣。','3346-3381',NULL,1643162346,1782398647);
INSERT INTO highlights VALUES('27480233_35_3268-3317','27480233',35,'厨房里的植物学','而不太能吃辣的人，只要把山葵的根部拿来用力地磨，就可以得到辣味更加温和、风味更加突出的手磨芥末了。','3268-3317',NULL,1643162333,1782398647);
INSERT INTO highlights VALUES('27480233_35_3189-3268','27480233',35,'厨房里的植物学','山葵的话，靠近顶部的地方最辣，而靠近根部的地方辣度最低。因此，喜欢吃辣一点的人，可以一边笑着一边细细地把山葵的顶部拿来磨，这样就可以得到辣味浓郁的手磨芥末了。','3189-3268',NULL,1643162299,1782398647);
INSERT INTO highlights VALUES('27480233_35_2098-2216','27480233',35,'厨房里的植物学','但如果是炒菜的话，竖着切洋葱会更好些。因为横着切的话会破坏细胞，使细胞内的成分渗到外面来。竖着切的话，可以尽可能地不破坏细胞。直到我们吃的时候，才会通过咀嚼破坏洋葱的细胞，让洋葱的味道散发出来。这样的切法，可以使洋葱的味道变得更加浓郁。','2098-2216',NULL,1643160832,1782398647);
INSERT INTO highlights VALUES('27480233_35_1975-2069','27480233',35,'厨房里的植物学','横着切洋葱的话，会破坏洋葱的细胞，使洋葱口感变得更柔软。此外，把横着切的洋葱泡在水里的话，辣味成分会溶解在水里，吃的时候就吃不出辛辣的味道了。所以，如果是用洋葱做沙拉的话，横着切更好一些。','1975-2069',NULL,1643160810,1782398647);
INSERT INTO highlights VALUES('27480233_35_1762-1784','27480233',35,'厨房里的植物学','横着切洋葱的话，会破坏细胞，释放刺激性物质。','1762-1784',NULL,1643160594,1782398647);
INSERT INTO highlights VALUES('27480233_35_1137-1184','27480233',35,'厨房里的植物学','蒜素这种物质非常怕热，加热后就会分解。所以，切之前把洋葱放进微波炉里加热一会儿也是一个好方法。','1137-1184',NULL,1643160511,1782398647);
INSERT INTO highlights VALUES('27480233_35_1033-1105','27480233',35,'厨房里的植物学','洋葱释放出来的这种叫作蒜素的刺激性物质，具有低温时不易挥发的特性。所以，如果我们在切洋葱之前把它放进冰箱里冷冻一会儿，就可以抑制这种物质的挥发。','1033-1105',NULL,1643160481,1782398647);
INSERT INTO highlights VALUES('27480233_35_632-682','27480233',35,'厨房里的植物学','跑出来的蒜氨酸和外面的酶发生化学反应，会生成一种叫作蒜素的刺激性物质。就是这种蒜素，刺激着我们的眼睛','632-682',NULL,1643160292,1782398647);
INSERT INTO highlights VALUES('27480233_34_4174-4284','27480233',34,'草原物语','埃及文明和美索不达米亚文明的发祥地，是麦子类作物的起源地。印度河流域文明的发祥地，是稻子的起源地。而中华文明的发祥地，是黄豆的起源地。中美洲的玛雅文明和阿兹特克文明的发祥地种植着玉米，而南美洲的印加文明发祥地则种植着土豆','4174-4284',NULL,1643120667,1782398647);
INSERT INTO highlights VALUES('27480233_34_3272-3290','27480233',34,'草原物语','这种种子落下来的性质叫作“脱粒性”。','3272-3290',NULL,1643120559,1782398647);
INSERT INTO highlights VALUES('27480233_34_3134-3212','27480233',34,'草原物语','人工栽培的麦子类作物最重要的性质，就是种子不会脱落下来。野生的麦子为了留下后代，会把种子散播出去。','3134-3212',NULL,1643120552,1782398647);
INSERT INTO highlights VALUES('27480233_34_1212-1293','27480233',34,'草原物语','禾本科植物的叶子中，储存有硅这种甚至可以被用作玻璃原料的坚固物质。此外，禾本科植物的叶子中还含有很多纤维，不易被消化。这样一来，动物们很难以禾本科植物的叶子为食。','1212-1293',NULL,1643120274,1782398647);
INSERT INTO highlights VALUES('27480233_33_1030-1077','27480233',33,'红灯笼是成熟的果实！','被子植物花了很大的工夫来进化，甚至将原本作为守护胚珠而存在的子房进化成了果实，以吸引动物来吃。','1030-1077',NULL,1643120049,1782398647);
INSERT INTO highlights VALUES('27480233_29_3891-3915','27480233',29,'种子的秘密','相较于碳水化合物，类脂质可以产出两倍以上的能量。','3891-3915',NULL,1643097957,1782398647);
INSERT INTO highlights VALUES('27480233_29_3432-3445','27480233',29,'种子的秘密','黄豆也被称为“田间的肉”。','3432-3445',NULL,1643097892,1782398647);
INSERT INTO highlights VALUES('27480233_29_2633-2691','27480233',29,'种子的秘密','豆科植物的种子都不含有胚乳，被称为“无胚乳种子”。和豆科植物一样，黄瓜和南瓜这些葫芦科的植物的种子，也都是无胚乳种子','2633-2691',NULL,1643097814,1782398647);
INSERT INTO highlights VALUES('27480233_29_1000-1089','27480233',29,'种子的秘密','糙米的表面还有一层“糠”。这里，我们去掉糠的部分，将胚的部分称作胚芽。这种保留了胚芽部分的米，就是“胚芽米”。我们再把胚芽的部分也去掉，只留下胚乳的部分，就是我们平常吃的大米了。','1000-1089',NULL,1643097658,1782398647);
INSERT INTO highlights VALUES('27480233_27_590-676','27480233',27,'植物的血型是什么？','植物中的叶绿素和我们血液里红细胞中的血红蛋白非常相似。叶绿素和血红蛋白的基本构造都是一样的。唯一的区别就是，叶绿素分子构造的中心元素是镁，而血红蛋白分子构造的中心元素是铁。','590-676',NULL,1643097002,1782398647);
INSERT INTO highlights VALUES('27480233_26_1126-1217','27480233',26,'植物为什么是绿色的？','叶绿素为了进行光合作用，会利用波长短的蓝光和波长长的红光、黄光。这些颜色的光，能够被叶绿素吸收，而位于中间波长的绿光，不太会被用来进行光合作用，所以也就不会被吸收，而是直接被反射回去','1126-1217',NULL,1643096291,1782398647);
INSERT INTO highlights VALUES('27480233_25_1539-1543','27480233',25,'植物不能动的原因','异养生物','1539-1543',NULL,1643095841,1782398647);
INSERT INTO highlights VALUES('27480233_25_1448-1454','27480233',25,'植物不能动的原因','“自养生物”','1448-1454',NULL,1643095838,1782398647);
INSERT INTO highlights VALUES('27480233_24_2321-2446','27480233',24,'萝卜腿竟然是一种夸奖！','对于野生植物来说，“多样性”是非常重要的，但是对于人工培育的栽培植物来说，追求的则是“均一性”。人们即使已经得到了希望的植物体，也会反复地进行淘汰，直到达到相同的性质。这个过程被叫作“固定”。','2321-2446',NULL,1643095691,1782398647);
INSERT INTO highlights VALUES('27480233_23_1723-1794','27480233',23,'先有树还是先有草？','双子叶植物的子叶有两片，而单子叶植物的子叶只有一片。而且，双子叶植物的茎里面，有着由导管和筛管组成的环状物—形成层，而单子叶植物则没有形成层。','1723-1794',NULL,1643095149,1782398647);
INSERT INTO highlights VALUES('27480233_22_2328-2341','27480233',22,'简笔画胡萝卜的画法','单子叶植物，是没有形成层的','2328-2341',NULL,1643094957,1782398647);
INSERT INTO highlights VALUES('27480233_22_1963-1982','27480233',22,'简笔画胡萝卜的画法','拥有这种形成层，正是双子叶植物的特征。','1963-1982',NULL,1643094926,1782398647);
INSERT INTO highlights VALUES('27480233_22_1608-1668','27480233',22,'简笔画胡萝卜的画法','形成层内侧的芯的部分有着输送从根部吸收的水分的导管，被称为木质部。而形成层外侧的部分有着运送营养成分的筛管，被称为韧皮部','1608-1668',NULL,1643094322,1782398647);
INSERT INTO highlights VALUES('27480233_22_1281-1322','27480233',22,'简笔画胡萝卜的画法','胡萝卜的这个同心圆分为内侧的芯和外侧两部分，而这两部分的分界线，被称为“形成层”。','1281-1322',NULL,1643094259,1782398647);
INSERT INTO highlights VALUES('27480233_21_2451-2501','27480233',21,'竹子究竟是树还是草呢？','其实对于植物来说，究竟是树还是草，并不是什么大问题。它们都只是为了适应环境而逐渐进化成了现在的样子。','2451-2501',NULL,1643093473,1782398647);
INSERT INTO highlights VALUES('27480233_21_1689-1737','27480233',21,'竹子究竟是树还是草呢？','一般来说，我们把茎部肥大结实的木质化植物定义为树。而把没有木质化现象，有着柔软茎部的植物定义为草','1689-1737',NULL,1643093308,1782398647);
INSERT INTO highlights VALUES('27480233_21_1249-1301','27480233',21,'竹子究竟是树还是草呢？','但是，实际上香蕉树并不是树，而是一株巨大的草。香蕉“树”从地面伸展出巨大的叶子，形态上就像一棵大树一样。','1249-1301',NULL,1643093084,1782398647);
INSERT INTO highlights VALUES('27480233_20_1914-1951','27480233',20,'不发芽的原因是什么？','很多野草的种子都有感受到光照就会发芽的特性，这种特性被称为“需光发芽性”。','1914-1951',NULL,1643073518,1782398647);
INSERT INTO highlights VALUES('27480233_20_1117-1147','27480233',20,'不发芽的原因是什么？','种子这种即使满足了发芽的必要条件也不发芽的状态，被称为“休眠','1117-1147',NULL,1643073433,1782398647);
INSERT INTO highlights VALUES('27480233_18_2765-2794','27480233',18,'松树为什么有着美好的寓意？','这种运水方式是进化成导管前一阶段的系统，被叫作“假导管”。','2765-2794',NULL,1643073282,1782398647);
INSERT INTO highlights VALUES('27480233_18_1782-1788','27480233',18,'松树为什么有着美好的寓意？','“落叶阔叶树','1782-1788',NULL,1643073129,1782398647);
INSERT INTO highlights VALUES('27480233_18_1735-1766','27480233',18,'松树为什么有着美好的寓意？','与之相对的，进化后的被子植物的树叶更加宽阔，因此也被称为阔叶树','1735-1766',NULL,1643073117,1782398647);
INSERT INTO highlights VALUES('27480233_18_1480-1548','27480233',18,'松树为什么有着美好的寓意？','一种是裸子植物中的常绿树。裸子植物在适应严寒的过程中，为了防止水分从叶子中蒸发，就把叶子逐渐进化成了细细的外形。这样的植物被称作针叶树。','1480-1548',NULL,1643073084,1782398647);
INSERT INTO highlights VALUES('27480233_17_1576-1621','27480233',17,'让人着迷的植物毒素','咖啡因是生物碱这种毒性物质中的一种，原本是植物为了防止昆虫或动物的食害而分泌出的驱虫物质。','1576-1621',NULL,1643072724,1782398647);
INSERT INTO highlights VALUES('27480233_16_4287-4293','27480233',16,'红叶为什么会变红？','花青素的作用','4287-4293',NULL,1643035119,1782398647);
INSERT INTO highlights VALUES('27480233_16_3705-3744','27480233',16,'红叶为什么会变红？','花青素可以吸收紫外线，保护细胞。紫苏这样的植物中的花青素，起到的就是这个作用。','3705-3744',NULL,1643035054,1782398647);
INSERT INTO highlights VALUES('27480233_16_3393-3419','27480233',16,'红叶为什么会变红？','一心为了生存的植物，是不会在变美这件事情上花心思的。','3393-3419',NULL,1643035028,1782398647);
INSERT INTO highlights VALUES('27480233_16_2349-2428','27480233',16,'红叶为什么会变红？','人们都说，在昼夜温差大的时候，红叶的颜色会变得更好看。那是因为，白天光合作用下形成的糖分，到了晚上就会变成花青素。而叶子中的叶绿素，在低温下会被更大程度地破坏','2349-2428',NULL,1643034906,1782398647);
INSERT INTO highlights VALUES('27480233_16_2250-2320','27480233',16,'红叶为什么会变红？','使光合作用持续进行的叶子中的叶绿素，最终还是会在低温下被破坏。这个时候，叶子失去了绿色的叶绿素，就会使储存在叶子中的红色花青素变得格外显眼。','2250-2320',NULL,1643034882,1782398647);
INSERT INTO highlights VALUES('27480233_16_1836-1900','27480233',16,'红叶为什么会变红？','叶子中的这些糖分形成了一种叫作花青素的红色色素。对于植物来说，这种花青素是在水分不足或是寒冷气温的情况下减轻植物紧张程度的物质。','1836-1900',NULL,1643034820,1782398647);
INSERT INTO highlights VALUES('27480233_16_1365-1439','27480233',16,'红叶为什么会变红？','植物在叶子的叶柄靠近根部的地方，形成一个不让水分和营养成分通过的区域，这个区域被称为“离层”。也就是说，植物将不再为叶子提供任何的水分或是营养成分。','1365-1439',NULL,1643034744,1782398647);
INSERT INTO highlights VALUES('27480233_15_2081-2267','27480233',15,'印盒上的双叶葵','植物接受阳光照射，进行光合作用，所以叶子的面积越大越有利。但是如果叶子过大的话，叶柄就会支撑不住。所以，心形的形状，可以使靠近叶柄处的叶片面积更大，从而可以在保持叶柄平衡的情况下，使叶子的面积达到最大化。另外，心形的叶子使得叶根的部分凹下去一块，可以让叶子上的雨水和夜露顺着叶柄流到植物的根部，从而达到集水的作用。','2081-2267',NULL,1643017580,1782398647);
INSERT INTO highlights VALUES('27480233_15_1783-1833','27480233',15,'印盒上的双叶葵','“河骨”是生长在水边的一种叫作黄金莲的植物。黄金莲，是一种开着鲜艳的黄色花朵的睡莲科的水生草本植物。','1783-1833',NULL,1643017512,1782398647);
INSERT INTO highlights VALUES('27480233_15_1341-1344','27480233',15,'印盒上的双叶葵','雨久花','1341-1344',NULL,1643017082,1782398647);
INSERT INTO highlights VALUES('27480233_14_1906-1944','27480233',14,'日本蒲公英VS西洋蒲公英','西洋蒲公英拥有一种就算不受粉也可以结成种子的能力，被称为无融合生殖的特殊能力','1906-1944',NULL,1643016164,1782398647);
INSERT INTO highlights VALUES('27480233_14_900-963','27480233',14,'日本蒲公英VS西洋蒲公英','“就算被践踏了，也要坚强地站起来”，这其实只不过是人类的幻想罢了。植物的生存方式，比我们人类这种情绪化的“毅力论”有逻辑得多。','900-963',NULL,1643015839,1782398647);
INSERT INTO highlights VALUES('27480233_13_2694-2710','27480233',13,'苹果的蒂在哪里？','苹果和草莓确实都是蔷薇科的植物。','2694-2710',NULL,1642940389,1782398647);
INSERT INTO highlights VALUES('27480233_13_1801-1869','27480233',13,'苹果的蒂在哪里？','草莓的红色果肉，其实是一种位于花朵根部被叫作花托的肥大的部分。在花托上面，分布着很多小小的子房。在随后发育的过程中，花托的部分逐渐胀大。','1801-1869',NULL,1642940283,1782398647);
INSERT INTO highlights VALUES('27480233_13_1233-1281','27480233',13,'苹果的蒂在哪里？','苹果的果肉并不是由肥大的子房形成的。苹果的果肉，是由花朵根部被叫作花托的部分包裹着子房而形成的。','1233-1281',NULL,1642940241,1782398647);
INSERT INTO highlights VALUES('27480233_13_1310-1337','27480233',13,'苹果的蒂在哪里？','由于果肉并不是由子房发育而成的，苹果也被叫作“假果”。','1310-1337',NULL,1642940140,1782398647);
INSERT INTO highlights VALUES('27480233_12_1034-1073','27480233',12,'三角龙的衰退和植物的进化','裸子植物的“胚珠裸露在外”。与之相对，被子植物的“胚珠被包藏于闭合的子房内”。','1034-1073',NULL,1642939668,1782398647);
INSERT INTO highlights VALUES('27480233_10_1786-1820','27480233',10,'蝴蝶为什么会停在菜叶上？','昆虫和植物在竞争的同时，也在一起进化。这样的进化被称为“共同进化”。','1786-1820',NULL,1642925536,1782398647);
INSERT INTO highlights VALUES('27480233_9_3025-3103','27480233',9,'花儿究竟是为谁开','所有的生物都为了自身利益而行动。但是从人类的角度来看，蜜蜂这种完全利己主义的行动实际上却是一种互相帮助的行为。蜜蜂的行动，使它们和花朵达成了一种共赢的关系。','3025-3103',NULL,1642925319,1782398647);
INSERT INTO highlights VALUES('27480233_9_1719-1756','27480233',9,'花儿究竟是为谁开','蜜蜂对紫色情有独钟，因此可以引来蜜蜂的紫色花朵，通常情况下都是分散盛开的。','1719-1756',NULL,1642925190,1782398647);
INSERT INTO highlights VALUES('27480233_9_1003-1012','27480233',9,'花儿究竟是为谁开','早春花田的形成原因','1003-1012',NULL,1642925169,1782398647);
INSERT INTO highlights VALUES('27480233_8_2356-2418','27480233',8,'鲜花占卜的必胜法','植物花朵的部分，原本就是由叶子分化而成的。就像叶子为了实现最高效率，以斐波那契数列进行排布一样，花瓣为了实现最优最均衡的排布','2356-2418',NULL,1642924188,1782398647);
INSERT INTO highlights VALUES('27480233_8_830-847','27480233',8,'鲜花占卜的必胜法','金盏花。金盏花的花瓣是奇数，13瓣','830-847',NULL,1642924029,1782398647);
INSERT INTO highlights VALUES('27480233_8_693-737','27480233',8,'鲜花占卜的必胜法','因为大波斯菊的花瓣是偶数，8瓣。因此不管我们数多少次，最后剩下的都是表示“不喜欢”的花瓣','693-737',NULL,1642923948,1782398647);
INSERT INTO highlights VALUES('27480233_7_2646-2664','27480233',7,'植物的达·芬奇密码','植物叶子的生长方式也符合斐波那契数列','2646-2664',NULL,1642923741,1782398647);
INSERT INTO highlights VALUES('27480233_7_3085-3212','27480233',7,'植物的达·芬奇密码','用360度除以黄金比例1.618，可以得到222.5度。而从角度较小的那一侧看，是137.5度。这个角度，是遵循斐波那契数列规律的最精巧的角度。植物的叶子以这样的数列规律排布的话，所有的叶片都不会重叠，可以充分地吸收阳光。此外，还可以使茎的强度更加均衡。','3085-3212',NULL,1642923714,1782398647);
INSERT INTO highlights VALUES('920085_41_991-1035','920085',41,'梦想的文艺','每天起飞五千架重轰炸机往下洒极细的砂子，把黑雾过滤成白雾，而伦敦市民就一律因此增寿十年。','991-1035',NULL,1580636889,1782398669);
INSERT INTO highlights VALUES('920085_40_1443-1460','920085',40,'怎样读小说','关心社会的便好，不关心社会的便坏。','1443-1460',NULL,1580636585,1782398669);
INSERT INTO highlights VALUES('920085_40_1702-1759','920085',40,'怎样读小说','我们读一本小说，绝不该以内容与穿插的惊奇与否而定去取，而是要以作者怎样处理内容的态度，和怎样设计去表现，去定好坏。','1702-1759',NULL,1580636557,1782398669);
INSERT INTO highlights VALUES('920085_40_1172-1257','920085',40,'怎样读小说','我们读小说时，不应只注意它的内容，也须学习它的文字，看它怎么以最少的文字，形容出复杂的心态物态来；看它怎样用最恰当的文字，把人情物状一下子形容出来，活生生的立在我们的眼前','1172-1257',NULL,1580636470,1782398669);
INSERT INTO highlights VALUES('920085_40_728-764','920085',40,'怎样读小说','小说是讲人生经验的。我们读了小说，才会明白人间，才会知道处身涉世的道理。','728-764',NULL,1580636398,1782398669);
INSERT INTO highlights VALUES('920085_38_1201-1241','920085',38,'文艺与木匠','中文能写通顺，外国书能念，你还须去生活。我看，你到三十岁左右再写东西，绝不算晚。','1201-1241',NULL,1580634786,1782398669);
INSERT INTO highlights VALUES('920085_38_1166-1198','920085',38,'文艺与木匠','文字写通顺了，你要“至少”学会一种外国语，给自己多添上一双眼睛。','1166-1198',NULL,1580634775,1782398669);
INSERT INTO highlights VALUES('920085_38_1105-1116','920085',38,'文艺与木匠','你先要把中文写通顺了。','1105-1116',NULL,1580634759,1782398669);
INSERT INTO highlights VALUES('920085_37_2556-2651','920085',37,'文牛','青年朋友们，假使你没有变成一头牛的把握，请不要干我这一行事吧；当你写不出字来的时候，你比谁的苦痛都更大！我是永不怨天尤人的人，今天我只后悔自己选错了职业——完全是我自己的事，与别人毫不相干。','2556-2651',NULL,1580633725,1782398669);
INSERT INTO highlights VALUES('920085_37_1696-1767','920085',37,'文牛','我没法不先戒烟，以延缓上吊之期了；人都惜命呀！没有烟，我只会流汗，一个字也写不出！戒烟就是自己跟自己摔跤，我怎能写字呢？半个月，没写出一个字！','1696-1767',NULL,1580633433,1782398669);
INSERT INTO highlights VALUES('920085_37_770-790','920085',37,'文牛','只要我愿意，我可连着有一个星期的星期日！','770-790',NULL,1580633220,1782398669);
INSERT INTO highlights VALUES('920085_35_2630-2646','920085',35,'读书','可是至少给我一点我不知道的东西。','2630-2646',NULL,1580632749,1782398669);
INSERT INTO highlights VALUES('920085_35_2612-2618','920085',35,'读书','书是别人的好','2612-2618',NULL,1580632737,1782398669);
INSERT INTO highlights VALUES('920085_35_2388-2400','920085',35,'读书','而是书中的一段最入我的味','2388-2400',NULL,1580632705,1782398669);
INSERT INTO highlights VALUES('920085_35_2327-2351','920085',35,'读书','我读书似乎只要求一点灵感。“印像甚佳”便是好书，','2327-2351',NULL,1580632693,1782398669);
INSERT INTO highlights VALUES('920085_35_2148-2168','920085',35,'读书','第三，读完一本书，没有批评，谁也不告诉。','2148-2168',NULL,1580632650,1782398669);
INSERT INTO highlights VALUES('920085_35_2071-2119','920085',35,'读书','不合我的意，我就练习跳远。书要是不服气的话，来跳我呀！看侦探小说的时候，我先看最后的几页，省事。','2071-2119',NULL,1580632605,1782398669);
INSERT INTO highlights VALUES('920085_35_1951-1959','920085',35,'读书','书应该记住自己。','1951-1959',NULL,1580632547,1782398669);
INSERT INTO highlights VALUES('920085_35_1924-1936','920085',35,'读书','第二，读得很快，而不记住','1924-1936',NULL,1580632531,1782398669);
INSERT INTO highlights VALUES('920085_35_1831-1895','920085',35,'读书','第一，我读书没系统。借着什么，买着什么，遇着什么，就读什么。不懂的放下，使我糊涂的放下，没趣味的放下，不客气。我不能叫书管着我。','1831-1895',NULL,1580632524,1782398669);
INSERT INTO highlights VALUES('920085_35_1520-1547','920085',35,'读书','这要说到第三类书了。其实这不该算一类；就这么算吧，顺嘴','1520-1547',NULL,1580632480,1782398669);
INSERT INTO highlights VALUES('920085_35_1440-1489','920085',35,'读书','第二类书根本就看不懂，可是人家的纸上没印着一句废话；懂不懂的，人家不闹玄虚，它瞪我，或者我是该瞪。','1440-1489',NULL,1580632461,1782398669);
INSERT INTO highlights VALUES('920085_35_1313-1335','920085',35,'读书','第一类书不是没法懂，而是懂了以后使我更糊涂。','1313-1335',NULL,1580632411,1782398669);
INSERT INTO highlights VALUES('920085_22_10512-10547','920085',22,'新韩穆烈德','证明不应当存在的便得死亡，不用别人动手，自己就会败坏，像搁陈了的橘子。','10512-10547',NULL,1580630567,1782398669);
INSERT INTO highlights VALUES('920085_22_1516-1543','920085',22,'新韩穆烈德','自己觉得像已放散了一天的香味的花，应当敛上了瓣休息会儿','1535-1562',NULL,1580629328,1782398669);
INSERT INTO highlights VALUES('920085_22_1362-1404','920085',22,'新韩穆烈德','这个，使他常想到自己像个极雅美的磁盆，盛着清水，可是只养着一些浮萍与几团绒似的绿苔！','1362-1404',NULL,1580629298,1782398669);
INSERT INTO highlights VALUES('920085_21_6321-6339','920085',21,'听来的故事','他以自己的糊涂给别人的聪明开了一条路','6321-6339',NULL,1580629121,1782398669);
INSERT INTO highlights VALUES('920085_21_5683-5767','920085',21,'听来的故事','人家老孟自然，糊涂得像条骆驼，可是老那么魁梧壮实，一声不出，能在沙漠里慢慢溜达一个星期！他不去找缝子钻，社会上自然给他预备好缝子，要不怎么他老预备着发笑呢。他觉得合适。','5683-5767',NULL,1580628965,1782398669);
INSERT INTO highlights VALUES('920085_21_5128-5203','920085',21,'听来的故事','我们的时代——没办法就是办法的时代。一个人无须为他的时代着急，也无须为个人着急，他只须天真的没办法，自然会在波浪上浮着，而相信：‘哼，我浮着最合适。’','5147-5222',NULL,1580628874,1782398669);
INSERT INTO highlights VALUES('920085_21_5095-5118','920085',21,'听来的故事','他使我对于成功或失败都感觉到淡漠，使我心中平静','5095-5118',NULL,1580628846,1782398669);
INSERT INTO highlights VALUES('920085_20_2151-2185','920085',20,'火车','绿嘴唇咧开，露出几个乌牙；绿嘴唇并上，鼓起，拍，一口吐液，唾在地上。','2151-2185',NULL,1580621289,1782398669);
INSERT INTO highlights VALUES('920085_20_1379-1415','920085',20,'火车','四十多岁，脖子很细很长，似乎可以随时把脑袋摘下来，再安上去，一点也不费事','1379-1415',NULL,1580621069,1782398669);
INSERT INTO highlights VALUES('920085_19_780-832','920085',19,'一封家信','我们善意的来推测，这位先生的闭口不响，一定具有要维持和平的苦心和盼望。可是，人与人之间是多么不易谅解呢；','780-832',NULL,1580617565,1782398669);
INSERT INTO highlights VALUES('920085_18_6332-6361','920085',18,'杀狗','打了极长的两个哈欠，大泪珠像虫儿似的向左右轻爬，倒还痛快。','6332-6361',NULL,1580608920,1782398669);
INSERT INTO highlights VALUES('920085_18_1466-1487','920085',18,'杀狗','初才子嗤的笑了一声，像一个水点落在红铁上。','1466-1487',NULL,1580607315,1782398669);
INSERT INTO highlights VALUES('920085_17_725-750','920085',17,'浴奴','然后把黄而无神的眼珠定在手绢中心的一滩黄稠的汁儿上','725-750',NULL,1580562035,1782398669);
INSERT INTO highlights VALUES('920085_13_1113-1153','920085',13,'歪毛儿','打完，眼泪在眼眶里转，转好大半天，像水花打旋而渗不下去的样儿。始终他不许泪落下来','1113-1153',NULL,1580471917,1782398669);
INSERT INTO highlights VALUES('920085_13_811-833','920085',13,'歪毛儿','一跑，俩歪毛左右开弓的敲着脸蛋，像个拨浪鼓儿','811-833',NULL,1580466862,1782398669);
INSERT INTO highlights VALUES('920085_12_5084-5107','920085',12,'铁牛和病鸭','铁牛脸上的笑意像个开花弹似的，从脸上射到空中。','5084-5107',NULL,1580466115,1782398669);
INSERT INTO highlights VALUES('920085_12_4294-4336','920085',12,'铁牛和病鸭','台上正当中坐着病鸭，头发挺长，脸色灰绿，长嘴放在胸前，眼睛时开时闭，活像个半睡的鸭子','4294-4336',NULL,1580465979,1782398669);
INSERT INTO highlights VALUES('920085_12_3546-3557','920085',12,'铁牛和病鸭','于是他的脑中转开了螺丝','3546-3557',NULL,1580465840,1782398669);
INSERT INTO highlights VALUES('920085_12_3271-3305','920085',12,'铁牛和病鸭','病鸭是牢骚的结晶，袋中老带着点“补丸”之类的小药，未曾吃饭先叹口气。','3271-3305',NULL,1580465781,1782398669);
