INSERT INTO highlights VALUES('920085_8_1188-1213','920085',8,'微神','小得已经快和蓝天化在一处了，像万顷蓝光中的一粒黑痣','1188-1213',NULL,1580366737,1782398669);
INSERT INTO highlights VALUES('920085_8_964-1071','920085',8,'微神','我在山坡上晒太阳，一点思念也没有，可是自然而然地从心中滴下些诗的珠子，滴在胸中的绿海上，没有声响，只有些波纹走不到腮上便散了的微笑；可是始终也没成功一整句。一个诗的宇宙里，连我自己好似只是诗的什么地方的一个小符号。','983-1090',NULL,1580366643,1782398669);
INSERT INTO highlights VALUES('920085_8_890-934','920085',8,'微神','偶尔走过一只来，没长犄角就留下须的小动物，向一块大石发了会儿愣，又颠颠着俏式的小尾巴跑了','890-934',NULL,1580366598,1782398669);
