INSERT INTO highlights VALUES('920085_7_13064-13102','920085',7,'大悲寺外','有些人是这样：至死总假装宽厚大方，一点不为自己的命想一想，好像死是最便宜的事','13083-13121',NULL,1580364541,1782398669);
INSERT INTO highlights VALUES('920085_7_11421-11503','920085',7,'大悲寺外','你或者出于无意，可是对于我，这句话是种报复、惩罚。它的颜色是红的一条布，像条毒蛇；它确是有颜色的。它使我把生命变成一阵颤抖；志愿，事业，全随颤抖化为——秋风中的落叶','11421-11503',NULL,1580364300,1782398669);
INSERT INTO highlights VALUES('920085_7_8668-8685','920085',7,'大悲寺外','所以是小姐——有点忽东忽西的小性。','8668-8685',NULL,1580363928,1782398669);
