INSERT INTO highlights VALUES('920085_7_1422-1541','920085',7,'大悲寺外','可是，那双眼！上眼皮受着“胖”的影响，松松的下垂，把原是一对大眼睛变成了俩螳螂卵包似的，留个极小的缝儿射出无限度的黑亮。好像这两道黑光，假如你单单的看着它们，把“胖”的一切注脚全勾销了。那是一个胖人射给一个活动、灵敏、快乐的世界的两道神光','1422-1541',NULL,1580363185,1782398669);
INSERT INTO highlights VALUES('920085_7_1347-1398','920085',7,'大悲寺外','胖胖的，脑后折着三道肉印；我常想，理发师一定要费不少的事，才能把那三道弯上的短发推净。脸像个大肉葫芦，','1347-1398',NULL,1580363167,1782398669);
