INSERT INTO highlights VALUES('920085_4_9886-9986','920085',4,'不成问题的问题','也就是下午一点钟吧，天上有几缕秋云，阳光从云隙发出一些不甚明的光，云下，存着些没有完全被微风吹散的雾。江水大体上还是黄的，只有江岔子里的已经静静地显出绿色。葡萄的叶子就快落净，茶花已顶出一些红瓣儿来。','9886-9986',NULL,1580297603,1782398669);
