INSERT INTO highlights VALUES('30914610_13_3324-3394','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','容易焦虑的孩子会产生鸵鸟心态：当他不敢或不愿面对“必须改变”的现实时，为了追求安全感，他可能会以更强烈的情绪、更固执的行动来抗拒“被改变”。','3324-3394',NULL,1620565578,1782398655);
INSERT INTO highlights VALUES('30914610_13_4781-4791','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','要提供正面乐观的描述','4781-4791',NULL,1620565577,1782398655);
INSERT INTO highlights VALUES('30914610_12_6504-6543','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','过度担忧的保护措施，不仅剥夺了孩子思考、判断与表达的机会，也让孩子难以茁壮成长','6504-6543',NULL,1620565576,1782398655);
INSERT INTO highlights VALUES('30914610_13_3848-3855','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','.要辨识焦虑源','3848-3855',NULL,1620565576,1782398655);
INSERT INTO highlights VALUES('30914610_12_2084-2138','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','当孩子对事情的结果有负面预期的时候，结局往往也容易朝失败的方向发展，这样的现象在心理学上称为“自我实现预言”','2084-2138',NULL,1620565575,1782398655);
INSERT INTO highlights VALUES('30914610_15_4307-4324','30914610',15,'第十章 孩子是冲动“小霸王”：一言不合就动手打人怎么办','要以具有同理心的话语回应孩子的情绪','4307-4324',NULL,1620565574,1782398655);
INSERT INTO highlights VALUES('30914610_12_4933-4947','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','3.要为孩子安排感兴趣的事物','4933-4947',NULL,1620565574,1782398655);
INSERT INTO highlights VALUES('30914610_14_4251-4288','30914610',14,'·第四部分 小学高年级阶段孩子的情绪问题','谢谢你告诉我，这对我很重要，因为这样我才知道你担心穿这件衣服会被同学笑话。','4251-4288',NULL,1620565573,1782398655);
INSERT INTO highlights VALUES('30914610_12_3531-3545','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','1.要强化孩子勇敢不哭的时刻','3531-3545',NULL,1620565572,1782398655);
INSERT INTO highlights VALUES('30914610_15_4575-4658','30914610',15,'第十章 孩子是冲动“小霸王”：一言不合就动手打人怎么办','我知道你现在很生气。”“妈妈知道你真的很痛。”“我知道你很委屈。”如果看到孩子紧握拳头，眼神充满怒意，可以跟他说“我知道你很努力地在控制自己，想要在生气的时候不动手”','4575-4658',NULL,1620565572,1782398655);
INSERT INTO highlights VALUES('30914610_13_6052-6099','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','对年龄小一点的孩子，父母可以先帮孩子把心里紧张的情绪说出来：“你担心会做不好，所以很紧张吧？”','6052-6099',NULL,1620565571,1782398655);
INSERT INTO highlights VALUES('30914610_12_2521-2595','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','无论是为孩子设定过高的目标、提出过度的要求，还是低估孩子的能力、给予的期许过低，都会强化孩子的低自尊心理，同时也就使孩子更容易出现畏缩、哭泣的行为。','2521-2595',NULL,1620565570,1782398655);
INSERT INTO highlights VALUES('30914610_12_4283-4298','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','2.要为孩子创造克服挑战的机会','4283-4298',NULL,1620565570,1782398655);
INSERT INTO highlights VALUES('30914610_13_3802-3821','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','让敏感、警觉的性格成为他们成功的助力。','3802-3821',NULL,1620565569,1782398655);
INSERT INTO highlights VALUES('30914610_14_4679-4756','30914610',14,'·第四部分 小学高年级阶段孩子的情绪问题','一旦孩子感受到被尊重，那么他们在内心满足的情况下所做出的决定，无论是分享或拒绝，都能以一种坚定且温和的态度回应别人，也将促成心神自在、怀有善意的人际互动。','4679-4756',NULL,1620565569,1782398655);
INSERT INTO highlights VALUES('30914610_15_4997-5011','30914610',15,'第十章 孩子是冲动“小霸王”：一言不合就动手打人怎么办','要用温和的动作舒缓孩子的情绪','4997-5011',NULL,1620565568,1782398655);
INSERT INTO highlights VALUES('30914610_14_3715-3799','30914610',14,'·第四部分 小学高年级阶段孩子的情绪问题','过度替别人着想的孩子，一方面是性格含蓄，不善于表达，另一方面也会因为习惯猜测别人怎么想，导致“言者无心，闻者足戒”的状况。常以为对方在暗示什么，其实只是自己的揣测而已。','3715-3799',NULL,1620565567,1782398655);
INSERT INTO highlights VALUES('30914610_12_1871-1890','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','低自尊的孩子容易出现情绪低落或哭泣行为','1871-1890',NULL,1620565566,1782398655);
INSERT INTO highlights VALUES('30914610_13_6115-6144','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','“你看起来有点担心，怎么了？”引导孩子正确发泄紧张的情绪，','6115-6144',NULL,1620565566,1782398655);
INSERT INTO highlights VALUES('30914610_14_4404-4412','30914610',14,'·第四部分 小学高年级阶段孩子的情绪问题','要给予孩子自主权','4404-4412',NULL,1620565565,1782398655);
INSERT INTO highlights VALUES('30914610_15_5506-5525','30914610',15,'第十章 孩子是冲动“小霸王”：一言不合就动手打人怎么办','要以转移注意力的方式暂缓孩子激动的情绪','5506-5525',NULL,1620565565,1782398655);
INSERT INTO highlights VALUES('30914610_15_7113-7149','30914610',15,'第十章 孩子是冲动“小霸王”：一言不合就动手打人怎么办','对处于成长阶段的孩子来说，在踏入社会之前学会做出合理的行为是很有必要的。','7113-7149',NULL,1620565563,1782398655);
INSERT INTO highlights VALUES('30914610_13_4256-4328','30914610',13,'第八章 不安也可以变优点：如何帮助焦虑的孩子','但事实上，光是面对生活中各种不同的要求，譬如学习成绩、兴趣班学习、朋友互动等，对孩子来说，都是压力的积累，一旦超过承受压力的上限，情绪就会失控。','4256-4328',NULL,1620565563,1782398655);
INSERT INTO highlights VALUES('30914610_12_4976-4998','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','喜好与兴趣是增添成就感和正能量的重要调剂品！','4976-4998',NULL,1620565562,1782398655);
INSERT INTO highlights VALUES('30914610_12_6044-6076','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','这些表达会内化成孩子自我对话的内容，成为他心中撕不掉的自我标签。','6044-6076',NULL,1620565561,1782398655);
INSERT INTO highlights VALUES('30914610_12_4529-4544','30914610',12,'第七章 家有落泪小天使：如何帮助爱哭的孩子','为孩子提供有可能成功的“挑战”','4529-4544',NULL,1620565560,1782398655);
INSERT INTO highlights VALUES('30914610_11_6094-6189','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','父母最好提前和孩子说明在这个环境中需要注意的事项，带孩子一起学习环境中的规范要求，并陪伴孩子一同进行一段时间的活动，在确认孩子熟悉环境、了解规范、清楚活动方式及安全事项之后，再让他自由探索。','6094-6189',NULL,1618045337,1782398655);
INSERT INTO highlights VALUES('30914610_11_5351-5385','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','也要记得将焦点放在孩子愿意帮忙的动力上，而非事情做得好不好的结果上。','5351-5385',NULL,1618045224,1782398655);
INSERT INTO highlights VALUES('30914610_11_5392-5421','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','有你和我一起做家务，省了不少时间，而且轻松多了，妈妈好开心','5392-5421',NULL,1618045213,1782398655);
INSERT INTO highlights VALUES('30914610_11_5231-5294','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','让孩子通过帮忙做事来释放高活动量的需求。当孩子完成任务后，一定要记得肯定他的表现、感谢他的帮忙，进而提升孩子的成就感和自信心。','5231-5294',NULL,1618045176,1782398655);
INSERT INTO highlights VALUES('30914610_11_5159-5174','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','要主动给孩子提供当小帮手的机会','5159-5174',NULL,1618045156,1782398655);
INSERT INTO highlights VALUES('30914610_11_4796-4815','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','成功经验，都能强化孩子自我控制的能力。','4796-4815',NULL,1618045122,1782398655);
INSERT INTO highlights VALUES('30914610_11_4087-4091','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','注视彼此','4087-4091',NULL,1618045055,1782398655);
INSERT INTO highlights VALUES('30914610_11_4033-4045','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','即比赛看谁可以最久不说话','4033-4045',NULL,1618045042,1782398655);
INSERT INTO highlights VALUES('30914610_11_4025-4032','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','“看谁最厉害”','4025-4032',NULL,1618045034,1782398655);
INSERT INTO highlights VALUES('30914610_11_3857-3860','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','木头人','3857-3860',NULL,1618045001,1782398655);
INSERT INTO highlights VALUES('30914610_11_3773-3784','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','.要安排动静穿插的活动','3773-3784',NULL,1618044993,1782398655);
INSERT INTO highlights VALUES('30914610_11_3700-3746','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','建议父母在孩子每天放学后，为他们安排适量的运动或户外活动，让孩子每天能有充分释放活力的时间。','3700-3746',NULL,1618044982,1782398655);
INSERT INTO highlights VALUES('30914610_11_3380-3393','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','要为孩子提供充足的活动时间','3380-3393',NULL,1618044948,1782398655);
INSERT INTO highlights VALUES('30914610_11_2910-2986','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','孩子不是不懂规矩，只是他们对周围环境中的各种事物充满好奇，又喜欢用身体碰触、动手操作等方式去探索，既让自己可以充分释放身体能量，又能达到探索环境的目的。','2910-2986',NULL,1618044906,1782398655);
INSERT INTO highlights VALUES('30914610_11_1730-1742','30914610',11,'第六章 我家孩子像条虫：好动的孩子怎么教','理解孩子的身体需要很重要','1730-1742',NULL,1618044790,1782398655);
INSERT INTO highlights VALUES('30914610_10_7115-7207','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','他需要的是父母的理解和帮助，引导他在分心时“用对方法，专注当下”，更需要父母给出良好的示范。父母不轻易分心、烦躁，看见孩子的努力和进步，给予孩子更多的正面反馈，孩子也一定会越来越专注！','7115-7207',NULL,1618044664,1782398655);
INSERT INTO highlights VALUES('30914610_10_6894-6994','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','特别是在如今的互联网时代，父母少看电视、少玩手机、少面对电脑，多花些时间陪伴孩子，和孩子讨论做事的顺序与方法，一起检视需要完成的事情，一起执行有助于提升注意力的策略，孩子就会在有榜样的氛围里逐渐进步。','6894-6994',NULL,1618044631,1782398655);
INSERT INTO highlights VALUES('30914610_10_6409-6505','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','陪伴孩子写作业时，不要一见到孩子字写得不漂亮、答案不完整就立刻要他涂改。这样的行为不但会干扰孩子的注意力，还很容易造成孩子情绪上的反弹，即使内容真的有误，也要先让孩子处理完一个段落再进行订正。','6409-6505',NULL,1618044572,1782398655);
INSERT INTO highlights VALUES('30914610_10_5591-5632','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','每个段落完成后，父母要记得肯定孩子的专注和成果，让孩子休息一下再开始下一段落的作业','5591-5632',NULL,1618044487,1782398655);
INSERT INTO highlights VALUES('30914610_10_5502-5544','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','父母可以根据作业难度、内容性质等，和孩子一起将作业分为较小的段落，鼓励孩子分段完成。','5502-5544',NULL,1618044469,1782398655);
INSERT INTO highlights VALUES('30914610_10_5433-5473','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','时间短一点、作业少一点，让孩子做得到、做得完、做得好，完成的动力与效率才会更高。','5433-5473',NULL,1618044432,1782398655);
INSERT INTO highlights VALUES('30914610_10_5364-5373','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','3.做小段落的切分','5364-5373',NULL,1618044392,1782398655);
INSERT INTO highlights VALUES('30914610_10_5051-5056','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','.简化环境','5051-5056',NULL,1618044364,1782398655);
INSERT INTO highlights VALUES('30914610_10_4159-4177','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','1.要吃饱、睡好，适度运动，规律作息','4159-4177',NULL,1618044340,1782398655);
INSERT INTO highlights VALUES('30914610_10_4525-4594','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','美国儿科医学会曾针对包含午睡在内的每日睡眠时长提出建议：学前儿童（3～5岁）需要10～13小时，学龄儿童（6～12岁）则以9～12小时为佳','4525-4594',NULL,1618044302,1782398655);
INSERT INTO highlights VALUES('30914610_10_3330-3337','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','注意力不易转换','3330-3337',NULL,1618044205,1782398655);
INSERT INTO highlights VALUES('30914610_10_3194-3199','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','注意力涣散','3194-3199',NULL,1618044202,1782398655);
INSERT INTO highlights VALUES('30914610_10_3033-3038','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','注意力短暂','3033-3038',NULL,1618044183,1782398655);
INSERT INTO highlights VALUES('30914610_10_2917-2922','30914610',10,'·第三部分 小学低年级阶段孩子的情绪问题','注意力不足','2917-2922',NULL,1618044180,1782398655);
INSERT INTO highlights VALUES('30914610_9_6385-6453','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','让孩子拥有自主的选择权，能减缓孩子抗拒父母权威的心理，如果能再加入一些有趣的元素，通常孩子就会二话不说地接受父母的安排，飞快地行动起来。','6385-6453',NULL,1618043678,1782398655);
INSERT INTO highlights VALUES('30914610_9_6296-6356','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','你要当救援小队长，赶紧出动去拿抹布来擦，还是要当清洁公司工作人员帮忙擦地板，或者要当大力士把擦完的抹布洗干净和拧干呢？”','6296-6356',NULL,1618043668,1782398655);
INSERT INTO highlights VALUES('30914610_9_6115-6177','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','父母必须跟孩子讨论负责任的方式，如帮对方擦药或做一件对方指定且合理的事，才能为孩子提供修复关系、重新与人友善交流的学习机会。','6115-6177',NULL,1618043625,1782398655);
INSERT INTO highlights VALUES('30914610_9_5727-5744','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','3.要让孩子从自然合理的后果中学习','5727-5744',NULL,1618043569,1782398655);
INSERT INTO highlights VALUES('30914610_9_5552-5701','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','这时需要“就事论事”，把焦点转回原来的事情上，告诉他：“我知道你有你的想法，但现在请先擦干地上的水！”“我知道你很想赶快去玩，但现在请先把围兜挂好！”当父母不被孩子的“态度”影响，而能把焦点放在事情上时，就会有比较多的心力引导孩子做出适当的行为，也不至于让孩子有机会在你情绪性的话语中挑语病反击你。','5552-5701',NULL,1618043552,1782398655);
INSERT INTO highlights VALUES('30914610_9_5279-5293','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','2.要先处理事情，再处理态度','5279-5293',NULL,1618043495,1782398655);
INSERT INTO highlights VALUES('30914610_9_5052-5140','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','“我知道你不是故意的，是因为急着要喝水才会打翻，而且你肚子很饿，一定不想现在去收拾。”之后再以中性、平和的方式告诉他：“请你把水擦干，就可以吃饭了。”这样孩子就会比较容易接受。','5052-5140',NULL,1618043440,1782398655);
INSERT INTO highlights VALUES('30914610_9_4482-4494','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','1.要用中性语句陈述指令','4482-4494',NULL,1618043385,1782398655);
INSERT INTO highlights VALUES('30914610_9_3226-3326','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','所以，当孩子难过、生气、失望时，如果父母没有先让孩子“说出”内心的需求、委屈、失望，反而急着要说服他或希望他“不要有这种不愉快的感觉”，那么孩子不但无法学到调节情绪的方法，当下的反抗行为反而会更激烈。','3226-3326',NULL,1618043237,1782398655);
INSERT INTO highlights VALUES('30914610_9_2520-2554','30914610',9,'第四章 我不是故意唱反调：爱反抗、不听话的孩子怎么教','误以为全天下最重要的事情就是满足自己的需求，而不需要顾及他人的感受。','2520-2554',NULL,1618040646,1782398655);
INSERT INTO highlights VALUES('30914610_8_6824-6892','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','因为，这样会让孩子在心里产生不必要的恐惧，也会让孩子对照顾者或环境产生不安，造成“不敢一个人独处”“害怕待在密闭空间里”等其他心理问题。','6824-6892',NULL,1618040161,1782398655);
INSERT INTO highlights VALUES('30914610_8_4780-4788','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','3.要先处理心情','4780-4788',NULL,1618039775,1782398655);
INSERT INTO highlights VALUES('30914610_8_4669-4754','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','父母可以试着轻抚孩子的背部，顺着脊椎两侧轻拍慢抚；也可以轻轻按摩孩子的双臂，让孩子紧绷的身体放松下来。除此之外，对各种负面情绪都适用的腹式呼吸，也是使身体放松的有效方法。','4669-4754',NULL,1618039668,1782398655);
INSERT INTO highlights VALUES('30914610_8_4393-4435','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','人们生气的生存目的是要移除阻碍我们的人、事、物，而移除这些障碍常需要我们身体的参与。','4393-4435',NULL,1618039597,1782398655);
INSERT INTO highlights VALUES('30914610_8_4348-4355','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','2.要引导放松','4348-4355',NULL,1618039124,1782398655);
INSERT INTO highlights VALUES('30914610_8_4221-4322','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','你今天好想吃饼干。”“晚餐不能吃饼干，你一定很失望、很难过……”“妈妈知道你真的很想吃饼干。”温和坚定的语气和态度，会让小凯的情绪被温柔地安抚下来，进入平静的状态，小凯也能从对话中学到父母要教他的道理。','4221-4322',NULL,1618039111,1782398655);
INSERT INTO highlights VALUES('30914610_8_3873-3879','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','.要淡定回应','3873-3879',NULL,1618039047,1782398655);
INSERT INTO highlights VALUES('30914610_8_3062-3105','30914610',8,'第三章 我家有座“活火山”：如何帮助爱发脾气的孩子','除了本身的特质之外，父母或其他大人对孩子情绪的回应方式，也会影响孩子表现内心感受的方式','3062-3105',NULL,1618038915,1782398655);
INSERT INTO highlights VALUES('30914610_7_6200-6228','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','鼓励孩子跟昨天的自己比，只要努力、有进步，就是一种成功。','6200-6228',NULL,1618038228,1782398655);
INSERT INTO highlights VALUES('30914610_7_5089-5099','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','要陪伴孩子度过挫败期','5089-5099',NULL,1618038128,1782398655);
INSERT INTO highlights VALUES('30914610_7_4838-4894','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','父母也可以示范另一种面对失败结果的态度，叫作“力不从心”，即接受自己目前无法突破这个困境、失败也没有关系的态度。','4838-4894',NULL,1618038101,1782398655);
INSERT INTO highlights VALUES('30914610_7_4471-4479','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','.要乐观描述失败','4471-4479',NULL,1618037336,1782398655);
INSERT INTO highlights VALUES('30914610_7_4324-4343','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','孩子七分成功，父母三分努力”的基本原则','4324-4343',NULL,1618037324,1782398655);
INSERT INTO highlights VALUES('30914610_7_4007-4090','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','父母通过从旁观察，针对困难的挑战，给予孩子一些具体可行的建议，或者点出孩子已经在往更好的方向前进了，鼓励孩子再试试看，引导他突破眼前的难关，也是帮助孩子成功的好方法。','4007-4090',NULL,1618037304,1782398655);
INSERT INTO highlights VALUES('30914610_7_3715-3771','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','根据孩子目前的具体表现和行为事实，给予直接、正面的鼓励和肯定，让孩子清楚地知道自己哪里做得很好，强化孩子的成就感','3715-3771',NULL,1618037237,1782398655);
INSERT INTO highlights VALUES('30914610_7_3677-3686','30914610',7,'·第二部分 幼儿园阶段孩子的情绪问题','1.要强化成功经验','3677-3686',NULL,1618037198,1782398655);
INSERT INTO highlights VALUES('30914610_6_4429-4547','30914610',6,'·第一部分 孩子情绪问题总论','轻轻地闭上眼睛，身体放松，把双手很自然地放在身体两侧。好，现在请慢慢地把气吐出来，再慢慢地吸气、吐气。吸气的时候，把气吸到最深的地方，让肚子胀起来；接着，再慢慢地将气呼出来。吐气的时候让你的肩膀自然地放松下来，非常非常放松……”腹式呼吸','4429-4547',NULL,1618036862,1782398655);
INSERT INTO highlights VALUES('30914610_6_2889-2925','30914610',6,'·第一部分 孩子情绪问题总论','同理关怀与规范要求双管齐下，沟通对话与协商讨论并重的“权威民主”教养形态','2889-2925',NULL,1618036741,1782398655);
INSERT INTO highlights VALUES('30914610_6_2852-2881','30914610',6,'·第一部分 孩子情绪问题总论','第三，父母的教养形态对孩子的情绪行为也有着长远且深刻的影响','2852-2881',NULL,1618036657,1782398655);
INSERT INTO highlights VALUES('30914610_6_2601-2624','30914610',6,'·第一部分 孩子情绪问题总论','第二，孩子的“气质”对其情绪行为的影响也很大。','2601-2624',NULL,1618036650,1782398655);
INSERT INTO highlights VALUES('30914610_6_2250-2274','30914610',6,'·第一部分 孩子情绪问题总论','第一，要知道人类所有的情绪行为都受大脑机制的影响','2250-2274',NULL,1618036644,1782398655);
