INSERT INTO highlights VALUES('3300044239_5_6006-6244','3300044239',5,'第一章 从岁月中盗得几首往事','夏天从树梢　从街道搬走了我走上街头看了看人间的下一位旅客——秋天从很久以前风尘仆仆地搬到了人间我问他会住多久他说　住到下雪的那天','6006-6244',1,1692782319,1782398565);
