INSERT INTO highlights VALUES('26174310_173_1572-1635','26174310',173,'没有窗户的房间——读袁哲生','《送行》的叙事任务根本不在交代一个什么故事，而在人的处境；从而送行二字形成生命的整体象征，哀而不伤，怨而不怒，平淡中益见深刻。','1572-1635',NULL,1585985112,1782398694);
