INSERT INTO highlights VALUES('26174310_172_5361-5393','26174310',172,'辑四 之后——告别的叹息','天生的小说家想写的总是那些不能解决的问题，而不是他想解决的问题。','5361-5393',NULL,1585984559,1782398694);
INSERT INTO highlights VALUES('26174310_172_3365-3417','26174310',172,'辑四 之后——告别的叹息','我应该记录下来一些我对自己作品有价值的部分，好留下一些自信，以免日后遭人曲解或贬低的时候心中没有了主见。','3365-3417',NULL,1585984390,1782398694);
INSERT INTO highlights VALUES('26174310_172_1491-1518','26174310',172,'辑四 之后——告别的叹息','，而不是用极有限的时光，去筑一个适合忘却死亡的象牙塔。','1491-1518',NULL,1585984082,1782398694);
INSERT INTO highlights VALUES('26174310_172_651-668','26174310',172,'辑四 之后——告别的叹息','其实，我最爱那“生活中宽广的空白”','651-668',NULL,1585983958,1782398694);
INSERT INTO highlights VALUES('26174310_171_1144-1290','26174310',171,'未命名','因为我觉得这种方式“药性”比较温和一点，对心脏有益。如果神仙们给了一支好签，那我就“暗爽在心内”，庆幸自己果然是“上帝的选民”；如果抽到坏签，我就告诉自己抽签只是“几率”问题，不足为意；如果抽到“模棱两可”的签诗，那么以我的中文功力，一定可以把文解释成一支上签，以展现我们“民智已开”的实力。','1144-1290',NULL,1585983782,1782398694);
INSERT INTO highlights VALUES('26174310_110_539-603','26174310',110,'不朽的苍凉','在昆德拉的小说里，人生宛如一场“媚俗”的邂逅，那些“可笑的爱”“不朽的渴望”，仿佛在在说明了世俗红尘不过是场“为了别离的聚会”。','539-603',NULL,1585913879,1782398694);
INSERT INTO highlights VALUES('26174310_99_506-519','26174310',99,'摇摆','我在心里狠狠地踢了他几脚，','506-519',NULL,1585913332,1782398694);
INSERT INTO highlights VALUES('26174310_75_640-668','26174310',75,'搬不动的行李','因为我总是在必须搬家之时，才发现最搬不动的行李就是自己。','640-668',NULL,1585911286,1782398694);
INSERT INTO highlights VALUES('26174310_72_620-660','26174310',72,'眼前的世界','王小毛不摘花了，因为他闻不到花香了；王小毛也很少抬头了，因为路上还有很多电线杆。','620-660',NULL,1585911059,1782398694);
INSERT INTO highlights VALUES('26174310_66_3421-3589','26174310',66,'偏远的哭声','但是，我的生活中充满了这样的时刻，在某一天下午雷雨过后五花十色张开碰撞的雨伞遮蔽下的人群中，在某一个晚起的假日早晨骑着摩托车去住家附近自助餐馆的炎热柏油路上，来不及防备地我就想起了一些不甘沉淀的往事。我该如何同时记起你认真生活的勇气，又忘掉你匆匆结束生命的决定？我要如何提醒自己人生在世追求的是爱，同时又不会偷偷地想到或许恨的力量更大？','3421-3589',NULL,1585818260,1782398694);
INSERT INTO highlights VALUES('26174310_65_798-818','26174310',65,'楼上的父亲','因为昨日已经走得太远，而父亲就在楼下……','798-818',NULL,1585817582,1782398694);
INSERT INTO highlights VALUES('26174310_64_1334-1395','26174310',64,'我的狗脸岁月','“你回家去啦！”这宛如午后惊雷的一句话来得正是时候，早一秒则太快，似乎防人之心过重；晚一秒则太迟，迟了西瓜就进我口中去矣。','1334-1395',NULL,1585816843,1782398694);
INSERT INTO highlights VALUES('26174310_62_2341-2395','26174310',62,'我的铁达尼','是，要不要带行李的问题就浮上台面了。若是带了呢，好像显得太从容了；若说不带呢，多出来的时间又不知道该干什么。','2341-2395',NULL,1585813080,1782398694);
INSERT INTO highlights VALUES('26174310_61_4139-4157','26174310',61,'酒墙','老鸟有交代，中鸟要等待，菜鸟要忍耐，','4139-4157',NULL,1585812760,1782398694);
INSERT INTO highlights VALUES('26174310_59_4110-4133','26174310',59,'贰','我的毕业感言是：“本人最好不要看自己的照片。”','4110-4133',NULL,1585807745,1782398694);
INSERT INTO highlights VALUES('26174310_59_3252-3381','26174310',59,'贰','误以为考上大学之后最大的好处就是可以不用再上学了，于是开始结群游荡。我们就像水族箱里的热带鱼一样不会迷失方向，可是，某一天，有一尾不自爱的热带鱼破坏了我们平静美好的生活，他说了一句非常不应该的话：“你们将来打算做什么？”顿时，我们辨认方向的雷达就忽然失灵了。','3252-3381',NULL,1585807666,1782398694);
INSERT INTO highlights VALUES('26174310_58_1312-1359','26174310',58,'蜡像馆','在假日的人群中，我像是一个没有生命的道具，一道僵冷的门槛，一座空寂的天井，或是一卷漏光的竹帘。','1312-1359',NULL,1585740096,1782398694);
INSERT INTO highlights VALUES('26174310_58_519-584','26174310',58,'蜡像馆','假日始终令我迷惑，就像地球有白天和夜晚一样。暑假像是个漫长而刺眼的白昼，使我汲汲于寻觅一个藏身之处，好重回地球上属于黑暗的那半面。','519-584',NULL,1585739711,1782398694);
INSERT INTO highlights VALUES('26174310_57_513-574','26174310',57,'火车快飞','就在胖德问我福建闽江以南盛产什么东西的时候，我爸爸出现了。他看起来非常疲倦，而且衣衫不整；也就是说，他看起来和平常一模一样','513-574',NULL,1585738396,1782398694);
INSERT INTO highlights VALUES('26174310_56_3336-3403','26174310',56,'鸽子的天空','接下来的几天，我们都陶醉在一股节庆的欢乐气氛里，不断推想着各种可能遇见的难题，以及三百种“如果……”，然而，就是没有再提打电话这件事。','3336-3403',NULL,1585737794,1782398694);
INSERT INTO highlights VALUES('26174310_56_2892-2947','26174310',56,'鸽子的天空','我听了害怕得不得了，仿佛上帝正躲在一片刺眼的阳光后面，只要我敢轻举妄动的话，祂就会立刻往我头上打下一道闪电来。','2892-2947',NULL,1585737509,1782398694);
INSERT INTO highlights VALUES('26174310_56_2388-2426','26174310',56,'鸽子的天空','在狱中，我们是两株鬼鬼祟祟的爬藤，盘算着总有一天让我们出其不意偷偷攀出墙外。','2388-2426',NULL,1585737448,1782398694);
