INSERT INTO highlights VALUES('26174310_48_12633-12718','26174310',48,'6 温泉浴池','泡进青石板砌成的温泉水池，就在身体的酸涩渐渐缓解的时候，寤寐中，看着自己那已无任何思考能力的灵魂，随着水蒙蒙的热气从石窗口飘到屋外林荫斑斓的晨光里，魂飞魄散，一笔勾销……','12633-12718',NULL,1585633466,1782398694);
INSERT INTO highlights VALUES('26174310_48_9997-10016','26174310',48,'6 温泉浴池','那不是快乐，而是一种很结实的空虚之感。','9997-10016',NULL,1585632948,1782398694);
