INSERT INTO highlights VALUES('26174310_47_3567-3783','26174310',47,'5 进去吧','快到家的时候，J的心情竟然酸酸地紧张了起来，好像正在跟踪一个邻家女孩的感觉。他沿着大楼外墙底下的排水沟向前推进，到了公寓大门口的那一排正面之前，他倚在墙角，慢慢探出龟缩的脑袋……班长老和路长老的脚踏车已经不在了。小黄走过来了，它发现了J鬼鬼祟祟的模样，就拖着肥重的身躯迎上来，粗短的一小截尾巴怀疑地游到左，又游到右。','3567-3783',NULL,1585629935,1782398694);
INSERT INTO highlights VALUES('26174310_44_2582-2604','26174310',44,'2 给他一包苏打饼干','我被关了四十多年了……”母亲的声音还颤抖的。','2582-2604',NULL,1585626267,1782398694);
INSERT INTO highlights VALUES('26174310_43_2325-2367','26174310',43,'壹','世事难料不是吗？当J的父亲发现他的拼图少了一块时，同时也察觉到家里竟然多出了一个人。','2325-2367',NULL,1585625320,1782398694);
INSERT INTO highlights VALUES('26174310_43_1580-1661','26174310',43,'壹','父亲像一座恼羞成怒的石像压在对面的椅子上，J可以听到椅子的关节发出矿层崩裂前互相倾轧推撞的声音，那声音无情极了，好像一只红头发的狒狒在盛怒之下突然磨断了一排牙齿。','1580-1661',NULL,1585625253,1782398694);
