INSERT INTO highlights VALUES('26174310_37_2581-2638','26174310',37,'贰','可以承认自己的才情浅薄，却不必责怪无聊的世界逼人太甚。铁和血不一定就能让人心更加深刻，一如无聊不必然使人感到悠闲。','2581-2638',NULL,1585623602,1782398694);
INSERT INTO highlights VALUES('26174310_37_2466-2581','26174310',37,'贰','先人流血流汗开创了几十年的太平日子，让我们置身于一个非常难得的处境：穷极无聊。当然，我们憎恨无聊，因为无聊使得写作难上加难，仿佛在大片白茫茫的雪地里寻觅一只神出鬼没的银狐。但我们不必小看无聊，无聊如此壮大，它的疆土必定不小；我们尽','2466-2581',NULL,1585623593,1782398694);
