INSERT INTO highlights VALUES('26174310_27_2281-2360','26174310',27,'瑞蒙·卡佛的吸尘器','两个同样只有一线希望的人还互相打消了对方仅存的一丝期待，就像那台笨拙却精密的怪物吸尘器，把一间原本就困窘、空荡荡的屋子吸得一尘不染、一滴不剩，只留下一片死寂。','2281-2360',NULL,1585578159,1782398694);
