INSERT INTO highlights VALUES('26174310_25_1248-1322','26174310',25,'海明威的红笔','海明威的写作一向得力于他著名的“冰山理论”:“水底下的部分占整座冰山的八分之七，凡是你知道的东西都能删去；删去的是水底的部分，适足以强化你的冰山。”','1248-1322',NULL,1585575139,1782398694);
