INSERT INTO highlights VALUES('26174310_23_1850-1915','26174310',23,'姜德的针头','姜德的叙事口吻很冷漠，就像一个面无表情的护士，虽然你不喜欢他用尖利的针头扎进你的肉里，但事后，你仍然会忍不住赞美他的快、狠而且准。','1850-1915',NULL,1585574732,1782398694);
