INSERT INTO highlights VALUES('26174310_23_579-624','26174310',23,'姜德的针头','有的短篇小说就像一根针头，它生来就无法令人感到一丝丝愉快，却具全了一根针头应有的美好品德。','579-624',NULL,1585574480,1782398694);
INSERT INTO highlights VALUES('26174310_20_2660-2699','26174310',20,'邮票','现在回想起来，真有点不愿相信，一个人要从一个地方到另一个地方，就是这么地简单。','2660-2699',NULL,1585563484,1782398694);
INSERT INTO highlights VALUES('26174310_20_669-708','26174310',20,'邮票','她把脸颊吹得鼓鼓的，像癞蛤蟆一样，多出来的两条猪尾巴辫子，货郎鼓似的甩来甩去。','669-708',NULL,1585563295,1782398694);
INSERT INTO highlights VALUES('26174310_18_10492-10535','26174310',18,'夏天的回声','鳖血兑了米酒，老乌龟用食指搅和搅和，咕噜一口，咬牙切齿的，脖子上的筋也极过瘾地浮上来。','10492-10535',NULL,1585549876,1782398694);
INSERT INTO highlights VALUES('26174310_17_424-454','26174310',17,'窗','老画家觉得自己过不了今天了，于是他推开窗子，好让灵魂飞出去。','424-454',NULL,1585545288,1782398694);
INSERT INTO highlights VALUES('26174310_16_11880-11932','26174310',16,'除夕','见地面上有个被路灯照得发亮的一块钱硬币，便喜滋滋地捞进手心，然后才仰头接着对妇人说，“两粒要七十九块咧！','11880-11932',NULL,1585490022,1782398694);
INSERT INTO highlights VALUES('26174310_16_7991-8016','26174310',16,'除夕','好把自己心头痒痒的那铺了一层炭灰的星星之火给扇上来','7991-8016',NULL,1585489416,1782398694);
INSERT INTO highlights VALUES('26174310_16_7162-7249','26174310',16,'除夕','只见有的用手指和拇指细细捏紧烟屁股吸着，也有半合眼木着表情忽地却心绪激昂而猛吸一口的。自然更多的是嚼着槟榔的准消费者，他们碾着牙床，望着同一个方向，像一群正要分解尸块的野狼。','7162-7249',NULL,1585489187,1782398694);
INSERT INTO highlights VALUES('26174310_15_1988-2035','26174310',15,'一件急事','轻轻走到父亲背后，伸出右手，用食指勾动他的裤袋。他回过头来，布满血丝的眼睛过了许久才眨动一下。','1988-2035',NULL,1585471843,1782398694);
INSERT INTO highlights VALUES('26174310_14_5414-5445','26174310',14,'进城的一天','他听见的最后半句是：“看不往死里打，了不起也还是个残废的……”','5414-5445',NULL,1585471269,1782398694);
INSERT INTO highlights VALUES('26174310_14_3174-3206','26174310',14,'进城的一天','小癞痢走在他身旁，逢到踩过水洼子的时候，身上便被溅了特多的淤泥。','3174-3206',NULL,1585470690,1782398694);
INSERT INTO highlights VALUES('26174310_14_1910-1936','26174310',14,'进城的一天','船夫老头儿啄着一杆白铜锅旱烟，踞在岸边一块大青石上，','1910-1936',NULL,1585470506,1782398694);
INSERT INTO highlights VALUES('26174310_11_698-725','26174310',11,'牛奶和秋千','当一个人站在高处的时候，他的责任只是轻轻往下一滑而已。','698-725',NULL,1585464800,1782398694);
INSERT INTO highlights VALUES('26174310_11_479-527','26174310',11,'牛奶和秋千','当我看着别的同学把粉黄色的果汁牛奶一口喝光的时候，我感到我心中的一个角落也被他们吞进肚子里去了。','479-527',NULL,1585464775,1782398694);
INSERT INTO highlights VALUES('26174310_11_584-626','26174310',11,'牛奶和秋千','当我最接近天空的时刻，心中产生了一个奇怪的想法：我想让老天看清楚我这可怜兮兮的样子。','584-626',NULL,1585464762,1782398694);
INSERT INTO highlights VALUES('26174310_10_3677-3730','26174310',10,'尸布','看着他倒头便沉沉睡去，我感到无比的孤寂。我没这命啊！学了半天还裹不好一双腿。月光下，我的浴巾还很新、很白。','3677-3730',NULL,1585464612,1782398694);
INSERT INTO highlights VALUES('26174310_10_1309-1347','26174310',10,'尸布','我看倒不如说是鲁智深的堂兄弟。外形，像；年龄，仿佛；举止，不远；酒量，一样。','1309-1347',NULL,1585464223,1782398694);
INSERT INTO highlights VALUES('26174310_9_3632-3662','26174310',9,'差不多先生别传','可是没想到阳间和他们差不多的人愈来愈多，桌上的生死簿愈堆愈厚','3632-3662',NULL,1585463955,1782398694);
INSERT INTO highlights VALUES('26174310_9_3548-3586','26174310',9,'差不多先生别传','于是决定把这两兄弟留在身边，与牛头马面并列在侧，专门管理和他们差不多的死鬼。','3548-3586',NULL,1585463774,1782398694);
INSERT INTO highlights VALUES('26174310_9_2847-2892','26174310',9,'差不多先生别传','因为这对双胞胎兄弟愈来愈相像，有时连别人也分不清，于是，渐渐地，大家就一律叫他们差不多了。','2847-2892',NULL,1585463660,1782398694);
