INSERT INTO highlights VALUES('26607363_94_425-441','26607363',94,'兴趣与钱','为工作而生活，不要为生活而工作。','425-441',NULL,1584713967,1782398699);
INSERT INTO highlights VALUES('26607363_94_788-850','26607363',94,'兴趣与钱','做你爱做的事，或者爱你所做的事，让你的“兴趣”为你赚钱，你不必整天为了生活的手段劳心劳力，等精疲力竭之后，才去想生活的目的。','788-850',NULL,1584713956,1782398699);
INSERT INTO highlights VALUES('26607363_93_914-1050','26607363',93,'好不好？','第一，当你说“好”以前，必须先要慎思之、明辨之。第二，在你未能确定“好”或“不好”之前，可以坦白地说暂时不能回答。第三，练习沉默。当然对十分尖锐的问题除外。','914-1050',NULL,1584713772,1782398699);
