INSERT INTO highlights VALUES('26607363_83_1033-1052','26607363',83,'出乎自然','能够把美德化为生活习惯的人，值得羡慕。','1033-1052',NULL,1584712547,1782398699);
INSERT INTO highlights VALUES('26607363_82_831-954','26607363',82,'劳者多能','人接受事的磨炼，要注意采取适宜的角度。——让我们把角度改成“态度”吧，谁的态度是积极的，社会经验就对谁发生积极的作用；谁永远保持生命的热情，社会经验就是谁的燃料；谁始终为他的理想奋斗，社会经验就会提供谁更有效的方法。那么，磨来磨去，仍是一把快刀。','831-954',NULL,1584712418,1782398699);
