INSERT INTO highlights VALUES('26607363_74_841-906','26607363',74,'取法乎上','当然客厅的长沙发上也可以睡觉，不过那应该是第二志愿。对失学的人，社会当然要给他路走，不过那条路可不是留着引诱在学青年荒废光阴用的。','841-906',NULL,1584711385,1782398699);
