INSERT INTO highlights VALUES('26607363_62_778-876','26607363',62,'求才广告','“征求女性一位，能烹调、缝纫、护理、补习功课，早起晚睡，推干就湿。永远忍耐，忘记自己，每日工作至少十八小时，必要时二十四小时不眠不休，每周工作七日，无娱乐，无薪水，终身不得辞职，必要时牺牲性命。”','778-876',NULL,1584705730,1782398699);
