INSERT INTO highlights VALUES('3300056625_112_864-1018','3300056625',112,'春天','的确是这样，我时常万念俱灰。也时常死灰复燃生活给了我多少积雪我就能遇到多少个春天','864-1018',1,1719132878,1782398567);
INSERT INTO highlights VALUES('3300056625_110_437-717','3300056625',110,'寂静','关上窗这一刻的寂静让人心动像流水里躲进一块石头内部的鱼推开窗城市的喧嚣水流一样涌进来到处都在咕嘟咕嘟冒泡','437-717',1,1719132741,1782398567);
INSERT INTO highlights VALUES('3300056625_109_440-1171','3300056625',109,'竹子或扁担','竹子的骨气是因为，心是空的一个了无牵挂的人很容易活出一身正气而扁担则不同作为竹子的一部分需要承担生活的压力一路吱吱扭扭全是琐碎的唠叨和叮嘱不是我矫情总想起过世多年的母亲曾经的孤儿一身正气的铁姑娘后来因为挑着我们被生活劈成三片四片的样子','440-1171',1,1719132672,1782398567);
INSERT INTO highlights VALUES('3300056625_101_396-400','3300056625',101,'当我老了','当我老了','396-400',1,1719131945,1782398567);
INSERT INTO highlights VALUES('3300056625_93_936-1039','3300056625',93,'石台上的老人','让他擦去我满身锈迹让我像一把闪光的铁锹插在新鲜的春泥里','936-1039',1,1719130900,1782398567);
INSERT INTO highlights VALUES('3300056625_88_973-1166','3300056625',88,'一片野芦苇','春天是岁月的加速度一片野芦苇却让我慢下来慢到须发皆白像一个雪人等待季节的确认和融化','973-1166',1,1719130502,1782398567);
INSERT INTO highlights VALUES('3300056625_86_852-1295','3300056625',86,'拾柴记','那年冬天，我接受着一棵树的馈赠和树林一起保守着一棵树的死讯直到开春林管员砍走了那棵树我在那棵树的树墩上哭了一场傍晚，我蹲在墙角看着母亲把最后几根树枝塞进灶膛看着它用火苗忽明忽暗地映照着母亲仿佛晃动的树荫','852-1295',1,1719130272,1782398567);
INSERT INTO highlights VALUES('3300056625_83_1039-1107','3300056625',83,'床前明月光','原来所有的想念都是有重量的从前压弯着一个人，现在压弯另一个人','1039-1107',1,1719130067,1782398567);
INSERT INTO highlights VALUES('3300056625_76_2052-2363','3300056625',76,'麦子熟了','其实，我的余生里始终有一片麦地一直金黄，如漫无边际的黄沙父亲曾用一生的时间在沙里淘金最后只淘了一捧黄土当我把白晃晃的馒头供奉给父亲才发现覆盖父亲的坟只是一个巨大的窝头','2052-2363',1,1719129560,1782398567);
INSERT INTO highlights VALUES('3300056625_76_1171-1382','3300056625',76,'麦子熟了','几十年，父母在麦口里拔芽拔掉自己的黑发换成白发拔掉自己的青年换老年我曾那么惬意地躺在麦子的舌头上以为温柔才是柔软的故乡','1171-1382',1,1719129529,1782398567);
INSERT INTO highlights VALUES('3300056625_75_441-820','3300056625',75,'火车穿过村庄','一列火车从远处赶来又向远方奔去像一位慌张的母亲打着手电，叫喊了一声许多年以后我在阳台小声应答日子仍像一列绿皮火车在深夜过去了一节，还有一节','441-820',1,1719129394,1782398567);
INSERT INTO highlights VALUES('3300056625_71_1023-1127','3300056625',71,'最后一头耕牛','每当黎明现出霞光我都会看见两行潮湿的蹄印和一次含泪的回眸','1023-1127',1,1719128849,1782398567);
INSERT INTO highlights VALUES('3300056625_71_441-674','3300056625',71,'最后一头耕牛','最后一头水牛被从池塘牵出时正值壮年一对弯角轻易就把太阳从地平线里挑出顺便把天空划出伤口','441-674',1,1719128711,1782398567);
INSERT INTO highlights VALUES('3300056625_70_445-587','3300056625',70,'初冬还不是返乡的季节','初冬，多么美好一切枯萎都恰到好处树木瘦去叶子河流瘦去抒情','445-587',1,1719128635,1782398567);
INSERT INTO highlights VALUES('3300056625_70_1087-1192','3300056625',70,'初冬还不是返乡的季节','初冬，不适合想念落日轻勾手指，把影子拉长几粒鸟鸣，压低异乡','1087-1192',1,1719128624,1782398567);
INSERT INTO highlights VALUES('3300056625_69_992-1221','3300056625',69,'路','我闭着眼睛心里还是害怕我缩回手怕把战栗传导给他让他误以为我很冷熄灭他内心的光明','992-1221',1,1719128489,1782398567);
INSERT INTO highlights VALUES('3300056625_60_757-949','3300056625',60,'钢性','看来，我远不如一颗钉子在过去几十年的时光里我也四处碰壁然而至今我仍是一个漂泊的人','757-949',1,1719127928,1782398567);
INSERT INTO highlights VALUES('3300056625_59_442-633','3300056625',59,'想念是一种幸福','想念是把叠好的衣服一件一件放满衣橱怀念是把衣服挂满房间而衣橱是空的','442-633',1,1719127620,1782398567);
INSERT INTO highlights VALUES('3300056625_56_891-948','3300056625',56,'素日','一个人的爱被拒绝却依然保持着明亮不容易','891-948',1,1719127074,1782398567);
INSERT INTO highlights VALUES('3300056625_55_439-585','3300056625',55,'站着打盹','在我身边等餐的兄弟斜靠着墙正在从世界上退出还是正在拥有全部的世界','439-585',1,1719126908,1782398567);
INSERT INTO highlights VALUES('3300056625_54_542-657','3300056625',54,'再明亮的月光也是夜晚','我看见月亮从天上跑下来伏在父亲的右肩，跟随父亲回家月亮安静得很，像个熟睡的孩子','542-657',1,1719126865,1782398567);
INSERT INTO highlights VALUES('3300056625_52_544-603','3300056625',52,'和留守老人攀谈一会儿','一个木匠，儿女们都像完工的家具被租给了南方','544-603',1,1719126697,1782398567);
INSERT INTO highlights VALUES('3300056625_49_854-917','3300056625',49,'刻章','把我摁在一群密密麻麻的人群中间他说你看，这个就是你','854-917',1,1719126573,1782398567);
INSERT INTO highlights VALUES('3300056625_48_1135-1283','3300056625',48,'陶罐','那时候所有的铁都在人们的体内每个人都铁骨铮铮地过着，经不起磕碰的日子','1135-1283',1,1719126377,1782398567);
INSERT INTO highlights VALUES('3300056625_47_887-1120','3300056625',47,'指纹锁','从未想过与生俱来的纹路会形成一把锁锁住一个人的一生可我也无法保证每次回来的我都完整无损','887-1120',1,1719126028,1782398567);
INSERT INTO highlights VALUES('3300056625_45_437-488','3300056625',45,'转向','道路荡漾着车灯车灯荡漾着夜','437-488',1,1719125914,1782398567);
INSERT INTO highlights VALUES('3300056625_42_710-996','3300056625',42,'旱情','我可以叫她大婶子四嫂子、二大娘也可以叫她三麦家的她们都有白得发苦的头发像晴空中的白云都有一嗓子嘹亮的哭腔像胡同里的风','710-996',1,1719109268,1782398567);
INSERT INTO highlights VALUES('3300056625_39_868-1116','3300056625',39,'春天','这个七单全超的年轻人现在坐在地下道的出口处抽烟像一根木头想把自己点燃但他潮湿的眼睛让他富含水分所以只能发出滋滋的声音','868-1116',1,1719109151,1782398567);
INSERT INTO highlights VALUES('3300056625_38_852-994','3300056625',38,'时间的水分','还有的人一出生就能将另一个人一生的奋斗拧成一条奔腾的河流','852-994',1,1719108964,1782398567);
INSERT INTO highlights VALUES('3300056625_35_437-1134','3300056625',35,'春光','我可不可以这样理解太阳不制造光而是所有的光创造了太阳所有追逐着光的事物都是艰苦的都要经过黑夜漫长的煎熬枝条默默返青草地默默吐绿这些默默的事物在黑暗里摸索默默构成了一个盛大的春天我可不可以这样认为是花朵成就了春天而不是春天催开了花朵','437-1134',1,1719108828,1782398567);
INSERT INTO highlights VALUES('3300056625_32_437-793','3300056625',32,'靠山','那时我虽小父亲要想举起我就要向上天做出投降的动作放下我又要给大地鞠躬致歉为了我父亲一直在天地之间卑躬屈膝','437-793',1,1719108636,1782398567);
INSERT INTO highlights VALUES('3300056625_31_1019-1214','3300056625',31,'无用之用','每次经过我都无法抵御内心对这些密集断头后的恐惧无法抵御对失去头颅仍要保持站立不倒的恐惧','1019-1214',1,1719108546,1782398567);
INSERT INTO highlights VALUES('3300056625_30_396-900','3300056625',30,'我是虚无的','我是虚无的我总感觉自己是虚无的一些事物常常把我冲散像一团浓烟每次重新聚拢都会少去一部分我还遇到很多和我一样的人我们形成一场场大雾在阳光之前等待又在阳光之中消失','396-900',1,1719108489,1782398567);
INSERT INTO highlights VALUES('3300056625_29_528-946','3300056625',29,'夜行','电瓶车灯照耀的光像一种救赎仿佛世界的开端天地那么大无尽的夜色包裹我如同泥土包裹一颗种子带给我强烈的责任感愿人间所有的黑暗都在与我对峙每一线光明都和我有关','528-946',1,1719108454,1782398567);
INSERT INTO highlights VALUES('3300056625_28_437-534','3300056625',28,'倒影','看这些柔软的水是如何将这沉重的山轻松倒吊的','437-534',1,1719108364,1782398567);
INSERT INTO highlights VALUES('3300056625_27_809-951','3300056625',27,'无题','这多像一些真理被少数人践行总有一些不被认可的路要自己去走','809-951',1,1719108329,1782398567);
INSERT INTO highlights VALUES('3300056625_26_437-873','3300056625',26,'道别','每次和母亲道别我都不再回头就像刮过树梢的风不肯回头就像拐过小桥的流水不肯回头我不能把一场离别分成多次丢给母亲不能让一棵落光叶子的树还在风中摇摆不能让一个老人在冰冷的桥头多次滑倒','437-873',1,1719108303,1782398567);
INSERT INTO highlights VALUES('3300056625_23_437-874','3300056625',23,'时光','我们总以为拥有大把的时光实际上是时光拥有大把的我们比如此刻那么多骑手聚在一起等单就像时光的手指上落满了一群叽叽喳喳的燕子等时光之手把我们握紧几十年来，朝阳一直没变有的人正值青春而我已接近迟暮','437-874',1,1719108083,1782398567);
INSERT INTO highlights VALUES('3300056625_21_663-950','3300056625',21,'灰烬万岁','生而为树没有萎靡于漫长的腐败没有用木耳或蘑菇掩盖内心的不甘和惊慌而是用轰轰烈烈地燃烧向热爱过的大地表明态度','663-950',1,1719107961,1782398567);
INSERT INTO highlights VALUES('3300056625_19_667-724','3300056625',19,'空心菜','是谁早早摘取了我的心却要我活出人间滋味','667-724',1,1719107856,1782398567);
INSERT INTO highlights VALUES('3300056625_18_886-942','3300056625',18,'春天','而我身体里的春天拒绝了一枚青果的成熟','886-942',1,1719107681,1782398567);
INSERT INTO highlights VALUES('3300056625_17_396-1050','3300056625',17,'往事','往事为何我会反复提到钉子我感觉的疼，深入骨髓动一动都有金属的质感如果回头我还要承受分离的痛那些旧时光的钉子把我钉在了今生有些注定会成为过往来世遥远。我力所能及的是把自己从现世的墙壁取下来或者挂上去。而这一切都和钉子有关','396-1050',1,1719107536,1782398567);
INSERT INTO highlights VALUES('3300056625_16_852-1278','3300056625',16,'谋杀者','我在山坡上来回行走曲里曲折的小路像一条白绫一头捆着村庄，一头被我牵着我向村庄走去小路变宽，白绫松弛我向山上攀爬白绫绷紧，小路细长村庄呼吸困难眩晕，被白绫吊着','852-1278',1,1719107468,1782398567);
INSERT INTO highlights VALUES('3300056625_16_438-586','3300056625',16,'谋杀者','我的村庄老了不再像当初那样打闹，欢笑而变得安静，落寞在阳光下昏昏欲睡','438-586',1,1719107438,1782398567);
INSERT INTO highlights VALUES('3300056625_15_782-945','3300056625',15,'天空','一只鸟飞了，也就飞了天空并不因此更加空旷一些日子飞了，也就飞了有的消失于遗忘，有的消失于无尽的怀想','782-945',1,1719107324,1782398567);
INSERT INTO highlights VALUES('3300056625_14_719-1009','3300056625',14,'我爱','我爱这周而复始的生活也爱生活里的小悲伤小欢喜，小意外如果我们老了就让我们像一对坏掉的钟表突然停在了某个时刻让这个时刻成为永恒','719-1009',1,1719106863,1782398567);
INSERT INTO highlights VALUES('3300056625_12_891-1030','3300056625',12,'写诗','所有的钉子不是死于尖锐而是在漫长的等待中被想念锈蚀','891-1030',1,1719106656,1782398567);
INSERT INTO highlights VALUES('3300056625_9_633-689','3300056625',9,'打桩','打桩机还在哐哐，哐哐，哐哐像夜的肺病','633-689',1,1707874395,1782398567);
INSERT INTO highlights VALUES('3300056625_8_777-1021','3300056625',8,'打工潮','我一直无法描述这样的场景在辽阔的大地上工厂、车间、出租房以及流水线上到处都是散落的标点符号等着被文字重新认领','777-1021',1,1707873901,1782398567);
INSERT INTO highlights VALUES('3300056625_6_437-668','3300056625',6,'失事','想让一张纸站立起来就把纸折出棱角太平整的纸只会俯首帖耳听命于笔而站立起来的纸则不同','437-668',1,1707873639,1782398567);
INSERT INTO highlights VALUES('3300056625_4_1317-1377','3300056625',4,'午夜推行人','月亮是天空的一处漏洞所以夜从来都黑得不够彻底','1317-1377',1,1707873453,1782398567);
INSERT INTO highlights VALUES('3300056625_3_1665-1738','3300056625',3,'用笔记录生活','我相信世界终究是美好的，也会呈现生活的另一面。就像一棵树的枝叶、枝条上的霜雪、叶片上的虫洞，都是一棵树所要承受的生命之重，但它从不重于生命的本身。','1665-1738',1,1707873231,1782398567);
INSERT INTO highlights VALUES('3300056625_3_434-650','3300056625',3,'用笔记录生活','又到春天了如果想念是一种植物是像迎春一样开黄色的花还是像柳枝抽嫩绿的芽？如果春风里也有刀子倒春寒是不是那个转身离开的背影？','434-650',1,1707873004,1782398567);
