INSERT INTO highlights VALUES('25506340_67_722-785','25506340',199,'后记','同时我也注意到，对自己来说真正迫切的东西，却又是语言所无法言说、记录的。而正是这些并非不说而是无法言说的秘密，让我继续活下去。','688-751',NULL,1582627099,1782398693);
INSERT INTO highlights VALUES('25506340_66_2489-2525','25506340',198,'二〇〇一年一月二十二日（周一）','如果只是拘泥于肉眼所能看到的东西的话，心就会从眼睛看不到的东西身上溜走。','2315-2351',NULL,1582626956,1782398693);
INSERT INTO highlights VALUES('25506340_63_2311-2411','25506340',195,'十月七日（周六）','从理想的层面来说，我们必须下潜至荣格所说的集体无意识的深处挖掘出可以与他人分享的语言。是不是可以说，我们不应以只强调自身的“自我”（ego）来书写，而必须以同时关注他人的“自我”（self）来创作呢？','2101-2201',NULL,1582624561,1782398693);
