INSERT INTO highlights VALUES('25506340_52_1831-1896','25506340',184,'十月十七日（周日）','对人来说，拥有梦想是多么幸福的事，哪怕梦想无法成真。武满彻生前曾说过：“坚持‘希望’，使之成为无限的确定的现实，希望将无穷无尽。”','1665-1730',NULL,1582604667,1782398693);
