INSERT INTO highlights VALUES('25506340_41_1818-1878','25506340',173,'私','作者的诗人正隐藏在这些“形式”之中。因为想要表达什么所以写诗，如果单纯从这样的视角读诗的话，就不能理解诗中的“我”（私）','1650-1710',NULL,1582555908,1782398693);
INSERT INTO highlights VALUES('25506340_40_733-795','25506340',172,'谎','认为蓝天的蓝仿佛是掩盖其背后宇宙的虚无的窗帘。而将无数的星星的存在暴露给我们的夜空，则一直坦诚地告诉我们人类生存条件的真谛。','574-636',NULL,1582548854,1782398693);
INSERT INTO highlights VALUES('25506340_39_1262-1301','25506340',171,'人','虽然还是会难以避免地掉进半途而废或虚无主义的陷阱，但我也没有因此而觉得走投无路','1099-1138',NULL,1582546865,1782398693);
