INSERT INTO highlights VALUES('25506340_28_1845-1913','25506340',160,'遵从自己的身体','只是，身体会自然地寻求充分必要的东西，会逐渐地排斥多余的东西。饮食如此，读书、获取信息也是如此。与其增加不如削减，与其多余不如稍有不足。','1678-1746',NULL,1582529930,1782398693);
INSERT INTO highlights VALUES('25506340_27_1467-1528','25506340',159,'一个人生活之辩','对于家庭的理解，且不论对错，相较于互相依赖、互相依存的家庭而言，我更倾向于认为家庭是由宽松的纽带而联系在一起的个人的集合。','1296-1348',NULL,1582528145,1782398693);
INSERT INTO highlights VALUES('25506340_26_2658-2672','25506340',158,'我的“生活方式”','我认为应该是作家的生活态度。','2484-2498',NULL,1582527740,1782398693);
INSERT INTO highlights VALUES('25506340_26_1793-1831','25506340',158,'我的“生活方式”','人们是将以自身意志选择的与大多数人不同甚至是对立的生活方式才称为生活方式吧。','1614-1652',NULL,1582527647,1782398693);
INSERT INTO highlights VALUES('25506340_25_2900-2943','25506340',157,'五十年之岁月','在这里，时代的变化与自身的衰老以一种难以分割的方式结合在一起，让人稍微变得有点儿疯狂。','2570-2612',NULL,1582527307,1782398693);
INSERT INTO highlights VALUES('25506340_24_2555-2562','25506340',156,'我的生死观','尽人事，听天命','2387-2394',NULL,1582468151,1782398693);
INSERT INTO highlights VALUES('25506340_24_667-719','25506340',156,'我的生死观','因为我们的眼睛是朝向外部的。这样的话，剩下的问题就在于如何完美地处理自己的内心与社会的准则之间的关系了。','507-559',NULL,1582467885,1782398693);
INSERT INTO highlights VALUES('25506340_23_1916-1922','25506340',155,'十吨大卡车来了','《山羊之歌》','1748-1754',NULL,1582467764,1782398693);
INSERT INTO highlights VALUES('25506340_22_1506-1562','25506340',154,'不着边际','。然而，这种敷衍也多半不是毫无益处的。因为在我们由一个敷衍向另一个敷衍演进的生命过程中，真相隐藏期间，忽隐忽现。','1346-1402',NULL,1582467400,1782398693);
INSERT INTO highlights VALUES('25506340_22_1467-1506','25506340',154,'不着边际','思考基本上是没有结论的。我们自以为的结论，不过是为了让自己安心而做出的敷衍罢了','1307-1346',NULL,1582467388,1782398693);
INSERT INTO highlights VALUES('25506340_20_3742-3803','25506340',152,'单纯的事、复杂的事','当一个人的生命被逼迫到必须寻找到另一个逃避之所的非常时刻，在自己的自由意志下选择逃向死亡，这是文明人绝对无法阻止的野性。”','3539-3599',NULL,1582466781,1782398693);
INSERT INTO highlights VALUES('25506340_19_1487-1510','25506340',151,'阿尔茨海默病母亲的来信','人啊，不管是男人女人，都必须能够一个人活下去。','1202-1227',NULL,1582458849,1782398693);
