INSERT INTO highlights VALUES('25506340_16_1831-1857','25506340',148,'遇见自我','我们就在这种对自己的心和灵魂一无所知的前提下生活着。','1673-1699',NULL,1582457321,1782398693);
INSERT INTO highlights VALUES('25506340_16_1794-1811','25506340',148,'遇见自我','或许，自己的心比他人的心更加难懂。','1636-1653',NULL,1582457314,1782398693);
INSERT INTO highlights VALUES('25506340_16_1005-1063','25506340',148,'遇见自我','与自己这样的人打交道，自己也是十分辛苦的。但是，若是有一天同自己打交道变得简单了，那首先说明你自己变成了一个无聊的人','846-904',NULL,1582454959,1782398693);
