INSERT INTO highlights VALUES('25506340_12_544-559','25506340',144,'昼寝','“昼寝”是一个多么爽快的词啊。','387-402',NULL,1582363153,1782398693);
INSERT INTO highlights VALUES('25506340_8_1470-1504','25506340',140,'没有路的路','坦克的那种旁若无人的行驶轨迹，也许就是人类利己主义心理的完美呈现吧。','1307-1341',NULL,1582361334,1782398693);
INSERT INTO highlights VALUES('25506340_8_1575-1595','25506340',140,'没有路的路','文明产物中不知附带了多少人类的暴力欲望。','1414-1434',NULL,1582361296,1782398693);
INSERT INTO highlights VALUES('25506340_8_870-888','25506340',140,'没有路的路','给人一种不被道路束缚肆意而行的感觉。','712-730',NULL,1582361201,1782398693);
INSERT INTO highlights VALUES('25506340_5_1489-1617','25506340',137,'余裕','世上既有怎么都恨不起来的恶人，也有怎么都喜欢不起来的好人。虽然表面上我们以善恶对错来判断是非曲直，但事实上我们心里清楚得很，人心这种玄之又玄的东西，可不是以一两个既定标准去衡量世间万物的。我们害怕成为某一价值观的忠实拥趸，即使这种价值观百利而无一害也不行。','1335-1464',NULL,1577632399,1782398693);
INSERT INTO highlights VALUES('25506340_5_1304-1325','25506340',137,'余裕','要想变得从容、淡然，必先获得空间上的余裕。','1150-1171',NULL,1577632282,1782398693);
INSERT INTO highlights VALUES('44346269_16_9992-10075','44346269',16,'附录A 如何发现世界一流的学校','“这是对学者智商的侮辱。教师的语言应该足够生动有趣，能够让孩子主动探身聆听每一个字，应该用智慧的火花吸引并保持他们的注意力，而不是用学小孩说话的方式来达到这一目的。”','9992-10075',NULL,1673439590,1782398628);
INSERT INTO highlights VALUES('44346269_16_8840-8981','44346269',16,'附录A 如何发现世界一流的学校','但是他们如何衡量与上述数据可体现的方面同样重要的一些无形成果？他们怎么知道学校是否在训练学生更高难度的思维方式和处理他们从未见过的难题的能力？大多数标准化的测试都无法捕获这些信息。他们怎么判断学校是否在传授学生世界上最伟大的成功故事背后的秘诀，即坚持不懈、自我控制和诚实正直的品质？','8840-8981',NULL,1673439416,1782398628);
INSERT INTO highlights VALUES('44346269_16_7861-7880','44346269',16,'附录A 如何发现世界一流的学校','“没有卓越的领导，再好的愿景也枉然。”','7861-7880',NULL,1673438835,1782398628);
INSERT INTO highlights VALUES('44346269_16_7067-7136','44346269',16,'附录A 如何发现世界一流的学校','最聪明的国家常常把教师的薪资待遇和公平公正放在首位（把更多的资源输送给最需要的学生）。在你寻找世界级的教育时要记住，人，永远比道具更重要。','7067-7136',NULL,1673438716,1782398628);
INSERT INTO highlights VALUES('44346269_16_4074-4095','44346269',16,'附录A 如何发现世界一流的学校','假如你遇到了自己不了解的事，你会怎么做？”','4074-4095',NULL,1673438329,1782398628);
INSERT INTO highlights VALUES('44346269_16_3139-3172','44346269',16,'附录A 如何发现世界一流的学校','通常，我问的前两个问题简单而直接：“你现在在做什么？”“为什么？”','3139-3172',NULL,1673438246,1782398628);
INSERT INTO highlights VALUES('44346269_16_432-487','44346269',16,'附录A 如何发现世界一流的学校','同大多数记者一样，我不想给出任何建议，而是希望通过讲述其他人的故事让读者自己得出结论。这样做，对大家都更有益。','432-487',NULL,1673436547,1782398628);
INSERT INTO highlights VALUES('44346269_14_18739-18813','44346269',14,'第10章 严格教育的力量','“可是，我真的很努力。”小女孩轻声说道。“我不是对你的努力评分，而是对考试结果进行评分。”','18739-18813',NULL,1673435363,1782398628);
INSERT INTO highlights VALUES('44346269_14_18588-18710','44346269',14,'第10章 严格教育的力量','“我妈妈想知道为什么你给我的成绩是F。”泰勒透过眼镜低头看着她，眼睛一眨不眨。“你的F不是我给的，”他说，“而是你自己得到的。”','18588-18710',NULL,1673435349,1782398628);
INSERT INTO highlights VALUES('44346269_14_16466-16527','44346269',14,'第10章 严格教育的力量','这些国家缺乏领导或运气，无法认识到经济和社会的发展是所有普通公民的智慧结晶，以及获得智慧的唯一途径就是刻苦学习、勤勉工作。','16466-16527',NULL,1673435072,1782398628);
INSERT INTO highlights VALUES('44346269_14_15817-15911','44346269',14,'第10章 严格教育的力量','不过有一件事很明确：为了给孩子提供他们应该受到的教育，我们首先要认同严格的重要性。学校存在的意义是帮助孩子学会思考，学会努力学习，以及学会如何应对失败，这是使得其他一切成为可能的核心共识。','15817-15911',NULL,1673434985,1782398628);
INSERT INTO highlights VALUES('44346269_14_15143-15200','44346269',14,'第10章 严格教育的力量','说到幸福，不得不提及联合国发布的《2012年世界幸福指数报告》，在该报告中，芬兰人的幸福指数排名第2（仅次于丹麦）','15143-15200',NULL,1673434911,1782398628);
INSERT INTO highlights VALUES('44346269_14_14321-14353','44346269',14,'第10章 严格教育的力量','韩国仓鼠转轮般的严苛教育所造成的问题就如同它所解决的问题一样多。','14321-14353',NULL,1673434834,1782398628);
INSERT INTO highlights VALUES('44346269_14_13373-13498','44346269',14,'第10章 严格教育的力量','在芬兰、韩国和波兰，几乎都存在一个共识，那就是为了获得成功，孩子们都应该学会更深入地思考。在任何情况下，这种共识的形成都源于民族危机感：要想发展经济、振兴国家，仅有美好的愿景是不行的。于是，大家逐渐对凡事应该付出艰苦努力产生了共识，并随之改变了一切。','13373-13498',NULL,1673431185,1782398628);
INSERT INTO highlights VALUES('44346269_14_13290-13344','44346269',14,'第10章 严格教育的力量','那里的人们对待学校教育更严肃，是因为教育本身就是一项值得他们严肃认真地去对待的事情，而且每个人都认同这一点。','13290-13344',NULL,1673431165,1782398628);
INSERT INTO highlights VALUES('44346269_14_7197-7241','44346269',14,'第10章 严格教育的力量','我更关心的是学生能不能胜任一份工作，而不是他们能不能顺利和自己的伙伴们一起走个过场。”[插图]','7197-7241',NULL,1673430616,1782398628);
INSERT INTO highlights VALUES('44346269_13_6932-6941','44346269',13,'第9章 年薪400万美元的老师','韩国的“双减”政策','6932-6941',NULL,1673424833,1782398628);
INSERT INTO highlights VALUES('44346269_12_19755-19794','44346269',12,'第三部分 春','惩罚绝不是管理一所学校的好办法。同时沃里宁觉得，自主权对他来说跟金钱一样重要。','19755-19794',NULL,1673423906,1782398628);
INSERT INTO highlights VALUES('44346269_12_19697-19755','44346269',12,'第三部分 春','“学校应该开始更加仔细地甄选老师，并给他们更多激励。”其中一种激励方式毫无疑问就是薪酬，另一种则是对教师行业的尊重。','19697-19755',NULL,1673423893,1782398628);
INSERT INTO highlights VALUES('44346269_12_10386-10424','44346269',12,'第三部分 春','研究者发现，青少年在15岁时树立的远大志向，往往可以预测其未来的人生发展情况','10386-10424',NULL,1673423261,1782398628);
INSERT INTO highlights VALUES('44346269_12_6260-6408','44346269',12,'第三部分 春','第一天，学生需要阅读几篇短文，对各篇短文分析论述，考试时间共计6小时。第二天，学生们需要从14个选题中选出一个题目，然后写出一篇观点独到、篇幅很长的文章，考试时间也是6小时。斯塔拉以最近考过的几个题目为例，其中一个题目为“在中东很难实现和平的原因”，她想到的另一个题目为“我写博客，因此我存在”。','6260-6408',NULL,1673422969,1782398628);
INSERT INTO highlights VALUES('44346269_11_29490-29565','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','肯定是针对师资力量。师资力量决定了一切问题的成败。我们需要优秀的师资力量——教师应该拥有扎实的学术基础，并经过严格选拔。师资领域的变革是我最想做的。”','29490-29565',NULL,1673411763,1782398628);
INSERT INTO highlights VALUES('44346269_11_29359-29410','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','每一次改革都会带来一些伤害。人们总是倾向于稳定。当你习惯了一些事情时，便会觉得什么都不发生是最好的。”','29359-29410',NULL,1673411745,1782398628);
INSERT INTO highlights VALUES('44346269_11_29309-29329','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','争议对一个改革者而言从来都是不可避免的。','29309-29329',NULL,1673411664,1782398628);
INSERT INTO highlights VALUES('44346269_11_21175-21229','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','公平性永远是最核心的价值观，以资金来推动公平性，以延迟分流的政策来保障公平性，而这又恰恰证明了体系的严格性。','21175-21229',NULL,1673404855,1782398628);
INSERT INTO highlights VALUES('44346269_11_19445-19465','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','波兰的大部分学校在学生16岁时开始分流。','19445-19465',NULL,1673404581,1782398628);
INSERT INTO highlights VALUES('44346269_11_17753-17802','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','这似乎是某种限制性效应：一旦孩子们像被贴上标签一样，被分到更低的分流层中，他们的学习就会随之懈怠。','17753-17802',NULL,1673404399,1782398628);
INSERT INTO highlights VALUES('44346269_11_17242-17328','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','但毫无疑问，同伴效应的影响力不容忽视。”这些学生一旦进了职业学校，和其他师生在一起，就难免会耳濡目染地发生一些变化。他们似乎一夜之间丧失了某些能力，也许是他们学习的内驱力。','17242-17328',NULL,1673404360,1782398628);
INSERT INTO highlights VALUES('44346269_11_15104-15136','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','自助者天助，贫困的孩子只是缺少物质享受，精神上的求索却从未迷失。','15104-15136',NULL,1673404191,1782398628);
INSERT INTO highlights VALUES('44346269_11_9256-9293','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','但是小学、初中、高中结业时，学生们都要参加规定的标准化考试，试题全国统一。','9256-9293',NULL,1673402458,1782398628);
INSERT INTO highlights VALUES('44346269_11_9102-9158','44346269',11,'第7章 波兰教育提升的秘密——延迟分流','新的方案将会只设定基本目标，将授课的细节留给学校自行斟酌决定。与此同时，政府会要求大约25%的教师重返学校进修。','9102-9158',NULL,1673402439,1782398628);
INSERT INTO highlights VALUES('44346269_10_22840-22920','44346269',10,'第6章 为什么韩国学生都拼命学习？','责任心，这种在生活中遇事敢于担当、做事勤勉踏实、办事有条有理的行为习惯，在人生每个成长阶段都至关重要。它甚至比智力水平或家庭背景更能准确地预测人们的寿命长短。[插图]','22840-22920',NULL,1673336204,1782398628);
INSERT INTO highlights VALUES('44346269_10_20249-20271','44346269',10,'第6章 为什么韩国学生都拼命学习？','性格是可塑的！事实上，性格比智商更具可塑性。','20249-20271',NULL,1673335929,1782398628);
INSERT INTO highlights VALUES('44346269_10_14941-14962','44346269',10,'第6章 为什么韩国学生都拼命学习？','事实上，是公众对学习的尊重促成了优质的教学','14941-14962',NULL,1673333412,1782398628);
INSERT INTO highlights VALUES('44346269_10_14448-14571','44346269',10,'第6章 为什么韩国学生都拼命学习？','这种在教育的重要性上所达成的社会共识，潜移默化地产生了各种各样的影响。不仅让韩国、芬兰的课程设置更系统、教学重点更突出，而且让师范院校更严谨、入学考试难度更大。即使在家里吃饭时谈到这个话题，人们也会变得严肃起来，仿佛与教育有关的一切都要严肃对待。','14448-14571',NULL,1673333380,1782398628);
INSERT INTO highlights VALUES('44346269_10_12173-12225','44346269',10,'第6章 为什么韩国学生都拼命学习？','美国华裔父母会亲自手把手训练孩子的阅读、书写和数学能力；当孩子长大后，父母会给他们更多的自主权来独立学习','12173-12225',NULL,1673333180,1782398628);
INSERT INTO highlights VALUES('44346269_10_11602-11631','44346269',10,'第6章 为什么韩国学生都拼命学习？','事实上，对孩子的热情并不影响对孩子的严格要求，反之亦然。”','11602-11631',NULL,1673333027,1782398628);
INSERT INTO highlights VALUES('44346269_10_11631-11677','44346269',10,'第6章 为什么韩国学生都拼命学习？','那些努力对孩子既温情又严厉的父母和老师，似乎更容易与孩子产生共鸣，并且赢得孩子的信任与尊重。','11631-11677',NULL,1673333009,1782398628);
INSERT INTO highlights VALUES('44346269_10_10894-10937','44346269',10,'第6章 为什么韩国学生都拼命学习？','换言之，当孩子读完一本书时，认真地针对书中内容向他提问，比单纯地祝贺他读完了书更有用。','10894-10937',NULL,1673332920,1782398628);
INSERT INTO highlights VALUES('44346269_10_10405-10470','44346269',10,'第6章 为什么韩国学生都拼命学习？','为了让表扬发挥实际作用，父母的表扬应该真实、具体，次数不宜过多。然而，过分强调自尊的文化，已经从美国家庭蔓延到了许多学校的课堂上。','10405-10470',NULL,1673332875,1782398628);
INSERT INTO highlights VALUES('44346269_10_9964-10029','44346269',10,'第6章 为什么韩国学生都拼命学习？','童年的溺爱和过度保护，可能会导致孩子成年以后，由于从未经历过挫折而不具备应有的自控力和忍耐力，而这些能力的培养比学术技能重要得多。','9964-10029',NULL,1673332839,1782398628);
INSERT INTO highlights VALUES('44346269_10_9415-9614','44346269',10,'第6章 为什么韩国学生都拼命学习？','父母自己在家时会单纯因为喜爱而阅读，那么孩子也更容易享受阅读的乐趣。[插图]这种模式广泛适用于不同国家和不同收入的家庭。孩子会知道什么是家长所珍视的东西，父母的实际行动比任何说教的作用都大。','9415-9614',NULL,1673332632,1782398628);
INSERT INTO highlights VALUES('44346269_9_24370-24383','44346269',9,'第二部分 冬','美国教育对孩子的期望很低。','24370-24383',NULL,1673331460,1782398628);
INSERT INTO highlights VALUES('44346269_9_12782-12849','44346269',9,'第二部分 冬','学校领导和老师可以自由撰写教案，在学校内部进行试验，从而找出更有效的、更有创造性的方法，因地制宜地设计出连中央机构都想不到的教学方针。','12782-12849',NULL,1673327766,1782398628);
INSERT INTO highlights VALUES('44346269_9_11556-11645','44346269',9,'第二部分 冬','芬兰人认为，认真对待教育的唯一办法就是选拔高学历的教师，从每一代年轻人中选择最优秀的那一小部分并加以严格训练。而事实上，他们也正是这样做的。几乎没有国家尝试过这么彻底的改革策略。','11556-11645',NULL,1673322173,1782398628);
INSERT INTO highlights VALUES('44346269_9_6558-6608','44346269',9,'第二部分 冬','和许多国家一样，政府更在乎是否有足够数量的教师能进行社会培训和学校教育，而往往忽视了教师的个人素质。','6558-6608',NULL,1673321775,1782398628);
INSERT INTO highlights VALUES('44346269_9_5788-5918','44346269',9,'第二部分 冬','在芬兰，所有师范院校的选拔条件都很严格，能考取师范院校、参加教师培训项目，就像在美国被医学院录取一样，是非常光荣的事。本就应该这样，从源头开始实施严格的选拔，而不是在教师上岗多年后再制定复杂的评价机制，来淘汰表现较差的人——这样做注定会挫败整个教师行业的士气。','5788-5918',NULL,1673321713,1782398628);
INSERT INTO highlights VALUES('44346269_9_5254-5597','44346269',9,'第二部分 冬','而现在，芬兰学校的师范专业对学生的选拔更加严格，其难度与麻省理工学院的选拔标准不相上下。这并不是夸大其词，无论怎样描述芬兰教师的选拔标准都不为过。在美国，每二十所教育学院才有一所设立了严格的选拔制度。[插图]有很多学院根本没有任何录取标准，换句话说，任何人都可以当孩子的老师，无论他们自己所接受的教育有多么糟糕','5254-5597',NULL,1673321674,1782398628);
INSERT INTO highlights VALUES('44346269_8_5896-5932','44346269',8,'第4章 为什么美国学生不擅长数学？','正如温斯顿·丘吉尔所说：“所谓成功，就是不断经历失败，但从不丧失热情。”','5896-5932',NULL,1673320455,1782398628);
INSERT INTO highlights VALUES('44346269_7_14315-14573','44346269',7,'第3章 韩国的隐形教育系统——校外辅导','如果没有对教育事业的狂热投入，韩国不可能在2011年度成为世界经济强国。自1962年以来，韩国GDP已经增长了400多倍，成为全球第13大经济体，其中，教育功不可没。[插图]教育就像韩国反贫困计划中的一支疫苗，它会让家庭背景对孩子人生发展的影响越来越小。[插图]','14315-14573',NULL,1673315588,1782398628);
INSERT INTO highlights VALUES('44346269_7_14813-14874','44346269',7,'第3章 韩国的隐形教育系统——校外辅导','这本是培养精英少年的极端选拔制度，结果硬生生演变为影响成年人安身立命的制度。即使创办更多的大学，公众仍然只会关注最好的大学','14813-14874',NULL,1673315566,1782398628);
INSERT INTO highlights VALUES('44346269_5_15434-15500','44346269',5,'第一部分 秋','像波兰这样的破茧成蝶型——波兰是处于上升期的国家，贫困孩子的比例与美国不相上下，但孩子们掌握的知识和技能在最近一段时间内有显著增长。','15434-15500',NULL,1673263988,1782398628);
INSERT INTO highlights VALUES('44346269_5_15368-15430','44346269',5,'第一部分 秋','像韩国这样的高压型——在韩国，因为孩子们面临的学习压力过大，在学习上用力过猛，政府甚至下达了学习宵禁令，试图缓解这一紧张局面','15368-15430',NULL,1673263906,1782398628);
INSERT INTO highlights VALUES('44346269_5_15299-15365','44346269',5,'第一部分 秋','像芬兰这样的乌托邦型——教育机制完全建立在相信孩子在没有过度竞争或没有父母过多干预的情况下，也能获得较高层次的逻辑思维能力的基础上；','15299-15365',NULL,1673263896,1782398628);
INSERT INTO highlights VALUES('44346269_5_13067-13104','44346269',5,'第一部分 秋','并不是所有孩子都必须成为工程师或律师，但是他们都需要学会如何思考，不是吗？','13067-13104',NULL,1673263598,1782398628);
INSERT INTO highlights VALUES('44346269_5_12209-12256','44346269',5,'第一部分 秋','原因在于PISA并不仅仅是针对客观事实的测试，它还考查考生是否能够根据既定事实来分析解决问题。','12209-12256',NULL,1673263532,1782398628);
INSERT INTO highlights VALUES('44346269_5_6709-6790','44346269',5,'第一部分 秋','实际上，PISA的测试结果揭示了显而易见却被视而不见的东西，那就是教育经费的大量投入并不会使孩子变得更聪明。其实，这一切都取决于老师、家长和学生如何利用这些经费。','6709-6790',NULL,1673260307,1782398628);
INSERT INTO highlights VALUES('44346269_5_6817-6840','44346269',5,'第一部分 秋','最后的成功取决于执行力，这也是最难做好的部分。','6817-6840',NULL,1673260298,1782398628);
INSERT INTO highlights VALUES('44346269_5_1234-1261','44346269',5,'第一部分 秋','人们永远无法衡量教育中很重要的那个部分——人的品质”。','1234-1261',NULL,1673259967,1782398628);
