INSERT INTO highlights VALUES('36985428_38_1234-1704','36985428',38,'第35讲 意义丛林中的向导','什么是空气？灵魂，不愿在身体内落户。什么是镜子？第二张脸，第三只眼睛。什么是岸？波涛休息的枕头。什么是诗歌？远航的船只，没有码头。什么是雨？从乌云的列车上下来的最后一位旅客。什么是笼子？满满的空。','1234-1704',NULL,1673776576,1782398626);
INSERT INTO highlights VALUES('36985428_38_492-538','36985428',38,'第35讲 意义丛林中的向导','阿多尼斯。他是阿拉伯世界的大诗人和思想家，他的诗集《我的孤独是一座花园》，是薛庆国教授翻译的','492-538',NULL,1673776358,1782398626);
INSERT INTO highlights VALUES('36985428_37_716-978','36985428',37,'第34讲 嘎吱响的门','嘎吱响的门它想去哪里？它想回家去所以嘎吱响。可它就在家！但它想进屋。成为一张桌成为一张床。','716-978',NULL,1673776225,1782398626);
INSERT INTO highlights VALUES('36985428_37_479-504','36985428',37,'第34讲 嘎吱响的门','以色列有一位我很佩服的大诗人，他叫耶胡达·阿米亥。','479-504',NULL,1673776216,1782398626);
INSERT INTO highlights VALUES('36985428_36_2094-2144','36985428',36,'第33讲 在路的中央','看上去，它什么也没写；但细细品味，你又觉得写了很多东西。这就是这首诗的奇妙，它说出了好像没说的东西。','2094-2144',NULL,1673775106,1782398626);
INSERT INTO highlights VALUES('36985428_36_1012-1422','36985428',36,'第33讲 在路的中央','在路的中央有一块石头有一块石头在路的中央有一块石头在路的中央有一块石头我的生活单调得令人生厌但我永远不会忘记这件事情我不会忘记在路的中央有一块石头有一块石头在路的中央在路的中央有一块石头（孙成敖 译）','1012-1422',NULL,1673775046,1782398626);
INSERT INTO highlights VALUES('36985428_36_490-499','36985428',36,'第33讲 在路的中央','巴西诗人安德拉德，','490-499',NULL,1673774967,1782398626);
INSERT INTO highlights VALUES('36985428_35_1770-1811','36985428',35,'第32讲 神秘，在最平凡的事物中','《神秘》的诗。奥克塔维奥·帕斯','1770-1811',NULL,1673774764,1782398626);
INSERT INTO highlights VALUES('36985428_35_1586-1638','36985428',35,'第32讲 神秘，在最平凡的事物中','神秘就潜伏在这些看上去不神秘的事物里。我们写诗，就是要把那神秘的部分发掘出来，用神秘的语言把它表达出来。','1586-1638',NULL,1673774711,1782398626);
INSERT INTO highlights VALUES('36985428_34_575-675','36985428',34,'第31讲 要造就一片草原','21岁时，狄金森第一次跟爸爸去华盛顿，在费城遇到了英国大诗人华兹华斯，她深深地爱上了华兹华斯。但当时华兹华斯已经结婚了，狄金森的这份爱注定是无望的。回到家里，她再也不愿出门了，从此闭门谢客，终生未嫁。','575-675',NULL,1673774365,1782398626);
INSERT INTO highlights VALUES('36985428_34_492-519','36985428',34,'第31讲 要造就一片草原','艾米莉·狄金森这位女诗人。她可是美国数一数二的大诗人。','492-519',NULL,1673774116,1782398626);
