INSERT INTO highlights VALUES('36985428_32_581-687','36985428',32,'第29讲 闪电般的联想','人们是怎么评价庞德的呢？他是美国诗人、文学评论家、意象派诗歌运动的重要代表人物，和艾略特同为后期象征主义诗歌的领军人物。他从中国古典诗歌、日本俳句中生发出“诗歌意象”的理论，为东西方诗歌的互相借鉴做出了卓越贡献。','581-687',NULL,1673772779,1782398626);
INSERT INTO highlights VALUES('36985428_31_987-1005','36985428',31,'第28讲 歌唱你自己','惠特曼一生只写了一部诗集《草叶集》。','987-1005',NULL,1673766899,1782398626);
