INSERT INTO highlights VALUES('36985428_28_1091-1735','36985428',28,'第25讲 怎么“自我介绍”呢？','我是一位矮个子的秃老头在半个多世纪之间与名词、动词、助词、形容词和问号等一起磨炼语言生活到了今天说起来我还是喜欢沉默我喜欢各种各样的工具也喜欢树木和灌木丛可是，我并不善于记住它们的名称我对过去的日子不感兴趣对权威持有反感我有着一双既斜视又有乱视的老花眼家里虽没摆有佛龛和神龛却有连接室内巨大的信箱对于我，睡眠是一种快乐梦即使破了，醒来时也会全忘光（田原 译）','1091-1735',NULL,1673761272,1782398626);
INSERT INTO highlights VALUES('36985428_27_1918-2342','36985428',27,'第24讲 “再见”是为了再次遇见','下船的孩子对大海说，上船的孩子对陆地说。船儿对栈桥说，栈桥对船儿说。钟声对大钟说，炊烟对小镇说。小镇对白天说，夕阳对天空说。我也说吧，说再见吧。对今天的我，说再见吧。','1918-2342',NULL,1673760971,1782398626);
INSERT INTO highlights VALUES('36985428_27_2629-2652','36985428',27,'第24讲 “再见”是为了再次遇见','写诗，就是要用最少的语言写出最多的感觉和感情。','2629-2652',NULL,1673760862,1782398626);
INSERT INTO highlights VALUES('36985428_27_1528-1828','36985428',27,'第24讲 “再见”是为了再次遇见','上层的雪很冷吧，冰冷的月亮照着它。下层的雪很重吧，上百的人压着它。中间的雪很孤单吧，看不见天也看不见地。','1528-1828',NULL,1673760787,1782398626);
INSERT INTO highlights VALUES('36985428_27_1125-1153','36985428',27,'第24讲 “再见”是为了再次遇见','金子美铃1903年出生，1930年就死了，她才活了27岁','1125-1153',NULL,1673760741,1782398626);
INSERT INTO highlights VALUES('36985428_26_633-673','36985428',26,'第23讲 略论口味不同','马雅可夫斯基出生在格鲁吉亚的一个村子里。1906年，马雅可夫斯基全家搬到了莫斯科','633-673',NULL,1673757224,1782398626);
INSERT INTO highlights VALUES('36985428_24_1543-1903','36985428',24,'第21讲 你不快乐的每一天都不是你的','你不快乐的每一天都不是你的：你只是虚度了它。无论你怎么活，只要不快乐，你就没有生活过。夕阳倒映在水塘，假如足以令你愉悦，那么爱情，美酒，或者欢笑便也无足轻重。幸福的人，是他从微小的事物中汲取到快乐，每一天都不拒绝自然的馈赠！','1543-1903',NULL,1673755914,1782398626);
INSERT INTO highlights VALUES('36985428_24_1217-1238','36985428',24,'第21讲 你不快乐的每一天都不是你的','佩索阿，他是葡萄牙语世界最伟大的现代诗人。','1217-1238',NULL,1673755892,1782398626);
INSERT INTO highlights VALUES('36985428_23_547-611','36985428',23,'第20讲 哑孩子','洛尔迦，1898年6月5日出生，1936年8月18日去世。全世界爱进步、爱诗的人都记得他。他被认为是20世纪最伟大的西班牙诗人。','547-611',NULL,1673704212,1782398626);
INSERT INTO highlights VALUES('36985428_22_2684-3148','36985428',22,'第19讲 没有假如，就没有诗','假如蜜蜂没有近视小鹿（9岁）假如蜜蜂没有近视它就不会看不清前方的路一头撞到了巨人山它拎着的那个小桶也不会打翻花蜜也不会洒在我的鼻子上可假如真的这样我又怎么能闻到鼻尖上空气里微醉的甜香','2684-3148',NULL,1673703902,1782398626);
INSERT INTO highlights VALUES('36985428_21_1591-1801','36985428',21,'第18讲 我偏爱写诗的荒谬','当我说“未来”这个词，第一音方出即成过去。当我说“寂静”这个词，我打破了它。当我说“无”这个词，我在无中生有。','1591-1801',NULL,1673703328,1782398626);
INSERT INTO highlights VALUES('36985428_21_758-808','36985428',21,'第18讲 我偏爱写诗的荒谬','1996年她获得了诺贝尔文学奖。纯洁性，就是说她写得干净透明；力量，就是说她有非凡的想象力和创造力。','758-808',NULL,1673703130,1782398626);
INSERT INTO highlights VALUES('36985428_21_498-507','36985428',21,'第18讲 我偏爱写诗的荒谬','波兰女诗人辛波斯卡','498-507',NULL,1673703089,1782398626);
INSERT INTO highlights VALUES('36985428_20_678-696','36985428',20,'第17讲 当你老了','在我眼里，叶芝是爱尔兰最伟大的诗人。','678-696',NULL,1673702773,1782398626);
INSERT INTO highlights VALUES('36985428_19_1037-1344','36985428',19,'第16讲 火车的想象','火车用它们那认真的车轮勤勉地将绿色的（或者灰色的或者白色的）风景缝在一起如同一架缝纫机敏捷地在布料上行走（马文韬 译）','1037-1344',NULL,1673702397,1782398626);
INSERT INTO highlights VALUES('36985428_18_489-498','36985428',18,'第15讲 蚂蚁和蝉','法国诗人雷蒙·格诺','489-498',NULL,1673702043,1782398626);
INSERT INTO highlights VALUES('36985428_17_3322-3359','36985428',17,'第14讲 通灵者兰波','我们无时无刻不生活在感觉里，你不妨试着去抓住任何一个感觉，把它写成一首诗。','3322-3359',NULL,1673701465,1782398626);
INSERT INTO highlights VALUES('36985428_16_2072-2098','36985428',16,'第13讲 活在珍贵的人间','天才常常是缺乏耐心的。没有一个天才，有耐心平庸地活着','2072-2098',NULL,1673700509,1782398626);
INSERT INTO highlights VALUES('36985428_16_641-1098','36985428',16,'第13讲 活在珍贵的人间','活在这珍贵的人间太阳强烈水波温柔一层层白云覆盖着我踩在青草上感到自己是彻底干净的黑土块活在这珍贵的人间泥土高溅扑打面颊活在这珍贵的人间人类和植物一样幸福爱情和雨水一样幸福','641-1098',NULL,1673700207,1782398626);
INSERT INTO highlights VALUES('36985428_15_2671-2702','36985428',15,'第12讲 “一切”的力量','在一首诗中，把互相矛盾的东西放到一起，可以产生一种强烈的力量。','2671-2702',NULL,1673700060,1782398626);
INSERT INTO highlights VALUES('36985428_15_1099-1626','36985428',15,'第12讲 “一切”的力量','一切都是命运一切都是烟云一切都是没有结局的开始一切都是稍纵即逝的追寻一切欢乐都没有微笑一切苦难都没有泪痕一切语言都是重复一切交往都是初逢一切爱情都在心里一切往事都在梦中一切希望都带着注释一切信仰都带着呻吟一切爆发都有片刻的宁静一切死亡都有冗长的回声','1099-1626',NULL,1673700048,1782398626);
INSERT INTO highlights VALUES('36985428_13_844-1271','36985428',13,'第10讲 夜色似乎明亮了一下','傍晚，吃饭了我出去喊仍在林子里散步的老父亲夜色正一点一点地渗透黑暗如墨汁在宣纸上蔓延我每喊一声，夜色就被推开推远一点点喊声一停，夜色又聚集围拢了过来我喊父亲的声音在林子里久久回响又在风中如波纹般荡漾开来父亲的答应声使夜色似乎明亮了一下','844-1271',NULL,1673689454,1782398626);
INSERT INTO highlights VALUES('36985428_11_1167-1656','36985428',11,'第8讲 雪把冬天翻译成春天','我是雪我被太阳翻译成水我是水我把种子翻译成植物我是植物，我把花朵翻译成果实我是果实我被父母翻译成生命我是生命我被衰老翻译成死亡我是死亡我被冬季翻译成雪我是雪我被太阳翻译成水','1167-1656',NULL,1673688814,1782398626);
INSERT INTO highlights VALUES('36985428_9_1921-1957','36985428',9,'第6讲 诗人的工作','蓝蓝说：“想象力、爱和对语言的敏感，这三种人生的无价之宝，从诗歌开始。”','1921-1957',NULL,1673688072,1782398626);
INSERT INTO highlights VALUES('36985428_8_2795-2853','36985428',8,'第5讲 脑海中的骑手','一滴水不重复，怎么会变成一条小溪呢？海浪不重复，怎么会形成大海的气势呢？雨也是一滴一滴重复，才能润泽大地，浇灌庄稼。','2795-2853',NULL,1673687550,1782398626);
INSERT INTO highlights VALUES('36985428_6_2883-2913','36985428',6,'第3讲 诗藏在什么地方？','写诗，就是用你自己的句子，去写你自己的事情、自己心里的感觉。','2883-2913',NULL,1673666832,1782398626);
INSERT INTO highlights VALUES('36985428_5_3144-3266','36985428',5,'第2讲 诗是活泼泼的生命','一个静止的名字不是诗，但是它动起来、活泼起来的时候，仿佛在同你说话的时候，就是诗了。比如说，一棵树不是诗，但它在风中抖动树叶瑟瑟作响的时候，或者秋风一吹黄叶纷纷飘落的时候，这就是诗。诗就是灵动的东西、鲜活的东西，是你能感觉到它的生命存在的东西。','3144-3266',NULL,1673666570,1782398626);
INSERT INTO highlights VALUES('36985428_3_717-744','36985428',3,'前言 每个孩子天生都是诗人','也就是说，一个写诗的人，不管什么年纪，都得有一颗童心。','717-744',NULL,1673661851,1782398626);
INSERT INTO highlights VALUES('25314646_94_4196-4230','25314646',94,'种种荒谬与欢笑的可能','一扇窗减窗台，减窗框，减窗玻璃。/一个开口，不过如此，/开得大大的”','4215-4249',NULL,1581821156,1782398670);
INSERT INTO highlights VALUES('25314646_94_4059-4116','25314646',94,'种种荒谬与欢笑的可能','自然万物无需名字，无需人类为其冠上任何意义或譬喻；它们的存在是纯粹的，是自身俱足而不假外求的（《一粒沙看世界》）。','4078-4135',NULL,1581821121,1782398670);
INSERT INTO highlights VALUES('25314646_94_3766-3802','25314646',94,'种种荒谬与欢笑的可能','对辛波斯卡而言，性别并不重要；个人如何在生命中为自己定位才是她所关心的。','3785-3821',NULL,1581821052,1782398670);
INSERT INTO highlights VALUES('25314646_94_1981-2201','25314646',94,'种种荒谬与欢笑的可能','《金婚纪念日》，她道出美满婚姻的神话背后的阴影——长期妥协、包容的婚姻磨蚀了一个人的个性特质，也抹煞了珍贵的个别差异：性别模糊，神秘感渐失，差异交会成雷同，一如所有的颜色都褪成了白色。','2000-2220',NULL,1581820745,1782398670);
INSERT INTO highlights VALUES('25314646_94_1600-1641','25314646',94,'种种荒谬与欢笑的可能','《甜美的短歌》（“你走上山坡，我走过山谷。你将盛开如玫瑰，我将长成一株雪球树……”','1619-1660',NULL,1581820636,1782398670);
INSERT INTO highlights VALUES('25314646_92_515-522','25314646',92,'三个最奇怪的词','三个最奇怪的词','534-541',NULL,1581820457,1782398670);
INSERT INTO highlights VALUES('25314646_91_1603-1890','25314646',91,'植物的沉默','尽管问吧，我会尽可能说明：我的眼睛看到了什么？我的心为什么会跳动？我的身体怎么没有生根？但要如何回答没有提出的问题，尤其当答问者对你们而言是如此的微不足道？','1622-1909',NULL,1581820422,1782398670);
INSERT INTO highlights VALUES('25314646_90_2535-2622','25314646',90,'在众生中','我可能是我——但一无惊奇可言，也就是说，一个截然不同的人。','2554-2641',NULL,1581820210,1782398670);
