INSERT INTO highlights VALUES('25314646_82_554-809','25314646',82,'我们幸运极了','我们幸运极了不确知自己生活在什么样的世界。一个人将得活好长好长的时间，铁定比世界本身还要久。','573-828',NULL,1581819054,1782398670);
INSERT INTO highlights VALUES('25314646_81_552-680','25314646',81,'一见钟情','他们两人都相信是一股突发的热情让他俩交会。这样的笃定是美丽的，但变化无常更是美丽。','571-699',NULL,1581818961,1782398670);
INSERT INTO highlights VALUES('25314646_81_2338-2455','25314646',81,'一见钟情','每个开始毕竟都只是续篇，而充满情节的书本总是从一半开始看起。','2357-2474',NULL,1581818927,1782398670);
INSERT INTO highlights VALUES('25314646_77_2120-2307','25314646',77,'结束与开始','了解历史真相的人得让路给不甚了解的人。以及所知更少的人。最后是那些简直一无所知的人。','2139-2326',NULL,1581775300,1782398670);
