INSERT INTO highlights VALUES('25314646_74_2415-2716','25314646',74,'桥上的人们','他们更进一步听到了雨水的溅洒声，感觉冷冷的雨滴落在他们的颈上和背上，他们注视着桥以及桥上的人们，仿佛看到自己也在那儿，参与同样无终点的赛跑，穿越同样无止尽，跑不完的距离，并且有勇气相信这的确如此。','2434-2735',NULL,1581650674,1782398670);
