INSERT INTO highlights VALUES('25314646_65_1098-1306','25314646',65,'一粒沙看世界','窗外是美丽的湖景，但风景不会自我观赏。它存在这个世界，无色，无形，无声，无臭，又无痛。湖底其实无底，湖岸其实无岸。','1117-1325',NULL,1581648712,1782398670);
