INSERT INTO highlights VALUES('25314646_52_553-684','25314646',52,'巨大的数目','地球上住着四十亿人，但是我的想象依然如故。它和巨大的数目格格不入。它依然为个体特质所动。','572-703',NULL,1581644808,1782398670);
