INSERT INTO highlights VALUES('25314646_48_1139-1486','25314646',48,'幸福的爱情','请看看那对幸福的恋人。他们难道不能至少试着掩饰一下，看在朋友的份上假装有点难过！你听他们的笑声——真是刺耳。他们使用的语言——清楚得让人起疑。还有他们的庆典、仪式，精心安排互相配合的例行工作——这分明是在人类背后搞鬼！','1158-1505',NULL,1581560686,1782398670);
INSERT INTO highlights VALUES('25314646_48_2087-2225','25314646',48,'幸福的爱情','就让那些从未找到幸福爱情的人不断去说世上没有这种东西。这信念会让他们活得较轻松死得较无憾。','2106-2244',NULL,1581560614,1782398670);
