INSERT INTO highlights VALUES('25314646_16_1224-1512','25314646',16,'博物馆','王冠的寿命比头长。手输给了手套。右脚的鞋打败了脚。至于我，你瞧，还活着。和我的衣服的竞赛正如火如荼进行着。这家伙战斗的意志超乎想象！它多想在我离去之后继续存活','1243-1531',NULL,1581474327,1782398670);
INSERT INTO highlights VALUES('25314646_13_553-678','25314646',13,'不会发生两次','同样的事不会发生两次。因此，很遗憾的我们未经演练便出生，也将无机会排练死亡。','572-697',NULL,1581474012,1782398670);
