INSERT INTO highlights VALUES('25314646_4_2381-2451','25314646',4,'诗人与世界','大体而言，灵感不是诗人或艺术家的专属特权；现在、过去和以后，灵感总会去造访某一群人——那些自觉性选择自己的职业并且用爱和想象力去经营工作的人','2400-2470',NULL,1581471857,1782398670);
