INSERT INTO highlights VALUES('912824_71_627-717','912824',145,'致魏心宏','所有的作家分成两类，一类在解释自己，另一类在另外开拓世界。前一类作家写的一切，其实是广义的个人经历，如海明威；而后一类作家主要是凭借想象力来营造一些什么，比如卡尔维诺、尤瑟娜尔等人','716-806',NULL,1530499316,1782398732);
INSERT INTO highlights VALUES('912824_71_779-814','912824',145,'致魏心宏','一个人在一生里总要写到自己，这是必须要做的事。但是只做这一件事是不行的','868-903',NULL,1530499301,1782398732);
INSERT INTO highlights VALUES('912824_70_3463-3487','912824',144,'致艾晓明','而最美好的事物则是把一件美好的东西造出来时的体验','3664-3688',NULL,1530499163,1782398732);
