INSERT INTO highlights VALUES('912824_70_2313-2365','912824',144,'致艾晓明','在我们这里，假如谁要奉献一点可观的东西，就需要冷静而睿智，同时在内心深处彻头彻尾的疯狂。这可不那么容易。','2475-2527',NULL,1530498961,1782398732);
