INSERT INTO highlights VALUES('912824_34_493-594','912824',108,'写在五线谱上的信','银河，你好！做梦也想不到我把信写到五线谱上吧？五线谱是偶然来的，你也是偶然来的。不过我给你的信值得写在五线谱里呢。但愿我和你，是一支唱不完的歌。','578-680',NULL,1529907527,1782398732);
