INSERT INTO highlights VALUES('912824_25_1113-1187','912824',99,'目空一切的那种爱','也许有一天我会明白人需要什么，也就是撇开灰色的社会生活（倒霉的机械重复，乏味透顶的干巴巴的人的干涉），也撇开对于神圣的虔诚，人能给自己建立什么生活。','1198-1272',NULL,1529903881,1782398732);
INSERT INTO highlights VALUES('912824_22_667-739','912824',96,'我要你，和我有宿缘的人','我们这种人的归宿不是在人们已知的领域里找得到的，是吗？谁也不能使我们满意，谁也不能使我们幸福，只有自己做出非凡的努力。还有我要你，和我有宿缘的人','749-821',NULL,1529294244,1782398732);
