INSERT INTO highlights VALUES('912824_5_867-987','912824',80,'诗人之爱','那时候这条路上就走来一个虎头虎脑、傻乎乎的孩子，他长得就像我给你那张相片上的一样。后来又走过来一个又黑又瘦的少年。后来又走过来一个又高又瘦又丑的家伙，涣散得要命，出奇地喜欢幻想。后来，再过几十年，他就永远不会走上这条路了。你喜欢他的故事吗？','956-1076',NULL,1529285070,1782398732);
INSERT INTO highlights VALUES('912824_5_484-565','912824',80,'诗人之爱','我和你分别以后才明白，原来我对你爱恋的过程全是在分别中完成的。就是说，每一次见面之后，你给我的印象都使我在余下的日子里用我这愚笨的头脑里可能想到的一切称呼来呼唤你','573-654',NULL,1529284841,1782398732);
INSERT INTO highlights VALUES('912824_3_1595-1644','912824',78,'代序 爱情十问','如果你找到了一个人，但为了和他相处，必须改变自我、压抑自我，或者委屈自我，那肯定不是爱情，不会幸福','1416-1465',NULL,1529163995,1782398732);
