INSERT INTO highlights VALUES('3300020004_59_1521-1628','3300020004',59,'附：给祝羽捷的信','身为母亲，我必须整理过滤，和主流社会秩序良性对接，把健康平稳的一面给孩子做安心的基石，而我个人，也是写作者必备的人格锐角、边缘化及微量毒素，一直是在被压制状态。但实际上，过于和谐无扰、一味求安的内心，是会走向沉滞的','1521-1628',NULL,1673619089,1782398627);
INSERT INTO highlights VALUES('3300020004_58_2798-2959','3300020004',58,'我们不善告别','和生命一样，关系的死亡也是林林总总。有的骤然消亡，是猝死；更多的是“相去日益远”，大大小小不规则形状的外伤、内伤，退让、忍耐，一次次延医治疗，不过是绵延病程。形亡之前，早已心死。生命不仅要对他者告别，也是对旧我的告别，这种事，有人一跃而过，如蝉蜕；有人则较为困难，总是辗转中，最终明白，按下删除键，轻装过的记忆更利于出发。','2798-2959',NULL,1673618847,1782398627);
INSERT INTO highlights VALUES('3300020004_58_2752-2769','3300020004',58,'我们不善告别','乐莫乐兮新相知，悲莫悲兮生别离。”','2752-2769',NULL,1673618588,1782398627);
INSERT INTO highlights VALUES('3300020004_57_3568-3600','3300020004',57,'有些虚度，会长出翅膀','这些虚度的清晨，还有夜晚，是会“在我们身后，长出薄薄的翅膀”来的','3568-3600',NULL,1673618222,1782398627);
INSERT INTO highlights VALUES('3300020004_57_1221-1294','3300020004',57,'有些虚度，会长出翅膀','情绪和水源、新鲜空气、矿产一样是有限资源，不节制地挥洒只会让你心力交瘁，身心枯萎。我有个豆友的签名把我笑得半死，是“当我不再和笨蛋讲道理之后……”','1221-1294',NULL,1673617893,1782398627);
INSERT INTO highlights VALUES('3300020004_56_2685-2735','3300020004',56,'爱是一生成熟的果实','总有一天，你走过的路、看过的书、爱过的人，都会化为你的精神血肉，美在你的体内流通增值，最后满溢而出。','2685-2735',NULL,1673617625,1782398627);
INSERT INTO highlights VALUES('3300020004_56_1489-1576','3300020004',56,'爱是一生成熟的果实','爱人是一件比爱己更幸福的事，而且无须回报：养儿无关防老（非交换）、不需独占（非剥夺性）、你对对方尽心付出，只是为了让她羽翼丰满，最后有能力离开自己，飞得越远越好（非储藏性）。','1489-1576',NULL,1673617480,1782398627);
INSERT INTO highlights VALUES('3300020004_56_1251-1261','3300020004',56,'爱是一生成熟的果实','弗洛姆的《爱的艺术》','1251-1261',NULL,1673617454,1782398627);
INSERT INTO highlights VALUES('3300020004_56_1305-1365','3300020004',56,'爱是一生成熟的果实','“人格的发展，会经历获取性、剥夺性、储藏性的阶段，最后，人格的发展会升华为生产性。生产性的人格，意味着成熟的爱的能力。”','1305-1365',NULL,1673617447,1782398627);
INSERT INTO highlights VALUES('3300020004_56_1172-1203','3300020004',56,'爱是一生成熟的果实','说到底，幸福不外乎来源于两点：自我实现和与他人建立温暖的链接。','1172-1203',NULL,1673617150,1782398627);
INSERT INTO highlights VALUES('3300020004_53_2006-2021','3300020004',53,'时间的果','虽说相见亦无事，但无事亦喜悦。','2006-2021',NULL,1673615841,1782398627);
INSERT INTO highlights VALUES('3300020004_47_1822-1873','3300020004',47,'云的名字','英国人卢克·霍华德，是一个职业药剂师、业余气象学家、虔诚的教徒，是世界上第一个给云彩用拉丁语命名的人。','1822-1873',NULL,1673613811,1782398627);
INSERT INTO highlights VALUES('3300020004_46_1127-1158','3300020004',46,'铅笔的可悔品质','然，关于铅笔的“可悔”品质，最著名的拥护者莫过于海明威老师了。','1127-1158',NULL,1673613395,1782398627);
INSERT INTO highlights VALUES('3300020004_32_2612-2680','3300020004',32,'力量、勇气与爱','勇气，并不是闪闪发光的英雄主义，勇气中也包含着怯懦，就像爱中也有不爱的时刻，这来回摇摆的踱步，斑驳的杂质，才是真相，也是它最可爱的部分。','2612-2680',NULL,1673600981,1782398627);
INSERT INTO highlights VALUES('3300020004_32_2456-2583','3300020004',32,'力量、勇气与爱','小熊鼓起勇气，坐上了红毯，纵身一跃，归来以后，小老鼠赞美小熊的勇气，又问他在天上飞是什么感觉，小熊说：“其实吧，在天上飞的时候，我吓得心惊肉跳，脑子里一片空白，我紧紧闭着眼睛，什么也没看到，也许我根本没有什么勇气。”老鼠说：“也许，这才是真正的勇气吧。”','2456-2583',NULL,1673600964,1782398627);
INSERT INTO highlights VALUES('3300020004_30_1786-1836','3300020004',30,'定于一','做一件事，心无旁骛，寄托在所做之事上，是‘一’，是‘诚’，即是‘涅槃’。‘定于一’是静，而非寂寞。”','1786-1836',NULL,1673600462,1782398627);
INSERT INTO highlights VALUES('3300020004_30_1647-1674','3300020004',30,'定于一','我喜欢低泡型思维的水晶人，“你看见什么？”“一个苹果”','1647-1674',NULL,1673600429,1782398627);
