INSERT INTO highlights VALUES('3300020004_27_2891-2986','3300020004',27,'安野光雅：云中一雁','画者的心相造就了气质——他是那么可爱的人，他有把心爱的椅子，到哪儿都带着，像身体的一部分。为了防丢，还特地买了一把备用。“这事得瞒着原来那把椅子，”他说，“我希望它相信，我可只有你一个哟。”','2891-2986',NULL,1673599613,1782398627);
