INSERT INTO highlights VALUES('3300020004_24_3113-3211','3300020004',24,'茨维塔耶娃：无手之抚，无唇之吻','茨维塔耶娃在文字和非文字层面上，是两个人，她一直用文字层面的那个自己抵御和托起非文字层面那个。最后，她无处可躲，只好躲进了死亡：“她把头伸进绳索，就像埋到了枕头里。”她说：“我不想死，我想消失。”','3113-3211',NULL,1673591686,1782398627);
INSERT INTO highlights VALUES('3300020004_23_523-582','3300020004',23,'阿莉娅：母与女','在严酷的未来，你要记住我们的往昔：我，是你的第一个诗人，你，是我最好的诗。”这是茨维塔耶娃为年幼的女儿阿莉娅写的诗句。','523-582',NULL,1673589519,1782398627);
