INSERT INTO highlights VALUES('3300020004_21_3051-3658','3300020004',21,'塞尔努达：美，及比美更多的','我用云对你说过爱，天空支起的忧郁额头，悲伤涌动；我用植物对你说过爱，透明的轻巧造物覆上突然的羞赧；我用流水对你说过爱，光亮的生命蒙上阴影的河底；我用恐惧对你说过爱，我用快乐对你说过爱，用过厌倦，用过恐怖的词语。但是这样不够：比生命更远，我想用死亡对你说爱；比爱更远我想用遗忘对你说爱。','3051-3658',NULL,1673588704,1782398627);
INSERT INTO highlights VALUES('3300020004_21_4024-4119','3300020004',21,'塞尔努达：美，及比美更多的','曼德尔斯塔姆，另外一位不合时宜的诗人，曾经将诗歌比喻为扔向大海深处的漂流瓶，把读者当成偶遇的拾荒者，对着那封瓶中信，惊喜地看见与自己灵魂的撞脸，在灵泊中暗生缱绻。而我想说：“此情，已查收。”','4024-4119',NULL,1673588620,1782398627);
INSERT INTO highlights VALUES('3300020004_21_961-1004','3300020004',21,'塞尔努达：美，及比美更多的','童年时有真皮层的敏感度，却没有表达能力。成年后能叙事了，但远程记忆模糊，情境已经脱水了','961-1004',NULL,1673587404,1782398627);
INSERT INTO highlights VALUES('3300020004_18_600-678','3300020004',18,'奈保尔：无寄','几个比较成功的游记作者：陈丹燕是靠对人事的敏感度；西西老师对建筑有造诣，理解和关注空间的能力比一般作家强；村上春树会去数乞丐碗里的钱，留心细节，成就体温感。','600-678',NULL,1673581994,1782398627);
INSERT INTO highlights VALUES('3300020004_17_1599-1691','3300020004',17,'伯格：我们在此相遇','什么是存在？什么又是不存在？如何在空无之中创造一切？只要有欲望和思念就够了。相遇，从来就不是你遇见我，而是你遇见你眼中的我。既然如此，重逢也不必是你重见我，只要你重见你眼中的我就行了。','1599-1691',NULL,1673581742,1782398627);
INSERT INTO highlights VALUES('3300020004_15_745-806','3300020004',15,'寿岳章子：温暖牌回忆录','旧时俄国文学有高远的灵魂感，日本文学则长于低矮贴地的日常细节，也就是朴素去躁的“侘寂”气质。前者是灵魂之花，后者是世俗的根','745-806',NULL,1673577230,1782398627);
