INSERT INTO highlights VALUES('3300020004_9_2711-2827','3300020004',9,'叶嘉莹：古典文心','什么叫作“弱德”呢？德有很多种，有健者之德，有弱者之德，它是一种持守。叶嘉莹说：“现在很多人都以强者为德，夫妻、朋友吵架，你凶，我比你还要凶恶，都以为自己要做一个强者才是好的，我小时候学习的不是如此。弱德是一种德，需要坚强地持守。”','2711-2827',NULL,1673516884,1782398627);
