INSERT INTO highlights VALUES('3300020004_6_836-940','3300020004',6,'莫兰迪：在有限中宁静致远','一片真正有人居住过的安静树叶，一个在最谦卑的视线中捕捉到的安静眼神，它们是广阔的进行者，这些形象使世界变大，使夏天变大，在这些时刻，诗歌散布着平静之波，广阔性被静观放大，静观的态度是一种如此重要的人性价值。”','836-940',NULL,1673493344,1782398627);
INSERT INTO highlights VALUES('3300020004_3_1140-1217','3300020004',3,'序 树状的幸福','我每天读书在十万字上下，其中能吸收营养的，有几页就不错了，有的则毫无养分，但是如果你不读，就会对某些东西有误解。它的好处是体现在“没有它时”那个层面上的。','1140-1217',NULL,1673492764,1782398627);
