INSERT INTO highlights VALUES('917268_11_913-937','917268',151,'弟弟','支教是种责任和义务，是去付出，而不仅仅是去寻找；','24543-24567',NULL,1577864049,1782398677);
INSERT INTO highlights VALUES('917268_7_4676-4752','917268',151,'弟弟','必须让你有遗憾，这样你才会重返这个世界。虽然这个世界没有那么轻松，没有那么仁慈，没有那么公平。','14528-14604',NULL,1577862879,1782398677);
INSERT INTO highlights VALUES('917268_7_4506-4545','917268',151,'弟弟','眼泪不能落在尸身上，泪会化作暴雨，哭声会变成巨雷，让她在那边那条路上走得艰难。','14390-14429',NULL,1577862768,1782398677);
INSERT INTO highlights VALUES('29165585_73_737-769','29165585',73,'为什么夏天穿毛呢衣服不好？','夏天还是穿棉织物或者麻织物的衣服好。棉和麻容易干燥，透气性更好。','737-769',NULL,1590115216,1782398668);
INSERT INTO highlights VALUES('29165585_72_706-761','29165585',72,'有没有用空气筑成的墙壁？','科学家发现，空气的墙壁甚至比砖砌的墙壁保暖的效果更好。所以现在已经开始制作空心砖。这种砖就像掏出了馅儿的馅饼。','706-761',NULL,1590115192,1782398668);
INSERT INTO highlights VALUES('29165585_71_621-686','29165585',71,'穿三件衬衣暖，还是穿一件三倍厚的衬衣暖？','关键与其说是在于衬衣，不如说是在于衬衣之间的空气。空气是一种不良导热体。衬衣之间的空气越多，保护我们身体不受冷的那空气衣服就越厚。','621-686',NULL,1590115157,1782398668);
INSERT INTO highlights VALUES('29165585_63_678-715','29165585',63,'有没有硬的液体？','沙、碱和白垩——由于炽热就熔化在一起了。结果得到熔化的像水似的液态的玻璃。','678-715',NULL,1590040079,1782398668);
INSERT INTO highlights VALUES('29165585_61_1416-1463','29165585',61,'细瓷器制造的秘密','细瓷器要烧两次：头一次只是略为烧一下，然后上釉，再重烧。第二次烧是制细瓷器的最主要的秘密所在。','1416-1463',NULL,1590036211,1782398668);
INSERT INTO highlights VALUES('29165585_60_1162-1185','29165585',60,'是谁发明细瓷器的？','最先会烧细瓷器的是中国人，那是在一千七百年以前','1162-1185',NULL,1590035753,1782398668);
INSERT INTO highlights VALUES('29165585_57_3253-3305','29165585',57,'从厨房用的瓦罐可以学到什么？','可是，它还有一个大缺点：它要渗水，虽然渗得很慢。在各个熔合的黏土颗粒之间还有小孔，水会从这些小孔漏出去。','3253-3305',NULL,1589985615,1782398668);
INSERT INTO highlights VALUES('29165585_57_3668-3687','29165585',57,'从厨房用的瓦罐可以学到什么？','盐和沙、黏土熔合——这就得到了一层釉。','3668-3687',NULL,1589985601,1782398668);
INSERT INTO highlights VALUES('29165585_57_2881-2922','29165585',57,'从厨房用的瓦罐可以学到什么？','留在黏土里的水受热变成了水蒸气。水蒸气占的地方比水大许多倍，它就冲破罐壁跑了出来。','2881-2922',NULL,1589985517,1782398668);
INSERT INTO highlights VALUES('29165585_57_2838-2852','29165585',57,'从厨房用的瓦罐可以学到什么？','如果罐子没有干透，就会裂开。','2838-2852',NULL,1589985509,1782398668);
INSERT INTO highlights VALUES('29165585_57_2381-2450','29165585',57,'从厨房用的瓦罐可以学到什么？','陶工旋盘——这是装在一根轴上旋转的一块圆板。它是用脚来转动的。陶工把一块黏土团放在板的中央，大拇指摁进黏土团里，其余的四指放在外面扶着它。','2381-2450',NULL,1589985461,1782398668);
INSERT INTO highlights VALUES('29165585_56_1293-1349','29165585',56,'除了瓦罐，还有什么东西是黏土制的？','可以和许多种金属制成很有价值的合金。比如说硬铝就是铝和镁、铜、锰的合金，只有钢的三分之一重，却有和钢一样的强度。','1293-1349',NULL,1589985135,1782398668);
INSERT INTO highlights VALUES('29165585_56_1258-1271','29165585',56,'除了瓦罐，还有什么东西是黏土制的？','它很轻，只有铁的三分之一重','1258-1271',NULL,1589985108,1782398668);
INSERT INTO highlights VALUES('29165585_56_915-924','29165585',56,'除了瓦罐，还有什么东西是黏土制的？','各种黏土里都含有铝','915-924',NULL,1589985015,1782398668);
INSERT INTO highlights VALUES('29165585_55_1610-1644','29165585',55,'有没有黄色的铜？','酸性的和含盐的食物要腐蚀铜器。产生出的铜盐就像是给人下了最毒的毒药。','1610-1644',NULL,1589984969,1782398668);
INSERT INTO highlights VALUES('29165585_55_675-692','29165585',55,'有没有黄色的铜？','黄铜根本不是铜，而是铜和锌的合金，','675-692',NULL,1589984910,1782398668);
INSERT INTO highlights VALUES('29165585_55_656-665','29165585',55,'有没有黄色的铜？','没有不是红色的铜。','656-665',NULL,1589984903,1782398668);
INSERT INTO highlights VALUES('29165585_55_955-1013','29165585',55,'有没有黄色的铜？','铁生锈会一直透到里层。而铜生锈，或者说所谓氧化，却只在表层。出现在表层的氧化薄膜自己会保护铜不再腐蚀，就像一层油漆。','955-1013',NULL,1589984896,1782398668);
INSERT INTO highlights VALUES('29165585_54_1189-1246','29165585',54,'害病的纽扣','要使白锡能转变成灰锡，先要传染：只要加一点点灰锡就行了。可是只传染还不够，还要让它受凉：需要温度不超过二十摄氏度。','1189-1246',NULL,1589984764,1782398668);
INSERT INTO highlights VALUES('29165585_53_1833-1855','29165585',53,'为什么生铁不像熟铁，熟铁不像钢？','熟铁里碳很少，钢里碳多一些，生铁里碳却很多。','1833-1855',NULL,1589984680,1782398668);
INSERT INTO highlights VALUES('29165585_52_1164-1173','29165585',52,'铁器是用什么做的？','铁里差不多总有碳。','1164-1173',NULL,1589984348,1782398668);
INSERT INTO highlights VALUES('29165585_51_967-989','29165585',51,'为什么马口铁生锈不像普通的铁那么厉害？','房顶铁皮用另外一种比较便宜的金属——锌来镀。','967-989',NULL,1589984272,1782398668);
INSERT INTO highlights VALUES('29165585_51_1162-1183','29165585',51,'为什么马口铁生锈不像普通的铁那么厉害？','在锌制的器皿里煮食物或者保存食物是危险的。','1162-1183',NULL,1589984246,1782398668);
INSERT INTO highlights VALUES('29165585_51_1149-1162','29165585',51,'为什么马口铁生锈不像普通的铁那么厉害？','锌和酸反应生成的锌盐极毒。','1149-1162',NULL,1589984235,1782398668);
INSERT INTO highlights VALUES('29165585_51_630-650','29165585',51,'为什么马口铁生锈不像普通的铁那么厉害？','铁也常常镀上一层锡——用锡层保护铁不生锈','630-650',NULL,1589984199,1782398668);
INSERT INTO highlights VALUES('29165585_50_1284-1312','29165585',50,'为什么铁要生锈？','防止铁生锈的正确方法，就是在它上面涂一层不透湿气的东西。','1284-1312',NULL,1589984020,1782398668);
INSERT INTO highlights VALUES('29165585_50_1022-1045','29165585',50,'为什么铁要生锈？','空气会吹干所有的东西，可它自己从来没有干燥过。','1022-1045',NULL,1589983977,1782398668);
INSERT INTO highlights VALUES('29165585_45_575-604','29165585',45,'英国最早的餐叉','1608年，有个名叫汤姆斯·科里阿特的英国人，到了意大利。','575-604',NULL,1589927376,1782398668);
INSERT INTO highlights VALUES('29165585_44_983-1028','29165585',44,'从前的人吃东西用什么，怎么吃？','让我们一起回到14世纪或者15世纪，走进武士的城堡，就在他们聚集在桌旁吃饭的时候去看看吧。','983-1028',NULL,1589885287,1782398668);
INSERT INTO highlights VALUES('29165585_43_998-1006','29165585',43,'我们喝茶和咖啡有多久了？','茶之后出现了咖啡','998-1006',NULL,1589884697,1782398668);
INSERT INTO highlights VALUES('29165585_43_748-781','29165585',43,'我们喝茶和咖啡有多久了？','1610年，茶第一次输入欧洲，是荷兰商人从遥远的爪哇岛把它运来的。','748-781',NULL,1589884679,1782398668);
INSERT INTO highlights VALUES('29165585_42_2410-2463','29165585',42,'古时候的人吃什么？','18世纪末，马铃薯仍旧是新奇的东西。法国王后在胸襟上插着马铃薯花，而煮马铃薯每天也只有在国王的餐桌上才有。','2410-2463',NULL,1589884636,1782398668);
INSERT INTO highlights VALUES('29165585_42_2300-2314','29165585',42,'古时候的人吃什么？','它出身在遥远的地方——南美洲','2300-2314',NULL,1589884614,1782398668);
INSERT INTO highlights VALUES('29165585_39_834-902','29165585',39,'为什么奶会变酸？','罪魁祸首是一些像酵母菌那样的细菌，在空气里经常有这种细菌。这种细菌一落到牛奶里，就着手工作——把乳糖变成乳酸。由于酸，牛奶就凝结起来了。','834-902',NULL,1589884191,1782398668);
INSERT INTO highlights VALUES('29165585_39_695-747','29165585',39,'为什么奶会变酸？','凝乳——这是酪素，是乳蛋白质。它溶在奶里，就像糖溶在水里。只要在奶里加一些酸，酪素就会带着脂肪分离出来。','695-747',NULL,1589884155,1782398668);
INSERT INTO highlights VALUES('29165585_37_2276-2338','29165585',37,'人造食物','其中一种——维生素A——帮助我们生长；另外一种——维生素D——使我们不会得佝偻病；第三种——维生素C——使我们不会生坏血病。','2276-2338',NULL,1589883961,1782398668);
INSERT INTO highlights VALUES('29165585_37_2412-2422','29165585',37,'人造食物','鱼肝油里有维生素D。','2412-2422',NULL,1589883943,1782398668);
INSERT INTO highlights VALUES('29165585_36_693-726','29165585',36,'为什么我们要吃肉？','煮肉的时候，有一部分蛋白质凝结起来，浮在水面上，就像一片片棉花絮。','693-726',NULL,1589883546,1782398668);
INSERT INTO highlights VALUES('29165585_35_950-1015','29165585',35,'汤是什么？','原来除了十九匙水之外，这盆肉汤里还有四分之一匙脂肪，四分之一匙胶质，少许的盐（不仅是普通的食盐，还有别种盐类），其余的就是“味质”','950-1015',NULL,1589883389,1782398668);
INSERT INTO highlights VALUES('29165585_31_634-668','29165585',31,'为什么面团里放上酵母会发起来？','只是在面团里的不是橡皮，而是同样柔韧的面筋；不是空气，而是二氧化碳。','634-668',NULL,1589866897,1782398668);
INSERT INTO highlights VALUES('29165585_29_579-627','29165585',29,'面包的皮是从哪里来的？','在面粉——不是马铃薯粉，而是普通的面粉——里也含有淀粉。所以面包一烘烤，上面也同样结成一层硬皮。','579-627',NULL,1589866744,1782398668);
INSERT INTO highlights VALUES('29165585_28_751-797','29165585',28,'为什么浆过的衣服是硬的？','浆过的衣服用热熨斗一烫，淀粉由于受到强热变成糊精。衣服上就生成一层硬皮，就像马铃薯上的那样。','751-797',NULL,1589866709,1782398668);
INSERT INTO highlights VALUES('29165585_27_612-658','29165585',27,'为什么烘烤的马铃薯有硬皮，煮的却没有？','由于受到强热，马铃薯表层的淀粉变成了糊精——一种胶，把一颗颗的淀粉颗粒胶结成一层红色的硬皮。','612-658',NULL,1589866669,1782398668);
INSERT INTO highlights VALUES('29165585_26_657-721','29165585',26,'为什么我们不吃生马铃薯？','这就是为什么没有人吃生马铃薯的缘故。马铃薯煮熟了，那些细胞壁受热以后破裂了，水就透进淀粉颗粒里。这就使得淀粉颗粒膨胀了，变软了。','657-721',NULL,1589866631,1782398668);
INSERT INTO highlights VALUES('29165585_22_608-673','29165585',22,'关于炉子的谜','炉子烧着了，却没有火焰。空气哪里进去，烟就从哪里出来。这是什么？这是人。','608-673',NULL,1589866314,1782398668);
INSERT INTO highlights VALUES('29165585_21_701-728','29165585',21,'为什么水能灭火？','这正是水为什么能灭火的道理：它不让空气接近燃烧的物体。','701-728',NULL,1589866160,1782398668);
INSERT INTO highlights VALUES('29165585_17_1154-1211','29165585',17,'火柴是什么时候发明的？','说实在的，这就是一个打火机。打火机里也有小石头，就是火石；也有一小块钢，就是那小轮；也有火绒，就是浸透汽油的灯芯。','1154-1211',NULL,1589771374,1782398668);
INSERT INTO highlights VALUES('29165585_17_706-728','29165585',17,'火柴是什么时候发明的？','那钢是火镰，那石头是火石，而那块海绵是火绒。','706-728',NULL,1589771302,1782398668);
INSERT INTO highlights VALUES('29165585_9_1552-1641','29165585',9,'为什么我们要喝水？','东西是用什么构成的并不怎么重要，最主要的是它是怎样构成的，这就是奥妙所在。','1552-1641',NULL,1589770422,1782398668);
INSERT INTO highlights VALUES('839748_75_1330-1377','839748',75,'3','赵，有空白的眼睛；我，有漆黑的忧愁。','1330-1377',1,1691374792,1782398609);
INSERT INTO highlights VALUES('839748_69_1074-1168','839748',69,'四十二 深圳，我喊你（一）','单靠几把镰刀，肯定割不完辽阔心事。单靠几把锤子肯定敲不掉整座忧愁的南山。','1074-1168',1,1691374207,1782398609);
INSERT INTO highlights VALUES('839748_67_724-740','839748',67,'四十 夜放图','饿，就吃一块夜；渴，就饮一杯黑。','724-740',1,1691373879,1782398609);
INSERT INTO highlights VALUES('839748_65_707-717','839748',65,'三十八 庞大的单数','“落雨大，水浸街。”','707-717',1,1691373750,1782398609);
INSERT INTO highlights VALUES('839748_61_734-741','839748',61,'三十四 双十的花忆','《轻握的温柔》','734-741',1,1691372866,1782398609);
INSERT INTO highlights VALUES('839748_61_1255-1302','839748',61,'三十四 双十的花忆','我今夜浴在灯光的手心，我的心就有了温暖。一天劳动让我在夜晚中显现幸福，整个城市的灯光站在街市上','1255-1302',1,1691372786,1782398609);
INSERT INTO highlights VALUES('839748_58_736-754','839748',58,'三十一 第七盏路灯','我不阻止第七盏路灯领养一个孤单的影子','736-754',1,1691372554,1782398609);
INSERT INTO highlights VALUES('839748_56_577-588','839748',56,'二十九 春天的四克拉雨水','四滴雨水四颗春天的钉子','577-588',1,1691372479,1782398609);
INSERT INTO highlights VALUES('839748_56_429-513','839748',56,'二十九 春天的四克拉雨水','张干吗在二楼的窗口丢下眼泪它砸伤一寸心口下的四滴雨水','429-513',1,1691372474,1782398609);
INSERT INTO highlights VALUES('839748_55_785-947','839748',55,'二十八 许·丝绸·白瓷','南山区，我用诗歌描你的柳叶眉。用桃花作胭脂用月色调水粉用一阵湖北籍的目光缓缓地将一件丝绸吹退','785-947',1,1691372381,1782398609);
INSERT INTO highlights VALUES('839748_55_606-653','839748',55,'二十八 许·丝绸·白瓷','七月七日，雨。一阵大雨跑到我眼里哭泣','606-653',1,1691372334,1782398609);
INSERT INTO highlights VALUES('839748_54_496-505','839748',54,'二十七 许·白纻裙','斜晖悠悠，逝水脉脉','496-505',1,1691372274,1782398609);
INSERT INTO highlights VALUES('839748_52_1475-1491','839748',52,'二十五 许·镜中','瞬间，一些事情就像桃花一样凋谢了','1475-1491',1,1691372209,1782398609);
INSERT INTO highlights VALUES('839748_52_764-850','839748',52,'二十五 许·镜中','一个叫做西乡的码头和一艘轮船一声汽笛就像离别时低沉的叫喊','764-850',1,1691372158,1782398609);
INSERT INTO highlights VALUES('839748_52_914-1111','839748',52,'二十五 许·镜中','我不愿意离别，那时候西乡的桃树和桃花也不愿意离别风扭动了一下细腰桃花顾盼忽然，江边的风景换成了细细的雨丝','914-1111',1,1691372146,1782398609);
INSERT INTO highlights VALUES('839748_51_645-805','839748',51,'二十四 许·宝安区','当街，一支姓许的藕莲步轻移。比春风稍胖修长的小腿被清水养育得多么白净恰似一段春光，乍泄。','645-805',1,1691372055,1782398609);
INSERT INTO highlights VALUES('839748_46_637-770','839748',46,'3','一只漂泊的风筝漂过立春、夏至、秋分，小雪，如果不是清明下起细雨我几乎想不起春天，六点钟，父亲','637-770',1,1691371457,1782398609);
INSERT INTO highlights VALUES('839748_46_799-889','839748',46,'3','带着关节炎，走十八里山路，去城关中学给我送来柴米和一小罐盐炒黄豆','799-889',1,1691371452,1782398609);
INSERT INTO highlights VALUES('839748_46_420-573','839748',46,'3','春天，六点钟，倦鸟合拢的翅膀，重新张开。春天，六点钟，父亲十年磨刀，我一朝砍柴。儿子放起了风筝，眼里只有春风，蓝天，白云收不住翅膀。','420-573',1,1691371283,1782398609);
INSERT INTO highlights VALUES('839748_45_592-676','839748',45,'2','他撒下的种子；我，背上书包，一溜小跑我家，坐北朝南。','592-676',1,1691371248,1782398609);
INSERT INTO highlights VALUES('839748_45_420-528','839748',45,'2','春天，六点钟，小麦苗青，桑园洁净。春天，六点钟，父亲将牛牵出牛圈他扛起犁耙，在七里半的水田，深深浅浅','420-528',1,1691371240,1782398609);
