INSERT INTO highlights VALUES('839748_3_3551-3592','839748',3,'乡关何处（序）','诗不描述现实，而是打开它，让我们看见一个原本隐藏着的世界，一种我们没发现的深层自我','3551-3592',1,1691246107,1782398609);
INSERT INTO highlights VALUES('839748_3_3170-3283','839748',3,'乡关何处（序）','这让我想到我用过的两个命题，一曰“重合的孤独”，一个个孤独，又重合得认不出自己，才够绝对了；二曰“无人称”，明明“有人”，却无力无法指认出那人，一种活生生的被抹煞、被忽略，比简单的无人更惨痛——以此透视存在，我们谁不是农民工？','3170-3283',1,1691246026,1782398609);
