INSERT INTO highlights VALUES('23199283_32_6373-6433','23199283',32,'幾米问答室','有些人的创作是从概念出发，而我喜欢将人物放置在空间里，然后让他们彼此产生互动，编成故事。我对“人与空间的变化”最感兴趣。','6373-6433',NULL,1581407571,1782398706);
INSERT INTO highlights VALUES('23199283_30_2874-2908','23199283',30,'《我的错都是大人的错》','每个小孩都是一本生动有趣的故事书。每个大人都是一本呆板无聊的教科书。','2874-2908',NULL,1581406943,1782398706);
INSERT INTO highlights VALUES('23199283_29_3751-3814','23199283',29,'《失乐园》','还有“包子头”，包子头是个笨笨的角色，但他温和善良。我用“脑袋里有点馅，但总是不够用……”来塑造他，他很多事情想不通，与世无争','3751-3814',NULL,1581406643,1782398706);
INSERT INTO highlights VALUES('23199283_29_2935-2978','23199283',29,'《失乐园》','我觉得“奔跑”这件事跟小朋友的心情有很大的连结，那种不顾一切往前跑的单纯动力很吸引我。','2935-2978',NULL,1581406568,1782398706);
INSERT INTO highlights VALUES('23199283_25_2064-2117','23199283',25,'《又寂寞又美好》','有时候，创作是需要等待的。也许所有的素材都齐全了，就是缺少一个串连的点，但这个点何时出现，大概只有天知道。','2064-2117',NULL,1581406024,1782398706);
INSERT INTO highlights VALUES('23199283_18_1108-1156','23199283',18,'《我的心中每天开出一朵花》','我想画一本书，一年三百六十五天，一天一页，每一页都有一朵花，书名就叫作《我的心中每天开出一朵花》','1108-1156',NULL,1581405400,1782398706);
INSERT INTO highlights VALUES('23199283_13_5771-5799','23199283',13,'《蓝石头》','创作像一趟旅程。最后抵达的终点，未必是当初设想的目的地。','5771-5799',NULL,1581404573,1782398706);
INSERT INTO highlights VALUES('23199283_12_6580-6621','23199283',12,'《幸运儿》','人生值得一活，就因为在任何一个时间点，每种角色都同时有着不幸的特质，和幸福的潜力。','6580-6621',NULL,1581403322,1782398706);
INSERT INTO highlights VALUES('23199283_12_6191-6263','23199283',12,'《幸运儿》','在这个平凡的世界，不平凡要付出极大的代价。董事长的幸运和成功，就像很多人的美貌与才气，一开始令人赞叹，后来被人们排斥，最后让当事人自己放逐自己。','6191-6263',NULL,1581403290,1782398706);
INSERT INTO highlights VALUES('23199283_12_6158-6172','23199283',12,'《幸运儿》','自由过了保鲜期，会发酵成寂寞','6158-6172',NULL,1581403255,1782398706);
INSERT INTO highlights VALUES('23199283_12_6037-6067','23199283',12,'《幸运儿》','当你什么都有了，活着只剩下失去。当你事事第一，谁能与你同行？','6037-6067',NULL,1581403233,1782398706);
INSERT INTO highlights VALUES('23199283_12_4920-5141','23199283',12,'《幸运儿》','众人昂首望着董事长飞去……在这个画面里，你可以找到曾经出现在幾米作品里的角色。《森林里的秘密》的小女孩，《微笑的鱼》里抱着鱼缸的男子，《向左走·向右走》的男女主角，《我的心中每天开出一朵花》的男子、女子和小蝴蝶，《月亮忘记了》的小男孩，《地下铁》的盲女……我还偷偷画了小王子和大野狼在里面，你找到了吗？','4920-5141',NULL,1581402922,1782398706);
INSERT INTO highlights VALUES('23199283_11_10965-11019','23199283',11,'《地下铁》','自己最喜欢的童书插画家之一，曾获得凯迪克（Caldecott）大奖的插画家彼得·希斯（Peter Sis），','10965-11019',NULL,1581401673,1782398706);
INSERT INTO highlights VALUES('23199283_11_10046-10087','23199283',11,'《地下铁》','幾米出了一张《地下铁的二十个音乐场景》的CD，由音乐来表达，传递画境的情愫与讯息。','10046-10087',NULL,1581401583,1782398706);
