INSERT INTO highlights VALUES('23199283_11_4215-4237','23199283',11,'《地下铁》','法国小说，书名是《谁在地下铁的出口等着我》。','4215-4237',NULL,1581400834,1782398706);
INSERT INTO highlights VALUES('23199283_11_1985-2033','23199283',11,'《地下铁》','时间，一直是我解决困境的良药。答案线索，往往都藏在生活的细节中。我只好等待、沉淀，让自己慢慢来。','1985-2033',NULL,1581400459,1782398706);
INSERT INTO highlights VALUES('23199283_10_5161-5168','23199283',10,'《月亮忘记了》','陈绮贞创作歌手','5161-5168',NULL,1581400262,1782398706);
INSERT INTO highlights VALUES('23199283_10_6266-6400','23199283',10,'《月亮忘记了》','我也好希望自己像个星球一般不管是否被人遗忘每段时间就会默默地更新自己从我熟悉的那个地方将头抬起','6266-6400',NULL,1581400125,1782398706);
INSERT INTO highlights VALUES('23199283_9_4901-5113','23199283',9,'《向左走·向右走》','波兰诗人辛波丝卡的诗句： 他们彼此深信，是瞬间迸发的热情让他们相遇，这样的确定是美丽的，但变幻无常更为美丽。','4901-5113',NULL,1581396490,1782398706);
INSERT INTO highlights VALUES('23199283_9_4326-4435','23199283',9,'《向左走·向右走》','为了让他们彼此寻找，我画了一张人群满满的画面。除了和读者以及剧中人物玩捉迷藏的游戏外，也传达一种想法——每个人都是自己生命的主角，其他人都只是龙套；但是，一个人不管有再多精彩的故事，一旦把镜头拉高拉远，什么都看不见了。','4326-4435',NULL,1581396276,1782398706);
INSERT INTO highlights VALUES('23199283_9_1230-1247','23199283',9,'《向左走·向右走》','一对永远找不到对方而各自哀伤的恋人','1230-1247',NULL,1581395970,1782398706);
INSERT INTO highlights VALUES('23199283_9_971-982','23199283',9,'《向左走·向右走》','日本漫画家柴门文的作品','971-982',NULL,1581395931,1782398706);
INSERT INTO highlights VALUES('23199283_8_11516-11555','23199283',8,'《微笑的鱼》','对思考型的人，很多时间看似都留给自己独处，仿佛家人都不重要似的，事实并非如此。','11516-11555',NULL,1581395737,1782398706);
INSERT INTO highlights VALUES('23199283_8_10481-10548','23199283',8,'《微笑的鱼》','伟大的艺术家都是把创作与人生合二为一的吧！创作绝对是这些人自我疗愈的复杂过程，而这些因痛苦而生的作品，也往往治愈了读者或观赏者的心灵。','10481-10548',NULL,1581395613,1782398706);
INSERT INTO highlights VALUES('23199283_8_10055-10131','23199283',8,'《微笑的鱼》','现代生活太重视表象了，缺乏对内心深处的觉知，童话与绘本正好提供一种通往心灵的管道，也可以让成年人静下来与孩子分享沟通，提醒成年人不要忽略自己与他人的感觉','10055-10131',NULL,1581395554,1782398706);
INSERT INTO highlights VALUES('23199283_8_9194-9204','23199283',8,'《微笑的鱼》','日本心理学家河合隼雄','9194-9204',NULL,1581395459,1782398706);
INSERT INTO highlights VALUES('23199283_8_8965-9016','23199283',8,'《微笑的鱼》','短短的两声小海浪，就可以建构出人到了海边的“感觉”，声音的“感觉”就是我们对人性情境坐标的记忆和对位。','8965-9016',NULL,1581395408,1782398706);
INSERT INTO highlights VALUES('23199283_8_7722-7741','23199283',8,'《微笑的鱼》','只要你能解放别人，自己同样也能获得自由','7722-7741',NULL,1581395207,1782398706);
INSERT INTO highlights VALUES('23199283_8_5735-5802','23199283',8,'《微笑的鱼》','从别人的眼中看这个故事，或许只看到一个寂寞的男人，遇见一只微笑的鱼，让他重新思索人生。对我而言，它却是一个从残酷现实中产生的美丽故事。','5735-5802',NULL,1581394967,1782398706);
INSERT INTO highlights VALUES('23199283_8_1524-1551','23199283',8,'《微笑的鱼》','书中的中年男子，每天重复单调地过生活，不快乐也不悲伤。','1524-1551',NULL,1581394665,1782398706);
INSERT INTO highlights VALUES('23199283_8_904-1023','23199283',8,'《微笑的鱼》','但是我却有一种记住画面的能力。这些画面，或许来自现实，或许来自想象，只要让我感动，就会存放在记忆中，像一张在暗房中显影的照片，随着时间过去，逐渐清晰明朗，连细微处也会渐渐放大。这些画面不定时出现，有时以为遗忘了，却又在最不经意的时刻浮现。','904-1023',NULL,1581394458,1782398706);
INSERT INTO highlights VALUES('23199283_7_4390-4782','23199283',7,'《森林里的秘密》','谢谢你毛毛兔，这个下午真好玩，星期三的下午风在吹， 我和我的梦都慢慢睡着了……毛毛兔没跟我说再见就离开了。 没有梦的城市好寂寞。 如今我再读到这一段，还是觉得感伤。因为，生命中有很多事物，来不及说再见，就离开了。','4390-4782',NULL,1581394334,1782398706);
INSERT INTO highlights VALUES('23199283_7_2982-3022','23199283',7,'《森林里的秘密》','用眼睛看图，用耳朵听故事，而且还要把句子大声念出来，体会声音中很多的韵律与层次。','2982-3022',NULL,1581394071,1782398706);
INSERT INTO highlights VALUES('23199283_7_2934-2943','23199283',7,'《森林里的秘密》','我认识了林真美老师','2934-2943',NULL,1581394037,1782398706);
INSERT INTO highlights VALUES('23199283_7_2376-2686','23199283',7,'《森林里的秘密》','我看到了我遗失的梦，在黑暗中微微发着光，我们拜访神秘的地洞，温暖的小屋有着许多的故事，我们在草丛花间愉快地追逐，我跟我的梦一起嬉戏……我们飞了起来，迎着风，向前飞驰，风吹乱了我的头发……','2376-2686',NULL,1581394022,1782398706);
INSERT INTO highlights VALUES('23199283_7_755-800','23199283',7,'《森林里的秘密》','我四十岁才开始创作，这是我的第一本书。当我开始创作时，其实还搞不清楚，创作到底是怎么一回事','755-800',NULL,1581393770,1782398706);
INSERT INTO highlights VALUES('23199283_4_2043-2097','23199283',4,'生命大发的意义','我感念那一段饱受折磨的伤痛时光，让我变得感性而敏锐，许多平凡的小事变得重要，而许多非凡的大事又变得无足轻重。','2043-2097',NULL,1581393591,1782398706);
INSERT INTO highlights VALUES('23199283_3_9352-9448','23199283',3,'成为幾米之前','当我创意满满时，觉得好像头上开满了花。画画这件事就像园丁照顾花园，必须每天辛勤地工作，很久以后的某一天，才会突然繁花盛开。','9352-9448',NULL,1581393194,1782398706);
INSERT INTO highlights VALUES('23199283_3_7598-7693','23199283',3,'成为幾米之前','Sempé、Edward Gorey、Shel Silverstein、Michael Sowa、John Burningham等人的作品，这些插画家的作品中蕴含的深度和趣味，令我非常震撼。','7598-7693',NULL,1581392880,1782398706);
INSERT INTO highlights VALUES('23199283_3_5147-5172','23199283',3,'成为幾米之前','大二那一年，我选择了设计组，学习比较实务的美术专业','5147-5172',NULL,1581392667,1782398706);
INSERT INTO highlights VALUES('23199283_3_3970-3975','23199283',3,'成为幾米之前','李石樵先生','3970-3975',NULL,1581391889,1782398706);
INSERT INTO highlights VALUES('23199283_3_3869-3874','23199283',3,'成为幾米之前','吴炫三先生','3869-3874',NULL,1581391871,1782398706);
INSERT INTO highlights VALUES('34336245_74_854-910','34336245',74,'百搭款的西装式长风衣适用于所有场合','款式上选择最经典百搭的，颜色上选择易于搭配的黑色或藏青色，纽扣以单排为好。长度不要过长，差不多膝盖以下这个位置。','854-910',NULL,1643529285,1782398647);
INSERT INTO highlights VALUES('34336245_72_549-600','34336245',72,'怎么看都已经过时的羽绒服，如果是亮面棕色款式就会显得时尚','羽绒服长度以刚好盖住臀部为佳，不论是搭配裙子还是裤子，这个长度 刚好合适。颜色的话不要黑色，棕色最佳。','549-600',NULL,1643529236,1782398647);
INSERT INTO highlights VALUES('34336245_69_639-691','34336245',69,'专题 9 将围巾围在其他地方','将围巾系在手提包上。将围巾系在女士挎包上，稍微垂下一段。也可以用围巾在保守风的手提包的提手上系一个蝴蝶结','639-691',NULL,1643528052,1782398647);
INSERT INTO highlights VALUES('34336245_69_568-604','34336245',69,'专题 9 将围巾围在其他地方','在白色牛仔裤上搭配围巾腰带，如此可以增添优雅气质，给人以教养良好的印象。','568-604',NULL,1643528033,1782398647);
INSERT INTO highlights VALUES('34336245_67_571-608','34336245',67,'十年后也可以使用的卡其色','卡其色能够很好地和黑色、白色、深蓝色等基础颜色搭配，所以也被称为万能颜色。','571-608',NULL,1643527905,1782398647);
INSERT INTO highlights VALUES('34336245_66_791-830','34336245',66,'比起昂贵的化妆品，撞色搭配会让肌肤显得更美','小麦肤色和古铜肤色的人十分适合鲜艳的颜色。而肤色白皙、粉嫩的人则适合淡色衣服。','791-830',NULL,1643527726,1782398647);
INSERT INTO highlights VALUES('34336245_65_533-584','34336245',65,'Chapter08 颜 色 只要用银色代替灰色，就会有时尚氛围','黄色既可以和暖色系服饰搭配，也可以和冷色系服饰搭配，如果不知道应该怎样搭配时，建议大家选择鲜艳的黄色。','533-584',NULL,1643527686,1782398647);
INSERT INTO highlights VALUES('34336245_63_825-851','34336245',63,'看起来很优雅的A字裙是女性必备服饰','在这里要介绍的是带有图案的A字裙和黑白色花纹的A字裙','825-851',NULL,1643527585,1782398647);
INSERT INTO highlights VALUES('34336245_61_1270-1292','34336245',61,'只要穿上束带裤就会变得很时尚','裤子: LEPSIM LOWRYS FARM','1270-1292',NULL,1643527505,1782398647);
INSERT INTO highlights VALUES('34336245_60_580-617','34336245',60,'黑色的裤子要选择九分裤','选择黑色裤子的秘诀就是，不要选择普通长度，而是要选择稍微露出脚踝的九分裤。','580-617',NULL,1643527436,1782398647);
INSERT INTO highlights VALUES('34336245_58_800-856','34336245',58,'牛仔裤是为了整洁而存在的','最便于搭配的牛仔裤并不是细脚牛仔裤，而是男友风牛仔裤。仿佛是“借了男朋友的牛仔裤来穿”一样，稍微有些宽松的款式。','800-856',NULL,1643527336,1782398647);
INSERT INTO highlights VALUES('34336245_56_1171-1269','34336245',56,'专题 7 要做到“不注意看也是时尚女性”打底衫一定要是灰色','无肩带背心: GU圆领背心: COMME CA ISM吊带背心: Gap','1171-1269',NULL,1643527273,1782398647);
INSERT INTO highlights VALUES('34336245_56_792-814','34336245',56,'专题 7 要做到“不注意看也是时尚女性”打底衫一定要是灰色','除基本的贴身背心和圆领背心外，还有无肩带背心','792-814',NULL,1643527254,1782398647);
INSERT INTO highlights VALUES('34336245_56_742-763','34336245',56,'专题 7 要做到“不注意看也是时尚女性”打底衫一定要是灰色','无论是抹胸还是贴身背心，一定要选择灰色的。','742-763',NULL,1643527214,1782398647);
INSERT INTO highlights VALUES('34336245_53_524-587','34336245',53,'将V领开衫穿出外套风格的话就会变成流行典范','V领是长款开衫的关键，可以像外套一样穿出成熟的感觉。像照片中所展示的开衫一样，无论什么颜色的衣服都可以搭配。尤为推荐灰色开衫。','524-587',NULL,1643527055,1782398647);
INSERT INTO highlights VALUES('34336245_53_486-490','34336245',53,'将V领开衫穿出外套风格的话就会变成流行典范','长款开衫','486-490',NULL,1643527042,1782398647);
INSERT INTO highlights VALUES('34336245_52_898-925','34336245',52,'用鲜艳色彩的搭配来改变印象','无论是冷色系还是暖色系作为搭配色，较为推荐的是黄色系。','898-925',NULL,1643526943,1782398647);
INSERT INTO highlights VALUES('34336245_51_412-431','34336245',51,'应该持有的T恤为3类！英文、V领、灰色','应该持有的T恤为3类！英文、V领、灰色','412-431',NULL,1643526837,1782398647);
INSERT INTO highlights VALUES('34336245_50_908-934','34336245',50,'搭配高手穿着条纹T恤会很受欢迎','条纹的黑色部分较粗的话会有休闲感，较细的话会显得优雅','908-934',NULL,1643526768,1782398647);
INSERT INTO highlights VALUES('34336245_47_514-551','34336245',47,'将格子衬衫彻底作为搭配色来使用','格子衬衫十分适合黑白灰这类单调的颜色，以及土黄色，同时也可以搭配条纹T恤。','514-551',NULL,1643526483,1782398647);
INSERT INTO highlights VALUES('34336245_44_490-513','34336245',44,'Chapter06 上 衣 藏青色雪纺上衣比花边更能体现成熟的风情','女性最应该拥有的一件基础服装就是纯棉的白色衬衫','490-513',NULL,1643269543,1782398647);
INSERT INTO highlights VALUES('34336245_43_588-637','34336245',43,'专题 6 把黑色紧身裤换成其他颜色就能脱俗','深蓝色、炭灰色、酒红色这三种颜色。裙子下方看到的并不是普通的黑色，而是这三种颜色，就会显得非常时尚','588-637',NULL,1643269395,1782398647);
INSERT INTO highlights VALUES('34336245_42_676-720','34336245',42,'无论穿跟多高的鞋都能如履平地的秘技','除了图片中的BUTTERFLY TWISTS以外，很多别的品牌也出了这种口袋鞋可供选择。','676-720',NULL,1643269365,1782398647);
INSERT INTO highlights VALUES('34336245_42_720-766','34336245',42,'无论穿跟多高的鞋都能如履平地的秘技','上班时间、宴会回来的路上、鞋子突然损坏的情况下，一想到有口袋鞋在，对高跟鞋就变得无所畏惧了。','720-766',NULL,1643269358,1782398647);
INSERT INTO highlights VALUES('34336245_41_850-878','34336245',41,'长筒靴加入棕色就不会显得厚重','最应该避免穿的是中高靴，因为会把视线集中到最粗的腿肚子上','850-878',NULL,1643269271,1782398647);
INSERT INTO highlights VALUES('34336245_41_591-649','34336245',41,'长筒靴加入棕色就不会显得厚重','我常用的长筒靴是棕色的。棕色能很好地避免过于保守，不会造成只有腿部很沉重的印象。理想的颜色是如图片中这样柔和的棕色。','591-649',NULL,1643269236,1782398647);
INSERT INTO highlights VALUES('34336245_40_822-846','34336245',40,'只要穿上“大叔鞋”，就有“潮流感”','只有茶色会变成“真正的大叔”，使得搭配难度上升。','822-846',NULL,1643269191,1782398647);
INSERT INTO highlights VALUES('34336245_40_789-821','34336245',40,'只要穿上“大叔鞋”，就有“潮流感”','藏青色或银色的“大叔鞋”也常被推荐。需要注意的是茶色的“大叔鞋”','789-821',NULL,1643269184,1782398647);
INSERT INTO highlights VALUES('34336245_38_765-796','34336245',38,'尖头平底鞋有拉长腿部的视觉效果','银色或金色这类闪亮的鞋子如果是平底款式的话，不会过于华丽，脱俗','765-796',NULL,1643268996,1782398647);
INSERT INTO highlights VALUES('34336245_32_794-830','34336245',32,'日常使用的大包选择圆角款式更显气质','每天使用的包如果是米白色的圆角款型，绝对能使平时穿的衣服看上去更有气质！','794-830',NULL,1643261481,1782398647);
INSERT INTO highlights VALUES('34336245_30_823-896','34336245',30,'回头率高的女性，都有一个彩色的包','春夏季可以选择黄色、绿色、蓝色这些清爽的颜色。秋冬季可以选择沉稳的芥末黄、苔藓绿、酒红色等易于搭配的颜色。银色或金色的包则四季通用，可以轮换搭配。','823-896',NULL,1643261277,1782398647);
INSERT INTO highlights VALUES('34336245_29_1306-1349','34336245',29,'包越多越好','基本款衣服，用包和饰物来搭配出风格，这是时尚的基础。所以请尽管去尝试各种不同风格的包。','1306-1349',NULL,1643260855,1782398647);
INSERT INTO highlights VALUES('34336245_29_640-709','34336245',29,'包越多越好','造型的目的是增加亮点，因此手拿包的款式推荐亮色款、花纹款和条纹款。材质方面，夏天选择藤质，冬天选择皮革、毛毡等，让心情也能感受季节的变化。','640-709',NULL,1643260765,1782398647);
INSERT INTO highlights VALUES('34336245_27_646-663','34336245',27,'专题 3 美丽动人掌握完美搭配饰品的法则','大款式的饰品要和小款式的饰品搭配，','646-663',NULL,1643260475,1782398647);
INSERT INTO highlights VALUES('34336245_27_546-561','34336245',27,'专题 3 美丽动人掌握完美搭配饰品的法则','首先，一起佩戴的饰品材质要统一','546-561',NULL,1643260455,1782398647);
INSERT INTO highlights VALUES('34336245_24_1253-1297','34336245',24,'婚礼避免穿连衣裙，改为雪纺无袖上衣','最推荐的颜色是金色，所有颜色中金色是最华丽的。所以出席重要场合时，包和鞋子选择金色的吧。','1253-1297',NULL,1643260056,1782398647);
INSERT INTO highlights VALUES('34336245_20_639-699','34336245',20,'高品位的同色搭配是全身灰色或者白色','最简单的方法是，全部采用白色或灰色这类浅色系，在此基础上用一、两件颜色鲜艳的饰物点缀。只要颜色足够艳丽，什么色系都可以。','639-699',NULL,1643259589,1782398647);
INSERT INTO highlights VALUES('34336245_10_737-751','34336245',10,'Rule 6 贴身款式只需腰部贴身','“贴身款式需要做到腰部贴身”','737-751',NULL,1643255203,1782398647);
INSERT INTO highlights VALUES('34336245_9_891-932','34336245',9,'Rule 5 首先要确定的不是颜色和花纹，而是衣服的款型','人都会不知不觉形成穿同一类型衣服的癖好，如果自己能意识到这一点，那么后面就简单了。','891-932',NULL,1643255133,1782398647);
INSERT INTO highlights VALUES('34336245_9_961-1041','34336245',9,'Rule 5 首先要确定的不是颜色和花纹，而是衣服的款型','时尚的印象由全身的平衡来决定。改变现有衣服的平衡以及搭配上的平衡，比改变颜色和花纹，更能马上改变形象。','961-1041',NULL,1643255123,1782398647);
INSERT INTO highlights VALUES('34336245_8_813-854','34336245',8,'Rule 4 极力避免穿着连衣裙','比如把衬衫领子露出来，使休闲中透出些许华丽感，或者把色彩艳丽的毛衣搭在肩上做点缀，','813-854',NULL,1643255050,1782398647);
