INSERT INTO highlights VALUES('839188_4_3122-3576','839188',4,'小鸟在天空消失的日子','《活着》    活着    现在活着    那就是口渴    是枝叶间射下来耀眼的阳光    是忽然想起的一支旋律    是打喷嚏    是与你手牵手    活着    现在活着    那就是超短裙    是天文馆    是约翰·施特劳斯    是毕加索    是阿尔卑斯山    是遇到一切美妙的事物    而且还要    小心翼翼提防潜藏的恶    活着    现在活着    是敢哭    是敢笑    是敢怒    是自由    活着    现在活着    是刚才狗在远处的狂吠    是现在地球的旋转    是生命刚刚在何处诞生的啼哭    是现在士兵在某地负伤    是此时秋千的摇荡    是现在时光的流逝    活着    现在活着    是鸟儿展翅    是海涛汹涌    是蜗牛爬行    是人在相爱    是你的手温    是生命','3122-3576',NULL,1582953669,1782398702);
