INSERT INTO highlights VALUES('3300054377_164_339-618','3300054377',164,'笔筒','笔筒笔筒是笔的家长它望子成龙有朝一日笔能写出惊人的文学名声会洗干净它黑色的教诲许多家长排队祈祷成为笔筒干巴巴站着孕育出一个不会断水的孩子','339-618',5,1684736718,1782398619);
