INSERT INTO highlights VALUES('43318719_19_5385-5436','43318719',19,'正文十一','你不必只看到整个天空中最显著的云，这样微妙的云彩同样有价值——也许更有价值，因为你是唯一注意到它的人。','5385-5436',1,1737883240,1782398554);
INSERT INTO highlights VALUES('43318719_19_5310-5353','43318719',19,'正文十一','观云是一种在日常生活中发现异国情调的心境。以迭浪云为例，它看起来就像一连串卷曲的海浪。','5310-5353',1,1737883216,1782398554);
