INSERT INTO highlights VALUES('43318719_17_6503-6615','43318719',17,'正文九','描述了云彩不同的透明程度。左边这样的云被称为“透光云”，它足够薄，你可以透过它看到太阳的位置。中间的这种云被称为“蔽光云”，它足够厚，你无法透过它看到太阳的位置。而右边这样的云被称为“漏光云”，它的云块比较厚，云块间有缝隙，','6503-6615',1,1737778436,1782398554);
