INSERT INTO highlights VALUES('43318719_14_4050-4134','43318719',14,'正文六','层积云是这三种云中最低的一种，因为离我们最近，它的团块看起来最大。最高的是卷积云，由于离我们远，云块比较小，看起来更像小颗粒。中云族的高积云，云块大小介于前两种云之间。','4050-4134',1,1737723388,1782398554);
