INSERT INTO highlights VALUES('43318719_12_10488-10533','43318719',12,'正文四','这是太阳光被云层中的微小水滴反射回来，发生衍射所形成的现象。这一现象也被称为“布罗肯幽灵”','10488-10533',1,1737721169,1782398554);
