INSERT INTO highlights VALUES('22486199_48_544-600','22486199',110,'云虹 CLOUD BOW','云虹很像彩虹，但颜色更浅。事实上，它们往往不会呈现出任何可辨别的颜色，看起来就像白化的彩虹，或是彩虹的鬼魂经过。','543-599',5,1689470165,1782398617);
