INSERT INTO highlights VALUES('22486199_42_512-573','22486199',103,'夜光云 NOCTILUCENT','神秘的夜光云比大气层中所有的云都要高。它也被称为“极地中间层云”，它们有着怪异的蓝白色外观，通常呈现为微妙的涟漪或波浪状。','531-592',2,1689468100,1782398617);
INSERT INTO highlights VALUES('22486199_40_625-639','22486199',101,'钻石尘 DIAMOND DUST','钻石尘有时也被称为“冰雾”，','643-657',2,1689467921,1782398617);
INSERT INTO highlights VALUES('22486199_39_518-577','22486199',100,'雾和霭 FOG & MIST','雾和霭的区别主要在于能见度不同。通常来说，在霭中的能见度为1—2千米，但在雾中的能见度不超过1千米——雾只是霭的加厚版','534-593',2,1689467501,1782398617);
