INSERT INTO highlights VALUES('22486199_37_522-582','22486199',98,'雨幡洞云 FALLSTREAK HOLE','雨幡洞云看起来很奇怪，但实际上并不罕见。它们也被称为“穿孔云”，是中云族或高云族云层中脆弱的裂口，其下方悬吊着冰晶拖尾。','536-596',2,1689467290,1782398617);
INSERT INTO highlights VALUES('22486199_36_767-796','22486199',97,'滚轴云 ROLL CLOUD','但大多数滚轴云属于弧状云（第53页），并且是由风暴引起的。','787-816',2,1689467177,1782398617);
INSERT INTO highlights VALUES('22486199_36_707-738','22486199',97,'滚轴云 ROLL CLOUD','有一种著名的滚轴云叫作“阵晨风云”，它出现在澳大利亚北昆士兰。','727-758',2,1689467167,1782398617);
INSERT INTO highlights VALUES('22486199_35_512-541','22486199',96,'火积云 PYROCUMULUS','当发生森林火灾时，上升的空气柱会形成云彩，它们被称为火积云','531-560',2,1689466986,1782398617);
