INSERT INTO highlights VALUES('22486199_31_502-555','22486199',91,'砧状云 INCUS','砧状云是积雨云（第27页）的一部分。事实上，它是暴风雨到来前云彩最典型的特征：冰晶在云的顶部形成巨大的顶篷','527-580',2,1689466055,1782398617);
