INSERT INTO highlights VALUES('22486199_15_768-800','22486199',73,'雨层云 NIMBOSTRATUS','积雨云的降水迅猛而短暂，雨层云的降水则相对持久，可以持续数小时。','763-795',2,1689418723,1782398617);
INSERT INTO highlights VALUES('22486199_14_1531-1584','22486199',72,'卷层云 CIRROSTRATUS','晕的存在是区分卷层云和高层云的一种准确方法，高层云更低，并且是由（至少一部分是由）水滴组成的，不会产生晕。','1610-1663',2,1689418674,1782398617);
INSERT INTO highlights VALUES('22486199_14_951-971','22486199',72,'卷层云 CIRROSTRATUS','能产生这样的晕，表明天空中的云是卷层云。','991-1011',2,1689418640,1782398617);
