INSERT INTO highlights VALUES('22486199_12_1441-1538','22486199',70,'卷云 CIRRUS','除了密卷云（参见下表）之外，卷云所有其他的种类都可以折射、反射太阳光，产生彩色的光弧和光环，也就是晕现象','1527-1624',2,1689418393,1782398617);
INSERT INTO highlights VALUES('22486199_12_549-653','22486199',70,'卷云 CIRRUS','卷云是所有云彩类型中外形最优雅缥缈的，也是高度最高的——云体全部由冰晶组成。冰晶下落的时候穿过对流层上部高空中的风，形成精美的天空艺术绘画效果，这就是“幡”','551-655',2,1689418254,1782398617);
INSERT INTO highlights VALUES('22486199_11_895-911','22486199',69,'高层云 ALTOSTRATUS','这些云条被称作波状辐辏状高层云。','936-952',2,1689417572,1782398617);
