INSERT INTO highlights VALUES('25298416_7_1739-1822','25298416',7,'爱自己的歌','没有生命的砂，多么悲哀啊！用手一握，悉悉索索的从手指中间漏下。','1739-1822',NULL,1580711412,1782398678);
INSERT INTO highlights VALUES('25298416_4_3418-3427','25298416',4,'总序 周作人的“日常”','清少纳言与石川啄木','3418-3427',NULL,1580711288,1782398678);
INSERT INTO highlights VALUES('25298416_5_459-714','25298416',5,'引语','他的诗歌是我顶喜欢的。我们并不为别人的缘故而生活着，我们乃是为了自己的缘故而生活着的。爱惜刹那刹那的生命之心。爱惜那在忙碌的生活之中，浮到心头又复即消去的刹那刹那的感觉之心','459-714',NULL,1580711260,1782398678);
INSERT INTO highlights VALUES('3300080713_20_12080-12106','3300080713',20,'常见问题','你必须有创造力，并且不管距离多远，都要坚持保持联系。','12080-12106',0,1763174271,1782398514);
INSERT INTO highlights VALUES('3300080713_19_2396-2440','3300080713',19,'第十三章 作者心语','但“爱箱”如果是满的，我们就会创造一种友好的氛围，一种寻求理解、容许分歧和愿意协商的氛围','2396-2440',0,1763128014,1782398514);
INSERT INTO highlights VALUES('3300080713_18_10079-10106','3300080713',18,'第十二章 爱那不可爱的','我们做出积极的行动，并不是靠感觉，而是我们作出的选择。','10079-10106',0,1763127903,1782398514);
INSERT INTO highlights VALUES('3300080713_16_7078-7116','3300080713',16,'第十章 爱是一种选择','本章的一个核心思想是，无论我们能否自然地使用伴侣的爱语，我们都选择去使用它。','7078-7116',0,1763122189,1782398514);
INSERT INTO highlights VALUES('3300080713_16_6579-6600','3300080713',16,'第十章 爱是一种选择','爱是你为别人做些什么，而不是为自己做些什么','6579-6600',0,1763122125,1782398514);
INSERT INTO highlights VALUES('3300080713_16_6216-6253','3300080713',16,'第十章 爱是一种选择','你付给我再多的钱，我也不会为你用吸尘器打扫房子，但是我会为了爱去做这件事。','6216-6253',0,1763122063,1782398514);
INSERT INTO highlights VALUES('3300080713_16_5554-5589','3300080713',16,'第十章 爱是一种选择','几乎从来没有两个人在同一天爱上彼此，他们也几乎从来不会在同一天不再相爱','5554-5589',0,1763122001,1782398514);
INSERT INTO highlights VALUES('3300080713_16_4124-4184','3300080713',16,'第十章 爱是一种选择','在情感满足的状态中，我们都可以把我们的创造力，投入婚姻之外的许多有益身心的项目中，同时，也能让我们的婚姻保持活力和成长。','4124-4184',0,1763121637,1782398514);
INSERT INTO highlights VALUES('3300080713_15_8094-8179','3300080713',15,'第九章 发现你的主要爱语','每周三次请配偶为自己的“爱箱”打分，并按照他（她）的建议去做，使他（她）的“爱箱”得分能够提高。如果你的配偶的打分一直是10分，你可以好好表扬一下自己，但是不要停止去爱。','8094-8179',0,1763120093,1782398514);
INSERT INTO highlights VALUES('3300080713_15_1754-1818','3300080713',15,'第九章 发现你的主要爱语','听说了“肯定的言辞”“精心的时刻”“接受礼物”“服务的行动”和“身体的接触”这五种爱语后，能够立刻知道自己和配偶的主要爱语是什么','1754-1818',0,1763119043,1782398514);
INSERT INTO highlights VALUES('3300080713_13_12048-12073','3300080713',13,'第七章 爱的语言之四：服务的行动','很多婚姻问题源于婚后应该停止“约会行为”这种迷思。','12048-12073',0,1763110363,1782398514);
INSERT INTO highlights VALUES('3300080713_13_9815-9844','3300080713',13,'第七章 爱的语言之四：服务的行动','我太爱你了，所以我不允许你这样对我，这对你、对我都不好。”','9815-9844',0,1763110152,1782398514);
INSERT INTO highlights VALUES('3300080713_13_9120-9164','3300080713',13,'第七章 爱的语言之四：服务的行动','妻子可以在丈夫批评她后说：“听起来这对你来说非常重要，你能解释一下为什么它那么重要吗？”','9120-9164',0,1763110086,1782398514);
INSERT INTO highlights VALUES('3300080713_11_14025-14079','3300080713',11,'第五章 爱的语言之二：精心的时刻','①多一些同情，少一些劝告；②多一些理解，少一些解答；③多了解一些问题，少下一些结论；④多关心人，少关心问题。','14025-14079',0,1763024469,1782398514);
INSERT INTO highlights VALUES('3300080713_11_11774-11814','3300080713',11,'第五章 爱的语言之二：精心的时刻','优质的活动的副产品之一是，它们提供了一个记忆库，可以让人在未来的岁月里提取记忆。','11774-11814',0,1763024075,1782398514);
INSERT INTO highlights VALUES('3300080713_11_10757-10819','3300080713',11,'第五章 爱的语言之二：精心的时刻','确立一个“每日分享时间”。在这个时间里，每个人分享当天发生的三件事，以及他（她）的感受。我称之为健康婚姻的“每日最低要求”。','10757-10819',0,1763023945,1782398514);
INSERT INTO highlights VALUES('3300080713_11_7939-7974','3300080713',11,'第五章 爱的语言之二：精心的时刻','我的目标是发现你的想法和感受，而不是为自己辩护或者纠正你。我想理解你。','7939-7974',0,1763022377,1782398514);
INSERT INTO highlights VALUES('3300080713_11_7712-7724','3300080713',11,'第五章 爱的语言之二：精心的时刻','四　留心对方的肢体语言。','7712-7724',0,1763022337,1782398514);
INSERT INTO highlights VALUES('3300080713_11_7564-7578','3300080713',11,'第五章 爱的语言之二：精心的时刻','三　倾听对方，了解对方的感受','7564-7578',0,1763022321,1782398514);
INSERT INTO highlights VALUES('3300080713_11_7380-7402','3300080713',11,'第五章 爱的语言之二：精心的时刻','二　不要一边听你的配偶说话，一边做其他事情。','7380-7402',0,1763022295,1782398514);
INSERT INTO highlights VALUES('3300080713_11_7299-7317','3300080713',11,'第五章 爱的语言之二：精心的时刻','一　当你的配偶说话时，保持眼神交流，','7299-7317',0,1763022289,1782398514);
INSERT INTO highlights VALUES('3300080713_11_6981-7046','3300080713',11,'第五章 爱的语言之二：精心的时刻','我们很多人都像帕特里克一样，接受的训练是分析问题和解决问题，但是我们忘了婚姻是一种关系，而不是一个需要完成的项目或需要解决的问题。','6981-7046',0,1763022224,1782398514);
INSERT INTO highlights VALUES('3300080713_11_4413-4493','3300080713',11,'第五章 爱的语言之二：精心的时刻','至于时间问题，你会找到时间的，你是个聪明人，”我继续说，“如果你不是一个好的决策者，你就不会有现在的成就。你有能力规划你的生活，并且将安德莉亚纳入你的计划中。”','4413-4493',0,1763021698,1782398514);
INSERT INTO highlights VALUES('3300080713_11_2732-2758','3300080713',11,'第五章 爱的语言之二：精心的时刻','让一个人感到被爱的东西不一定会让另一个人也感到被爱。','2732-2758',0,1763021425,1782398514);
INSERT INTO highlights VALUES('3300080713_11_1238-1283','3300080713',11,'第五章 爱的语言之二：精心的时刻','精心的时刻的核心是“在一起”，这不单单指身体的接近，最重要的是把全部的注意力放在对方身上。','1238-1283',0,1763021244,1782398514);
INSERT INTO highlights VALUES('3300080713_10_12425-12494','3300080713',10,'第四章 爱的语言之一：肯定的言辞','要对你的配偶说称赞、鼓励和请求的话，不要命令或责备对方，这样才能肯定他（她）的自我价值，创造亲密的关系，治愈创伤，并且充分激发配偶的潜能。','12425-12494',0,1763005817,1782398514);
INSERT INTO highlights VALUES('3300080713_10_11233-11255','3300080713',10,'第四章 爱的语言之一：肯定的言辞','一个人的爱的语言不一定是另一个人的爱的语言。','11233-11255',0,1763005655,1782398514);
INSERT INTO highlights VALUES('3300080713_10_8795-8831','3300080713',10,'第四章 爱的语言之一：肯定的言辞','人类最深层的需求可能就是被人赏识的需求。肯定的言辞可以满足许多人这种需求','8795-8831',0,1763005376,1782398514);
INSERT INTO highlights VALUES('3300080713_10_8570-8593','3300080713',10,'第四章 爱的语言之一：肯定的言辞','请求会创造表达爱的机会，而要求会扼杀这种机会。','8570-8593',0,1763005337,1782398514);
INSERT INTO highlights VALUES('3300080713_10_7957-7995','3300080713',10,'第四章 爱的语言之一：肯定的言辞','但如果我们用请求的方式说出自己的需要和意愿，则是在提供引导，而不是下最后通牒','7957-7995',0,1763005216,1782398514);
INSERT INTO highlights VALUES('3300080713_10_7330-7352','3300080713',10,'第四章 爱的语言之一：肯定的言辞','对待过去的失败，最好的做法就是让它成为历史。','7330-7352',0,1763005135,1782398514);
INSERT INTO highlights VALUES('3300080713_10_6345-6426','3300080713',10,'第四章 爱的语言之一：肯定的言辞','“今天晚上你没有主动帮我，我感到失望和伤心。”这句话如果用温和、坦率的语气说出来，是爱的表达，因为说话的人希望配偶了解她，她正在通过分享内心的感受来建立亲密的关系','6345-6426',0,1763005016,1782398514);
INSERT INTO highlights VALUES('3300080713_10_5109-5153','3300080713',10,'第四章 爱的语言之一：肯定的言辞','也许，你的配偶在生活中的某个或某些领域具有未开发的潜力，正等待你鼓励的话语将它激发出来。','5109-5153',0,1763004774,1782398514);
INSERT INTO highlights VALUES('3300080713_9_8353-8412','3300080713',9,'第三章 恋爱','①是你心甘情愿的，而非勉强的；②体现出真实的努力和自制力；③依靠理智而不只是依靠本能；④旨在为配偶的个人成长提供帮助。','8353-8412',0,1763002978,1782398514);
INSERT INTO highlights VALUES('3300080713_9_6166-6245','3300080713',9,'第三章 恋爱','这种爱需要努力和克制。它是一种选择，是为了使对方受益而付出精力。如果他（她）的生活因为你的努力而变得丰富，你也会获得一种满足感，那是真爱一个人而带来的满足感。','6166-6245',0,1763002673,1782398514);
INSERT INTO highlights VALUES('3300080713_8_2553-2658','3300080713',8,'第二章 保持“爱箱”常满','“在每个孩子的心里，都有一个等着被爱填满的‘情感箱子’。当一个孩子真正感到被爱时，他才会正常成长；但是，当他的‘爱箱’空了的时候，他会有不良的行为。孩子的许多不良行为，都是因为他的空‘爱箱’正在发出对爱的渴望。','2553-2658',0,1763001315,1782398514);
INSERT INTO highlights VALUES('3300080713_8_1230-1274','3300080713',8,'第二章 保持“爱箱”常满','人类存在的核心是对亲密关系和被爱的渴望。婚姻的目的就是为了满足我们对亲密关系和爱的需求。','1230-1274',0,1763000586,1782398514);
INSERT INTO highlights VALUES('834467_20_19813-19885','834467',42,'回到南门','我看到了远处突然升起一片火光，越来越大的雨点与那片火纠缠起来，燃烧的火不仅没有熄灭，反而逐渐增大。就如不可阻挡的呼喊，在雨中脱颖而出，熊熊燃烧。','19725-19797',1,1700666539,1782398597);
INSERT INTO highlights VALUES('834467_20_12091-12117','834467',42,'回到南门','然后她走到窗前打开窗户，像刚下了蛋的母鸡一样叫唤了。','12063-12089',1,1700665748,1782398597);
INSERT INTO highlights VALUES('834467_20_8774-8830','834467',42,'回到南门','那个贫困家中唯一的装饰品，破碎时的声响让我经历了长时间的战栗。王立强会像拧断一根黄瓜一样，咔嚓一声拧断我的脖子。','8746-8802',1,1700665373,1782398597);
INSERT INTO highlights VALUES('834467_20_1620-1728','834467',42,'回到南门','可我回到家中以后，王立强令我失望地没有流露一丝的吃惊，仿佛他早就知道我能提回家中似的接过了水瓶。看着他蹲下去的背影，我用最后的希望提醒他：“我只休息了一次。”','1594-1702',1,1700664108,1782398597);
INSERT INTO highlights VALUES('834467_20_1432-1506','834467',42,'回到南门','希望在想象里为我描绘了这样的情形，当我将两瓶开水提回家时，王立强是那样的欣喜若狂，他高声喊叫李秀英，那个床上的女人也走过来了，他们两人由衷地赞叹我。','1406-1480',1,1700664065,1782398597);
INSERT INTO highlights VALUES('834467_19_5245-5324','834467',41,'诬陷','我努力使自己勇敢，心里还是一阵阵发虚。下课后我极力鼓动受罚的同学和我一样反抗老师。他们在表达自己不满时和我一样激动，可一旦说到拒绝写检查，他们全部吞吞吐吐了。','5222-5301',1,1700492179,1782398597);
INSERT INTO highlights VALUES('834467_18_9924-9979','834467',40,'抛弃','这个女人以她垂暮的气息腐化着国庆蓬勃的生命力，从而让我现在眺望尚是年幼的国庆时，看到了他脸上闪烁着灰暗的衰落。','9871-9926',1,1700399032,1782398597);
INSERT INTO highlights VALUES('834467_18_7935-8089','834467',40,'抛弃','这种时候国庆在谈到他母亲时，不再因为往事过于遥远而显得淡漠。他经常说从前这个词了，从前他母亲活着的时候，他有多么多么好。他从来没有告诉我们从前幸福的具体事例，只是用不停的感叹，让我们对他模糊不清的从前羡慕不已。他开始想象他的母亲，在无依无靠的时候，这个只有九岁的孩子，想象没有面对未来，而是过早地通往了过去。','7911-8065',1,1700398642,1782398597);
INSERT INTO highlights VALUES('834467_18_3271-3418','834467',40,'抛弃','前面走着一个单薄的大孩子，他的笛声固然美妙，可他能打败国庆的父亲吗？我们三个人傻乎乎地跟着他，他发怒的样子让我们充满信心。他走到了一棵挂满雨水的树下，突然沉思起来，可是等到我们也走入树下后，他立刻抬腿猛踢一下树木，同时自己逃离了出去。树上的雨水纷纷落下，淋得我们满身都是。他却哈哈大笑地回家了。','3247-3394',1,1700385520,1782398597);
INSERT INTO highlights VALUES('834467_18_511-553','834467',40,'抛弃','过早的自由使他像扛着沉重的行李一样，扛着自己的命运，在纷繁的街道上趔趔趄趄不知去向。','487-529',1,1700384427,1782398597);
INSERT INTO highlights VALUES('834467_17_13282-13337','834467',39,'威胁','我是这时候转身离去的，像一只清晨的公鸡那样昂首阔步。我当时心里充满了罪恶的欢乐，国庆绝望的神色是我欢乐的基础。','13293-13348',1,1700354254,1782398597);
INSERT INTO highlights VALUES('834467_17_12357-12471','834467',39,'威胁','此后的时间里，我必须为自己不负责任的威胁承担后果。国庆和刘小青正如他们宣告的那样，不再理睬我。而我在实现自己的威胁时，却显得力不从心。他们是两个人，我只是一个人，问题的关键就在这里，他们可以坚定地不理我，我则是心慌意乱地不理他们','12368-12482',1,1700354211,1782398597);
INSERT INTO highlights VALUES('834467_17_11377-11463','834467',39,'威胁','我清晰地记起了当初刘小青说这话时的神态，他是将快要掉进嘴巴的鼻涕使劲一吸，吸回到鼻孔后突发奇想说这番话的。他吸鼻涕的声音十分响亮，我都能感觉到鼻涕飞入他鼻孔时滑溜溜的过程。','11388-11474',1,1700353953,1782398597);
INSERT INTO highlights VALUES('834467_17_9861-9905','834467',39,'威胁','她只是沉浸在我当时年龄还无法理解的自我与孤独之中，她站在生与死的界线上，同时被两者抛弃。','9872-9916',1,1700353763,1782398597);
INSERT INTO highlights VALUES('834467_17_9336-9414','834467',39,'威胁','里面黑白的相片让我看到了一群严肃的男女老人，竟然没有一个在微笑。老太太轻声告诉我：“他们全死了。”','9347-9425',1,1700353703,1782398597);
INSERT INTO highlights VALUES('834467_17_5621-5651','834467',39,'威胁','我突然发现了逃跑的意义，它使惩罚变得遥远，同时又延伸了快乐。','5597-5627',1,1699974267,1782398597);
INSERT INTO highlights VALUES('834467_17_2541-2623','834467',39,'威胁','接着是很细的声音，像一根线穿过针眼一样穿过了我的耳朵，她告诉我，她要是穿上潮湿的内衣就会——“立刻死掉。”','2517-2599',1,1699973913,1782398597);
INSERT INTO highlights VALUES('834467_17_2254-2313','834467',39,'威胁','我一直没有弄明白李秀英究竟得了什么病，她对阳光的热爱给了我无法磨灭的印象。这位我后来的母亲整个身体就像是一场绵绵阴雨。','2230-2289',1,1699973774,1782398597);
INSERT INTO highlights VALUES('834467_15_9647-9762','834467',36,'消失','我当时的心情十分古怪，说不准是悲哀，还是不安。我能明确意识到的，那就是一种情景将在我眼中永远消失。在傍晚的时刻，孙有元步履蹒跚地在那条小路上摇摇晃晃地出现，向我和池塘走来。我总是很远就看到了他抱在怀里的油布雨伞，和肩上的蓝布包袱。','9623-9738',1,1699972530,1782398597);
INSERT INTO highlights VALUES('834467_15_7688-7694','834467',36,'消失','“死啦，死啦','7664-7670',1,1699972309,1782398597);
INSERT INTO highlights VALUES('834467_15_7615-7659','834467',36,'消失','我父亲像是被凳子发射出去似的，蹿进了祖父的房间，过了一会十分紧张地走出来，手舞足蹈地说：','7591-7635',1,1699972304,1782398597);
INSERT INTO highlights VALUES('834467_15_7413-7482','834467',36,'消失','“你们爷爷快死啦。”他的理由是，“人和黄鼠狼一样，你要捉它时它就放个臭屁把你熏晕了，自己可以逃走。你们爷爷要逃走啦，所以那里面臭死人啦。”','7389-7458',1,1699972246,1782398597);
INSERT INTO highlights VALUES('834467_15_6185-6256','834467',36,'消失','即将收割的稻子在阳光里摇晃时，吹来的东南风里飘拂着植物的气息。我不知道祖父是否闻到了，但我祖父古怪的思维断定了自己迟迟未死和那些沉重的稻穗有关','6161-6232',1,1699972081,1782398597);
INSERT INTO highlights VALUES('834467_15_3550-3625','834467',36,'消失','在期待里躺了一夜的孙有元，翌日清晨看到孙广才走进来时，敏捷地撑起身体问他的儿子：“棺材呢？”','3526-3601',1,1699971750,1782398597);
INSERT INTO highlights VALUES('834467_14_6727-6767','834467',35,'风烛残年','孙有元当时坐在那个斑驳的墙角，用一贯的慈祥看着我，他亲切的目光在那时让我不寒而栗','6699-6739',1,1699709873,1782398597);
INSERT INTO highlights VALUES('834467_14_5112-5159','834467',35,'风烛残年','满脸通红的孙广才像个孩子那样不知疲惫地乱喊乱叫，他的喊叫如同狂风似的吹得我们弟兄三人身体抖动。','5086-5133',1,1699709718,1782398597);
INSERT INTO highlights VALUES('834467_14_4097-4126','834467',35,'风烛残年','接着我听到了哥哥幼稚的声音穿上了严肃的外套后，向我祖父走去','4071-4100',1,1699709479,1782398597);
INSERT INTO highlights VALUES('834467_14_3143-3169','834467',35,'风烛残年','他像冬天的狂风那样在我们狭窄的家中，时时会突然咆哮。','3117-3143',1,1699709345,1782398597);
INSERT INTO highlights VALUES('834467_13_5580-5635','834467',34,'遥远','然后是三个人走出家门，我祖母身穿黑衣的婆婆，将他们带到一条大路上。她指示我的祖母往西走，而她自己则走向了东面。','5556-5611',1,1699694434,1782398597);
INSERT INTO highlights VALUES('834467_10_17358-17387','834467',30,'战栗','总之当我们凶狠地对待这个世界时，这个世界突然变得温文尔雅了','17333-17362',1,1699688983,1782398597);
INSERT INTO highlights VALUES('834467_10_11879-11928','834467',30,'战栗','在我眺望昔日的时光时，在池塘旁所看到的苏宇快乐幸福的童年生活，其实如当时从水面上吹过的风一样不可靠','11852-11901',1,1699688098,1782398597);
INSERT INTO highlights VALUES('834467_8_4738-4928','834467',27,'出生','“剪刀离得远，拿起来不方便。孩子生下来还得给他洗洗。本来早就给你送饭来了，没出家门就疼了。我知道要生了，想去拿剪刀，疼得走不过去……”父亲很不耐烦地打断她的唠叨：“是男的？还是女的？”母亲回答：“是男的。”','4716-4906',1,1699674681,1782398597);
INSERT INTO highlights VALUES('834467_7_6660-6709','834467',26,'死去','翌日清晨，全家都换上了补丁遍体的衣服，仿佛鱼的鳞片一样，我们像是四条可笑的鱼，迎着旭日游出了家门。','6638-6687',1,1699664495,1782398597);
INSERT INTO highlights VALUES('834467_7_2164-2181','834467',26,'死去','他的喊叫像破碎的玻璃片一样纷纷扬扬','2142-2159',1,1699663926,1782398597);
INSERT INTO highlights VALUES('834467_7_835-976','834467',26,'死去','他走出的已经不是房屋。我的弟弟不小心走出了时间。他一旦脱离时间便固定下来，我们则在时间的推移下继续前行。孙光明将会看着时间带走了他周围的人和周围的景色。我看到了这样的真实场景：生者将死者埋葬以后，死者便永远躺在那里，而生者继续走动。这真实的场景是时间给予依然浪迹在现实里的人的暗示。','813-954',1,1699663751,1782398597);
INSERT INTO highlights VALUES('834467_6_6072-6115','834467',25,'婚礼','这位春风得意的年轻人立刻脸色惨白，我记得杂声四起的晒场在那一刻展现了声响纷纷掉落的图景','6050-6093',1,1699662760,1782398597);
INSERT INTO highlights VALUES('834467_5_9719-9786','834467',24,'南门','她经常嗑着我们家的瓜子出现在操场上，她吐瓜子壳时的放肆劲，仿佛她已经儿女成群。有一次她吐出瓜子壳以后，我看到她嘴角长时间挂着一条唾沫。','9697-9764',1,1699661337,1782398597);
