INSERT INTO highlights VALUES('25314648_3_1611-1723','25314648',3,'译序 碎语、奇迹市场或希望','她一直在强调对于世界的“我不知道”的态度：“在诗歌语言中，每一个词语都被权衡，绝无寻常或正常之物。没有一块石头或一朵石头之上的云是寻常的。没有一个白昼和白昼之后的夜晚是寻常的。总之，没有一个存在，没有任何人的存在是寻常的。”','1630-1742',NULL,1581931964,1782398674);
