INSERT INTO highlights VALUES('857883_9_6462-6535','857883',9,'［答客问］逃避现实是我唯一的内心现实','人类逃避现实的苦难是一种必然的努力倾向和本能。正视现实，并积极地介入参与到现实生活世界当中去当然是重要的，但并不能看成人类唯一的和必须作出的选择。','6462-6535',NULL,1564582852,1782398680);
