INSERT INTO highlights VALUES('857883_9_6071-6118','857883',9,'［答客问］逃避现实是我唯一的内心现实','他没有将这个世界引入个人的内在世界当中，而是将抽象的世界看作最为本质的和人类赖以逃避现实的世界','6071-6118',NULL,1564565682,1782398680);
INSERT INTO highlights VALUES('857883_9_5972-5997','857883',9,'［答客问］逃避现实是我唯一的内心现实','正是现实世界的变动不居，导致人类的持续焦虑与恐惧。','5972-5997',NULL,1564565654,1782398680);
INSERT INTO highlights VALUES('857883_9_5393-5498','857883',9,'［答客问］逃避现实是我唯一的内心现实','什么叫“有意义”？都是胡扯！不过是自欺欺人而已。人活着只不过是你生下来了，你不得不活着，除非你自杀掉拉倒。你说有什么意义可言？一切“意义”化的说辞都是某种利益集团为了达成一个特别的目的而故意制造出来的一套谎言。','5393-5498',NULL,1564565606,1782398680);
INSERT INTO highlights VALUES('857883_9_3905-4036','857883',9,'［答客问］逃避现实是我唯一的内心现实','我们的头脑当中总是有一个特别强烈的固执的“是”和“非”的分别，而很少有一个“有”和“无”的观念。“是”就是好的，就是正确的；其他的就是坏的，反动的，就是个贬义词。这种简单二元的不由分说的是非观就像一种病毒程序一样输入了我们的头脑，进而成为我们判断一切的基本指令。','3905-4036',NULL,1564564817,1782398680);
