INSERT INTO highlights VALUES('27001575_87_0-235','27001575',87,'一生的诗','小时候    写的诗    像一条叮叮咚咚的小河    淘气极了    少年时    写的诗    像一只闪闪的飞鸟    在一棵树上撒娇    青年时    写的诗    像一只花豹    在一座森林里奔跑    中年时    写的诗    像一只黑色的岩鹰    尖利的爪把岩石抓成碎屑    人老了    诗也老了    老年写的诗不再动了    像一束生日的烛光    在静静地闪耀','0-235',NULL,1601727898,1782398660);
