INSERT INTO highlights VALUES('27001575_80_112-370','27001575',80,'红金鱼橡皮','小马虎的作业    潦草得像一蓬水草    红金鱼游去了    小肚子吃得真饱    小玲玲的作业    整齐得像一畦禾苗    红金鱼游去了    小肚子饿得咕咕叫    红金鱼吃饱了    就躺在文具盒里睡觉    小风叫不醒它    它感到太累了    红金鱼吃掉的错别字有多少    连它自己也不知道    奇怪的是它的小肚子    反而越吃越小    有一天    红金鱼不见了    可在小朋友的作业本里    都能发现它的微笑','112-370',NULL,1601727471,1782398660);
