INSERT INTO highlights VALUES('27001575_24_0-327','27001575',24,'一朵甜美的笑','孩子，你没有什么给我    只给我一朵甜美的笑    我担心，那笑从我的手心飞走    会变成一只会唱歌的小鸟    孩子，你没有什么给我    只给我一朵甜美的笑    我担心，那笑从我的指缝漏掉    会变成一株开紫花的小草    孩子，你没有什么给我    只给我一朵甜美的笑    我担心，那笑从我的布兜溜走    会变成一只蝈蝈又蹦又跳    孩子，你没有什么给我    只给我一朵甜美的笑    我担心，那笑落入一条小河    会变成一条鱼儿游进波涛    孩子，你没有什么给我    只给我一朵甜美的笑    那笑轻轻抖落在我的心上    像碎碎的银子在幸福地闪耀','0-327',NULL,1601646005,1782398660);
