INSERT INTO highlights VALUES('38084989_103_1577-1662','38084989',103,'流星坠落的地方','还有，树木不会遇到何去何从的繁难选题，无论是人为还是偶然，只要坚守在诞生地就能吸收无穷无尽的营养、接受明媚的阳光，轻松生活。只要仰望着天空繁衍就好。这不是比什么都幸福吗？','1577-1662',1,1738826020,1782398550);
