INSERT INTO highlights VALUES('38084989_26_561-1051','38084989',26,'路','丢了啊也不知丢了什么也不知丢在了哪里走在路上两只手在口袋里摸索石头 一个连一个的石头无边无际道路沿着幽深的石墙伸向远方石墙上铁门紧闭在路上印出狭长的阴影道路从清晨通向夜晚又从夜晚通向黎明摸索着石墙 潸然泪下仰望 天空蓝得让人惭愧行走在这寸草不生的路上那是因为我 留在了石墙的另一侧我活着 只是为了寻找丢失的所有','561-1051',1,1738575453,1782398550);
