INSERT INTO highlights VALUES('25631683_7_3132-3171','25631683',7,'父亲和船','可在我出生之前，二女河就干涸了，裸露的河床像掉了牙齿的瘪嘴，气泡都冒不出一个。','3132-3171',NULL,1658907547,1782398640);
INSERT INTO highlights VALUES('25631683_6_24733-24819','25631683',6,'天上人间','那个午后，阳光犹犹豫豫的，似乎揣着很大的心思。老汉被光晕吞没，布满沟壑的脸犹如残壁，稍稍一捅，便会坍塌掉。而褐色的脖子则如没有燃透的枯木，里里外外透着焦煳味。姚百万别过头。','24733-24819',NULL,1658832767,1782398640);
INSERT INTO highlights VALUES('25631683_6_2016-2088','25631683',6,'天上人间','男人后脑勺卧着三个大大的旋儿。俗话说一个旋愣，两个旋硬，三个旋打架不要命。姚百万不由得一抖，大馅儿饼砸到脸上的喜悦被突然而至的疑问扫得干干净净。','2016-2088',NULL,1658760637,1782398640);
