INSERT INTO highlights VALUES('25631683_5_15367-15409','25631683',5,'双向道','他知道秃子不认账，他需要秃子不认，这样就可以一趟趟找秃子，就可以一次次给孟鹰打电话。','15367-15409',NULL,1658734712,1782398640);
INSERT INTO highlights VALUES('25631683_5_15210-15249','25631683',5,'双向道','孟鹰苦笑着叹口气。事与愿违，一直如此。想维系的总会断掉，想挣脱的总咬着他不放。','15210-15249',NULL,1658734561,1782398640);
INSERT INTO highlights VALUES('25631683_5_15255-15286','25631683',5,'双向道','孟灯第一次进城住了五天，那五天却毁了孟鹰苦心经营了六年的婚姻。','15255-15286',NULL,1658734551,1782398640);
INSERT INTO highlights VALUES('25631683_5_10892-10949','25631683',5,'双向道','孟鹰不抱期望，因为他的人生就是一个泥潭。他从未从那里走出来。他曾经以为走出来了，后来明白，那不过是时钟暂停的错觉。','10892-10949',NULL,1658733674,1782398640);
INSERT INTO highlights VALUES('25631683_5_8951-9033','25631683',5,'双向道','看着沉沉昏睡的孟燕，孟灯动了放弃的念头。五百元，倒有一张是假的，是有些憋屈，况且卖的是孟燕的伙伴黑头。但让孟燕跟着遭罪，那就不划算了。他心疼那一百块钱，更心疼孟燕。','8951-9033',NULL,1658733149,1782398640);
INSERT INTO highlights VALUES('25631683_5_7479-7500','25631683',5,'双向道','去秃子家的路上，孟灯想，或许不该找吴老三。','7479-7500',NULL,1658732880,1782398640);
INSERT INTO highlights VALUES('25631683_5_126-143','25631683',5,'双向道','黑头如一卷破行李，被秃子夹在腋下。','126-143',NULL,1658731594,1782398640);
INSERT INTO highlights VALUES('25631683_4_34113-34149','25631683',4,'容器','不知道警察读懂他的眼神没有，我读懂了。我颤了颤，心底一片车轮碾过的声响。','34113-34149',NULL,1658646850,1782398640);
INSERT INTO highlights VALUES('25631683_4_33498-33696','25631683',4,'容器','我脑门上的青筋嘣嘣乱跳，紧张、害怕，还有一点儿不可告人的兴奋。我处在一个十字路口，站在警察一边还是站在赵小川一边？如果站在警察一边，我会就自己所知如实相告，赵小川定会有牢狱之灾，我可以乘机甩掉这个包袱。如果站在赵小川一边，可一推三不知，证据不充分，赵小川就不会有太多问题。毕竟，他是我儿子，我和刘小艾的儿子。    面临抉择，我左右为难。如果只是包袱，或只是儿子……可他是儿子和包袱的混合体。','33498-33696',NULL,1658646787,1782398640);
INSERT INTO highlights VALUES('25631683_4_32440-32465','25631683',4,'容器','赵小川的话麻绳一样一圈一圈缚着我，我不由自主地缩着','32440-32465',NULL,1658646645,1782398640);
INSERT INTO highlights VALUES('25631683_4_29439-29471','25631683',4,'容器','那些疙瘩没有安静地窝着，而是不停地繁殖撕扯挤压，胀得我极其难受。','29439-29471',NULL,1658646237,1782398640);
INSERT INTO highlights VALUES('25631683_4_28256-28282','25631683',4,'容器','我和刘小艾悄悄交换眼神儿，结果被彼此眼底的哀愁撞开。','28256-28282',NULL,1658646075,1782398640);
