INSERT INTO highlights VALUES('25631683_3_13316-13408','25631683',3,'苦水淖','我更喜欢六指自己说。纸上的数字是死的，就像封冻的河，要窥见冰层下的秘密，得有特殊本事。而嘴巴和眼睛是活的，更像河水，尽管鱼仍在下面，窥视就容易多了。我盯着六指，就能判断六指有没有说谎。','13316-13408',NULL,1658536218,1782398640);
