INSERT INTO highlights VALUES('3300020364_45_393-776','3300020364',218,'短的一生，长的一瞬','有些事是你不知道的例如那个夏末的清晨我曾用一秒钟回头看你走在湖边的背影那在香樟树下和阳光一起微笑的眼睛吹过脸颊的风那些洒在湖上的金子都是我说不出的感觉我想我会用短短的一生怀念那长长的一瞬','522-845',NULL,1664075306,1782398634);
