INSERT INTO highlights VALUES('3300020364_10_388-762','3300020364',183,'月光如雪','有些很美好的事物只有独自一人的时候才会遇见没有人相信我心里藏着很多月光仰着头的时候月光如雪沁入肺腑我的心，被月光照得多么明亮可是要在很深很黑的夜站得很近很近的人才能看见','517-831',NULL,1664072779,1782398634);
