INSERT INTO highlights VALUES('23485007_21_32038-32118','23485007',23,'第21章 番外之两个人：未来得及看清的你，未来得及说再见的我','我们怀着美好的希望，勇敢地走着，跌倒了再爬起，失败了就再努力，永远相信明天会更好，永远相信不管自己再平凡，都会拥有属于自己的幸福，这才是平凡人生中最灿烂的风景。','45260-45340',NULL,1659420706,1782398637);
INSERT INTO highlights VALUES('23485007_21_32009-32032','23485007',23,'第21章 番外之两个人：未来得及看清的你，未来得及说再见的我','真正点亮生命的不是明天的景色，而是美好的希望。','45212-45235',NULL,1659420642,1782398637);
INSERT INTO highlights VALUES('23485007_21_31945-32003','23485007',23,'第21章 番外之两个人：未来得及看清的你，未来得及说再见的我','但那并不重要，重要的是明天之后还有明天，只要生命没有结束，永远有下一个明天，永远可以希望着下一刻就是我们想要的幸福。','45129-45187',NULL,1659420623,1782398637);
INSERT INTO highlights VALUES('23485007_20_7139-7247','23485007',22,'第20章 尾声 宽恕的美丽','只要曾经年少，每个人都会在心底深处为逝去的青春留一点柔软。在沧桑流年的某个间隙，眼中会忽然掠过一缕莫名的黯然，在似曾相识的风景前，心头会蓦然升起一段无名的惆怅。但这些黯然与惆怅，并不意味着他们想和那些记忆中的人重逢。','10343-10451',NULL,1659412991,1782398637);
INSERT INTO highlights VALUES('23485007_20_3496-3527','23485007',22,'第20章 尾声 宽恕的美丽','在十年后，她才懂得一个道理，心里想的必须要说出来，人家才会知道','5263-5294',NULL,1659412318,1782398637);
INSERT INTO highlights VALUES('23485007_19_25117-25148','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','请相信，青春的逝去并不可怕，可怕的是失去了勇敢地热爱生活的心。','34859-34890',NULL,1659409886,1782398637);
INSERT INTO highlights VALUES('23485007_19_25058-25111','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','青春的可贵并不是因为那些年轻时光，而是那颗盈满了勇敢和热情的心，不怕受伤，不怕付出，不怕去爱，不怕去梦想。','34781-34834',NULL,1659409878,1782398637);
INSERT INTO highlights VALUES('23485007_19_24808-24877','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','水龙头哗哗地流着，在下水口处形成了一个旋转的水涡，褐色的泥水带着过去的气息，眷念地打着圈，却被干净的新水冲得快速流走，越来越淡，渐渐消失。','34436-34505',NULL,1659409764,1782398637);
INSERT INTO highlights VALUES('23485007_19_22313-22411','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','似乎亦舒说过一句话，男人爱一个女人时会觉得她又小又笨又可怜，需要事事操心；不爱一个女人时，就觉得她又聪明又强悍，根本无须自己关心。这句话其实不仅仅适用于男女之间的感情，还适用于一切爱与被爱的关系。','30953-31051',NULL,1659409448,1782398637);
INSERT INTO highlights VALUES('23485007_19_16416-16501','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','中国的高考很残酷，不仅仅是指它竞争的激烈，而是它只看最终一刻结果的残酷，不像国外，申请大学需要看综合表现，而中国，不管以前的成绩有多辉煌，这一刻没有成功，就一切都被否认。','22968-23053',NULL,1659408703,1782398637);
INSERT INTO highlights VALUES('23485007_19_14256-14281','23485007',21,'第19章 那盛大的告别：烟花盛放之后，心怀余热告别绚烂17岁','天行健，君子以自强不息；地势坤，君子以厚德载物’！','19845-19870',NULL,1659408410,1782398637);
INSERT INTO highlights VALUES('23485007_18_18475-18596','23485007',20,'第18章 两个人的对视：我们都会冷战，都会妥协，只是不会说出爱','“Men heap together the mistakes of their lives, and create a monster they call destiny.”    人们将生命中的错误聚集到一起，创造出一个恶魔，叫命运。','25607-25746',NULL,1659405828,1782398637);
INSERT INTO highlights VALUES('23485007_15_13614-13682','23485007',17,'第15章 那些鲜艳色彩：我导演年少的戏曲，他导演我们的爱情','为什么年少时的爱，单纯却笨拙，诚挚却尖锐？为什么当我们不懂爱的时候，爱得最无所保留，而当我们懂得如何去爱的时候，却已经不愿意再轻易付出？','18295-18363',NULL,1659341057,1782398637);
INSERT INTO highlights VALUES('23485007_15_1939-2023','23485007',17,'第15章 那些鲜艳色彩：我导演年少的戏曲，他导演我们的爱情','上天是很公平的，人得到一些，注定就会失去一些，有时候失去是为了得到，有时候得到意味着失去，这世界上没有人什么都有，所以，永远不要羡慕他人所有，而是要学会珍惜自己所有。”','2959-3043',NULL,1659338778,1782398637);
INSERT INTO highlights VALUES('23485007_9_15317-15372','23485007',11,'第9章 青春的代价','成年人不管犯多大的错，都是自己结的果。    可少年，他们的错误，常常一半源自父母，一半源于对生命的无知。','20941-21015',NULL,1659254957,1782398637);
INSERT INTO highlights VALUES('23485007_8_584-634','23485007',10,'第8章 与文艺有关','我就像一根绷紧的皮筋，本来紧张地准备全力弹出，却没有弹，只是慢慢地、慢慢地松了力量，不为人知地懈了。','1261-1311',NULL,1659245464,1782398637);
INSERT INTO highlights VALUES('23485007_6_19304-19316','23485007',8,'第6章 似曾风雨路','刘希夷的《代悲白头翁》。','25644-25656',NULL,1659166431,1782398637);
INSERT INTO highlights VALUES('23485007_6_19322-19602','23485007',8,'第6章 似曾风雨路','洛阳城东桃李花，飞来飞去落谁家？    洛阳女儿好颜色，行逢落花长叹息。    今年花落颜色改，明年花开复谁在？    已见松柏摧为薪，更闻桑田变成海。    古人无复洛城东，今人还对落花风。    年年岁岁花相似，岁岁年年人不同。    寄言全盛红颜子，应怜半死白头翁。    此翁白头真可怜，伊昔红颜美少年。    公子王孙芳树下，清歌妙舞落花前。    光禄池台文锦绣，将军楼阁画神仙。    一朝卧病无相识，三春行乐在谁边？    宛转蛾眉能几时，须臾鹤发乱如丝。    但看古来歌舞地，唯有黄昏鸟雀悲。','25683-26215',NULL,1659166425,1782398637);
INSERT INTO highlights VALUES('23485007_6_4617-4710','23485007',8,'第6章 似曾风雨路','成长，如同参加跑步比赛。看到别人比自己跑得快时并不一定会着急悲伤，唯有被同一起跑线上的人日渐超越时，才会着急伤悲。也许你不会记得那些已远远落在后面的人，可你会永远记得那个跑在你前面的人。','6086-6179',NULL,1659097497,1782398637);
