INSERT INTO highlights VALUES('23485007_5_5167-5280','23485007',7,'第5章 平淡不平淡','男人的友谊大概就如踢足球，底线和规矩，都心中了然，合作与较量清楚分明，争斗呐喊中，融会着彼此的汗水；女人的友谊大概就如烹制菜肴，没有定式、没有规矩、酸甜苦辣，皆可入菜，滋味可以复杂到除了烹制者，没有人知道她究竟往里面放了什么。','6826-6939',NULL,1659083116,1782398637);
INSERT INTO highlights VALUES('23485007_4_3678-3730','23485007',6,'第4章 懵懂的感情','我们和其他行星相遇、碰撞，这些碰撞无可避免地会影响到我们运行的轨迹，有些影响是正面的，有些影响是负面的。','4963-5015',NULL,1659073505,1782398637);
