INSERT INTO highlights VALUES('3300027195_30_429-692','3300027195',30,'长途','一条白热的长途伸向旷野的边上，像一条重的扁担压上挑夫的肩膀。几丝持续的蝉声牵住西去的太阳，晒得垂头的杨柳呕也呕不出哀伤。','429-692',1,1691896954,1782398607);
