INSERT INTO highlights VALUES('3300027195_22_429-891','3300027195',22,'新秋','我道是谁呀，灰淡的白云下轻轻打着哨，摸摸墙头草又拉拉牵牛花，一见我便溜，那么样害羞！原来是你呵，一夜雨刚停住，我还在床上，你早来唱唱又摇摇那小树，等我走出来，一笑又走开。','429-891',1,1691852193,1782398607);
