INSERT INTO highlights VALUES('3300027195_21_397-782','3300027195',21,'倦','倦忙碌的蚂蚁上树，蜗牛寂寞的僵死在窗槛上看厌了，看厌了；知了，知了只叫人睡觉。蟪蛄不知春秋，可怜虫亦可以休矣！至多像残余的烟蒂头在绿苔地上冒一下蓝烟吧？被时光遗弃的华梦该闭在倦眼的外边了。','397-782',1,1691852090,1782398607);
