INSERT INTO highlights VALUES('3300027195_9_431-854','3300027195',9,'西长安街','长的是斜斜的淡淡的影子，枯树的，树下走着的老人的和老人撑着的手杖的影子，都在墙上，晚照里的红墙上，红墙也很长，墙外的蓝天，北方的蓝天也很长，很长。啊！老人，这道儿你一定觉得是长的，这冬天的日子也觉得长吧？是的，我相信。看，我也走近来了，真不妨一路谈谈话，谈谈话儿呢。','431-854',1,1691851368,1782398607);
