INSERT INTO highlights VALUES('3300058588_285_354-928','3300058588',473,'篱笆院','篱笆院我向父亲讲述这些年来的外地生活大多的时候，我在说父亲在听偶尔父亲会把一句话夹在我的话语中间仿佛父子俩面对面地扎着一道看不见的篱笆我的话是那些一直排列着的枝条父亲的话则是不远处就砸下的一根木桩我们配合默契地一直扎着，扎着扎着扎着父亲突然停了下来然后轻轻打响了鼾声。我知道篱笆墙到了该留下大门的地方了我把一条毛毯轻轻地盖在父亲身上仿佛我轻轻关上了篱笆院的大门阳光温暖地照着，篱笆院里的父子俩','355-929',2,1690729664,1782398613);
INSERT INTO highlights VALUES('3300058588_279_766-851','3300058588',467,'父子','这就是生活有时学会一个动作却要耗尽另一个人，一生的等待','767-852',2,1690729349,1782398613);
INSERT INTO highlights VALUES('3300058588_278_388-542','3300058588',466,'独坐草间','如果我的父母在天上水里应该有他们的倒影如果在地下树上应该有他们的嫩芽可是没有','389-543',2,1690729284,1782398613);
INSERT INTO highlights VALUES('3300058588_257_505-612','3300058588',445,'抱偏瘫的母亲过水坑','母亲在长久的等待中像水果耗尽了自己的糖分','506-613',2,1690728457,1782398613);
INSERT INTO highlights VALUES('3300058588_254_754-870','3300058588',442,'扉页','从未想过母亲会像一本书的扉页在长期的阅读习惯中一直被我忽略','755-871',2,1690728353,1782398613);
INSERT INTO highlights VALUES('3300058588_231_922-1085','3300058588',419,'傍晚，在河边','此刻，我只想做一层冰用表面的坚强掩盖深处的软弱掩盖涌动的激情让它们沿着表面的惯性一点一点地变硬','923-1086',2,1690708669,1782398613);
INSERT INTO highlights VALUES('3300058588_216_760-878','3300058588',404,'故乡月','那时父亲取出的火柴是唯一推开夜的黑抽屉轻轻一划所有的童年就亮了','761-879',2,1690708203,1782398613);
INSERT INTO highlights VALUES('3300058588_216_532-622','3300058588',404,'故乡月','嫦娥也是俏皮的小丫头两个牛角小辫上的红头绳遗落在刚刚路过的晚霞里','533-623',2,1690708195,1782398613);
INSERT INTO highlights VALUES('3300058588_216_387-470','3300058588',404,'故乡月','当农活闲下来月亮也不再慌里慌张悠然地揣着云朵的口袋','388-471',2,1690708186,1782398613);
INSERT INTO highlights VALUES('3300058588_200_354-842','3300058588',388,'梦','梦在电话里，女儿大哭骗人，我没有梦到妈妈连爸爸也没有梦到妻子抬头看我泪在眼眶里打转我故作轻松地吹了声口哨其实最不可靠的就是梦了离家时我们答应到女儿的梦里去却一次也没有启程倒是五岁的女儿，不远千里一次次跑到我和妻子的梦里来','355-843',2,1690707684,1782398613);
INSERT INTO highlights VALUES('3300058588_197_938-993','3300058588',385,'请原谅','伸手不见五指时仍有星星在闪耀生活之重从不重于生命本身','939-994',2,1690707614,1782398613);
INSERT INTO highlights VALUES('3300058588_193_389-547','3300058588',381,'春天的车轮','三年了，三个春天如同横梗在路上的三块石头这辆马车每颠簸一次车上就会掉下一些花样的人群','390-548',2,1690707393,1782398613);
INSERT INTO highlights VALUES('3300058588_190_10592-10683','3300058588',378,'自序 文学拯救了我','只能像钟摆一样让爱在爱里就像时间在时间里自然而然，嘀嘀嗒嗒','10596-10687',2,1690707227,1782398613);
INSERT INTO highlights VALUES('3300058588_190_7784-8214','3300058588',378,'自序 文学拯救了我','从空气里赶出风从风里赶出刀子从骨头里赶出火从火里赶出水赶时间的人没有四季只有一站和下一站世界是一个地名王庄村也是每天我都能遇到一个个飞奔的外卖员用双脚锤击大地在这个人间不断地淬火','7808-8238',2,1690707083,1782398613);
INSERT INTO highlights VALUES('35172617_7_4439-4463','35172617',68,'第2章 辨别孩子的优势与不足','表2-1　需要具备执行技能的发展型任务[插图]','4385-4404',NULL,1659747557,1782398636);
INSERT INTO highlights VALUES('35172617_7_4021-4202','35172617',68,'第2章 辨别孩子的优势与不足','也有可能你的孩子在学校里表现尚可，在家里表现却不那么好，这正是你要读本书的原因。出现这种情况的原因有很多，例如，家庭环境不如学校那么井井有条，家里可能出现更多给孩子带来压力的因素（如兄弟姐妹之间可能相互打闹，惹得对方心烦）；或者，你对执行技能的期望与孩子的发展现状不同步（要么太高，要么太低）。另外，你自己的执行技能的不足甚至使孩子觉得家里是一个更难待下去的地方','3974-4155',NULL,1659747524,1782398636);
INSERT INTO highlights VALUES('35172617_6_14947-15017','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','如果孩子患有注意缺陷/多动障碍，某些执行技能将受到损害。受损害的技能主要是反应抑制、保持专注、工作记忆、时间管理、着手做事和咬定目标不放松。','14851-14921',NULL,1659746635,1782398636);
INSERT INTO highlights VALUES('35172617_6_14046-14107','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','除了界限与限制，家长还开始教学生一些替代的行为（如爱抚家里的猫咪而不是扯她的尾巴，在跟同伴玩耍发生冲突时讲道理而不是打人）','13963-14024',NULL,1649893608,1782398636);
INSERT INTO highlights VALUES('35172617_6_13689-13803','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','反应抑制这项技能有多么重要：如果没有它，不但十分危险，还常常导致与权威产生冲突。当你的孩子还是个婴儿时，特别是一旦他能够爬行时，你要给他设定一些界限和限制，使用大门、房门、儿童安全锁，以及简单地把许多危险物品放在他拿不到的地方等','13607-13721',NULL,1649893540,1782398636);
INSERT INTO highlights VALUES('35172617_6_13228-13254','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','但在6个月到12个月期间，婴儿抑制反应的能力急剧提升','13147-13173',NULL,1649893483,1782398636);
INSERT INTO highlights VALUES('35172617_6_13192-13214','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','当婴儿在大约6个月大发展反应抑制这项技能时，','13111-13133',NULL,1649893475,1782398636);
INSERT INTO highlights VALUES('35172617_6_13043-13075','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','能够对某个人或某一事件给予反应或者不给予反应，是控制行为的关键。','12963-12995',NULL,1649893466,1782398636);
INSERT INTO highlights VALUES('35172617_6_12596-12689','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','对婴儿，你可以提供控制性的、“因果关系”的玩具，这样，当婴儿做出某个动作（比如猛击它）的时候，玩具便会做某件事情（例如移动或发出声音）。或者，你可以让某个玩具“消失”，然后让婴儿去寻找。','12518-12611',NULL,1649893302,1782398636);
INSERT INTO highlights VALUES('35172617_6_11978-12000','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','婴儿五六个月大时形成的一项新技能是工作记忆，','11902-11924',NULL,1649893227,1782398636);
INSERT INTO highlights VALUES('35172617_6_10267-10305','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','对父母和老师来说，儿童时期是帮助强化孩子学习与发展执行技能的至关重要的机会。','10219-10257',NULL,1649743826,1782398636);
INSERT INTO highlights VALUES('35172617_6_9683-9736','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','在这个时期，额叶中出现了“不用则废”的过程。也就是说，使用中的神经连接就保留下来，没有得到运用的就被废弃。','9638-9691',NULL,1649743712,1782398636);
INSERT INTO highlights VALUES('35172617_6_8950-8990','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','在孩子11～12岁开始出现第二个灰质显著增长时期之前，孩子的心理技能继续得到巩固','8894-8934',NULL,1649743499,1782398636);
INSERT INTO highlights VALUES('35172617_6_8811-8834','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','。起初的增长出现在儿童时期的快速学习和体验阶段','8756-8779',NULL,1649743488,1782398636);
INSERT INTO highlights VALUES('35172617_6_8755-8811','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','在儿童5岁之前，脑灰质（指神经元，特别是突触）的增加达到顶峰，接下来，神经元的连接开始缓慢减少，或者称为“修剪”','8700-8756',NULL,1649743482,1782398636);
INSERT INTO highlights VALUES('35172617_6_7940-7999','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','不过，假如孩子身上的“生物设备”基本正常，而且不存在基因方面的缺陷或环境因素导致的创伤，那么大脑的发育可以正常地进行。','7901-7960',NULL,1649743208,1782398636);
INSERT INTO highlights VALUES('35172617_6_6295-6344','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','情绪控制能力较差，那么，在他发现弟弟坐在他的飞机模型上时，你要设法帮助他跟弟弟讲道理而不是动拳头。','6246-6295',NULL,1649742850,1782398636);
INSERT INTO highlights VALUES('35172617_6_6222-6288','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','例如，若你的孩子工作记忆能力较弱，那你会努力为孩子想一些办法，帮助他更加可靠地获取关键信息（比如，她必须把哪些家庭作业从学校带回家）','6173-6239',NULL,1649742834,1782398636);
INSERT INTO highlights VALUES('35172617_6_3904-3923','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','许多认知和行为困难，源于缺乏执行技能。','3838-3857',NULL,1649742496,1782398636);
INSERT INTO highlights VALUES('35172617_6_3277-3322','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','执行技能是你的孩子将你对他未来的期望和梦想（或者是他自己的期望和梦想）变成现实所需的技能。','3226-3271',NULL,1649310911,1782398636);
INSERT INTO highlights VALUES('35172617_6_2146-2208','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','当他们需要整理自己的输出时，也就是说，当他们要确定在什么时候做什么事情并且需要控制自己的行为以便把事情做好时，麻烦就出现了。','2112-2174',NULL,1649310738,1782398636);
INSERT INTO highlights VALUES('35172617_6_2277-2305','35172617',67,'第1章 聪明的孩子怎么会到头来如此混乱','因为你的孩子尽管有智力，但缺乏最好地利用智力的执行技能。','2243-2271',NULL,1649310718,1782398636);
INSERT INTO highlights VALUES('35172617_4_5114-5152','35172617',65,'引言','你不能只是关注你和孩子之间的吻合度，孩子与他身边的环境之间的吻合度也很重要。','5078-5116',NULL,1648944371,1782398636);
INSERT INTO highlights VALUES('35172617_4_4492-4581','35172617',65,'引言','孩子在生物学上发展与提升执行技能的能力，早在孩子出生之前就已确定，但孩子是不是能发挥出发展与提升那些技能的潜力，很大程度上取决于环境。身为父母的你，是孩子成长环境的重要组成部分。','4459-4548',NULL,1648944284,1782398636);
INSERT INTO highlights VALUES('35172617_4_3195-3222','35172617',65,'引言','孩子拥有比你想象的更出色的自控、决策和解决问题的技能。','3164-3191',NULL,1648655148,1782398636);
INSERT INTO highlights VALUES('35172617_4_1358-1400','35172617',65,'引言','孩子的大脑培育和提高执行技能的基础，早在他出生之前就已经打下，你无法控制这种生物能力','1330-1372',NULL,1648654889,1782398636);
INSERT INTO highlights VALUES('35172617_4_1074-1228','35172617',65,'引言','大多数聪明却混乱的孩子都缺乏一些思维习惯，这些习惯被称为执行技能（executive skill）。这些基于大脑的根本技能，是执行下面这些任务时所必需的：整理物品、制订计划、着手做事、专注做事、控制冲动、掌控情绪、具备适应能力和灵活性等，而且做这些事情几乎是每个孩子在学校、家里以及和朋友在一起时的基本要求。','1047-1201',NULL,1648654784,1782398636);
INSERT INTO highlights VALUES('35172617_4_1017-1058','35172617',65,'引言','你的孩子也许很想做他需要做的事情，也具备做好这些事情的潜力，但就是不知道该怎么做。','990-1031',NULL,1648654767,1782398636);
INSERT INTO highlights VALUES('3300025707_49_453-478','3300025707',49,'38 幸灾乐祸','灾难如果发生在我们的敌人头上，我们很难不幸灾乐祸。','453-478',1,1723776343,1782398561);
INSERT INTO highlights VALUES('3300025707_48_2791-2825','3300025707',48,'37 吃相','他们都是自食其力的人，心里坦荡荡的，饿来吃饭，取其充腹，管什么吃相！','2791-2825',1,1723776329,1782398561);
INSERT INTO highlights VALUES('3300025707_45_3199-3256','3300025707',45,'34 代沟','沟是死的，人是活的！代沟需要沟通，不能像希腊神话中的亚历山大以利剑砍难解之绳结那样容易的一刀两断，因为人终归是人。','3199-3256',1,1723774522,1782398561);
INSERT INTO highlights VALUES('3300025707_39_451-520','3300025707',39,'28 谦让','可以无须让的时候，则无妨谦让一番，于人无利，于己无损；在该让的时候，则不谦让，以免损己；在应该不让的时候，则必定谦让，于己有利，于人无损。','451-520',1,1723722244,1782398561);
INSERT INTO highlights VALUES('3300025707_38_1195-1249','3300025707',38,'辑四 我对生活有诸多意见','人总要主动去捍卫一些事，否则你就会轻易地盲从。','1195-1249',1,1723713575,1782398561);
INSERT INTO highlights VALUES('3300025707_32_1246-1359','3300025707',32,'22 蚊子与苍蝇','（一）蚊子奏细乐；（二）我挥手致敬；（三）乐止；（四）休息片刻；（五）是我不当心，皮肤碰了蚊子的嘴，奇痛；（六）蚊子奏乐；（七）我挥手送客；（八）我痒；（九）我抓；（十）我还痒；（十一）我还抓；（十二）出血；（十三）我睡着了。','1246-1359',1,1723712637,1782398561);
INSERT INTO highlights VALUES('3300025707_32_1181-1208','3300025707',32,'22 蚊子与苍蝇','过了一天非人的生活了，到了夜晚想做一件人做的事，睡觉。','1181-1208',1,1723712622,1782398561);
