INSERT INTO highlights VALUES('3300025707_15_4810-4850','3300025707',15,'07 流行的谬论','其实干一行应该爱一行才对。因为没有一行没有乐趣，至少一件工作之完满地完成便是乐趣','4810-4850',1,1723685484,1782398561);
INSERT INTO highlights VALUES('3300025707_14_1471-1477','3300025707',14,'06 骂人的艺术','四　旁敲侧击','1471-1477',1,1723683199,1782398561);
INSERT INTO highlights VALUES('3300025707_14_1235-1280','3300025707',14,'06 骂人的艺术','假如你骂一个无关痛痒的人，你越骂他他越得意，时常可以把一个无名小卒骂出名了，你看冤与不冤？','1235-1280',1,1723683142,1782398561);
INSERT INTO highlights VALUES('3300025707_14_1172-1197','3300025707',14,'06 骂人的艺术','你骂大人物，就怕他不理你，他一回骂，你就算骂着了。','1172-1197',1,1723683133,1782398561);
INSERT INTO highlights VALUES('3300025707_12_774-802','3300025707',12,'04 悲观','人生即是一串痛苦所构成。能避免一分的苦痛，即是一分的幸福','774-802',1,1723682277,1782398561);
