INSERT INTO highlights VALUES('23606759_42_569-618','23606759',42,'035 但愿来生我们终日在一起','世上的事都是这样的，你如向人请求点恩惠，人家便将白眼报之，要是请他打一记耳光，人家便会欣然应命的。','569-618',NULL,1582196714,1782398681);
INSERT INTO highlights VALUES('23606759_40_546-599','23606759',40,'033 要是世上只有我们两个人多好','当我看见一个眼睛似乎很贪馋，走路东张西望，时常踩在人家脚上，嘴里似乎喃喃自语的老头子，我就认识，这就是我。','546-599',NULL,1582196502,1782398681);
INSERT INTO highlights VALUES('23606759_35_675-737','23606759',35,'028 我希望你永远待我好','不要愁老之将至，你老了一定很可爱。而且，假如你老了十岁，我当然也同样老了十岁，世界也老了十岁，上帝也老了十岁，一切都是一样。','675-737',NULL,1582196106,1782398681);
INSERT INTO highlights VALUES('23606759_30_1160-1316','23606759',30,'023 特此警告','人们的走路姿式，大可欣赏，有一位先生走起路来身子直僵僵，屁股凸起；有一位先生下脚很重，走一步路全身肉都震动；有一位先生两手反绑，脸孔朝天，皮鞋的历笃落，像是幽灵行走；有一位先生缩颈弯背，像要向前俯跌的样子；有的横冲直撞，有的摇摇摆摆，有的自得其乐；有一位女士歪着头，把身体一扭一扭地扭了过去，似乎不是用脚走的样子','1160-1316',NULL,1582195428,1782398681);
INSERT INTO highlights VALUES('23606759_27_1168-1227','23606759',27,'021 我爱你也许并不为什么理由','我爱你也许并不为什么理由，虽然可以有理由，例如你聪明，你纯洁，你可爱，你是好人等，但主要的原因大概是你全然适合我的趣味','1168-1227',NULL,1581931695,1782398681);
INSERT INTO highlights VALUES('23606759_27_1260-1285','23606759',27,'021 我爱你也许并不为什么理由','你愿意恨我吗？即使你愿意恨我，我也不愿意被你恨的。','1260-1285',NULL,1581931678,1782398681);
INSERT INTO highlights VALUES('23606759_27_894-953','23606759',27,'021 我爱你也许并不为什么理由','臭虫报告了春天的消息，昨天在被中发现一个，小小心心用纸儿将它裹了，我碰一碰它就怕，觉得浑身臭虫在爬，恶心死人。愿你笑！','894-953',NULL,1581931622,1782398681);
INSERT INTO highlights VALUES('23606759_27_859-893','23606759',27,'021 我爱你也许并不为什么理由','跟他们大人我讲不来话，因为我太小了，跟小人儿又讲不来话，因为我太大了','859-893',NULL,1581931608,1782398681);
INSERT INTO highlights VALUES('23606759_25_811-912','23606759',25,'019 我并不真怪你','你一定不要害怕未来的命运，有勇气把眼睛睁得大大的，凝视一切；没勇气闭上眼睛，信任着不可知的势力拉着你走，幸福也罢，不幸也罢，横竖结局总是个The end。等我们走完了生命的途程，然后透过一口气相视而笑。','811-912',NULL,1581931487,1782398681);
INSERT INTO highlights VALUES('23606759_23_1030-1127','23606759',23,'017 我是属于你，永远而且完全地','如果我想要做一个梦，世界是一片大的草原，山在远处，青天在顶上，溪流在足下，鸟声在树上，如睡眠的静谧，没有一个人，只有你我，在一起跳着飞着躲着捉迷藏，你允不允许？因为你不允许我做的梦，我不敢做的。','1030-1127',NULL,1581931345,1782398681);
INSERT INTO highlights VALUES('23606759_23_1181-1202','23606759',23,'017 我是属于你，永远而且完全地','我多么愿意自己是个诗人，只是为了你的缘故。','1181-1202',NULL,1581931311,1782398681);
INSERT INTO highlights VALUES('23606759_20_684-753','23606759',20,'014 我爱你像爱一首诗一样','问你寒假里有没有计划的人，我不知是谁，大概是一位蠢货，一定。理想的人生，应当充满着神来之笔，那才酣畅有劲。计划，即使实现了也没趣。祝福你。','684-753',NULL,1581931050,1782398681);
