INSERT INTO highlights VALUES('27350612_8_2767-2898','27350612',8,'教学，要落在实处','“语文课最大的问题是面面俱到，却又没有一处能讲清、讲透、讲明白、讲彻底，字、词、句、篇、章、修、罗……小学讲，初中讲，高中还在讲，一节课可能涉及三十个知识点，每个知识点都用了那么几秒钟，但没有把一个知识点弄清楚，所以，教师一直在重复，学生一直在懂与不懂之间……”','2767-2898',NULL,1674186855,1782398625);
