INSERT INTO highlights VALUES('27350612_7_3776-3881','27350612',7,'从“有味朗读”谈“有效朗读”','同学们读得很顺畅、很流利，但是没有文言文的味道，请同学们再读一遍，要求读出文言文的味道来→有了文言文的味道，读出一点喜悦的味道→有了喜悦的味道，再读出复杂的情愫→再读出一点快乐来。四次引导，环环相扣、层层深入。','3776-3881',NULL,1674186112,1782398625);
INSERT INTO highlights VALUES('27350612_7_2909-2982','27350612',7,'从“有味朗读”谈“有效朗读”','从读出“文言味道”，到读出“作者的喜悦”，再到读出“复杂的情愫”，最后又要学生读出作者的“快乐”，学生在逐步深入的朗读中，对文章逐渐有了深入的理解','2909-2982',NULL,1674185714,1782398625);
INSERT INTO highlights VALUES('27350612_7_2141-2164','27350612',7,'从“有味朗读”谈“有效朗读”','夜游的兴致中又有着点点滴滴的感慨和淡淡的无奈。','2141-2164',NULL,1674184419,1782398625);
