INSERT INTO highlights VALUES('27350612_7_1095-1152','27350612',7,'从“有味朗读”谈“有效朗读”','读这三句话时，把其中的“念”“盖”和“但”三个词语的声音尽可能拖长一点（边说边拖长声音示范），这就有了文言文的味道','1095-1152',NULL,1674184226,1782398625);
