INSERT INTO highlights VALUES('27350612_6_13016-13094','27350612',6,'语文课可以上得这样扎实、朴实和厚实','评价一个语文教师是否优秀不在于他给学生讲解了多少课文，传授了多少语文知识，而在于他是否教给了学生学习的方法，激起了学生读书的兴趣，培养了学生良好的读书习惯。','13016-13094',NULL,1674182356,1782398625);
INSERT INTO highlights VALUES('27350612_6_9257-9372','27350612',6,'语文课可以上得这样扎实、朴实和厚实','读完后，不要急于回答，你的眼睛要盯着画线的句子，思考这个句子让你懂得了什么，你是怎么理解这个句子的，把你的理解写在书上，这就是“批注”。读书要学会思考，不思考，书读得再多也没有用，读书作记号留下的是思考的痕迹，加批注是思考的结果。','9257-9372',NULL,1674180215,1782398625);
