INSERT INTO highlights VALUES('27350612_4_651-794','27350612',4,'序二 课堂赢在细节','课堂由一个个“教学细节”组成：字词教学怎样进行才有效？怎么介绍作者才能避免走过场？朗读指导怎么才能让学生一次又一次地提高？品读环节应该怎样引领，才能让学生倾听到文本深处的声音？什么样的语文活动不是为了哗众取宠而是基于学生的成长？如何设计问题才能一点点打开学生的思维，并抵达灵魂的深处？…','651-794',NULL,1629593850,1782398625);
