INSERT INTO highlights VALUES('3300049180_269_4854-4947','3300049180',334,'第十八章 冰箱、牛奶和志愿','“婚姻吧，如果有非忍不可的理由，你一定会忍，如果没有，你肯定就不忍了。我现在既没有必须要忍的理由，也没有不能忍的理由，鹏飞来也好，不来也好，都是庄家的事，我懒得管庄家的屁事，爱咋咋地。”','4854-4947',1,1722907281,1782398563);
