INSERT INTO highlights VALUES('3300049180_268_4919-4961','3300049180',333,'第十七章 无处可逃','暮色四合，白日里的暑气尚未完全消退，闷热的空气蒸笼般笼罩在四周，密不透风，无处可逃。','4919-4961',1,1722906552,1782398563);
INSERT INTO highlights VALUES('3300049180_268_1835-1974','3300049180',333,'第十七章 无处可逃','“这招很灵的，我只要一捣蛋，我爸妈就联手收拾我，他们配合得可好了，我爸负责打，我妈负责骂，每次收拾完我之后，他俩关系就特别好，我偷偷听到我妈对我爸说，‘林武峰，我在对林栋哲的阶级斗争中对你产生了新的爱情’，你听我的，你只要放开了调皮捣蛋、成绩下降，庄叔叔就回来了，这招绝对灵。”','1835-1974',1,1722906137,1782398563);
