INSERT INTO highlights VALUES('23562424_8_1690-1762','23562424',52,'别拿自己的尺子量对方','对方一说到“问题”，我们就急着去出主意、提建议，忙着为对方“解决问题”。但实际上，对方多数时候只是为了借“问题”宣泄情绪，根本不需要我们的建议。','1412-1484',NULL,1660783051,1782398636);
