INSERT INTO highlights VALUES('23562424_8_1078-1180','23562424',52,'别拿自己的尺子量对方','“什么叫如其所是呢？就是，对方怎么感受的，这才是事实，我们要按照对方的感受去理解他。”黄家良说，“但是，很多人习惯上认为，重要的是发生了什么事实。但是，他却不知道，这只是他眼中的事实，而不是对方的事实。”','816-918',NULL,1660782946,1782398636);
