INSERT INTO highlights VALUES('23562424_6_10206-10275','23562424',50,'每一次分手都是心灵的修复','婚姻之所以容易成为爱情的坟墓，一个很重要的原因是，婚姻只是我们过去家庭模式的复制。','8556-8597',NULL,1659866809,1782398636);
INSERT INTO highlights VALUES('23562424_6_9926-10027','23562424',50,'每一次分手都是心灵的修复','“符合”不是“等于”，热恋中的人必须要明白这一点。你对恋人有一种期待，恋人对你也有一种期待。很可能，你既符合她的期待，她也符合你的期待。但是，这种相互的符合只是一种运气，你们彼此并不真正懂得对方的期待。','8282-8383',NULL,1659866781,1782398636);
INSERT INTO highlights VALUES('23562424_6_1718-1820','23562424',50,'每一次分手都是心灵的修复','获得了足够的无条件的爱之后，我们会变成孩子，恋人也会变成孩子，我们一起退行到童年。这时，我们互为对方的理想父母，又互为对方的孩子。这是恋爱的关键期，这个阶段决定了我们是重复童年的错误，还是修正童年的错误。','1425-1527',NULL,1659865394,1782398636);
INSERT INTO highlights VALUES('23562424_6_1610-1689','23562424',50,'每一次分手都是心灵的修复','在恋爱前期，我们会积极地给予对方无条件的爱，或者用直白的方法，或者用狡猾的方法，总之都会让对方感觉到：不论你做什么，我都会一如既往地爱你，我的爱是没有条件的。','1321-1400',NULL,1659865384,1782398636);
INSERT INTO highlights VALUES('23562424_6_1505-1525','23562424',50,'每一次分手都是心灵的修复','我们其实是按照理想父母的原型去寻找恋人。','1220-1240',NULL,1659865366,1782398636);
INSERT INTO highlights VALUES('23562424_6_1554-1576','23562424',50,'每一次分手都是心灵的修复','理想父母都有一个特点：能给予我们无条件的爱。','1265-1287',NULL,1659865353,1782398636);
INSERT INTO highlights VALUES('23562424_6_1209-1310','23562424',50,'每一次分手都是心灵的修复','恋爱，其主要意义不是让我们找到一个能相处一辈子的伴侣，而是让我们真正明白自己是一个独立的人，伴侣是另外一个和自己一样独立、一样重要的人。并且，我们还深深地懂得，这两个相互独立的人，又能无比亲密地相处。”','966-1067',NULL,1659865229,1782398636);
INSERT INTO highlights VALUES('23562424_6_980-1025','23562424',50,'每一次分手都是心灵的修复','现实父母或多或少让我们不满意，我们心中都藏着一个理想父母的模型，它是我们选择恋人的基石。”','745-790',NULL,1659865177,1782398636);
INSERT INTO highlights VALUES('23562424_6_913-980','23562424',50,'每一次分手都是心灵的修复','恋爱是一种特殊的选择。其实，我们无意识中都将恋爱当作了治疗，目的是修正我们童年的错误，其表现就是，恋人多数时候都是我们选中的理想父母。','678-745',NULL,1659865159,1782398636);
