INSERT INTO highlights VALUES('26639909_49_581-715','26639909',49,'魔季','山容已经不再是去秋的清瘦了，那白绒绒的芦花海也都退潮了，相思树是墨绿的，荷叶桐是浅绿的，新生的竹子是翠绿的，刚冒尖儿的小草是黄绿的。还是那些老树的苍绿，以及藤萝植物的嫩绿，熙熙攘攘地挤满了一山。我慢慢走着，我走在绿之上，我走在绿之间，我走在绿之下。绿在我里，我在绿里。','581-715',5,1689385483,1782398618);
