INSERT INTO highlights VALUES('26639909_13_687-1359','26639909',13,'寻人启事','寻人启事妈妈在客厅贴起一张大红纸上面写着黑黑的几行字：兹有小男孩一名不知何时走失谁把他拾去了啊，仁人君子他身穿小小的蓝色水手服他睡觉以前一定要念故事他重得像铅球又快活得像天使满街去指认金龟车是他的专职当电扇修理匠是他的大志他把刚出生的妹妹看了又看露出诡笑：“妈妈呀，如果你要亲她就只准亲她的牙齿。”那个小男孩到哪里去了听说有位名叫时间的老人把他带了去却换给我一个比妈妈还高的少年正坐在那里愁眉苦脸地背历史那昔日的小男孩啊不知何时走失谁把他带还给我啊，仁人君子。','687-1359',5,1689210398,1782398618);
