INSERT INTO highlights VALUES('23562223_46_1792-1839','23562223',46,'就怕查酒驾的','不管你正经历什么，请记得：如果事与愿违，就相信一定另有安排。愿你想要的都拥有，得不到的都释怀。','1792-1839',NULL,1598539375,1782398661);
INSERT INTO highlights VALUES('23562223_45_782-811','23562223',45,'从来没像现在这么讨厌过一个符号','其实除了惶恐，除了不断地把手机屏幕划亮，谁比谁懂得更多呢？','782-811',NULL,1598538945,1782398661);
INSERT INTO highlights VALUES('23562223_45_694-742','23562223',45,'从来没像现在这么讨厌过一个符号','反正自打我们每个人在手机和平板电脑上耽误的时间越多，我们被“+”得越瓷实，以至于我们得委身于它。','694-742',NULL,1598538923,1782398661);
INSERT INTO highlights VALUES('23562223_44_1550-1665','23562223',44,'要把这个谎编圆','我们仿佛进入了一个功利时代，不停地要求立竿见影的效果，孩子没有大量阅读的积累，没有系统的写作训练，没有留心地观察过生活，你凭什么要求孩子必须写出高分作文？最后作文变成了一个撒谎教育，还要求把这个谎言编圆，编出意义。真难为孩子们了。','1550-1665',NULL,1598538833,1782398661);
INSERT INTO highlights VALUES('23562223_43_1832-1864','23562223',43,'太多的孩子，就是未知的自己','我带学生，会像当年老师对我一样，因为太多的孩子，就是未知的自己。','1832-1864',NULL,1598538144,1782398661);
INSERT INTO highlights VALUES('23562223_41_517-562','23562223',41,'辑三 没带纸巾就买个馒头擦嘴','我从来不跟突然冒出来的状况较劲，我委曲求全，顺流直下三千尺，走哪到哪，忽然就能发现新风景。','517-562',NULL,1598506303,1782398661);
