INSERT INTO highlights VALUES('23562223_11_1834-1922','23562223',11,'爱情就是你嘴巴子上那些擦不净的口水','我们都是那些无法用长相赢得精彩人生的人，站在他们的背后看各自的爱情片段，你会觉得可笑，夸张，其实别人若在背后看我们，何尝不是这样的印象呢？因为爱情本来就粗糙、潦草、不那么通顺。','1834-1922',NULL,1597735964,1782398661);
INSERT INTO highlights VALUES('23562223_6_1775-1883','23562223',6,'那些惹祸的小事儿','我们每个人都有自己界定的标准，我们希望别人服从，我们理所应当地去强迫另外一个人的边界感。放过小事儿，也许能过得更加从容。爱是付出，如果你不横下一条心有点儿“我干了，你随意”的精神，这日子常常会亮起“过不下去”的红灯。','1775-1883',NULL,1597719134,1782398661);
INSERT INTO highlights VALUES('23562223_6_1291-1308','23562223',6,'那些惹祸的小事儿','有时候，推倒婚姻这堵墙的就是小事。','1291-1308',NULL,1597719052,1782398661);
INSERT INTO highlights VALUES('23562223_6_879-1026','23562223',6,'那些惹祸的小事儿','婚姻就是张婚纱照，脸上多少麻子都能拿厚厚的粉给盖上，膀大腰圆的两口子也都有白婚纱和燕尾服，冰岛去不起，怎么也能跑巴厘岛出个外景，弄得好像所有湖光山色都在见证幸福，最后一道手，还有图像修片，最后交到客户手里，永远是你能挂在墙上，能逮谁给谁看的“我们俩前几天拍的”。可是，过日子，首先得把脸洗干净。','879-1026',NULL,1597718961,1782398661);
INSERT INTO highlights VALUES('23562223_4_2378-2401','23562223',4,'序：对这个世界，保持礼貌','真实最省心，不见那么多人，就不用扮演太多角色，','2378-2401',NULL,1597718809,1782398661);
INSERT INTO highlights VALUES('23562223_4_2641-2657','23562223',4,'序：对这个世界，保持礼貌','粗缯大布裹生涯，腹有诗书气自华”','2641-2657',NULL,1597718706,1782398661);
INSERT INTO highlights VALUES('23562223_4_1942-2021','23562223',4,'序：对这个世界，保持礼貌','可是，今天，我们能认真个地跟别人道个别吗？我们还有揣摩每一个字怎么下笔，才能让另外一个人“见字如晤”的心境吗？也许你有心，但是，已经不知道谁值得你那么去做了。','1942-2021',NULL,1597718590,1782398661);
INSERT INTO highlights VALUES('23562223_4_856-871','23562223',4,'序：对这个世界，保持礼貌','浩荡离愁白日斜，吟鞭东指即天涯','856-871',NULL,1597718432,1782398661);
INSERT INTO highlights VALUES('3300135523_61_1232-1357','3300135523',61,'致谢',unistr('对于“活着”这件小事，我从来不曾“超脱”。\u000a乘兴而来已是幸事，倒也不必强求去所无羁。\u000a我挺喜欢我与这个世界的瓜葛。'),'1232-1357',0,1766205805,1782398508);
INSERT INTO highlights VALUES('3300135523_9_7040-7159','3300135523',9,'不能永远开心，那就永远开阔','如果无法与疼痛的、焦躁的、压抑的、脆弱的、疯狂的自己和解，就给自己一个拥抱吧。因为每一个“自己”都是勇敢的自己，每一个我们都已经做得很好了。在变幻莫测又分崩离析的岁月里，愿你我与世界始终是彼此接纳的。','7040-7159',0,1766205759,1782398508);
INSERT INTO highlights VALUES('3300135523_9_6927-7011','3300135523',9,'不能永远开心，那就永远开阔','我希望开心之余的你是开阔的——有爱的力量也被爱着，有包容力也被包容。我希望焦虑之外的你是有趣的，是灵动的，是激情的、热烈的、奋不顾身的，也是沉静的、思索的、波澜不惊的。','6927-7011',0,1766205724,1782398508);
INSERT INTO highlights VALUES('3300135523_9_6768-6898','3300135523',9,'不能永远开心，那就永远开阔','你的勇敢不是无所畏惧，而是有勇气与畏惧相处。你的自由不是毫无边界，而是看清边界却不视之为枷锁。愿你可以坦然体察那些平和或焦躁的情绪，愿你关心一草一木，愿你接纳自己，愿你充分感受每个时刻。愿你的每一段平稳都带来心安而非无聊，愿你的每一段曲折带来更多风景而非伤痕。','6768-6898',0,1766205691,1782398508);
INSERT INTO highlights VALUES('3300135523_9_6630-6663','3300135523',9,'不能永远开心，那就永远开阔','我希望无论健康或疾病、快乐或悲伤的你，都可以是有质感的张扬的生命。','6630-6663',0,1766205670,1782398508);
INSERT INTO highlights VALUES('3300135523_10_2151-2165','3300135523',10,'心有猛虎，严禁投喂','明净的海水是镶嵌在石壁的镜子','2151-2165',0,1766205619,1782398508);
INSERT INTO highlights VALUES('3300135523_21_2036-2064','3300135523',21,'冯女士','而艺术，是不是可以成为让感受得以被看见、被传递的媒介呢？','2036-2064',0,1766205509,1782398508);
INSERT INTO highlights VALUES('3300135523_23_5383-5417','3300135523',23,'在爱之中，我得以遇见自己','所有的一切都无法阻止你成为具有无限生命力、无限张力的独一无二的自己。','5383-5417',0,1766205395,1782398508);
INSERT INTO highlights VALUES('3300135523_23_5059-5302','3300135523',23,'在爱之中，我得以遇见自己','我期待着许许多多的女孩，在成为自己以前，不必成为谁的谁；期待着每一个不完美的“你”或“她”，都是完全的、完整的、完满的自我。我喜欢你的眼睛不够大，或是鼻梁不够高；我喜欢你每天清晨蓬乱的头发；我喜欢你的敏感、你的偏执、你的脆弱；我喜欢你的热情，或是对世界的疏离；我喜欢你的目光，坚定或是闪躲；我喜欢你的生动、你的真实、你的恰到好处的不完美；我喜欢你的样子，特立独行或是淹没于人群；我喜欢的你是你，不在乎我是否喜欢的你，这样的或那样的你。','5059-5302',0,1766205387,1782398508);
INSERT INTO highlights VALUES('3300135523_23_7826-7831','3300135523',23,'在爱之中，我得以遇见自己','相信暖阳。','7826-7831',0,1766205354,1782398508);
INSERT INTO highlights VALUES('3300135523_27_1996-2012','3300135523',27,'我们只是不一样','我们没有不正常，我们只是不一样。','1996-2012',0,1766205329,1782398508);
INSERT INTO highlights VALUES('3300135523_28_520-551','3300135523',28,'我会认认真真过好这一生','“要决定放弃才需要找很多理由，坚持下去只需要一个理由就足够了”','520-551',0,1766205314,1782398508);
INSERT INTO highlights VALUES('3300135523_28_5923-6003','3300135523',28,'我会认认真真过好这一生','绚烂比圆满更重要。那些写给童稚、写给青春，写给暮年、写给死亡的，归根结底，是写给安慰。我们可以不完美，但不能放任自己的不完美而不去争取自己想要的、更好的生活。”','5923-6003',0,1766205131,1782398508);
INSERT INTO highlights VALUES('3300135523_28_6473-6569','3300135523',28,'我会认认真真过好这一生','。我看到这世界很大，道路很多，没有什么是一个人一生中“必须完成的任务”。我不再备份电脑里的每一个文件了。所有的一切我都可以失去，所有的一切我也都不会失去。','6473-6569',0,1766205113,1782398508);
INSERT INTO highlights VALUES('3300135523_29_1539-1559','3300135523',29,'我们把书页合上，去看看太阳','没有什么可以被完成。没有什么必须去完成。','1539-1559',0,1766205090,1782398508);
INSERT INTO highlights VALUES('3300135523_29_1864-1883','3300135523',29,'我们把书页合上，去看看太阳','用一个宏大的世界，稀释一些小小的烦恼。','1864-1883',0,1766205083,1782398508);
INSERT INTO highlights VALUES('3300135523_37_1754-1789','3300135523',37,'我的病隙碎笔','不一定非得完全接受自己才能活下去。只要你依然喜欢自己，你就会好好的。）','1754-1789',0,1766205024,1782398508);
