INSERT INTO highlights VALUES('3300135523_48_1616-1689','3300135523',48,'年','王小波先生在《写给新的一年》中的一段话：“但愿在新的一年里，我们能远离一切古怪的事，大家都能做个健全的人——我实在想不出有什么话比这句话更吉利。”','1616-1689',0,1766204893,1782398508);
