INSERT INTO highlights VALUES('816114_12_1265-1365','816114',12,'十 守着十八个鸡蛋等你','我说：“二给，你是一只自私的母鸡。不过，自私得可爱。”二给说：“你也是一个自私的人。不过，自私得没有我可爱。对了，你还固执，固执得让人讨厌。”','1265-1365',NULL,1592655163,1782398673);
INSERT INTO highlights VALUES('816114_11_1118-1180','816114',11,'九 老树精婆婆的七彩头发','就是这样，大风每天都遇见低着头在灌木丛、草地上、花朵间找头发的老树精婆婆，每天都是一样的对话，每天都会被那尖厉的嚷嚷吓一跳。','1118-1180',NULL,1592652491,1782398673);
