INSERT INTO highlights VALUES('816114_10_4354-4403','816114',10,'八 别去五厘米之外','他们同时打开房门，同时走出房子，走了五厘米，哈哈，他们之间的距离就只有四厘米了，说起话来省力多了。','4354-4403',NULL,1592652232,1782398673);
INSERT INTO highlights VALUES('816114_9_2545-2605','816114',9,'七 变成一颗南瓜子','我呢，我是一个可怜的南瓜小女妖，我不知道自己什么时候来到这个世界，也不知道自己什么时候离开，那么，以后你就叫我什什好了。','2545-2605',NULL,1592610219,1782398673);
INSERT INTO highlights VALUES('816114_9_2427-2495','816114',9,'七 变成一颗南瓜子','名字？连我自己都不知道。我不知道自己从哪里来，也不知道自己要到哪里去。这样吧，你就叫我哪哪好了。”少女的语气里，流动着几分忧伤几分自嘲。','2427-2495',NULL,1592610203,1782398673);
INSERT INTO highlights VALUES('816114_8_4727-4741','816114',8,'六 六十楼的土土土','是——那种很深的疲惫和迷茫。','4727-4741',NULL,1592554956,1782398673);
INSERT INTO highlights VALUES('816114_8_4487-4511','816114',8,'六 六十楼的土土土','太久没有亲近泥土的人，瞳孔里会开出烟灰色的花朵。','4487-4511',NULL,1592554932,1782398673);
INSERT INTO highlights VALUES('816114_8_2865-2948','816114',8,'六 六十楼的土土土','把鼻子摔扁了，还摔飞了两颗门牙。我的屁股之所以一边高一边低，也是摔的。每次我以不同的姿势和水泥地面亲吻的时候，周围爆发出的笑声，就像大小不一的冰雹“啪啪”落在瓦片上。','2865-2948',NULL,1592554737,1782398673);
INSERT INTO highlights VALUES('816114_8_2344-2367','816114',8,'六 六十楼的土土土','他的皮鞋很亮很亮，亮得能映出一百层之高的楼顶。','2344-2367',NULL,1592554399,1782398673);
INSERT INTO highlights VALUES('816114_8_2221-2240','816114',8,'六 六十楼的土土土','别问我为什么害怕，害怕是不需要理由的。','2221-2240',NULL,1592554346,1782398673);
INSERT INTO highlights VALUES('816114_8_987-1020','816114',8,'六 六十楼的土土土','嘴啃泥式，四脚朝天式，屁股落地式，头部着陆式……称得上千姿百态呢。','987-1020',NULL,1592554207,1782398673);
INSERT INTO highlights VALUES('816114_8_421-441','816114',8,'六 六十楼的土土土','我每天都在寻找瞳孔里开着烟灰色花朵的人。','421-441',NULL,1592554062,1782398673);
INSERT INTO highlights VALUES('816114_7_2618-2648','816114',7,'五 寻找淡玉的锅','。我一直在等待，一直在思念，一直在困惑，怎么有时间生锈呢？”','2618-2648',NULL,1592397559,1782398673);
INSERT INTO highlights VALUES('816114_6_1775-1865','816114',6,'四 小耳有秘密','“嘿，小耳，你的秘密太大，也太调皮啦。它还没落到树洞底，就一个劲儿地蹦啦。我看它迟早都会从洞里跳出来，它一出来，你的秘密，就谁都知道啦！所以，你赶紧找些泥土来，把洞口快快堵上吧。”','1775-1865',NULL,1592396816,1782398673);
INSERT INTO highlights VALUES('816114_6_2325-2369','816114',6,'四 小耳有秘密','哎呀，你的秘密实在是太大，太调皮啦。它不肯睡觉，总想往外钻，弄得我不得安宁，太难受啦。”','2325-2369',NULL,1592396807,1782398673);
INSERT INTO highlights VALUES('816114_5_9305-9420','816114',5,'三 绿藤红藤','脑子里只有他们的影子，只有他们的脸在交替出现。时而是藤绿浓密的乌发，时而是藤红笑吟吟的眼睛；时而是藤绿教我读诗词，摇头晃脑如痴如醉的模样；时而是藤红为我烙南瓜饼时，光洁的额头上细细密密的汗……一幕幕，一幕幕，难道都是梦里的事情吗？','9305-9420',NULL,1592395878,1782398673);
INSERT INTO highlights VALUES('816114_4_4896-4985','816114',4,'二 抱抱','亲爱的朋友，如果某一天，那一天没有起风，可是你却遇到一棵摇摇摆摆的树，请一定要张开你的双臂，去抱抱它。抱抱，它就不哭了。','4896-4985',NULL,1592395057,1782398673);
INSERT INTO highlights VALUES('816114_4_3978-3998','816114',4,'二 抱抱','阿姨大笑，脸上的粉，细细碎碎飘落了一些。','3978-3998',NULL,1592395001,1782398673);
INSERT INTO highlights VALUES('816114_4_3024-3052','816114',4,'二 抱抱','“因为我像它。”小去说，“那些落下的叶子，是它的眼泪。”','3024-3052',NULL,1592394941,1782398673);
INSERT INTO highlights VALUES('23199285_51_733-741','23199285',51,'由繁到简的跨境信心','懂得体会少即是多','733-741',NULL,1581223732,1782398676);
INSERT INTO highlights VALUES('23199285_48_1703-1760','23199285',48,'等待对的时间对的人','创作有时就像爱情，需要缘分。时间对了，人错了，没辙；人对了，时间错了，白搭。只有在对的时间遇见对的人才可能开花结果','1703-1760',NULL,1581223615,1782398676);
INSERT INTO highlights VALUES('23199285_46_1674-1780','23199285',46,'被创作的小鸟唤醒','皮娜·鲍什说她的创作来源就是“恐惧”，她作品里有爱，也是因为要对抗恐惧而需要爱。我的创作来自于“追寻”，这个追寻可能来自于追索现实中某种永远不存在的感觉，仿佛生命永远有一种空洞，虽然什么都有，但好像又什么都没有。','1713-1819',NULL,1581223490,1782398676);
INSERT INTO highlights VALUES('23199285_46_1427-1645','23199285',46,'被创作的小鸟唤醒','《森林里的秘密》，小女孩和毛毛兔一起寻找未知。《微笑的鱼》，上班族和发光的鱼一起寻找自我。《向左走·向右走》，都会孤单寂寞的男女，互相找寻。《地下铁》，盲女在找寻新的人生。《蓝石头》，找寻它失落的另一半。','1427-1645',NULL,1581223456,1782398676);
INSERT INTO highlights VALUES('23199285_46_1378-1398','23199285',46,'被创作的小鸟唤醒','好像我所有的作品都脱不了“追寻”这主题。','1378-1398',NULL,1581223434,1782398676);
