INSERT INTO highlights VALUES('23199285_42_1203-1291','23199285',42,'简单即是神采','所以我会在创作时让自己和作品保持距离，不要太切身，不要讲得太满，留有空间让读者去倾吐自己的感受，可以把自己投进到作品里面来，可以和故事缝合，这样才能使有限的作品产生无限的意涵。','1203-1291',NULL,1581217362,1782398676);
