INSERT INTO highlights VALUES('23199285_33_1879-1921','23199285',33,'完美的编辑过程','每次遇到犹豫没把握的事情时，她总说：“别急，我们先放着，先别做决定，再看看再想想。”','1919-1961',NULL,1581216670,1782398676);
INSERT INTO highlights VALUES('23199285_21_532-653','23199285',21,'电影是创作的神秘魔窟','二〇〇三年，《向左走·向右走》，杜琪峰导演；二〇〇三年，《地下铁》，王家卫监制、马伟豪导演；二〇一一年，《星空》，林书宇导演。','532-653',NULL,1581169300,1782398676);
INSERT INTO highlights VALUES('23199285_19_3760-3810','23199285',19,'找出来又故意盖去的线索——一个有趣的角色设定','灵感的触发可能就像这样，生活上碰到的、看到的各种事情，都可能是灵感的触媒，觉得有必要就加到作品里面。','3858-3908',NULL,1581168753,1782398676);
