INSERT INTO highlights VALUES('25170964_8_5933-5957','25170964',8,'文本解读靠涵养，但也有方法','《景阳冈》一文的解读，我认为要抓两个字：人、物。','5933-5957',NULL,1674620703,1782398624);
INSERT INTO highlights VALUES('25170964_8_5477-5558','25170964',8,'文本解读靠涵养，但也有方法','不过“知人论世”要注意两点：一是参阅别人的意见最好在自己的解读之后，避免先入为主；二是作品的艺术世界并不是作家自己生活的简单再现，我们不能在作家和作品之间画等号。','5477-5558',NULL,1674620610,1782398624);
INSERT INTO highlights VALUES('25170964_8_5235-5245','25170964',8,'文本解读靠涵养，但也有方法','第五是“知人论世”。','5235-5245',NULL,1674620539,1782398624);
