INSERT INTO highlights VALUES('25170964_8_4553-4584','25170964',8,'文本解读靠涵养，但也有方法','第三种方法是寻找“缝隙”，也就是寻找作品中自相矛盾不可解释之处','4553-4584',NULL,1674620426,1782398624);
INSERT INTO highlights VALUES('25170964_8_4126-4178','25170964',8,'文本解读靠涵养，但也有方法','其次是还原生活。茅盾提出：“应当一边读，一边回想他所经验的相似的人生，或者一边读，一边到现实的生活中去看','4126-4178',NULL,1674620335,1782398624);
INSERT INTO highlights VALUES('25170964_8_3692-3741','25170964',8,'文本解读靠涵养，但也有方法','首先就是从语言入手，仔细推敲词句，想想作者为什么用这个词而不用那个词，用这种说法而不用另一种说法。','3692-3741',NULL,1674620324,1782398624);
INSERT INTO highlights VALUES('25170964_8_3448-3599','25170964',8,'文本解读靠涵养，但也有方法','所以一个读者，要多读书，多思考，通过读书去积累各个领域的知识，通过读书去认识形形色色的人，通过读书去欣赏五湖四海的风景，通过读书去经历与众不同的人生，通过读书去接触丰富多元的观点，通过读书养成特有的语言敏感……只有这样，你读书时才可能“视接千里、思通万载”，有感受，有发现，文本解读的能力才会有所提高。','3448-3599',NULL,1674620257,1782398624);
INSERT INTO highlights VALUES('25170964_8_2312-2348','25170964',8,'文本解读靠涵养，但也有方法','就是这种没有定论的“未知结构”使《老人与海》这部结构简单的小说成为经典。','2312-2348',NULL,1674619971,1782398624);
INSERT INTO highlights VALUES('25170964_8_1238-1270','25170964',8,'文本解读靠涵养，但也有方法','只要是你自己内心里“生”出来的，这个“生”的本身就是最好的收获。','1238-1270',NULL,1674619726,1782398624);
INSERT INTO highlights VALUES('25170964_7_2477-2523','25170964',7,'有些文章，可以找出“原版”来上','其中，我个人最难以接受的是，大量的动感的画面感很强的文字被“程式化”、“概念化”的词语替代。','2477-2523',NULL,1674618438,1782398624);
