INSERT INTO highlights VALUES('26001263_9_4112-4145','26001263',9,'06','“老天，伦尼！什么事你都记不住，偏偏我讲的话你竟然记得一字不漏。”','4112-4145',NULL,1583839347,1782398686);
INSERT INTO highlights VALUES('26001263_9_4990-5161','26001263',9,'06','“但我们就不是这样。”他说。“因为——”“因为我有你，而你——”“而我有你。我们互相照顾。这就是为什么。只要我们在一起，天不怕地不怕，什么都不怕。”伦尼得意地大叫起来。','4990-5161',NULL,1583839333,1782398686);
INSERT INTO highlights VALUES('26001263_9_727-844','26001263',9,'06','一条水蛇轻盈地滑过水面，头露在水面上如潜望镜般左右摆动。它从水潭的一头游到另一头，游到一只苍鹭脚边。苍鹭站在浅水处纹风不动，接着，它忽然无声无息地猛一低头，长长的嘴咬住水蛇头。水蛇被苍鹭慢慢吞进嘴里的时候，露在外面的尾巴依然拼命扭动。','727-844',NULL,1583839004,1782398686);
INSERT INTO highlights VALUES('26001263_8_8840-8906','26001263',8,'05','乔治慢慢地说：“——我想，其实我一开始就明白，我们是永远办不到的。刚开始只是因为他很喜欢听我讲，后来，我自己也渐渐以为真的办得到。”','8840-8906',NULL,1583838334,1782398686);
