INSERT INTO highlights VALUES('26001263_7_4296-4377','26001263',7,'04','我发现很多人都是这样——找个人说话，不管他听得懂听不懂。无所谓，根本无所谓。反正重要的就是找人说话，要不然，安安静静坐着不说话也没关系。反正都一样，没什么差别。”','4296-4377',NULL,1583832946,1782398686);
