INSERT INTO highlights VALUES('28416170_18_5482-5594','28416170',18,'侏儒的话','人生好比是疯子所举办的奥林匹克大会，我们一面和人生战斗，一面必须学习如何和人生战斗。对于这种游戏的不合理觉得愤慨难忍的人，就赶快跑到界限外好了。自杀也是一种方便的方法，不过如果想在人生的竞技场上立足，必须不畏疮痍地奋斗才行。','5482-5594',NULL,1585361162,1782398697);
