INSERT INTO highlights VALUES('42766056_48_1144-1223','42766056',48,'第3章 初当领导，不敢“建造”','第四个阶段——Inspire（激发），启迪与引领每个人确定自己的目标和愿景，实现自己的理想。','1144-1223',1,1751466583,1782398542);
INSERT INTO highlights VALUES('42766056_48_881-1067','42766056',48,'第3章 初当领导，不敢“建造”','→第一个阶段是Do（做事），好比造一栋房子时做好砌砖这件事。→第二个阶段是Build（建造），作为团队领导，领导大家盖房子，从蓝图到设计，再到施工。→第三个阶段是Coach（教练），支持团队明确他们心目中房子的样子，进而盖好他们自己的房子。','883-1069',1,1743740680,1782398542);
