INSERT INTO highlights VALUES('42766056_42_3329-3435','42766056',42,'序言 那许多“不敢”','因为我们每个人生命里真正的太阳不应该是别人，而应该是我们自己。这不是说我们不可以从别人的身上收获力量和勇气，而是这些力量最终要变成我们自己的光和亮，才能照亮我们自己的人生路。','3329-3435',1,1743302455,1782398542);
INSERT INTO highlights VALUES('42766056_42_2659-2849','42766056',42,'序言 那许多“不敢”','→面对这个选择，我到底在害怕什么？→我害怕的这件事，为什么对我重要？真的有这么重要吗？→如果没那么重要，那真正重要的是什么？我更深层的恐惧是什么？→这件让我恐惧的事，是真实存在的吗？','2659-2849',1,1743302374,1782398542);
