INSERT INTO highlights VALUES('449751_21_5051-5180','449751',21,'9.胎儿大小多少的逻辑','克罗米芬过量会导致面部潮红，卵巢增大，腹部不适，以及少见的视物模糊、恶心、呕吐、头痛、疲乏等。长期或大剂量使用克罗米芬，甚至导致个别病人出现卵巢过度刺激综合征，表现为全身毛细血管通透性改变，大量体液外渗，继而出现胸水、腹水，甚至心包积液，严重者心肺功能衰竭。','5051-5180',NULL,1613289121,1782398658);
INSERT INTO highlights VALUES('449751_20_15381-15416','449751',20,'8.忽略孕前和产前检查是造人最大的风险','孩子是上天的礼物，但是最好的东西从来不是独来，他带着所有的东西同来。”','15381-15416',NULL,1613276541,1782398658);
