INSERT INTO highlights VALUES('449751_20_4905-5009','449751',20,'8.忽略孕前和产前检查是造人最大的风险','子痫，顾名思义，因为怀孩子导致的抽风。一般都有一个渐进式发展的疾病过程，开始可能只是血压轻微升高，脚踝略有浮肿，如果化验尿常规，可能会有少量尿蛋白，这叫作“子痫前期”，过去统称为妊娠高血压综合征，简称妊高症。','4905-5009',NULL,1613226454,1782398658);
