INSERT INTO highlights VALUES('449751_20_804-998','449751',20,'8.忽略孕前和产前检查是造人最大的风险','人家怀孕后都性情柔顺，整天摸着肚子对着孩子不是唱歌就是说话，和风细雨的一副全世界最幸福的女人模样。她却双眼外凸、二目炯炯，食量大增，能吃能拉，人却日渐消瘦。拿她妈的话说就是“吃玉米饼子拉玉米糊糊，吃豆腐拉豆腐脑”，“好像长了根直肠子一样，食物吃进去还没来得及消化就出去了，而且每天都有好几次稀糊一样的大便”。此外，她的脾气也大，几句话不合就跟别人吵架，即使闲坐，脸上也是一层细密的汗珠子。','804-998',NULL,1613134957,1782398658);
INSERT INTO highlights VALUES('449751_19_1251-1412','449751',19,'7.压肚子的野把式，不是单纯失传那么简单','“唉，现在的女人连孩子都不会生了，你们这些姑娘，除了大便干燥的时候被迫锻炼一下盆底肌肉，平时一点都不好好锻炼身体，就耍嘴皮子有两下子。刚才那个产妇挺大高个子，要体力没体力，要耐力没耐力，生孩子真费死劲了，眼看孩子脑袋就卡在那儿，可他妈就是死活不用力，胎心都掉到60次了，我的老天爷，急死我了，真想上去两个大嘴巴，扇醒她。”','1251-1412',NULL,1613125418,1782398658);
INSERT INTO highlights VALUES('449751_19_11343-11397','449751',19,'7.压肚子的野把式，不是单纯失传那么简单','医生是一个需要终生学习的职业，可是你看看，我们国家哪里有一套对医生的整体培训系统，靠自觉，那能有几分力量？”','11343-11397',NULL,1613118342,1782398658);
