INSERT INTO highlights VALUES('449751_16_15039-15146','449751',16,'4.循序渐进：分娩就像建座罗马城','小医生很辛苦很累，要在最底层煎熬很多年。聪明的一眼看穿，走了；身体不好的受不了这份累，走了；短视的看不到熬出来的那一天，走了；还有注重生活质量、不愿意受这份洋罪的，也走了。留下来的只要身体好，都能熬成专家和教授。”','15039-15146',NULL,1612946941,1782398658);
