INSERT INTO highlights VALUES('40740496_29_7536-7582','40740496',29,'3','事实上，生活没有出现任何问题。就像现在一样，未来也会这样生活下去的。因为除此以外，她别无选择','7536-7582',1,1755050167,1782398538);
INSERT INTO highlights VALUES('40740496_29_6800-6847','40740496',29,'3','但她始终觉得体内存在着伤口，而且那个深不见底的伤口仿佛比身体还要大，就要把自己彻底吞噬了一样。','6800-6847',1,1755050041,1782398538);
INSERT INTO highlights VALUES('40740496_29_6555-6626','40740496',29,'3','那瞬间，她感受到了意外的痛苦。活下来的时间无限地延长了，但这一点也没有让她觉得开心。过去一个月里忧心忡忡的不治之症，竟然只是一个无谓的小烦恼。','6555-6626',1,1755049876,1782398538);
INSERT INTO highlights VALUES('40740496_29_6239-6334','40740496',29,'3','她确信自己是一个善良的人，这种确信促使她从来不给任何人添麻烦。她为人老实，任劳任怨，因此也取得了一定的成功。但不知道为什么，面对眼前颓废的建筑和杂乱无章的野草，她竟变成了一个从未活过的孩子。','6239-6334',1,1755049760,1782398538);
INSERT INTO highlights VALUES('40740496_29_6115-6211','40740496',29,'3','她站在往十里地铁站等待着迟迟不来的换乘地铁，遥望着车站对面临时搭建起的、破破烂烂的简易房屋和毫无人迹的空地上长满的野草，她突然觉得自己仿佛从未活在这个世界上一样。但这是事实，她从未真正地活过。','6115-6211',1,1755049645,1782398538);
INSERT INTO highlights VALUES('40740496_29_4842-4867','40740496',29,'3','她终于醒悟到，自己所了解的他只不过是一个影子罢了。','4842-4867',1,1755049381,1782398538);
INSERT INTO highlights VALUES('40740496_29_1284-1309','40740496',29,'3','她茫然地感受着自己体内像是炙热的泡沫在沸腾着愤怒。','1284-1309',1,1755049007,1782398538);
