INSERT INTO highlights VALUES('40740496_27_2688-2724','40740496',27,'1','没过多久，她便醒悟到自己迫切想要从疲惫中拯救出来的人不是别人，而是自己。','2688-2724',1,1754998357,1782398538);
INSERT INTO highlights VALUES('40740496_22_11051-11121','40740496',22,'2','静静接受着这一切的她无法看成是某种神圣的象征或是灵长，但又无法称为野兽。他觉得她应该是植物、动物、人类，抑或介于这三者之间的某种陌生的存在。','11051-11121',1,1754988908,1782398538);
INSERT INTO highlights VALUES('40740496_22_10070-10140','40740496',22,'2','此时此刻的她双手捧着温暖的水杯，像一只怕冷的小鸡蜷缩着身体低头看着自己的脚，但与其说这样的姿势会诱发怜悯，倒不如说她散发着如同阴影般的孤独。','10070-10140',1,1754988726,1782398538);
INSERT INTO highlights VALUES('40740496_19_7570-7645','40740496',19,'5','我扒开妻子紧攥的右手，一只被掐在虎口窒息而死的鸟掉在了长椅上。那是一只掉了很多羽毛的暗绿绣眼鸟，它身上留有捕食者咬噬的牙印，红色的血迹清晰地漫延开来。','7570-7645',1,1754966598,1782398538);
INSERT INTO highlights VALUES('40740496_19_7043-7127','40740496',19,'5','我就跟事不关己的旁观者一样无动于衷地望着眼前的光景，我看着她疲惫不堪的脸和像是用口红乱抹的、沾有鲜血的嘴唇。她呆呆地望着围观的人群，饱含着泪水的双眼终于与我四目相对了。','7043-7127',1,1754966459,1782398538);
INSERT INTO highlights VALUES('40740496_19_5158-5257','40740496',19,'5','某种咆哮和呼喊层层重叠在一起，它们充斥着我的内心。是肉，因为我吃过太多的肉。没错，那些生命原封不动地留在了我心里。血与肉消化后流淌在身体的每一个角落，虽然残渣排泄到了体外，但那些生命仍旧留在了那里。','5158-5257',1,1754965898,1782398538);
INSERT INTO highlights VALUES('40740496_17_6652-6696','40740496',17,'3','那两颗如同橡子般的乳头在她的衬衫里呼之欲出，她的视线却一直追随着其他人的嘴唇和一举一动。','6652-6696',1,1754916517,1782398538);
