INSERT INTO highlights VALUES('43229346_25_121-191','43229346',25,'什么是光明','什么是光明　　光明就是　　当你快乐　　允许他人悲伤　　当你悲伤　　允许他人快乐　　不以自身处境　　规范另一种心声','121-191',5,1690162458,1782398616);
INSERT INTO highlights VALUES('43229346_24_2-102','43229346',24,'原来是命运','生活得久了　　发觉自己　　不是一个人　　是一种命运　　是红尘万千命运中　　极为平凡的一种　　说幸也幸　　说不幸也不幸　　说拥有也拥有　　说一无所有　　也一无所有','2-102',5,1690162416,1782398616);
