INSERT INTO highlights VALUES('43229346_18_235-343','43229346',18,'李子熟了','可如今我不再踮着脚尖盼望了　　只若无其事默默用心默默等　　这种安静等待也很好　　就像冬熊蜷在洞里　　它不管冰雪何时消融　　不焦虑春天何时才到来　　只一心做好最应做的那件事　　该来的早晚会来','235-343',5,1690161441,1782398616);
