INSERT INTO highlights VALUES('3300070952_9_5652-5724','3300070952',9,'准则4 婴幼儿时期至关重要','一般来说，能及时回应孩子，能给予孩子温暖和稳定的预期，冲突后能及时修复感情的亲子关系能够让孩子拥有安全基地','5652-5724',1,1747443420,1782398544);
INSERT INTO highlights VALUES('3300070952_8_5847-5994','3300070952',8,'准则3 明确父母和孩子的职责','儿童阶段的一项重要任务是培养良好的情绪调节能力，即培养感知和管理情绪的能力，以及学习如何在各种感受、想法和冲动中找到自我，而非淹没其中。来自父母的接纳和共情是儿童发展情绪调节能力的关键因素。','5847-5994',1,1747439151,1782398544);
INSERT INTO highlights VALUES('3300070952_8_4182-4235','3300070952',8,'准则3 明确父母和孩子的职责','在上面的做法里，父母都是在要求孩子抑制某种欲望或冲动。可是坦白说，尚未发育完全的孩子基本没有能力做到这一点','4182-4235',1,1747438925,1782398544);
INSERT INTO highlights VALUES('3300070952_7_10403-10487','3300070952',7,'准则2 真相不唯一','我们需要把行为（我们做了什么）与我们自身（我们的本心）区分开来。','10403-10487',1,1747438278,1782398544);
INSERT INTO highlights VALUES('3300070952_7_10550-10576','3300070952',7,'准则2 真相不唯一','其一，我们的本心是好的。其二，我们也需要努力去改进。','10550-10576',1,1747438266,1782398544);
INSERT INTO highlights VALUES('3300070952_7_8575-8609','3300070952',7,'准则2 真相不唯一','父母：“嗯，那咱们该怎么办呢？我们肯定能想出一个我们都满意的办法。”','8575-8609',1,1747438025,1782398544);
INSERT INTO highlights VALUES('3300070952_7_4506-4542','3300070952',7,'准则2 真相不唯一','孩子既需要父母了解并肯定他们的感受，又需要明白感受不能代替和干扰决策本身','4506-4542',1,1747437648,1782398544);
INSERT INTO highlights VALUES('3300070952_7_3671-3719','3300070952',7,'准则2 真相不唯一','健康就是能够身处多种现实之间，不忽视其中任何一种，就是既能走进许多人的内心，又能拥有独立的自我。','3671-3719',1,1747437424,1782398544);
INSERT INTO highlights VALUES('3300070952_7_1172-1269','3300070952',7,'准则2 真相不唯一','构筑牢固关系的前提是双方共同认定没有谁绝对正确，因为人在关系中的安全感来自理解，而非说服。','1172-1269',1,1747437149,1782398544);
INSERT INTO highlights VALUES('3300070952_7_990-1111','3300070952',7,'准则2 真相不唯一','只有具备同时接纳多重真相（例如我们眼中的真相和对方眼中的真相）的能力，关系中的双方才能感受到自己被看见，感受到自己的存在，哪怕两人存在分歧','990-1111',1,1747437138,1782398544);
