INSERT INTO highlights VALUES('3300070952_6_4202-4249','3300070952',6,'第1部分 贝姬医生的育儿准则','我们儿时的养育者回应我们的方式，随后会成为我们回应自己的方式，而我们也会将这一方式传递给下一代','4202-4249',1,1747436563,1782398544);
INSERT INTO highlights VALUES('3300070952_6_2344-2425','3300070952',6,'第1部分 贝姬医生的育儿准则','许多父母把行为当作评判孩子的标尺，而非洞察孩子需要的线索。','2344-2425',1,1747436329,1782398544);
INSERT INTO highlights VALUES('3300070952_6_1694-1731','3300070952',6,'第1部分 贝姬医生的育儿准则','把人本身与他们做的事区分开来，是引发深刻改变，同时又不影响亲子感情的关键。','1694-1731',1,1747436235,1782398544);
