INSERT INTO highlights VALUES('920149_6_1333-1438','920149',6,'宋雨：阿勒泰下雪了','如何从私人情感空间逐渐走向更为开阔的生命情感现场，或者说，怎样从自怨自艾、自怜自爱的状态里走出来，蜕变成一个气韵充沛，充满说服力的诗人，除了需要生活的沉淀外，可能还需要更加开阔的视野，需要更为强健的精神推动力。','1333-1438',NULL,1613440390,1782398657);
