INSERT INTO highlights VALUES('920149_5_1783-1868','920149',5,'魔头贝贝：让我们来数数锯齿','成就一个写作者的无外乎是两种东西：生活经历与人生经验，前者需要你用肉身去穿越，后者需要你具有“一只强大的胃”，去吸纳，去消化，然后从中提炼出你对生活的态度和你的审美眼光。','1783-1868',NULL,1613402010,1782398657);
