INSERT INTO highlights VALUES('920149_42_6169-6860','920149',42,'张二棍：把去年的棺木再漆一遍','挪用一个词比如，“安详”也可以用来形容屋檐下，那两只形影不离的麻雀但更多的时刻，“安详”被我不停地挪用着比如暮色中，矮檐下两个老人弯下腰身在他们，早年备好的一双棺木上，又刷了一遍漆老两口子一边刷漆一边说笑。棺木被涂抹上迷人的油彩。去年或者前年，他们就刷过那时候，他们也很安详但棺材的颜色，显然没有现在这么深——呃，安详的色彩也是一层一层加深的','6169-6860',NULL,1612854545,1782398657);
INSERT INTO highlights VALUES('920149_42_5480-6107','920149',42,'张二棍：把去年的棺木再漆一遍','黑夜了，我们还坐在铁路桥下幸好桥上的那些星星我真的摘不下来幸好你也不舍得，我爬那么高去冒险。我们坐在地上你一边抛着小石头一边抛着奇怪的问题你六岁了，怕黑，怕远方怕火车大声的轰鸣怕我又一个人坐着火车去了远方。你靠得我那么近，让我觉得你就是，我分出来的一小块儿最骄傲的一小块儿别人肯定不知道，你模仿着火车鸣笛的时候，我内心已锃亮而辽远。我已为你，铺好铁轨我将用一生，等你通过','5480-6107',NULL,1612854512,1782398657);
INSERT INTO highlights VALUES('920149_42_4832-5418','920149',42,'张二棍：把去年的棺木再漆一遍','静夜思等着炊烟，慢慢托起缄默的星群有的星星，站得很高仿佛祖宗的牌位有一颗，很多年了守在老地方，像娘有那么几颗，还没等我看清就掉在不知名的地方像乡下那些穷亲戚没听说怎么病就不在了。如果你问我哪一颗像我，我真的不敢随手指点。小时候我太过顽劣，伤害了很多萤火虫。以至于现在我愧疚于，一切微细的光','4832-5418',NULL,1612854489,1782398657);
INSERT INTO highlights VALUES('920149_42_4184-4770','920149',42,'张二棍：把去年的棺木再漆一遍','穿墙术你有没有见过一个孩子摁着自己的头，往墙上磕我见过。在县医院咚，咚，咚他母亲说，让他磕吧似乎墙疼了他就不疼了似乎疼痛，可以穿墙而过 我不知道他脑袋里装着什么病。也不知道一面墙吸纳了多少苦痛才变得如此苍白就像那个背过身去的母亲。后来，她把孩子搂住仿佛一面颤抖的墙伸出了手','4184-4770',NULL,1612854445,1782398657);
INSERT INTO highlights VALUES('920149_42_2601-2859','920149',42,'张二棍：把去年的棺木再漆一遍','六言因为拥有翅膀鸟群高于大地因为只有翅膀白云高于群鸟因为物我两忘天空高于一切因为苍天在上我愿埋首人间','2601-2859',NULL,1612854353,1782398657);
