INSERT INTO highlights VALUES('23863103_8_348-431','23863103',8,'关于《罗汉池》','当匠心独运的雕刻家（艺术家）把这两个原本泾渭分明，一个“出世”，一个“入世”，方向原本相背的命题巧妙合而为一的时候，宗教可以像爱情一般深情，爱情也可能像宗教一般无私；','348-431',NULL,1587194428,1782398689);
INSERT INTO highlights VALUES('23863103_7_427-500','23863103',7,'关于《猴子》','吕秋美终于决定为爱出走，“我”是唯一的目击者，“我”感到无限惆怅，因为不再有人陪我一起等待，我的心中下起一阵骤雨，即使那是一个阳光灿烂的夏日午后。','427-500',NULL,1587194227,1782398689);
INSERT INTO highlights VALUES('23863103_3_25397-25472','23863103',3,'猴子','火柴烧了大半了，橘黄色的光点开始颤抖、缩小。    我看见自己缩成一团青色的淡影扁扁地倒在马桶上。    火柴熄灭了，厕所内又回复到一片黑暗。','25397-25472',NULL,1587107908,1782398689);
INSERT INTO highlights VALUES('23863103_3_18390-18421','23863103',3,'猴子','我从愉快的幻想里探出头来。梁羽玲还站在球场另一边正在练习发球。','18390-18421',NULL,1587102379,1782398689);
INSERT INTO highlights VALUES('23863103_3_12674-12753','23863103',3,'猴子','“怎么没有，我就吃。”荣小强话还没说完，一只油亮结实的手臂就像把火钳似的插进水池里，咬住一条大鱼尾巴往水面上揪，鱼打了个滚，泼剌一声逃回池子里，溅起一阵水花。','12674-12753',NULL,1587101638,1782398689);
INSERT INTO highlights VALUES('23863103_3_2904-2958','23863103',3,'猴子','灯熄了，人也走光了，好像一场露天电影的布幕上打出了“再会”之后，我的脑袋里只依稀卷动着一长排演员表上的名字。','2904-2958',NULL,1587092947,1782398689);
INSERT INTO highlights VALUES('23863103_3_1819-1928','23863103',3,'猴子','邱叔挤出一口黄浓浓的痰回头炸在身后边的一株昙花叶子上，然后盯了祁寡妇两眼，一时还找不到话说；祁寡妇将软趴趴的领口往上提了一下，一双短胖的手臂闲着慌似的前后甩起来，愈甩愈用力，且来回走动着，差一点一巴掌甩在我的后脑袋上。','1819-1928',NULL,1587092748,1782398689);
INSERT INTO highlights VALUES('23863103_3_783-818','23863103',3,'猴子','方才的那股狂劲完全消失了，看起来就像是一块油黑的湿抹布默默蹲在水槽里。','783-818',NULL,1587092526,1782398689);
INSERT INTO highlights VALUES('23863103_3_610-691','23863103',3,'猴子','水柱哗哗地冲，猴子把头埋进铁窗格里急促地尖叫起来，红红的一团屁股朝外，像一块烧得快熔化的热铁给浇了水，周围涨起一层血紫色，好像还有一阵白烟从猴子背上的毛缝间冒出来','610-691',NULL,1587092480,1782398689);
