INSERT INTO highlights VALUES('40315793_15_3679-3774','40315793',16,'第14章 精选的笑话和被忽略的笑话','樱桃歇息间，听到外间那书生和几个渔夫，在分析刚才砚台砸到樱桃前胸上的后果。大家七嘴八舌，说，砚台砸在平胸上，会出现三种情况：一、胸被砸得更平了；二、胸被砸凹下去了；三、胸被砸得还能肿起来点儿','6341-6436',NULL,1669521260,1782398631);
