INSERT INTO highlights VALUES('40315793_14_28225-28450','40315793',15,'第13章 明亮','“你吹的是啥？”　　“随意吹的呀。”　　“随意吹的是啥？”　　“在这个世界上，你是我找到的唯一的亲人。”　　“酸，从电视上学到的吧？”　　“是，但跟电视上不一样。”　　“有啥不一样？”　　“电视上说的都是假的，我说的是真心话。”　　“想故意感人？”　　“这还感人，应该伤心呀。”　　“啥意思？”　　“这话证明，事到如今，我在世上连个亲人都没有哇。”又说，“别人的亲人都是现成的，我还得去找，事情还不惨吗？”','40055-40555',NULL,1669470596,1782398631);
