INSERT INTO thoughts VALUES('251436658_7Z0nfOpAg','3300101680',NULL,NULL,unistr('首先被吸引是因为题目，在一地鸡毛的教育中还能笑得出来，确实是一种超能力！我觉得能在一个快速发展，变化的环境中，依旧能够寻求内心的平衡，做到真正的自洽，才有足够的底气去养育一个内心丰盈的孩子而不是传递焦虑。\u000a喜欢文中的一句话“没有什么是偶然的，你今天看到这篇文章，能读到这里，也不是偶然，你内心的频率和这篇文章的能量有共振，你才会一直看到这里，还面带微笑，是吧？一切发生，皆有缘由。”\u000a哈哈，一个没有孩子的大人在阅读本书时，把自己又重新养育了一次。依旧好奇“我为什么是我？”那就继续思考吧！'),100,'',0,1743220535,1782398548);
