INSERT INTO thoughts VALUES('251436658_7TpDxtdBa','3300026077',NULL,NULL,unistr('“她的诗，放在中国女诗人的诗歌中，就像把杀人犯放在一群大家闺秀里一样醒目：别人都穿戴整齐、涂着脂粉、喷着香水，白纸黑字，闻不出一点汗味，唯独她烟熏火燎、泥沙俱下，字与字之间，还有明显的血污。”这是非常形象的评价。因为苦难，所以她的诗里尽是惨烈的“白”，掩盖一切黑的雪，照耀一切的月光，还有她养的兔子……但苦难并不能将她掩埋，她在尘埃里昂扬，依旧期待下一个春天。\u000a虽然里面有很多超出经历的理解，但一些简单美好的意象，通过诗的语言，勾勒出的简单画面，依旧打动人心，也许这就是生活，一草一木皆是情。\u000a一个人，摇摇晃晃，用诗做拐杖，这真是绝妙的武器！'),100,'',0,1723525772,1782398562);
