INSERT INTO thoughts VALUES('251436658_7exEbdRX2','820703',22,NULL,unistr('我想到了一个古希腊的故事：几个人被锁在岩洞里，一堵墙，一团火，黑暗中只有影子相伴。一人意外逃脱出洞后，发现外面有光的神奇的世界，回来告诉同伴，同伴不仅不信，而且很生气，因为他们一生注定锁在洞里，容不得别人戳破事实，后来合伙把那人打死了。\u000a有时候“疯子”只是大多数选择自我蒙蔽的人强加给少数知道真相的人的锁链，用“疯子”把他锁住，真相也就锁住了，又能自我欺骗了。'),NULL,'819-826',0,1579594563,1782398707);
