INSERT INTO thoughts VALUES('251436658_7gfTxAnhF','26174310',46,NULL,'读者可能还都想着他父亲发生了什么，而作者故意避之不谈，一直写一些无关紧要的旁枝，“我”由电视的好处不停回忆被赶出门的情景，一样的情节，添油加醋，就像反复的电影镜头，诱导读者比较不同，每看一次，发现一点不同。作者要干嘛？“我”要干嘛？或是只是回想一点什么来打发时间？还要等多久呢？谁知道呢？！',NULL,'',0,1585629460,1782398694);
