INSERT INTO thoughts VALUES('251436658_7fZK7lMBA','26607363',77,NULL,'作者从收拾抽屉，得出道理：人总是不自觉就在浪费时间，并倡导不要把时间花在会后悔的事情上。很佩服他能从生活中的小事反思并得出感悟，但佩服之余总觉些不甘，不能完全赞同，如果时时刻刻都不浪费，岂不是又少了什么乐趣。如果一些事情不去尝试，又怎么知道是不是浪费时间。对于会后悔的事，难道做之前就那么容易辨认吗？那世界上该没有后悔之事了。',NULL,'',0,1584712023,1782398699);
