INSERT INTO thoughts VALUES('251436658_7fnonaRYM','25506340',168,NULL,unistr('活着\u000a所谓现在活着，那就是口渴\u000a是枝丫间射下来耀眼的阳光\u000a是忽然脑海里响起的一支旋律\u000a是打喷嚏\u000a是与你手牵手\u000a活着\u000a所谓现在活着\u000a那就是超短裙\u000a是天象仪\u000a是约瀚·施特劳斯\u000a是毕加索\u000a是阿尔卑斯山\u000a是与一切美好事物的邂逅\u000a而且，还要\u000a小心翼翼地提防潜藏的恶\u000a活着\u000a所谓现在活着\u000a是敢哭\u000a是敢笑\u000a是敢怒\u000a是自由\u000a活着\u000a所谓现在活着\u000a是此刻狗在远处的狂吠\u000a是现在地球的旋转\u000a是现在某处生命诞生的啼哭\u000a是现在士兵在某地负伤\u000a是现在秋千的摇荡\u000a是现在时光的流逝\u000a活着\u000a所谓现在活着\u000a是鸟儿展翅\u000a是海涛汹涌\u000a是蜗牛爬行\u000a是人在相爱\u000a是你的手温\u000a是生命'),NULL,'688-692',0,1582533693,1782398693);
