INSERT INTO thoughts VALUES('251436658_7FbS1d1Te','44346269',NULL,NULL,unistr('这本书是记者写的，非常好的一点是她用事实和数据说话，并不直接给出观点，给读者留白，形成自己的理解。\u000a最大的感受是:只有知道的更多，才能站在更多不同的角度去思考问题，没有一个问题是简单的，只有一个答案，教育也是。没有完美的教育，每个国家教育都存在问题，但影响最大的问题是什么？每一个政策出台的目的又是什么？它有直接解决现实的问题吗？它与要培养什么样的人的目标有没有背道而驰呢？改革是困难的，但一成不变是长久的灾难，时间和实践将会检验真理。'),100,'',0,1673441229,1782398628);
