INSERT INTO thoughts VALUES('251436658_7KhEkqLZT','839748',NULL,NULL,unistr('郭金牛的这本诗集写出了底层打工人的悲苦，诗中的意象和句法很特别，虽无一处写苦，却处处见苦，冷静又具体的悲苦。最近在读劳动人民的诗，王计兵《赶时间的人》，他是一名外卖员，打工路途的风景与人事成为他笔下的诗，诗风朴素却深刻，好懂；陈年喜《陈年喜的诗》，他是一名矿工，爆破工作使他的诗有土地的大气，历史的沧桑，诗多以地点为名，其中多为工人迁徙的乡愁，相比其他写法有些单一。\u000a《纸上还乡》写法变换，意象变幻，句法变化，读完似懂非懂，但又很有感触，也许有了阅历后再来读，会有不一样的感受。'),100,'',0,1691377562,1782398609);
