INSERT INTO thoughts VALUES('251436658_7fwuNeOTZ','857264',46,NULL,unistr('\u000a回忆童年，好像很快乐，在田野里撒腿，在山里乱窜，在河里淌水……，但很难不让人怀疑，那是不是真的，有多少自己幻想的成分。回忆会装饰，把美好的装饰得更美好！而现在，当下，不用回忆，看着自己的二十多岁，撇开装饰，平凡朴素，似乎什么都没有，但也搞不清自己的二十多岁是什么样子。'),NULL,'',0,1583050777,1782398701);
