INSERT INTO thoughts VALUES('251436658_7fw99VYkO','857264',5,NULL,unistr('大学时也遇到过体面的流浪汉，要求在食堂帮付一顿饭钱，他难为情地说，我也很尴尬，没有拒绝。\u000a想起来生活中总有不好意思说出口的事情，当别人顶着被拒绝的难堪鼓起勇气说出口时，实在不好意思拒绝。'),NULL,'',0,1583030958,1782398701);
