INSERT INTO reading_stats VALUES(7,'annually',0,'{"readTimes":{"1767196800":4192,"1769875200":8826,"1772294400":10842,"1774972800":3910,"1777564800":7969,"1780243200":54,"1782835200":0,"1785513600":0,"1788192000":0,"1790784000":0,"1793462400":0,"1796054400":0},"readDays":27,"readRecordsWord":"书籍分布","readLongest":[{"book":{"bookId":"3300150171","title":"呼兰河传","author":"萧红","intro":"萧红，中国著名女性作家，被誉为“30年代的文学洛神”。萧红出生于黑龙江呼兰县的呼兰河畔。作为一代人的教科书文章，《呼兰河传》是萧红知名度最高的作品之一，祖父的后花园让人心驰神往。萧红以孩子对故乡的柔情描绘着呼兰河的一草一木，又以进步人士的视角批判故乡的愚昧与残忍。在依恋与批判的矛盾中，萧红于20岁逃离了故乡。唯余《呼兰河传》，记录着萧红二十年的岁月与人生。","cover":"https://cdn.weread.qq.com/weread/cover/42/cpplatform_ec8uuw5oikef9vxpga6ztv/s_cpplatform_ec8uuw5oikef9vxpga6ztv1750759808.jpg","version":1081380258,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":3,"maxFreeInfo":{"maxfreeChapterIdx":3,"maxfreeChapterUid":3,"maxfreeChapterRatio":100},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2025-06-26 00:00:00","lastChapterIdx":10,"paperBook":{"skuId":""},"centPrice":3900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":18034,"tags":[]},{"book":{"bookId":"3300119345","title":"我应该，我要，我愿意（女性主义诗人焦野绿 全新女性力量诗集）","author":"焦野绿","intro":"本书是专治焦虑的95后女性主义诗人、小红书头部青年诗人焦野绿的全新女性力量诗集《我应该，我要，我愿意》，全书收录212首最新原创诗歌。\n这部作品中，焦野绿透过女性诗人细腻的视角，立足日常，为普通人发声。\n全书共五个章节，从开始面对心中的呐喊走向成长与勇气，从学会拥抱世界到接受爱和自己，每一首诗都是她人生中往前行走的足迹。\n涂鸦是焦野绿创作的独特方式，作为95后，她脱离传统诗歌的写作框架，用年轻的语言，前卫的方法，把诗歌带到大街小巷，让诗意和真实生活碰撞。在这本书里，读者与作者同频，在诗句之间感受被理解、被看到、被表达的喜悦；他们关心世界，更关心自己。\n“这天地广阔，有一半是我的”\n“我会踩着时间的骨头，成为勇者”\n“暂时只爱自己，停止招待过客”\n“我应该，我要，我愿意”\n……\n焦野绿把年轻人那些迷茫、焦虑以及如鲠在喉的痛苦都写下来，在新颖、轻盈的表达中给人治愈的力量：我要用尽全力，不让自己成为别人。","cover":"https://cdn.weread.qq.com/weread/cover/67/cpplatform_scnnhjahwbmpevtkpgcaae/s_cpplatform_scnnhjahwbmpevtkpgcaae1730774980.jpg","version":1080400600,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":28,"maxFreeInfo":{"maxfreeChapterIdx":28,"maxfreeChapterUid":28,"maxfreeChapterRatio":75},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16566968,"publishTime":"2024-05-01 00:00:00","lastChapterIdx":214,"paperBook":{"skuId":""},"centPrice":2800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":6527,"tags":["笔记最多","单日阅读最久"]},{"book":{"bookId":"3300201028","title":"人呐（用极短的时间读懂极深的人心）","author":"莫言","intro":"用极短的时间，读懂极深的人心。\n 献给每一个在世事中浮沉、在人情里挣扎的现代人。\n《人呐》是莫言时隔六年推出的全新短篇小说集，收录 81 篇精悍之作。篇幅虽短，意犹未尽；文字极简，力道千钧。莫言以半生阅世的通透与悲悯，将人间百态、人性幽微凝于数百字之间，写尽人心深处的复杂与纯粹、温热与寒凉、荒诞与坚韧。\n他不把故事写满，只留下冰山一角；不把道理说尽，只留给读者无限想象。这部作品既是莫言对自身写作边界的再度突破，更是一位文学大家历经千帆、阅尽沧桑后，对“人”这一命题朴素又深刻的叩问与感慨：人呐，本就藏着世间的答案。\"\n翻开本书，去窥探一个个真实又荒诞的灵魂。","cover":"https://cdn.weread.qq.com/weread/cover/56/cpplatform_jblifhwlknxy75ola6zofn/s_cpplatform_jblifhwlknxy75ola6zofn1775792084.jpg","version":495182888,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":15,"maxFreeInfo":{"maxfreeChapterIdx":15,"maxfreeChapterUid":98,"maxfreeChapterRatio":86},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2026-03-30 00:00:00","lastChapterIdx":89,"paperBook":{"skuId":""},"centPrice":5990,"copyrightChapterUids":[85],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":3766,"tags":[]},{"book":{"bookId":"3300153973","title":"缓慢而永远","author":"姬中宪","intro":"《缓慢而永远》这本书将“缓慢而永远”这句话深埋进许多人的体内，成为心底最柔软又最有力的一对词，也是这个时代的反义词。这本书没有刺激的噱头和热搜一时的话题，仅在读者口耳间私密传阅，却慢慢汇聚起一股共情的洪流，让那些有情而无力的人辨认出彼此：\n“我匮乏的词语很难形容出这本书带给我的感觉，读的过程中泪珠无数次地滑落，也有一些片断让我乐不可支，笑出声来。”\n“作者像是掌握了言语真谛的人，朴实有力，又点到即止，写到人的心窝窝里。”\n“书中故事各各风味相异，合起来竟是宏大的一部生命篇章。”\n“简直大幅复刻我的生活，我真的和作者差了一辈吗？”\n世上并非没有真正的感同身受，人类的悲喜可以相通。它不提供虚假治愈，而是将人生困境对象化、可视化，正是在这样的隔书凝视中，我们不知不觉地完成了对自我的疗愈。它不提供鸡汤式答案，却迂回地解答了这本书副标题的那个问题：我们该以怎样的方式度过这一生？\n•～•～•～•～•～•～•～•～•～••～•～•～•～•～•～•～•～•～•\n姬中宪，著有小说《花言》《穿西装的椅子》《一二三四舞》《我不爱你》《阑尾》，杂文集《我仍然没有与这个世界握手言和》等，获第十届上海文学奖、中峻杯《小说选刊》最佳读者印象奖、《十月》县@智征文大赛首奖、第十一届储吉旺文学奖、腾讯“瞬间与永恒”短小说大赛第一名等。生于山东，现居上海，曾是中国第一代职业社工，现任教于华东政法大学社会发展学院。","cover":"https://cdn.weread.qq.com/weread/cover/21/cpplatform_dq1sv9jvo2nu9pxqyhmilo/s_cpplatform_dq1sv9jvo2nu9pxqyhmilo1753255916.jpg","version":685545138,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":12,"maxFreeInfo":{"maxfreeChapterIdx":12,"maxfreeChapterUid":12,"maxfreeChapterRatio":20},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":17629620,"publishTime":"2020-08-01 00:00:00","lastChapterIdx":28,"paperBook":{"skuId":""},"centPrice":3840,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":3585,"tags":[]},{"book":{"bookId":"3300153784","title":"她乡","author":"陈慧","intro":"「菜场女作家」陈慧继广受欢迎的《在菜场，在人间》后，再次回归人物叙事，以泥土般质朴的笔触与月光般温柔的凝视，讲述中国小镇女性的生活和命运。 \n在江苏平原的村庄、浙江小镇的乡下，作者目之所及的女性大多过着朴素而沉默的生活。她以筛米粒般的耐心，筛去猎奇的稗子与矫饰的秕谷，如实写下她们的喜怒哀乐，让她们不再是陌生的剪影，而就像是读者身边的某个女性长辈或女性友邻。\n作者写“她们”的故事——邻居、朋友、顾客、同一个菜场的小贩，也写“我们”的故事——我、养母、奶奶、姑姨和姐妹……以亲历者的身份记录下平民女性可敬、可爱、可怜、可感的多种样子，以平等的视角记录下生命与生活的本真。","cover":"https://cdn.weread.qq.com/weread/cover/40/cpplatform_6zn53gzfatfkb53habe9s8/s_cpplatform_6zn53gzfatfkb53habe9s81753166118.jpg","version":702939161,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":4,"maxfreeChapterRatio":11},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2025-07-01 00:00:00","lastChapterIdx":20,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1347,"tags":[]},{"book":{"bookId":"43168703","title":"植物的战斗","author":"汪诘 科学有故事团队","intro":"所有的动物都不能离开植物存活，植物没有大脑，却有超级智能，它们放弃移动，却能反击同类、诱捕动物、与人类相爱相杀，是地表超强生物！本书梳理29类植物的6大生存法则，从进击的勇士地衣将生命带到陆地开始；到伪装大师兰花的欺骗套路；驯服高手辣椒、咖啡、小麦等改变自己也改变了世界；有毒植物的目的是传播种子；信息间谍菟丝子；百变魔法师薄荷颠覆人类对冷热的理解。看植物从一粒种子活成一支部队，探索植物生存的根基，揭秘植物机体的奥秘，读懂植物38亿年的生存史，就在认识世界的道路上又前进了一小步。","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/703/43168703/s_43168703.jpg","version":2103403557,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":38,"maxfreeChapterRatio":72},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-60041,"publishTime":"2022-01-01 00:00:00","lastChapterIdx":33,"paperBook":{"skuId":""},"centPrice":6800,"copyrightChapterUids":[34],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":953,"tags":[]},{"book":{"bookId":"3300131550","title":"子午线诗歌译丛  我只要少许：简·赫斯菲尔德诗选","author":"简·赫斯菲尔德 著","translator":"史春波 ","intro":"《我只要少许》是从美国诗人简·赫斯菲尔德的新诗集《问：新诗与诗选》及已出版的九部诗集中精选的其创作生涯各时期具有代表性的作品。简·赫斯菲尔德是当代英语世界中极富声誉的女诗人，诗作亦受到中国古典文学与日本诗歌影响，擅长以理性、克制的诗思和简练、富有哲学深意的语言揭示日常生活中潜藏的智慧，提醒人类与自然之间紧密而互为因果的关系。她极具个性的写作风格为读者带来不同层次的诗歌养分，近年来为愈来愈多的中国读者所认识和喜爱。","cover":"https://cdn.weread.qq.com/weread/cover/70/cpplatform_3zq9ukiovekxa9k8vvaukb/s_cpplatform_3zq9ukiovekxa9k8vvaukb1737362111.jpg","version":2085529142,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":23,"maxFreeInfo":{"maxfreeChapterIdx":23,"maxfreeChapterUid":23,"maxfreeChapterRatio":29},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5207994,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":239,"paperBook":{"skuId":""},"centPrice":2900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":544,"tags":[]},{"book":{"bookId":"40747885","title":"教室里的非暴力沟通","author":"苏拉·哈特 维多利亚·霍德森","translator":"杨洁","intro":"1999年非暴力沟通中心发起一个教育项目，为学校开发教学材料，为教师提供培训。《教室里的非暴力沟通》这本书正是非暴力沟通中心教育项目的成果之一。通过阐释非暴力沟通的一些基本前提，《教室里的非暴力沟通》勾勒出一个模式，它让教师们很乐意与学生分享交流，帮助教师把课堂变得生动，让师生以及学生之间能够相互理解、相互关心，释放孩子天性中的学习渴望。","cover":"https://cdn.weread.qq.com/weread/cover/31/YueWen_40747885/s_YueWen_40747885.jpg","version":95712780,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":9,"maxfreeChapterRatio":12},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":18192240,"publishTime":"2015-05-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2100,"copyrightChapterUids":[],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":526,"tags":[]}],"preferCategory":[{"categoryId":300000,"categoryTitle":"文学","parentCategoryId":300000,"parentCategoryTitle":"文学","readingCount":5,"readingTime":30091},{"categoryId":100001,"categoryTitle":"社会小说","parentCategoryId":100000,"parentCategoryTitle":"精品小说","readingCount":2,"readingTime":5113},{"categoryId":100022,"categoryTitle":"治愈小说","parentCategoryId":100000,"parentCategoryTitle":"精品小说","readingCount":1,"readingTime":3589},{"categoryId":100020,"categoryTitle":"女性小说","parentCategoryId":100000,"parentCategoryTitle":"精品小说","readingCount":1,"readingTime":1347},{"categoryId":1500000,"categoryTitle":"科学技术","parentCategoryId":1500000,"parentCategoryTitle":"科学技术","readingCount":1,"readingTime":953},{"categoryId":1400000,"categoryTitle":"教育学习","parentCategoryId":1400000,"parentCategoryTitle":"教育学习","readingCount":1,"readingTime":526},{"categoryId":1000000,"categoryTitle":"个人成长","parentCategoryId":1000000,"parentCategoryTitle":"个人成长","readingCount":0,"readingTime":0},{"categoryId":200000,"categoryTitle":"历史","parentCategoryId":200000,"parentCategoryTitle":"历史","readingCount":0,"readingTime":0}],"preferCategoryWord":"偏好阅读文学","readStat":[{"stat":"读过","counts":"8本"},{"stat":"读完","counts":"1本"},{"stat":"阅读","counts":"27天"},{"stat":"笔记","counts":"35条"}],"registTime":1528859683,"compare":-0.6769864704863117,"dayAverageReadTime":203,"baseTime":1767196800,"totalReadTime":35793,"readDistributionWord":"点评分布","preferBooks":[{"type":13,"title":"我的最爱"},{"type":1,"title":"近期偏爱"},{"type":0,"title":"常读常新"},{"type":5,"title":"思考最多","bookInfo":{"bookId":"3300119345","title":"我应该，我要，我愿意（女性主义诗人焦野绿 全新女性力量诗集）","author":"焦野绿","intro":"本书是专治焦虑的95后女性主义诗人、小红书头部青年诗人焦野绿的全新女性力量诗集《我应该，我要，我愿意》，全书收录212首最新原创诗歌。\n这部作品中，焦野绿透过女性诗人细腻的视角，立足日常，为普通人发声。\n全书共五个章节，从开始面对心中的呐喊走向成长与勇气，从学会拥抱世界到接受爱和自己，每一首诗都是她人生中往前行走的足迹。\n涂鸦是焦野绿创作的独特方式，作为95后，她脱离传统诗歌的写作框架，用年轻的语言，前卫的方法，把诗歌带到大街小巷，让诗意和真实生活碰撞。在这本书里，读者与作者同频，在诗句之间感受被理解、被看到、被表达的喜悦；他们关心世界，更关心自己。\n“这天地广阔，有一半是我的”\n“我会踩着时间的骨头，成为勇者”\n“暂时只爱自己，停止招待过客”\n“我应该，我要，我愿意”\n……\n焦野绿把年轻人那些迷茫、焦虑以及如鲠在喉的痛苦都写下来，在新颖、轻盈的表达中给人治愈的力量：我要用尽全力，不让自己成为别人。","cover":"https://cdn.weread.qq.com/weread/cover/67/cpplatform_scnnhjahwbmpevtkpgcaae/s_cpplatform_scnnhjahwbmpevtkpgcaae1730774980.jpg","version":1080400600,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":28,"maxFreeInfo":{"maxfreeChapterIdx":28,"maxfreeChapterUid":28,"maxfreeChapterRatio":75},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16566968,"publishTime":"2024-05-01 00:00:00","lastChapterIdx":214,"paperBook":{"skuId":""},"centPrice":2800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"笔记最多"},{"type":3,"title":"最沉浸的"},{"type":4,"title":"读到深夜"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"3300153784","title":"她乡","author":"陈慧","intro":"「菜场女作家」陈慧继广受欢迎的《在菜场，在人间》后，再次回归人物叙事，以泥土般质朴的笔触与月光般温柔的凝视，讲述中国小镇女性的生活和命运。 \n在江苏平原的村庄、浙江小镇的乡下，作者目之所及的女性大多过着朴素而沉默的生活。她以筛米粒般的耐心，筛去猎奇的稗子与矫饰的秕谷，如实写下她们的喜怒哀乐，让她们不再是陌生的剪影，而就像是读者身边的某个女性长辈或女性友邻。\n作者写“她们”的故事——邻居、朋友、顾客、同一个菜场的小贩，也写“我们”的故事——我、养母、奶奶、姑姨和姐妹……以亲历者的身份记录下平民女性可敬、可爱、可怜、可感的多种样子，以平等的视角记录下生命与生活的本真。","cover":"https://cdn.weread.qq.com/weread/cover/40/cpplatform_6zn53gzfatfkb53habe9s8/s_cpplatform_6zn53gzfatfkb53habe9s81753166118.jpg","version":702939161,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":4,"maxfreeChapterRatio":11},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2025-07-01 00:00:00","lastChapterIdx":20,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"2026/01/02/阅读"},{"type":6,"title":"最爱文学","bookInfo":{"bookId":"3300150171","title":"呼兰河传","author":"萧红","intro":"萧红，中国著名女性作家，被誉为“30年代的文学洛神”。萧红出生于黑龙江呼兰县的呼兰河畔。作为一代人的教科书文章，《呼兰河传》是萧红知名度最高的作品之一，祖父的后花园让人心驰神往。萧红以孩子对故乡的柔情描绘着呼兰河的一草一木，又以进步人士的视角批判故乡的愚昧与残忍。在依恋与批判的矛盾中，萧红于20岁逃离了故乡。唯余《呼兰河传》，记录着萧红二十年的岁月与人生。","cover":"https://cdn.weread.qq.com/weread/cover/42/cpplatform_ec8uuw5oikef9vxpga6ztv/s_cpplatform_ec8uuw5oikef9vxpga6ztv1750759808.jpg","version":1081380258,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":3,"maxFreeInfo":{"maxfreeChapterIdx":3,"maxfreeChapterUid":3,"maxfreeChapterRatio":100},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2025-06-26 00:00:00","lastChapterIdx":10,"paperBook":{"skuId":""},"centPrice":3900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了5小时"},{"type":2,"title":"最爱分享"},{"type":12,"title":"共读最多"},{"type":10,"title":"欣赏小众"},{"type":8,"title":"总有一天读完"}]}',1782398784);
INSERT INTO reading_stats VALUES(8,'overall',0,'{"readTimes":{"1514736000":246515,"1546272000":182323,"1577808000":579302,"1609430400":105159,"1640966400":212747,"1672502400":353245,"1704038400":173310,"1735660800":229804,"1767196800":35793},"readDays":914,"readLongest":[{"book":{"bookId":"519185","title":"长相思（赵丽颖、杨洋主演）","author":"桐华","intro":"同名电视剧由赵丽颖、杨洋主演，2018年即将开拍。桐华继《大漠谣》《云中歌》《曾许诺》后历经三年创作，再现上古时代瑰丽多姿的爱情神话。写不尽的儿女情长，说不完的地老天荒，最恢宏的画卷，最动人的故事，最浩大的恩怨，最纠结的爱恨，尽在桐华《长相思》。","cover":"http://wfqqreader-1252317822.image.myqcloud.com/cover/185/519185/s_519185.jpg","version":0,"format":"txt","type":0,"soldout":1,"bookStatus":2,"payType":1,"finished":1,"maxFreeChapter":16,"maxFreeInfo":{"maxfreeChapterIdx":16,"maxfreeChapterUid":16,"maxfreeChapterRatio":54},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":0,"publishTime":"2013-03-01 00:00:00.0","lastChapterIdx":151,"paperBook":{"skuId":""},"centPrice":1200,"copyrightChapterUids":[],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":true,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":114045,"tags":["单日阅读最久"]},{"book":{"bookId":"823534","title":"巨人的陨落（全集）","author":"肯·福莱特","translator":"于大卫","intro":"今年最火的外国文学！全球读者平均3个通宵读完！在第一次世界大战的硝烟中，每一个迈向死亡的生命都在热烈地生长——威尔士的矿工少年、刚失恋的美国法律系大学生、穷困潦倒的俄国兄弟、富有英俊的英格兰伯爵，以及痴情的德国特工……从充满灰尘和危险的煤矿到闪闪发光的皇室宫殿，从代表着权力的走廊到爱恨纠缠的卧室，五个家族迥然不同又纠葛不断的命运逐渐揭晓，波澜壮阔地展现了一个我们自认为了解，但从未如此真切感受过的20世纪。","cover":"https://cdn.weread.qq.com/weread/cover/57/yuewen_823534/s_yuewen_8235341677835489.jpg","version":1416930052,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":15,"maxFreeInfo":{"maxfreeChapterIdx":15,"maxfreeChapterUid":15,"maxfreeChapterRatio":64},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":124,"paperBook":{"skuId":""},"centPrice":12980,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-CN","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":112506,"tags":[]},{"book":{"bookId":"3300025230","title":"长得好看能当饭吃吗：提升认知的33个经济学常识","author":"谢宗博","intro":"水是必需品都这么便宜，钻石没什么用为啥那么贵？\r\n为什么男朋友会在虚拟游戏中花费巨资买道具？\r\n我这么优秀，为什么还是剩下了？\r\n餐厅为什么会有“饮料无限续杯”的服务，不怕被喝破产吗？\r\n我年轻力壮还需要买保险吗？\r\n……\r\n在生活中，我们常常会面临一些疑问和困惑。其实，生活中的一切问题都可以在经济学中找到答案。本书提出了生活中经常遇到的33个问题，通过讲故事的手法，结合现实生活中的实例，从经济学角度进行分析，你会发现，所有的问题都能用经济学进行解答。掌握经济学思维，能帮你更通透的认清人生中各种事件背后的逻辑，从而更好地做好人生抉择。","cover":"https://cdn.weread.qq.com/weread/cover/63/cpPlatform_xqUDh8Yhgiz5xypk5RBAph/s_cpPlatform_xqUDh8Yhgiz5xypk5RBAph.jpg","version":1969655778,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":9,"maxfreeChapterRatio":1},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":17824239,"publishTime":"2022-04-01 00:00:00","lastChapterIdx":43,"paperBook":{"skuId":"13199617"},"centPrice":4599,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":62103,"tags":[]},{"book":{"bookId":"3300049180","title":"小巷人家（同名影视原著）","author":"大米","intro":"20世纪70年代末，苏州棉纺厂家属区一条小巷里住着庄家、林家、吴家三个家庭，恢复高考、知青返城和改革开放等时代变迁让三家家长和孩子们的命运都发生了翻天覆地的变化。\n长辈们先后随时代变迁，或调动或留职停薪，各寻出路。\n晚辈们随时代变迁而拼搏。\n庄家长子庄图南考入同济建筑系，但国家统包统分，他无法决定自己的毕业去向，同时，他的暗恋对象李佳为了留沪，放弃了两人间的感情萌芽。数年后，两人在浦东新区的工地上重逢......\n次女庄筱婷考入上海交通大学，毕业后和男友林栋哲两地分居，两人瞒着家人偷偷领了结婚证......\n外甥儿向鹏飞是知青子女，他孤身一人回苏州上学，但高考落榜......\n社会青年李一鸣和宋向阳在两次落榜后，分别成为了个体工商户和乡镇企业技术员......\n邻居吴家的长女吴姗姗受家庭环境拖累，变得争强好胜......\n吴家继女张敏就读纺织职高，毕业时恰逢棉纺厂人员精简，不再招收职高或技校文凭的职工子弟......\n一方小院，袅袅炊烟，\n几家人、两代人的故事。","cover":"https://cdn.weread.qq.com/weread/cover/32/cpplatform_wxxo2bpco5xlabw5b7y38v/s_cpplatform_wxxo2bpco5xlabw5b7y38v1705993399.jpg","version":945314316,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":10,"maxFreeInfo":{"maxfreeChapterIdx":10,"maxfreeChapterUid":258,"maxfreeChapterRatio":54},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5895577,"publishTime":"2023-02-01 00:00:00","lastChapterIdx":72,"paperBook":{"skuId":""},"centPrice":2999,"copyrightChapterUids":[250],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":55149,"tags":[]},{"book":{"bookId":"23485007","title":"那些回不去的年少时光（套装全2册）","author":"桐华","intro":"桐华经典青春怀旧小说、全文修正；全二册完美收藏。总有些时光，要在过去后，才发现它已深深刻在记忆中。20世纪的最后十年，一代人最独一无二的成长记忆，小虎队、上海滩、四大天王，每当提到这些我们都无限感慨，还有那些尘封在日记里的面孔与心事……正因为短暂，青春的散场才会显得如此弥足珍贵，重要的是，我们曾经拥有那疼痛而又快乐的青春。拿起这本书，那些属于年少的记忆瞬间扑面而来，彼时的少年已经长大，属于青春的飞扬和放肆也逐渐离我们而去，胸腔里是一颗已经斑驳的心。心中，却流淌着跨越了时光的温暖，永不消逝。","cover":"https://cdn.weread.qq.com/weread/cover/15/yuewen_23485007/s_yuewen_234850071695728864.jpg","version":338802106,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":46},"free":0,"mcardDiscount":20,"ispub":2,"extra_type":5,"cpid":-60041,"publishTime":"2013-02-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":10600,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":49554,"tags":[]},{"book":{"bookId":"230107","title":"白夜行","author":"东野圭吾","translator":"刘姿君","intro":"1999年，东野圭吾41岁正值盛年，写作出道已14年，在笔力、技巧、体力和雄心上都炉火纯青，于是洋洋洒洒写出了这部鸿篇巨制《白夜行》。这种规模宏大的长篇作品在职业作家一生的创作中极为罕见，完成后基本都被视为生涯代表作。《白夜行》一经推出即成为东野圭吾的长篇小说代表作，被万千书迷视为东野圭吾作品中的无冕之·王，畅销至今。《白夜行》中文版发行量超600万册，和《嫌疑人X的献身》《恶意》《解忧杂货店》并称为东野圭吾四大杰作。","cover":"https://cdn.weread.qq.com/weread/cover/1/yuewen_230107/s_yuewen_2301071682244014.jpg","version":1259384051,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":110,"maxfreeChapterRatio":51},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":24367662,"publishTime":"2017-07-21 00:00:00","lastChapterIdx":28,"paperBook":{"skuId":""},"centPrice":3576,"copyrightChapterUids":[135],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":44482,"tags":[]},{"book":{"bookId":"25631683","title":"麦子的盖头","author":"胡学文","intro":"麦子的丈夫马豆根在煤矿事故中受了伤，完全瘫痪不能治愈，由此引发出麦子跟马豆根和老于之间充满悬疑色彩的一场人性较量，麦子用她的坚贞和执着发现了美丽谎言背后的真相，她对未来的生活究竟会做出怎样的选择。","cover":"https://cdn.weread.qq.com/weread/cover/32/YueWen_25631683/s_YueWen_25631683.jpg","version":0,"format":"txt","type":0,"soldout":1,"bookStatus":1,"payType":1,"finished":1,"maxFreeChapter":3,"maxFreeInfo":{"maxfreeChapterIdx":3,"maxfreeChapterUid":3,"maxfreeChapterRatio":100},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":0,"publishTime":"2019-04-01 00:00:00","lastChapterIdx":8,"paperBook":{"skuId":""},"centPrice":2200,"copyrightChapterUids":[],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":true,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":36905,"tags":[]},{"book":{"bookId":"3300008362","title":"意象的帝国：诗的写作课","author":"黄梵","intro":"《意象的帝国：诗的写作课》是作家、诗人黄梵在其系列写作课讲课录音的基础上重新修订、增补而成。全书分为“受用一生的写作观念”“一堂课学会写出好诗句”“新诗写作的核心”“写出整首诗的若干方法”等四堂写作课，针对诗歌创意写作的思路和具体方法路径展开讲解、阐释，是一本具有整体性、实操性的新诗写作指南。","cover":"https://cdn.weread.qq.com/weread/cover/62/3300008362/s_3300008362.jpg","version":1376444221,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":4,"maxfreeChapterRatio":29},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5207994,"publishTime":"2021-08-01 00:00:00","lastChapterIdx":8,"paperBook":{"skuId":""},"centPrice":2380,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":35785,"tags":[]},{"book":{"bookId":"26174310","title":"送行","author":"袁哲生","intro":"1995年，袁哲生出版首部作品《静止在树上的羊》，隐约展现日后的小说风格，本书“辑一”即来自于此作。在“辑二”文学评论里，我们则见证小说家与其他创作者的隐秘关联。到了“辑三”“辑四”，袁哲生书写出《温泉浴池》《偏远的哭声》等成熟之作。从最初到最终，从袁哲生的小说到他的私人手札，我们得以见证一个经典作者的诞生。","cover":"https://cdn.weread.qq.com/weread/cover/40/YueWen_26174310/s_YueWen_26174310.jpg","version":161260036,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":10,"maxFreeInfo":{"maxfreeChapterIdx":10,"maxfreeChapterUid":10,"maxfreeChapterRatio":31},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":9555120,"publishTime":"2019-07-20 00:00:00","lastChapterIdx":175,"paperBook":{"skuId":""},"centPrice":1399,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":35694,"tags":[]},{"book":{"bookId":"820703","title":"一头想要被吃掉的猪","author":"朱利安·巴吉尼","translator":"吴奕俊","intro":"·如果研究红颜色的专家是红绿色盲，还算不算专家？ ·如果实现了长生不死，那么每一天的意义是什么？ ·如果救生艇上的物资只够维持12个人的生命，那么第13个人还要不要救？ ·如果一幅被埋葬的作品公之于众之际就会被损毁，该不该公开？ ·“忒修斯”号船在修补过程中材料被全部替换，用替换下的旧材料又建造了一艘船，那么哪一艘才是原来的“忒修斯”号呢？ …… 100个思想实验，挖掘我们的真实想法和思想漏洞。","cover":"https://wfqqrea