:"再阅读 0 小时可得","title":"阅读时长","rankText":"第2878891位获得此勋章的书友","displayText":"阅读 100 小时"}],"registTime":1528859683,"readDistributionWord":"点评分布","baseTime":0,"totalReadTime":2129952,"readRecordsWord":"书籍分布","preferBooks":[{"type":13,"title":"我的最爱","bookInfo":{"bookId":"3300049180","title":"小巷人家（同名影视原著）","author":"大米","intro":"20世纪70年代末，苏州棉纺厂家属区一条小巷里住着庄家、林家、吴家三个家庭，恢复高考、知青返城和改革开放等时代变迁让三家家长和孩子们的命运都发生了翻天覆地的变化。\n长辈们先后随时代变迁，或调动或留职停薪，各寻出路。\n晚辈们随时代变迁而拼搏。\n庄家长子庄图南考入同济建筑系，但国家统包统分，他无法决定自己的毕业去向，同时，他的暗恋对象李佳为了留沪，放弃了两人间的感情萌芽。数年后，两人在浦东新区的工地上重逢......\n次女庄筱婷考入上海交通大学，毕业后和男友林栋哲两地分居，两人瞒着家人偷偷领了结婚证......\n外甥儿向鹏飞是知青子女，他孤身一人回苏州上学，但高考落榜......\n社会青年李一鸣和宋向阳在两次落榜后，分别成为了个体工商户和乡镇企业技术员......\n邻居吴家的长女吴姗姗受家庭环境拖累，变得争强好胜......\n吴家继女张敏就读纺织职高，毕业时恰逢棉纺厂人员精简，不再招收职高或技校文凭的职工子弟......\n一方小院，袅袅炊烟，\n几家人、两代人的故事。","cover":"https://cdn.weread.qq.com/weread/cover/32/cpplatform_wxxo2bpco5xlabw5b7y38v/s_cpplatform_wxxo2bpco5xlabw5b7y38v1705993399.jpg","version":945314316,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":10,"maxFreeInfo":{"maxfreeChapterIdx":10,"maxfreeChapterUid":258,"maxfreeChapterRatio":54},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5895577,"publishTime":"2023-02-01 00:00:00","lastChapterIdx":72,"paperBook":{"skuId":""},"centPrice":2999,"copyrightChapterUids":[250],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了10天"},{"type":1,"title":"近期偏爱","bookInfo":{"bookId":"3300119345","title":"我应该，我要，我愿意（女性主义诗人焦野绿 全新女性力量诗集）","author":"焦野绿","intro":"本书是专治焦虑的95后女性主义诗人、小红书头部青年诗人焦野绿的全新女性力量诗集《我应该，我要，我愿意》，全书收录212首最新原创诗歌。\n这部作品中，焦野绿透过女性诗人细腻的视角，立足日常，为普通人发声。\n全书共五个章节，从开始面对心中的呐喊走向成长与勇气，从学会拥抱世界到接受爱和自己，每一首诗都是她人生中往前行走的足迹。\n涂鸦是焦野绿创作的独特方式，作为95后，她脱离传统诗歌的写作框架，用年轻的语言，前卫的方法，把诗歌带到大街小巷，让诗意和真实生活碰撞。在这本书里，读者与作者同频，在诗句之间感受被理解、被看到、被表达的喜悦；他们关心世界，更关心自己。\n“这天地广阔，有一半是我的”\n“我会踩着时间的骨头，成为勇者”\n“暂时只爱自己，停止招待过客”\n“我应该，我要，我愿意”\n……\n焦野绿把年轻人那些迷茫、焦虑以及如鲠在喉的痛苦都写下来，在新颖、轻盈的表达中给人治愈的力量：我要用尽全力，不让自己成为别人。","cover":"https://cdn.weread.qq.com/weread/cover/67/cpplatform_scnnhjahwbmpevtkpgcaae/s_cpplatform_scnnhjahwbmpevtkpgcaae1730774980.jpg","version":1080400600,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":28,"maxFreeInfo":{"maxfreeChapterIdx":28,"maxfreeChapterUid":28,"maxfreeChapterRatio":75},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16566968,"publishTime":"2024-05-01 00:00:00","lastChapterIdx":214,"paperBook":{"skuId":""},"centPrice":2800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"最近阅读1小时"},{"type":0,"title":"常读常新","bookInfo":{"bookId":"22486199","title":"云彩收集者手册","author":"加文·普雷特-平尼","translator":"王燕平,张超","intro":"《云彩收集者手册》介绍了46种云彩和大气光学现象，并且收录了全世界云彩爱好者拍摄的百余幅精彩摄影作品。从太空边缘的神秘夜光云，到我们周围的重重雾霭，都在这本手册之中。即使没有任何自然观察经验，读者也可以了解云彩的名称、特征、形成原因，鉴别云的种类，并利用书中的趣味记分系统与亲朋好友展开观云竞赛。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22486199/s_YueWen_22486199.jpg","version":735988311,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":66,"maxfreeChapterRatio":60},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":13583905,"publishTime":"2018-03-01 00:00:00","lastChapterIdx":63,"paperBook":{"skuId":""},"centPrice":3999,"copyrightChapterUids":[59],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"有2年都在读"},{"type":5,"title":"思考最多","bookInfo":{"bookId":"934343","title":"看画识童心：儿童绘画心理解析","author":"徐静茹","intro":"本书是一本绘画解析的工具书，把孩子的心理呼唤以及天赋密码翻译给成人。同时，书中记录了大量通过绘画建立起自信、修复心灵创伤的儿童的成功疗愈案例，并配有300余副儿童绘画作品，具有很强的实践性和可操作性，很多案例跟踪长达十年之久。书中还介绍了孩子各生理和心理期、各种感官优势在绘画上的表现特征，帮助学画、艺考家长更好地识别孩子的天赋，开发优势智能，让他们成为最好的自己。","cover":"https://cdn.weread.qq.com/weread/cover/28/YueWen_934343/s_YueWen_934343.jpg","version":1131647273,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":13,"maxFreeInfo":{"maxfreeChapterIdx":13,"maxfreeChapterUid":13,"maxfreeChapterRatio":30},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4049188,"publishTime":"2018-01-01 00:00:00","lastChapterIdx":66,"paperBook":{"skuId":""},"centPrice":3480,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"共记录273条笔记"},{"type":3,"title":"最沉浸的","bookInfo":{"bookId":"519185","title":"长相思（赵丽颖、杨洋主演）","author":"桐华","intro":"同名电视剧由赵丽颖、杨洋主演，2018年即将开拍。桐华继《大漠谣》《云中歌》《曾许诺》后历经三年创作，再现上古时代瑰丽多姿的爱情神话。写不尽的儿女情长，说不完的地老天荒，最恢宏的画卷，最动人的故事，最浩大的恩怨，最纠结的爱恨，尽在桐华《长相思》。","cover":"http://wfqqreader-1252317822.image.myqcloud.com/cover/185/519185/s_519185.jpg","version":0,"format":"txt","type":0,"soldout":1,"bookStatus":2,"payType":1,"finished":1,"maxFreeChapter":16,"maxFreeInfo":{"maxfreeChapterIdx":16,"maxfreeChapterUid":16,"maxfreeChapterRatio":54},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":0,"publishTime":"2013-03-01 00:00:00.0","lastChapterIdx":151,"paperBook":{"skuId":""},"centPrice":1200,"copyrightChapterUids":[],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":true,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"单次阅读7小时"},{"type":4,"title":"读到深夜","bookInfo":{"bookId":"3300044239","title":"偷诗歌的人","author":"曹韵","intro":"《偷诗歌的人》是一本以短诗为主的原创诗歌作品集。收藏人间的喜怒哀乐与美好情惑。如江风上的明月，如深夜里的烟火，有爱情里的玫瑰，也有爱不能得的沉郁。诗人的创作灵感来源于日常生活与普世情感，充满烟火气。内容分为六个部分，第一、二部分关于珍贵温暖的记忆，以“从岁月中盗得几首往事”和“从蹉跎里折光一枝”为主题；第三、四部分关于情诗，以浪漫的书写表达“从诗里藏你的名字”和“从你的眉眼里偷一首情诗”;第五部分关于和解，以“从遗憾处取一份释怀”呈现另一番世间情；第六部分则关于想象，乌托邦的怀想抒发“从日子里窃一物幻想”的主题，让诗歌的语言更有张力。 就像诗人所说:“只诚恳地记录日子”，希望这本偷来的诗歌，是你如春的温暖。","cover":"https://cdn.weread.qq.com/weread/cover/32/cpPlatform_m2mgzCFKP3FysMaNudJJWk/s_cpPlatform_m2mgzCFKP3FysMaNudJJWk.jpg","version":580397995,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":5,"maxfreeChapterRatio":27},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":19196446,"publishTime":"2022-05-01 00:00:00","lastChapterIdx":11,"paperBook":{"skuId":""},"centPrice":5200,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读至23:51"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"935560","title":"半小时漫画中国史2","author":"二混子","intro":"看半小时漫画，通五千年历史，用漫画解读历史，开启阅读新潮流！《半小时漫画中国史2》是《半小时漫画中国史》系列的第2部，高潮迭起的大汉王朝，群雄逐鹿的三国时代，恣意奔放的魏晋风度，都在本书中大放异彩！《半小时漫画中国史2》，其实是一本严谨的极简中国史！作者曾获前央视主持人、热播网综《奇葩说》导师张泉灵鼎力推荐！看半小时漫画，通五千年历史，用漫画解读历史，开启阅读新潮流。仅仅通过手绘和段子，二混子就捋出清晰的历史大脉络：春秋战国像个班级、大秦过把瘾就死、三国就三大战役、魏晋乱世多奇葩、南北朝盛产败家子、大唐酷炫民族风……掀开纷繁复杂的历史表象，略去无关紧要的细枝末节，每一页都有历史段子，每三秒让你笑翻一次，而二混子手绘的帝王将相则是又贱又蠢萌：秦皇、汉武、唐宗、宋祖、曹操、孙权，全都和你我一样，有优点和缺陷，有朋友和敌人，他们在历史关键节点迸发出的惊人能量铸就了三千年的精彩中国史。而你在笑出腹肌的同时，不知不觉已经通晓了历史。","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/560/935560/s_935560.jpg","version":715758120,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":30,"maxfreeChapterRatio":13},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":14792401,"publishTime":"2018-05-01 00:00:00","lastChapterIdx":14,"paperBook":{"skuId":""},"centPrice":1599,"copyrightChapterUids":[28],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"2018/06/16/阅读"},{"type":6,"title":"最爱文学","bookInfo":{"bookId":"3300119345","title":"我应该，我要，我愿意（女性主义诗人焦野绿 全新女性力量诗集）","author":"焦野绿","intro":"本书是专治焦虑的95后女性主义诗人、小红书头部青年诗人焦野绿的全新女性力量诗集《我应该，我要，我愿意》，全书收录212首最新原创诗歌。\n这部作品中，焦野绿透过女性诗人细腻的视角，立足日常，为普通人发声。\n全书共五个章节，从开始面对心中的呐喊走向成长与勇气，从学会拥抱世界到接受爱和自己，每一首诗都是她人生中往前行走的足迹。\n涂鸦是焦野绿创作的独特方式，作为95后，她脱离传统诗歌的写作框架，用年轻的语言，前卫的方法，把诗歌带到大街小巷，让诗意和真实生活碰撞。在这本书里，读者与作者同频，在诗句之间感受被理解、被看到、被表达的喜悦；他们关心世界，更关心自己。\n“这天地广阔，有一半是我的”\n“我会踩着时间的骨头，成为勇者”\n“暂时只爱自己，停止招待过客”\n“我应该，我要，我愿意”\n……\n焦野绿把年轻人那些迷茫、焦虑以及如鲠在喉的痛苦都写下来，在新颖、轻盈的表达中给人治愈的力量：我要用尽全力，不让自己成为别人。","cover":"https://cdn.weread.qq.com/weread/cover/67/cpplatform_scnnhjahwbmpevtkpgcaae/s_cpplatform_scnnhjahwbmpevtkpgcaae1730774980.jpg","version":1080400600,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":28,"maxFreeInfo":{"maxfreeChapterIdx":28,"maxfreeChapterUid":28,"maxfreeChapterRatio":75},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16566968,"publishTime":"2024-05-01 00:00:00","lastChapterIdx":214,"paperBook":{"skuId":""},"centPrice":2800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了2小时"},{"type":2,"title":"最爱分享","bookInfo":{"bookId":"216219","title":"诗里特别有禅","author":"骆玉明","intro":"焦虑时读读这些古诗，用禅意让焦虑消失！\n禅是一种富于智慧的人生态度，能让人以恬静而欢喜的心情看待世间的一切。在本书中，我们将在复旦大学著名教授骆玉明的带领下解读和欣赏一系列体现禅理与禅趣的诗篇，通过阅读本书消除紧张和焦虑，便能以朴素自然的心情、随缘自适的态度，求得本应属于你的完美的生命。","cover":"https://cdn.weread.qq.com/weread/cover/47/yuewen_216219/s_yuewen_2162191709022000.jpg","version":1813390274,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":27,"maxfreeChapterRatio":57},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":14792401,"publishTime":"2024-03-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5500,"copyrightChapterUids":[24],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"分享6次"},{"type":12,"title":"共读最多","bookInfo":{"bookId":"839028","title":"你今天真好看","author":"莉兹·克里莫","translator":"周高逸","intro":"妹子们都说《你今天真好看》超性感耶！比《秘密花园》更解压。 辛普森动画组漫画家莉兹·克里莫首部作品集。收录了莉兹·克里莫150多张逗趣漫画。书中集结了所有你能想到的各种萌物，恐龙、棕熊、兔子、企鹅，甚至还有伞蜥、獾、土拨鼠、狐獴……在诙谐的对话中，它们展现出一种与生俱来的幽默感和令人艳羡的生活情趣。 你可能是书中任何一个动物，而书中的动物可能是你身边的任何一个人。 谁不曾享受过与父母的温情一刻？ 谁没有被朋友的玩笑弄得一时语塞？ 谁不会因自己反应慢半拍而哭笑不得？ 这本书就是有这样的魔力让你不由自主地会心一笑。","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/28/839028/s_839028.jpg","version":1505795231,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":4,"maxFreeInfo":{"maxfreeChapterIdx":4,"maxfreeChapterUid":12,"maxfreeChapterRatio":3},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2015-07-01 00:00:00","lastChapterIdx":9,"paperBook":{"skuId":"11734749"},"centPrice":4900,"copyrightChapterUids":[10],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"9位好友也爱读"},{"type":10,"title":"欣赏小众","bookInfo":{"bookId":"27329013","title":"语文课超有趣：部编本语文教材同步学（四年级下册）","author":"李夏","intro":"    “语文课超有趣”系列由部编本语文教材总主编温儒敏教授担任顾问，由北京大学语文教育研究所组织学者团队，按照“新课标”要求，以温儒敏高效语文学习理念为核心编写。本系列围绕新版教材的课文篇目，同步进行相关知识的汇总、梳理、延伸、启发，帮助学生全面了解课文周边的历史、人文、社会、自然科学知识，具有很强的配套性、知识性、趣味性和启发性，是语文教育研究领域多位名师、专家共同推荐的语文课内同步拓展阅读教辅书。配套性：与新版语文教材同步推出，根据课文篇目进行针对性编写。知识性：精选课文周边知识，帮助学生了解每一课背后的知识体系。趣味性：打破刷题、死记硬背模式，符合不同年级学生的阅读趣味。启发性：提供跨学科知识转化的钥匙，引导学生自发拓展认知领域。\r\n","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/13/27329013/s_27329013.jpg","version":1638503945,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":90},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":-60041,"publishTime":"2019-12-01 00:00:00","lastChapterIdx":31,"paperBook":{"skuId":""},"centPrice":1280,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"仅有3429人读过"},{"type":8,"title":"总有一天读完","bookInfo":{"bookId":"27350612","title":"上一堂朴素的语文课","author":"韩素静","intro":"《上一堂朴素的语文课》是“河南省最具影响力教师”韩素静在长期亲身教学和大量听评课基础上用心写就的总结和反思。书中有对源自教学一线的大量课例的翔实记录和精心剖析，涉及新授课、讲评课、听读课等多种课型和多个教学环节，通过从不同角度对不同走向的课例进行解读，挖掘其精妙与遗憾之处背后的原因，并对如何实现高效语文课堂提出了具体而有效的策略，对广大一线教师具有指导和借鉴作用。","cover":"https://cdn.weread.qq.com/weread/cover/30/YueWen_27350612/s_YueWen_27350612.jpg","version":1238901742,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":8,"maxfreeChapterRatio":15},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4552919,"publishTime":"2015-09-01 00:00:00","lastChapterIdx":61,"paperBook":{"skuId":"11770604"},"centPrice":3200,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"7天只读了29%"}]}',1782398786);
INSERT INTO popular_highlights VALUES('934343',17,'疗愈的几个阶段','弗洛伊德说：未被表达的情绪永远都不会消失。它们只是被活埋了，有朝一日会以更丑恶的方式爆发出来。','424-471',444,1782478597);
INSERT INTO popular_highlights VALUES('934343',7,'前言：我的故事','创伤是生命的一份厚礼，它可以帮助我去做最好的自己。','4066-4091',240,1782478597);
INSERT INTO popular_highlights VALUES('934343',16,'何为疗愈？','所以，表达即疗愈，共鸣即疗愈。','583-598',221,1782478597);
INSERT INTO popular_highlights VALUES('934343',18,'创伤的馈赠','荣格曾经说：如果没有悲伤与之平衡，“快乐”这个词将失去意义。','422-452',204,1782478597);
INSERT INTO popular_highlights VALUES('934343',22,'如何接纳','所以今天的父母一定要了解，艺术作品是不能拿来比较的。艺术的领域里，没有标准答案，只有个性发展。 在艺术的世界中，没有第一，只有唯一。','3123-3217',198,1782478597);
INSERT INTO popular_highlights VALUES('934343',9,'什么是绘画疗愈','绘画治疗这种非语言的表达性治疗手法，对于不善于用语言表达想法、消极内向、有语言障碍、语言功能发展不足、遭受严重创伤而关闭表达系统的儿童，是非常有效的心理治疗工具。','1013-1094',182,1782478597);
INSERT INTO popular_highlights VALUES('934343',11,'解读原理','但是孩子很容易受到影响和暗示，如果不能给予他们宽松、自由的表达环境，或者总是加以对错、优劣或者道德的评判，孩子画画的时候就会呈现出迎合和讨好的状态。','1583-1657',156,1782478597);
INSERT INTO popular_highlights VALUES('934343',17,'疗愈的几个阶段','一定要接纳孩子任何形式的表达，阻断表达是非常危险的。','1889-1915',144,1782478597);
INSERT INTO popular_highlights VALUES('934343',6,'序四','孩子是表达的弱者，就算是教育工作者，要做到完全了解和理解孩子都绝非易事。','971-1007',130,1782478597);
INSERT INTO popular_highlights VALUES('934343',16,'何为疗愈？','满足即疗愈，释怀即疗愈。','1093-1105',128,1782478597);
INSERT INTO popular_highlights VALUES('934343',23,'解读须知','很多有经验的疗愈师看出了绘画中的很多问题，却一直保持缄默，就是因为他们深知解读本身并不重要，只有确定可以帮到对方的时候，解读才有意义。','750-817',128,1782478597);
INSERT INTO popular_highlights VALUES('934343',23,'解读须知','一个孩子正面的优势得到肯定，才能使这部分充分放大，最终让负面的部分逐渐减弱、消失。一知半解的初学者解读出来的往往都是负面信息，如果解读出孩子的一大堆缺点，给孩子造成自卑心理，那还不如不解读。','3357-3452',128,1782478597);
INSERT INTO popular_highlights VALUES('934343',35,'怎么看攻击性','如今孩子压抑的原因，不是看得见的伤害，而是周围总有人讲太多大道理。对于一个有情绪的孩子来说，他们需要的就是物理性的宣泄，如果总是受到太多冠冕堂皇的说教，对于他们来说也是一种伤害。','3122-3211',126,1782478597);
INSERT INTO popular_highlights VALUES('934343',9,'什么是绘画疗愈','梦就是潜意识这个画家描绘的图画，弗洛伊德解开了潜意识的图画语言，也就等于解开了图画的心理语言。','598-645',120,1782478597);
INSERT INTO popular_highlights VALUES('934343',11,'解读原理','对所有学生画出来的画，都本着尊重和接纳的态度，不做任何道德的评判，所以我可以看到形形色色真实的表达。','2183-2233',120,1782478597);
INSERT INTO popular_highlights VALUES('934343',10,'绘画为何能解读孩子的心？','艺术和心灵的关系是天然的，孩子和艺术之间的关系也是天然的，当我们把这些天然的关系挖掘出来， 解读孩子的画就是一件很简单的事了。','537-632',112,1782478597);
INSERT INTO popular_highlights VALUES('934343',55,'顺应天赋的洪流','台湾漫画家蔡志忠曾经说：父母就是弓，孩子是箭，弓要送箭去它想去的地方，帮助箭实现箭的梦想。真希望每个父母都能懂得，顺应孩子的天赋，才是最好的培养。','2130-2203',108,1782478597);
INSERT INTO popular_highlights VALUES('934343',9,'什么是绘画疗愈','大量的实践案例已经证实，越是自由随意的涂鸦，可被解读出来的信息就越多。越小的孩子越适合绘画疗愈，疗愈的效果也越好，绘画疗愈已成为药物治疗和语言治疗的一个重要补充。','2245-2326',105,1782478597);
INSERT INTO popular_highlights VALUES('934343',58,'发现天性','很多时候，心灵某个地方留下的创伤我们都没有来得及察觉，它就进入了结痂过程，被深深埋在潜意识里，只有在专门疗愈的时候，我们才会察觉到它，才感觉到疼痛。而这种伤痛绝非无害，它会成为我们某种能力的上限封条。','2169-2269',105,1782478597);
INSERT INTO popular_highlights VALUES('934343',12,'画中的集体无意识','所以我们常常看到男孩画动作，女孩画静物；男孩发起冲突，女孩装饰美化；男孩的色彩简单沉稳，女孩的色彩丰富多样；男孩充满创造性，女孩充满建设性。','1729-1799',102,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','如果与一群人交流让你感到头痛，相较于大的团体工作，你更喜欢独立，或是与两三个朋友一起工作的话，那就请不要选择教师作为自己的职业。','1737-1801',3444,1782478597);
INSERT INTO popular_highlights VALUES('38260364',6,'第4章 代序','没有其他任何一个行业比教师更具有求知精神、更不满现状、更执着地追求创造思想。','498-536',2788,1782478597);
INSERT INTO popular_highlights VALUES('38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','与其强迫自己压制激动的心情，不如去找一个以另外一种完全不同的方式引发兴奋或生气的活动，从而帮你把“弹簧”压下去。以一种玩笑的方式来面对不快的事情，你就会成为所有思想和感觉的主宰者。','2671-2761',2786,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','亲爱的同行们，学校的使命以及教师最重要的任务，就是为人而斗争，克服消极影响，并扩大积极影响。','880-926',2574,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','教师才能的基础，是要对每个孩子都有可能被成功地教育这一点深信不疑。','2956-2989',2508,1782478597);
INSERT INTO popular_highlights VALUES('38260364',8,'第6章 教师的健康、充实的精神生活、快乐的工作','年轻人，我建议你们审视一下自己，如果工作不能让你快乐，就辞去学校的工作，在生活中正视自己，并找到喜欢的事业。否则工作的这些年对你而言将会是地狱。”','757-830',2197,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','教育工作不在于一朝一夕，而是要经过很长一段时间，才可见其成效。我们教授、灌输给孩子们的知识和技能，有可能得五年、十年后才会显现出来。','642-708',2112,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','只有当孩子遇到了聪明智慧、水平高超的教师，他的本性才能得到充分展现。','1157-1191',1800,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','不要把孩子和自己一概而论，也不要对他提出和大人一样的要求，要理解孩子的行为和孩子集体关系的复杂性，自己不要孩子气，也不要把自己放到和孩子一样的水平上。','3265-3340',1540,1782478597);
INSERT INTO popular_highlights VALUES('38260364',13,'第11章 教师的时间和教学各阶段的相互依存','请在小学阶段就教会所有学生这样阅读：在阅读的同时思考，在思考的同时阅读。阅读的能力应该达到自动化的程度，要让视觉和意识的感知能力大大超过大声朗读的能力。','1097-1173',1344,1782478597);
INSERT INTO popular_highlights VALUES('38260364',12,'第10章 时间从哪里来？一昼夜只有24小时','这个准备是什么？就是阅读，每天不间断地阅读，一生都与书为伴。潺潺的小溪流动，从不停歇，注入思想的河流。','1478-1529',1331,1782478597);
INSERT INTO popular_highlights VALUES('38260364',11,'第9章 请记住，没有也不可能有抽象的学生','正确认识到每个学生在某个阶段适合什么，如何进一步发展他的智力，是教育智慧特别重要的组成部分之一。','872-920',1310,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','影响学生精神世界最重要的工具是教师的话语、周围世界和艺术之美，以及创造一定的环境，使得人际关系中所有的情感都得到最充分的表达。','1296-1359',1296,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','如果你能感受到每个孩子的独特性，如果每个孩子的喜悦和悲伤都能打动你的内心，并引发你的思考、关心和担忧，那么就请勇敢地选择这份高尚的教师工作，将其作为你的职业，你一定会在其中找到创造的乐趣。','2186-2280',1241,1782478597);
INSERT INTO popular_highlights VALUES('38260364',15,'第13章 “双教学大纲”和学生的思维发展','为记忆、熟记并在记忆中储存大纲规定的教材创造一个智力背景。学生只有在思考的时候，才能牢牢掌握知识。请思考一下，怎么把现在正在学习的或即将学习的东西变成学生乐于思考、分析和观察的对象。','1791-1882',1230,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','要想成为一个真正的教育者，就必须要学好“热忱”这节课，在很长一段时间里用心去认识一切，了解学生的关注点，他们在想些什么，因为什么而高兴，又因为什么而不安，这是我们教育事业中最细微的事情之一。','4437-4532',1224,1782478597);
INSERT INTO popular_highlights VALUES('38260364',9,'第7章 如何预防日常工作中的神经衰弱？','如果可以的话，每位教师都应该使孩子的每一个小小闪光点发光发亮，而不是去熄灭它们。','478-518',1209,1782478597);
INSERT INTO popular_highlights VALUES('38260364',7,'第5章 什么是教师的才能？它是如何形成的？','教师职业是一项研究人的科学，要不断地深入人的复杂的精神世界。其显著特点是，不断地发掘人身上新的东西，对新的东西感到惊奇，并能看到人的成长过程，这就是滋养教育工作才能的根源。','1830-1916',1140,1782478597);
INSERT INTO popular_highlights VALUES('38260364',29,'第27章 阅读是“学困生”智力培养的重要手段','在学习困难学生的脑力劳动中起决定性作用的是阅读、阅读、再阅读，而并非补课，也不是无止境的“督促”。','629-678',1140,1782478597);
INSERT INTO popular_highlights VALUES('38260364',25,'第23章 怎么检查作业本？','经验表明，最合理的方法是定期抽查：教师每隔一段时间收几个学生的练习本进行检查。只有测验时才要检查所有人的作业。','1680-1735',1116,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','着眼长远，把当前的事情做好，聚焦于能够增加价值的事情，就是在为自己拓展人生的边际。','8704-8745',2700,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',3,'序 经济学有什么用？','“选择，而非金钱，才是经济学家研究的统一主题。”','1949-1973',2640,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',8,'04 价格陷阱 买前冲动，买完后悔，怎么走出商家的套路？','所以说，我们花了一笔钱，如果不去，我们会觉得亏，因为那个是惩罚机制，但惩罚机制其实并没有帮助我们更多地去健身房；反而是奖励机制，可以让我们更好地培养去健身房的习惯。','8491-8573',2176,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','与大家关系密切的就是工资增长远远没有赶上社会财富的增长，这就导致依靠工资收入来累积财富的人，在社会财富中的地位必然逐步下降。','4839-4901',2057,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','禀赋效应（endowment effect），是指我们一旦拥有某件物品，那么自然而然就会对该物品价值的评价比没有拥有之前大大增加，这实际上可以理解为我们常说的“敝帚自珍”。','7959-8045',1962,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',14,'09 幸存者偏差 为什么别人家的孩子都那么优秀？','正如那句流行的话：爱笑的女孩，运气都不会太差——没错，因为运气差的女孩，根本笑不出来。','9834-9877',1920,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','你的财富越多地用于消费，那么通胀对你来说就意味着收入的贬值，消费的增加；越多地用于投资，通胀就意味着财富的溢价。','7395-7451',1680,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','也就是说，大家所谓的穷富，主要是跟身边的人对比，而不是跟过去的自己对比。所谓的穷，只是跟朋友或身边的人相比，自己的生活条件不如别人罢了。','1838-1906',1540,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','这就是财富增长过程中必然导致的结果：财富和收入之间的离散度在加大，劳动产生的收入增长远远赶不上资产创造的财富增长，“人挣钱”远远赶不上“钱生钱”。','5267-5340',1504,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','穷只是一种错觉，其实是你的购买力排位下降了','461-482',1479,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','因为社会的总消费会与总供给实现天然的均衡，如果在消费、供给没有发生变化的情况下，财富的增加并不会带来更多的购买力。','3976-4033',1386,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',10,'06 经济学偏差 我为什么不是理性经济人？','证实性偏差是指当人确立了某一个信念或观念时，在收集信息和分析信息的过程中，会产生一种寻找支持这个信念的证据的倾向。','9149-9206',1296,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',11,'07 信息不对称 为什么掌握的资讯越多，这个世界的信息鸿沟就越深？','所谓回声室效应，是指在一个网络空间里，如果你听到的都是和你意见相似的回响，你会认为自己的看法代表主流，从而扭曲你对一般共识的认识。','5143-5208',1292,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','我们要树立投资意识，通过投资手段，不仅让自己的钱和资产不缩水，不感受到“穷”，更要用有限的资金实现保值增值，让自己和家庭过上更好的生活。','9067-9135',1275,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',9,'05 理性人假设 总是做不到理性消费，我该怎么改？','一些商品可以提供一段时间的免费试用，客户通过免费试用的方式使用一段时间后，在顾客心理上因为禀赋效应放大了商品的价值，所以舍不得送回去，就会产生购买行为。','8281-8357',1241,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',5,'01 坎蒂隆效应 为什么收入越来越多，却感觉越来越穷？','看来，我们并不是真的变穷了，只是身边朋友太有钱，让我们相形之下没有了“有钱”的感觉。','2252-2294',1224,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',4,'第一章 生活“异常”现象里隐藏的经济学','水是必需品都这么便宜，钻石没什么用为啥那么贵？','544-567',1220,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',19,'13 锚定效应 为什么总是找不到比初恋更好的男朋友呢？','法国社会心理学家托利得说过：测验一个人的智力是否属于上乘，只要看他脑子里能否同时容纳两种相反的思想，而无碍于其处世行事。即“思可相反，得须相成”。','7398-7471',1200,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',22,'16 次优选择 等了30年，只想找到最完美的心灵伴侣，我错了吗？','我理解中的恋爱，应该是灵魂与灵魂的碰撞，是心与心的接触，是千般疼万般惜的懂得与理解，是无欲无求的呵护与守候，是“才下眉头，却上心头”的挂与念，是“金风玉露一相逢，便胜却人间无数”的震撼与惊喜。','840-936',1053,1782478597);
INSERT INTO popular_highlights VALUES('3300025230',6,'02 边际决策 水是必需品都这么便宜，钻石没什么用为啥那么贵？','换句话说，如果你能把投入一份时间精力的产品卖出更多份，那就是做着边际成本递减的事。规模越大，你需要多投入的精力越少，而你的收入越高。','8444-8510',1008,1782478597);
INSERT INTO popular_highlights VALUES('3300101680',7,'第1章 会笑，是高阶能力','孩子的语言，是“玩”， 成年人的语言，才是“语言”。 孩子比我们有趣多了， 孩子喜欢愿意陪他们玩的成年人。 就是这么简单。','1026-1284',1188,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',4,'文前','做错了，没关系。我们没有经验嘛！ 所以不需要自责，只需要允许自己 随时重新开始。','754-850',990,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',7,'第1章 会笑，是高阶能力','我不准备收拾，等安迪放学回来，让他自己把这个数据收集完。','8884-8912',944,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',7,'第1章 会笑，是高阶能力','孩子就是这样的， 你交给他们的事， 只要带着尊重和信任， 他们便会全身心地投入去做，毫无保留。','3746-3948',923,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',12,'第5章 破除“扫兴父母”的魔咒','作为孩子最后的港湾， 永远不要站在孩子的对立面， 提醒自己永远和孩子站一边。','3734-3880',918,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',5,'前言 笑出来，不容易','伟大梦想放不下， 鸡毛蒜皮躲不过。 时间不够，精力不够，钱不够； 不够强壮，不够能干，不够平和； 再怎么做，似乎也做得不够多、不够好。','870-1049',867,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',9,'第3章 理解儿童','养育，是每一个父母的自我突破和完成之旅。','15210-15230',770,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',10,'第二部分 专治笑不出来','当他们令人“生厌”的时候， 并不是因为他们是“问题”，而是他们遇到了“问题”。','593-660',765,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',8,'第2章 为什么笑不出来','用“解决问题”的思路来面对养育是个“无底洞”。问题会层出不穷，解决了今天的“问题”，明天孩子还会有新的“问题”。而且孩子的问题会不断折射出背后的“我”的问题。','5225-5382',754,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',16,'第8章 那些棘手的问题（成年人版）','生活的智慧，其实就是让生活的一地鸡毛，变成七彩的鸡毛而已。','5334-5363',720,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',8,'第2章 为什么笑不出来','起点是给自己种下一颗觉知的种子， 并开始有意识地观察自己。','8784-8867',684,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',12,'第5章 破除“扫兴父母”的魔咒','我们的角色是支持孩子们去做他们觉得有趣的事，而不是让他们跟着我们的价值判断，做我们眼中“性价比最优”的事。','18433-18486',637,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',12,'第5章 破除“扫兴父母”的魔咒','孩子不是问题，孩子需要你的帮助去解决问题。','4721-4742',636,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',9,'第3章 理解儿童','矛盾的产生，是因为我们成年人很难“回到”想象的世界里。','1428-1455',629,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',19,'第10章 怎么就丧失了笑的能力','我不太确定别人怎么样，反正我自从有了孩子以后，就更加关注教育方面的信息，这表面看起来是为了孩子的成长，其实完全是一种自我平复。只有这个时候，你会感觉既没有忽略孩子，又在自我成长，还暂时地撇开了现实。','11392-11491',612,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',9,'第3章 理解儿童','会玩的爱，是可以穿越时光、抵抗岁月的。','9917-9936',600,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',16,'第8章 那些棘手的问题（成年人版）','不要觉得养育孩子，一定要不断地去“做”，事实上很多时候是“不做”。要意识到，“不做”，有时候也是一种“做”。','1484-1545',578,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',9,'第3章 理解儿童','孩子大部分时间是生活在想象世界里的，而不是在我们成年人认为的“现实世界”。','1108-1145',561,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',11,'第4章 改下脑回路','人生到最后，追求的是什么呢？最高的“成就”不是钱和物本身，而是幸福生活的能力，是吧？幸福的最高境界是什么？无非是开悟，是吧？开悟，就是时时刻刻活在当下，拥有无尽欢喜。','20925-21008',560,1782478598);
INSERT INTO popular_highlights VALUES('3300101680',20,'第11章 轮回里看到自己','每个普通人，一旦意识到、觉知到，就可以做出改变。这种改变，哪怕需要很长的时间跨度，也终会带来正面的影响。','7965-8017',560,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','大脑的设计不是为了让你思考，而是为了让你不用思考，因为大脑其实并不擅长思考。思考是缓慢且不可靠的。','613-662',988,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','所以，如果内容不足以吸引你的注意力，那么好奇心何时还会有持久力呢？答案似乎取决于我们对可能学到多少东西的判断。当我们认为自己能学到很多东西时，我们就会保持住这份好奇心。','7392-7476',952,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','人类不经常思考，因为我们的大脑不是为了思考而设计的，而是为了避免思考而设计的。','1659-1698',900,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','当你计划一节课的时候，你要从希望学生在课程结束前知道的信息开始。下一步，你要考虑这门课的关键问题可能是什么，你如何构建这个问题，使它有合适的难度水平来吸引你的学生，这样你自然就能尊重学生的认知局限性。','14664-14764',826,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','你的记忆系统是这样下注的：如果你仔细思考某件事，你就可能再次思考它，所以它应该被存储起来。因此，你的记忆不是你想记住什么或你试图记住什么的产物；它是你思考的结果。','773-854',756,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','视觉需要额外的脑力，因为看东西实际上比下棋或解决微积分问题更难。','1810-1842',748,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',11,'第3章 为什么学生记得住电视上的所有细节，却忘记我们教给他们的知识呢？','要想教得好，你应该认真考虑布置的每一项作业会让学生实际思考什么（而不是你希望他们思考的），因为那才是他们会记住的。','1296-1353',736,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','解决工作记忆过载的方法很简单：放慢速度，使用记忆辅助工具，如在白板上书写，以避免学生在工作记忆中保留太多信息。','13999-14054',714,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','这一原则的含义是，教师应该重新考虑如何鼓励学生去思考，以便最大限度地让学生从成功的思考中获得愉悦感。','1051-1101',702,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','当我们可以侥幸完成任务时，我们就不会去思考。相反，我们依赖记忆。我们面临的大多数问题都是我们以前解决过的，所以我们只是在做我们过去做过的事情。','3453-3524',702,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','一项最初需要大量思考的任务，随着实践练习，变成了一项不需要思考的任务。','5183-5218',608,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','这就是旅行如此累人的原因之一：所有在家可以自动完成的琐碎动作都需要你的全部注意力。','4669-4710',595,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',8,'引言','重复对于学习很有好处，但对于学习动力却很不利。由于重复太多，学习动力骤降，学生不再集中注意力，也就无法学习。','1091-1145',588,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','与其降低学生作业的难度，不如让思考变得更容易。','8598-8621',561,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','尽管事实上我们并不擅长思考，但我们实际上喜欢思考。人类天生好奇，我们会寻找机会参与思考。但是因为思考是如此困难，我们必须具备适当的条件，才能让这种好奇心茁壮成长，否则我们就很容易放弃思考。','5320-5414',560,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','当你以新的方式组合信息（来自环境的信息和长期记忆）时，思考就会产生。','9600-9634',544,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','孩子们从阅读中接触到的事实和词汇比其他任何活动都要多，大量数据证实，以阅读为乐趣的人在一生中都享受着认知带来的好处。','21835-21893',540,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',10,'第2章 当标准化测试只需要事实时，教师如何教授学生所需要的技能？','知道的越多，学习新事物就越容易。这表明，开始上学时知识较少的孩子将越来越落后。这一事实对早期教育意味着什么？在中小学阶段及其后的教育阶段呢？','24730-24800',540,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',3,'推荐序','学生是否动脑思考，在很大程度上取决于教学活动能否持续地让学生体验到解决问题的愉悦感。','839-881',520,1782478598);
INSERT INTO popular_highlights VALUES('3300053854',9,'第1章 为什么学生不喜欢上学？','解决适当难度的问题是有益的，但解决过于简单或过于困难的问题则令人不快。','8377-8412',510,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','写一个客观意象，再给它染上情感或立场之色。','19330-19351',649,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',6,'第三堂课 新诗写作的核心','请选择下列一种情感或情绪，用主观意象准确表达：孤独、无聊、爱情、乡愁、绝望、幸福、激动等。','8649-8694',473,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',6,'第三堂课 新诗写作的核心','用泛陌生化的意识写咖啡馆，无须写成诗句。','38258-38278',392,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','写“A是B”的句子，A与B尽量不搭界。','40454-40473',364,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','如果我们真沦为读图的奴隶，就意味我们把语言中的丰富想象，全部用图像简化、同化、固化，等于忘了古人早已发现的“读图”局限，忘了他们发明语言，想摆脱读图局限的初衷。','8785-8865',360,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','观念对人行为的影响，是迅速和惊人的，甚至能改变人出自本能的行为，观念之力甚至拧得过基因之力。','1135-1181',324,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','请用不太搭界的事物，解释下列事物（择其一）：烟囱、森林、瀑布、汤勺、头发、书店。如果一时写不出来，可套用“A不必是B”这种模式写。比如，“我们不必成天觅食”“我们不必像动物一样成天打斗”等等。','43791-43887',324,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','人有了观念，等于有了比基因突变还强大的工具，人就不会把自己的行为，完全交给基因调遣，他可以通过发掘出各种观念，大肆改变行为，甚至可以随时随地迅速改变，这是其他物种望尘莫及的。','1940-2027',266,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','真正的写作，是让你把写作交给内心的两个自我管辖，让理性的自我预先画出“鱼”的样子，又让即兴探索的自我推动着“鱼”一步一步向前演变，进化成“智人”。学会同时发掘两个自我的潜力，正是写作课欲达成的目标。','16608-16707',255,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',3,'自序：一个人的写作启蒙','不少人写的诗，之所以无价值、无意义，还是因为对诗意在人类进程中的角色安排，知之甚少，这样就以为“修辞立诚”的“诚”，不过是真实说出自己的看法……','997-1069',234,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','所谓的真实是指赋予事实合理的倾向或意义。','21298-21318',221,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','古人写诗时，一旦使用了大量客观意象，等描述完客观意象，他一定会添上有情感或立场色彩的诗句，来给前面写的客观意象“染色”，染上情感或立场之色。','15768-15838',221,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','海明威有一句话，颇能帮我们消除这一认识魔障，他说，“任何文章的初稿都是狗屎”。','13517-13556',220,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','我把这种模式叫“错搭模式”，我为错搭模式总结出了一个公式：A的B。这里的A和B，分别是两个不太搭界的事物。正因为不太搭界，普通人没事不会把两者搭配在一起，所以，我才称这种搭配叫错搭','31895-31985',198,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','我有个写作朋友，就有严重的写作障碍，障碍来自他的写作观念，他认为必须想好文章的每句话才能下笔，他迷信理性对写作的全面控制和调遣，结果每写一两句话，他都要苦思冥想好几天……','14470-14555',195,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','用三分钟写这样的短句。任何两个事物都可以搭配在一起，只有一条原则，找彼此相关度低的，把它们按“A的B”这种模式搭配。','35247-35305',176,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',3,'自序：一个人的写作启蒙','意识到，普通人容易理解的人性，才是支撑那些眼花缭乱诗句的基础。确切地说，构成诗意的内部机制，与构成自我的内部机制，不过是人性的一体两面。诗、文明的悖论、野心等，都来自悖论人性的挑动。','1606-1697',169,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',4,'第一堂课 受用一生的写作观念','从新闻中找一个事件的结局，将它作为你故事的结尾，请自编一个故事梗概（不超过一百五十字），除了结局与新闻一样，其余完全不同。','20686-20747',168,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','我想说，不管你想写什么，都应该从写诗开始，因为诗歌是一切写作的起点和终点。为何这么说？因为诗歌不只是对诗歌负责，它还对语言负责，它是民族语言的守护神。所有文学体裁中，诗歌是离语言最近的。','2673-2766',156,1782478598);
INSERT INTO popular_highlights VALUES('3300008362',5,'第二堂课 一堂课学会写出好诗句','大家一定要理解，文学的实质就是绕着弯子说话，是迂回的艺术，所谓的“曲线救国”。意象就是一种百读不厌的迂回表达。','51521-51576',156,1782478598);
INSERT INTO popular_highlights VALUES('26454163',90,'可可西里：中国最伟大的荒野','我们创造了文明，文明却消灭了荒野。','1855-1872',5680,1782478598);
INSERT INTO popular_highlights VALUES('26454163',93,'九寨沟：毁灭与创造','一切磨难皆是修炼，一切毁灭皆是创造。','947-965',5460,1782478598);
INSERT INTO popular_highlights VALUES('26454163',90,'可可西里：中国最伟大的荒野','这便是可可西里，中国最伟大的荒野。而我们要做的是，让荒野永远归荒野！','19081-19115',5404,1782478598);
INSERT INTO popular_highlights VALUES('26454163',90,'可可西里：中国最伟大的荒野','在可可西里，所有这些植物只有100天的生长周期。它们必须在短短两三个月内完成发芽、成长、开花、结籽的全过程。','9342-9396',5008,1782478598);
INSERT INTO popular_highlights VALUES('26454163',93,'九寨沟：毁灭与创造','未来的九寨沟，一定会有旧的景观消失，也一定会有新的景观诞生。但无论如何，它都将纯净似海，都将如梦如幻，都将万紫千红。','10564-10622',4114,1782478598);
INSERT INTO popular_highlights VALUES('26454163',87,'序 可以实现的理想','我有一个梦想，我希望：有一天，要将中国的雪山看遍。有一天，要将中国的江河看遍。有一天，要将中国的城市看遍。','368-502',3883,1782478598);
INSERT INTO popular_highlights VALUES('26454163',90,'可可西里：中国最伟大的荒野','而我们要做的是，让荒野永远归荒野！','1009-1026',3090,1782478598);
INSERT INTO popular_highlights VALUES('26454163',88,'中国从哪里来？','印度板块仍在以每年44~50毫米的速度北进，力量不断向外围扩散，使高原内部及其周围都成为地震高发带。近年来的许多具有破坏性的地震，如汶川地震、雅安地震、玉树地震、九寨沟地震等，大多受其影响。','14959-15054',2560,1782478598);
INSERT INTO popular_highlights VALUES('26454163',92,'横断山：中国极致风光最密集的山脉','1935年，红军强渡大渡河，并夺取泸定桥。之后历经数月，他们翻越二郎山、夹金山，穿过红原、若尔盖的沼泽湿地，在付出惨重代价后才得以走出横断山脉。','10561-10633',2560,1782478598);
INSERT INTO popular_highlights VALUES('26454163',99,'西安：鲜衣怒马一千年','每个人心中都有一个西安。或是秦皇的兵马俑，或是汉唐的长安城，又或是明清的古城墙。','863-903',2457,1782478598);
INSERT INTO popular_highlights VALUES('26454163',91,'阿里：荒野文明','今天的阿里，依然保持着独有的魅力。它拥有中国视宁度最好的星空，拥有中国最独特的动植物，还拥有纯朴的居民……阿里，它就在荒野中，既荒野，又文明。','13755-13858',2358,1782478598);
INSERT INTO popular_highlights VALUES('26454163',93,'九寨沟：毁灭与创造','一般家庭烧水壶底的水垢与钙华为同一种物质，美与丑的差别在于它所处的位置。','8746-8782',2299,1782478598);
INSERT INTO popular_highlights VALUES('26454163',98,'甘肃：愈多元愈美丽','而陇南的另一条重要的河流西汉水，曾将一对秦人情侣分隔两岸。相思之情化作《诗经》中的名句“蒹葭苍苍，白露为霜，所谓伊人，在水一方”，千古流传。','5356-5426',2214,1782478598);
INSERT INTO popular_highlights VALUES('26454163',104,'浙江：无敌生产力','如果有人问我，什么是浙江？我会回答：浙江就是无敌生产力。','16132-16192',2145,1782478598);
INSERT INTO popular_highlights VALUES('26454163',98,'甘肃：愈多元愈美丽','其中最大的河流——黑河，是仅次于塔里木河的中国第二大内陆河，也正是古人所说的“弱水三千”。','8729-8774',2070,1782478598);
INSERT INTO popular_highlights VALUES('26454163',88,'中国从哪里来？','烟雨江南、大漠西北，再加上气候高寒的青藏高原，中国的三大自然区——东部季风区、西北干旱半干旱区、青藏高寒区，就此成形。','8708-8767',1807,1782478598);
INSERT INTO popular_highlights VALUES('26454163',88,'中国从哪里来？','大碰撞造就了如今地球上最高、最年轻的高原——青藏高原，并影响到中国的地貌、气候、水系、生命等，且这一影响还在继续。','975-1032',1764,1782478598);
INSERT INTO popular_highlights VALUES('26454163',98,'甘肃：愈多元愈美丽','从1915年回族人马保子制作出第一碗面算起，兰州牛肉面的历史不过刚刚百年，推荐牛肉面的文章却早已经浩如烟海。','2107-2161',1740,1782478598);
INSERT INTO popular_highlights VALUES('26454163',90,'可可西里：中国最伟大的荒野','黑唇鼠兔，又称高原鼠兔，其上下唇缘为黑褐色，体色为棕黄或沙黄褐色。它们栖息于海拔为3200 ～ 5200米的高山草原、草甸带。','10277-10340',1734,1782478598);
INSERT INTO popular_highlights VALUES('26454163',87,'序 可以实现的理想','从陆地地貌类型上讲，它可以划分为33%的山地、26%的高原、19%的盆地、10%的丘陵和12%的平原。','780-831',1680,1782478598);
INSERT INTO popular_highlights VALUES('3300026077',169,'我身体里也有一列火车','我身体里的火车从来不会错轨 所以允许大雪，风暴，泥石流，和荒谬','1006-1065',7997,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',163,'我爱你','如果给你寄一本书，我不会寄给你诗歌 我要给你一本关于植物，关于庄稼的 告诉你稻子和稗子的区别 告诉你一棵稗子提心吊胆的 春天','773-947',6035,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',160,'文前','作为一个农人，我羞于用笔墨说出对一颗麦子的情怀 我只能把它放在嘴里 咀嚼从秋到夏的过程','2294-2397',4494,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',166,'下午，摔了一跤','云白得浩浩荡荡 散落一地的草绿得浩浩荡荡','786-834',4428,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',161,'代序 余秀华：让我疼痛的诗歌','如果给你寄一本书，我不会寄给你诗歌 我要给你一本关于植物，关于庄稼的 告诉你稻子和稗子的区别 告诉你一棵稗子提心吊胆的 春天','1350-1532',4380,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',171,'与一面镜子遇见了','遇见他，我就喜欢在这镜子前徘徊，如一个傻子，一个犯病者 结果我不停地撞上去 知道自己是死在哪里，却不肯写一个 验尸报告','920-1063',4301,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',160,'文前','一个人就是一个下沉的过程，包括庄稼，野草，兔子和经过村庄的云','3180-3210',3870,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',164,'我养的狗，叫小巫','对于一个不怕疼的人，他无能为力','1014-1029',3654,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',183,'荒漠','一个能够升起月亮的身体，必然驮住了无数次日落','451-473',3648,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',164,'我养的狗，叫小巫','我们走到了外婆屋后 才想起，她已经死去多年','1058-1107',2816,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',160,'文前','而爱，还是那么大，没有随我不停矮下的身体 矮下去','1552-1606',2752,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',187,'2014','如果十月安慰我，就允许五月烫伤我','757-773',2278,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',186,'烛光','真的 我已经忘记了人生的摇曳之态','1839-1883',2244,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',220,'我想要的爱情','你看，我不打算以容貌取悦你了 也没有需要被你怜悯的部分：我爱我身体里块块锈斑 胜过爱你','515-614',2070,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',173,'后山黄昏','不管厚土多厚，一个人走进去 总是很轻','714-760',1984,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',178,'关系','但是风一定会吹过黄昏 我们同葬于泥土，距离恒定','777-828',1872,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',193,'你的眼睛','愿这湖水千年，映照清风朗月 愿你一生所得，皆为你所愿','964-1018',1872,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',161,'代序 余秀华：让我疼痛的诗歌','她的诗，放在中国女诗人的诗歌中，就像把杀人犯放在一群大家闺秀里一样醒目——别人都穿戴整齐、涂着脂粉、喷着香水，白纸黑字，闻不出一点汗味，唯独她烟熏火燎、泥沙俱下，字与字之间，还有明显的血污。','2783-2878',1830,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',161,'代序 余秀华：让我疼痛的诗歌','这个世界里有很多乔装打扮的诗人，不知他们干吗要冒充诗人，把语言弄得前不着天后不着地的，把毫无关系的东西放在一起，毫无感情或语言逻辑，以为就是诗歌呢。','3324-3398',1800,1782478599);
INSERT INTO popular_highlights VALUES('3300026077',163,'我爱你','阳光好的时候就把自己放进去，像放一块陈皮','418-438',1792,1782478599);
INSERT INTO popular_highlights VALUES('27329013',6,'白云生处有人家——《乡下人家》','一月梅花，二月杏花，三月桃花，四月牡丹，五月石榴花，六月荷花，七月葵花，八月桂花，九月菊花，十月芙蓉，十一月山茶花，腊月水仙花。十二个月，月月有花语，月月有花香。','1084-1165',34,1782478599);
INSERT INTO popular_highlights VALUES('27329013',26,'走在乡间的小路上——《搭石》','当我见马路上有砖头或树枝，人们宁可绕着走，也不肯弯腰拾起的时候，我又想到山里人在雨水过后，自觉摆搭石的情景，想到有人发现搭石不稳，退回岸上，找块好石头搭上的情景……','1756-1838',34,1782478599);
INSERT INTO popular_highlights VALUES('27329013',4,'序言','要学好语文，光靠做题是不行的，局限于课内也学不好，办法只有一个，就是把课内学习与课外阅读结合起来，多读书，好读书，读好书，读整本的书。','2333-2400',33,1782478599);
INSERT INTO popular_highlights VALUES('27329013',5,'第一单元','政治上的失败造就了他文学事业的成功。','1556-1574',30,1782478599);
INSERT INTO popular_highlights VALUES('27329013',16,'第四单元','尽管觉得猫有些“毛病”，老舍还是很喜欢猫。乃至于将浇花、玩牌、逗小猫玩，当作三大休息方式。','2104-2149',26,1782478599);
INSERT INTO popular_highlights VALUES('27329013',6,'白云生处有人家——《乡下人家》','朔风如解意，容易莫摧残。','1480-1492',22,1782478599);
INSERT INTO popular_highlights VALUES('820703',4,'1. 骗人的恶魔','是否所有事情都不言自明，无须怀疑？我们的人生是否可能只是一场梦，或者这个世界只是我们虚构出来的？这些想法也许很怪异，但能够想象到这一点，显示出现实世界的真实性是可以被怀疑的。','393-480',561,1782478599);
INSERT INTO popular_highlights VALUES('820703',5,'2. 瞬间移动装置','心理，而非生理上的延续标志着他依然是同一个人。','1289-1312',414,1782478599);
INSERT INTO popular_highlights VALUES('820703',15,'12. 沙滩上的毕加索','如果我们接受艺术也会消亡，没有任何事物能真正永恒存在，也许就能看清艺术与生命的价值，更重要的是过程，而不是结果。','1666-1722',400,1782478599);
INSERT INTO popular_highlights VALUES('820703',5,'2. 瞬间移动装置','也许我们问斯特里欧斯是克隆人还是“本尊”是个错误的问题，也许我们应该问的是，这种做法对我们过去与未来的存在有何影响，也许这个问题的答案就是要不择手段地保持心理持续性。','1838-1921',340,1782478599);
INSERT INTO popular_highlights VALUES('820703',23,'20. 赖活不如好死','我们需要死亡赋予生命外在形式与意义，没有死亡，我们将会发现人生毫无意义。','967-1003',304,1782478599);
INSERT INTO popular_highlights VALUES('820703',7,'4. 虚拟外遇','外遇通常是夫妻关系存在问题的外在表现，而不是夫妻关系破裂的原因。','1494-1526',240,1782478599);
INSERT INTO popular_highlights VALUES('820703',13,'10. 蒙蔽公平','公平并不等同给予每个人相同的东西。那公平是什么意思？','738-764',228,1782478599);
INSERT INTO popular_highlights VALUES('820703',9,'6. 幸运轮盘','重点是过去的低概率不会影响下一次的概率，玛吉本来应该注意到这一点。','1396-1429',225,1782478599);
INSERT INTO popular_highlights VALUES('820703',15,'12. 沙滩上的毕加索','一般来说，我们认为应该保存或修复绘画使它们和以前一样，但是或许我们应该将艺术品的逐渐磨损也看作表现形式中的重要组成部分。','1328-1388',225,1782478599);
INSERT INTO popular_highlights VALUES('820703',10,'7. 无言胜利','“就算我不做，别人也会做的。”这是一般人使自身恶行合理化的拙劣借口。只要犯错，就该负起责任，这跟别人犯不犯没有任何关系。','732-792',224,1782478599);
INSERT INTO popular_highlights VALUES('820703',10,'7. 无言胜利','另一种回答是：结果不能使手段合理化，萨克斯应该拒绝服从命令。虽然萨克斯将因此丧命，犯人也将遭受更多痛苦，但至少他做出了符合道德的选择，维护了自己原本的正直。但是，这种做法比保住性命和减少痛苦更高尚吗？','1607-1707',221,1782478599);
INSERT INTO popular_highlights VALUES('820703',13,'10. 蒙蔽公平','当我们走到无知的幕后，我们同时也带上了既有的政治观与偏见，并且根据这些观点做决定。因此，在政治哲学史上，无知之幕被看作最有用的思想实验，也是最没价值的思想实验。','1665-1745',216,1782478599);
INSERT INTO popular_highlights VALUES('820703',7,'4. 虚拟外遇','性和爱其实不同，如果我们让生物冲动引发的交配行为破坏感情的纽带，我们就太傻了。','944-983',210,1782478599);
INSERT INTO popular_highlights VALUES('820703',99,'96. 家庭第一','我有没有理由将与我关系密切的人的福祉放在他人之上？','1595-1620',204,1782478599);
INSERT INTO popular_highlights VALUES('820703',8,'5. 一头想要被吃掉的猪','器官移植与输血一开始被提出来也被认为是骇人听闻的，然而等到人们逐渐习惯，许多对这种现象不道德的指责也逐渐消失，只剩极少数宗教派别还在反对。','1628-1697',196,1782478599);
INSERT INTO popular_highlights VALUES('820703',4,'1. 骗人的恶魔','哲学家习惯找我们以为已经了解的事物提出各种理由，让我们怀疑这些已经很熟悉的事物。自然法则、物质世界、上帝、善、其他人的想法、正义、时间——哲学家找到了怀疑一切事物的理由。','951-1036',187,1782478599);
INSERT INTO popular_highlights VALUES('820703',3,'序言','缺乏理性的想象只是幻想，而缺乏想象的理性很乏味，','385-409',180,1782478599);
INSERT INTO popular_highlights VALUES('820703',9,'6. 幸运轮盘','赌徒很容易在自己想象的场景中迷失，哲学家也是。','803-826',180,1782478599);
INSERT INTO popular_highlights VALUES('820703',45,'42. 拿了钱就跑','如果可以预测未来，人类的自由意志将无法改变未来，因为不管我们如何选择都会是预测的一部分。我们也许自由，但是我们前面的未来可能只有一个，一个原则上可以预测的未来。','2011-2091',180,1782478599);
INSERT INTO popular_highlights VALUES('820703',6,'3. 印度人与冰','我们有时候都会因为正确的理由而判断错误。','1104-1124',176,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','把留出固定的时间专心陪伴爱人当作生命的重中之重，并保持对爱人的好奇心。','2218-2253',3598,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','你们关系的含义远远大于在同一个屋檐下生活，大于共同生儿育女。你们是对方最重要的朋友，是对方最亲密的人。','399-450',2646,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','伴侣间的互相了解永远没有期限，你可以一辈子都对伴侣的内心世界保持好奇，一辈子都勇于和他（她）分享自己的内心世界，并且永远不停止对他（她）的探索。','1716-1788',2500,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','两条生命轨道相交时，会不可避免地发生碰撞与摩擦。这时，应怀着好奇心去探索对方，而不是面红耳赤地去争论孰是孰非，这样才能让两人在意见相左时相向而行，而非渐行渐远。','678-758',2023,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','真正的爱情,不是花前月下的山盟海誓,而是平凡日子里的细水长流。天长地久的爱情是朝夕相处的产物，成功的亲密关系来源于平凡日子里一句慰勉的话语、一个关怀的动作。','1576-1654',1950,1782478599);
INSERT INTO popular_highlights VALUES('33915626',4,'CHAPTER 2 如何避免“婚内孤独”','如果在相处中出现了问题，就要及时和伴侣交流，而不能向其他人大倒苦水。','7123-7157',1854,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','我们的伴侣并不一定总是和我们的想法一致，而这就是生活有意思的地方：和一个与你想法完全同步的人结婚无异于和自己结婚，而这和单身又有什么两样呢？','6417-6487',1850,1782478599);
INSERT INTO popular_highlights VALUES('33915626',8,'CHAPTER 6 成长的空间','家，其实可以定义为：无论你在哪儿，和谁在一起，你都可以感到被爱，有归属感和安定感。','2579-2620',1712,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','最伟大的关系的基石是互相尊重、共情，以及对对方的深刻理解。','3061-3090',1372,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','从生理角度来看，我们不想找一个与自己基因相近的另一半，反而会被那些和我们基因差异很大的人吸引。','4759-4806',1300,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','相爱就代表要向对方展现内心的脆弱，而这会让人觉得难堪或不适应。','5751-5782',1246,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','一个开放的大脑，一双认真倾听的耳朵，一个真诚的愿望，一颗想要建立联系的好奇心。','15805-15844',1245,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','许多人都在围城中痛苦挣扎：要么陷入平静的绝望中，要么极度沮丧，要么觉得这样的生活乏味至极。但是，在你绝望到想举手投降之前，请注意，现实生活中也有很多“神仙眷侣”，让我们再一次相信爱情的存在。','1080-1175',1241,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','进行对话的目的不是极力去证明你是对的，你的伴侣是错的；目的是理解你们之间的相同点与不同点，并去理解他（她）看待世界的方式。','22145-22206',1199,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','任何亲密关系里都会有矛盾，但是如果你们现在避开矛盾，以后必定会面临更多的麻烦。','6021-6060',1157,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','如果你带着好奇心和伴侣相处，时时刻刻都觉得对方身上有神秘感，那么你的亲密关系和你的人生都会异常丰富多彩。','6754-6806',1095,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','约会的价值在于创造出专属于两人的时间，并高度珍视这段时间。','13581-13610',1054,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','想要拥有一份真挚的爱情，不需要追求完美，只需要多加练习：练习如何表达爱和接受爱。','2044-2084',1040,1782478599);
INSERT INTO popular_highlights VALUES('33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','两个人必然存在差异。如果你们最终能理解和接受差异，这些差异就能丰富你们的亲密关系。','6303-6344',1040,1782478599);
INSERT INTO popular_highlights VALUES('33915626',4,'CHAPTER 2 如何避免“婚内孤独”','真正意义上的忠诚是什么？简而言之，就是我们拒绝和伴侣之外的其他人在一起的可能性。我们要在身体和情感上都忠诚于伴侣，并和他人保持界限，恰当处理亲密关系之外的私人关系。','3105-3187',972,1782478599);
INSERT INTO popular_highlights VALUES('216219',25,'代序 从诗走进禅，一路好风光','倘能消弭固执和对立，消弭贪欲和妄念，消弭紧张和焦虑，便能以空灵玄妙的智慧、朴素自然的心情、随缘自适的态度，求得本应属于你的完美的生命。','1929-1996',3618,1782478600);
INSERT INTO popular_highlights VALUES('216219',25,'代序 从诗走进禅，一路好风光','王维的诗“行到水穷处，坐看云起时”是禅。','1668-1688',1744,1782478600);
INSERT INTO popular_highlights VALUES('216219',28,'三 何处惹尘埃','最美妙的音乐，只能靠自己去想象，而不是等待演奏家用手去弹奏；最高深的佛法，也只能自己去体会，而无法用语言文字来传达这就是两则故事相通的地方。','2528-2598',1620,1782478600);
INSERT INTO popular_highlights VALUES('216219',28,'三 何处惹尘埃','空手把锄头，步行骑水牛。 人从桥上过，桥流水不流。','3221-3276',1332,1782478600);
INSERT INTO popular_highlights VALUES('216219',25,'代序 从诗走进禅，一路好风光','苍山空寂，明月清朗，幽潭澄澈，野花自开自落，浮云时聚时散，这里面都有禅意。诗人流连于自然的美景，写出自由的心与天地造化相融的平静和快乐。','1004-1072',1209,1782478600);
INSERT INTO popular_highlights VALUES('216219',26,'一 鸟鸣山更幽','一切都会过去，变化的背后仍然是一片深邃的幽静。','419-442',1185,1782478600);
INSERT INTO popular_highlights VALUES('216219',25,'代序 从诗走进禅，一路好风光','禅是一种哲学、一种宗教，但禅更是一种体验、一种生命形态。','758-786',1120,1782478600);
INSERT INTO popular_highlights VALUES('216219',31,'六 春在枝头已十分','尽日寻春不见春，芒鞋踏遍陇头云。 归来笑拈梅花嗅，春在枝头已十分。','1219-1282',1024,1782478600);
INSERT INTO popular_highlights VALUES('216219',26,'一 鸟鸣山更幽','而另一种安静，或者换一个词，幽静，却更富于精神性和情感意味。那是脱离了虚浮的嘈杂之后，面向生命本源和世界本源的一种感受。这种幽静得之于自然，同时也得之于内心，物我在这里并无区分。','846-935',962,1782478600);
INSERT INTO popular_highlights VALUES('216219',29,'四 满船空载月明归','世间有无穷的是非、无穷的争执，还有无穷的诱惑，人不能不在其中走过，要全然不动心也许很难，但若是处处动心，那恐怕要一生慌张，片刻也不得安宁。','5181-5250',890,1782478600);
INSERT INTO popular_highlights VALUES('216219',36,'十一 平常心是道','春有百花秋有月，夏有凉风冬有雪。 若无闲事挂心头，便是人间好时节。','2050-2113',833,1782478600);
INSERT INTO popular_highlights VALUES('216219',32,'七 只许佳人独自知','人们说莲花“出淤泥而不染”时，常常偏重在“不染”。其实淤泥也很重要，没有淤泥是长不出莲花的。','5707-5753',826,1782478600);
INSERT INTO popular_highlights VALUES('216219',26,'一 鸟鸣山更幽','空山不见人，但闻人语响。 返景入深林，复照青苔上。','2973-3028',810,1782478600);
INSERT INTO popular_highlights VALUES('216219',29,'四 满船空载月明归','你什么也没有得到，空船而去，空船而归，但心是欢喜的。','423-449',810,1782478600);
INSERT INTO popular_highlights VALUES('216219',32,'七 只许佳人独自知','爱有尽头，恨也有尽头。不能爱时便不爱，事已过去便不恨，不能死在爱与恨里，一切才有生机。','4469-4512',774,1782478600);
INSERT INTO popular_highlights VALUES('216219',26,'一 鸟鸣山更幽','世界是永恒，也是当下；世界是深邃的空寂，也是无限的生机。偏执地看，无论站在哪一边都不对，都不能真正把握这个世界，只有泯灭了对立的整体，才能达成对世界的彻悟。','4564-4642',720,1782478600);
INSERT INTO popular_highlights VALUES('216219',30,'五 坐看云起时','手把青秧插满田，低头便见水中天。 六根清净方为道，退步原来是向前。','5080-5143',714,1782478600);
INSERT INTO popular_highlights VALUES('216219',31,'六 春在枝头已十分','最高的完成并不是外在目标的完成，而是自我的完成。','3974-3998',702,1782478600);
INSERT INTO popular_highlights VALUES('216219',29,'四 满船空载月明归','千尺丝纶直下垂，一波才动万波随。 夜静水寒鱼不食，满船空载月明归。','1611-1674',697,1782478600);
INSERT INTO popular_highlights VALUES('216219',25,'代序 从诗走进禅，一路好风光','你倘若并不曾预设一个固定的目标，就会看到世界充满着奇妙的变化。','1739-1770',680,1782478600);
